/* characters q11 (247 mục) — R2.6 bồi tiểu sử Lý Thiến Mai */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["characters"]={"updatedAt":"2026-07-16","count":247,"chars":[{"id":"vuong-lam","name":"Vương Lâm","nguon":["@c1214","@c1215","@c1216","@c1217","@c1218","@c1219","@c1221","@c1222","@c1223","@c1224","@c1225","@c1226","@c1227","@c1228","@c1229","@c1230","@c1231","@c1232","@c1233","@c1234","@c1235","@c1236","@c1237","@c1238","@c1239","@c1240","@c1241","@c1242","@c1243","@c1244","@c1245","@c1246","@c1247","@c1248","@c1249","@c1250","@c1251","@c1252","@c1253","@c1254","@c1255","@c1256","@c1257","@c1258","@c1259","@c1260","@c1261","@c1262","@c1263","@c1264","@c1265","@c1266","@c1267","@c1268","@c1269","@c1270","@c1271","@c1272","@c1273","@c1274","@c1275","@c1276","@c1277","@c1278","@c1279","@c1280","@c1281","@c1282","@c1283","@c1284","@c1285","@c1286","@c1287","@c1288","@c1289","@c1290","@c1291","@c1292","@c1293","@c1294","@c1295","@c1296","@c1297","@c1298","@c1299","@c1300","@c1301","@c1302","@c1303","@c1304","@c1305","@c1306","@c1307","@c1308","@c1309","@c1310","@c1311","@c1312","@c1313","@c1314","@c1315","@c1316","@c1317","@c1318","@c1319","@c1320","@c1321","@c1322","@c1323"],"canhGioiCaoNhat":"Đang nghênh Cửu chuyển nghiệp kiếp, trợ Chu Tước thức tỉnh lần thứ tư @c1318","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Sau mười năm hôn mê trong hình tượng đá, hồn huyết của Lý Thiến Mai được bà lão bạch y (sư tỷ nàng) đưa tới dung nhập, Vương Lâm mở mắt thức tỉnh. Hắn phát hiện đã tiến vào cảnh giới kỳ dị gọi là Đạo cảnh — có thể nhìn thấu nguyên thần đối phương, thấy rõ căn bản thần thông và phong ấn, khiến thần thông đối phương đình chỉ biến hóa theo tâm hắn, thậm chí có thể loại bỏ thần thông khỏi trí nhớ đối phương. Khi thử trên bà lão Toái Niết đại viên mãn, hắn suýt nghịch chuyển phong ấn ngàn năm khiến bà tái trọng thương. Nghe bà lão kể lại mười năm hy sinh của Lý Thiến Mai — dùng máu tươi, tinh huyết tâm thần, đạo huyết nguyên thần, ngọc bội mệnh hồn, cuối cùng đáp ứng Yêu Tông đi khe sâu nhất chiến trường đổi hồn huyết — Vương Lâm run rẩy, lớp da đá toàn thân sụp đổ, hắn biến thành người máu, tu vi tuôn ra kinh thiên động địa, cả đại lục hoang dã tan nát thành bốn năm mảnh. Hắn bắt bà lão bắt dẫn đường tới chiến trường Yêu Tông cứu Lý Thiến Mai.","anchor":"hắn tiến vào một cảnh giới kỳ dị, đó là Đạo cảnh","bridge":true,"khoang":"@c1214"},{"mucCt":"ky","text":"Nghe xong toàn bộ câu chuyện về Lý Thiến Mai, nói bốn chữ 'Ta đi cứu nàng!', bỏ qua cả nhu cầu bế quan tăng hiểu biết Đạo cảnh hướng bước thứ ba lẫn nguy cơ Thác Sâm phát hiện ở giới ngoại. Nhớ lại lời ly biệt của Lý Thiến Mai tại Vô Cực Tông, đau đớn vì nợ nàng mười năm không thể trả. Lao đi như lưu tinh kéo theo bà lão tóc bạc, xuyên tinh vực cấp hai để lại khe nứt phân đôi cả tinh vực, vượt tinh vực cấp ba tiến vào tinh vực cấp bốn. Tại đại lục Hải Hồn Tông, phá vỡ đại trận phòng hộ trong nháy mắt, ra lệnh mở truyền tống trận và giao nộp toàn bộ nguyên tinh. Ánh mắt khiến tông chủ Khuy Niết đại viên mãn tự phun máu tạo thương tích mà không cần động thủ. Không kiên nhẫn chờ nửa canh giờ, dùng tay phải ép nguyên lực tinh không ngưng tụ cưỡng kích hoạt truyền tống trận, trận pháp sụp đổ sau khi truyền tống xong. Để lại lời hứa bồi thường gấp mười lần cho Hải Hồn Tông.","anchor":"Mặc dù hắn cần nhất lúc này chính là ngồi xuống bế quan trong thời gian dài, có thể tăng thêm sự hiểu biết của mình trong Đạo cảnh","bridge":true,"khoang":"@c1215"},{"mucCt":"ky","text":"Cùng bà lão tóc bạc cưỡng ép ngưng tụ thiên địa nguyên lực vào truyền tống trận tinh vực cấp dưới để truyền tống tức thì lên tinh vực cấp sáu, phá nát truyền tống trận khi xuất hiện. Lao tới ba đại lục Tiên Âm Môn, một chưởng phá tan đại trận phòng ngự mà tu sĩ Toái Niết cũng phải tốn thời gian mới phá nổi, năm khe nứt từ năm ngón tay lan khắp trận pháp. Ép tông chủ tân nhiệm Tiên Âm Môn giao toàn bộ nguyên tinh và mở truyền tống trận tới Vô Cực Tông. Truyền tống tới tu chân tinh Vô Cực Tông tinh vực cấp tám, tuyên bố muốn lấy một thứ pháp bảo tại đây.","anchor":"Một người, một chưởng, lực lượng một bước, rung động thiên địa.","bridge":true,"khoang":"@c1216"},{"mucCt":"ky","text":"Quay lại Vô Cực Tông qua truyền tống trận, xưng danh Lữ Tử Hạo xin mượn ngọn núi do kiếm Cổ Thần hóa thành (pháp khí Cổ Thần cửu tinh) để cứu Lý Thiến Mai nơi chiến trường. Vận Cổ Thần lực kích hoạt ngọn núi, mi tâm lần lượt ngưng tụ bốn Cổ Thần tinh điểm. Chỉ nói một chữ “Lôi!” đoạt quyền khống chế mười chín lôi cầu của hắc y lão giả, đánh ngược lại chủ nhân. Tung ngàn vạn đạo kiếm khí kèm hai nai con đen trắng, đánh lui cả hắc y lão giả lẫn tông chủ Vô Cực Tông. Tiết lộ đã đánh trọng thương Thủy Đạo Tử khiến bế quan, hạ huyết thệ chứa hồn phách nhưng bị hắc y lão giả bóp nát. Ngộ ra “cường giả vi tôn”, chuẩn bị đối đầu bốn thái tổ trưởng lão tiếp viện.","anchor":"Tu chân giới lấy thực lực nói chuyện, cường giả vi tôn.","bridge":true,"khoang":"@c1217"},{"mucCt":"ky","text":"Bị sáu trưởng lão thần thông Thiên Nhân Đệ Nhất Suy của Vô Cực Tông vây công. Phát hiện ngọc bội mệnh hồn Lý Thiến Mai nứt thêm nửa tấc, mệnh hồn cực kỳ suy yếu, vô cùng đau đớn lo lắng. Trong cơn bức bách đột phá lên Lục tinh vương tộc Cổ Thần, tinh điểm thứ năm và thứ sáu đồng loạt hiện ra, tinh điểm thứ bảy bắt đầu hình thành vòng xoáy. Đạp sụp ngọn núi sơn môn Vô Cực Tông, thu thanh huyết kiếm Cổ Thần bị phong ấn bên trong — khi chạm vào cảm giác máu mủ tình thâm, huyết kiếm vốn thuộc về hắn. Dồn sức mạnh Cổ Thần vào huyết kiếm chém một nhát, khiến hai trưởng lão mất nhục thân, bốn người trọng thương. Bay lên trời cảnh cáo Vô Cực Tông: nếu Quy Nguyên Tông bị tổn thương sẽ xóa tên Vô Cực Tông khỏi Vân Hải. Ngộ ra trong tu chân giới sức mạnh quyết định tất cả.","anchor":"Một kiếm, một câu nói, so với tất cả những lời hứa của hắn còn mạnh hơn gấp hàng vạn lần","bridge":true,"khoang":"@c1218"},{"mucCt":"ky","text":"Thu huyết kiếm Cổ Thần hóa giọt máu đỏ thấm vào mi tâm sau trận Vô Cực Tông, tự nhận định ba thành uy lực huyết kiếm đủ chém chết bất kỳ Thiên Nhân Đệ Nhất Suy. Chưa mở phong ấn, dùng đệ nhất đạo thuật cảm ngộ trong Đạo cảnh cũng đủ chiến Thiên Nhân Đệ Nhất Suy, nếu thêm pháp khí Cổ Thần thì giao chiến được Thiên Nhân Đệ Nhị Suy. Phân tích nếu mở phong ấn, tu vi bạo tăng, có hy vọng đạt Toái Niết trung kỳ, đối phó được cả Thiên Nhân Đệ Tam Suy. Xác lập mục tiêu: đạt Đệ Tam Bộ, giết Thủy Đạo Tử, giết lão tổ gia tộc thượng cổ La Thiên năm đó lừa gạt đường sống của hắn. Cảm nhận tu sĩ Đệ Tam Bộ không còn bí ẩn bất khả chiến bại trong mắt hắn. Khai phá tầng thứ tám, lần đầu bước vào tầng thứ chín Vân Hải tinh vực. Phóng sát khí kinh động mãnh thú cấp mười hai, được lão bà áo trắng dẫn đường tới cái khe chiến trường Yêu Tông.","anchor":"Mục tiêu của ta đó là đạt tới Đệ Tam Bộ, giết Thủy Đạo Tử, giết lão tổ của gia tộc thượng cổ ở La Thiên năm đó đã lừa gạt đường sống của ta!","bridge":true,"khoang":"@c1219"},{"mucCt":"ky","text":"Cùng Bạch Bà Tử bay từ tầng thứ hai tinh vực đến khe chiến trường Yêu Tông chỉ trong vài ngày. Đến nơi, khí tức khiến mấy ngàn tu sĩ và sáu cao thủ chấn động, mãnh thú hoảng sợ lui lại. Vung tay tạo cuồng phong lôi đình quét sạch toàn bộ mãnh thú bên ngoài khe. Nhận ra đầu lâu hắc khí mang khí tức ma đầu Tịch Diệt Giới, há miệng hóa lốc xoáy hút hết toàn bộ. Không chờ trận pháp mở, dùng hai tay xé rách khe chiến trường. Cửu U Long nghìn trượng lao ra cắn nuốt, bị đánh hai chưởng — chưởng đầu khiến toàn thân rồng bị thương nặng máu tuôn, chưởng hai chặt đứt hai sừng. Giẫm lên đầu rồng yêu cầu nó làm vật cưỡi để dẫn đường vào khe tìm Lý Thiến Mai.","anchor":"Trở thành vật cưỡi của ta, ta sẽ tha mạng cho ngươi","bridge":true,"khoang":"@c1221"},{"mucCt":"ky","text":"Dùng hai chưởng ấn chứa ba luồng khí tức (thần linh thái cổ, sức mạnh cắn nuốt hồn phách, khí tức thú hoàng Cát Cùng) thu phục Cửu U Long làm vật cưỡi, khiến toàn bộ tu sĩ bên ngoài khe nứt chấn động. Giao đấu với trưởng lão Yêu Tông (Thiên Nhân Đệ Nhị Suy): kích hoạt tinh điểm Cổ Thần trên mi tâm đánh lui đối thủ, hóa giọt máu mi tâm thành huyết kiếm đỏ chém nát pháp bảo mai rùa và xuyên vào thân đối thủ. Thu huyết kiếm dung nhập cơ thể, toàn thân hóa thành huyết kiếm — bản thân chính là kiếm, song chỉ tay phải phá hủy Dịch Linh Ấn hoàn chỉnh rồi điểm trán đối thủ đánh bay ra khỏi khe nứt. Trong lúc giao đấu âm thầm thi triển đạo thuật, đưa ngoại lực xâm nhập đạo niệm trưởng lão khiến nó suy yếu dần. Nhận ngọc giản bản đồ khe nứt từ trưởng lão, cảnh báo cách chữa trị, rồi cưỡi Cửu U Long bay sâu vào khe nứt tìm Lý Thiến Mai.","anchor":"hắn, chính là huyết kiếm!","bridge":true,"khoang":"@c1222"},{"mucCt":"ky","text":"Cưỡi Cửu U Long tiến sâu vào khe nứt chiến trường Yêu Tông, phóng kim quang chiếu vạn trượng phát hiện mấy vạn mãnh thú bao vây. Hồi tưởng mười năm trong Thiên Nghịch, xác nhận Mộng Đạo là thần thông thứ ba (đạo thuật), sau Tàn Dạ Lưu Nguyệt. Tiến tới biên giới khe nứt Tử Giới, thế giới chuyển từ đen sang tím, Cửu U Long run rẩy sợ hãi. Cảm nhận dao động thần thông còn sót lại, lần đầu tìm được manh mối về Lý Thiến Mai. Thi triển Tuế Nguyệt Nghịch Chuyển đảo ngược thời gian, nhìn thấy ảo ảnh quá khứ: nữ tử áo lam bị thương, tay cầm trường kiếm, bút vàng vờn quanh, đang nhanh chóng bay đi trong hư vô.","anchor":"Mộng đạo. Đây chính là thứ ta cảm ngộ được trong Đạo cảnh, sau Tàn Dạ Lưu Nguyệt chính là thần thông thứ ba của ta, nó là đạo thuật.","bridge":true,"khoang":"@c1223"},{"mucCt":"ky","text":"Nhận ra Lý Thiến Mai gầy yếu da bọc xương đang giao chiến với hư ảnh tiên tử trong khe nứt tím, kích động vui mừng điên cuồng. Dùng thần niệm kích thích Cửu U Long tiến sâu nhưng Cửu U Long hoảng sợ dừng lại tại vùng băng hàn cấm địa. Lấy ngọc bội mệnh hồn Lý Thiến Mai ra thấy vết nứt lan rộng, mệnh hồn suy yếu, tính mạng nguy kịch, quyết định nhảy khỏi Cửu U Long tự mình xông vào. Một mình tàn sát vô số mãnh thú bằng kiếm khí, lửa lam, lôi đình, Dịch Linh Ấn, thế như chẻ tre tiến tới cuối thông đạo. Tại vùng băng hàn sâu nhất, triệu hồi hơn một vạn Văn thú từ khe nứt trữ vật giao chiến với mãnh thú bạch khí, rồi tiếp tục tiến lên.","anchor":"Vương Lâm giống như là một pho tượng sát thần, tất cả lực lượng đều không thể ngăn cản hắn nửa bước","bridge":true,"khoang":"@c1224"},{"mucCt":"ky","text":"Cảm nhận khí tức Lý Thiến Mai trong dao động thần thông, điên cuồng chém giết hơn vạn Văn thú mở đường máu. Dùng Định Thân Thuật phóng quy tắc quấn quanh hư ảnh chiếc roi làm chậm tốc độ nhưng không ngăn được hoàn toàn. Thi triển Súc Địa Thành Thốn dung nhập hư vô, xuất hiện ngay bên cạnh Lý Thiến Mai khi chiếc roi chỉ còn cách nàng bảy tấc, tay không túm lấy hư ảnh chiếc roi. Phun máu nhưng không lùi một bước, kích phát tinh điểm Cổ Thần trên mi tâm, hư ảnh Cổ Thần hiện ra phá hủy chiếc roi. Lý Thiến Mai nói lời cảm ơn rồi nhắm mắt, sức sống cạn kiệt, hồn phách tan rã. Dùng nguyên lực phong bế sức sống trong cơ thể nàng nhưng không ngăn được tử khí. Thi triển Tuế Nguyệt thần thông — thạch môn khổng lồ hiện ra, dòng Tuế Nguyệt chảy quanh thân nàng làm chậm quá trình sức sống tiêu tan, nhưng phải duy trì liên tục tiêu hao nguyên lực. Nhớ lại cảnh Lý Mộ Uyển năm xưa già đi trong vòng tay mình và người yêu đang ngủ trong Tị Thiên Quan. Đối mặt thêm hai hư ảnh chiếc roi và vô số mãnh thú bao vây, quyết tâm mang Lý Thiến Mai xông ra, cào mi tâm mở phong ấn cấm chế phức tạp, giải phóng toàn bộ tu vi đã bị phong ấn ở Thất Thải giới hai ngàn năm trước, thể hiện tư thái cực mạnh.","anchor":"Vương Lâm lúc này sau hai ngàn năm, thể hiện tư thái cực mạnh trong khe nứt này!","bridge":true,"khoang":"@c1225"},{"mucCt":"ky","text":"Vì Lý Thiến Mai và ân nghĩa mười năm, Vương Lâm không do dự xé mở phong ấn cấm chế trong cơ thể, giải phóng đạo quả từ thất thải giới. Nguyên lực thiên địa điên cuồng chảy vào, tu vi từ Tịnh Niết đại viên mãn đột phá lên Toái Niết sơ kỳ rồi tiếp tục bạo tăng lên Toái Niết trung kỳ. Hai hư ảnh chiếc roi từ hư vô tối đen lao tới tấn công, chiếc thứ nhất bị lốc xoáy nguyên lực đánh vỡ, chiếc thứ hai bị hắn tay trái túm lấy. Ngửa mặt rít gào \"Lỗ chủy!\", tiếng gào khiến hơn trăm mãnh thú thất khiếu chảy máu nổ tung thành sương máu, vương thú phía ngoài sợ hãi lùi lại. Ném chiếc roi đi, phun huyết quang hóa thành huyết kiếm lao theo phá hủy chiếc roi trong hư vô, tiếng kêu rên từ hư vô truyền ra. Khe nứt quỷ dị khiến Thiên Kiếp không thể xuất hiện, nếu ở ngoài Thiên Kiếp sẽ mạnh hơn vô số lần.","anchor":"Hắn từ Tịnh Niết đại viên mãn đã thực sự bước một bước, tiến vào Toái Niết.","bridge":true,"khoang":"@c1226"},{"mucCt":"ky","text":"Nhận diện nữ tử áo đen là mãnh thú bọ cạp chín đuôi cấp mười ba đã hóa hình, tu vi tương đương Thiên Nhân Đệ Nhất Suy. Dùng huyết kiếm chém nát chín roi đuôi bọ cạp hư ảnh, thi triển thần thông học từ Lỗ Phu Tử đánh ra chưởng ấn ngưng tụ thiên địa nguyên lực kết hợp sức mạnh Cổ Thần tràn ngập vạn dặm. Kích hoạt tinh điểm Cổ Thần, biến thành hình thể Cổ Thần gần ngàn trượng, da thô ráp, uy áp kinh thiên. Phá nát hai càng bọ cạp, kéo đứt hai đuôi, quăng thân bọ cạp vào đàn mãnh thú khiến nó gần như tử vong. Cầm đuôi bọ cạp làm vũ khí lao vào đàn mãnh thú nện liên tục, khiến chúng kinh sợ như đang đối diện mãnh thú cấp mười ba. Chương xác nhận đây là trạng thái mạnh nhất trong hai ngàn năm tu đạo: Toái Niết trung kỳ, Cổ Thần tinh lục tinh (tinh điểm thứ bảy đã hiện hình), năm đạo bổn nguyên thức tỉnh, huyết kiếm máu Cổ Thần, đủ tư cách bá chủ một phương ở cả nội giới lẫn ngoại giới. Khi nữ tử dọa Viễn Cổ Đế Phi sẽ giết toàn tộc, Vương Lâm đáp lạnh lùng rằng toàn tộc đã chết, chỉ còn một mình.","anchor":"Vương Lâm lúc này chính là mạnh nhất trong hai ngàn năm tu đạo của hắn","bridge":true,"khoang":"@c1227"},{"mucCt":"ky","text":"Tiêu diệt bọ cạp cấp mười ba Tử Huyết, xé chín đuôi dung hợp thành một thu vào trữ vật, đập vỡ đầu lấy hắc đan chứa nguyên thần. Dùng thần thức lục soát ký ức bọ cạp, phát hiện khe nứt có mười chín mãnh thú hóa hình, càng sâu càng có mãnh thú cường đại, và nữ tử thần bí đang chữa thương sâu bên trong. Liên tưởng khe nứt này với khe nứt Phong Tiên giới nơi Văn Vương từng thoát ra, nghi hai nơi có liên hệ. Nảy ý dùng thiên kiếp giáng khi ra khỏi khe nứt để phá đại trận Phong Giới. Phân thân Y Nguyệt — phi tử viễn cổ Tiên Hoàng — xuất hiện, nhận ra huyết kiếm từng đả thương Tiên Hoàng và năm đạo bổn nguyên trong cơ thể Vương Lâm, đề nghị liên minh: đổi việc chữa thương lấy dẫn hắn tới tế đàn Cổ Thần. Vương Lâm cảnh cáo sẽ đánh thẳng tới nơi nàng chữa thương nếu Lý Thiến Mai có chuyện, nhận ngọc bội truyền tống rồi rời khe nứt.","anchor":"Ngươi có thể thử một lần!","bridge":true,"khoang":"@c1228"},{"mucCt":"ky","text":"Sau gần một tháng vào khe nứt chiến trường, toàn bộ mãnh thú bên trong bao gồm cả thú vương đều bị phá nát thân thể, một kích mất mạng, mùi máu tanh tràn ngập, sâu bên trong có lẽ đã hình thành biển máu. Tu sĩ bên ngoài chấn động, khó tin một mình hắn gây ra cuộc tàn sát này. Đúng lúc đó vô lượng kiếp giáng xuống Vân Hải tinh vực, thái thượng trưởng lão Yêu Tông nhìn về phía khe nứt, gợi ý thiên kiếp do Vương Lâm dẫn phát.","anchor":"Toàn bộ đều là thi thể! Đều là thi thể mãnh thú","bridge":true,"khoang":"@c1229"},{"mucCt":"ky","text":"Xuất hiện từ khe nứt chiến trường mặc y phục đỏ đẫm máu, tay phải che chở Lý Thiến Mai, tay trái giơ lên đỡ tia sét ngàn trượng của thiên kiếp. Tranh đoạt quyền điều khiển lôi lực thiên địa, truyền ý chí vào sấm sét rồi ra lệnh toàn bộ lôi đình phản kích ngược lên tầng mây, tiếng nổ kinh thiên truyền khắp tinh vực cấp chín. Ý chí ẩn trong lôi đình vô tình xâm nhập mật thất Thần Tông, kích hoạt Thất Thải Đinh tỏa sáng khiến Thủy Đạo Tử phun máu, toàn bộ công sức ép Thất Thải Đinh uổng phí. Nhìn xuyên tầng mây thấy lỗ hổng thông thế giới khác, bên trong có lầu các bạch ngọc, pho tượng và hai thanh thạch kiếm. Nhận định thiên kiếp chưa đủ phá đại trận Phong Giới. Dùng hư ảnh hai con hươu phóng ngàn vạn đạo kiếm khí chống hư kiếm xanh, nhưng thanh thạch kiếm vỡ tung phóng ra trường kiếm xanh thật sự lao về phía mình.","anchor":"Một người, một tay, một đôi mắt lạnh lùng giống như che trời vậy","bridge":true,"khoang":"@c1230"},{"mucCt":"ky","text":"Dùng huyết kiếm đối đầu lần lượt bốn thanh kiếm thiên kiếp (xanh, lam, đen, vàng), kiếm không hề suy xuyển. Rạch Cổ Thần tinh điểm trên mi tâm lấy giọt máu Cổ Thần lực tiếp cho huyết kiếm, triệu hồi hư ảnh hình người đẩy lùi ba kiếm. Bị tiếng gọi vùng đất ước mơ biến thành giọng phụ mẫu, Lý Mộ Uyển, Vương Bình, Chu Tước lão Thánh Hoàng nhưng đạo tâm kiên cố không lay động. Chờ đúng lúc thiên kiếp triển khai toàn bộ uy lực, dùng huyết kiếm xé tinh không phía dưới, kết hợp tu vi và áp lực núi mây mở khe nứt vào hư vô nơi Phong Giới Đại Trận. Bước vào hư vô, hóa thành lạc ấn, dùng thân chống đỡ núi mây, phun máu truyền toàn bộ lực thiên kiếp lên đại trận dạng lưới vô biên. Trở thành người đầu tiên từ cổ chí kim mượn thiên kiếp phá phong ấn Phong Giới.","anchor":"Nhưng từ cổ chí kim, mượn lực lượng của thiên kiếp và phá vỡ phong ấn thì chưa từng có. Vương Lâm là người đầu tiên!","bridge":true,"khoang":"@c1231"},{"mucCt":"ky","text":"Triệu hư ảnh Cổ Thần truyền lực công kích vào Phong Giới đại trận, kích phát hào quang bảy màu biến ảo thành trường thương bạch ngọc xuyên thấu núi mây Thiên Kiếp, lộ bốn thanh bảo kiếm bên trong, bản thân phun máu vì thương thế. Nhớ lại tiếng gào không cam lòng của tu sĩ giới nội chết trên Phong Giới đại trận, khơi dậy huyết tính. Pho tượng trên lầu các bạch ngọc tỉnh dậy phát động Cửu Cung Phong Ấn — chín thiên thạch hóa tinh cầu nhập vào thân qua chín đốm máu, cố ngưng tụ ở ngực để phong ấn. Hóa Lục tinh Cổ Thần cao nghìn trượng, giấu Lý Thiến Mai trên người, dùng sức Cổ Thần ngăn chín thiên thạch ngưng tụ, tuyên bố mình là Cổ Thần không phải tiên nên Phong Tiên không hiệu quả. Pho tượng tiếp tục phát động Bát Quái Ấn mạnh hơn Cửu Cung, bị dồn ép buộc phải lui bước. Trong tình thế nguy cấp bình tĩnh gọi chủ nhân Phong Giới xuất hiện — lộ ra đã chuẩn bị kế hoạch đưa người này tới Phong Giới đại trận từ trước.","anchor":"Chủ nhân Phong Giới, ta đã đưa ngươi tới Phong Giới đại trận, ngươi có thể xuất hiện rồi!","bridge":true,"khoang":"@c1232"},{"mucCt":"ky","text":"Truyền thần niệm khiến Thiên Nghịch Châu tái xuất, ngọc bội chủ nhân Phong Giới bay ra kích hoạt hình ảnh Tông Chủ Yêu Tông dưới dạng đại thụ chọc trời. Được chủ nhân Phong Giới truyền đạt bí mật về Thiên Kiếp: đến từ thái cổ, từ thiên đạo sinh tử, ngay cả Tiên Hoàng cũng có, kiếp hiện tại chỉ là Tiểu Kiếp chưa phải Đại Kiếp hay Thiên Cực Kiếp. Nhớ lời Thanh Thủy về cảm ngộ Cực Cảnh khi đạt Toái Niết, quyết liều mạng không chống cự để Bát Quái ấn vào toàn thân, chịu phong ấn Cửu Cung Bát Quái phá phách bên trong cơ thể nhờ sức hồi phục thân Cổ Thần. Khiêu khích Thiên Kiếp, đối mặt thêm ba lớp kiếp mới: Thất Tinh Bắc Đẩu sát kiếp, Bát Hoang Phong Thiên Trận phong tỏa lục phương, Ngũ Hành thủ ấn Kim Mộc Thủy Hỏa Thổ.","anchor":"Thiên Nghịch Châu vốn đã tiêu tan bên trong nguyên thần của hắn đột nhiên xuất hiện","bridge":true,"khoang":"@c1233"},{"mucCt":"ky","text":"Ngộ ra bản chất thiên kiếp diễn biến từ chín tới một (Cửu Cung → Bát Quái → Thất Tinh → Ngũ Hành → Tứ Tượng → Tam Tài → Lưỡng Nghi → Nhất Kiếp), cuối cùng hợp thành thiên cực kiếp tức Cực Cảnh. Từ chối thái thượng trưởng lão Yêu Tông trợ giúp, tuyên bố phải một mình đối kháng kiếp nạn. Bị Thất Tinh đánh trọng thương, nguyên thần sụp đổ nhưng khóa chặt không cho tiêu tán, chủ động cắn nuốt hỏa chưởng ấn Ngũ Hành để tái tạo nguyên thần. Dùng Ly hỏa và Chấn lôi ẩn trong Bát Quái phản kháng Ngũ Hành. Điểm ngón tay khiến Chu Tước thiên kiếp rời tam linh, quy phục nhập thể — hỏa diễm gần đạt hư hỏa, lần thức tỉnh thứ tư chỉ kém một đường. Chịu Tam Tài xuyên thấu mi tâm, ngực, tứ chi. Lưỡng Nghi Thái Cực phát nổ bao trùm toàn thân, thân Cổ Thần lục tinh huyết nhục mơ hồ. Cuối cùng bên trong cơ thể cũng sinh ra Cực Cảnh, đồng bộ với Cực Cảnh của thiên kiếp. Suốt quá trình vẫn toàn lực bảo vệ Lý Thiến Mai.","anchor":"Trong cơ thể hắn cũng có Cực Cảnh sinh ra","bridge":true,"khoang":"@c1234"},{"chuong":"@c1235","importance":"major","mucCt":"ky","tieuDe":"Tái sinh Cực Cảnh, phá Phong Giới thoát giới ngoại","text":"Trong vô lượng kiếp, thân thể hấp thu thiên kiếp, khi thiên kiếp diễn biến tới Cực Cảnh thì cơ thể đồng thời sinh ra Cực Cảnh đã mất ngàn năm — tóc bạc chuyển đỏ, tia chớp đỏ lóe trong mắt, thân ngừng sụp đổ, nguyên thần ngừng tiêu tán. Dùng hai đạo Cực Cảnh (thiên kiếp và bản thân) kết hợp sợi tơ xanh của chủ nhân Phong Giới phá lỗ hổng nhỏ trên Phong Giới Đại Trận. Thu nhỏ thân Cổ Thần, tay ôm Lý Thiến Mai hóa cầu vồng lao ra Thái Cổ Tinh Thần — chính thức đặt chân vào giới ngoại. Ngay khi vừa thoát, Khai Thiên Phủ (tổ khí Phong Giới Đại Trận) lao theo chém một nhát xuyên ngực, gây trọng thương cực nặng: nguyên thần sắp sụp đổ, lục phủ ngũ tạng vỡ vụn, vết thương chứa khí tức Cổ Thần không thể khép. Quát Khai Thiên Phủ phản chủ, luồng sáng do dự nhưng cuối cùng vẫn chém, rồi dung nhập Phong Giới Đại Trận biến mất. Đối diện mấy trăm tu sĩ giới ngoại (Tịnh Niết tới Toái Niết hậu kỳ đại viên mãn) xông tới giết, lần đầu thi triển tiên thuật Thôn Linh Phệ Thể Tuyệt Thiên do Thanh Thủy truyền. Bắt quyết điểm vào ngực, thân héo rũ như xương khô, hóa sương mù đen nuốt sạch tinh hoa tu sĩ để chữa thương khôi phục tu vi — nạn nhân đầu thành bao da rỗng, nạn nhân thứ hai bành trướng tự bạo. Bắt đầu tàn sát tu sĩ giới ngoại.","anchor":"thân thể Vương Lâm lại một lần nữa sinh ra Cực Cảnh đã mất đi từ lâu!"},{"mucCt":"ky","text":"Ẩn trong sương mù đen, dùng Thôn Linh Phệ Thể Tuyệt Thiên liên tục thôn phệ mấy trăm tu sĩ giới ngoại đang thủ trận tại Phong Giới Đại Trận. Diệt lão giả Toái Niết đại viên mãn bằng tia chớp đỏ xuyên phá thần thông ngũ sắc và tấm khiên mặt quỷ. Hóa sương mù đen thành dòng xoáy khổng lồ hút gần trăm tu sĩ chạy xa trở lại rồi quơ cánh tay sương mù thôn phệ nốt. Tu vi cấp tốc khôi phục, nguyên thần no đủ, hồn phách cô đọng, nhưng vết thương ngực khôi phục chậm. Cảm giác thôn phệ giống ăn tiên quả, gây mê muội không nỡ dừng, hai mắt lóe hồng quang, cười khằng khặc khi đuổi giết — bị tu sĩ giới ngoại gọi là ma, lộ dấu hiệu ma hóa rõ ràng. Cảm ứng nguy hiểm từ xa, vội thôn phệ nốt tu sĩ còn lại rồi dùng súc địa thành thốn biến mất. Ngay lúc biến mất, một thân ảnh khổng lồ sánh với tinh không gầm thét tên hắn lao tới.","anchor":"giống như là ăn tiên quả vậy, làm cho người ta mê muội, làm cho người ta không nỡ dừng lại","bridge":true,"khoang":"@c1236"},{"mucCt":"ky","text":"Dung nhập trời đất thoát khỏi tầm mắt Thác Sâm ở giới ngoại Thái Cổ Tinh Thần. Quay đầu thi triển Cực Cảnh (tia chớp đỏ — thiên kiếp cực) tấn công Thác Sâm, tia chớp chui vào cơ thể phá hoại liên tục không thể hủy diệt. Bị Thác Sâm phản đòn khi đang dung nhập trời đất, phun máu tươi, sương đen tiêu tan, vết thương ngực chứa khí tức Khai Thiên Phủ lại toạc ra rất khó khôi phục. Nhờ ba cao thủ bước thứ ba ngăn Thác Sâm nên thoát được, nhận định Thác Sâm yếu hơn nhiều so với lúc ở vùng đất Cổ Thần nhưng vẫn sẽ truy sát lại. Xác định mục tiêu đưa Lý Thiến Mai tới chỗ Lam Mộng Đạo Tôn ở Lam Sơn (Lam Ti Tộc). Quyết tâm giết tu sĩ giới ngoại chuẩn bị cho đại chiến hai giới, tấn công Ma Nạp Tinh, dùng sương đen hóa mấy vạn phần nuốt toàn bộ tu sĩ, dùng thuật Định khống chế lão giả áo xanh lục (thiên nhân đệ nhất suy) rồi dùng Cực Cảnh xâm nhập cơ thể hắn.","anchor":"Giờ phút này không thể có lòng dạ đàn bà, ta sinh ra trong giới nội, lớn lên trong giới nội","bridge":true,"khoang":"@c1237"},{"mucCt":"ky","text":"Nuốt hết tu sĩ ngoại giới trên tu chân tinh, sương đen hình thành lửa ma, dùng Trừu Tinh Hồn Lực rút tinh hồn toàn hành tinh. Tiếp tục cắn nuốt nhiều tu chân tinh thu được bảy đám khí tinh hồn, nguyên thần hồi phục gần hết, chỉ còn vết thương do Khai Thiên Phủ chưa lành. Quyết định hướng tới Nguyệt Tộc để hấp thụ sức mạnh Cổ Thần bức khí tức Khai Thiên Phủ ra, tính kế nếu Thác Sâm truy kích sẽ dẫn hắn đến Nguyệt Tộc cho hai bên đối đầu. Hồi tưởng toàn bộ cục diện nội-ngoại giới và sứ mệnh Chủ nhân Phong Giới giao phó: thống lĩnh nội giới chống ngoại giới. Khẳng định nơi đây không thuộc về hắn, hắn từ nội giới đến, ánh mắt kiên định.","anchor":"Không giết ba người này, ta dù đuổi kịp Vương Lâm, cũng không có cơ hội để cắn nuốt!","bridge":true,"khoang":"@c1238"},{"mucCt":"ky","text":"Dụ Thác Sâm vào tinh vực Nguyệt Tộc, hấp thụ Cổ Thần khí từ pho tượng bức khí tức Khai Thiên Phủ ra khỏi ngực, vết thương hoàn toàn lành. Lần đầu chính diện giao phong Thác Sâm: biến thân ngàn trượng dùng huyết kiếm, triệu tinh hồn bảy tu chân tinh, thi triển Dịch Linh Ấn và Cổ Thần thần quyền khiến tay phải Thác Sâm tê dại. Dùng tâm lý chiến hét Đồ Ti chưa chết buộc Thác Sâm không dám nuốt hắn. Bị Phong Thần Đại Trận và bảy chí bảo Nguyệt Tộc tấn công, xương cốt vỡ vụn khi đụng đốt xương cửu tinh. Thuyết phục Thác Sâm liên thủ, triển khai Cổ Thần bát tinh thuật Hư phá tan trận pháp. Thi triển Thôn Linh Phệ Tuyệt Thiên thôn phệ hơn ba vạn tộc nhân phục hồi. Dùng Dòng chảy tinh thần hút ngược Cổ Thần lực Thác Sâm, huyết kiếm chém đứt ngón trỏ Thác Sâm. Chém đốt xương Cổ Thần thành hai, cướp một nửa. Dùng năm đạo bổn nguyên chống lực trùng kích, mở Cực Cảnh, dùng Côn Cực Tiên bắt nguyên thần lão giả tóc bạc Nguyệt Tộc rồi rời đi. Thu hoạch: nửa đốt xương Cổ Thần cửu tinh và nguyên thần lão giả Nguyệt Tộc.","anchor":"Đây có thể nói là lần đầu tiên Vương Lâm và Thác Sâm thực sự chính diện giao phong","bridge":true,"khoang":"@c1239"},{"mucCt":"ky","text":"Thoát khỏi cuộc đuổi giết của Thác Sâm sau khi mi tâm hắn dị biến tỏa sáng chói mắt rồi bỏ chạy. Lảo đảo xuất hiện trong tinh không Thái Cổ Tinh Thần, lấy Lý Thiến Mai ra từ khe trữ vật, dùng Tuế Nguyệt thần thông duy trì sinh cơ cho nàng. Thu nửa đốt xương ngón tay Cổ Thần vào khe trữ vật. Dùng Côn Cực Tiên hóa phong ấn phong bế toàn thân lão giả tóc bạc rồi thu vào không gian trữ vật. Ôm Lý Thiến Mai bay suốt qua tinh không, dùng Súc Địa Thành Thốn và Na Di hướng về Lam Ti tinh vực để tìm Lam Mộng Đạo Tôn cứu nàng. Nhớ lại lời hứa mười năm trước với Lý Thiến Mai và lời hứa với Lý Mộ Uyển. Cuối cùng tới được Lam Ti tinh vực, nói với nàng rằng đã tới nơi.","anchor":"dù là trời khiến nàng chết thì hắn cũng sẽ cướp nàng lại","bridge":true,"khoang":"@c1240"},{"text":"Lam Mộng Đạo Tôn xuất hiện cướp lại Lý Thiến Mai bằng gió lốc, từ đầu đến cuối không liếc Vương Lâm. Vương Lâm nhận ra tiếng nói chính là tai ương Thất Thải Giới hơn mười năm trước. Hắn bay vào tu chân tinh của Lam Mộng Đạo Tôn, vận toàn bộ nguyên lực và Cổ Thần lực leo Lam Sơn dưới trận pháp cấm chế kinh thiên, ba ngày mồ hôi lẫn máu, phun máu, mạch máu gần nổ tung mới lên đỉnh. Lý Thiến Mai đã tỉnh lại nhưng mất toàn bộ trí nhớ, tự xưng Lam Nguyệt, hỏi hắn là ai. Vương Lâm đau khổ đáp tên mình rồi buông bỏ chống cự, bị lực cản đẩy tung khỏi đỉnh núi, tự nhủ nhớ về Mộng nhi.","anchor":"Quên hết mọi chuyện, cũng tốt.cũng tốt.","mucCt":"ky","bridge":true,"khoang":"@c1241"},{"mucCt":"ky","text":"Rời Lam Sơn một mình trong tâm trạng bi thương, để Lý Thiến Mai ở lại. Khi Na Di tới biên giới tinh vực Lam Ti tộc, cảm nhận nguy cơ sinh tử mãnh liệt, mạnh hơn cả khi gặp Thác Sâm, chỉ thua Thủy Đạo Tử. Thi triển ánh mắt ác mộng bằng năm đạo bổn nguyên trong đồng tử, phát hiện bạch y nữ tử quỷ dị không có sinh cơ đã bám theo mình nhiều ngày từ sau khi gặp Thác Sâm, chỉ dừng ở ranh giới Lam Ti tộc. Đả tọa bảy ngày phân tích, phát hiện thân thể biến hóa sau khi leo Lam Sơn: nguyên lực tăng, Cổ Thần lực hùng hậu hơn do bị nén, nguyên thần linh hồn nhạy cảm hơn nhiều. Suy đoán Lam Mộng Đạo Tôn dùng cách ám chỉ cảnh báo về bạch y nữ tử. Ở lại tu chân tinh thổ nạp một tháng, khôi phục tu vi tới đỉnh phong. Cuối cùng Lam Mộng Đạo Tôn hiện thân đề nghị truyền chín đại thần thông.","anchor":"Gần hai ngàn năm tu đạo, khám phá ra hết thảy mọi chuyện trên thế gian","bridge":true,"khoang":"@c1242"},{"mucCt":"ky","text":"Lam Mộng Đạo Tôn đưa ra hấp dẫn cực lớn: chín thức thần thông, sáu thức tiên pháp, ba thức đạo thuật, hương hỏa hai ngàn triệu môn đồ, năm đạo khí thiên thạch thiên ngoại, hứa giúp thân thể Cổ Thần và bảy đạo bổn nguyên đại thành. Hai điều kiện: ăn vong tâm quả thoát ly giới nội trở thành người Thái Cổ Tinh Thần, cắt đứt tình cảm giới nội kết đạo lữ với nữ nhi Lam Mộng. Vương Lâm nhớ tới tiên nhân hy sinh trong Phong Giới Đại Trận và lời hứa cả đời với Lý Mộ Uyển, dứt khoát cự tuyệt. Phản vấn Lam Mộng về người trọng yếu nhất khiến đối phương trầm mặc. Chỉ ra giới nội tồn tại lực lượng khiến chưởng tôn hoảng sợ bỏ chạy. Lam Mộng chấp nhận, xóa nhân quả, truyền ba thức thần thông: Phiên Thiên Ấn (lật thiên địa, đồ diệt vạn linh), thuật phòng ngự ánh sáng (cảm ngộ cảnh giới Không Linh), thức thứ ba (một trong tam đại đạo thuật, chưa thi triển). Được tiết lộ bản thân có năm đạo bổn nguyên — cổ kim chưa từng có.","anchor":"Ta, có thể không cần, không học.","bridge":true,"khoang":"@c1243"},{"mucCt":"ky","text":"Tiếp nhận thức thứ ba từ Lam Mộng Đạo Tôn — Dung biến đạo thuật, thần thông dung hợp thay đổi bổn nguyên. Thi triển Hô Phong đạo và Vũ đạo để Lam Mộng dung hợp giúp thành một giới phòng hộ tương đương Quang ảnh thuẫn. Bế quan bốn tháng trên đỉnh núi tu chân tinh, ngồi bất động dưới mưa gió sấm chớp, mắt đầy tơ máu. Trong đêm mưa tầm tã, đột phá lĩnh ngộ thành công Phiên Thiên Ấn — thiên địa trong đồng tử đảo lộn, thi triển lật trời thành đất, uy lực hủy thiên diệt địa vượt xa mọi thần thông trước đây. Nhận ra Phiên Thiên Ấn còn có biến thức: nghịch chuyển da và nội tạng thân thể con người thì sát thương mạnh hơn vô số lần. Tiếp tục bế quan lĩnh ngộ thức thứ hai Quang ảnh thuẫn.","anchor":"Bốn tháng có thể học được Phiên Thiên Ấn…ta vốn tưởng hắn phải mất mấy năm","bridge":true,"khoang":"@c1244"},{"mucCt":"ky","text":"Sau khi hiểu Phiên Thiên Ấn, Vương Lâm dành bốn tháng lần mò Quang Ảnh Thuẫn, tản thần thức bao trùm toàn bộ tu chân tinh, nhìn thấy ánh sáng (sức sống) từ vạn vật ngưng tụ quanh thân hóa quang ảnh khổng lồ nhưng chưa hoàn toàn minh ngộ, cảm nhận được bức tường ngăn cách — cửa ải tiến vào bước thứ ba. Chuyển sang cảm ngộ đạo thuật dung hợp từ tiểu cầu lốc xoáy, năm đạo bổn nguyên hấp thu khí từ tiểu cầu cho đến khi tiểu cầu hoàn toàn tiêu tan. Lần đầu thi triển đạo thuật dung hợp: cầm thanh kiếm băng biến thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi. Quyết định dung hợp Súc Địa Thành Thốn trước để khắc phục khuyết điểm không thi triển được khi thiên địa nguyên lực rối loạn. Nhận ra cần hương hỏa Hỏa Tước Tộc và sấm sét Thiểm Lôi Tộc để năm đạo bổn nguyên đại thành, ấn ký Thái Cổ Tinh Thần trên mi tâm có thể cắn nuốt lẫn nhau tiến hóa hoàn mỹ. Dự định tra nguyên thần trưởng lão Nguyệt Tộc để biết Chưởng Tôn thuộc bộ tộc thái cổ nào.","anchor":"Vương Lâm cũng không biết bức tường này là một cửa ải để một tu sĩ tiến vào bước thứ ba","bridge":true,"khoang":"@c1245"},{"mucCt":"ky","text":"Sau mấy tháng nhập định trên đỉnh núi Lam Ti Tộc, dung hợp thành công Súc Địa Thành Thốn với cơ thể, lấy bản thân làm trời đất, bù sơ hở cũ khi thiên địa nguyên lực hỗn loạn, nhược điểm mới là tiêu hao nguyên lực nhiều hơn, chỉ thi triển liên tục hơn mười lần phải bổ sung. Rà soát toàn bộ thần thông bình sinh, nảy ý dung hợp Rải Đậu Thành Binh vào Hô Phong Hoán Vũ. Thử ép dung hợp Phong Tiên Ấn vào tiểu cầu lốc xoáy Hô Phong Hoán Vũ nhưng bùng nổ kinh thiên, dùng Súc Địa Thành Thốn mới dung hợp mang vụ nổ ra biên giới tinh vực, dùng Quang Ảnh Thuẫn phản xạ sức hủy diệt thoát hiểm. Đổi phương pháp bóp nát tiểu cầu, mở giới ngàn trượng Hô Phong Hoán Vũ rồi đưa Phong Tiên Ấn vào, nhưng sức bài xích khiến Phong Tiên Ấn sụp đổ tan vỡ. Dị biến xảy ra: cấm chế dung nhập vào giới hình thành thiên địa, vô số chiến hồn hóa tinh quang rơi vào từng mảnh vỡ.","anchor":"Thuật này cũng có chút thành công, mặc dù vẫn còn một chút khiếm khuyết","bridge":true,"khoang":"@c1246"},{"mucCt":"ky","text":"Giới ngàn trượng co rút dung nhập vào cơ thể, hoàn thành dung hợp Hô Phong Hoán Vũ. Phát hiện chiến hồn trên các đại lục trôi nổi trong giới tản ra khí tức trắng sữa — hương hỏa thật sự, dung nhập năm đạo bổn nguyên. Nhận ra chuỗi nhân quả: mảnh vỡ Lôi Tiên Giới qua Thiên Kiếp luyện hóa, dùng Rải Đậu Thành Binh tạo mười tám tầng địa ngục thu nạp hồn phách, Lam Mộng Đạo Tôn trợ giúp dung hợp thành một giới — tất cả khiến hương hỏa phát sinh. Lấy nửa đốt ngón tay Cổ Thần ra thử dùng tinh điểm hấp thụ nhưng thất bại vì ý chí bên trong chống lại. Lấy nguyên thần lão già tóc bạc Nguyệt Tộc từ Côn Cực Tiên, dùng huyết kiếm tra tấn suốt mấy canh giờ hút tinh khí sức sống, rồi dùng thần thức tìm kiếm thần thuật trong ký ức. Sau khi khai thác xong, hủy diệt hoàn toàn nguyên thần lão già. Hồn phách lão già hiện ra trong Hô Phong Hoán Vũ giới, tản ra hương hỏa kinh người — chứng minh cao thủ mạnh tạo hương hỏa nhiều hơn. Từ ký ức biết Nguyệt Tộc còn ba bộ lạc, bộ lạc hướng chính đông có lão tổ tông bước thứ ba (Chưởng Tôn) đang bế quan trị thương. Gọi Nguyệt Tộc là Nô Tộc. Quyết định rời đi vì nữ tử áo trắng Lam Ti Tộc vẫn đợi bên ngoài.","anchor":"Ta không thể giết ngươi sao? Người của Nô Tộc mà cũng dám cuồng vọng!","bridge":true,"khoang":"@c1247"},{"text":"Vương Lâm đọc ký ức lão già Nguyệt Phệ Tộc, biết Thanh Vân Linh Thuật cần Linh Chủng và có thể hấp thụ sức mạnh Cổ Thần. Hắn thu đốt ngón tay Cổ Thần rồi rời tinh vực Lam Ti, nhưng bị Lan Phi Lâu Lan nhiều lần chặn Súc Địa Thành Thốn và phong tỏa Thuấn Di. Hắn cố ý để đối phương bắt nhằm hỏi thân phận, kiểm chứng mục đích hút thần tính Cổ Thần, sau đó dùng Hô Phong Hoán Vũ Giới thu hồi khói vàng, huyết kiếm phá bàn tay hư ảo, nhận ra nàng chỉ là phân thân và phát động Phiên Thiên Ấn.","anchor":"Hết thảy những việc vừa rồi, đều là do Vương Lâm cố ý hành động","bridge":true,"khoang":"@c1248"},{"mucCt":"ky","text":"Thi triển Phiên Thiên Ấn của Lam Mộng Đạo Tôn lần đầu trong thực chiến, tạo thiên địa hư ảnh nghịch chuyển đè bẹp đối phương. Phân tích chính xác Bạch Y Nữ Tử chỉ là hình chiếu phân thân tu vi thiên nhân tam suy, tố cáo nàng dùng ảo thuật ảnh hưởng tâm thần hắn. Tung chiến hồn trong Hô Phong Hoán Vũ giới tấn công ồ ạt, dùng Quang Ảnh Thuẫn phản chiết xạ trường kiếm đen ngược lại đối phương. Rút huyết kiếm chém nứt ngọc bội nữ tử khiến nàng phun máu bỏ chạy. Khi bổn tôn phóng chiếu cánh tay qua ngọc bội ấn ngón tay xuống, cảm nhận nguy cơ sinh tử vượt cả Thủy Đạo Tử, dừng truy kích triển khai Hô Phong Hoán Vũ giới và Quang Ảnh Thuẫn phòng thủ. Quang Ảnh Thuẫn bị ngón tay xuyên phá hoàn toàn, Hô Phong Hoán Vũ giới đang đối kháng, trận chiến chưa kết thúc.","anchor":"Năm đạo bổn nguyên trong mắt điên cuồng xoay tròn, đảo một cái lại thấy rõ thân thể Bạch Y Nữ Tử nọ","bridge":true,"khoang":"@c1249"},{"mucCt":"ky","text":"Chống đỡ ngón tay triệu hồi bổn tôn bằng ba lớp phòng ngự (Quang Ảnh Thuẫn, Hô Phong Hoán Vũ giới, đốt xương Cổ Thần), bị một tia lực vô hình xuyên ngực nhưng nhờ thân Cổ Thần hồi phục tức khắc. Phản kích bằng huyết kiếm chém đứt cánh tay triệu hồi, phá vỡ ngọc bội của Bạch Y Nữ Tử khiến nàng phun máu bỏ chạy. Dung nhập thiên địa truy sát liên tục trong Thái Cổ Tinh Thần, thi triển lôi đình cắt đường rồi Phiên Thiên Ấn đánh trúng nữ tử, huyết kiếm đâm xuyên hậu tâm. Nhìn thấy lực hương hỏa môn đồ nồng đậm vượt ba thành Hô Phong Hoán Vũ giới của nữ tử, nảy ý muốn biến nàng thành một hồn trong Hô Phong Hoán Vũ giới. Truy đuổi tới tinh vực Ma Hạt Tộc, huyết kiếm đâm trúng vai phải nữ tử. Hóa thân Cổ Thần ngàn trượng, một quyền tạo khe nứt tinh không bức nữ tử hiện hình, dùng Quang Ảnh phản xạ mọi thần thông của mấy ngàn tu sĩ Ma Hạt Tộc khiến chết thương vô số.","anchor":"Trái tim Vương Lâm đập thình thịch, trong nháy mắt khi nữ tử này rời đi, thân thể hắn nhoáng lên, hầu như đồng thời biến mất, đuổi theo nàng một lần nữa.","bridge":true,"khoang":"@c1250"},{"mucCt":"ky","text":"Truy sát Bạch Y Nữ Tử tới phía đông Thái Cổ Tinh Thần, thi triển Định Thần Thuật đóng băng trời đất, dùng bổn nguyên lực kéo nàng ra khỏi hư vô. Dùng huyết kiếm đâm thiên linh phá nguyên thần, đoạt hồn phách nhập Hô Phong Hoán Vũ giới và hấp thụ hương hỏa nồng đậm. Ngân Y Nữ Thi tự thoát khỏi khe trữ vật, bắt nuốt kim tuyến phân thân Lan Phi mà huyết kiếm không thể tổn thương, rồi cảnh báo hương hỏa là một âm mưu rất lớn. Vương Lâm chấn động, đối chiếu với lời chủ nhân Phong Giới, Thủy Đạo Tử, Lam Mộng Đạo Tôn, quyết tâm cảnh giác, tự nhủ cả đời chưa bao giờ dựa vào môn đồ hương hỏa. Xác định mục tiêu tiếp theo là đạo thiểm điện vạn năm bất diệt của Thiểm Lôi Tộc để lôi bổn nguyên tiến thêm bước lớn, phóng đi hướng Thiểm Lôi Tộc.","anchor":"Mặc kệ thật giả, việc này cần cực kỳ cảnh giác, cả đời ta tu đạo, cũng chưa bao giờ cần đến môn đồ hương hỏa gì","bridge":true,"khoang":"@c1251"},{"mucCt":"ky","text":"Đứng ngoài tinh vực Thiểm Lôi Tộc, nhờ đã hấp thụ sấm sét pho tượng ở thế giới bảy màu, nuốt Đạo quả, ngộ lôi bản nguyên nên xâm nhập lôi trì thành công. Tiến vào sâu nhất trong lôi trì, khoanh chân thổ nạp, khí tức hoàn toàn tiêu tán, dung hợp hoàn toàn với lôi trì trở thành một phần của nó. Ký hiệu tia chớp từ mắt phải phóng ra xuyên lôi trì, tất cả sấm sét nhường đường chỉ phương hướng. Tia chớp bay đến tu chân tinh màu vàng, phát hiện thanh niên hắc y Thiểm Lôi Tộc sắp chết đã tự kéo ký hiệu tộc trên mi tâm ra ngoài. Tia chớp phóng vào vết thương mi tâm, thực hiện đoạt xá thân xác thanh niên này.","anchor":"Sau đó tia chớp phóng thẳng lên miệng vết thương trên mi tâm người thanh niên","bridge":true,"khoang":"@c1252"},{"mucCt":"ky","text":"Một phần nguyên thần Vương Lâm đoạt xá thành công thân thể Vu Phi (thanh niên hắc y Thiểm Lôi Tộc đang hấp hối), ký hiệu tia chớp xuất hiện trên mi tâm, bản thể vẫn ở lôi vực dung nhập lôi trì. Lục ký ức Vu Phi để hiểu thân phận và hoàn cảnh. Nhận ra người Thái Cổ Tinh Thần tu vi nằm trong ký hiệu truyền thừa trên mi tâm, ký hiệu do mình tự sinh ra có cấp độ cao hơn nhiều so với ký hiệu Thiểm Lôi Tộc. Trên đường đến động phủ gặp ba tu sĩ Kết Đan (một nam áo trắng hậu kỳ, hai nữ sơ kỳ) ép Vu Phi bái kiến, chỉ dùng ánh mắt phá vỡ Kim Đan cả ba. Xâm nhập động phủ truyền thừa Vu Phi bị Tề Trì chiếm, cấm chế tự mở, đánh bại Tề Trì (Nguyên Anh sơ kỳ), dùng Sưu Thần Thuật lục ký ức lão, lấy hết pháp bảo đan dược, không giết vì luật tộc cấm chém giết sinh tử. Từ ký ức Tề Trì hiểu hệ thống Lôi Tinh và Thiểm Lôi Bảng — còn 7 năm nữa tranh đoạt suất vào thánh địa hấp thu sấm sét bất diệt. Kế hoạch dùng danh tính Vu Phi tích Lôi Tinh trong 7 năm để quang minh chính đại vào thánh địa.","anchor":"hắn dùng phương pháp đoạt xá để trở thành người của Thiểm Lôi Tộc, sau đó mới bắt đầu kế hoạch hấp thu luồng sấm sét bất diệt","bridge":true,"khoang":"@c1253"},{"mucCt":"ky","text":"Trong động phủ Tề Trì, bóp vỡ Lôi quả hấp thu lực lượng sấm sét vào nguyên thần để khảo sát, nhận định một Lôi quả đổi được một khối Lôi Tinh. Khi Khâu Đức Hải dẫn ba tu sĩ Kết Đan đến đòi cống nạp, bước ra bùng uy áp cực mạnh khiến bốn người bất lực hoàn toàn. Phá ký hiệu mi tâm ba Kết Đan khiến Kim Đan vỡ, phế tu vi, cướp pháp bảo. Truy đuổi Khâu Đức Hải thuấn di hơn mười lần gần mười vạn dặm, ép cả bốn trưởng lão Nguyên Anh dẫn đường về sơn môn. Tại sơn môn Thiên Lôi Tông, vung tay tạo cuồng phong phá ký hiệu mi tâm bốn Nguyên Anh, lấy sạch bảo vật ném bốn người xuống quảng trường. Nghe lời sùng bái cuồng nhiệt của tu sĩ Hóa Thần gầy mà nhớ tới Hứa Lập Quốc.","anchor":"hắn nhớ tới Hứa Lập Quốc","bridge":true,"khoang":"@c1254"},{"mucCt":"vua","text":"Hạ xuống quảng trường Thiên Lôi Tông, ra lệnh Chung Đại Hồng giao nộp toàn bộ vật đổi Lôi tinh rồi hất tay áo thu hết. Gọi Hứa Lập Quốc ra khỏi túi trữ vật, truyền thần niệm giao nhiệm vụ cướp vật đổi Lôi tinh. Tặng Hàm Hồn đan cho Chung Đại Hồng để buộc hắn sưu tập vật phẩm của Thiểm Lôi Tộc, tính kế không dùng đan dược mình đổi trực tiếp vì sẽ tăng thực lực cho Thiểm Lôi Tộc.","anchor":"Có lẽ để Hứa Lập Quốc đi cướp lấy những vật để đổi Lôi tinh thì thích hợp hơn so với ta","bridge":true,"khoang":"@c1255"},{"mucCt":"vua","text":"Vương Lâm ở lại Thiên Lôi Tông một tháng thổ nạp, sai Hứa Lập Quốc và Chung Đại Hồng quét bốn phía thu gom vật phẩm đổi Lôi tinh, đã gom được gần mười vạn. Nghiên cứu ngọc giản chứa công pháp Tụ Lôi Ấn của Thiểm Lôi Tộc, mục đích thực sự là điều tra tộc ấn vì mơ hồ cảm giác việc hấp thu sấm sét bất diệt cực kỳ quan trọng.","anchor":"Hắn mơ hồ cảm giác được vấn đề mình hấp thu sấm sét bất diệt là cực kỳ quan trọng","bridge":true,"khoang":"@c1256"},{"mucCt":"ky","text":"Vương Lâm lĩnh ngộ công pháp Tụ Lôi Ấn từ ngọc giản Thiểm Lôi Tộc, thử thi triển nén sấm sét ba vạn lần đạt cực hạn thân thể Vu Phi. Nguyên thần hắn đã thành sấm sét, vượt cả lão tổ Thiên Nhân Ngũ Suy của Thiểm Lôi Tộc. Nghiên cứu tộc ấn Thiểm Lôi Tộc hơn một tháng, phát hiện bên trong ký hiệu ẩn giấu ý chí đang ngủ say có thể hấp thu sấm sét từ tộc nhân. Cơ chế cực kỳ giống Môn Đồ Hương Hỏa — tộc nhân dâng tính mạng và sấm sét cho sấm sét bất diệt khi chết. Mở rộng suy đoán: toàn bộ Thái Cổ Tinh Thần có thể là vùng nuôi dưỡng của một tồn tại tu vi siêu việt, liên hệ đến thế giới Thủy Đạo Tử chứa hai mươi tỷ môn đồ, đại trận Phong giới, lời Ngân Y Nữ Tử về hương khói có độc, và Lam Mộng Đạo Tôn bị tiếng rống người Nội giới trọng thương. Kiên quyết tuyệt đối không tu luyện hương hỏa. Thu vật phẩm Chung Đại Hồng sưu tầm, ban cho hắn một viên thuốc, đồng ý đi đổi Lôi tinh tại Lôi Tinh Điện.","anchor":"Dù là thật hay giả thì hương hỏa này ta tuyệt đối không bao giờ tu luyện.","bridge":true,"khoang":"@c1257"},{"text":"Vương Lâm cùng Chung Đại Hồng đến Lôi Tinh Điện, ban đan dược và chỉ điểm tu vi cho thuộc hạ. Ánh mắt của hắn khiến Hắc Ma Pháp Vương run rẩy, sau đó hắn tiến vào khe nứt và chú ý đến sương mù xanh quanh cấm địa.","anchor":"Nhưng khoảnh khắc khi Vương Lâm quét mắt lên người thì tâm thần Hắc Ma Pháp Vương lập tức nhảy dựng lên toàn thân giống như đang run rẩy","mucCt":"vua","bridge":true,"khoang":"@c1258"},{"mucCt":"ky","text":"Đi qua khe nứt sương mù sấm sét dẫn đến Lôi Tinh Điện, nhận ra sương mù thực chất là sấm sét hóa thành bằng thuật đại thần thông, hiệu quả mơ hồ giống Hô Phong Hoán Vũ. Lợi dụng khe nứt mở ra khiến cấu trúc phòng hộ bộc lộ, bùng thần thức sấm sét xâm nhập áp chế hoàn toàn sương mù rồi thôi diễn ngược lại, học được tuyệt học thất truyền Hóa Lôi Vi Vụ của Thiểm Lôi Tộc — là người đầu tiên trong lịch sử làm được điều này nhờ nguyên thần chứa luồng sấm sét bất diệt. Dùng thần thức quét qua đại điện Lôi Tinh Điện, phát hiện tầng không gian thứ tư có chín cường giả đang thổ nạp: năm Khuy Niết, ba Tịnh Niết, một Toái Niết. Vào cửa đông, che giấu tu vi biến hóa thành Vấn Đỉnh trước mặt ba lão già canh ao, ném lượng lớn vật phẩm vào ao đen suốt nửa ngày để đổi Lôi tinh bằng ngọc giản mệnh hồn của Vu Phi. Chính thức lọt vào Thiểm Lôi Bảng vị trí 799 dưới tên Vu Phi với bốn mươi sáu vạn bốn ngàn Lôi tinh, gây xôn xao tộc nhân trên mười ba tu chân tinh.","anchor":"đã thấy được tất cả những thứ bên trong, học được một trong những tuyệt học thất truyền của Thiểm Lôi Tộc, Hóa Lôi Vi Vụ","bridge":true,"khoang":"@c1259"},{"mucCt":"ky","text":"Được ba lão già Dương Thực cửa đông Lôi Tinh Điện tặng tạo hóa theo quy củ: Tụ Lôi Hoàn nén 8900 lần, ngọc giản công pháp Thiểm Lôi Tộc mở rộng tộc ấn, ngọc giản lôi quang để nhận nhiệm vụ cửa tây. Được lão già thứ ba tiết lộ bí mật Lôi Lục Đạo — sấm sét chia sáu loại, và chỉ dẫn đi nhận nhiệm vụ Linh Niệm Lôi. Vào cửa tây xem nhiệm vụ, phát hiện bí mật kinh hoàng: tổ tiên Thiểm Lôi Tộc cùng Đệ Tam Bộ đại năng tạo bảy trăm vạn thế giới, đóng vai thiên đạo giáng thiên kiếp hủy diệt tu sĩ Hóa Thần đỉnh phong, tu sĩ thiên tài ngưng tụ Linh Niệm Lôi khi độ kiếp thực chất bị hình thần câu diệt. Nhận ra người tự xưng Thiên Đạo gặp khi chiến đấu với Vọng Nguyệt chính là tộc nhân Thiểm Lôi Tộc. Định chộp ngọc giản nhiệm vụ Linh Niệm Lôi nhưng Chu Thiên Tử chộp trước và quát Cút, trong mắt lóe sát ý.","anchor":"trong mắt đột nhiên lóe lên một luồng hàn quang khó thể phát hiện, đây là điềm báo hắn muốn giết người","bridge":true,"khoang":"@c1260"},{"mucCt":"ky","text":"Dùng thân phận Vu Phi đưa ngọc giản cho lão tu sĩ cửa Tây để được chấp nhận vào bảy trăm vạn thiên địa. Theo sau Chu Thiên Tử vào con đường, phá nát tất cả không gian loạn lưu, ung dung đuổi kịp. Chu Thiên Tử toàn lực hóa Lôi Long tấn công, Vương Lâm chỉ nhẹ vung tay phá tan, lộ tu vi vượt xa Toái Niết. Bản nguyên chiến ý của Chiến Tinh Dã đã ăn sâu vào gốc rễ tâm thần hắn, khiến hắn hiếu chiến hơn trước.","anchor":"Luồng bản nguyên chiến ý của Chiến Tinh Dã đã ăn sâu vào gốc rễ trong tâm thần Vương Lâm","bridge":true,"khoang":"@c1261"},{"mucCt":"ky","text":"Dùng thần thông qua ánh mắt kích nổ toàn bộ sấm sét trong cơ thể Chu Thiên Tử, phá tan thân xác và nguyên thần lão. Bóp nát nguyên thần Chu Thiên Tử khi lão cầu xin tha mạng, hấp thu sấm sét và lấy tộc ấn. Chu Thiên Tử trước khi chết kịp nhìn thấy hồn phách bị phong ấn trong cơ thể trong suốt của Vương Lâm và kêu lên không phải. Phá cửa vào bảy trăm vạn thiên địa, trở thành người ngoài đầu tiên xâm nhập trọng địa Thiểm Lôi Tộc kể từ đám tu sĩ thần bí năm xưa. Mạo danh Vu Phi, dùng ngọc giản tộc của Vu Phi qua kiểm tra, nhận linh phù, ngọc giản hướng dẫn và Linh Niệm Lôi. Nghiên cứu Linh Niệm Lôi, nhận ra nó giống một sinh linh chứa ý niệm sinh cơ, cần thu thập đủ một ngàn luồng mới thành niệm lôi hoàn chỉnh. Khi Trương Cảnh Vân tiếp cận dụ dỗ, Vương Lâm nhìn thấu sơ hở và ý đồ xấu nhưng giả vờ đồng ý đi theo, bị dẫn đến tổ hơn mười người trước trận pháp.","anchor":"Tất nhiên nếu so sánh về tâm trí thì sẽ không thể nào bằng","bridge":true,"khoang":"@c1262"},{"mucCt":"ky","text":"Vương Lâm cùng nhóm Trương Cảnh Vân tiến vào trận pháp, truyền tống vào bảy trăm vạn thiên địa. Hắn hóa thành một trong mười hư ảnh Tiên nhân trên kiếp vân, chứng kiến Trương Cảnh Vân đóng vai thiên đạo điều khiển sấm sét đánh xuống lão tu sĩ Vi Lỗ Bị đang độ kiếp. Nghe tu sĩ họ Chu giải thích sấm sét mạnh dần là để buộc tu sĩ sinh ra Linh Niệm Lôi, Vương Lâm tâm thần rung động mãnh liệt, nhận ra thiên kiếp hắn từng trải qua nhiều lần cũng đều do tu sĩ Lôi Tiên Giới hóa thân thiên đạo mà đánh xuống. Cảm giác đáng sợ tràn ngập trong lòng hắn, mơ hồ hiểu ra bản chất thật sự của thiên kiếp.","anchor":"hắn đã vượt qua nhiều thiên kiếp, tất cả cũng đều như thế này","bridge":true,"khoang":"@c1263"},{"text":"Trong bảy trăm vạn thiên địa, Vương Lâm bị Trương Cảnh Vân và nhóm tu sĩ Thiểm Lôi Tộc xem là mục tiêu cướp niệm lôi, nhưng hắn chế trụ Trương Cảnh Vân, tuyên bố chính mình là thiên đạo của bọn chúng rồi giết đối phương. Sau đó hắn dùng Cực cảnh như thiên kiếp giết các tu sĩ Vấn Đỉnh, phá ý đồ tự bạo, giết tu sĩ Âm Hư, lấy tộc ấn và rời đi trước sự chấn động của tu sĩ bản địa.","anchor":"Đám người các ngươi tự so mình với thiên đạo, tùy ý hàng lâm thiên kiếp… Như vậy ngày hôm nay ta chính là thiên đạo của các ngươi!","bridge":true,"khoang":"@c1264"},{"mucCt":"ky","text":"Bóp nát hơn mười tộc ấn Thiểm Lôi Tộc, dung hợp gần ngàn luồng Linh Niệm Lôi thành một luồng hoàn chỉnh hình quả cầu khói chứa nhiều gương mặt. Linh Niệm Lôi tự phóng xuyên mắt phải nhập nguyên thần, dung hợp sấm sét, khai mở ký ức lôi bản nguyên từ thuở thiên địa sơ khai. Trong ký ức thấy chín loại sấm sét quấn quanh nhau tạo đồ án quái dị chứa lôi bản nguyên chân chính. Âm thanh viễn cổ truyền vào nguyên thần minh ngộ: lôi có Cửu đạo chứ không phải Lục đạo, cộng lôi bản nguyên thành mười viên mãn thì đại thành, có thể đột phá Đệ Nhị Bộ thành Đệ Tam Bộ đại năng. Mắt phải xuất hiện tia chớp thứ hai nhỏ hơn vờn quanh ký hiệu gốc, mỗi vòng làm lôi bản nguyên tăng trưởng. Đã hấp thu loại sấm sét thứ chín (Linh Niệm Lôi), còn thiếu tám loại. Quyết định không giết tu sĩ độ kiếp mà giết tộc nhân Thiểm Lôi Tộc đoạt niệm lôi. Hóa gió bão sấm sét phạm vi vạn trượng tàn sát hơn ngàn tu sĩ Thiểm Lôi Tộc trong vài ngày, từ Vấn Đỉnh đến Khuy Niết Tịnh Niết đều hình thần câu diệt, thu bốn luồng lôi niệm hoàn chỉnh. Ngày thứ tư linh phù cảm ứng có người độ kiếp gần đó, thu gió bão thành vòng xoáy, cầm linh phù thuấn di về phía đó.","anchor":"Cửu lôi có hạn, bản nguyên vì vậy mà sinh, chín tiến lên mười, mười luồng viên mãn, bản nguyên đại thành","bridge":true,"khoang":"@c1265"},{"mucCt":"ky","text":"Dùng kế mồi nhử: lợi dụng người đàn ông trung niên Hóa Thần đỉnh phong đang độ kiếp để dụ Tiên nhân Thiểm Lôi Tộc qua lỗ hổng kiếp vân. Xé kiếp vân xuất hiện, giết Tiên nhân Khuy Niết hậu kỳ đại viên mãn bằng một ngón tay điểm ót, hình thần câu diệt, thu tộc ấn. Bóp nát hạt châu lôi quang, mắt phải hấp thu năm luồng niệm lôi, tia chớp liên tục xoay tròn trong mắt phải. Trong nửa canh giờ giết trên một trăm tộc nhân Thiểm Lôi Tộc. Giết một tu sĩ Toái Niết dùng thuật phân thân bỏ chạy bằng tia chớp đỏ (cực cảnh hóa thành), hủy nguyên thần, thu tộc ấn. Xác nhận hiện tại không phải bản thể nên không có cực cảnh trong người, chỉ dựa tu vi Toái Niết, nhưng có thể triệu hồi cực cảnh. Phát hiện Tán Linh Thượng Nhân ẩn trong hư không theo dõi, chĩa tia chớp đỏ ép hắn lộ diện, đe dọa sẽ giết nếu không giải thích lý do.","anchor":"Lúc này Vương Lâm không phải là bản thể nên cũng không có cực cảnh trong người, chỉ dựa vào tu vi Toái Niết mà muốn giữ lại lão già thì cũng có chút khó khăn","bridge":true,"khoang":"@c1266"},{"mucCt":"ky","text":"Phóng tia chớp hồng sắc xuyên mi tâm thanh niên đầu láng, kích bản thể Tán Linh hiện ra, nói rằng đúng như dự đoán. Bình tĩnh lắng nghe toàn bộ lai lịch Tán Linh và chân tướng bảy trăm vạn thiên địa là lao ngục sưu tập Linh Niệm Lôi, mắt lộ vẻ phức tạp. Cùng Tán Linh phá hư không phóng về tận cùng thế giới.","anchor":"Quả nhiên đúng như ta dự đoán","bridge":true,"khoang":"@c1267"},{"mucCt":"ky","text":"Nghe Tán Linh Thượng Nhân tiết lộ toàn bộ chân tướng bảy trăm vạn thiên địa: ngục tù do Thiểm Lôi Tộc tạo ra, thiên đạo thiên kiếp chỉ là nhiệm vụ thu hoạch Linh Niệm Lôi, mọi giai thoại tiên giới đều giả. Trầm mặc suy nghĩ rồi gật đầu đồng ý liên thủ, động lực chính không phải vì đại trưởng lão mà vì muốn giúp người này thoát khỏi ngục tù, muốn phá vỡ một thứ gì đó và chứng minh điều gì đó. Đề xuất kế hoạch: dùng linh phù huyết sắc tự do vào bảy trăm vạn thiên địa rồi dụ đại trưởng lão tới. Nhận linh phù huyết sắc từ Tán Linh tự hủy mấy vạn phân thân ngưng tụ. Nói lời từ biệt rồi phóng về quảng trường trung tâm, cưỡng bức xé rách trận pháp truyền tống đang vận chuyển để tiến vào, gây kinh hoàng cho tu sĩ Thiểm Lôi Tộc xung quanh.","anchor":"Quan trọng là hắn muốn giúp đỡ người này. Đây là một loại cảm giác, hắn muốn phá vỡ một cái gì đó","bridge":true,"khoang":"@c1268"},{"mucCt":"ky","text":"Xuất hiện giữa sấm sét trên bầu trời lãnh địa Thiểm Lôi Tộc, tuyên bố mình là chủ nhân của Hứa Lập Quốc. Thần thức cường giả Toái Niết viên mãn không thể phát hiện được hắn. Khi lão già áo xanh (Tịnh Niết) vô tình ngăn Hứa Lập Quốc, Vương Lâm xuất hiện bên cạnh lão, tùy ý điểm lên mi tâm khiến lão tan vỡ thân thể và diệt vong nguyên thần chỉ bằng một chỉ. Cường giả Toái Niết viên mãn khiếp sợ muốn bỏ trốn.","anchor":"tay phải tùy ý điểm lên mi tâm lão già","bridge":true,"khoang":"@c1269"},{"mucCt":"ky","text":"Vương Lâm giết tu sĩ Toái Niết bỏ chạy, thu Hứa Lập Quốc rồi xông thẳng thánh địa Thiểm Lôi Tộc, công khai tuyên bố tới thu sấm sét bất diệt và diệt tộc này. Hắn dùng nguyên thần làm mồi dụ đại trưởng lão vào lôi vực, phối hợp bản thể Cổ Thần, huyết kiếm, Tụ Lôi Ấn, Quang Ảnh Thuẫn, Cực Cảnh và lôi bản nguyên giao chiến sinh tử. Trong lúc bị tám hồn phách Thái Cổ Lôi Long vây công, hắn vận dụng Côn Cực Tiên, hóa Thôn Hồn thôn phệ hồn phách Lôi Long, khiến lôi bản nguyên và nguyên thần biến hóa mạnh thành lôi đồ đồ đằng tia chớp. Cuối cùng hắn bóp nát linh phù mở hắc động đi tới bảy trăm vạn thiên địa, kéo theo sấm sét bất diệt và đại trưởng lão truy sát vào trong.","anchor":"Hôm nay Vương Lâm ta đến đây, thu sấm sét bất diệt, diệt Thiểm Lôi Tộc của ngươi","bridge":true,"khoang":"@c1270"},{"mucCt":"ky","text":"Vương Lâm dùng linh phù dẫn đại trưởng lão Thiểm Lôi Tộc vào bảy trăm vạn thiên địa, cùng Tán Linh phá luồng sấm sét bất diệt và liên tiếp dùng lôi bổn nguyên, Phiên Thiên Ấn, Dịch Linh Ấn, Quang Ảnh Thuẫn để phối hợp phản kích. Khi Lục Đạo Thần Lôi áp xuống, hắn rút lực lượng hương hỏa có độc từ các hồn phách trong Hô Phong Hoán Vũ để phá vòng xoáy lôi, khiến đại trưởng lão hoảng sợ vì nhận ra lực lượng cấp Đệ Tam Bộ. Sau đó hắn nhận Trảm Thiên kiếm do Tán Linh ngưng tụ từ bảy trăm vạn thiên địa, dùng sinh mạng và ý niệm của vô số sinh linh chém liên tiếp nhiều kiếm, phá giáp truyền thừa, trọng thương đại trưởng lão và thề không dừng tay nếu đối thủ chưa chết.","anchor":"Vương Lâm ngẩng mạnh đầu, tay phải nắm chặt trường kiếm bảy thước rồi đột nhiên chém về phía trước.","bridge":true,"khoang":"@c1271"},{"mucCt":"ky","text":"Chém kiếm thứ sáu mang oán khí ngập trời, dẫn động hàng loạt oan hồn tu sĩ bị thiên kiếp giết trong bảy trăm vạn thiên địa thôn phệ toàn bộ máu thịt xương cốt đại trưởng lão Thiểm Lôi tộc. Bị Tam Tức Thuật của đại trưởng lão hút thọ nguyên, dùng Tuế nguyệt thuật nghịch chuyển ngàn năm đối kháng. Chém kiếm thứ bảy, trường kiếm bảy thước rời tay hóa cầu vồng phá nát tinh không, toàn bộ sinh linh bảy trăm vạn thiên địa hiến dâng tính mạng dung nhập vào kiếm. Kiếm quang đâm xuyên nguyên thần đại trưởng lão. Cuối cùng triệu Côn Cực Tiên phóng tới kết liễu nguyên thần đại trưởng lão đang sắp tử vong.","anchor":"hắn chém ra kiếm thứ bảy, đây là kiếm cuối cùng","bridge":true,"khoang":"@c1272"},{"mucCt":"ky","text":"Dùng Côn Cực Tiên hóa roi kim quang quét lấy nguyên thần đại trưởng lão Thiểm Lôi tộc (Thiên Nhân Đệ Ngũ Suy) đang sắp tiêu tán, chụp vào tay, đánh giá đây là cơ hội tạo hóa có thể dùng Tát Đậu Thành Binh và khai thác cảm ngộ sấm sét. Theo Tán Linh rời bảy trăm vạn thiên địa đang sụp đổ qua lỗ hổng tinh không, bước vào Thái Cổ Tinh Thần. Ngẩng đầu nhìn tinh không tự hỏi liệu có thật sự thoát khỏi lao ngục, nhớ lại cuộc luận đạo năm xưa cùng Lô Vân Tòng và Lý Thiến Mai về thiên địa là vòng tròn lớn. Nhận hơn một vạn Linh Niệm Lôi từ Tán Linh theo đúng thỏa thuận. Quyết định tấn công Thiểm Lôi tộc để thôn phệ sấm sét bất diệt, phân tích đại trưởng lão đã chết, hai Thiên Nhân Đệ Tứ Suy tu lôi không đáng sợ vì lôi bản nguyên của hắn đã kinh thiên động địa. Hóa thân sấm sét phóng về đại trận phòng hộ Thiểm Lôi tộc, sấm sét tinh không tự ngưng tụ quanh hắn như đế vương xuất hành. Con đường tu đạo đang hướng về truyền thuyết Đệ Tam Bộ không cần hương hỏa, tự lực bản nguyên đại thành.","anchor":"Con đường Vương Lâm tu đạo đang hướng về phía truyền thuyết này, hắn đang tiến từng bước đến gần","bridge":true,"khoang":"@c1273"},{"mucCt":"ky","text":"Vương Lâm kéo lôi vực áp sát đại trận phòng hộ Thiểm Lôi tộc, dùng Bát Long Hợp Nhất hợp chín hồn phách Thái Cổ Lôi Long thành lôi long khổng lồ để công phá trận pháp. Hắn tuyên bố đại trưởng lão Thiểm Lôi tộc đã tan thân, nguyên thần bị bắt, rồi triệu Côn Cực Tiên quấn tàn thần đại trưởng lão ra trước tộc nhân để đánh sập niềm tin của Thiểm Lôi tộc.","anchor":"Đại trưởng lão Thiểm Lôi tộc đã tan vỡ thân thể, nguyên thần bị ta bắt giữ","bridge":true,"khoang":"@c1274"},{"mucCt":"ky","text":"Vương Lâm đưa tàn thần Đại trưởng lão Thiểm Lôi Tộc bị Côn Cực Tiên quấn quanh ra trước toàn tộc, khiến niềm tin của Thiểm Lôi Tộc sụp đổ. Hắn nhân lúc hỗn loạn dùng huyết kiếm giết một tu sĩ Thiên Nhân Đệ Tứ Suy rồi cưỡi lôi long công phá thánh địa và miếu thờ. Khi sấm sét bất diệt bị vòng xoáy hư vô kéo đi, hắn tuyên bố đó là vật mình muốn đoạt, hóa thân Cổ Thần ngàn trượng để cưỡng ép kéo lại bất chấp lời uy hiếp từ trong vòng xoáy.","anchor":"Sấm sét bất diệt là vật mà Vương Lâm ta thích, đừng hòng kẻ nào muốn tranh giành","bridge":true,"khoang":"@c1275"},{"mucCt":"ky","text":"Vương Lâm giằng sấm sét bất diệt khỏi vòng xoáy và nhận ra cánh tay khổng lồ thuộc về kẻ năm xưa cướp hồn phách Uyển Nhi. Hắn bộc phát lực lượng Cổ Thần, hỏa lam sắc, lôi long, huyết kiếm và chiến ý để chém đứt bàn tay sứ giả thiên đạo. Sau khi vòng xoáy rút lui, hắn thề tương lai phá vỡ thiên địa báo thù cho hiền thê, rồi dùng Súc Địa Thành Thốn bắt và nuốt sấm sét bất diệt nhằm luyện hóa cho lôi bản nguyên đại thành.","anchor":"Chính là các người! Năm xưa cướp đi hồn phách của Uyển Nhi","bridge":true,"khoang":"@c1276"},{"mucCt":"ky","text":"Vương Lâm đi vào đô thành phàm tục ở hướng tây, tìm hiểu cách người nơi đây dùng Phàn Tinh giao dịch, rồi dùng nguyên thần dò xuống lòng đất để lấy Phàn Tinh cất vào không gian trữ vật. Hắn mua một căn nhà ở khu thành tây, tạm nhập vai học trò nghèo chờ kỳ thi năm sau và cảm nhận một đêm đời thường yên tĩnh giữa khói bếp, tiếng trẻ con cùng rượu gạo lão chủ quán tặng. Trong căn nhà đơn sơ, hắn vận chuyển lôi bản nguyên và hỏa bản nguyên, dùng biển lửa lam sắc cùng hư ảnh Chu Tước luyện hóa tám Thái Cổ Lôi Long bị giam trong nguyên thần. Sau khi rượu gạo hóa thành trợ lực hỏa diễm, hắn lần lượt thôn phệ dung hợp bảy con, cuối chương chỉ còn một Thái Cổ Lôi Long chưa bị luyện hóa.","anchor":"Tám Thái Cổ Lôi Long đã bị Vương Lâm ta thôn phệ và dung hợp hết bảy","bridge":true,"khoang":"@c1277"},{"mucCt":"ky","text":"Trong cơn mưa trên thành trì phàm nhân, Vương Lâm nhớ lại tuổi thơ trên Chu Tước tinh và nhận ra Trường Tôn Hội đã nhanh chóng phát lệnh truy sát hung thủ diệt Thiểm Lôi Tộc. Hắn lập tức luyện hóa con Thái Cổ Lôi Long cuối cùng, để đủ tám con dung nhập nguyên thần, làm lôi bản nguyên tăng mạnh và nguyên thần hóa thành tia chớp nối liền thiên địa trong cơ thể. Sau đó hắn thả sấm sét bất diệt ra, dùng nguyên thần lôi đình thôn phệ và thi triển Đạo thuật Dung hợp để hướng tới lôi bản nguyên đại thành.","anchor":"Đến lúc này thì tám con Thái Cổ Lôi Long đều bị dung hợp vào trong nguyên thần Vương Lâm","bridge":true,"khoang":"@c1278"},{"mucCt":"ky","text":"Vương Lâm ẩn trong căn nhà lụp xụp ở thành tây, vừa tiếp tục thôn phệ sấm sét bất diệt vừa phát hiện thuật tộc ấn dò xét quét tới. Hắn vung tay làm hình ảnh căn nhà vặn vẹo như gương vỡ, khiến lão già đạo bào không phát hiện được mình rồi rời đi. Sau khi luyện hóa hoàn toàn ý chí trong sấm sét bất diệt, lôi bản nguyên của hắn tăng mạnh, riêng lực lượng sấm sét đạt tới Toái Niết hậu kỳ. Hắn còn nhìn thấy ba hình ảnh ký ức cổ xưa về kiếp nạn tan vỡ, người đàn ông có đồ án hoa bảy cánh và miếu thờ Thiểm Lôi Tộc, rồi chấn động khi thủ lĩnh có kim quang xoay người.","anchor":"Vương Lâm vẫn đang khoanh chân ngồi trong căn nhà lụp xụp, nguyên thần đang điên cuồng thôn phệ luồng sấm sét bất diệt","bridge":true,"khoang":"@c1279"},{"mucCt":"ky","text":"Vương Lâm nhận ra ánh sáng năm màu trong mắt trái nam tu sĩ lạ là Cực Cảnh, liên hệ ngay tới Nạp Đa và Côn Cực Tiên để suy đoán giữa Nội giới, Chu Tước tinh và đám tu sĩ thần bí có bí mật lớn. Hắn kiểm nghiệm dị biến lôi bản nguyên, phát hiện khi vận dụng sấm sét thì tu vi vượt Toái Niết trung kỳ lên Toái Niết hậu kỳ, còn khi không dùng lôi lực vẫn ở Toái Niết trung kỳ. Sau đó hắn rời phòng trong đêm mưa mua rượu, âm thầm cắt một phần nguyên thần lão già đạo bào để đọc ký ức, biết Thái Cổ Tinh Thần đang truy tìm diện rộng và thần thông của Vân Lạc có thể suy tính vị trí của hắn. Cuối cùng hắn nuốt nguyên thần đại trưởng lão Thiểm Lôi tộc, khiến nguyên thần sấm sét biến hóa và gọi sáu loại lôi xuất hiện.","anchor":"Vương Lâm quen với Nạp Đa thì cũng chính thức biết được chính mình đã mở ra một cánh cửa lớn cho cực cảnh","bridge":true,"khoang":"@c1280"},{"mucCt":"ky","text":"Vương Lâm triệu Lôi Lục đạo từ khe nứt trong nguyên thần, khiến lôi quang bùng ra và suýt làm lộ tung tích trên tu chân tinh. Hắn lập tức rời căn nhà tới sơn cốc sâu trong Thập Vạn đại sơn để luyện hóa, giữa lúc nhiều nhóm tu sĩ bắt đầu truy dấu. Trong khi cuộc lục soát mở rộng, hắn hấp thu toàn bộ Linh Niệm lôi do Thiểm Lôi tộc tích lũy, làm nguyên thần sấm sét và lôi tu tăng mạnh, đồng thời kiên quyết không tu luyện hương hỏa.","anchor":"Dù thế nào cũng không nên tu luyện hương hỏa!","bridge":true,"khoang":"@c1281"},{"mucCt":"ky","text":"Vương Lâm ẩn thân trong Thập Vạn Đại Sơn, lần lượt luyện hóa Thiên Ẩn lôi, Địa Dung lôi, Nguyên Hóa lôi, Từ Hợp lôi và Đạo Ý lôi, nhờ đó phá Toái Niết hậu kỳ để tiến vào Toái Niết đại viên mãn. Không tìm được ba luồng sấm sét cuối, hắn tự định Cực cảnh làm luồng thứ bảy, phong Lôi Oa thành Huyết Mạch lôi thứ tám, rồi lấy cả đời nghịch tu hóa thành Nghịch mệnh lôi thứ chín. Khi chín luồng sấm sét quanh lôi bản nguyên hoàn chỉnh, Không Đại Môn của Đệ Tam Bộ hiện ra và hắn quyết định thử đánh vỡ cánh cửa ấy.","anchor":"tu vi Vương Lâm đột nhiên phá tan cánh cửa Toái Niết hậu kỳ để tiến lên Toái Niết đại viên mãn","bridge":true,"khoang":"@c1282"},{"mucCt":"ky","text":"Vương Lâm xé cấm chế ẩn thân, hiện thân giữa thiên địa rồi dùng lôi bản nguyên đại thành gọi lôi đồ công kích cánh cửa Không Chi, khiến cánh cửa xuất hiện khe nứt nhỏ nhưng bản thân bị phản chấn trọng thương. Sau đó hắn dẫn sấm sét dung nhập Thập Vạn Đại Sơn, hóa thành mười vạn lôi sơn trấn áp vài vạn tu sĩ và dùng Súc địa Thành Thốn rời khỏi chiến trường. Trong tinh không, hắn nhận ra một luồng bản nguyên đại thành chưa đủ phá vách ngăn Đệ Tam Bộ, nên xác lập quyết tâm dùng hai, thậm chí năm luồng bản nguyên đại thành để phá cửa.","anchor":"Nhưng nếu một luồng bản nguyên đại thành không thể làm gì được thì ta sẽ dùng hai bản nguyên đại thành để đánh vỡ vách ngăn.","bridge":true,"khoang":"@c1283"},{"mucCt":"ky","text":"Dấu vết Không Môn của Vương Lâm khiến Tư Mặc Tử nhận ra hắn không dựa vào hương hỏa mà chỉ bằng bản nguyên đại thành vẫn làm Không Môn xuất hiện. Lam Mộng Đạo Tôn và cô gái hắc y Phiêu Miễu tộc cũng bị dị tượng này làm chấn động. Vương Lâm dựa vào ký ức truyền thừa để vào Điên Lạc Địa, dùng đan dược đổi động phủ trăm năm và bế quan chữa thương thì cuối chương có người bước vào động phủ.","anchor":"Hắn không dựa vào hương hỏa, chỉ dựa vào bản nguyên đại thành mà làm cho Không Môn xuất hiện","bridge":true,"khoang":"@c1284"},{"mucCt":"ky","anchor":"Ngươi là người của ta, người có thể nhịn nhưng ta không thể nhịn được","text":"Vương Lâm tiếp tục ẩn tại tu chân tinh trong Thái Cổ Tinh Thần, để Chung Đại Hồng ra ngoài dò tin và mua con rối. Khi Chung Đại Hồng trọng thương trở về, hắn nhìn ra đối phương bị chặt đứt quỹ tích vận chuyển tu vi trong cơ thể và còn bị lưu lạc ấn thần thức. Hắn tuyên bố Chung Đại Hồng là người của mình nên không thể nhịn, lập tức mang Chung quay lại thành trì Ám Hạt Tộc. Tại đó, hắn cho tu sĩ trong thành ba hơi thở rời đi rồi dẫn lôi đình phá tan thành trì, làm đại điện nổ tung và bảo tháp dưới đất lộ ra.","bridge":true,"khoang":"@c1285"},{"mucCt":"vua","anchor":"Từ nay về sau, người Ám Hạt Tộc tôn ta là chủ nhân","text":"Vương Lâm trấn sát nam tử trung niên Ám Hạt Tộc, phá bảo tháp, phong ấn thiếu chủ cùng nhiều tộc nhân rồi áp đảo lão giả thiên nhân đệ nhị suy. Hắn buộc toàn bộ Ám Hạt Tộc phát lời thề tộc ấn quy phục, sau đó hỏi tin Điên Lạc, hệ thống con rối, Hỏa Tước tộc và nhận ra Viêm hỏa dị tinh liên hệ nguồn gốc Tứ Thánh Tông.","bridge":true,"khoang":"@c1286"},{"mucCt":"ky","text":"Vương Lâm nhận ra Viêm hỏa dị tinh giống hòn đá trắng của Chu Tước Thánh Tông, nhớ lại ân tình Chu Tước lão Thánh Hoàng và suy đoán Điên Lạc có thể liên quan tới Thánh Hoàng đời thứ tư. Hắn thu dị tinh, nghiên cứu con rối Ám Hạt Tộc, phát hiện nó vốn là tu sĩ bị tế luyện, dùng lôi đồ cùng Định thân thuật phá tầng phòng hộ để thấy nguyên thần bên trong. Sau khi con rối nổ tung, hắn liên hệ tinh thể trong thân nó với tinh thể ở vết thương đầu lâu Cổ Thần rồi rời động phủ, lệnh Kiệt trưởng lão dẫn tới tu chân tinh của trưởng lão Lạc Sinh hội gần nhất.","anchor":"Vương Lâm đã lập tức nhận ra vật ấy","bridge":true,"khoang":"@c1287"},{"mucCt":"ky","text":"Được lão giả Ám Hạt Tộc dẫn tới chủ tinh Long Giáp Tộc để tìm mua con rối cao giai và Viêm hỏa dị tinh, Vương Lâm nhận ra Tư Mặc Tử là một trong ba tu sĩ bước thứ ba từng truy đuổi Thác Sâm. Hắn phán đoán đối phương bám tới để giết mình nhưng còn kiêng kỵ Điên Lạc đại đế, nên đổi ý không chỉ mua vật mà chuẩn bị ở Long Giáp Tộc đánh một trận với đối phương.","anchor":"Hắn tới đây vốn là định mua một ít con rối cao giai về nghiên cứu, nếu có thể gặp Viêm hỏa dị tinh thì cũng mua một ít.","bridge":true,"khoang":"@c1288"},{"mucCt":"ky","anchor":"Ta ở nơi này chờ ngươi, có dám đánh một trận không","text":"Tại lầu giao dịch Long Giáp Tộc, Vương Lâm dùng tiếng hừ và ánh mắt trấn áp lão giả Hỏa Tước tộc thiên nhân đệ tam suy, rồi dùng hồn đan chứa hỏa bổn nguyên đổi Viêm hỏa dị tinh và Băng long đan để làm mồi kéo Hỏa Tước tộc vào cuộc. Hắn luyện một vạn Băng long đan bằng Đạo thuật Dung, hỏa diễm, lôi đình, máu Cổ Thần và tinh khí nguyên thần thành đan sát thương có thể uy hiếp thiên nhân đệ ngũ suy. Sau đó hắn luyện Viêm hỏa dị tinh thành tinh thể hỏa hệ, phá một phần phong ấn cuối của đoạn kiếm lộc cốt, rồi công khai khiêu chiến Tư Mặc Tử trước toàn tu chân tinh.","bridge":true,"khoang":"@c1289"},{"mucCt":"ky","text":"Vương Lâm đứng trên đỉnh núi tu chân tinh chờ Tư Mặc Tử, được chương khắc họa là người sau hai ngàn năm tu đạo đã có phong phạm đại tông sư và đủ tư cách khiêu chiến phân thân tu sĩ bước thứ ba chỉ có tu vi Thiên Nhân đệ ngũ suy. Khi Tham Lang trọng thương không còn điều khiển phiến lá phong ấn, hắn bước ra, chụp lấy phiến lá, rồi giao chiến trực diện với Tư Mặc Tử. Trong trận, hắn thi triển Sơn Băng thuật, hút toàn bộ sơn hồn của tu chân tinh để khiến thuật này viên mãn, phát động đệ cửu băng và sau đó nhận ra thần thông của Tư Mặc Tử có liên hệ Phá Thiên tông cùng Tư Mã Mặc.","anchor":"Đồng tử nhỏ bé hai ngàn năm tu đạo giờ đã đứng trên đỉnh của tu chân giới","bridge":true,"khoang":"@c1290"},{"mucCt":"ky","text":"Vương Lâm bị Tư Mặc Tử nhốt trong Phá Thiên Đạo nhưng hét tên Tư Mã Mặc để làm đối phương khựng nhịp. Hắn nhân cơ hội tung gần bốn ngàn vạn đạo kiếm khí trọng thương phân thân Tư Mặc Tử, rồi tự hóa thành kiếm khí phá sập thiên địa thần thông và lao ra ngoài. Sau đó hắn thi triển Phiên thiên thần thông, dùng thiên địa đối lại thiên địa để nén Tư Mặc Tử, trước khi Đại đế đặt hạn năm nhịp thở cho trận chiến.","anchor":"Vương Lâm sau khi lao ra thân thể nhoáng lên","bridge":true,"khoang":"@c1291"},{"mucCt":"ky","text":"Trong trận chiến giới hạn năm nhịp thở, Vương Lâm liên tiếp dựng Quang ảnh thuẫn chống Tuế Nguyệt cấm và chưởng ấn của Tư Mặc Tử. Hắn dùng lôi bổn nguyên kết thành lôi đồ vạn trượng, hòa thân vào lôi đồ phá nát cấm chế, đánh Tư Mặc Tử trọng thương rồi tự nghịch chuyển trạng thái già nua do Tuế Nguyệt quét qua. Trước khi tiếng bốn kết thúc, hắn tiếp tục truy kích bằng cách kích nổ viên đan dược màu vàng và Viêm hỏa dị tinh bị áp súc ở cự ly gần.","anchor":"Không đợi cho đan dược này tới gần thêm, Vương Lâm không chút do dự gầm lên","bridge":true,"khoang":"@c1292"},{"mucCt":"ky","text":"Vương Lâm dùng chuỗi sát chiêu gồm Viêm hỏa dị tinh và huyết kiếm khiến phân thân Tư Mặc Tử trọng thương, rồi bị biến cố từ hư vô chen vào khi đối phương định bỏ chạy. Hắn thu ngân y nữ tử, kiểm tra pháp bảo của Tham Lang, giữ chín mươi chín thanh phi kiếm Cổ Yêu cho phân thân thứ hai, sau đó kéo tới Long Giáp Tộc tính sổ vì tộc trưởng từng giúp Tư Mặc Tử. Cuối chương, sứ giả của đại đế xử phạt tộc trưởng Long Giáp Tộc và cung kính tham kiến hắn là “thiếu đế”.","anchor":"Thuộc hạ tham kiến thiếu đế","bridge":true,"khoang":"@c1293"},{"chuong":"@c1294","importance":"normal","mucCt":"ky","tieuDe":"Được phong thiếu đế","text":"Vương Lâm được sứ giả Điên Lạc đại đế tuyên bố là thiếu đế do đại đế lựa chọn, địa vị tại vùng đất Điên Lạc cao hơn cả mười ba trưởng lão. Hắn tha mạng cho Thiếu tộc trưởng Long Giáp Tộc sau khi người này bị phế, chỉ định thanh niên Khuy Niết làm tân tộc trưởng, buộc Long Giáp Tộc giao Băng long đan, Viêm hỏa dị tinh và con rối. Sau đó hắn nhận ngọc bội chữ “đế” làm tín vật thân phận và được truyền lời mời dự tuyển chọn trưởng lão Lạc Sinh hội sau ba tháng.","anchor":"Đại đế đã truyền lệnh xuống, báo cho tất cả tộc lạc tại vùng đất Điên Lạc, ngài là thiếu đế do đại đế lựa chọn"},{"chuong":"@c1295","importance":"bridge","mucCt":"ky","tieuDe":"Bóng ma của Tham Lang","text":"Vương Lâm bị Tham Lang xem là kẻ thù và khắc tinh lớn nhất vì từng đoạt nhiều pháp bảo của hắn, khiến nỗi sợ của Tham Lang ở giới ngoại trở thành khe hở đạo tâm.","anchor":"Mà trọng yếu nhất là Vương Lâm nọ"},{"mucCt":"ky","text":"Vương Lâm rời tu chân tinh Long Giáp Tộc, mang theo toàn bộ tích lũy của tộc này gồm Băng long đan, Viêm hỏa dị tinh và nhiều con rối. Hắn suy xét việc Điên Lạc đại đế giết phân thân Tư Mặc Tử, ban danh hiệu thiếu đế, đưa ngọc bội và hẹn mình ba tháng sau tới Lạc Sinh hội, rồi quyết định sẽ đi xem mục đích thật của đối phương. Khi quay về tu chân tinh Ám Hạt Tộc, hắn xuất hiện đúng lúc Tham Lang đang khoe pháp bảo, khiến Tham Lang hoảng sợ bỏ chạy ngay cả pháp bảo cũng không kịp thu hồi.","anchor":"Thân ảnh Vương Lâm từ trong thiên địa đi ra cũng vô cùng sửng sốt","bridge":true,"khoang":"@c1296"},{"mucCt":"ky","text":"Vương Lâm bất ngờ thấy Tham Lang ở Thái Cổ Tinh Thần dù từng cho rằng đối phương đã chết trong Vọng Nguyệt. Hắn không truy đuổi ngay mà dùng đại thủ và nguyên thần tinh khí lần lượt thu chín mươi chín phi kiếm, Hộ Cốt Cửu Bi, Vụ Ma Thương, Thiên Hoàng Lô và Táng Thiên Mộc Linh do Tham Lang bỏ lại. Trong lúc kiểm tra, hắn nhận ra Vụ Ma Thương có khí tức Cổ Ma, Thiên Hoàng Lô liên quan Cổ Yêu, rồi lấy Đế lệnh ra buộc hơn ngàn tu sĩ ở lại nghe Chung Đại Hồng trước khi rời khỏi tu chân tinh.","anchor":"Vương Lâm chưa bao giờ ngờ được là ở Thái Cổ Tinh Thần lại có thể thấy Tham Lang","bridge":true,"khoang":"@c1297"},{"mucCt":"ky","text":"Vương Lâm dùng gợn sóng không gian truy kích Tham Lang nhưng bị Nhất diệp phong thiên cản lại, sau đó đổi cách vòng qua phong ấn. Nhờ Huyết kiếm làm Tham Lang trọng thương, hắn đoạt phiến lá khô, phong ấn rồi cất đi. Khi Tham Lang gọi ba trăm ma hồn Cổ Ma, hắn nhận ra dấu vết Cổ Thần lực, dùng tiếng rống Cổ Thần phá tan ma phong và suy ra đầu mối về nơi Tham Lang lấy được pháp bảo.","anchor":"Ánh mắt Vương Lâm lộ vẻ mừng rỡ như điên, bước từng bước về phía Tham Lang","bridge":true,"khoang":"@c1298"},{"mucCt":"ky","text":"Vương Lâm không mắc bẫy truy sát ngay mà đổi hướng thu bình ngọc màu tím, rồi dùng súc địa thành thốn tiếp tục đuổi theo Tham Lang. Trong lúc truy đuổi, hắn nhận ra pháp bảo của Tham Lang đều liên quan ba đại cổ tộc và xem nơi phát sinh cơ duyên đó là cơ hội lớn đối với mình. Khi Tham Lang gọi yêu lang bằng yêu khí Cổ Yêu, Vương Lâm hóa Cổ Thần lục tinh, ngưng huyết kiếm chém đôi yêu lang, sau đó dùng Định khống chế Tham Lang để hỏi chuyện thay vì giết ngay.","anchor":"Tham Lang này đúng là phúc tinh trên đường tu đạo của Vương Lâm ta","bridge":true,"khoang":"@c1299"},{"mucCt":"ky","anchor":"Thân thể Vương Lâm trong khi di động dần dần thu nhỏ lại.","text":"Vương Lâm dùng Định thân thuật khống chế Tham Lang, thu lấy pho tượng bị tàn phá và bị pho tượng kéo vào dị tượng tâm thần về tinh không sụp đổ, hư vô cùng đại lục vô biên. Hắn ép Tham Lang khai lai lịch cổ mộ, các pháp bảo và con đường ra ngoài Phong Giới Đại Trận. Khi Tham Lang bỏ chạy, hắn bắt lại, dùng thần thức cùng bổn nguyên lôi đình sưu ký ức để xác nhận lời khai, rồi tha mạng và âm thầm xóa mùi thối do Vọng Nguyệt để lại trên người Tham Lang.","bridge":true,"khoang":"@c1300"},{"mucCt":"ky","text":"Vương Lâm giữ Vân Độn tộc trên tu chân tinh, dựng động phủ và đặt nhiều tầng cấm chế để bế quan. Hắn nhớ kỳ tuyển chọn trưởng lão Lạc Sinh hội sau ba tháng, xác định trọng tâm không phải chức vị mà là lợi dụng biến cố này nhằm Hỏa Tước tộc. Thông qua giọt máu có tia bổn nguyên trong hồn đan, hắn cảm ứng vị trí của vật mồi và chuẩn bị bước hai bằng cách gọi Hứa Lập Quốc cùng Lưu Kim Bưu ra.","anchor":"Đến lúc đó phối hợp với kế hoạch của ta thì việc thu được hỏa bổn nguyên của Hỏa Tước tộc hẳn sẽ thành","bridge":true,"khoang":"@c1301"},{"mucCt":"ky","text":"Vương Lâm nhận ra giá trị của Lưu Kim Bưu, hứa trả tự do và cho cơ duyên nếu hắn lừa được một bộ tộc, rồi dùng ngọn lửa màu lam từ mắt trái để cấy ký ức Chu Tước đời sáu cho hắn. Sau khi phái Lưu Kim Bưu và Hứa Lập Quốc rời đi, hắn xác nhận mồi câu thứ hai đã được thả nhằm vào Hỏa Tước tộc, rồi lấy pho tượng đoạt từ Tham Lang ra nghiên cứu và gọi Ngân y nữ tử tới nhận diện.","anchor":"Mồi câu thứ hai đã được thả ra rồi. Hỏa Tước tộc, các người đừng để ta thất vọng","bridge":true,"khoang":"@c1302"},{"mucCt":"ky","anchor":"Lần thi triển pháp thuật này hắn không thu được chút ký ức nào của nữ tử nhưng lại có thu hoạch rất lớn","text":"Trong động phủ trên tu chân tinh Ám Hạt Tộc, Vương Lâm lấy pho tượng ra hỏi ngân y nữ tử, khiến nàng hoảng loạn rồi bộc phát thanh khí tấn công. Hắn dùng vòng xoáy nguyên lực, lôi đồ, huyết kiếm để phá chưởng ấn, cưỡng ép bắt một quả cầu thanh khí, sau đó Sưu thần ngân y nữ tử và phát hiện thân ảnh trung niên áo bảy màu do phong ấn biến thành trong thức hải nàng. Hắn liên hệ chuỗi bí mật bảy màu với Thiên Vận Tử, Chưởng Tôn, Thất Thải Giới và Thất Thải Thần Không Đinh, tạm gác nghi vấn để luyện hóa nhóm pháp bảo của Tham Lang, nhận Hộ cốt Thạch Bi, dung hợp Thiên Hoàng Lô vào tinh điểm Cổ Thần thứ nhất, đồng thời nảy ý dùng ma hồn cùng thân thể Cổ Ma để tạo phân thân thứ ba.","bridge":true,"khoang":"@c1303"},{"mucCt":"ky","text":"Ở động phủ tại Ám Hạt Tộc, Vương Lâm bế quan luyện hóa Ma Hồn bình, dùng Đạo thuật Dung hợp nhất ma hồn thành kén trong bảy ngày. Khi kén phản kháng bằng ý chí Cổ Ma, hắn dùng máu chứa bổn nguyên lực và máu Cổ Thần để huyết luyện, khiến kén chuyển sang huyết sắc. Sau đó hắn tiếp tục dẫn ma hồn trong bình cho kén hấp thu, xác định pháp bảo này chứa ba nghìn hồn phách Cổ Ma và đặt mục tiêu dung hợp chúng thành hồn phách Cổ Ma của riêng mình.","anchor":"Trong pháp bảo của Cổ Ma này ẩn chứa tới ba nghìn hồn phách của Cổ Ma","bridge":true,"khoang":"@c1304"},{"mucCt":"vua","text":"Vương Lâm được Ám Hạt Tộc và Vân Độn tộc hộ tống tới ngoài Đại đế tinh, quan sát lực lượng từ lực và lực giằng xé bao phủ nơi tuyển chọn trưởng lão Lạc Sinh hội. Khi bị tộc trưởng Hà tộc bắt quỳ, hắn bình thản hỏi ngược, rồi được Long Giáp Tộc và sứ giả đại đế công khai hướng tới trước mắt các tộc.","anchor":"Vương Lâm mĩm cười nhìn lão giả vừa nói, chậm rãi cất lời","bridge":true,"khoang":"@c1306"},{"mucCt":"ky","text":"Vương Lâm được sứ giả đại đế và đoàn tu sĩ cung kính bái kiến là thiếu đế trước mấy vạn tu sĩ, rồi bình tĩnh nhận lễ và được mở thông đạo Đại đế tinh sớm. Hắn xử phạt Hồn Xà tộc, tước vị trưởng lão Lạc Sinh hội của tộc trưởng Hà tộc, đày người này tới tu chân tinh Ám Hạt Tộc quỳ phạt trăm năm, đồng thời buộc tộc trưởng Vân Độn tộc tự phế một tay vì từng dẫn họa về phía hắn. Khi Tư Mặc Tử xuất hiện cùng Vân Lạc, hắn gọi đối phương là bại tướng, khiêu khích vào sương mù từ lực tự hủy tu vi rồi lạnh lùng mắng Vân Lạc không biết lớn nhỏ.","anchor":"Thần sắc Vương Lâm bình tĩnh, nhìn về mấy tu sĩ đang bái kiến mình, khẽ gật đầu","bridge":true,"khoang":"@c1307"},{"mucCt":"ky","text":"Vương Lâm cảnh giác khi nữ tử Trường Tôn hội liên tục hỏi tên, cố ý dùng tên Hứa Mộc để tránh thuật pháp dựa vào tên thật. Hắn tiếp tục thử thái độ đại đế bằng cách yêu cầu cho tộc trưởng Ám Hạt Tộc thành trưởng lão Lạc Sinh hội và nhận ra đại đế không coi trọng hội này. Sau khi lên Đại đế tinh, hắn tự dò xét trường đấu, dùng Lôi đồ ép cấm chế hiện hình thành rùa khổng lồ và xác nhận đó là Cổ Hồn cấm liên quan tới mãnh thú.","anchor":"Hắn cho dù chưa từng nghe thấy thần thông nào thi triển dựa vào tên tuổi","bridge":true,"khoang":"@c1308"},{"mucCt":"ky","text":"Vương Lâm phát hiện Đại đế tinh có Cổ Hồn cấm, từ đó nghĩ tới khả năng gom đủ tứ đại cấm để chạm tới bốn nguyên cấm chế và mở thêm bổn nguyên. Hắn nhanh chóng chuyển sang cảnh giác với đại đế, dùng ký ức Thiên Nghịch cùng Lưu Nguyệt để xét bùn đất rồi suy đoán tinh cầu này có thể do thần thông tạo thành. Sau khi nhận ra lá cây có dấu hiệu hút nguyên lực, hắn rời đi quan sát và gặp lão giả mặc bạch y câu cá bên hồ.","anchor":"Nếu có thể học được toàn bộ tứ đại cấm","bridge":true,"khoang":"@c1309"},{"mucCt":"ky","text":"Vương Lâm uống thứ trong bầu của lão giả, sau mới biết đó là máu Viêm long, khiến hỏa bổn nguyên trong cơ thể nồng đậm hơn và nguyên lực tăng thêm một tia. Hắn chứng kiến lão giả câu lên Viêm long có uy áp ngang tu sĩ bước thứ ba, dùng bầu hứng máu từ đầu rồng rồi hút luôn phần máu còn sót để khỏi lãng phí. Sau khi luyện hóa, hắn bị lão giả kiểm tra và xác nhận là tộc nhân Chu Tước đời thứ sáu, đồng thời có thân thể Cổ Thần.","anchor":"Trong nháy mắt vừa rồi hắn cảm thấy hỏa bổn nguyên trong cơ thể lại nồng đậm hơn một chút","bridge":true,"khoang":"@c1310"},{"mucCt":"ky","text":"Vương Lâm bị Chu Tước đời thứ hai đặt tay lên thiên linh kiểm tra, lần lượt hiển lộ hỏa, lôi, sinh tử, nhân quả và chân giả bổn nguyên. Sau một đêm hấp thu máu rồng, lực hỏa diễm trong cơ thể hắn tăng rõ rệt nhưng vẫn còn thiếu một tia để đạt lần thức tỉnh thứ tư của Chu Tước. Khi tỉnh lại, hắn được xác nhận là người của Chu Tước tộc, được khuyên lấy Tư Mặc Tử để lập uy và chuẩn bị học bí thuật vận lực lấy từ mạch Huyền Vũ.","anchor":"Ngơ ngác nhìn năm đạo bổn nguyên bất đồng lơ lửng trên thiên linh Vương Lâm","bridge":true,"khoang":"@c1311"},{"mucCt":"ky","text":"Vương Lâm quan sát Lão Chu Tước đánh xuống hồ rồi tự đặt tay lên mặt nước để cảm nhận lực phản chấn. Từ phản lực rất yếu của nước và đạo lý nước nhỏ giọt xuyên đá, hắn suy ra khi một quyền đánh ra có thể mượn chính phản lực của vật bị công kích để tăng uy lực và khiến hình thái vật chất sụp đổ biến đổi. Hắn nhận ra bí thuật này đặc biệt hợp với thân Cổ Thần của mình, đồng thời nhớ lại trận với Thác Sâm và thừa nhận mình từng kém xa về cách vận dụng lực lượng. Sau khi lĩnh ngộ xong, hắn được Lão Chu Tước cuốn bằng hư hỏa tới trường đấu phía tây bắc để chuẩn bị thí luyện.","anchor":"Trong tích tắc khi bàn tay đánh xuống mặt hồ, Vương Lâm rõ ràng cảm nhận được một lực phản chấn truyền lại.","bridge":true,"khoang":"@c1312"},{"mucCt":"ky","anchor":"Thân hình Vương Lâm vừa hiện ra lập tức đã thu hút rất nhiều ánh mắt","text":"Vương Lâm theo lão Chu Tước hiện thân trước các cường giả, thu hút sát ý của Tư Mặc Tử, ánh nhìn của Lý Thiến Mai và sự chú ý của Diệu Âm đạo tôn. Hắn hành lễ với Lam Mộng đạo tôn, được lão Chu Tước công khai bảo hộ và được tuyên bố sẽ bước vào thí luyện thiếu đế thứ ba của vùng đất Điên Lạc. Khi Thái Hoang Công lộ thân phận, Vương Lâm nhận nửa đoạn móng tay chứa độc công làm vật phòng thân.","bridge":true,"khoang":"@c1313"},{"mucCt":"ky","text":"Vương Lâm nhận lời tham gia thí luyện thiếu đế vùng đất Điên Lạc và được Lão Chu Tước cuốn tới cây hương thứ nhất. Khi đặt tay lên hương, thân thể hắn bất động, hồn phách tiến vào Nhân giới trong Thiên, Địa, Nhân. Trong huyễn cảnh, hắn đứng trên cầu giữa thành trì phàm nhân mờ ảo như mộng, rồi chấn động khi thấy một thanh niên trên thuyền có dung mạo vô cùng quen thuộc.","anchor":"Trong nháy mắt khi hắn tiếp xúc với cây hương, hai mắt hắn nhắm lại, thân thể không nhúc nhích, hồn phách tiến vào trong cây hương","bridge":true,"khoang":"@c1314"},{"mucCt":"ky","text":"Trong huyễn cảnh cửa Nhân, Vương Lâm gặp một thanh niên phàm nhân gần ba mươi tuổi có dung mạo và linh hồn giống hệt mình, đại diện cho nhân sinh nếu hắn không tu đạo. Hắn đáp xuống thuyền đối ẩm, rồi nói ra thân thế phàm tục của thanh niên: cha là Vương Thiên Thủy, mẹ là Chu Anh Tố, xác nhận nơi này là Triệu quốc. Vương Lâm nhận ra cửa Nhân không phải vấn đạo như Thiên Vận Tử năm xưa mà là tâm ma, tạo hư hồn nhân sinh để dao động đạo tâm. Hắn đã hiểu cách đốt cây hương thứ nhất nhưng cố ý trì hoãn, muốn nhìn lại quê cũ, người thân và đặc biệt là Lý Mộ Uyển trước khi kết thúc. Trên Đại Đế tinh, thân thể hắn chảy hai hàng lệ trong suốt, Lam Mộng đạo tôn gọi đó là hiện tượng hồn về quê cũ. Hắn đứng trên Hằng Nhạc phái nhìn sơn thôn rồi rời đi trong nước mắt, sau đó cảnh hiện ra Lý Mộ Uyển thời thiếu nữ tại Lạc Hà môn đang luyện đan thất bại. Trong cửa Nhân, Vương Lâm dùng hồn tiến vào huyễn cảnh, gặp một thanh niên phàm nhân giống hệt mình từ dung mạo tới linh hồn và nhận ra đó là một nhân sinh khác nếu hắn không bước lên đường tu đạo. Sau khi xác nhận nơi này giống Triệu quốc và nói ra thân thế của thanh niên, hắn hiểu cửa Nhân không phải khảo nghiệm vấn đạo mà là tâm ma đánh vào điều mềm yếu nhất trong lòng. Hắn đã hiểu cách đốt cây hương đại diện cho Nhân, nhưng cố ý trì hoãn để nhìn lại quê cũ, cố nhân và Lý Mộ Uyển, khiến thân thể ngoài giới trên Đại Đế tinh rơi lệ.","anchor":"Cửa Nhân này ta lấy hồn tiến vào, vốn tưởng là khảo nghiệm giống như Thiên Vận Tử vấn đạo, nhưng lại không ngờ rằng nơi này không phải là vấn đạo mà là tâm ma","bridge":true,"khoang":"@c1315"},{"mucCt":"ky","text":"Trong Nhân giới thí luyện, Vương Lâm nhận ra thiếu nữ áo vàng là Lý Mộ Uyển dù dung mạo khác năm xưa. Hắn dùng bạch quang cứu hai con thú nhỏ bị thương để tiếp cận nàng, chờ bốn ngày trên đỉnh núi Lạc Hà môn để nàng quay lại. Khi lão Chu Tước từ Đại Đế tinh truyền âm thúc hắn dùng hỏa diễm trong hồn đốt cháy toàn bộ thế giới để hoàn thành cây hương thứ nhất, Vương Lâm thẳng thừng từ chối vì không đành hủy diệt giới có Lý Mộ Uyển. Hắn tuyên bố sẽ nghịch đạo, lấy chấp niệm bản thân hóa thành nghiệp hỏa để đốt nghiệp chướng luân hồi thay vì đi theo cách đốt phàm niệm.","anchor":"lấy chấp niệm bản thân hỏa thành nghiệp hỏa","bridge":true,"khoang":"@c1316"},{"mucCt":"ky","text":"Trong Nhân phương giới, Vương Lâm hiểu con đường lấy chấp niệm nhóm nghiệp chướng luân hồi để tìm mầm nghiệp hỏa, nhưng không chọn đốt hủy giới này mà tự thiêu hồn bằng lửa lam. Theo thời gian, mỗi lần Lý Mộ Uyển lên núi gặp hắn, chấp niệm trong lòng càng sâu khiến lửa thiêu hồn càng dữ dội, thân thể hắn suy yếu và già nua. Khi Lão Chu Tước định phóng biển lửa hủy Nhân giới để ép hắn buông bỏ, hắn tỉnh lại ôm Lý Mộ Uyển, lấy lưng chắn lửa và tuyên bố cả đời tu đạo chỉ vì nàng. Chính lời tuyên bố ấy khiến tia nghiệp hỏa màu đen bùng lên trong hồn phách, nhanh chóng lan khắp thân thể và bắt đầu hủy diệt hồn phách của hắn.","anchor":"Lão tổ, vãn bối cả đời tu đạo, chỉ vì một người","bridge":true,"khoang":"@c1317"},{"mucCt":"ky","text":"Giữa lúc bị nghiệp hỏa thiêu đến gần tiêu tán, Vương Lâm ôm Lý Mộ Uyển và công khai xác lập con đường lấy chấp niệm nhập đạo, lấy niệm tạo nghiệp, hóa nghiệp chướng luân hồi. Sau khi thân thể biến mất, hồn phách hắn hóa thành Chu Tước đen trong nghiệp hỏa, khiến tiếng kêu xuyên khỏi Nhân phương giới và chấn động Đại đế tinh. Hắn dẫn biển lửa đen đốt Nhân phương hương, nói tên thật của mình với Lý Mộ Uyển rồi chủ động nghênh tiếp Cửu chuyển nghiệp kiếp khi ngọn lửa quanh thân chuyển sang đỏ như máu.","anchor":"Ta lấy chấp niệm nhập đạo, lấy niệm tạo nghiệp, hóa thành nghiệp chướng luân hồi","bridge":true,"khoang":"@c1318"},{"mucCt":"ky","text":"Trong Nhân phương giới, Vương Lâm bị đệ nhất chuyển nghiệp hỏa màu đỏ thiêu đốt hồn phách nhưng không khuất phục, ngược lại hút toàn bộ lửa đỏ vào thân thể để luyện hóa. Khi Chanh, Hoàng, Lục tam kiếp đồng thời giáng xuống, hắn tiếp tục nuốt cả ba loại nghiệp hỏa vào hồn phách, rồi uống cạn bầu máu rồng để khiến hỏa lực trong cơ thể bạo tăng và đối kháng lẫn nhau. Giữa biển lửa, khí tức Thiên Nghịch châu sâu trong hồn phách hắn bắt đầu thức tỉnh, sau đó hắn lao lên phá bầu trời Nhân phương giới và khiêu khích đệ ngũ chuyển.","anchor":"Đem toàn bộ bốn chuyển nghiệp hỏa này hút vào bên trong hồn phách của ta","bridge":true,"khoang":"@c1319"},{"mucCt":"ky","text":"Phá bầu trời Nhân Phương giới lao vào Địa Phương giới, bị Cửu Chuyển Nghiệp Kiếp bảy màu thiêu tan hồn phách. Thiên Nghịch tái hiện sau thời gian dài biến mất, hút lửa bảy màu thành bảy ngọn lửa bất diệt và ngưng luyện hư ảnh hắn. Hai kiếp cuối đen trắng giáng xuống hoàn chỉnh chín màu. Mở mắt tuyên bố đốt lên nghiệp chướng luân hồi, chín màu lửa dung hợp thành sen lửa chín cánh tại mi tâm. Chu Tước chín màu từ sen lửa bay ra, phát tiếng kêu đánh dấu lần tỉnh giấc thứ tư.","anchor":"Thanh âm của Vương Lâm hướng về bốn phía truyền ra","bridge":true,"khoang":"@c1320"},{"mucCt":"ky","text":"Trong Địa Phương giới, Vương Lâm ngồi trên hỏa liên chín màu, hấp thu viêm huyết tinh hoa và long huyết từ viêm long do lão Chu Tước truyền qua Địa Phương hương. Chu Tước đời thứ tư trong Địa Phương giới xuất hư hỏa tương trợ, lão Chu Tước trên Đại đế tinh cũng tự xuất hư hỏa bản thân bổ sung. Khi bảy màu đã tan, hắn từ chối tiếp tục nhận trợ giúp và tự dùng đạo thuật dung hòa vạn vật để hòa tan hai màu trắng đen cuối cùng. Chín màu hợp thành một, Chu Tước của hắn lao ra với hư hỏa lưu chuyển trên toàn thân, hoàn tất thức tỉnh Chu Tước lần thứ tư, thực hỏa chính thức nhập hư.","anchor":"Lần thức tỉnh thứ tư đã đưa thực hỏa của ta nhập hư","bridge":true,"khoang":"@c1321"},{"mucCt":"ky","text":"Chu Tước của Vương Lâm bước vào lần thức tỉnh thứ tư, hấp thu toàn bộ hỏa diễm trong Địa phương giới, hỏa liên chín màu hóa giáp, đạt cực hạn thực hỏa. Thiên Nghịch trong cơ thể Vương Lâm đột nhiên bộc phát, hiện ở lồng ngực như dòng xoáy, điên cuồng hấp thu sương mù từ lực tràn vào. Trong hồn phách Vương Lâm hiện ra hình ảnh la bàn khổng lồ ngang tinh không, tâm la bàn là hạt châu Thiên Nghịch. Sau khi hút hết sương mù, Thiên Nghịch phun ra từ lực quét qua Chu Tước, toàn bộ thực hỏa tan nát hóa thành hư hỏa, nhưng hư hỏa phát sinh biến hóa quỷ dị đến mức lão tổ Chu Tước đời đầu chứng kiến cũng phải rung động.","anchor":"Trong Địa phương hương, Vương Lâm đang ở thời điểm mấu chốt chuyển hóa từ thực hỏa thành hư hỏa","bridge":true,"khoang":"@c1322"},{"mucCt":"ky","text":"Hư hỏa mới sinh của Vương Lâm hấp thu từ lực thiên đạo, phá quy luật cố định của Chu Tước tộc, khiến hắn trở thành người đầu tiên từ cổ chí kim có thể tiếp tục hấp thu thêm hư hỏa. Sương mù từ lực trong thân thể bùng ra, phá Địa phương giới lan khắp bầu trời Đại đế tinh, chuyển từ trạng thái bạo ngược sang chỉnh thể có sinh cơ. Địa phương hương nứt khắp thân rồi gãy đổ trước mặt mấy vạn tu sĩ, khiến thí luyện chỉ còn Thiên phương hương. Thiên Nghịch ẩn đi trong Địa phương giới, Vương Lâm hút Chu Tước hư huyễn vào mắt phải, cơ thể tràn ngập hư hỏa vô hình vô sắc mang lực lượng diệt thế. Hắn tới ngọn núi trọc gặp Chu Tước đời thứ tư, xác nhận thân phận ông, nhắc ân tình Chu Tước đời thứ năm rồi đưa thi hài Lão Thánh Hoàng về bên sư phụ cũ. Khi thân ảnh trong Địa phương giới biến mất, thân thể hắn dưới Nhân phương hương trên Đại đế tinh mở mắt tỉnh lại.","anchor":"Vương Lâm là người thứ nhất từ cổ chí kim có thể hấp thu thêm hư hỏa","bridge":true,"khoang":"@c1323"}],"tuViMoc":[{"chuong":"@c1214","canhGioi":"Đạo cảnh","text":"Sau mười năm hôn mê trong hình tượng đá, hấp thu máu tươi, tinh huyết, đạo huyết nguyên thần và hồn huyết của Lý Thiến Mai, Vương Lâm thức tỉnh và phát hiện đã tiến vào cảnh giới kỳ dị Đạo cảnh. Năng lực: nhìn thấu nguyên thần, khống chế thần thông đối phương, loại bỏ thần thông khỏi trí nhớ, nghịch chuyển phong ấn.","importance":"major"},{"chuong":"@c1217","canhGioi":"Cổ Thần bốn tinh điểm (tái ngưng tụ)","text":"Nhờ Cổ Thần lực từ ngọn núi thanh kiếm Cổ Thần chảy vào thân thể, mi tâm lần lượt tái hiện Cổ Thần tinh điểm thứ nhất đến thứ tư. Trước đó đã toái tinh nhưng Cổ Thần bên trong chưa suy xuyển, nay tái ngưng tụ.","importance":"major"},{"chuong":"@c1217","canhGioi":"Cổ Thần tứ tinh (tái ngưng tụ)","text":"Nhờ Cổ Thần lực từ ngọn núi thanh kiếm Cổ Thần chảy vào thân thể, mi tâm lần lượt tái hiện Cổ Thần tinh điểm thứ nhất đến thứ tư. Trước đó đã toái tinh nhưng Cổ Thần bên trong chưa suy xuyển, nay tái ngưng tụ.","importance":"major","nguon":["@c1217"]},{"chuong":"@c1217","canhGioi":"Cổ Thần tinh điểm thứ tư (phục hồi)","text":"Cổ Thần lực từ ngọn núi kiếm Cổ Thần hóa thành tràn vào thân thể, mi tâm lần lượt ngưng tụ tinh điểm Cổ Thần thứ nhất đến thứ tư — năm đó đã toái tinh nhưng Cổ Thần bên trong chưa suy xuyển. Thuộc hệ Cổ Thần, không phải tu vi chính.","importance":"major"},{"chuong":"@c1218","canhGioi":"Lục tinh vương tộc Cổ Thần","text":"Trong cơn bức bách bị vây công và lo lắng cho Lý Thiến Mai, tinh điểm thứ năm và thứ sáu đồng loạt hiện ra trên mi tâm, đạt Lục tinh Cổ Thần. Tinh điểm thứ bảy bắt đầu hình thành vòng xoáy nhưng chưa ngưng tụ hoàn toàn.","importance":"major"},{"chuong":"@c1225","canhGioi":"Giải phóng toàn bộ tu vi bị phong ấn Thất Thải giới","text":"Mở phong ấn cấm chế phức tạp trên mi tâm, giải phóng toàn bộ tu vi đã bị phong ấn ở Thất Thải giới hai ngàn năm trước, thể hiện tư thái cực mạnh.","importance":"major"},{"chuong":"@c1226","canhGioi":"Toái Niết sơ kỳ","text":"Mở phong ấn cấm chế giải phóng đạo quả thất thải giới, từ Tịnh Niết đại viên mãn chính thức bước vào Toái Niết sơ kỳ.","importance":"major"},{"chuong":"@c1226","canhGioi":"Toái Niết trung kỳ","text":"Đạo quả chưa tiêu tan hết, cảm ngộ mười năm Đạo cảnh chỉ phát huy một phần, tu vi tiếp tục bạo tăng từ Toái Niết sơ kỳ lên Toái Niết trung kỳ.","importance":"minor"},{"chuong":"@c1234","canhGioi":"Cực Cảnh (sinh ra)","text":"Cực Cảnh sinh ra bên trong cơ thể Vương Lâm khi thiên kiếp diễn biến từ Cửu Cung tới Lưỡng Nghi hợp nhất thành Nhất Kiếp, đạo niệm và ý cảnh biến dị theo đồng bộ với thiên cực kiếp bên ngoài.","importance":"major"},{"chuong":"@c1265","canhGioi":"Lôi bản nguyên — hấp thu Cửu đạo lôi loại thứ 9 (Linh Niệm Lôi)","text":"Linh Niệm Lôi dung nhập nguyên thần, khai mở ký ức lôi bản nguyên thái cổ. Mắt phải xuất hiện tia chớp thứ hai, lôi bản nguyên bắt đầu tăng trưởng. Đã hấp thu loại sấm sét thứ chín, còn thiếu tám loại nữa mới viên mãn.","importance":"major"},{"chuong":"@c1270","canhGioi":"Lôi nguyên thần viên mãn","text":"Thôn phệ hồn phách tám Thái Cổ Lôi Long trưởng thành, lôi bản nguyên tăng hơn mười lần, nguyên thần tiến hóa từ trạng thái gần sấm sét thành lôi nguyên thần viên mãn — co rút thành lôi đồ đằng tia chớp khổng lồ, uy áp ngang sấm sét bất diệt Thiểm Lôi Tộc.","importance":"major"},{"chuong":"@c1270","canhGioi":"Lôi bản nguyên tăng mạnh","text":"Sau khi thôn phệ hồn phách tám Thái Cổ Lôi Long, lôi bản nguyên trong nguyên thần Vương Lâm tăng vọt, nguyên thần hướng tới lôi nguyên thần và sinh ra uy áp đối kháng sấm sét bất diệt; đây là biến đổi thuộc hệ lôi bản nguyên, không phải tu vi chính.","importance":"major"},{"chuong":"@c1270","canhGioi":"Lôi đồ / đồ đằng tia chớp nguyên thần","text":"Sau khi thôn phệ hồn phách tám Thái Cổ Lôi Long, nguyên thần Vương Lâm co rút thành đồ đằng tia chớp khổng lồ, lôi bản nguyên tăng vọt và phát ra uy áp có thể đối kháng sấm sét bất diệt; đây là biến hóa thuộc hệ lôi nguyên thần, không phải cảnh giới tu vi chính.","importance":"major"},{"chuong":"@c1276","canhGioi":"Lôi bản nguyên đại thành","text":"Vương Lâm dự tính luyện hóa sấm sét bất diệt, hồn phách tám Thái Cổ Lôi Long và minh ngộ sấm sét trong nguyên thần đại trưởng lão để khiến lôi bản nguyên đại thành; đây là mốc bản nguyên, không phải cảnh giới tu vi chính đã hoàn tất ngay trong chương.","importance":"major"},{"chuong":"@c1279","canhGioi":"Tu lôi đạt Toái Niết hậu kỳ","text":"Sau khi luyện hóa sấm sét bất diệt, lôi bản nguyên của Vương Lâm tăng vọt, khiến riêng lực lượng sấm sét của hắn đạt tới mức Toái Niết hậu kỳ; đây là mốc thuộc hệ tu lôi, không phải toàn bộ tu vi chính.","importance":"major"},{"chuong":"@c1280","canhGioi":"Toái Niết hậu kỳ khi thi triển lực lượng sấm sét","text":"Khi dùng lực lượng sấm sét, tu vi của Vương Lâm vượt Toái Niết trung kỳ lên Toái Niết hậu kỳ; đây là trạng thái dị biến theo lôi bản nguyên, không phải toàn bộ hệ tu vi đều đồng bộ tăng.","importance":"minor"},{"chuong":"@c1282","canhGioi":"Toái Niết đại viên mãn","text":"Sau khi cưỡng ép thôn phệ Từ Hợp lôi, tu vi của Vương Lâm phá Toái Niết hậu kỳ và tiến vào Toái Niết đại viên mãn.","importance":"major"},{"chuong":"@c1282","canhGioi":"Lôi tu Toái Niết đỉnh phong Đệ Nhị Bộ","text":"Đạo Ý lôi chủ động dung hợp, khiến tu vi trên phương diện lôi tu của Vương Lâm đạt Toái Niết đỉnh phong trong Đệ Nhị Bộ; đây là mốc thuộc hệ lôi bản nguyên, không phải tu vi chính.","importance":"major"},{"chuong":"@c1320","canhGioi":"Chu Tước thức tỉnh lần thứ tư","text":"Vượt qua Cửu Chuyển Nghiệp Kiếp chín màu, chín ngọn lửa dung hợp thành sen lửa chín cánh tại mi tâm, Chu Tước chín màu bay ra và tỉnh giấc lần thứ tư.","importance":"major"}],"nhanMach":[{"ten":"Bà lão bạch y","tag":"an-nhan","quanHe":"Sư tỷ của Lý Thiến Mai, đưa hồn huyết cứu tỉnh Vương Lâm","ghiChu":"Bị Vương Lâm bắt giữ bắt dẫn đường tới chiến trường Yêu Tông"},{"ten":"Tông chủ Hải Hồn Tông","tag":"khac","quanHe":"Bị Vương Lâm uy hiếp cưỡng mở truyền tống trận","ghiChu":"@c1215"},{"ten":"Tông chủ tân nhiệm Tiên Âm Môn","tag":"khac","quanHe":"Tông chủ mới của Tiên Âm Môn, khiếp sợ uy danh Vương Lâm, không dám kháng cự","gap":"@c1216"},{"ten":"Trưởng lão Yêu Tông","tag":"doi-thu","quanHe":"Đối thủ giao đấu, sư phụ của Lý Thiến Mai","ghiChu":"Đánh bại nhưng tha mạng, được tặng ngọc giản bản đồ khe nứt"},{"ten":"Nữ tử áo đen (bọ cạp chín đuôi cấp mười ba)","tag":"doi-thu","quanHe":"Đối thủ, mãnh thú cấp mười ba bị Vương Lâm đánh bại","ghiChu":"Thuộc hạ Viễn Cổ Đế Phi, đả thương Lý Thiến Mai nên bị Vương Lâm trừng phạt @c1227"},{"ten":"Y Nguyệt","tag":"dong-minh","quanHe":"Đồng minh tạm thời","ghiChu":"Phi tử viễn cổ Tiên Hoàng, đề nghị liên minh: đổi chữa thương lấy dẫn Vương Lâm tới tế đàn Cổ Thần, trao ngọc bội truyền tống"},{"ten":"Huyền Bỉnh","tag":"khac","quanHe":"Thái thượng trưởng lão Yêu Tông, nhận ra Vương Lâm có ngọc bội Tông Chủ","ghiChu":"@c1233"},{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Ngũ đại tôn giả Thái Cổ Tinh Thần, mục tiêu Vương Lâm muốn đưa Lý Thiến Mai tới nhờ cậy","ghiChu":"@c1237"},{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Kẻ thù — cùng là vương tộc Cổ Thần, Thác Sâm muốn dung hợp Vương Lâm; tạm hợp tác chống Nguyệt Tộc rồi lại đối đầu","nguon":"@c1239"},{"ten":"Lão già tóc bạc Nguyệt Tộc","tag":"doi-thu","quanHe":"Thủ lĩnh Nguyệt Tộc — chỉ huy đại trận phong ấn Cổ Thần, bị Vương Lâm cuốn bắt nguyên thần mang đi","nguon":"@c1239"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Phụ thân Lý Thiến Mai, người gây tai ương ở Thất Thải Giới, giờ cướp lại Lý Thiến Mai và đặt điều kiện lãng quên","ghiChu":"Lam Mộng Đạo Tôn nói nếu sau khi mất trí nhớ mà hai người còn bắt đầu lại được thì sẽ không ngăn cản","nguon":"@c1241"},{"ten":"Trưởng lão Yêu Tông (lão già tóc bạc)","tag":"khac","quanHe":"Đối thủ rồi hòa hoãn","ghiChu":"Giao đấu kịch liệt, sau đó trưởng lão xin dừng, tặng ngọc giản bản đồ; Vương Lâm cảnh báo cách chữa đạo niệm."},{"ten":"Lan Phi","tag":"doi-thu","quanHe":"Viễn Cổ Bát Phi, truy đuổi Vương Lâm để hấp thu thần tính Cổ Thần trên mi tâm hắn","ghiChu":"Phân thân mang dung mạo Lý Mộ Uyển, bản thể cực mạnh"},{"ten":"Thanh niên hắc y (Thiểm Lôi Tộc)","tag":"khac","quanHe":"Tộc nhân Thiểm Lôi Tộc sắp chết, thân xác bị Vương Lâm đoạt xá","ghiChu":"@c1252"},{"ten":"Vu Phi","tag":"khac","quanHe":"Đoạt xá thân thể","ghiChu":"Tạm chiếm thân Vu Phi để trà trộn Thiểm Lôi Tộc, hứa sau khi xong việc sẽ trả lại thân thể kèm lợi ích khổng lồ","nguon":"@c1253"},{"ten":"Tề Trì","tag":"doi-thu","quanHe":"Chế phục, lục ký ức","ghiChu":"Đánh bại hoàn toàn, dùng Sưu Thần Thuật lục ký ức, lấy hết pháp bảo đan dược, không giết vì luật tộc","nguon":"@c1253"},{"ten":"Khâu Đức Hải","tag":"doi-thu","quanHe":"Trưởng lão Thiên Lôi Tông bị Vương Lâm phế tu vi và cướp bảo vật","ghiChu":"@c1254"},{"ten":"Chung Đại Hồng","tag":"khac","quanHe":"Tu sĩ Hóa Thần gầy Thiên Lôi Tông cuồng nhiệt sùng bái, xin làm tôi tớ, gợi nhớ Hứa Lập Quốc","ghiChu":"@c1254"},{"ten":"Hắc Ma Pháp Vương","tag":"khac","quanHe":"Tu sĩ Vấn Đỉnh sơ kỳ đỉnh phong bị Vương Lâm chấn nhiếp chỉ bằng ánh mắt","ghiChu":"@c1258"},{"ten":"Chu Thiên Tử","tag":"khac","quanHe":"Tu sĩ Khuy Niết của Thiểm Lôi Tộc, Vương Lâm quan sát với nụ cười bình tĩnh","ghiChu":"@c1258"},{"ten":"Ba lão già canh ao","tag":"an-nhan","quanHe":"Ân nhân — ba lão già Dương Thực cửa đông Lôi Tinh Điện tặng tạo hóa cho Vương Lâm khi hắn lên Thiểm Lôi Bảng","ghiChu":"@c1260"},{"ten":"Chu Thiên Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Chu Thiên Tử khinh thường Vương Lâm, định giết trong bảy trăm vạn thiên địa nhưng bị Vương Lâm phá tan Lôi Long"},{"ten":"Dương Thực","tag":"ban-be","quanHe":"Tiểu bối Thiểm Lôi Tộc đã tặng ngọc giản","ghiChu":"Tặng ngọc giản giúp Vương Lâm xác nhận thân phận Vu Phi tại cửa Tây"},{"ten":"Trương Cảnh Vân","tag":"doi-thu","quanHe":"Tu sĩ Vấn Đỉnh trung kỳ chuyên cướp Linh Niệm Lôi, tiếp cận dụ dỗ Vương Lâm (mạo danh Vu Phi) trong bảy trăm vạn thiên địa","ghiChu":"@c1262"},{"ten":"Tán Linh Thượng Nhân","tag":"khac","quanHe":"Người quan sát Vương Lâm sau trận chiến","ghiChu":"Tán Linh nhận xét Vương Lâm có lẽ không phải nô lệ của sấm sét"},{"ten":"Tán Linh Thượng Nhân","tag":"dong-minh","quanHe":"Đối tượng hợp tác","ghiChu":"Tán Linh chủ động lộ diện đề nghị giao dịch, tiết lộ chân tướng thế giới và thuật Tán Linh, cùng đi đến tận cùng thế giới"},{"ten":"Lão già áo xanh (Thiểm Lôi Tộc)","tag":"doi-thu","quanHe":"Giết chết","ghiChu":"Trưởng lão Tịnh Niết, bị Vương Lâm điểm mi tâm diệt vong @c1269"},{"ten":"Người đàn ông trung niên đạo bào xanh (Thiểm Lôi Tộc)","tag":"doi-thu","quanHe":"Đối đầu","ghiChu":"Cường giả Toái Niết viên mãn, khiếp sợ trước Vương Lâm @c1269"},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"doi-thu","quanHe":"Kẻ thù sinh tử","ghiChu":"Đại chiến trong lôi vực, hai bên đều trọng thương, đại trưởng lão đuổi theo Vương Lâm vào hắc động."},{"ten":"Chung Đại Hồng","tag":"dong-minh","quanHe":"Chủ nhân và thuộc hạ","ghiChu":"Chung Đại Hồng đổi cách xưng hô thành chủ nhân, tận lực hầu hạ và dâng những vật cướp được để đổi Lôi tinh."},{"ten":"Hắc Ma Pháp Vương","tag":"doi-thu","quanHe":"Kẻ bị uy thế áp đảo","ghiChu":"Hắc Ma Pháp Vương run rẩy và vã mồ hôi lạnh khi bị Vương Lâm quét mắt nhìn."},{"ten":"Nữ tử áo trắng","tag":"doi-thu","quanHe":"Đối thủ trực tiếp","ghiChu":"Nàng chặn đường, phong tỏa Thuấn Di và định hấp thu thần tính Cổ Thần của hắn; hắn cố ý để bị khống chế rồi phản chế, đồng thời nhìn ra nàng chỉ là phân thân."},{"ten":"Lão già tóc bạc (Nguyệt Tộc)","tag":"khac","quanHe":"Nguồn ký ức bị tra xét","ghiChu":"Ký ức của lão giúp Vương Lâm biết lịch sử Nguyệt Phệ Tộc, Thanh Vân Linh Thuật và Linh Chủng."},{"ten":"Tu sĩ họ Chu","tag":"doi-thu","quanHe":"Thành viên nhóm giả thiên kiếp bị Vương Lâm diệt sát.","ghiChu":"Tu sĩ họ Chu bỏ chạy sau cái chết của Trương Cảnh Vân nhưng bị Cực cảnh đánh chết."},{"ten":"Người đàn ông trung niên Ngoại giới","tag":"doi-thu","quanHe":"kẻ bị truy sát","ghiChu":"Vương Lâm dùng Cực Cảnh giết tu sĩ Toái Niết Ngoại giới này."},{"ten":"Lão già Toái Niết Thiểm Lôi Tộc","tag":"doi-thu","quanHe":"kẻ ngăn đường","ghiChu":"Bị Vương Lâm giết khi lao ra ngăn hắn xông vào thánh địa."},{"ten":"Lão già hắc y Thiểm Lôi Tộc Thiên Nhân Đệ Nhất Suy","tag":"doi-thu","quanHe":"đối thủ bị trọng thương","ghiChu":"Bị Vương Lâm phá thần thông, đánh tan thân thể và trọng thương nguyên thần."},{"ten":"Người đàn ông trung niên cao lớn Thiểm Lôi Tộc Thiên Nhân Đệ Tam Suy","tag":"doi-thu","quanHe":"cao thủ Thiểm Lôi Tộc đối địch","ghiChu":"Xuất hiện cứu nguyên thần lão già hắc y và nhận ra Vương Lâm phản tộc."},{"ten":"Lý Mộ Uyển","tag":"the-thiep","quanHe":"người trong lòng","ghiChu":"Dung mạo Lan Phi Lâu Lan giống Lý Mộ Uyển khiến tâm thần Vương Lâm chấn động trong lúc giao chiến."},{"ten":"Âm thanh trong vòng xoáy","tag":"doi-thu","quanHe":"đối đầu trong tranh đoạt sấm sét bất diệt","ghiChu":"Chủ thể chưa lộ danh tính trong vòng xoáy uy hiếp Vương Lâm buông tay."},{"ten":"Sứ giả thiên đạo","tag":"doi-thu","quanHe":"Kẻ thù cướp hồn thê tử","ghiChu":"Vương Lâm nhận ra sứ giả thiên đạo là kẻ năm xưa cướp hồn Uyển Nhi và tuyên bố thù không đội trời chung."},{"ten":"Lão già chủ quán than trước cổng thôn","tag":"khac","quanHe":"người phàm tặng rượu","ghiChu":"Lão chủ quán đưa bình rượu gạo cho Vương Lâm uống giữ ấm trong đêm lạnh."},{"ten":"Nam tu sĩ lạ có Cực Cảnh năm màu","tag":"khac","quanHe":"đầu mối bí ẩn","ghiChu":"Hình ảnh của người này khiến Vương Lâm liên hệ Cực Cảnh năm màu, Côn Cực Tiên và bí mật Nội giới."},{"ten":"Lão già đạo bào trong nhóm truy tìm","tag":"doi-thu","quanHe":"người bị cắt nguyên thần","ghiChu":"Vương Lâm âm thầm cắt một phần nguyên thần của lão để đọc ký ức về vòng truy tìm."},{"ten":"Vân Lạc","tag":"doi-thu","quanHe":"nguy cơ truy tung","ghiChu":"Thần thông suy tính của Vân Lạc có thể tính ra nơi Vương Lâm đang ở."},{"ten":"Lão già họ Chương","tag":"khac","quanHe":"Người trung gian giao dịch con rối.","ghiChu":"Lão được Chung Đại Hồng nhờ dẫn đi mua con rối, sau đó bị Ám Hạt Tộc bắt và chứng kiến Vương Lâm phá thành."},{"ten":"Nam tử trung niên Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ đả thương thuộc hạ của Vương Lâm.","ghiChu":"Người này đánh trọng thương Chung Đại Hồng và bắt lão họ Chương, khiến Vương Lâm tìm tới Ám Hạt Tộc."},{"ten":"Thiếu chủ Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ ra lệnh truy bắt sau giao dịch.","ghiChu":"Thiếu chủ ra lệnh bắt một người, đả thương một người và lưu lạc ấn thần thức, dẫn tới việc Vương Lâm ra mặt."},{"ten":"Thanh niên thiếu chủ Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ đánh lén bị phong ấn","ghiChu":"Dùng Ám hạt châu đánh lén nhưng bị Vương Lâm chế trụ và phong ấn."},{"ten":"Lão giả Ám Hạt Tộc hắc bào","tag":"dong-minh","quanHe":"Thuộc hạ bị thu phục","ghiChu":"Bị Vương Lâm đánh bại, phải đại diện Ám Hạt Tộc phát lời thề tôn hắn làm chủ."},{"ten":"Điên Lạc đại đế","tag":"khac","quanHe":"Đối tượng nghi vấn","ghiChu":"Được nhắc là tồn tại bước thứ ba tại Điên Lạc và có liên hệ lời đồn với Viêm hỏa dị tinh."},{"ten":"Chu Tước lão Thánh Hoàng","tag":"khac","quanHe":"Người từng để lại manh mối","ghiChu":"Lời từng nói về nguồn gốc Tứ Thánh Tông được Vương Lâm liên hệ khi thấy Viêm hỏa dị tinh."},{"ten":"Kiệt trưởng lão","tag":"dong-minh","quanHe":"Người dẫn đường bị Vương Lâm sai khiến tại Điên Lạc","ghiChu":"Vương Lâm lệnh Kiệt trưởng lão đưa tới nơi trưởng lão Lạc Sinh hội sinh sống gần nhất."},{"ten":"Tư Mặc Tử","tag":"doi-thu","quanHe":"kẻ truy sát","ghiChu":"Bị Vương Lâm nhận ra là tu sĩ bước thứ ba từng truy đuổi Thác Sâm và đang bám tới vùng đất Điên Lạc."},{"ten":"Nữ tử quản sự lầu các Long Giáp Tộc","tag":"khac","quanHe":"người tiếp đón giao dịch","ghiChu":"Tiếp Vương Lâm tại lầu các cửa hàng Long Giáp Tộc khi hắn hỏi mua Viêm hỏa dị tinh."},{"ten":"Lão giả Hỏa Tước tộc","tag":"doi-thu","quanHe":"người tranh mua Viêm hỏa dị tinh","ghiChu":"Xuất hiện ngay khi Vương Lâm hỏi mua Viêm hỏa dị tinh và yêu cầu hắn nhường."},{"ten":"Lão giả Hỏa Tước tộc","tag":"khac","quanHe":"đối tượng bị trấn áp và bị dẫn dụ giao dịch","ghiChu":"Vương Lâm dùng hồn đan có hỏa bổn nguyên làm mồi khiến lão giả Hỏa Tước tộc chủ động theo và đổi Viêm Hỏa dị tinh."},{"ten":"Thiếu tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"người giao dịch Băng long đan","ghiChu":"Thiếu tộc trưởng Long Giáp Tộc giao ba khối Viêm hỏa dị tinh và một vạn Băng long đan cho Vương Lâm."},{"ten":"Tham Lang","tag":"doi-thu","quanHe":"Đối thủ từng phong ấn","ghiChu":"Khi Tham Lang trọng thương mất quyền điều khiển phiến lá, Vương Lâm thoát ra và nắm lấy vật phong ấn."},{"ten":"Bạch Phàm","tag":"khac","quanHe":"Nguồn gốc thần thông","ghiChu":"Sơn Băng thuật Vương Lâm thi triển được Tư Mặc Tử nhận ra là thần thông của Bạch Phàm."},{"ten":"Tư Mã Mặc","tag":"khac","quanHe":"Manh mối lai lịch thần thông","ghiChu":"Vương Lâm nhớ tới ngọc giản Tư Mã Mặc khi liên hệ thuật của Tư Mặc Tử với Phá Thiên Đạo."},{"ten":"Đại đế vùng Điên Lạc","tag":"dong-minh","quanHe":"Tồn tại ra tay chặn Tư Mặc Tử và để sứ giả xưng Vương Lâm là thiếu đế.","ghiChu":"Quan hệ quyền lực mới lộ tại @c1293."},{"ten":"Nam tử trung niên hồng sam","tag":"dong-minh","quanHe":"Sứ giả của đại đế cung kính tham kiến Vương Lâm là thiếu đế.","ghiChu":"Lần đầu gặp tại @c1293."},{"ten":"Thanh niên Khuy Niết Long Giáp Tộc","tag":"cap-tren","quanHe":"Vương Lâm chỉ định người này làm tân tộc trưởng Long Giáp Tộc.","ghiChu":"Quan hệ lệ thuộc hình thành khi Long Giáp Tộc quy phục @c1294"},{"ten":"Lão giả nhận ra Đế lệnh","tag":"khac","quanHe":"người nhận ra lệnh vật","ghiChu":"Lão giả trong nhóm tu sĩ nhận ra Đế lệnh của Vương Lâm tại tu chân tinh Ám Hạt Tộc."},{"ten":"Đào Vân","tag":"khac","quanHe":"người trong ký ức đứt đoạn của ngân y nữ tử","ghiChu":"Vương Lâm biết tên Đào Vân qua lời lẩm bẩm hoảng loạn của ngân y nữ tử khi pho tượng kích phát ký ức."},{"ten":"Tử Lạc","tag":"khac","quanHe":"người trong ký ức đứt đoạn của ngân y nữ tử","ghiChu":"Vương Lâm biết tên Tử Lạc qua lời lẩm bẩm hoảng loạn của ngân y nữ tử khi pho tượng kích phát ký ức."},{"ten":"Trung niên áo bảy màu trong thức hải ngân y nữ tử","tag":"khac","quanHe":"thân ảnh phong ấn được phát hiện khi Sưu thần","ghiChu":"Vương Lâm nhìn thấy thân ảnh áo bảy màu sâu trong thức hải ngân y nữ tử, ban đầu thoáng liên hệ với Chưởng Tôn rồi tự loại bỏ khả năng này."},{"ten":"Cổ thần Đồ Ti","tag":"khac","quanHe":"hư ảnh Cổ Thần gợi nhận diện","ghiChu":"Hư ảnh Cổ Thần phía sau Vương Lâm khiến tồn tại trong vòng xoáy kinh hãi gọi là Đồ Ti."},{"ten":"Đại đế","tag":"khac","quanHe":"người can thiệp và đặt điều kiện","ghiChu":"Đại đế hứa bảo đảm Vương Lâm bình an ở vùng đất Điên Lạc nếu hắn thắng phân thân bước thứ ba trong năm nhịp thở."},{"ten":"Tộc trưởng Hà tộc","tag":"doi-thu","quanHe":"Bị đối phương nhắm làm đối tượng lập uy trước tuyển chọn trưởng lão Lạc Sinh hội.","ghiChu":"Tộc trưởng Hà tộc lầm tưởng Vương Lâm là người do Tham Lang phái tới."},{"ten":"Tộc trưởng Long Giáp Tộc mới","tag":"dong-minh","quanHe":"Được đối phương dẫn toàn tộc công khai bái kiến trước các tộc Điên Lạc.","ghiChu":"Màn bái kiến làm thân thế và uy thế của Vương Lâm lộ rõ hơn."},{"ten":"Sứ giả đại đế","tag":"khac","quanHe":"Được đối phương đi thẳng tới khi thông đạo Đại đế tinh mở.","ghiChu":"Cử chỉ của sứ giả khiến trưởng lão thứ mười ba kinh hãi."},{"ten":"Nam tử trung niên Hồn Xà tộc","tag":"doi-thu","quanHe":"Đối tượng bị Vương Lâm xử phạt","ghiChu":"Bị hủy tư cách dự tuyển chọn trưởng lão của Hồn Xà tộc sau khi đắc tội Vương Lâm."},{"ten":"Tộc trưởng Vân Độn tộc","tag":"doi-thu","quanHe":"Đối tượng bị Vương Lâm xử phạt","ghiChu":"Bị buộc tự phế một tay vì từng âm thầm dẫn họa về phía Vương Lâm."},{"ten":"Sứ giả đại đế","tag":"dong-minh","quanHe":"Người truyền lệnh và đón tiếp","ghiChu":"Cung kính bái kiến Vương Lâm là thiếu đế và nghe theo yêu cầu xử lý của hắn."},{"ten":"Nữ tử Trường Tôn hội","tag":"doi-thu","quanHe":"Người tìm cách dùng tên thật để thi triển thuật với hắn","ghiChu":"Vương Lâm cảnh giác và chỉ báo danh Hứa Mộc."},{"ten":"Tộc trưởng Ám Hạt Tộc","tag":"dong-minh","quanHe":"Đối tượng được hắn đề nghị đưa vào Lạc Sinh hội","ghiChu":"Vương Lâm dùng đề nghị này để tiếp tục thử thái độ của đại đế."},{"ten":"Lão giả mặc bạch y bên hồ","tag":"khac","quanHe":"người gặp trên Đại đế tinh","ghiChu":"Vương Lâm gặp lão bên hồ, ngồi cạnh hồi lâu trước khi lão mở lời hỏi rượu."},{"ten":"Chu Tước đời thứ hai","tag":"su-mon","quanHe":"tiền bối Chu Tước tộc","ghiChu":"Lão giả câu rồng xác nhận Vương Lâm là tộc nhân Chu Tước đời thứ sáu và nhận ra thân thể Cổ Thần của hắn."},{"ten":"Viêm long","tag":"khac","quanHe":"nguồn máu hỏa thuộc tính","ghiChu":"Máu của Viêm long giúp hỏa bổn nguyên của Vương Lâm tăng tiến."},{"ten":"Lão Chu Tước","tag":"su-mon","quanHe":"người truyền bí thuật vận dụng lực lượng","ghiChu":"Lão Chu Tước dùng mặt hồ dẫn dắt Vương Lâm tự ngộ cách mượn lực phản chấn."},{"ten":"Lão Chu Tước","tag":"an-nhan","quanHe":"người bảo hộ và đề cử","ghiChu":"Được lão Chu Tước che chở trước Tư Mặc Tử và đưa vào thí luyện thiếu đế."},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"người khiến tâm tình phức tạp","ghiChu":"Khi thấy nàng trong lam quang, ánh mắt Vương Lâm thoáng trở nên phức tạp."},{"ten":"Diệu Âm đạo tôn","tag":"khac","quanHe":"đại năng được giới thiệu","ghiChu":"Vương Lâm nghe thân phận Diệu Âm đạo tôn thì tâm thần chấn động vì không nhìn ra tu vi."},{"ten":"Thái Hoang Công","tag":"an-nhan","quanHe":"người tặng vật phòng thân","ghiChu":"Nhận nửa đoạn móng tay chứa độc công do Thái Hoang Công tặng."},{"ten":"Thanh niên phàm nhân giống Vương Lâm","tag":"khac","quanHe":"hư hồn nhân sinh","ghiChu":"Trong cửa Nhân, người này hiện ra như một đời phàm tục khác của Vương Lâm."},{"ten":"Chu Anh Tố","tag":"cha-me","quanHe":"mẹ trong thân thế phàm tục giả định","ghiChu":"Được Vương Lâm nói là mẹ của thanh niên phàm nhân giống mình."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Thiếu niên phàm nhân tư chất kém quyết chí tu tiên, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh làm nền tảng mọi đột phá sau này","chuong":"@c0001"},{"text":"Tự nổ thân thể đấu Đằng Hóa Nguyên (Nguyên Anh kỳ) để báo thù diệt tộc, linh hồn chi hỏa tồn tại xuyên Vực Ngoại rồi đoạt xá thân Mã Lương","chuong":"@c0100"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, khai mở con đường luyện thể và thôn hồn độc đáo","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một thể thống nhất, đạt tam tinh Cổ Thần và Hóa Thần hậu kỳ với ý cảnh cấp Anh Biến","chuong":"@c0365"},{"text":"Vượt mười bảy tầng Thiên Tôn Niết, được sắc phong Dược Thiên Tôn — danh hiệu thứ bốn mươi chín trong lịch sử","chuong":"@c1856"},{"text":"Đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh, ngưng hình dáng ban đầu Đại Thiên Tôn Chi Dương, bước vào hàng ngũ đỉnh cao cổ tộc","chuong":"@c1901"}]},"cn":"王林","gioiTinh":"nam","aliases":["Lữ Tử Hạo","Lữ mỗ","Hứa Mộc","Vu Phi","Thiếu đế mới của vùng đất Điên Lạc","Thiếu đế do đại đế lựa chọn"],"tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh và tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"}],"vaiTro":"Nhân vật chính — tu sĩ phàm nhân nghịch thiên, Dược Thiên Tôn tam cổ cửu tinh của Đạo Cổ","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, đến vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Tính tới giai đoạn trở về Cổ Tộc, hắn đã được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh, ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, và đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối. Sau biến cố Tiên Hoàng tự bạo, hắn tách tà"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","nguon":["@c1214","@c1215","@c1217","@c1218","@c1219","@c1220","@c1221","@c1222","@c1223","@c1224","@c1225","@c1226","@c1227","@c1228","@c1230","@c1232","@c1234","@c1235","@c1240","@c1241","@c1242","@c1248","@c1275","@c1284","@c1290","@c1312","@c1313","@c1318","@c1319","@c1320","@c1322","@c1323"],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Suốt mười năm chăm sóc tượng đá Vương Lâm tại đại lục hoang dã, Lý Thiến Mai lần lượt hy sinh máu tươi, tinh huyết tâm thần (cắn đầu lưỡi, dùng tiểu kiếm bạc đâm tim), đạo huyết nguyên thần (ý cảnh cả đời dung nhập trong nguyên thần luyện hóa), và ngọc bội mệnh hồn. Nàng nhớ ảo ảnh kiếp trước cá-chim, tự nhủ không cướp đoạt Vương Lâm, nhắc đến Mộc Băng Mi. Trước đó nàng từ bỏ cơ hội đại đệ tử Yêu Tông, vi phạm luật Phá Thiên Tông rời chiến trường tìm Vương Lâm ở Vô Cực Tông, bị sư tôn giam ba tháng rồi lấy cái chết ép được đi, từ đó mất môn phái. Cuối cùng để thu hồi hồn huyết, nàng đáp ứng Yêu Tông đi vào khe sâu nhất chiến trường dò xét thông đạo giới ngoại — nơi mãnh thú chí cường, chắc chắn phải chết. Nàng bố trí kiếm trận chín phi kiếm bảo vệ sơn cốc rồi rời đi, không trở về.","anchor":"Lý Thiến Mai vì giúp ngươi thức tỉnh mà trong vòng mười năm này ngày nào cũng dùng máu tươi vẽ lên toàn thân ngươi","bridge":true,"khoang":"@c1214"},{"chuong":"@c1215","importance":"bridge","mucCt":"gon","text":"Được hồi tưởng qua lời ly biệt tại Vô Cực Tông: chỉ mong Vương Lâm tiễn nàng, nhớ tới nàng, không cầu thay thế Lý Mộ Uyển, đang đứng trước nguy cơ sinh tử khiến Vương Lâm bỏ tất cả lao đi cứu.","anchor":"Nếu có một ngày ta qua đời, chàng phải nhớ kỹ những ngày chàng sống, có một nữ tử tên là Lý Thiến Mai, vụt qua đời chàng."},{"mucCt":"vua","text":"Ngọc bội mệnh hồn của nàng nứt thêm nửa tấc, mệnh hồn chưa tiêu tan nhưng cực kỳ suy yếu. Nếu ngọc bội vỡ đôi tức là nàng đã chết, cho thấy nàng đang gặp nguy cơ sinh tử nghiêm trọng.","anchor":"mệnh hồn của Lý Thiến Mai trên đó vẫn chưa tiêu tan, nhưng đã cực kỳ suy yếu","bridge":true,"khoang":"@c1218"},{"chuong":"@c1219","importance":"bridge","mucCt":"gon","text":"Được nhắc là một trong ba người năm đó giết vương thú được Yêu Tông chấp thuận, dù trái lệnh rời đi mười năm Yêu Tông không giết nhưng phẫn nộ.","anchor":"Năm đó Lý Thiến Mai chính là một trong ba người đã g**t ch*t một vương thú, cho nên đã được Yêu Tông chấp thuận"},{"chuong":"@c1220","importance":"bridge","mucCt":"gon","text":"Được lão già chiến trường nhắc tới, cho rằng với tu vi và pháp bảo của cô ta có thể phá được đầu lâu Cửu U Long.","anchor":"Nếu là Lý Thiến Maim với tu vi cùng với pháp bảo của cô ta, có lẽ có thể phá được cái đầu lâu"},{"chuong":"@c1221","importance":"bridge","mucCt":"vua","text":"Được nhắc nhiều lần: bị Yêu Tông trừng phạt phải đi vào sâu bên trong khe chiến trường, Vương Lâm lo lắng về tình trạng của nàng và quyết tâm vào khe tìm.","anchor":"hắn lo lắng về tình trạng của Lý Thiến Mai lúc này"},{"chuong":"@c1222","importance":"normal","mucCt":"vua","tieuDe":"Xác nhận là môn hạ cũ trưởng lão Yêu Tông","text":"Trưởng lão Yêu Tông xác nhận năm xưa thu nhận cô làm môn hạ và đồng ý cho cô rời đi. Nữ tử lạnh lùng nhận ra Lý Thiến Mai vào khe nứt là vì Vương Lâm.","anchor":"Lý Thiến Mai hiển nhiên là vì hắn"},{"chuong":"@c1223","importance":"bridge","mucCt":"ky","text":"Được nhắc nhiều lần. Vương Lâm hồi tưởng huyết quang của nàng đã cứu hắn mười năm trong Thiên Nghịch. Tại biên giới khe nứt Tử Giới, Vương Lâm tìm được manh mối đầu tiên qua dao động thần thông còn sót lại, rồi dùng Tuế Nguyệt Nghịch Chuyển nhìn thấy ảo ảnh quá khứ: nữ tử áo lam bị thương nặng, quần áo nhuốm máu, tay cầm trường kiếm, bút vàng vờn quanh, đang nhanh chóng bay đi.","anchor":"Vương Lâm than nhẹ, lại nhớ đến lời nói của lão bà áo trắng, nghĩ đến huyết quang tồn tại mười năm bên trong Thiên Nghịch, hắn lại càng mắc nợ Lý Thiến Mai, không thể đền đáp được."},{"mucCt":"ky","text":"Gầy yếu da bọc xương, dung nhan biến đổi, cầm trường kiếm giao chiến với hư ảnh tiên tử nhưng bị đánh phun máu bật lùi. Đã dùng hết toàn bộ pháp bảo, trường kiếm tan vỡ, nguyên lực và đan dược cạn kiệt, chỉ còn cây bút màu vàng vẽ ký hiệu chống cự yếu ớt. Đạo lam quang bảo vệ quanh nàng sắp sụp đổ, tuyệt vọng nhắm mắt chờ chết, thì thào “ta không hối hận”. Nghe tiếng nổ kinh thiên và tiếng kêu dài từ xa truyền đến, mở mắt không dám tin, nước mắt chảy xuống.","anchor":"Ta sắp chết rồi. không biết chàng đã thức tỉnh chưa. ta không còn cơ hội nhìn thấy chàng nữa.","bridge":true,"khoang":"@c1224"},{"mucCt":"ky","text":"Lam quang bảo hộ trên thân bị hư ảnh chiếc roi khổng lồ quất vỡ, mãnh thú lao tới tấn công. Cây bút màu vàng trong tay tan vỡ hóa kim quang tản ra. Sức sống cạn kiệt sau mười năm hao tổn, nguyên thần suy yếu, hồn phách bắt đầu tan rã. Khi nhìn thấy Vương Lâm lộ nụ cười ôn nhu, nói lời cảm ơn rồi nhắm mắt. Được Vương Lâm dùng nguyên lực phong bế sức sống và thi triển Tuế Nguyệt thần thông kéo dài sự sống, nhưng nếu dừng thì sức sống sẽ tiêu tan tức khắc.","anchor":"nguyên thần của Lý Thiến Mai bắt đầu suy yếu, hồn phách của nàng cũng bắt đầu tan rã","bridge":true,"khoang":"@c1225"},{"chuong":"@c1226","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm ôm trong tay phải bảo vệ khi hắn mở phong ấn đột phá, chính ân nghĩa mười năm của nàng là động lực khiến Vương Lâm quyết định mở phong ấn.","anchor":"vì Lý Thiến Mai, vì đền đáp ân nghĩa suốt mười năm của nữ tử này"},{"chuong":"@c1227","importance":"bridge","mucCt":"vua","text":"Đã bị thương nặng bởi roi của bọ cạp chín đuôi (phá vỡ lam quang bảo hộ), được Vương Lâm ôm trong tay suốt trận chiến, sau khi Vương Lâm hóa Cổ Thần thì được nắm trong lòng bàn tay.","anchor":"Ngươi đả thương nữ tử này, ta sẽ lấy đi tính mạng nhà ngươi"},{"chuong":"@c1228","importance":"bridge","mucCt":"vua","tieuDe":"","text":"Sinh cơ dần tiêu tán, Vương Lâm dùng Tuế Nguyệt thần thông trì hoãn nhưng không thể ngăn hoàn toàn, tình trạng nàng trở thành con bài mặc cả giữa Y Nguyệt và Vương Lâm.","anchor":"sinh cơ nữ tử này hoàn toàn tiêu tán"},{"importance":"bridge","mucCt":"vua","chuong":"@c1230","tieuDe":"Được Vương Lâm che chở ra khỏi khe nứt","text":"Được Vương Lâm tay phải che chở khi ra khỏi khe nứt chiến trường, sau đó được đặt lên lưng hắn, dùng nguyên lực buộc hai người lại.","anchor":"tay phải Vương Lâm che chở Lý Thiến Mai, giơ tay trái lên"},{"chuong":"@c1232","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm giấu trên người khi hắn hóa Lục tinh Cổ Thần, liên tục được duy trì Tuế Nguyệt thần thông.","anchor":"Lý Thiến Mai được hắn giấu ở trên người"},{"importance":"bridge","mucCt":"gon","chuong":"@c1234","tieuDe":"Được bảo vệ trong thiên kiếp","text":"Được Vương Lâm toàn lực bảo vệ suốt thiên kiếp, không chịu chút tổn thương nào.","anchor":"Lý Thiến Mai vẫn không phải chịu chút tổn thương nào"},{"chuong":"@c1235","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm ôm theo khi lao ra khỏi Phong Giới Đại Trận tới Thái Cổ Tinh Thần.","anchor":"tay phải ôm Lý Thiến Mai, trực tiếp hóa thành một đạo cầu vồng từ trong lỗ hổng lao ra"},{"chuong":"@c1240","importance":"bridge","mucCt":"vua","text":"Được Vương Lâm lấy ra từ khe trữ vật, thần sắc suy sụp sinh cơ tiêu tán, được dùng Tuế Nguyệt thần thông duy trì, ôm đi tới Lam Ti tinh vực tìm Lam Mộng Đạo Tôn cứu chữa.","anchor":"Thần sắc Lý Thiến Mai càng thêm suy sụp, sắp sửa héo rũ đi"},{"chuong":"@c1241","importance":"normal","tieuDe":"Tỉnh lại nhưng mất toàn bộ trí nhớ, trở thành Lam Nguyệt","text":"Được Lam Mộng Đạo Tôn mang về Lam Sơn, trục hết hắc khí từ thất khiếu, khôi phục dung mạo và tỉnh lại. Tuy nhiên mất toàn bộ trí nhớ, tự xưng Lam Nguyệt. Khi gặp Vương Lâm trên đỉnh núi, hỏi hắn là ai. Nhìn Vương Lâm bị đẩy tung đi, mơ hồ cảm thấy đau lòng và quen thuộc, hỏi phụ thân tại sao cảm giác hắn rất quan trọng.","anchor":"Phụ thân, tại sao khi con thấy hắn lại có một cảm giác quen thuộc","mucCt":"ky"},{"chuong":"@c1242","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Vương Lâm để lại Lam Sơn, hắn rời đi một mình.","anchor":"Mang theo Lý Thiến Mai mà đến, rời đi một mình"},{"chuong":"@c1248","importance":"normal","tieuDe":"Thổ nạp trên Lam Sơn","text":"Lý Thiến Mai yên lặng thổ nạp bên cạnh Lam Mộng Đạo Tôn trên Lam Sơn khi Vương Lâm rời khỏi tinh vực Lam Ti Tộc.","anchor":"Lý Thiến Mai yên lặng ngồi thổ nạp"},{"mucCt":"vua","text":"Lý Thiến Mai ở Lam sơn trong Tam Ti tộc khi chấn động từ tinh không truyền tới. Trong mắt nàng xuất hiện mê man và vùng vẫy, như có ký ức không thể quên đang chậm rãi thức tỉnh.","anchor":"Có một ký ức nào đó nàng không thể nào quên đang chậm rãi thức tỉnh","bridge":true,"khoang":"@c1275"},{"chuong":"@c1284","importance":"normal","mucCt":"ky","tieuDe":"Quyết ý tìm người","text":"Lý Thiến Mai đã tỉnh táo hơn và khôi phục một phần ký ức về Vương Lâm. Nàng nói với Lam Mộng Đạo Tôn rằng không ai nhìn thấu tương lai của Vương Lâm. Nàng khẳng định khi trí nhớ hoàn toàn khôi phục sẽ đi tìm hắn.","anchor":"Khi trí nhớ của con hoàn toàn khôi phục, con sẽ đi tìm huynh ấy"},{"mucCt":"gon","text":"Lý Thiến Mai được nhắc trong phần dựng khí thế Vương Lâm, khi hắn từng dựa vào lực lượng bản thân tới Thái Cổ Tinh Thần chỉ vì tiễn nàng.","anchor":"Lại cũng dựa vào lực lượng bản thân mà tới Thái Cổố Tinh Thần chỉ vì tiễn Lý Thiến Mai","bridge":true,"khoang":"@c1290"},{"chuong":"@c1312","importance":"bridge","mucCt":"gon","tieuDe":"Xuất hiện cạnh Lam Mộng","text":"Lý Thiến Mai xuất hiện cùng Lam Mộng Đạo Tôn trong hình ảnh đôi phụ tử toàn thân lam quang tại trường đấu.","anchor":"một chỗ khác là ở gần bọn hắn, một đôi phụ tử toàn thân tràn ngập lam quang!"},{"mucCt":"vua","anchor":"chính là nữ tử trong hai phụ tử thân thể tràn ngập lam quang kia","text":"Lý Thiến Mai xuất hiện bên cạnh Lam Mộng đạo tôn trong lam quang, nhìn Vương Lâm bằng ánh mắt nhu hòa pha mê man như muốn nhớ lại. Vương Lâm khi thấy nàng cũng thoáng hiện vẻ phức tạp, còn lão Chu Tước chú ý đến nàng với thần sắc cổ quái.","bridge":true,"khoang":"@c1313"},{"chuong":"@c1318","importance":"bridge","mucCt":"gon","tieuDe":"Rơi lệ nhìn hương","text":"Lý Thiến Mai nhìn cây hương thứ nhất với tâm trạng phức tạp rồi cắn môi rơi nước mắt.","anchor":"cắn cắn môi, trong mắt có nước mắt phức tạp chảy xuống"},{"mucCt":"vua","text":"Lý Thiến Mai nhìn Lam Mộng Đạo Tôn trong lúc tình thế của Vương Lâm nguy hiểm, ánh mắt từ mê man chuyển thành thống khổ và cầu xin. Nỗi lo của nàng khiến Lam Mộng Đạo Tôn phải lên tiếng trấn an.","anchor":"trong đôi mắt đẹp còn có vẻ mê man","bridge":true,"khoang":"@c1319"},{"chuong":"@c1320","importance":"bridge","mucCt":"gon","text":"Được Lam Mộng đạo tôn quay lại trấn an rằng Vương Lâm không đáng ngại sau biến cố thí luyện.","anchor":"Lam Mộng đạo tôn không hề mở miệng, trầm ngâm hồi lâu, xoay người đi tới bên người Lý THiến Mai"},{"chuong":"@c1322","importance":"bridge","mucCt":"gon","text":"Được Lam Mộng Đạo Tôn dùng lam quang bao phủ bảo vệ khi Đại đế tinh và sương mù từ lực dị biến.","anchor":"toàn thân tỏa ra lam quang, tràn ngập thân thể nữ nhi của mình"},{"chuong":"@c1323","importance":"bridge","mucCt":"gon","text":"Ở cạnh Lam Mộng đạo tôn, cúi đầu sau biến cố Địa phương hương gãy.","anchor":"Lý THiến Mai bên cạnh hắn, cúi đầu không biết có biểu hiện gì"}],"tuViMoc":[],"nhanMach":[{"ten":"Trưởng lão Yêu Tông","tag":"su-mon","quanHe":"Sư phụ cũ tại Yêu Tông","ghiChu":"Năm xưa thu nhận vì yêu mến tài năng, đồng ý cho rời đi"},{"ten":"Lam Mộng Đạo Tôn","tag":"cha-me","quanHe":"Phụ thân, chữa trị hắc khí và đặt tên Lam Nguyệt cho nàng","ghiChu":"Đạo Tôn gọi nàng là Nguyệt nhi, sai nàng ra gặp Vương Lâm","nguon":"@c1241"},{"ten":"Lam Mộng Đạo Tôn","tag":"dong-minh","quanHe":"cùng ở Lam Sơn","ghiChu":"Lý Thiến Mai thổ nạp bên cạnh Lam Mộng Đạo Tôn trên Lam Sơn sau khi Vương Lâm rời đi."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người rời Lam Ti","ghiChu":"Lý Thiến Mai ở lại Lam Sơn trong lúc Vương Lâm rời tinh vực Lam Ti Tộc."},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"người nàng muốn tìm lại","ghiChu":"Ký ức về Vương Lâm đã khôi phục một phần và nàng quyết ý đi tìm hắn khi nhớ lại hoàn toàn."}],"tuiDo":{"phapBao":[{"ten":"Ngọc bội mệnh hồn","trangThai":"da-dung","moTa":"Đặt lên tượng đá Vương Lâm trước khi rời đi, tỏa ánh sáng nhu hòa duy trì tượng đá khoảng một tháng, sau đó ánh sáng mờ dần và xuất hiện khe nứt","nguon":"@c1214"},{"ten":"Tiểu kiếm bạc","moTa":"Dùng đâm vào tim lấy tinh huyết khi tinh huyết đầu lưỡi không đủ cung cấp cho tượng đá","nguon":"@c1214"},{"ten":"Chín thanh phi kiếm","trangThai":"da-dung","moTa":"Bố trí thành kiếm trận bảo vệ sơn cốc khi rời đi, đã bị bà lão bạch y dùng ngọc giản hóa giải","nguon":"@c1214"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Thiên tài tu đạo truyền kỳ Vân Hải tinh vực: 5 tuổi nhập đạo, hơn 1200 năm đạt Toái Niết hậu kỳ","chuong":"@c1090"},{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên — đạo — nơi đi, kết hẹn ước trăm năm","chuong":"@c1097"},{"text":"Bất chấp lệnh cấm rời chiến trường Yêu Tông, vượt tinh vực tìm Vương Lâm, bị Phá Thiên Tông đoạn tuyệt sư đồ","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi và tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã, kiệt sức gần mất sinh cơ","chuong":"@c1214"},{"text":"Được Vương Lâm tiếp nhận sau khi khôi phục ký ức, xác nhận tình cảm giữa hai người","chuong":"@c1583"},{"text":"Quyết định chuyển thế đầu thai, nguyện chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi","chuong":"@c1697"}]},"cn":"李倩梅","gioiTinh":"nu","aliases":["Lý Oánh Chi","Lý Mộ Uyển","Lam Nguyệt","Lý Thiến Maim","nữ tử lam quang bên cạnh Lam Mộng đạo tôn","nữ tử bên cạnh Lam Mộng đạo tôn","nữ tử lam quang"],"tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","theLuc":[{"ten":"Lam Ti Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1312","vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi."},{"id":"ba-lao-bach-y","name":"Bà lão bạch y","cn":"","aliases":["Sư tỷ Lý Thiến Mai","Lão bà tóc bạc","Lão bà áo trắng","Bạch Bà Tử","Nữ thi áo trắng","Bà lão mặc bạch y"],"gioiTinh":"nu","theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết đại viên mãn","trangThai":"khong-ro","blurb":"Tu sĩ Toái Niết đại viên mãn xuất thân từ Yêu Tông cấp chín, sư tỷ của Lý Thiến Mai. Từ đại lục hoang dã, bà lần theo các chặng truyền tống cùng Vương Lâm, chứng kiến ngọc bội mệnh hồn Lý Thiến Mai nứt vỡ vớiẻ bi ai, rồi dẫn hắn đến khe chiến trường Yêu Tông.","vaiTro":"Sư tỷ của Lý Thiến Mai tại Yêu Tông cấp chín — người dẫn đường cho Vương Lâm","tinhCach":"Gắn bó, quan tâm với Lý Thiến Mai như người thân; thận trọng, dè chừng trước những phương thức truyền tống nguy hiểm; sẵn lòng dẫn đường, hỗ trợ Vương Lâm","tabs":{"diem":[{"text":"Từ Yêu Tông cấp chín dùng ngọc giản dò đường, tản thần thức quét toàn đại lục hoang dã tìm sơn cốc","chuong":"@c1214"},{"text":"Cùng Vương Lâm truyền tống từ tinh vực cấp dưới lên tinh vực cấp sáu qua phương thức cưỡng ép nguy hiểm","chuong":"@c1216"},{"text":"Theo sát Vương Lâm khi hắn bước vào Vô Cực Tông","chuong":"@c1217"},{"text":"Chứng kiến ngọc bội mệnh hồn Lý Thiến Mai nứt, thần sắc kịch biến lộ vẻ bi ai","chuong":"@c1218"},{"text":"Dẫn đường và bay cùng Vương Lâm đến khe chiến trường Yêu Tông, được tu sĩ nơi đây nhận ra","chuong":"@c1221"}],"kinhLich":[{"mucCt":"vua","text":"Từ Yêu Tông cấp chín dùng ngọc giản dò đường tới đại lục hoang dã, tản thần thức quét toàn đại lục tìm sơn cốc, hóa giải kiếm trận chín phi kiếm rồi đưa hồn huyết (trái cầu máu — phần hồn phách ngưng tụ) dung nhập tượng đá Vương Lâm. Kể lại toàn bộ sự hy sinh mười năm của Lý Thiến Mai với vẻ bi phẫn, bị Vương Lâm nhìn thấu nguyên thần kinh hãi lùi lại, cuối cùng bị hắn bắt giữ bắt dẫn đường tới chiến trường Yêu Tông.","anchor":"Ta nhìn nàng lớn lên từ nhỏ, là sư tỷ của nàng","bridge":true,"khoang":"@c1214"},{"mucCt":"vua","text":"Nói rõ tuyến đường truyền tống nhiều chặng: Hải Hồn Tông (tinh vực cấp bốn) → tinh vực cấp sáu → Tiên Âm Môn → Vô Cực Tông (tinh vực cấp tám) → tinh vực cấp chín → Yêu Tông. Cảnh báo truyền tống trận cần rất nhiều nguyên tinh. Bị Vương Lâm kéo theo suốt đường, kinh hãi trước tốc độ và khí thế, hơi hối hận đã kể hết mọi chuyện.","anchor":"Bà mơ hồ cảm thấy, người thanh niên trước mặt này tựa hồ sau khi nghe hết thảy những lời mình nói, sau khi nói xong bốn chữ kia, dường như từ tiên biến thành ma!","bridge":true,"khoang":"@c1215"},{"chuong":"@c1216","importance":"bridge","mucCt":"vua","text":"Cùng Vương Lâm truyền tống từ tinh vực cấp dưới lên tinh vực cấp sáu, sợ hãi vì phương thức cưỡng ép nguy hiểm. Chỉ đường cho Vương Lâm tới Tiên Âm Môn, chứng kiến hắn phá trận và ép giao nguyên tinh, rồi cùng truyền tống tới Vô Cực Tông.","anchor":"Bà trước đây còn lo lắng vấn đề nguyên tinh, nhưng khi thấy Vương Lâm tiếp nhận túi trữ vật của đối phương thì trong lòng thầm cười khổ."},{"chuong":"@c1217","importance":"minor","mucCt":"gon","text":"Theo sát Vương Lâm khi hắn bước vào Vô Cực Tông.","anchor":"Bà lão mặc bạch y kia vội vàng theo sát phía sau hắn."},{"chuong":"@c1218","importance":"bridge","mucCt":"gon","text":"Nhìn thấy ngọc bội mệnh hồn Lý Thiến Mai nứt, thần sắc kịch biến, ánh mắt lộ vẻ bi ai.","anchor":"thần sắc nổi lên kịch liệt, ánh mắt lộ ra vẻ bi ai"},{"chuong":"@c1219","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm cuốn đi sau trận Vô Cực Tông, sau đó chỉ đường cho Vương Lâm đến cái khe chiến trường Yêu Tông trong tầng thứ chín tinh vực.","anchor":"Giờ phút này, Vương Lâm dưới sự chỉ dẫn của lão bà áo trắng càng ngày càng tới gần nơi đây."},{"chuong":"@c1221","importance":"bridge","mucCt":"vua","text":"Bay cùng Vương Lâm đến khe chiến trường Yêu Tông, được tu sĩ ở đây nhận ra. Xác nhận với Vương Lâm rằng Lý Thiến Mai đã đi vào bên trong khe.","anchor":"Bạch Bà Tử nửa tháng trước rời khỏi, nghe nói là phụng mệnh của Yêu Tông"},{"chuong":"@c1223","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ lại lời nói liên quan đến huyết quang và Lý Thiến Mai.","anchor":"lại nhớ đến lời nói của lão bà áo trắng"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"su-mon","quanHe":"Sư muội, nhìn nàng lớn lên từ nhỏ","ghiChu":"Thay nàng đưa hồn huyết cứu Vương Lâm"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được cứu tỉnh","ghiChu":"Bị hắn nhìn thấu nguyên thần rồi bắt giữ bắt dẫn đường"}],"tuiDo":{"phapBao":[{"ten":"Ngọc giản","moTa":"Dùng dò phương hướng tìm sơn cốc, phát ra khí tức nhu hòa hóa giải kiếm trận chín phi kiếm của Lý Thiến Mai","nguon":"@c1214"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1214","@c1215","@c1216","@c1217","@c1218","@c1219","@c1221","@c1223"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","cn":"李慕婉","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1215","importance":"bridge","mucCt":"gon","text":"Được nhắc trong hồi tưởng: Lý Thiến Mai không muốn cướp đoạt địa vị của Lý Mộ Uyển trong lòng Vương Lâm, nàng từng chờ đợi hắn trong cô độc.","anchor":"có lẽ nàng không như Lý Mộ Uyển chờ đợi hắn trong cô độc"},{"chuong":"@c1243","importance":"normal","mucCt":"gon","tieuDe":"Lý do Vương Lâm cự tuyệt đạo thống","text":"Được Vương Lâm nghĩ tới khi cự tuyệt điều kiện kết đạo lữ với nữ nhi Lam Mộng Đạo Tôn — là lời hứa cả đời không thể từ bỏ.","anchor":"từ bỏ Lý Mộ Uyển"},{"chuong":"@c1248","importance":"normal","tieuDe":"Dung mạo bị mượn","text":"Lý Mộ Uyển không trực tiếp xuất hiện, nhưng dung mạo của Lan Phi Lâu Lan hiện ra giống nàng khiến Vương Lâm lập tức hoảng hốt trong khoảnh khắc giao chiến. Điểm yếu tâm thần ấy bị Lan Phi Lâu Lan lợi dụng để hút thần tính từ tinh điểm Cổ Thần của hắn.","anchor":"Dung nhan của nữ tử này không ngờ chính là Lý Mộ Uyển"},{"chuong":"@c1276","importance":"normal","mucCt":"vua","tieuDe":"Mối thù cướp hồn","text":"Lý Mộ Uyển được Vương Lâm nhắc lại như người năm xưa bị sứ giả thiên đạo cướp hồn phách. Việc này trực tiếp khiến Vương Lâm bùng nộ, chém bàn tay sứ giả và thề tương lai phá thiên địa báo thù cho hiền thê.","anchor":"cướp đi hồn phách của Uyển Nhi trong tay ra"},{"chuong":"@c1282","importance":"bridge","mucCt":"gon","text":"Lý Mộ Uyển được Vương Lâm nhắc tới khi hắn tự thuật cuộc đời nghịch thiên và việc từng tranh đoạt linh hồn nàng với thiên đạo.","anchor":"Ta tranh đoạt linh hồn hiền thê với thiên đạo, đánh bại năm tháng"},{"mucCt":"gon","text":"Lý Mộ Uyển được nhắc trong phần dựng phong phạm đại tông sư của Vương Lâm, gắn với việc hắn từng đoạt mệnh nàng với thiên đạo để tìm sinh cơ.","anchor":"Đoạt mệnh Lý Mộ Uyên với thiên đạo, trong hung hiểm tìm một đường sinh cơ","bridge":true,"khoang":"@c1290"},{"chuong":"@c1315","importance":"normal","mucCt":"vua","tieuDe":"Hiện ra trong huyễn cảnh cửa Nhân thời thiếu nữ","text":"Trong huyễn cảnh cửa Nhân, hình ảnh Lý Mộ Uyển thời thiếu nữ hiện ra tại Lạc Hà môn — nàng luyện đan thất bại, bị sư tôn sai đi lấy Thủy Nguyệt thảo, lè lưỡi hớn hở chạy khỏi đan phòng. Trong huyễn cảnh cửa Nhân, Lý Mộ Uyển hiện ra với dáng vẻ thiếu nữ ở Lạc Hà môn. Nàng luyện đan thất bại trong đan phòng, gọi sư tôn và bị sai đi lấy Thủy Nguyệt thảo để luyện lại. Xuất hiện trong huyễn giới cửa Nhân dưới hình dạng thiếu nữ xinh đẹp tại đan phòng Lạc Hà môn, Hỏa Phần quốc. Luyện đan thất bại, nói với sư tôn rằng Uyển nhi lại không luyện thành, được sai đi lấy Thủy Nguyệt thảo rồi vui vẻ chạy đi. Là người mà Vương Lâm muốn nhìn trước khi đốt hương.","anchor":"Sư tôn, Uyển nhi lại không luyện thành"},{"chuong":"@c1316","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện trong huyễn giới Lạc Hà môn","text":"Trong thế giới hồn thí luyện, Lý Mộ Uyển hiện thân dưới dáng thiếu nữ áo vàng đệ tử Lạc Hà môn, đang học luyện đan và hái thảo dược trên núi. Nàng phát hiện thú nhỏ bị thương nặng, dùng thảo dược nghiền nát bôi cho nó nhưng không đủ cứu. Vương Lâm xuất hiện dùng bạch quang chữa lành con thú, nàng tự xưng vãn bối ra mắt rồi sợ hãi rời đi. Bốn ngày sau nàng vượt qua sợ hãi quay lại đỉnh núi nhờ Vương Lâm cứu thêm một con thú nhỏ khác, sự cảnh giác giảm bớt khi thấy hắn cứu chữa thành công.","anchor":"Vãn bối Lý Mộ Uyển ra mắt tiền bối."},{"mucCt":"vua","text":"Trong Nhân giới hư ảo, Lý Mộ Uyển nhiều lần lên núi gặp Vương Lâm và tinh tế nhận ra hắn ngày càng suy yếu, già nua. Khi biển lửa của Lão Chu Tước giáng xuống, nàng được Vương Lâm ôm lấy che chở, rồi tâm thần chấn động trước lời hắn nói và kinh ngạc hỏi hắn là ai.","anchor":"Chẳng qua tiéng nói của hắn lại khiến cho tâm thần Lý Mộ Uyển chấn động vô cùng","bridge":true,"khoang":"@c1317"},{"chuong":"@c1318","importance":"normal","mucCt":"vua","tieuDe":"Nghe tên Vương Lâm","text":"Trong trạng thái hư ảo, Lý Mộ Uyển chứng kiến Vương Lâm tan biến rồi hóa thành Chu Tước đen giữa nghiệp hỏa. Nàng bị chấn động và suy yếu, gắng gượng hỏi thân phận hắn, sau cùng nghe hắn tự nói tên thật là Vương Lâm.","anchor":"- Ngươi rốt cục là ai!"}],"nhanMach":[{"ten":"Nữ tử áo trắng","tag":"khac","quanHe":"Dung mạo giống hệt","ghiChu":"Nữ tử áo trắng hiện ra dung mạo giống nàng khi áp sát Vương Lâm."},{"ten":"Lan Phi","tag":"khac","quanHe":"dung mạo tương đồng","ghiChu":"Dung nhan Lan Phi Lâu Lan hiện ra giống Lý Mộ Uyển và được dùng để tác động vào Vương Lâm."},{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"người trong lòng","ghiChu":"Dung mạo giống Lý Mộ Uyển khiến Vương Lâm chấn động trong lúc bị Lan Phi Lâu Lan khống chế."},{"ten":"Sứ giả thiên đạo","tag":"doi-thu","quanHe":"Kẻ cướp hồn","ghiChu":"Bị Vương Lâm xác nhận là kẻ năm xưa cướp hồn phách Uyển Nhi."},{"ten":"Sư tôn của Uyển nhi","tag":"su-mon","quanHe":"sư tôn","ghiChu":"Người dạy và sai nàng đi lấy Thủy Nguyệt thảo trong cảnh Lạc Hà môn."},{"ten":"Sư tôn của Lý Mộ Uyển","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Người sai nàng đi hái thảo dược và cũng là lý do nàng viện ra để rời khỏi Vương Lâm."},{"ten":"Ca ca của Lý Mộ Uyển","tag":"ho-hang","quanHe":"Ca ca","ghiChu":"Được nàng nhắc là có thiên tư tốt hơn và được môn phái bồi dưỡng trọng điểm."},{"ten":"Sư tỷ của Lý Mộ Uyển","tag":"su-mon","quanHe":"Sư tỷ","ghiChu":"Lời sư tỷ từng nói về lão quái tu chân giới khiến nàng cảnh giác với Vương Lâm."}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị Song Tu Môn truy sát vì Thiên Ly đan, được Vương Lâm cứu giúp, mở đầu mối duyên giữa hai người","chuong":"@c0123"},{"text":"Trong bốn năm đồng hành tại Tu Ma Hải, khắc 18.974 ngọc giản đan phương, thể hiện thiên phú luyện đan phi phàm","chuong":"@c0135"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt không quá mười năm, thân xác suy kiệt tang thương","chuong":"@c0302"},{"text":"Thân xác hóa xương khô, kim đan nứt vỡ, nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành Chu Như","chuong":"@c0313"},{"text":"Từ chối cắn nuốt hồn phách Chu Như, tự đẩy nguyên anh ra khỏi thân thể để cứu cô bé, hy sinh cơ hội tái sinh","chuong":"@c0381"},{"text":"Tàn hồn được phát hiện dung nhập trong thân Tống Trí, Vương Lâm dùng một năm phân tách tàn hồn ra, nhưng hồn phách vẫn thiếu một phần chưa rõ tung tích","chuong":"@c0929"}]},"nguon":["@c1215","@c1243","@c1248","@c1276","@c1282","@c1290","@c1315","@c1316","@c1317","@c1318"],"aliases":["Lý Thiến Mai","Lý Oánh Chi","Lam Nguyệt","Uyển Nhi","Lý Mộ Uyên"],"tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; nặng tình sâu sắc với Vương Lâm; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để cứu Chu Như","canhGioiCaoNhat":"Không đổi trong @c1315","vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải. Sau hơn trăm năm, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô, nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như nhưng cuối cùng nàng tự đẩy nguyên anh ra để cứu Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt hàng trăm năm. Tới mốc sau cùng, tàn hồn nàng được phát hiện dung nhập trong thân Tống Trí và được Vương Lâm dùng một năm phân "},{"id":"tong-chu-hai-hon-tong","name":"Tông chủ Hải Hồn Tông","cn":"","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Khuy Niết đại viên mãn","trangThai":"song","theLuc":[{"ten":"Hải Hồn Tông","trangThai":"gan-bo"}],"blurb":"Tông chủ Hải Hồn Tông, tu vi Khuy Niết đại viên mãn, xưng hùng tinh vực cấp bốn. Bị Vương Lâm uy hiếp cưỡng mở truyền tống trận.","vaiTro":"Tông chủ Hải Hồn Tông, bị Vương Lâm uy hiếp trên đường cứu Lý Thiến Mai","tinhCach":"Biết thời thế, lập tức cung kính tuân lệnh khi đối mặt kẻ mạnh áp đảo","tabs":{"diem":[{"text":"Tu vi Khuy Niết đại viên mãn nhưng chỉ đối mắt Vương Lâm đã tự phun máu tạo thương tích, lập tức tuân lệnh không chút do dự.","chuong":"@c1215"}],"kinhLich":[{"mucCt":"vua","text":"Đang nhập định trong mật thất thì bị đánh thức bởi chấn động khi Vương Lâm phá đại trận phòng hộ. Vừa đối mặt ánh mắt Vương Lâm thì tâm thần bất ổn, phun máu tự tạo thương tích dù Vương Lâm không hề động thủ. Lập tức cung kính tuân lệnh mở truyền tống trận và giao nộp toàn bộ nguyên tinh.","anchor":"Hắn không nhìn ra tu vi của đối phương nhưng trong nháy mắt người này phá vỡ đại trận phòng hộ thì loại thần thông này cũng phải bình thường","bridge":true,"khoang":"@c1215"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị Vương Lâm uy hiếp mở truyền tống trận và giao nguyên tinh","ghiChu":"@c1215"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1215"]},{"id":"tong-chu-tan-nhiem-tien-am-mon","name":"Tông chủ tân nhiệm Tiên Âm Môn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tiên Âm Môn","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Tông chủ mới của Tiên Âm Môn sau khi tông chủ cũ bị Vương Lâm giết","tinhCach":"Thận trọng; biết thời thế; sợ kẻ mạnh","blurb":"Tông chủ tân nhiệm Tiên Âm Môn, lên nắm quyền sau khi tông chủ và đại trưởng lão tiền nhiệm bị Vương Lâm (Lữ Tử Hạo) giết mười năm trước. Khi Vương Lâm quay lại, không dám kháng cự, lập tức giao nguyên tinh và mở truyền tống trận.","tabs":{"diem":[{"text":"Chứng kiến trận chiến năm xưa, từng tận mắt thấy tông chủ tiền nhiệm tử vong trong tay Vương Lâm","chuong":"@c1216"},{"text":"Biết thời thế, sẵn sàng giao cả Tiên Âm Môn nếu Vương Lâm đòi, chỉ cầu hắn rời đi nhanh","chuong":"@c1216"}],"kinhLich":[{"mucCt":"vua","text":"Khi Vương Lâm phá đại trận phòng ngự Tiên Âm Môn, tông chủ tân nhiệm nhận ra đó là Lữ Tử Hạo năm xưa, toát mồ hôi kinh hãi. Lập tức phát lệnh mở truyền tống trận và giao toàn bộ nguyên tinh, tự nhủ dù Vương Lâm muốn cả Tiên Âm Môn cũng chắp tay đưa ra.","anchor":"Đừng nói hắn muốn nguyên tinh, cho dù muốn cả Tiên Âm Môn, lão phu cũng chắp tay đưa ra, chỉ cầu hắn có thể nhanh chóng rời đi.","bridge":true,"khoang":"@c1216"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết tông chủ và đại trưởng lão tiền nhiệm, khiếp sợ uy danh của hắn","gap":"@c1216"}],"tuiDo":{}},"nguon":["@c1216"]},{"id":"vo-cuc-tu","name":"Vô Cực Tử","cn":"无极子","aliases":["Tông chủ Vô Cực Tông"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1217","importance":"normal","mucCt":"vua","tieuDe":"Đối đầu Vương Lâm, kể ân tình Vô Cực Tông","text":"Kể lại các ân tình với Vương Lâm: cho cực âm, không truy cứu vụ giết người Tiên Âm Môn, cho Quy Nguyên Tông lên tinh vực cấp bảy. Triệu long kiếm bảy thước tấn công nhưng bị ngàn vạn kiếm khí đánh lui. Nghe Vương Lâm nói đã đánh trọng thương Thủy Đạo Tử thì chấn động.","anchor":"Lữ đạo hữu, Vô Cực Tông đối đãi với ngươi không tệ."},{"chuong":"@c1218","importance":"bridge","mucCt":"gon","text":"Tham gia vây công Vương Lâm cùng sáu trưởng lão nhưng bị một kiếm trấn áp, không dám ngăn cản khi Vương Lâm rời đi.","anchor":"trong mắt cũng lóe lên sát khí vọt tới"}],"diem":[{"text":"Từng tham sức mạnh Cổ Thần, dung hợp thành một thể và bị giam trong tinh điểm thứ tư trên mi tâm","chuong":"@c1066"},{"text":"Bị hắc y lão giả nhiều lần nhắc tên cùng ước định năm xưa, khiêu khích vì không chịu hiện thân","chuong":"@c1020"},{"text":"Thay đổi nhìn nhận về Lữ Tử Hạo, không còn coi là vãn bối mà là người cùng thế hệ","chuong":"@c1183"},{"text":"Bùng uy áp Thiên Nhân Suy Kiếp đối đầu Vương Lâm: ánh mắt hóa kiếm quang, sấm sét phải tránh, mưa ngừng giữa trời","chuong":"@c1188"},{"text":"Khuất nhục chấp nhận ý chỉ Thần Tông hủy bỏ đại hội phân tông cấp tám","chuong":"@c1196"},{"text":"Tham gia vây công Vương Lâm cùng sáu trưởng lão nhưng bị một kiếm trấn áp, không dám ngăn cản","chuong":"@c1218"}]},"nguon":["@c1217","@c1218"],"vaiTro":"Đại nhân vật bí ẩn của Quy Nguyên Tông, gắn với sức mạnh Cổ Thần","tinhCach":"Thâm trầm bí ẩn, lâu không chịu hiện thân; trọng đại cục, biết nhẫn nhịn khuất nhục; uy áp cường đại; công tâm nhìn nhận và nâng đỡ người tài","blurb":"Vô Cực Tử là nhân vật bí ẩn từng tham sức mạnh Cổ Thần nên bị dung hợp làm một thể và giam trong tinh điểm thứ tư trên mi tâm, nhiều lần bị hắc y lão giả nhắc tên cùng ước định năm xưa. Về sau hắn lộ diện gắn với các sự kiện của Quy Nguyên Tông, đánh giá cao và nâng đỡ nhân tài như Lữ Tử Hạo, đồng thời bùng uy áp Thiên Nhân Suy Kiếp đối đầu Vương Lâm. Dù mang uy thế lớn, hắn vẫn phải khuất nhục chấp nhận ý chỉ Thần Tông hủy bỏ đại hội phân tông và cuối cùng bị Vương Lâm một kiếm trấn áp."},{"id":"hac-y-lao-gia-vo-cuc-tong","name":"Hắc y lão giả (thái thượng trưởng lão Vô Cực Tông)","aliases":["Thái thượng trưởng lão Vô Cực Tông"],"gioiTinh":"nam","theLuc":[{"ten":"Vô Cực Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhất Suy","trangThai":"song","blurb":"Thái thượng trưởng lão tóc bạc trắng của Vô Cực Tông, tu vi Thiên Nhân Đệ Nhất Suy. Cố ngăn Vương Lâm đoạt pháp khí Cổ Thần nhưng bị đánh bại, chụp nát huyết thệ của Vương Lâm khiến thương lượng thất bại hoàn toàn.","vaiTro":"Thái thượng trưởng lão Vô Cực Tông, ngăn cản Vương Lâm đoạt pháp khí","tinhCach":"Cao ngạo; coi thường kẻ yếu; quyết đoán tàn nhẫn khi chụp nát huyết thệ","tabs":{"diem":[{"text":"Thi triển mười chín lôi cầu nhưng bị Vương Lâm giành quyền khống chế bằng một chữ «Lôi», lôi đình quay ngược tấn công chính mình.","chuong":"@c1217"},{"text":"Chụp nát huyết thệ của Vương Lâm, chặn đứng mọi cơ hội thương lượng.","chuong":"@c1217"},{"text":"Triệu mười chín lôi cầu kinh thiên tấn công Vương Lâm nhưng bị đoạt quyền khống chế, lôi cầu quay ngược đánh chính mình","chuong":"@c1217"},{"text":"Bóp nát huyết thệ chứa hồn phách của Vương Lâm, cắt đứt mọi khả năng thương lượng","chuong":"@c1217"}],"kinhLich":[{"chuong":"@c1217","importance":"normal","mucCt":"vua","tieuDe":"Đối đầu Vương Lâm tại sơn môn Vô Cực Tông","text":"Từ đại điện lao ra gọi tên Lữ Tử Hạo, triệu mười chín lôi cầu tấn công nhưng bị Vương Lâm đoạt quyền khống chế đánh ngược. Tung lôi đình tím tiếp chiến, bị ngàn vạn kiếm khí đánh tan lôi đình phun máu lui lại. Trào phúng Vương Lâm tự coi là đại trưởng lão Thần Tông, chụp lấy bóp nát huyết thệ của Vương Lâm.","anchor":"Lữ Tử Hạo! Không ngờ là ngươi! Ngươi muốn chết sao!"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, cố ngăn Vương Lâm đoạt pháp khí nhưng bại trận"},{"ten":"Vô Cực Tử","tag":"cap-tren","quanHe":"Tông chủ Vô Cực Tông, cùng phe"},{"ten":"Vô Cực Tử","tag":"dong-minh","quanHe":"Tông chủ, cùng xuất thủ chống Vương Lâm"}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c1217"]},{"id":"thuy-dao-tu","name":"Thủy Đạo Tử","aliases":["Đạo nô"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Trong mật thất Thần Tông tầng thứ chín, toàn thân phát ánh sáng bảy màu, dung nhan lão hóa rồi nghịch chuyển liên tục, chịu thống khổ sinh tử đan xen suốt mười năm. Hai mắt đã không còn đồng tử, bị ánh sáng bảy màu che khuất. Thề trả thù Vương Lâm gấp ngàn vạn lần, nhắc đến chủ nhân tuy không chết nhưng cực kỳ suy yếu.","anchor":"Tiểu tạp chủng, những thống khổ mà lão phu phải chịu đựng, sớm muộn cũng sẽ có ngày ta hoàn trả lại cho ngươi hàng ngàn hàng vạn lần","bridge":true,"khoang":"@c1219"},{"importance":"normal","mucCt":"ky","chuong":"@c1230","tieuDe":"Ép Thất Thải Đinh thất bại do ý chí Vương Lâm","text":"Đang ở mật thất Thần Tông trong thời khắc mấu chốt ép Thất Thải Đinh ra khỏi mi tâm. Ý chí Vương Lâm theo lôi đình xâm nhập mật thất, kích hoạt Thất Thải Đinh tỏa sáng chói mắt, khiến hắn phun máu, toàn bộ công sức uổng phí, gầm thét kinh thiên.","anchor":"Thất Thải Đinh ở mi tâm hắn vốn đã ảm đạm trong nháy mắt dưới lôi đình tập trung ý chí của Vương Lâm liền lập tức tỏa sáng chói mắt"},{"chuong":"@c1272","importance":"bridge","mucCt":"gon","text":"Được nhắc để so sánh uy lực kiếm thứ bảy của Vương Lâm: ngay cả Thủy Đạo Tử gặp phải cũng phải bỏ chạy.","anchor":"dù Thủy Đạo Tử gặp phải một kiếm này thì vẻ mặt cũng biến đổi lớn"},{"chuong":"@c1293","importance":"bridge","mucCt":"gon","tieuDe":"Được lấy làm mốc","text":"Thủy Đạo Tử được Vương Lâm dùng làm mốc so sánh khi suy đoán tu vi của Điên Lạc đại đế.","anchor":"tu vi đại đế nọ tuyệt đối hơn hẳn Thủy Đạo Tử một bậc"},{"chuong":"@c1308","importance":"bridge","mucCt":"gon","tieuDe":"Làm đối chiếu kiêng kỵ","text":"Thủy Đạo Tử được nhắc làm đối chiếu để thấy Vương Lâm còn kiêng kỵ Thiên Vận Tử hơn.","anchor":"Loại câm giác kiêng kỵ này thì dù là Thủy Đạo Tử cũng không bằng"},{"chuong":"@c1310","importance":"bridge","mucCt":"gon","tieuDe":"Được dùng so sánh","text":"Thủy Đạo Tử được Vương Lâm dùng làm mốc so sánh khi cảm nhận uy áp của Viêm long.","anchor":"hắn cảm nhận được rõ ràng uy áp này không ngờ không kém cảm giác Thủy Đạo Tử gây ra cho hắn năm đó chút nào"},{"chuong":"@c1314","importance":"bridge","mucCt":"vua","text":"Tin tức Thủy Đạo Tử từng truyền âm về thân phận chủ nhân phong giới của Vương Lâm tiếp tục ảnh hưởng tới sự dè chừng và tính toán của Diệu Âm đạo tôn.","anchor":"Thủy Đạo Tử hẳn không dám lừa ta"}],"nhanMach":[{"ten":"Chủ nhân Phong Giới","tag":"su-mon","quanHe":"Chủ nhân, Thủy Đạo Tử bị gọi là Đạo nô","ghiChu":"@c1233"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"mục tiêu tương lai mà Vương Lâm muốn giết","ghiChu":"Vương Lâm dùng việc phải giết Thủy Đạo Tử để tự đặt áp lực trong trận chiến với đại trưởng lão Thiểm Lôi Tộc."}],"tuViMoc":[],"diem":[{"text":"Tiết lộ quá khứ từng theo chủ nhân phong giới chinh chiến khắp thiên địa rồi phản bội đánh lén tôn sư, mưu bày Luân Hồi đại trận trong cung điện Thần Tông","chuong":"@c1193"},{"text":"Bị Thất Thải Thần Không Đinh găm hoàn toàn vào mi tâm hủy diệt, hy sinh toàn bộ môn phái để bỏ chạy bảo mạng","chuong":"@c1211"},{"text":"Cảm nhận Vương Lâm trở về, phát bảy đạo mệnh lệnh tổng động viên toàn Vân Hải tinh vực chống trả","chuong":"@c1414"},{"text":"Kích nổ chuông vàng Viễn cổ Tiên Vực bằng bí thuật do Chủ nhân phong giới truyền, mưu phá hủy toàn bộ Vân Hải tinh vực để đồng quy vu tận với Vương Lâm","chuong":"@c1419"},{"text":"Lật quân bài mệnh hồn cuối cùng nhưng thất bại, nguyên thần bị Vương Lâm đánh từng quyền phá hủy và diệt sát","chuong":"@c1421"},{"text":"Sau khi chết vẫn nhiều lần được Vương Lâm lấy làm mốc đối chiếu uy lực các cường giả khác như Điên Lạc đại đế, Thiên Vận Tử, Viêm Long","chuong":"@c1293"}]},"nguon":["@c1217","@c1219","@c1230","@c1233","@c1272","@c1270","@c1293","@c1308","@c1310","@c1314"],"cn":"水道子","canhGioiCaoNhat":"Không đổi trong @c1314","tinhCach":"Tàn nhẫn quyết đoán, giết lầm không tha kẻ khả nghi; phản trắc mưu mô, từng đánh lén tôn sư để đoạt quyền; liều mạng bất chấp tổn thất khi quyết diệt mục tiêu; tham sống sợ chết, sẵn sàng hy sinh toàn môn phái để bảo toàn bản thân","vaiTro":"Cao thủ Đệ Tam Bộ của Thần Tông — kẻ phản chủ truy sát Vương Lâm","blurb":"Thủy Đạo Tử là đồng tử tóc bạc tu vi Đệ Tam Bộ, nắm quyền cao nhất Thần Tông khi sư tôn Vương San vắng mặt, ngồi trấn tại cung điện trung tâm tinh vực cấp chín. Năm xưa y từng theo chủ nhân phong giới chinh chiến khắp thiên địa rồi phản bội đánh lén tôn sư, về sau điều tra truy sát Vương Lâm suốt nhiều năm. Trong trận quyết chiến cuối cùng, y lần lượt dùng hết mọi thủ đoạn từ pháp bảo chuông vàng Viễn cổ Tiên Vực đến quân bài mệnh hồn nhưng đều bị Vương Lâm hóa giải, cuối cùng nguyên thần bị đánh nát từng phần và bị diệt sát."},{"id":"lao-gia-ao-den","name":"Lão giả áo đen","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Dẫn đầu sáu trưởng lão Vô Cực Tông vây công Vương Lâm, quát rằng nên bắt giao cho Thần Tông lấy tặng phẩm. Bị huyết kiếm Cổ Thần chém, thân thể hóa thành máu tươi, chỉ còn nguyên thần giãy giụa thoát đi.","anchor":"thân thể hắn bị huyết kiếm chém tới, trong tiếng kêu thảm thiết thân thể hóa thành một đám máu tươi","bridge":true,"khoang":"@c1218"}],"diem":[{"text":"Một ngón tay xuyên sọ giết chết thượng cổ tu sĩ áo đỏ tóc râu đỏ trong hư vô","chuong":"@c1059"},{"text":"Thi triển thần thông Súc Thốn Thành Không, co rút cả thế giới thành một thiên địa thu nhỏ","chuong":"@c1062"},{"text":"Rút kiếm gãy phun máu kích hoạt, chống Thác Sâm xuyên thấu vòng xoáy để cứu Viêm Lôi Tử","chuong":"@c1066"},{"text":"Dẫn đầu sáu trưởng lão Vô Cực Tông vây công Vương Lâm, định bắt giao cho Thần Tông","chuong":"@c1218"},{"text":"Đánh lén Vương Lâm lúc bị thương bằng kiếm khí, bị Nhân Quả trận phá giải và Sinh Tử Ấn đánh phun máu","chuong":"@c1564"},{"text":"Phân thân bước thứ ba lao tới cửa Thiên Nghịch bị ánh sáng thiêu đốt tiêu tán","chuong":"@c1151"}]},"nguon":["@c1218"],"vaiTro":"Đại năng bí ẩn của Liên Minh — tu vi Không Niết, trưởng lão Vô Cực Tông","tinhCach":"Thâm trầm bình tĩnh, quan sát kỹ trước khi ra tay; dứt khoát tàn nhẫn khi động thủ; mưu tính sâu xa, biết toan tính lợi hại; không ngại đánh lén khi có cơ hội","blurb":"Lão giả áo đen là đại năng bí ẩn cư tại tây bộ Liên Minh tinh vực, tu vi đạt tới Không Niết, nắm giữ thần thông Súc Thốn Thành Không có thể co rút cả thiên địa và bước một bước vượt vô số khoảng cách. Lão từng một ngón tay giết chết thượng cổ tu sĩ, rút kiếm gãy chống Thác Sâm cứu Viêm Lôi Tử, sau đó lộ diện với thân phận trưởng lão Vô Cực Tông dẫn đầu vây công Vương Lâm. Về sau lão nhiều lần giao chiến với các cường giả khác, từng đánh lén Vương Lâm lúc bị thương nhưng bị Sinh Tử Ấn đánh phun máu, trong khi phân thân của lão bị ánh sáng thiêu đốt tiêu tán trước cửa Thiên Nghịch."},{"id":"nu-tu-lanh-nhu-bang","name":"Nữ tử lạnh như băng (chiến trường Yêu Tông)","gioiTinh":"nu","trangThai":"song","canhGioiCaoNhat":"Không rõ","blurb":"Nữ tu khoảng 25 tuổi, thần sắc lạnh như băng, dùng kiếm mỏng màu vàng phát tơ vàng chém mãnh thú tại cái khe chiến trường Yêu Tông. Tuyên bố muốn giết vương thú như Lý Thiến Mai.","vaiTro":"Cao thủ nổi bật tại chiến trường cái khe Yêu Tông","tinhCach":"Lạnh lùng; tự tin; hiếu thắng","tabs":{"diem":[{"text":"Tuyên bố muốn giết vương thú cạnh tranh với thành tích Lý Thiến Mai","chuong":"@c1219"},{"text":"Cắn lưỡi phun máu lên kiếm tạo dòng chảy vàng, cùng lão già vây khốn đầu lâu khổng lồ Cửu U Long.","chuong":"@c1220"}],"kinhLich":[{"mucCt":"gon","text":"Dùng kiếm mỏng màu vàng phát tơ vàng chém mãnh thú tại chiến trường, khi có dấu hiệu vương thú xuất hiện liền tuyên bố muốn giết vương thú như Lý Thiến Mai.","anchor":"Vương thú? Lý Thiến Mai có thể giết, thì ta cũng có thể giết!","bridge":true,"khoang":"@c1219"},{"chuong":"@c1220","importance":"bridge","mucCt":"vua","text":"Liên thủ cùng năm cao thủ tấn công Cửu U Long, phun máu lên kiếm tạo dòng chảy vàng. Bị thương nặng, hổ khẩu tay phải nứt ra nhưng vẫn chiến đấu.","anchor":"hổ khẩu tay phải nứt ra, máu tươi chảy đầy lòng bàn tay"},{"chuong":"@c1222","importance":"minor","mucCt":"gon","tieuDe":"Nhận ra Lý Thiến Mai và Vương Lâm đến vì nhau","text":"Thầm than khi nhận ra Lý Thiến Mai vào khe nứt vì Vương Lâm, và Vương Lâm đến cũng vì cô.","anchor":"Lý Thiến Mai, ngươi và ta hàng trăm năm nay thủy chung vẫn âm thầm đấu đá nhau"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Kiếm mỏng màu vàng","moTa":"Khi ra tay phát ra tơ vàng, mãnh thú đụng vào bị phân thành bốn năm mảnh","nguon":"@c1219"}]}},"nguon":["@c1219","@c1220","@c1222"],"aliases":["Nữ tử lạnh lùng (chiến trường Yêu Tông)"]},{"id":"lao-gia-chien-truong-yeu-tong","name":"Lão già (chiến trường Yêu Tông)","gioiTinh":"nam","trangThai":"song","canhGioiCaoNhat":"Không rõ","blurb":"Một trong sáu cao thủ nổi bật tại chiến trường cái khe Yêu Tông, tu vi Toái Niết đại viên mãn, mơ hồ có dấu hiệu đạt Thiên Nhân Đệ Nhất Suy.","vaiTro":"Cao thủ tại chiến trường cái khe Yêu Tông","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Tự sáng tạo thần thông Vạn Đạo Tề Bạo, hấp thụ thiên địa nguyên lực hóa vạn kim đan cho nổ tung.","chuong":"@c1220"},{"text":"Rất có uy trong mấy nghìn tu sĩ chiến trường, ra lệnh kích hoạt đại trận hiến tế sức sống.","chuong":"@c1220"}],"kinhLich":[{"chuong":"@c1219","importance":"bridge","mucCt":"gon","text":"Xuất hiện tại chiến trường cái khe Yêu Tông, là một trong sáu cao thủ nổi bật, tu vi Toái Niết đại viên mãn.","anchor":"Vương thú? Lý Thiến Mai có thể giết, thì ta cũng có thể giết!"},{"mucCt":"vua","text":"Dẫn đầu sáu cao thủ liên thủ tấn công Cửu U Long, thi triển thần thông Vạn Đạo Tề Bạo nhưng không hạ được. Bị thương nhẹ (khóe miệng rỉ máu), ra lệnh mấy nghìn tu sĩ hiến tế sức sống kích hoạt Yêu Tông đại trận phong bế tạm thời khe chiến trường. Tiếc nuối nhắc đến Lý Thiến Mai có đủ sức phá đầu lâu Cửu U Long.","anchor":"Nếu là Lý Thiến Maim với tu vi cùng với pháp bảo của cô ta, có lẽ có thể phá được cái đầu lâu","bridge":true,"khoang":"@c1220"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"Người mà lão già cho rằng có đủ tu vi và pháp bảo phá được đầu lâu Cửu U Long"}],"tuiDo":{}},"nguon":["@c1219","@c1220"],"aliases":["Lão già tu vi cao nhất (chiến trường Yêu Tông)"]},{"id":"cuu-u-long","name":"Cửu U Long","cn":"九幽龙","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Cấp mười hai (bộc phát tương đương hoàng thú cấp mười ba)","trangThai":"song","blurb":"Ấu long từ Cửu U Thâm Uyên, toàn thân đen, dài nghìn trượng, hai sừng uốn lượn, thực lực cấp mười hai có thể bộc phát tương đương hoàng thú cấp mười ba. Ban đầu xuất hiện như mãnh thú cấp cao đe dọa tu sĩ tại chiến trường Yêu Tông, sau bị Vương Lâm đánh trọng thương và khuất phục làm vật cưỡi, chở hắn tiến sâu vào khe nứt chiến trường.","vaiTro":"Ấu long Cửu U Thâm Uyên, mãnh thú cấp cao rồi thành vật cưỡi Vương Lâm","tinhCach":"Hung mãnh, dám cắn nuốt tu sĩ; không sợ hãi trước đám đông; khuất phục trước sức mạnh áp đảo","tabs":{"diem":[{"text":"Xuất hiện từ khe chiến trường bên ngoài sáu tu chân tinh Yêu Tông, khiến mãnh thú lùi tránh đường","chuong":"@c1220"},{"text":"Lao ra cắn nuốt Vương Lâm, bị đánh hai chưởng đến trọng thương, máu tuôn và mất hai sừng","chuong":"@c1221"},{"text":"Khuất phục dưới hai chưởng ấn chứa ba luồng khí tức của Vương Lâm, trở thành vật cưỡi","chuong":"@c1222"},{"text":"Chở Vương Lâm tiến sâu vào khe nứt chiến trường Yêu Tông, khí tức vương thú xua tan mãnh thú xung quanh","chuong":"@c1223"},{"text":"Bị Vương Lâm dùng thần niệm kích thích tăng tốc tiến vào khe nứt tím, phát hiện khí tức băng hàn","chuong":"@c1224"}],"kinhLich":[{"mucCt":"ky","text":"Xuất hiện từ khe chiến trường bên ngoài sáu tu chân tinh Yêu Tông, mãnh thú lùi tránh đường. Phun hắc khí hóa vô số đầu lâu đen tấn công tứ phía. Sáu cao thủ liên thủ tấn công nhưng bị đầu lâu nghìn trượng hút sức sống đánh bại bốn người. Bị buộc thu đầu tránh khi mấy nghìn tu sĩ hiến tế sức sống kích hoạt Yêu Tông đại trận đóng khe chiến trường.","anchor":"loài thú này đi theo đàn, vượt qua cả những con thú hóa thành người, trong truyền thuyết là một trong sáu loài thú đồng hành với thiên giai đạo thú Cát Cùng","bridge":true,"khoang":"@c1220"},{"mucCt":"gon","text":"Lao ra từ khe chiến trường cắn nuốt Vương Lâm, bị đánh hai chưởng — bị thương nặng máu tuôn và mất hai sừng. Bị giẫm đầu ép làm vật cưỡi dẫn đường vào khe.","anchor":"Trở thành vật cưỡi của ta, ta sẽ tha mạng cho ngươi","bridge":true,"khoang":"@c1221"},{"chuong":"@c1222","importance":"normal","mucCt":"gon","tieuDe":"Khuất phục trở thành vật cưỡi Vương Lâm","text":"Khuất phục dưới hai chưởng ấn chứa ba luồng khí tức của Vương Lâm, trở thành vật cưỡi, chở Vương Lâm bay sâu vào khe nứt.","anchor":"con Cửu U Long này sao có thể chống cự, giờ phút này chỉ có thể khuất phục"},{"chuong":"@c1223","importance":"normal","mucCt":"vua","text":"Bị Vương Lâm thu phục, chở hắn tiến sâu vào khe nứt chiến trường Yêu Tông. Khí tức vương thú xua mãnh thú bốn phía. Khi vào vùng Tử Giới, run rẩy sợ hãi muốn quay đầu, phải nhờ thần niệm Vương Lâm trấn mới tiếp tục.","anchor":"Cửu U Long kia dường như bị thần niệm này k*ch th*ch, ngửa mặt lên trời kêu lên một tiếng"},{"chuong":"@c1224","importance":"bridge","mucCt":"vua","text":"Bị Vương Lâm dùng thần niệm kích thích tăng tốc tiến sâu vào khe nứt tím, nhưng phát hiện khí tức băng hàn đáng sợ, hồn phách run rẩy, hoảng sợ dừng lại không chịu tiến — nơi này giống cấm địa của nó.","anchor":"Dường như nơi này chính là cấm địa của nó, là nơi nó không dám bước chân vào."}],"tuViMoc":[],"nhanMach":[{"ten":"Cát Cùng","tag":"khac","quanHe":"Thiên giai đạo thú mà Cửu U Long là một trong sáu loài thú đồng hành"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân (bị ép làm vật cưỡi)","ghiChu":"Bị đánh bại và khuất phục tại khe chiến trường @c1221"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220","@c1221","@c1222","@c1223","@c1224"]},{"id":"my-phu-trung-nien-chien-truong-yeu-tong","name":"Mỹ phụ trung niên (chiến trường Yêu Tông)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong sáu cao thủ chiến trường Yêu Tông, thi triển thần thông tóc biến trắng tạo cơn gió lốc tấn công Cửu U Long.","vaiTro":"Cao thủ tại chiến trường khe nứt Yêu Tông","tinhCach":"Quyết liệt; sẵn sàng liều mạng chiến đấu","tabs":{"diem":[{"text":"Thi triển thần thông tóc biến trắng hình thành cơn gió lốc tấn công Cửu U Long.","chuong":"@c1220"}],"kinhLich":[{"chuong":"@c1220","importance":"bridge","mucCt":"gon","text":"Liên thủ tấn công Cửu U Long, thi triển thần thông lốc tóc trắng nhưng bị hấp thu sức sống, phun máu lui về.","anchor":"tóc biến thành màu trắng, đột nhiên ở bên ngoài thân thể hình thành một cơn gió lốc tóc trắng"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220"]},{"id":"nam-tu-tu-quang-chien-truong-yeu-tong","name":"Nam tử trung niên toàn thân tử quang (chiến trường Yêu Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong sáu cao thủ chiến trường Yêu Tông, đề nghị liên thủ giết Cửu U Long để gia nhập Yêu Tông nhưng thất bại.","vaiTro":"Cao thủ tại chiến trường khe nứt Yêu Tông","tinhCach":"Tham vọng; khao khát gia nhập Yêu Tông","tabs":{"diem":[{"text":"Đề nghị sáu người liên thủ giết Cửu U Long để trở thành người của Yêu Tông.","chuong":"@c1220"}],"kinhLich":[{"chuong":"@c1220","importance":"bridge","mucCt":"gon","text":"Đề nghị liên thủ giết Cửu U Long nhưng bị đầu lâu nghìn trượng đánh bại, phun máu mất sức sống.","anchor":"Sáu người chúng ta liên thủ giết con rồng này, sẽ có thể trở thành người của Yêu Tông"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220"]},{"id":"ba-tu-si-yeu-tong-suong-lam","name":"Ba tu sĩ Yêu Tông sương lam","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (mạnh hơn cấp mười hai)","trangThai":"song","blurb":"Ba người toàn thân tràn ngập sương mù lam, đại diện Yêu Tông trấn thủ chiến trường khe nứt. Mãnh thú chạm sương lam liền chết.","vaiTro":"Đại diện Yêu Tông trấn thủ chiến trường khe nứt","tinhCach":"Trầm tĩnh; uy nghiêm; không dễ ra tay; coi chiến trường là nơi rèn luyện sinh tử","tabs":{"diem":[{"text":"Toàn thân tràn ngập sương mù lam, mãnh thú và đầu lâu lại gần đều bị sương lam giết chết.","chuong":"@c1220"},{"text":"Tuyên bố sẽ tự đối phó Cửu U Long khi trận pháp hết hiệu lực.","chuong":"@c1220"},{"text":"Toàn thân bao phủ sương lam, truyền âm đánh giá Vương Lâm ít nhất Thiên Nhân Đệ Nhất Suy.","chuong":"@c1221"}],"kinhLich":[{"mucCt":"vua","text":"Quan sát Cửu U Long xuất hiện, nhận ra là ấu long từ Cửu U Thâm Uyên, truyền tin cấp báo trưởng lão. Tuyên bố sẽ tự đối phó Cửu U Long khi trận pháp hết hiệu lực nhưng bị gián đoạn khi hồng quang ngợp trời từ xa lao tới, sắc mặt đại biến.","anchor":"Năm đó ba người bọn ta cũng đã trải qua như vậy","bridge":true,"khoang":"@c1220"},{"chuong":"@c1221","importance":"bridge","mucCt":"gon","text":"Truyền âm đánh giá thực lực Vương Lâm, cố lao ra ngăn hắn xé khe nhưng bị phớt lờ.","anchor":"Ít nhất là Thiên Nhân Đệ Nhất Suy, chỉ là vì sao trên người hắn lại không có quầng sáng của Thiên Nhân"},{"chuong":"@c1222","importance":"minor","mucCt":"gon","tieuDe":"Chứng kiến Vương Lâm thu phục Cửu U Long và giao đấu trưởng lão","text":"Chấn động khi Vương Lâm thu phục Cửu U Long, đứng vững dưới sức tấn công từ giao đấu, cung kính gọi lão già tóc bạc là trưởng lão.","anchor":"Tham kiến trưởng lão"},{"chuong":"@c1229","importance":"bridge","mucCt":"gon","text":"Tiếp tục canh gác khe nứt, khi vô lượng kiếp giáng liền run rẩy sợ hãi lui lại.","anchor":"Tông chủ năm đó từng nói qua, chúng sinh khó độ vô lượng kiếp"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220","@c1221","@c1222","@c1229"]},{"id":"nam-tu-ao-trang-toc-bac","name":"Nam tử áo trắng tóc bạc (trong hồng quang)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (tu vi cường hãn khiến tinh không gợn sóng)","trangThai":"song","blurb":"Xuất hiện cuối chương trong đạo hồng quang ngợp trời, tu vi cường hãn khiến tinh không gợn sóng. Tiếng gào thét đi trước khiến toàn bộ chiến trường sợ hãi. Danh tính chưa rõ.","vaiTro":"Nhân vật bí ẩn xuất hiện cuối chương trong hồng quang","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Tu vi cường hãn bộc phát khiến tinh không gợn sóng, toàn bộ chiến trường — tu sĩ, mãnh thú, đầu lâu — đều sợ hãi.","chuong":"@c1220"}],"kinhLich":[{"mucCt":"ky","text":"Xuất hiện trong đạo hồng quang ngợp trời lao tới chiến trường khe nứt Yêu Tông. Tiếng gào thét kinh thiên truyền đến trước khiến toàn bộ chiến trường sợ hãi. Tu vi cường hãn bộc phát khiến tinh không gợn sóng. Có một lão bà áo trắng đi theo phía sau.","anchor":"một tu vi cường hãn bộc phát ra, khiến cho tinh không cũng phải xuất hiện gợn sóng","bridge":true,"khoang":"@c1220"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão bà áo trắng (trong hồng quang)","tag":"khac","quanHe":"Lão bà đi theo phía sau trong hồng quang"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220"]},{"id":"lao-ba-ao-trang-hong-quang","name":"Lão bà áo trắng (trong hồng quang)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đi theo phía sau nam tử áo trắng tóc bạc trong đạo hồng quang ngợp trời tại chiến trường Yêu Tông. Danh tính chưa rõ.","vaiTro":"Nhân vật bí ẩn đi theo nam tử áo trắng tóc bạc trong hồng quang","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Đi theo phía sau nam tử áo trắng tóc bạc trong hồng quang, danh tính chưa rõ.","chuong":"@c1220"}],"kinhLich":[{"chuong":"@c1220","importance":"bridge","mucCt":"gon","text":"Xuất hiện phía sau nam tử áo trắng tóc bạc trong đạo hồng quang ngợp trời tại chiến trường Yêu Tông.","anchor":"Ở phía sau nam tử này còn có một lão bà áo trắng đi theo"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam tử áo trắng tóc bạc (trong hồng quang)","tag":"khac","quanHe":"Người đi phía trước trong hồng quang"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220"]},{"id":"cat-cung","name":"Cát Cùng","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"trangThai":"song","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1220","importance":"bridge","mucCt":"gon","text":"Được nhắc đến — Cửu U Long là một trong sáu loài thú đồng hành với thiên giai đạo thú Cát Cùng.","anchor":"một trong sáu loài thú đồng hành với thiên giai đạo thú Cát Cùng"}],"tuViMoc":[],"nhanMach":[{"ten":"Cửu U Long","tag":"khac","quanHe":"Một trong sáu loài thú đồng hành"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1220"]},{"id":"tong-chu-doi-dau-yeu-tong","name":"Tông chủ đời đầu Yêu Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"},{"ten":"Thần Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (cực kỳ hùng mạnh, đến từ Viễn Cổ Tinh Vực)","trangThai":"mat-tich","blurb":"Tông chủ đời đầu và cũng là đời cuối cùng của Yêu Tông. Theo lời đồn cũng chính là tông chủ Thần Tông, đến từ Viễn Cổ Tinh Vực, đã mất tích không rõ sống chết.","vaiTro":"Người sáng lập Yêu Tông, phong ấn khe chiến trường, nhân vật truyền thuyết","tinhCach":"Hùng mạnh phi thường; có tầm nhìn chiến lược (bày đại trận sáu tu chân tinh, tách Yêu Tông canh giữ chiến trường)","tabs":{"diem":[{"text":"Tông chủ đời đầu kiêm đời cuối của Yêu Tông, theo lời đồn cũng là tông chủ Thần Tông, đến từ Viễn Cổ Tinh Vực.","chuong":"@c1221"},{"text":"Tự tay bày đại trận sáu tu chân tinh và phong ấn khe chiến trường, bản mệnh pháp bảo là cây đại thụ chọc trời.","chuong":"@c1221"}],"kinhLich":[{"mucCt":"gon","text":"Hình ảnh khắc trên sáu bia đá trong sáu sơn môn Yêu Tông, đứng trước đại thụ bản mệnh đối mặt chi chít con mắt Viễn Cổ Tinh Vực. Năm xưa phong ấn khe chiến trường nhưng không hoàn toàn vì có kẻ bên trong ngăn cản. Theo lời đồn cùng là tông chủ Thần Tông, hiện mất tích.","anchor":"Nghe nói tông chủ Thần Tông và tông chủ Yêu Tông trên thực tế là cùng một người","bridge":true,"khoang":"@c1221"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Bản mệnh pháp bảo đại thụ","moTa":"Cây đại thụ cao chọc trời, bản mệnh pháp bảo của tông chủ, hình ảnh được khắc trên bia đá.","nguon":"@c1221"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1221"]},{"id":"truong-lao-yeu-tong","name":"Trưởng lão Yêu Tông","cn":"","aliases":["Lão già tóc bạc (trưởng lão Yêu Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhị Suy","trangThai":"song","blurb":"Trưởng lão của Yêu Tông, tu vi Thiên Nhân Đệ Nhị Suy. Là sư phụ năm xưa thu nhận Lý Thiến Mai, đồng ý cho cô rời đi. Bại trận trước Vương Lâm và bị âm thầm đả thương bằng đạo thuật.","vaiTro":"Trưởng lão Yêu Tông, sư phụ cũ của Lý Thiến Mai","tinhCach":["Uy nghiêm nhưng biết tiến lùi; nhận ra thực lực chênh lệch liền xin dừng tay và chủ động giúp đỡ"],"tabs":{"diem":[{"text":"Tu vi Thiên Nhân Đệ Nhị Suy, thi triển Dịch Linh Ấn hoàn chỉnh năm ký hiệu nhưng vẫn bại trước Vương Lâm","chuong":"@c1222"},{"text":"Là sư phụ năm xưa thu nhận Lý Thiến Mai, tặng bản đồ khe nứt cho Vương Lâm vì tình sư đồ","chuong":"@c1222"}],"kinhLich":[{"chuong":"@c1229","importance":"bridge","mucCt":"gon","text":"Mười sáu trưởng lão bừng tỉnh khi tầng mây vô lượng kiếp xuất hiện, lao ra tinh không, cung kính chấp hành lệnh thái thượng trưởng lão tản thần niệm mở tu chân tinh.","anchor":"Chúng sinh khó độ vô lượng kiếp. Không ngờ hôm nay thật sự lão phu có thể chứng kiến vô lượng kiếp"}],"tuViMoc":[{"chuong":"@c1222","canhGioi":"Thiên Nhân Đệ Nhị Suy","text":"Tự xưng tu vi Thiên Nhân Đệ Nhị Suy khi giao đấu với Vương Lâm.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giao đấu, bị đánh bại và bị đạo thuật xâm nhập","ghiChu":"Được Vương Lâm tha mạng và cảnh báo cách chữa trị"},{"ten":"Lý Thiến Mai","tag":"su-mon","quanHe":"Sư phụ — môn hạ cũ","ghiChu":"Năm xưa yêu mến tài năng thu nhận, đồng ý cho rời đi"}],"tuiDo":{"phapBao":[{"ten":"Mai rùa (pháp bảo)","moTa":"Bấm quyết phun ra để phòng ngự, bị huyết kiếm Vương Lâm chém nát tan vỡ","trangThai":"hong","nguon":"@c1222"}]}},"nguon":["@c1222","@c1229"]},{"id":"van-thu","name":"Văn Thú","cn":"蚊兽","gioiTinh":"khac","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1224","importance":"bridge","mucCt":"vua","text":"Hơn một vạn Văn thú được Vương Lâm triệu hồi từ khe nứt trữ vật, ầm ầm lao ra giao chiến với mãnh thú bạch khí trong vùng băng hàn sâu nhất.","anchor":"hơn một vạn Văn thú ầm ầm xuất hiện, tràn ngập bốn phía Vương Lâm"},{"chuong":"@c1227","importance":"bridge","mucCt":"gon","text":"Vờn quanh Vương Lâm trong trận chiến, Văn Vương quắc mắt nhìn chằm chằm con bọ cạp sắp chết, lộ vẻ khát máu.","anchor":"Văn Vương còn quắc mắt nhìn chằm chằm con bọ cạp kia, lộ ra vẻ khát máu"},{"chuong":"@c1228","importance":"bridge","mucCt":"vua","tieuDe":"","text":"Hút máu bọ cạp cấp mười ba sau khi Vương Lâm đánh bại nó, tu vi tăng mạnh, dẫn năm nghìn Văn thú truy sát mãnh thú khắp khe nứt.","anchor":"Văn vương kêu lên, lộ ra vẻ mừng như điên, thân thể run rẩy, không ngờ tu vi tăng mạnh"},{"chuong":"@c1279","importance":"bridge","mucCt":"gon","tieuDe":"Hiện trong ký ức","text":"Văn Thú xuất hiện trong hình ảnh ký ức đầu tiên của sấm sét bất diệt dưới dạng một tồn tại khổng lồ lớn như tu chân tinh giữa kiếp nạn tan vỡ.","anchor":"Thậm chí hắn còn nhìn thấy một Văn Thú lớn như một tu chân tinh"}],"tuiDo":{},"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Đột phá từ hạ phẩm linh cấp lên trung phẩm linh cấp, tương đương Nguyên Anh hậu kỳ đại viên mãn.","chuong":"@c0266"},{"text":"Được xác nhận là hung thú đến từ tinh không, sống bằng cắn nuốt vạn vật và hung tính vượt xa yêu thú tu chân.","chuong":"@c0479"},{"text":"Sau trăm năm tế luyện bằng lượng nguyên tinh khổng lồ, lột xác thành công với khí tức ngang Tịnh Niết.","chuong":"@c1153"},{"text":"Tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới rồi xác lập vương quyền trong đàn Văn Thú.","chuong":"@c1169"},{"text":"Bất chấp nguy hiểm lột xác nhiều lần, hi sinh thân thể để đưa giọt máu của Vương Lâm vào đài cao và đánh thức chủ nhân.","chuong":"@c1703"},{"text":"Sau khi tới Tiên Cương đại lục, tiếp tục hiện thân làm tọa kỵ, nhiều lần chở Vương Lâm di chuyển và thoát thân.","chuong":"@c1773"}]},"nguon":["@c1224","@c1227","@c1228","@c1279"],"aliases":["Văn Vương","Văn thú vương"],"vaiTro":"Linh thú tọa kỵ trung thành của Vương Lâm","tinhCach":"Trung thành hộ chủ; hung mãnh khát máu; nặng tình đồng tộc; kiên quyết tìm chủ","blurb":"Văn Thú, còn được gọi là con muỗi khổng lồ, là hung thú đến từ tinh không và trở thành tọa kỵ, linh thú hộ chủ lâu dài của Vương Lâm. Nó trải qua nhiều lần lột xác, khuất phục các đàn Văn Thú tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới và tiếp tục theo Vương Lâm qua hư vô đến Tiên Cương đại lục."},{"id":"tu-huyet","name":"Tử Huyết","cn":"","aliases":["Nữ tử áo đen","Mãnh thú bọ cạp chín đuôi cấp mười ba"],"gioiTinh":"nu","theLuc":[{"ten":"Viễn Cổ Đế Phi","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Mãnh thú cấp mười ba","trangThai":"tu-vong","blurb":"Mãnh thú bọ cạp chín đuôi cấp mười ba đã hóa hình người, tu vi tương đương Thiên Nhân Đệ Nhất Suy. Tự xưng là thuộc hạ của Viễn Cổ Đế Phi. Bị Vương Lâm đánh bại hoàn toàn, gần như tử vong.","vaiTro":"Mãnh thú cấp mười ba hóa hình, đối thủ của Vương Lâm tại biển máu","tinhCach":"Hung hãn; ngạo mạn dựa thế Viễn Cổ Đế Phi; hoảng sợ khi gặp kẻ mạnh hơn","tabs":{"diem":[{"text":"Mãnh thú bọ cạp chín đuôi cấp mười ba đã hóa hình người, tu vi tương đương Thiên Nhân Đệ Nhất Suy","chuong":"@c1227"},{"text":"Thuộc hạ của Viễn Cổ Đế Phi, dùng danh nghĩa này để dọa nạt đối thủ","chuong":"@c1227"},{"text":"Bị Vương Lâm hình thể Cổ Thần đánh bại hoàn toàn — càng bị phá, đuôi bị kéo đứt, gần như tử vong","chuong":"@c1227"},{"text":"Bọ cạp chín đuôi cấp mười ba hóa hình người, thú hộ pháp Y Nguyệt","chuong":"@c1228"}],"kinhLich":[{"mucCt":"ky","text":"Là thủ phạm đả thương Lý Thiến Mai bằng roi đuôi bọ cạp. Giao chiến với Vương Lâm, chín chiếc roi hư ảnh bị huyết kiếm chém nát. Rút roi đuôi bọ cạp thực thể (toàn thân đen, đầy gai nhọn, cuối roi có móc câu như lưỡi hái) nhưng cũng bị huyết kiếm chặt đứt. Dọa Vương Lâm bằng danh nghĩa Viễn Cổ Đế Phi sẽ giết toàn tộc hắn. Buộc phải hiện nguyên hình bọ cạp khổng lồ vạn trượng nhưng bị Vương Lâm (hình thể Cổ Thần gần ngàn trượng) đánh bại hoàn toàn: hai càng bị đập nát, hai đuôi bị kéo đứt, thân bị quăng vào đàn mãnh thú, gần như tử vong.","anchor":"Ta là thuộc hạ của Viễn Cổ Đế Phi, ngươi dám giết ta, Đế Phi chắc chắn sẽ giết toàn tộc nhà ngươi!","bridge":true,"khoang":"@c1227"},{"chuong":"@c1228","importance":"normal","mucCt":"gon","tieuDe":"Bị Vương Lâm tiêu diệt","text":"Bị Vương Lâm đánh chết, xé chín đuôi, bị Văn thú hút sạch máu huyết, nguyên thần trong hắc đan bị lục soát ký ức.","anchor":"ban cho tên là Tử Huyết, thành một trong những thú dưới trướng ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, bị Vương Lâm đánh bại hoàn toàn","ghiChu":"@c1227"},{"ten":"Viễn Cổ Đế Phi","tag":"cap-tren","quanHe":"Thuộc hạ của Viễn Cổ Đế Phi","ghiChu":"Tự xưng thuộc hạ @c1227"},{"ten":"Y Nguyệt","tag":"khac","quanHe":"Chủ nhân","ghiChu":"Được Y Nguyệt thu phục từ khi còn cấp bảy, đặt tên Tử Huyết"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1227","@c1228"]},{"id":"y-nguyet","name":"Y Nguyệt","cn":"","aliases":["Nữ tử áo hồng","Phi tử viễn cổ Tiên Hoàng"],"gioiTinh":"nu","theLuc":[{"ten":"Viễn Cổ Đế Phi","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Suy Kiếp (phân thân)","trangThai":"song","blurb":"Một trong những phi tử của viễn cổ Tiên Hoàng, bản thể đang chữa thương sâu trong khe nứt bên trong tinh thể lục giác. Phân thân chỉ có tu vi Thiên Nhân Suy Kiếp.","vaiTro":"Phi tử viễn cổ Tiên Hoàng, đồng minh tạm thời của Vương Lâm","tinhCach":["Tự tin, điềm tĩnh khi mặc cả","Biết tính toán lợi hại, dùng Lý Thiến Mai làm con bài ép buộc"],"tabs":{"diem":[{"text":"Phi tử viễn cổ Tiên Hoàng, bản thể đang chữa thương sâu trong khe nứt","chuong":"@c1228"},{"text":"Nhận ra năm đạo bổn nguyên trong cơ thể Vương Lâm, xác nhận khi đại thành có thể đánh với Tiên Hoàng","chuong":"@c1228"}],"kinhLich":[{"chuong":"@c1228","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện, đề nghị liên minh với Vương Lâm","text":"Xuất hiện dưới dạng phân thân tu vi Thiên Nhân Suy Kiếp khi Vương Lâm sắp rời khe nứt. Nhận ra huyết kiếm từng đả thương Tiên Hoàng, nhận ra năm đạo bổn nguyên trong cơ thể Vương Lâm và khí tức quen thuộc trên người hắn. Đề nghị liên minh: nàng giúp Vương Lâm rời khe nứt cứu Lý Thiến Mai, đổi lại hắn quay lại giúp nàng chữa thương, phần thưởng là dẫn hắn tới tế đàn Cổ Thần và kết đồng minh vĩnh viễn. Trao ngọc bội truyền tống cho Vương Lâm. Bản thể ngồi trong tinh thể lục giác mười trượng sâu trong khe nứt tối đen, mở mắt nhìn vào hư vô.","anchor":"Ta là một trong những phi tử của viễn cổ tiên hoàng, tên là Y Nguyệt"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng minh tạm thời","ghiChu":"Đề nghị liên minh: đổi chữa thương lấy dẫn Vương Lâm tới tế đàn Cổ Thần"},{"ten":"Tiên Hoàng","tag":"the-thiep","quanHe":"Phi tử của viễn cổ Tiên Hoàng","ghiChu":"Tự xưng là một trong những phi tử"},{"ten":"Tử Huyết","tag":"khac","quanHe":"Chủ nhân — thú hộ pháp","ghiChu":"Thu phục bọ cạp từ khi còn cấp bảy, đặt tên Tử Huyết làm hộ pháp"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[{"ten":"Tử Huyết","trangThai":"mat","moTa":"Bọ cạp chín đuôi cấp mười ba, hộ pháp — bị Vương Lâm tiêu diệt","nguon":"@c1228"}],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1228"]},{"id":"lao-gia-tham-thinh-khe-nut","name":"Lão giả thám thính khe nứt","gioiTinh":"nam","aliases":[],"theLuc":[],"canhGioiCaoNhat":"Không rõ (một trong sáu đại cao thủ)","trangThai":"song","vaiTro":"Đại cao thủ trong nhóm tu sĩ canh khe nứt, dò xét nội tình","tinhCach":"Dũng cảm; cẩn thận","blurb":"Một trong sáu đại cao thủ trong mấy ngàn tu sĩ canh khe nứt chiến trường Yêu Tông. Lẻn vào khe nứt dò xét rồi quay về báo cáo toàn thi thể mãnh thú bị phá nát.","tabs":{"diem":[{"text":"Một trong sáu đại cao thủ, dám mạo hiểm lẻn vào khe nứt dò xét","chuong":"@c1229"}],"kinhLich":[{"chuong":"@c1229","importance":"normal","mucCt":"vua","tieuDe":"Trở về từ khe nứt, báo cáo cuộc tàn sát","text":"Sau mấy ngày lẻn vào khe nứt dò xét, trở về với thần sắc kinh hoàng. Báo cáo toàn bộ bên trong đều là thi thể mãnh thú bị phá nát từng mảnh, bao gồm cả thú vương, tất cả bị một kích mất mạng, sâu bên trong có lẽ đã hình thành biển máu.","anchor":"Toàn bộ đều là thi thể! Đều là thi thể mãnh thú"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1229"]},{"id":"thai-thuong-truong-lao-yeu-tong","name":"Thái thượng trưởng lão Yêu Tông","gioiTinh":"nam","aliases":["Huyền Bỉnh","Thái thượng trưởng lão Yêu Tông"],"theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","vaiTro":"Thái thượng trưởng lão Yêu Tông — nhân vật cao nhất của tông môn","tinhCach":"Trầm ổn; uyên bác; mang vẻ tang thương","blurb":"Nhân vật cao nhất của Yêu Tông, xuất hiện dưới dạng nam tử trung niên mặc đạo bào mang vẻ tang thương. Khi vô lượng kiếp giáng xuống Vân Hải tinh vực, ông hiện thân bảo hộ toàn bộ sơn môn, rồi chứng kiến Vương Lâm đỡ thiên kiếp và tranh đoạt lôi đình. Sau khi nhận ra ngọc bội Tông Chủ, ông xác định Vương Lâm là truyền nhân Tông Chủ và định bước lên trợ giúp.","tabs":{"diem":[{"text":"Hiện thân trước vô lượng kiếp, ra lệnh mở trận pháp bảo hộ toàn bộ sơn môn cùng tu sĩ bên ngoài","chuong":"@c1229"},{"text":"Chứng kiến Vương Lâm một tay đỡ thiên kiếp và tranh đoạt quyền điều khiển lôi đình","chuong":"@c1230"},{"text":"Dùng giọng sấm động cảnh báo tu sĩ Yêu Tông ngưng định tâm trước dòng xoáy","chuong":"@c1231"},{"text":"Nhận ra ngọc bội Tông Chủ, chấn động cực độ, xác định Vương Lâm là truyền nhân Tông Chủ","chuong":"@c1233"},{"text":"Nhận ra Vương Lâm có quan hệ không tầm thường với tông chủ và định bước lên trợ giúp","chuong":"@c1234"}],"kinhLich":[{"chuong":"@c1229","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện trước vô lượng kiếp, bảo hộ toàn môn","text":"Khi tầng mây tím vô lượng kiếp giáng xuống Vân Hải tinh vực, thái thượng trưởng lão hiện thân nam tử trung niên mặc đạo bào, nhận diện đây là vô lượng kiếp — loại thiên kiếp đáng sợ nhất với biến hóa khó lường. Nhắc lại lời tông chủ năm xưa rằng chúng sinh khó độ vô lượng kiếp. Ra lệnh mở trận pháp sơn môn, đưa toàn bộ tu sĩ bên ngoài vào tu chân tinh, kích hoạt trận pháp bảo hộ toàn bộ tu chân tinh. Cuối cùng nhìn thấy từ lỗ hổng trong tầng mây xuất hiện tòa lầu các bạch ngọc, trên đó có pho tượng ngồi khoanh chân và hai thanh thạch kiếm.","anchor":"Chúng sinh khó độ vô lượng kiếp. Không ngờ hôm nay thật sự lão phu có thể chứng kiến vô lượng kiếp"},{"importance":"bridge","mucCt":"gon","chuong":"@c1230","tieuDe":"Chứng kiến Vương Lâm tranh đoạt lôi đình","text":"Mắt tỏa sáng, hít sâu khi chứng kiến Vương Lâm một tay đỡ thiên kiếp và tranh đoạt quyền điều khiển lôi đình.","anchor":"Hai mắt thái thượng trưởng lão của Yêu Tông cũng tỏa sáng, hít một hơi thật sâu"},{"mucCt":"vua","text":"Nhìn chằm chằm vào dòng xoáy, thần sắc ngưng trọng, dùng giọng sấm động cảnh báo tu sĩ Yêu Tông ngưng định tâm thần. Giải thích đây là lời kêu gọi của vùng đất ước mơ trong vô lượng kiếp, nếu đạo tâm bất ổn sẽ bị lôi vào thế giới trong dòng xoáy, nhưng không ngăn nổi hàng trăm người biến mất.","anchor":"Đây là lời kêu gọi của vùng đất ước mơ trong vô lượng kiếp","bridge":true,"khoang":"@c1231"},{"chuong":"@c1233","importance":"major","mucCt":"ky","tieuDe":"Nhận phong mệnh chủ nhân Phong Giới","text":"Nhận ra ngọc bội Tông Chủ mà Vương Lâm phóng ra, chấn động cực độ, nhận định Vương Lâm là truyền nhân Tông Chủ chỉ định. Phá trận bay ra tinh không tới bên Phong Giới Đại Trận. Nhận mệnh lệnh từ chủ nhân Phong Giới: dùng đạo khí sửa sang Vân Hải Tinh Vực, giết kẻ phản kháng, đi tìm Nam Vân Tử, Hồng Sam Tử, Chiến Tiên Tử ở ba tinh vực còn lại để thông báo ước định hợp nhất Tứ Đại Tiên Giới chuẩn bị đại chiến giới ngoại.","anchor":"Ngọc bội của Tông Chủ! Hắn, hắn không ngờ lại có được ngọc bội của Tông Chủ!"},{"importance":"normal","mucCt":"gon","chuong":"@c1234","tieuDe":"Nhận ra quan hệ Vương Lâm với tông chủ","text":"Nhận ra Vương Lâm có quan hệ không tầm thường với tông chủ qua lời nói cuối và ngọc bội, định bước lên trợ giúp độ kiếp nhưng bị Vương Lâm từ chối.","anchor":"từ lời cuối cùng và ngọc bội này có thể thấy người này có quan hệ tuyệt không tầm thường với tông chủ"}],"tuViMoc":[],"nhanMach":[{"ten":"Tông chủ đời đầu Yêu Tông","tag":"su-mon","quanHe":"Nhắc lại lời tông chủ năm xưa về vô lượng kiếp","ghiChu":"@c1229"},{"ten":"Chủ nhân Phong Giới","tag":"cap-tren","quanHe":"Tông Chủ, ban phong mệnh","ghiChu":"@c1233"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người mang ngọc bội Tông Chủ, truyền nhân được chỉ định","ghiChu":"@c1233"},{"ten":"Thủy Đạo Tử","tag":"khac","quanHe":"Đạo nô bị chủ nhân Phong Giới lệnh trợ giúp Yêu Tông","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"su-mon","quanHe":"Tông Chủ, chủ nhân mà Huyền Bỉnh tuyệt đối trung thành","ghiChu":"Nhận phong mệnh trực tiếp @c1233"},{"ten":"Nam Vân Tử","tag":"dong-minh","quanHe":"Người cần tìm ở tinh vực khác theo phong mệnh","ghiChu":"@c1233"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Người cần tìm ở tinh vực khác theo phong mệnh","ghiChu":"@c1233"},{"ten":"Chiến Tiên Tử","tag":"dong-minh","quanHe":"Người cần tìm ở tinh vực khác theo phong mệnh","ghiChu":"@c1233"},{"ten":"Thủy Đạo Tử","tag":"dong-minh","quanHe":"Đạo nô, được lệnh trợ giúp Yêu Tông","ghiChu":"@c1233"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1229","@c1230","@c1231","@c1233","@c1234"],"cn":"玄秉"},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"木冰眉","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1230","tieuDe":"Bừng tỉnh trong Thần Tông nhìn thiên kiếp","text":"Bị giam cầm trong Thần Tông mười năm, bừng tỉnh từ đả tọa khi thiên kiếp chấn động tinh không, nhìn lên bầu trời.","anchor":"Mộc Băng Mi đã bị giam cầm mười năm nay từ trong đả tọa bừng tỉnh nhìn bầu trời"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Cứu Vương Lâm lúc cận tử và trực diện đối đầu Thiên Vận Tử.","chuong":"@c1010"},{"text":"Khẳng định mọi thần thông cùng nguyên lực thiên địa trong Côn Hư Tinh vực đều nằm trong tay nàng.","chuong":"@c1011"},{"text":"Sống sót sau khi Côn Hư cảnh bị Thác Sâm hủy diệt, tái ngộ Vương Lâm tại Vân Hải.","chuong":"@c1195"},{"text":"Xác nhận thân phận Liễu Mi, mẹ của Vương Bình, rồi từ biệt Vương Lâm.","chuong":"@c1196"},{"text":"Được Vương Lâm phong làm tông chủ Thần Tông.","chuong":"@c1422"},{"text":"Được nhận ra là phách thứ sáu màu lam của Thất Thải Tiên Tôn.","chuong":"@c1651"}]},"nguon":["@c1230"],"vaiTro":"Côn Hư Thánh Nữ — mẹ Vương Bình, tông chủ Thần Tông","tinhCach":"Lạnh lùng quyền uy nhưng nặng tình; bất khuất trước uy hiếp; âm thầm chịu đựng chia ly; kiên định trong đại chiến","blurb":"Mộc Băng Mi là Côn Hư Thánh Nữ, mẹ của Vương Bình và từng nắm quyền điều động thần thông, nguyên lực thiên địa trong Côn Hư Tinh vực. Sau biến cố Côn Hư bị Thác Sâm hủy diệt, nàng trọng thương lưu lạc tới Vân Hải, lấy thân phận Liễu Mi tái ngộ Vương Lâm rồi về Thần Tông và bị giam cầm nhiều năm. Về sau nàng được Vương Lâm phong làm tông chủ Thần Tông, tham dự phòng tuyến giới nội trong đại chiến, đồng thời được hé lộ là phách thứ sáu của Thất Thải Tiên Tôn."},{"id":"vuong-san-san","name":"Vương San San","cn":"王珊珊","gioiTinh":"nu","trangThai":"song","blurb":"Vương San San là nữ tử hoàng sam, tướng mạo thanh tú, đệ tử Thần Tông được sư tôn phái đến đại lục hoang dã trong Vân Hải tinh vực đón Mộc Băng Mi. Nàng tự xưng muội muội, mang theo đan dược, đồng hành cùng Mộc Băng Mi qua đại hội phân tông rồi đưa nàng trở về Thần Tông. Trong quá trình đó, nàng bí mật ghi lại tình cảnh trận chiến của Vương Lâm và truyền hình ảnh về tông môn.","vaiTro":"Đệ tử Thần Tông, người đón Mộc Băng Mi về tông môn","tinhCach":"Dịu dàng, thân thiện; chu đáo, hay giới thiệu người quen; kín đáo, làm việc theo lệnh sư tôn","tabs":{"diem":[{"text":"Nhận lệnh gia sư đến đại lục hoang dã Vân Hải tinh vực đón Mộc Băng Mi, mang theo đan dược và đề nghị cùng đi","chuong":"@c1163"},{"text":"Tại đại hội phân tông cấp năm, giới thiệu Lý Thiến Mai — thiên chi kiêu nữ — cho Mộc Băng Mi làm quen","chuong":"@c1181"},{"text":"Giải thích nguồn gốc thần thông rút hồn thuộc Đệ Tam Bộ theo lời sư tôn","chuong":"@c1188"},{"text":"Bí mật khắc toàn bộ tình cảnh trận chiến của Vương Lâm vào ngọc giản rồi truyền hình ảnh về Thần Tông","chuong":"@c1191"},{"text":"Nhận lệnh sư tôn đưa Mộc Băng Mi rời Vô Cực Tông trở về Thần Tông","chuong":"@c1196"},{"text":"Ở bên Mộc Băng Mi trong Thần Tông, sắc mặt tái nhợt nhìn thiên không khi thiên kiếp bùng nổ","chuong":"@c1230"}],"kinhLich":[{"mucCt":"gon","text":"Ở bên cạnh Mộc Băng Mi trong Thần Tông, sắc mặt tái nhợt nhìn lên thiên không khi thiên kiếp bùng nổ.","anchor":"Vương San San bên cạnh nàng sắc mặt tái nhợt, cũng đang nhìn lên thiên không","bridge":true,"khoang":"@c1230"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cha-me","quanHe":"Cha","ghiChu":"Cha ruột"},{"ten":"Mộc Băng Mi","tag":"cha-me","quanHe":"Mẹ","ghiChu":"Đang ở bên cạnh trong Thần Tông"}],"tuiDo":{}},"nguon":["@c1230"]},{"id":"tong-chu-pha-thien-tong","name":"Tông chủ Phá Thiên Tông","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1230","tieuDe":"Rời bế quan hướng về khe nứt Yêu Tông","text":"Đang bế quan, yên lặng nhìn tinh không khi thiên kiếp bùng nổ, thở dài đứng dậy mở thêm đại trận hộ tông rồi cất bước hướng về khe nứt Yêu Tông.","anchor":"tông chủ Phá Thiên Tông đang ngồi bế quan, yên lặng nhìn tinh không, hồi lâu mới thở dài một tiếng"},{"chuong":"@c1233","importance":"bridge","mucCt":"gon","text":"Đang bước tới trong tinh không thì thấy cây đại thụ chủ nhân Phong Giới hiện ra, dừng lại trầm tư.","anchor":"Tông Chủ của Phá Thiên Tông đang bước tới, nhưng trong nháy mắt thân thể hắn dừng lại"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1230","@c1233"]},{"id":"pho-tuong-lau-cac-bach-ngoc","name":"Pho tượng trên lầu các bạch ngọc","gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Thực thể bí ẩn ngồi khoanh chân trên tòa lầu các bạch ngọc trong tinh không, tay phải biến từ đá thành máu thịt, phát động các kiếp pháp Cửu Cung Phong Ấn và Bát Quái Ấn nhắm vào Vương Lâm.","vaiTro":"Thực thể điều khiển Thiên Kiếp hoặc bộ phận của Thiên Kiếp","tinhCach":"Bí ẩn; hành động cơ giới theo quy luật Thiên Kiếp","tabs":{"diem":[{"text":"Tay phải biến từ đá thành máu thịt, phát động Cửu Cung Phong Ấn và Bát Quái Ấn","chuong":"@c1232"}],"kinhLich":[{"chuong":"@c1232","importance":"normal","mucCt":"vua","tieuDe":"Tỉnh dậy phát động Cửu Cung và Bát Quái","text":"Mi tâm phát hào quang, tay phải biến từ đá thành máu thịt cử động, hô Cửu Cung Vô Lượng triệu chín tinh cầu giáng xuống Vương Lâm. Tiếp đó vung tay phải hô Bát Quái Vô Lượng triệu tám ký hiệu Bát Quái Ấn tạo vòng tròn khổng lồ đè xuống.","anchor":"Pho tượng đang khoanh chân ngồi trên lầu các bạch ngọc kia lúc này từ trong mi tâm có một đạo hào quang nhẹ nhàng lóe lên"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu phong ấn của Thiên Kiếp","ghiChu":"Phát Cửu Cung Phong Ấn và Bát Quái Ấn nhắm vào Vương Lâm @c1232"}],"tuiDo":{}},"nguon":["@c1232"]},{"id":"chu-nhan-phong-gioi","name":"Chủ nhân Phong Giới","aliases":["Tông Chủ"],"gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Chủ nhân Phong Giới là nhân vật bí ẩn được Vương Lâm đưa tới Phong Giới đại trận từ trước, chỉ hiện thân vào thời khắc nguy cấp dưới dạng cây đại thụ chọc trời mang mặt người già nua. Người này nắm giữ hiểu biết về bản chất Thiên Kiếp, giữ vai trò thủ hộ toàn bộ giới nội và có khả năng kích hoạt Khai Thiên Phủ cùng ngọc bội để bảo vệ Phong Giới Đại Trận trước các mối đe dọa từ bên ngoài.","vaiTro":"Chủ nhân Phong Giới — đồng minh bí ẩn được Vương Lâm bố trí thủ hộ giới nội","tinhCach":"Bí ẩn, ẩn mình chờ thời; uy nghiêm khi ban mệnh lệnh; mang khí chất già nua, ánh mắt hồi tưởng tang thương","tabs":{"diem":[{"text":"Được Vương Lâm gọi xuất hiện trong lúc đối đầu nguy cấp, tiết lộ đã được bố trí tại Phong Giới đại trận từ trước","chuong":"@c1232"},{"text":"Hiện thân từ ngọc bội dưới dạng cây đại thụ chọc trời với mặt người già nua, ban mệnh lệnh và hé lộ bản chất Thiên Kiếp","chuong":"@c1233"},{"text":"Dùng sợi tơ màu xanh quấn lên trận pháp phá hoại trên phạm vi lớn, ngăn khí linh phản kích, đối kháng Khai Thi","chuong":"@c1235"},{"text":"Được Vương Lâm nhắc tới như người thủ hộ toàn bộ giới nội khi so sánh với Chu Tước lão Thái","chuong":"@c1287"},{"text":"Ngọc bội mang khí tức của chủ nhân Phong Giới xuất hiện trên Phong Giới Đại Trận, kích hoạt Khai Thiên Phủ bảo vệ giới nội","chuong":"@c1425"}],"kinhLich":[{"chuong":"@c1232","importance":"normal","mucCt":"gon","tieuDe":"Được Vương Lâm gọi xuất hiện","text":"Vương Lâm tiết lộ đã đưa chủ nhân Phong Giới tới Phong Giới đại trận từ trước, gọi ra mặt trong lúc bị Bát Quái Ấn dồn ép.","anchor":"Chủ nhân Phong Giới, ta đã đưa ngươi tới Phong Giới đại trận, ngươi có thể xuất hiện rồi!"},{"chuong":"@c1233","importance":"major","mucCt":"ky","tieuDe":"Hiện thân ban mệnh lệnh, hé lộ bản chất Thiên Kiếp","text":"Hình ảnh hiện ra từ ngọc bội dưới dạng cây đại thụ chọc trời với mặt người già nua, ánh mắt hồi tưởng tang thương. Ra hàng loạt mệnh lệnh sắp xếp cục diện: lệnh Huyền Bỉnh dùng đạo khí sửa sang Vân Hải Tinh Vực và hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện chuẩn bị đại chiến giới ngoại. Gọi Thủy Đạo Tử là Đạo nô, cảnh cáo nếu toàn lực trợ giúp Yêu Tông sẽ không bị giết. Nhắc Cổ Yêu ước định năm đó khi nhận toàn bộ Quỷ Tông làm môn đồ. Nói với Vương Lâm bí mật Thiên Kiếp: đến từ thái cổ, từ thiên đạo sinh tử, ngay cả Tiên Hoàng cũng có, hiện tại chỉ là Tiểu Kiếp, ngại Viễn Cổ Tiên Quy nên không thể nói hết. Nói xong nhắm mắt, đại thụ sụp đổ tiêu tan, ngọc bội hóa tinh quang phá giải Phong Giới Đại Trận.","anchor":"Thiên Kiếp là kiếp, chỉ vì tạo hóa, có một số việc ta ngại Viễn Cổ Tiên Quy mà không thể nói"},{"importance":"bridge","mucCt":"gon","chuong":"@c1234","tieuDe":"Được Vương Lâm nhớ lại lời nói","text":"Được Vương Lâm nhớ lại lời nói về bản chất thiên kiếp trong lúc đối kháng kiếp nạn.","anchor":"Hắn mơ hồ nắm được lời nói của chủ nhân phong giới"},{"mucCt":"vua","text":"Dùng sợi tơ màu xanh quấn lên trận pháp phá hoại trên phạm vi lớn, ngăn khí linh phản kích, đối kháng Khai Thiên Phủ, hỗ trợ Vương Lâm phá lỗ hổng trên Phong Giới Đại Trận. Hét lên thúc giục Vương Lâm nhanh chóng thoát đi khi lỗ hổng mở ra. Sau khi lỗ hổng khép, sợi tơ xanh kết rễ vào chỗ lỗ hổng đó.","anchor":"Còn không mau đi, đợi tới khi nào!","bridge":true,"khoang":"@c1235"},{"chuong":"@c1270","importance":"minor","mucCt":"gon","tieuDe":"Được nhắc trong so sánh","text":"Chủ nhân Phong giới được nhắc để làm rõ rằng lần chống Thủy Đạo Tử trước kia không phải hoàn toàn do Vương Lâm tự mình ra tay.","anchor":"nhưng đó cũng không phải là Vương Lâm ra tay mà chính là chủ nhân Phong giới"},{"chuong":"@c1287","importance":"bridge","mucCt":"gon","tieuDe":"Được so sánh thủ hộ","text":"Chủ nhân phong giới được Vương Lâm nhắc tới như người thủ hộ toàn bộ giới nội khi so sánh với Chu Tước lão Thánh Hoàng.","anchor":"một người thì thủ hộ toàn bộ giới nội"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Được Vương Lâm đưa tới Phong Giới đại trận, gọi ra hỗ trợ","ghiChu":"@c1232"},{"ten":"Huyền Bỉnh","tag":"khac","quanHe":"Thuộc hạ trung thành, nhận phong mệnh","ghiChu":"@c1233"},{"ten":"Thủy Đạo Tử","tag":"khac","quanHe":"Đạo nô, bị ép toàn lực trợ giúp Yêu Tông","ghiChu":"@c1233"},{"ten":"Cổ Yêu","tag":"dong-minh","quanHe":"Yêu Tôn, từ giới ngoại đến, có ước định năm đó","ghiChu":"@c1233"},{"ten":"Cổ Yêu","tag":"khac","quanHe":"Yêu Tôn, năm đó từ giới ngoại đến, có ước định"},{"ten":"Huyền Bỉnh","tag":"cap-tren","quanHe":"Thuộc hạ trực tiếp / Thái thượng trưởng lão Yêu Tông","ghiChu":"Truyền phong mệnh sửa sang Vân Hải và hợp nhất Tứ Đại Tiên Giới"},{"ten":"Vương Lâm","tag":"khac","quanHe":"liên quan chiến tích cũ","ghiChu":"Được nhắc trong so sánh về lần đối đầu Thủy Đạo Tử trước kia."},{"ten":"Thủy Đạo Tử","tag":"doi-thu","quanHe":"liên quan lần chống đỡ trước kia","ghiChu":"Tên ông xuất hiện trong đoạn phân biệt công lao khi chống Thủy Đạo Tử."}],"tuiDo":{}},"nguon":["@c1232","@c1233","@c1234","@c1235","@c1270","@c1287"],"canhGioiCaoNhat":"không rõ"},{"id":"co-yeu-lao-to-tong","name":"Cổ Yêu","cn":"","aliases":["Yêu Tôn"],"gioiTinh":"nam","trangThai":"khong-ro @c1299","tabs":{"kinhLich":[{"chuong":"@c1233","importance":"normal","mucCt":"vua","tieuDe":"Hé lộ lai lịch và ước định với chủ nhân Phong Giới","text":"Được hé lộ năm đó từ giới ngoại đến, chủ nhân Phong Giới nhận toàn bộ Quỷ Tông làm môn đồ và trợ giúp chữa thương, giờ đã hồi phục thành cửu tinh Cổ Yêu. Được yêu cầu thực hiện ước định, gật đầu đồng ý nhưng ánh mắt lộ hàn quang giận dữ khi nhìn về Phong Giới Đại Trận.","anchor":"Yêu Tôn, năm đó ngươi từ giới ngoại đến, ta đã nhận toàn bộ Quỷ Tông của người làm môn đồ"},{"chuong":"@c1297","importance":"bridge","mucCt":"gon","tieuDe":"Liên quan Thiên Hoàng Lô","text":"Cổ Yêu được Vương Lâm nhắc tới khi hắn nhận định Thiên Hoàng Lô có liên quan lớn tới Cổ Yêu.","anchor":"vật này có liên quan tới Cổ Yêu"},{"chuong":"@c1299","importance":"bridge","mucCt":"gon","tieuDe":"Khí tức bị nhận ra","text":"Khí tức Cổ Yêu được Vương Lâm nhận ra khi Tham Lang mở khe không gian và gọi yêu lang tấn công.","anchor":"Yêu khí này Vương Lâm rất rõ ràng, chính là khí tức của Cổ Yêu"}],"tuViMoc":[],"nhanMach":[{"ten":"Chủ nhân Phong Giới","tag":"dong-minh","quanHe":"Ân nhân chữa thương năm đó, có ước định cần thực hiện","ghiChu":"@c1233"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lần đầu lộ diện, lập giao kèo với Vương Lâm và kể nguồn gốc chín tồn tại không hoàn chỉnh cùng chiến tranh cửu quận Yêu Lin","chuong":"@c0555"},{"text":"Giáng ý chí cường đại từ Thiên Yêu thành cứu Vương Lâm, mượn máu ngưng huyết ảnh đại chiến tán ma ba ngày","chuong":"@c0565"},{"text":"Đoạt cuốn tranh trong bình bạch ngọc, biến tiên khí thành yêu khí tại Tiên phủ","chuong":"@c0963"},{"text":"Liên thủ cùng Vương Lâm đối đầu Cổ Ma Tháp Già, hóa thất tinh Cổ Yêu thi triển Yêu Linh Biến và tự bạo phân thân cản địch","chuong":"@c0999"},{"text":"Phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, sau đó bị Vương Lâm bắt sống và hiện nguyên hình lục tinh trăm trượng","chuong":"@c1406"},{"text":"Sống sót sau đại chiến Vân Hải tinh vực, cảm nhận khí tức cổ Mạch Thương Khung Huyết và mơ hồ muốn bái tế","chuong":"@c1612"}]},"nguon":["@c1233","@c1297","@c1299"],"vaiTro":"Cường giả viễn cổ ẩn trong Yêu Cổ — lão tổ tông Thiên Yêu quận, đồng minh giao kèo của Vương Lâm","tinhCach":"Hành sự qua giao kèo và điều kiện ràng buộc lợi ích, tính toán chặt chẽ; sẵn sàng hao tổn bản thể và tự bạo phân thân để chiến đấu, không né tránh khi cần đối đầu; can thiệp gián tiếp qua trung gian thay vì trực tiếp lộ diện; mỉa mai sắc bén và tự phụ về lai lịch cổ tộc","blurb":"Cổ Yêu là một trong chín tồn tại không hoàn chỉnh từ giới ngoại đến, trú ngụ trong Yêu Cổ với tư cách lão tổ tông của Thiên Yêu quận, thường được gọi là Bối La. Ông lập giao kèo với Vương Lâm từ sớm, nhiều lần giáng ý chí hoặc hiện bản thể cứu viện và tham chiến — từ đại chiến tán ma đến liên thủ đánh Cổ Ma Tháp Già trong Tiên phủ — đồng thời trở thành biến số then chốt trong nhiều bước ngoặt của Vương Lâm. Về sau phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, bị Vương Lâm bắt sống và ép giao nộp bí mật, hiện vẫn tồn tại dưới dạng cổ yêu bị phong ấn trong không gian trữ vật của Vương Lâ"},{"id":"thanh-thuy","name":"Thanh Thủy","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1235","importance":"bridge","mucCt":"vua","text":"Được nhắc là người sáng tạo tiên thuật Thôn Linh Phệ Thể Tuyệt Thiên khi mới tới Lôi Tiên Giới, cả đời chỉ truyền cho mỗi Vương Lâm.","anchor":"Cả đời hắn trừ Vương Lâm ra chưa truyền cho bất cứ kẻ nào!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Vốn là thái tử Thanh Thủy Quốc, sau biến cố cố quốc bị diệt đã thức tỉnh Cực Cảnh, quay về bảy ngày đẫm máu tàn sát kẻ thù rồi tự phong ấn vì sát nghiệp quá nặng","chuong":"@c1462"},{"text":"Hiện thân bảo hộ Vương Lâm trước Huyết Thần Tử, lấy thân phận truyền nhân Bạch Phàm công khai nhận sư đệ và truyền thừa tiên thuật Hoán Vũ, Tát Đậu Thành Binh","chuong":"@c0816"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá vào Không Niết Sơ Kỳ — bước thứ ba","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm tọa trấn đài chiến Vân Hải, thay sư đệ bế quan ứng chiến, bị Hư Thần Thiên Tôn trọng thương gần chết","chuong":"@c1494"},{"text":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn, giải thích cuộc đời thê thảm và nguồn gốc sức mạnh","chuong":"@c1650"},{"text":"Cùng con gái Hồng Điệp bước vào chuyển thế đầu thai, nhờ Vương Lâm nếu tìm được con gái thì thay mình chiếu cố","chuong":"@c1696"}]},"nguon":["@c1233","@c1235"],"vaiTro":"Tiên quân Cực Cảnh — sư huynh đồng mạch Bạch Phàm của Vương Lâm, phách thứ nhất Thất Thải Tiên Tôn","tinhCach":"trọng nghĩa đồng môn, nhiều lần xả thân bảo hộ Vương Lâm; sát phạt quyết liệt, mang sát nghiệp nặng nề từ viễn cổ; thận trọng đa nghi, không dễ tin người; nặng tình thân, nguyện cùng con gái chuyển thế đầu thai","blurb":"Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới, sau khi cố quốc bị diệt vong đã thức tỉnh Cực Cảnh, quay về tàn sát kẻ thù rồi mang sát nghiệp cùng cực và tự phong ấn. Là sư huynh đồng mạch Bạch Phàm của Vương Lâm, ông nhiều lần hiện thân bảo hộ, truyền thừa tiên thuật Hoán Vũ và Tát Đậu Thành Binh, về sau dùng sát lục bổn nguyên phá Không Môn bước vào Không Niết Sơ Kỳ. Thân phận được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cuối cùng ông cùng con gái Hồng Điệp bước vào chuyển thế, nhờ Vương Lâm chiếu cố con gái nếu tìm được."},{"id":"nam-van-tu","name":"Nam Vân Tử","cn":"南云子","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nam Vân Tử là tu sĩ thuộc Thi Âm Tông của Liên Minh Tinh Vực, một trong ba người ở ba tinh vực được chủ nhân Phong Giới giao ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Trong đại chiến giới nội – giới ngoại, ông vừa xung trận bảo vệ Vân Hải, vừa đảm nhận sửa chữa Phong Giới Đại Trận và ngưng tụ hư ảnh trận pháp khổng lồ tấn công kẻ địch; sau khi bị Chưởng Tôn đánh trọng thương bế quan rồi phục hồi, ông cầm đầu lực lượng cuối cùng chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến tại Chu Tước Tinh, dốc toàn lực trợ giúp Vương Lâm mở Không Môn, và tiếp tục theo sát Vương Lâm xuất chinh c","vaiTro":"Tu sĩ Thi Âm Tông (Liên Minh Tinh Vực) — người giữ ước định hợp nhất Tứ Đại Tiên Giới, tinh thông trận pháp","tinhCach":"Trọng nghĩa khí, cả đời ít nói nhưng quyết báo đáp ân tình Phong Tôn; kiên định không lùi bước trước kẻ địch mạnh; tinh thông trận pháp, hành sự cẩn trọng; có tầm nhìn đại cục, biết nắm thời cơ chỉ huy chiến trường","tabs":{"diem":[{"text":"Được chủ nhân Phong Giới chọn làm một trong ba người giữ ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Xung trận chiến đấu bảo vệ Vân Hải và đảm nhận sửa chữa Phong Giới Đại Trận trong đại chiến giới nội – giới ngoại","chuong":"@c1427"},{"text":"Ngưng tụ hư ảnh trận pháp khổng lồ phối hợp tấn công kẻ địch, thể hiện trình độ trận pháp cao thâm","chuong":"@c1438"},{"text":"Cầm đầu chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến bên ngoài Chu Tước Tinh","chuong":"@c1520"},{"text":"Nắm thời cơ chỉ huy chiến trường và dốc toàn lực trợ giúp Vương Lâm mở Không Môn","chuong":"@c1524"},{"text":"Sau khi đấu tranh nội tâm rất lâu, cuối cùng chọn ở lại động phủ giới","chuong":"@c1694"}],"kinhLich":[{"chuong":"@c1233","importance":"normal","mucCt":"gon","tieuDe":"Được chủ nhân Phong Giới nhắc tên","text":"Chủ nhân Phong Giới lệnh Huyền Bỉnh đi tìm Nam Vân Tử cùng hai người khác ở ba tinh vực còn lại để thông báo ước định hợp nhất Tứ Đại Tiên Giới đã có thể thực hiện.","anchor":"tìm kiếm ba người Nam Vân Tử, Hồng Sam Tử và Chiến Tiên Tử"}],"tuViMoc":[],"nhanMach":[{"ten":"Chủ nhân Phong Giới","tag":"cap-tren","quanHe":"Người ban ước định","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"su-mon","quanHe":"Người ra ước định","ghiChu":"@c1233"},{"ten":"Huyền Bỉnh","tag":"dong-minh","quanHe":"Người mang phong mệnh đến tìm","ghiChu":"@c1233"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Cùng thuộc nhóm ba người cần tìm","ghiChu":"@c1233"},{"ten":"Chiến Tiên Tử","tag":"dong-minh","quanHe":"Cùng thuộc nhóm ba người cần tìm","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"dong-minh","quanHe":"Có ước định năm xưa với chủ nhân Phong Giới","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"khac","quanHe":"Người đặt ước định","ghiChu":"Được nhắc tên trong phong mệnh"},{"ten":"Huyền Bỉnh","tag":"khac","quanHe":"Người được lệnh đi tìm","ghiChu":"Thái thượng trưởng lão Yêu Tông"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1233"]},{"id":"hong-sam-tu","name":"Hồng Sam Tử","cn":"红衫子","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chiến trong các trận ","vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","tabs":{"diem":[{"text":"Được chủ nhân Phong Giới chọn là một trong những người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải bất ngờ xuất hiện tiếp viện giới nội khi chiến tranh bùng nổ","chuong":"@c1425"},{"text":"Phá sát giới mấy vạn năm, thi triển thần thông Huyết Sam, một mình đối đầu năm cao thủ bước thứ ba và chiếm ưu thế với tu vi Không Huyền Trung Kỳ","chuong":"@c1427"},{"text":"Bị hàn y đồng tử và tu sĩ bước thứ ba giới ngoại liên thủ phong ấn tại Thất Thải Giới, sau được Vương Lâm giải cứu khỏi đạo quả","chuong":"@c1469"},{"text":"Không do dự lao theo hỗ trợ Vương Lâm, cùng Thanh Lâm và Lam Mộng Đạo Tôn hộ pháp bổn tôn và khống chế phân thân Vương Lâm trong trận quyết chiến cuối","chuong":"@c1628"},{"text":"Chọn chuyển thế đầu thai rời đi sau khi đại cục an định","chuong":"@c1694"}],"kinhLich":[{"chuong":"@c1233","importance":"normal","mucCt":"gon","tieuDe":"Được chủ nhân Phong Giới nhắc tên","text":"Chủ nhân Phong Giới lệnh Huyền Bỉnh đi tìm Hồng Sam Tử cùng hai người khác ở ba tinh vực còn lại để thông báo ước định hợp nhất Tứ Đại Tiên Giới đã có thể thực hiện.","anchor":"tìm kiếm ba người Nam Vân Tử, Hồng Sam Tử và Chiến Tiên Tử"}],"tuViMoc":[],"nhanMach":[{"ten":"Chủ nhân Phong Giới","tag":"cap-tren","quanHe":"Người ban ước định","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"su-mon","quanHe":"Người ra ước định","ghiChu":"@c1233"},{"ten":"Huyền Bỉnh","tag":"dong-minh","quanHe":"Người mang phong mệnh đến tìm","ghiChu":"@c1233"},{"ten":"Nam Vân Tử","tag":"dong-minh","quanHe":"Cùng thuộc nhóm ba người cần tìm","ghiChu":"@c1233"},{"ten":"Chiến Tiên Tử","tag":"dong-minh","quanHe":"Cùng thuộc nhóm ba người cần tìm","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"dong-minh","quanHe":"Có ước định năm xưa với chủ nhân Phong Giới","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"khac","quanHe":"Người đặt ước định","ghiChu":"Được nhắc tên trong phong mệnh"},{"ten":"Huyền Bỉnh","tag":"khac","quanHe":"Người được lệnh đi tìm","ghiChu":"Thái thượng trưởng lão Yêu Tông"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1233"]},{"id":"chien-tien-tu","name":"Chiến Tiên Tử","cn":"战仙子","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Một trong ba người ở ba tinh vực còn lại mà Huyền Bỉnh cần tìm để thông báo ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện.","vaiTro":"Nhân vật ở tinh vực khác, liên quan ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Được chủ nhân Phong Giới nhắc tên, là một trong ba người cần liên lạc để hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện","chuong":"@c1233"}],"kinhLich":[{"chuong":"@c1233","importance":"normal","mucCt":"gon","tieuDe":"Được chủ nhân Phong Giới nhắc tên","text":"Chủ nhân Phong Giới lệnh Huyền Bỉnh đi tìm Chiến Tiên Tử cùng hai người khác ở ba tinh vực còn lại để thông báo ước định hợp nhất Tứ Đại Tiên Giới đã có thể thực hiện.","anchor":"tìm kiếm ba người Nam Vân Tử, Hồng Sam Tử và Chiến Tiên Tử"}],"tuViMoc":[],"nhanMach":[{"ten":"Chủ nhân Phong Giới","tag":"cap-tren","quanHe":"Người ban ước định","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"su-mon","quanHe":"Người ra ước định","ghiChu":"@c1233"},{"ten":"Huyền Bỉnh","tag":"dong-minh","quanHe":"Người mang phong mệnh đến tìm","ghiChu":"@c1233"},{"ten":"Nam Vân Tử","tag":"dong-minh","quanHe":"Cùng thuộc nhóm ba người cần tìm","ghiChu":"@c1233"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Cùng thuộc nhóm ba người cần tìm","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"dong-minh","quanHe":"Có ước định năm xưa với chủ nhân Phong Giới","ghiChu":"@c1233"},{"ten":"Chủ nhân Phong Giới","tag":"khac","quanHe":"Người đặt ước định","ghiChu":"Được nhắc tên trong phong mệnh"},{"ten":"Huyền Bỉnh","tag":"khac","quanHe":"Người được lệnh đi tìm","ghiChu":"Thái thượng trưởng lão Yêu Tông"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1233"]},{"id":"chu-tuoc","name":"Chu Tước","cn":"朱雀","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1234","tieuDe":"Quy phục thiên kiếp, gần đạt hư hỏa","text":"Trong Tứ Tượng thiên kiếp, được Vương Lâm điểm ngón tay triệu khiến rời tam linh, nhảy vào cơ thể hắn quy phục. Hấp thu Ly hỏa, Ngũ Hành hỏa ấn và lửa thiên kiếp, hỏa diễm đạt mức khó tin. Đã thức tỉnh ba lần sinh ra bổn nguyên nắm thực hỏa cực hạn, chỉ kém một đường là đạt lần thức tỉnh thứ tư bước vào hư hỏa. Chữa trị nguyên thần cho Vương Lâm.","anchor":"Chu Tước kia trực tiếp nhảy vào trong cơ thể Vương Lâm, lập tức có ngọn lửa ngập trời bùng lên"},{"mucCt":"gon","anchor":"Viêm hỏa dị tinh này không thể khiến cho Chu Tước của ta tỉnh giấc lần thứ tư","text":"Chu Tước được nhắc khi Vương Lâm xác định lượng Viêm hỏa dị tinh thu được chưa đủ để khiến Chu Tước của hắn tỉnh giấc lần thứ tư.","bridge":true,"khoang":"@c1289"},{"mucCt":"vua","text":"Chu Tước màu đen dưới chân Vương Lâm bị đệ nhất chuyển nghiệp hỏa thiêu đốt đến kêu thê lương, thân thể thu nhỏ và một nửa bị nhuốm đỏ. Sau đó nó được Vương Lâm triệu tới dung hợp cùng hắn trong lúc đối mặt kiếp hỏa.","anchor":"Chu Tước một nửa thân thể bị nhuốm thành màu đỏ kia","bridge":true,"khoang":"@c1319"},{"chuong":"@c1322","importance":"major","mucCt":"ky","tieuDe":"Thức tỉnh lần thứ tư — thực hỏa hóa hư hỏa biến dị","text":"Chu Tước tỉnh giấc lần thứ tư, toàn bộ hỏa diễm trong Địa phương giới tụ về thân thể nó, hỏa liên chín màu hóa thành áo giáp chín màu, đạt cực hạn thực hỏa. Sương mù từ lực do Thiên Nghịch phun ra quét qua, toàn bộ thực hỏa tan nát và hóa thành hư hỏa, nhưng hư hỏa phát sinh biến hóa quỷ dị khác thường.","anchor":"Trong nháy mắt khi sương mù từ lực đảo qua, thân thể Chu Tước liền chấn động mạnh mẽ"}],"tuViMoc":[{"chuong":"@c1234","canhGioi":"Gần hư hỏa (thức tỉnh lần 4 kém một đường)","text":"Sau khi hấp thu lửa thiên kiếp, hỏa diễm đạt cực hạn thực hỏa. Khoảng cách tới lần thức tỉnh thứ tư (hư hỏa/nộ hỏa) chỉ còn kém một đường.","importance":"minor"},{"chuong":"@c1322","canhGioi":"Hư hỏa (biến dị)","text":"Thức tỉnh lần thứ tư hoàn thành, thực hỏa tan nát hóa hư hỏa, nhưng do từ lực Thiên Nghịch quét qua nên hư hỏa xuất hiện biến hóa quỷ dị khác thường.","importance":"major"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"hỏa hệ gắn với Vương Lâm","ghiChu":"Hình ảnh Chu Tước hiện lên trong tinh thể hỏa hệ mà Vương Lâm luyện từ Viêm hỏa dị tinh."}]},"nguon":["@c1234","@c1289","@c1319","@c1322"],"tinhCach":[],"canhGioiCaoNhat":"Hư hỏa (vừa đạt, có biến dị)"},{"id":"lao-gia-toai-niet-dai-vien-man","name":"Lão giả Toái Niết đại viên mãn (thủ trận giới ngoại)","gioiTinh":"nam","theLuc":[{"ten":"Tu sĩ giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết đại viên mãn","trangThai":"tu-vong","blurb":"Lão giả tu vi Toái Niết đại viên mãn, chỉ huy đám tu sĩ giới ngoại thủ trận tại Phong Giới Đại Trận. Bị Vương Lâm dùng tia chớp đỏ diệt nguyên thần, xác bị sương mù đen thôn phệ thành tro.","vaiTro":"Tu sĩ giới ngoại thủ trận, bị Vương Lâm diệt","tinhCach":"Quyết đoán, dám đối đầu trực tiếp","tabs":{"diem":[{"text":"Chỉ huy kết trận chống Vương Lâm nhưng bị tia chớp đỏ xuyên phá tất cả phòng ngự, nguyên thần diệt tuyệt","chuong":"@c1236"}],"kinhLich":[{"mucCt":"vua","text":"Chỉ huy đám tu sĩ giới ngoại kết trận, hô lớn Kết trận, dùng toàn bộ nguyên lực thi triển thần thông ngũ sắc và tấm khiên hình mặt quỷ phòng thủ. Bị tia chớp đỏ từ trong sương mù đen xuyên phá tất cả, thức hải sụp đổ, nguyên thần diệt tuyệt, xác bị sương mù đen thôn phệ thành túi xương khô rồi hóa tro.","anchor":"Thức hải sụp đổ, nguyên thần diệt tuyệt, sinh cơ toàn bộ thân thể tiêu tán","bridge":true,"khoang":"@c1236"}],"tuViMoc":[{"chuong":"@c1236","canhGioi":"Toái Niết đại viên mãn","text":"Tu vi đạt Toái Niết đại viên mãn, là người mạnh nhất trong nhóm thủ trận.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm diệt","ghiChu":"@c1236"}],"tuiDo":{"phapBao":[{"ten":"Tấm khiên hình mặt quỷ","trangThai":"hong","moTa":"Pháp bảo phòng ngự, bị tia chớp đỏ Vương Lâm xuyên thủng rồi nổ tung","nguon":"@c1236"}]}},"nguon":["@c1236"]},{"id":"than-anh-khong-lo-c1236","name":"Thân ảnh khổng lồ (gầm thét cuối chương 1236)","gioiTinh":"khong-ro","trangThai":"song","blurb":"Thân ảnh lớn sánh với tinh không, xuất hiện cuối chương gầm thét tên Vương Lâm rồi lao tới nơi hắn vừa biến mất. Danh tính chưa xác nhận trong chương.","vaiTro":"Cường giả bí ẩn truy đuổi Vương Lâm","tinhCach":"Giận dữ, quyết liệt","tabs":{"diem":[{"text":"Thân ảnh lớn sánh với tinh không, gầm thét tên Vương Lâm lao tới","chuong":"@c1236"}],"kinhLich":[{"mucCt":"vua","text":"Xuất hiện ngay khi Vương Lâm vừa biến mất, gầm thét điên cuồng tên Vương Lâm. Thân ảnh lớn sánh với tinh không ầm ầm lao tới nơi Vương Lâm thôn phệ tu sĩ giới ngoại.","anchor":"Một thân ảnh thật lớn có thể sánh với tinh không đang hướng về nơi này ầm ầm lao tới","bridge":true,"khoang":"@c1236"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Truy đuổi Vương Lâm","ghiChu":"@c1236"}],"tuiDo":{}},"nguon":["@c1236"]},{"id":"thac-sam","name":"Thác Sâm","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Mười năm qua ở giới ngoại Thái Cổ Tinh Thần điên cuồng đồ sát bộ lạc thái cổ, bị ba cao thủ bước thứ ba truy sát, trong đó một người cảnh giới Không Niết đã giáng đòn nghiêm trọng. Cảm nhận khí tức Vương Lâm, xé tinh không đuổi theo. Bị Vương Lâm dùng Cực Cảnh (thiên kiếp cực) tấn công, tia chớp đỏ chui vào cơ thể phá hoại liên tục không thể hủy diệt nhưng nhờ sức hồi phục Cổ Thần nên không đáng lo. Phản đòn đánh trúng Vương Lâm. Khi muốn tiếp tục truy kích thì ba cao thủ ép tới buộc phải dừng lại. So với lúc ở vùng đất Cổ Thần đã yếu đi rất nhiều.","anchor":"Vương Lâm! Cuối cùng bổn thần đã tìm thấy ngươi rồi!","bridge":true,"khoang":"@c1237"},{"chuong":"@c1238","importance":"normal","mucCt":"ky","tieuDe":"Bị truy sát mười năm, quay đầu tuyên chiến","text":"Bị ba cao thủ bước thứ ba Thái Cổ Tinh Thần truy sát suốt mười năm, hai mắt đỏ ngầu xé khe tinh không lao ra. Phẫn nộ vì trong ba người có kẻ đạt cảnh giới Không Linh. Nhận ra ba người muốn hắn suy yếu, hiểu rằng không giết ba người này thì không thể cắn nuốt Vương Lâm. Hóa thành Cổ Thần khổng lồ, tuyên chiến và lao thẳng tới đối đầu.","anchor":"Ba người các người bám theo bổn thần mười năm, đơn giản là muốn bổn thần suy yếu"},{"chuong":"@c1239","importance":"major","mucCt":"ky","tieuDe":"Đại chiến Vương Lâm và Nguyệt Tộc, bị chém mất ngón trỏ","text":"Cho nổ một tinh điểm toái tinh phá vây ba cao thủ Viễn Cổ Tinh Thần, phong ấn nữ tu Không Niết vào tinh điểm thứ hai. Truy đuổi Vương Lâm đến tinh vực Nguyệt Tộc, giao chiến chính diện. Tuyên bố nắm toàn bộ sức mạnh truyền thừa Đồ Ti, Vương Lâm chỉ có ký ức. Muốn nuốt Vương Lâm nhưng bị uy hiếp bằng Đồ Ti chưa chết — lộ nỗi sợ lớn nhất. Bị Phong Thần Đại Trận phong ấn cùng Vương Lâm, tạm liên thủ, cung cấp Cổ Thần lực cho thần thông bát tinh Hư phá trận. Bị đốt xương cửu tinh đánh phun máu. Bị Dòng chảy tinh thần hút Cổ Thần lực, tay phải tê dại, ngón trỏ bị huyết kiếm chém đứt. Cho nổ tu sĩ bước thứ ba trong tinh điểm cố thôn phệ tàn cốt nhưng đốt xương bị Vương Lâm chém đôi, chỉ thu được một nửa vào tinh điểm. Nữ tu bước thứ ba trong mi tâm đột ngột bộc phát ánh sáng, Thác Sâm bỏ qua Vương Lâm phun máu bỏ chạy.","anchor":"Thác Sâm cả đời cuồng vọng, trời đất cũng không sợ, nhưng có một người mà cả cuộc đời này hắn e ngại nhất, đó chính là Đồ Ti"},{"chuong":"@c1240","importance":"bridge","mucCt":"gon","text":"Được nhắc lại: trong cuộc đuổi giết Vương Lâm, mi tâm đột ngột tỏa sáng chói mắt rồi vội vàng bỏ chạy, Vương Lâm đoán không ra nguyên nhân.","anchor":"hình ảnh cuối cùng là trong tinh điểm ở mi tâm Thác Sâm tỏa ra ánh sáng chói mắt"},{"chuong":"@c1242","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ lại: mi tâm Thác Sâm phát ánh sáng chói mắt, thần sắc đại biến vội vàng lui lại, có thể đã phát hiện bạch y nữ tử bám theo.","anchor":"hắn đã cẩn thận nhớ lại những chuyện trên đường từ lúc tiến vào Thái Cổ Tinh Thần này"},{"importance":"bridge","mucCt":"gon","chuong":"@c1247","tieuDe":"","text":"Được Vương Lâm nhắc đến khi so sánh phương pháp dùng tinh điểm hấp thụ đốt ngón tay Cổ Thần.","anchor":"Thác Sâm lấy tinh điểm để hấp thụ đốt ngón tay này, thuật này rất mạnh, hắn còn có thể nuốt được cao thủ bước thứ ba"},{"chuong":"@c1276","importance":"normal","mucCt":"ky","tieuDe":"Chống ý nô dịch","text":"Trong Man Hoang địa, Thác Sâm điên cuồng đánh vào mi tâm để chống lại ý chí muốn biến hắn thành nô lệ và đoạt hồn phách. Sau đó hắn khựng lại vì cảm nhận khí tức đồng tộc cực kỳ quen thuộc, nhận ra ký ức ấy liên quan tới Đồ Ti.","anchor":"Khí tức của người cùng tộc, khí tức này cực kỳ quen thuộc"},{"chuong":"@c1281","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc qua Tư Mặc Tử","text":"Thác Sâm được nhắc lại qua lai lịch Tư Mặc Tử là một trong ba đại năng Đệ Tam Bộ từng đuổi giết hắn.","anchor":"đuổi giết Thác SÂm khi Vương Lâm tiến vào trong Thái Cổ tinh thần"},{"chuong":"@c1288","importance":"bridge","mucCt":"gon","text":"Thác Sâm được nhắc lại trong ký ức của Vương Lâm về nhóm ba tu sĩ bước thứ ba từng truy đuổi hắn ở Thái Cổ Tinh Thần.","anchor":"Bộ dáng của đối phương chính là một trong ba người tu vi bước thứ ba truy đuổi Thác Sâm"},{"mucCt":"gon","anchor":"Thác Sâm dung họp với tu sĩ bước thứ ba, mà Vương Lâm thì lại dung hợp với pháp bảo","text":"Vương Lâm đối chiếu con đường của mình với Thác Sâm, cho rằng Thác Sâm dung hợp tu sĩ bước thứ ba còn hắn dung hợp pháp bảo Cổ Thần.","bridge":true,"khoang":"@c1303"},{"chuong":"@c1312","importance":"bridge","mucCt":"vua","tieuDe":"Được nhớ về lực đạo","text":"Thác Sâm được Vương Lâm nhớ lại như đối thủ vượt xa hắn trong phương diện vận dụng lực lượng Cổ Thần.","anchor":"Nhất là khi nhớ lại trận đánh với Thác Sâm, rất hiển nhiên là Thác Sâm đối với phương diện này vượt xa Vương Lâm."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Vương tộc Cổ Thần còn lại — muốn dung hợp nhưng bị cự tuyệt; tạm hợp tác chống Nguyệt Tộc rồi lại đối đầu","nguon":"@c1239"},{"ten":"Ti Mặc Tử","tag":"doi-thu","quanHe":"Cao thủ Viễn Cổ Tinh Thần truy sát hắn mười năm, bị bỏ qua nhờ thần thông hộ thân","nguon":"@c1239"},{"ten":"Lão già cảnh giới Không Linh (Viễn Cổ Tinh Thần)","tag":"doi-thu","quanHe":"Cao thủ Viễn Cổ Tinh Thần truy sát hắn mười năm","nguon":"@c1239"},{"ten":"Nữ tử Không Niết (Viễn Cổ Tinh Thần)","tag":"doi-thu","quanHe":"Cao thủ Viễn Cổ Tinh Thần, bị Thác Sâm đánh bại phong ấn vào tinh điểm","nguon":"@c1239"},{"ten":"Đồ Ti","tag":"khac","quanHe":"Liên hệ ký ức Cổ Thần","ghiChu":"Thác Sâm nhắc Đồ Ti khi nhận ra khí tức đồng tộc quen thuộc."},{"ten":"Tư Mặc Tử","tag":"doi-thu","quanHe":"Kẻ từng đuổi giết","ghiChu":"Tư Mặc Tử từng tham gia truy sát Thác Sâm."},{"ten":"Cổ thần Đồ Ti","tag":"khac","quanHe":"ký ức và đồng tộc","ghiChu":"Thác Sâm nhắc Đồ Ti như nguồn ký ức giúp nhận ra khí tức đồng tộc trong Thái Cổ Tinh Thần."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Lộ diện là kẻ đứng đầu huyết hải bị phong ấn mấy vạn năm trong Cổ Thần Chi Địa, thực chất là ma vật do oán niệm Cổ Thần Đồ Ti ngưng tụ","chuong":"@c0163"},{"text":"Trao Hỗn Nguyên khu thú quyển và cực phẩm linh thạch cho Vương Lâm, dụ dỗ phá phong ấn và ép hấp thu sức mạnh Đồ Ti","chuong":"@c0170"},{"text":"Phá phong ấn, hóa huyết hải thành huyết long vạn trượng xông vào hư vô, thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ","chuong":"@c1060"},{"text":"Thức tỉnh sau trăm năm, phá trận pháp bay khỏi Chu Tước Tinh, quét ngang Liên Minh tinh vực và truy tìm Vương Lâm xuyên nhiều tinh vực","chuong":"@c1147"},{"text":"Đại chiến Vương Lâm trong cổ mộ, lần đầu bỏ xưng bổn thần, quỳ nhận truyền thừa Đồ Ti và nói hai chữ đa tạ","chuong":"@c1386"},{"text":"Sau truyền thừa, Đồ Ti thức tỉnh trong thân Thác Sâm, góp sức phong ấn Chưởng Tôn rồi mờ mịt đi vào tinh không suy nghĩ về đầu thai chuyển thế","chuong":"@c1693"}]},"nguon":["@c1237","@c1238","@c1239","@c1240","@c1242","@c1247","@c1276","@c1281","@c1288","@c1303","@c1312"],"canhGioiCaoNhat":"Không đổi trong @c1312","cn":"拓森","gioiTinh":"nam","tinhCach":"Xảo trá, dùng bảo vật làm mồi nhử dụ dỗ Vương Lâm phá phong ấn; tàn nhẫn, khinh miệt chúng sinh như kiến và tàn sát hàng loạt tu sĩ không chớp mắt; cuồng ngạo đỉnh thiên, coi mọi thế lực đều không đáng kể; chấp niệm sâu nặng, liên tục khắc tên Vương Lâm và thề truy sát","theLuc":[{"ten":"Bộ tộc Cổ Thần","trangThai":"gan-bo"}],"vaiTro":"Phản diện trọng yếu — Cổ Ma Đồ Ti, ma vật chủ huyết hải bị phong ấn trong Cổ Thần Chi Địa","blurb":"Thác Sâm là nam tử tóc đỏ như máu, kẻ đứng đầu huyết hải, thực chất là ma vật do oán niệm của Cổ Thần Đồ Ti chết ngưng tụ — tức Cổ Ma Đồ Ti — bị phong ấn mấy vạn năm trên thạch chùy giữa Cổ Thần Chi Địa. Hắn dùng bảo vật dụ dỗ Vương Lâm phá phong ấn, thừa kế lực lượng truyền thừa bát tinh Cổ Thần Đồ Ti, triệu hoán Diệt Thần Mâu và thi triển tuế nguyệt quy tắc tàn sát hàng loạt tu sĩ, phá phong ấn bay khỏi Chu Tước Tinh quét ngang Liên Minh tinh vực, truy tìm Vương Lâm xuyên suốt nhiều tinh vực. Cuối cùng trong cổ mộ, sau trận chiến định mệnh với Vương Lâm, Thác Sâm lần đầu bỏ xưng bổn thần, qu"},{"id":"ba-cao-thu-buoc-thu-ba","name":"Ba cao thủ bước thứ ba (Thái Cổ Tinh Thần)","cn":"","aliases":[],"gioiTinh":"khac","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba (Không Niết — chưa độ kiếp)","trangThai":"song","blurb":"Ba cao thủ bước thứ ba (hai nam một nữ) của Thái Cổ Tinh Thần, truy sát Thác Sâm suốt nhiều năm. Trong đó một người đạt cảnh giới Không Niết, đã giáng cho Thác Sâm đòn nghiêm trọng.","vaiTro":"Nhóm cao thủ giới ngoại truy sát Thác Sâm","tinhCach":"Kiên nhẫn, chiến thuật ép kiệt sức đối thủ","tabs":{"diem":[{"text":"Hai nam một nữ, bên ngoài thân thể có gợn sóng ngăn cản thần thức, không nhìn rõ hình dáng","chuong":"@c1237"},{"text":"Một người đạt cảnh giới Không Niết (chưa độ kiếp), đã giáng cho Thác Sâm đòn nghiêm trọng","chuong":"@c1237"}],"kinhLich":[{"mucCt":"gon","text":"Truy sát Thác Sâm suốt nhiều năm ở Thái Cổ Tinh Thần, dùng chiến thuật dần ép kiệt sức. Khi nhận ra Cực Cảnh (thiên kiếp cực) liền tăng tốc tấn công Thác Sâm, buộc hắn không thể tiếp tục truy kích Vương Lâm.","anchor":"ba đạo cầu vồng phía sau gào thét, tốc độ tăng mạnh","bridge":true,"khoang":"@c1237"},{"chuong":"@c1239","importance":"normal","mucCt":"gon","tieuDe":"Bị Thác Sâm toái tinh phá vây","text":"Ba cao thủ bước thứ ba chặn Thác Sâm, bị hắn cho nổ tinh điểm toái tinh tạo sóng xung kích buộc tách ra. Lão già Không Linh và Ti Mặc Tử lộ nụ cười quỷ dị — thực chất không muốn bắt; nữ tu Không Niết bị phong ấn vào tinh điểm.","anchor":"Vương tộc Cổ Thần trong trời đất này có lẽ chỉ còn hai người này"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát, đồ sát bộ lạc thái cổ","ghiChu":"@c1237"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1237","@c1238","@c1239"]},{"id":"lao-gia-ao-xanh-luc-ma-nap-tinh","name":"Lão giả áo xanh lục (Ma Nạp Tinh)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ma Nạp Tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên nhân đệ nhất suy (đại thần thông)","trangThai":"tu-vong","blurb":"Đại thần thông tu sĩ trên Ma Nạp Tinh, tu vi thiên nhân đệ nhất suy. Bay ra phản kháng Vương Lâm nhưng bị thuật Định khống chế, Cực Cảnh xâm nhập cơ thể, sương đen tràn ngập.","vaiTro":"Tu sĩ giới ngoại bị Vương Lâm giết trên Ma Nạp Tinh","tinhCach":"Dũng cảm phản kháng kẻ xâm nhập","tabs":{"diem":[{"text":"Đại thần thông tu sĩ mạnh nhất trên Ma Nạp Tinh, tu vi thiên nhân đệ nhất suy","chuong":"@c1237"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1237","tieuDe":"Bị Vương Lâm giết trên Ma Nạp Tinh","text":"Bay ra phản kháng Vương Lâm khi hắn tấn công Ma Nạp Tinh, bị thuật Định khống chế rồi Cực Cảnh chui vào cơ thể, sương đen tràn ngập, kêu thảm thiết.","anchor":"Ma tu phương nào dám đến nuốt linh hồn trên Ma Nạp Tinh ta!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ tấn công giết chết","ghiChu":"@c1237"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1237"]},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","cn":"蓝梦道尊","aliases":["Lam Sơn","Lâm Mộng Đạo Tôn"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lam Ti Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1315","trangThai":"song","blurb":"Lam Mộng Đạo Tôn là một trong Thái Cổ Ngũ Tôn của Thái Cổ Tinh Thần, lãnh đạo Lam Ti Tộc, cư ngụ tại Lam Sơn và về sau được tiết lộ là người sinh ra trong giới nội. Ông từng chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thần thông, nhiều lần dõi theo và can thiệp giúp Vương Lâm. Dù từng vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, về sau ông tuyên bố đứng về phía Vương Lâm và tham chiến trong các biến cố lớn.","vaiTro":"Thái Cổ Ngũ Tôn — lãnh đạo Lam Ti Tộc","tinhCach":"Thâm trầm u buồn; trọng tình thân; điềm tĩnh thận trọng; nặng nhân quả","tabs":{"diem":[{"text":"Là một trong ngũ đại tôn giả Thái Cổ Tinh Thần, được Vương Lâm xác định qua ký ức tu sĩ giới ngoại.","chuong":"@c1237"},{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống không thành, sau đó truyền ba thức thần thông cho hắn.","chuong":"@c1243"},{"text":"Can thiệp cứu Vương Lâm trong Địa Phương hương nhưng bị sức mạnh Thiên Nghịch bức lui.","chuong":"@c1320"},{"text":"Đạt Không Huyền đại viên mãn, được nêu là đứng đầu Thái Cổ Ngũ Tôn.","chuong":"@c1435"},{"text":"Vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, dẫn tới ân đoạn nghĩa tuyệt.","chuong":"@c1492"},{"text":"Một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày.","chuong":"@c1583"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1237","tieuDe":"Được Vương Lâm nhắc tên","text":"Vương Lâm từ ký ức vài trăm tu sĩ đã nuốt xác định Lam Mộng Đạo Tôn là ngũ đại tôn giả Thái Cổ Tinh Thần, quyết định đưa Lý Thiến Mai tới chỗ vị này.","anchor":"Lam Mộng Đạo Tôn là một trong ngũ đại tôn giả của Thái Cổ Tinh Thần, ở trên lam Sơn chỗ của Lam Ti Tộc"},{"mucCt":"ky","text":"Nam tử trung niên mặc áo lam, tóc lam có vài sợi bạc, tướng mạo tuyệt thế, vẻ u buồn. Ngồi gảy cổ cầm trên Lam Sơn, thánh địa Lam Ti tộc. Nữ tử áo hồng nhạt (em gái người yêu hắn) tới hỏi sao chưa quên, hắn khẳng định tỷ tỷ của muội chưa chết. Sau đó cảm ứng bạch y nữ tử ở bờ tinh vực Lam Ti tộc, hiện thân chặn lại quát đuổi, bùng sát khí với ý cảnh tuyệt sát. Bạch y nữ tử nói Vương Lâm đã bị lựa chọn rồi và sẽ phải đi ra, rồi lui đi tiêu tan. Được giới thiệu là ngũ tôn Thái Cổ Tinh Thần, thiên tư đệ nhất Lam Ti tộc trong vô số năm, si tình chỉ yêu một nữ tử duy nhất, chính tình cảm giúp hắn đạt bước này, khiến cả Chưởng Tôn kiêng kỵ.","anchor":"Lam Mộng Đạo Tôn chính là người có thiên tư đệ nhất trong Lam Ti tộc trong vô số năm qua","bridge":true,"khoang":"@c1240"},{"text":"Xuất hiện trong lam quang, vung tay áo tạo gió lốc cuốn Lý Thiến Mai khỏi tay Vương Lâm, ôm nàng biến mất mà từ đầu đến cuối không liếc Vương Lâm. Mang nàng về Lam Sơn trên tu chân tinh riêng, bắt quyết trục hắc khí từ thất khiếu khiến nàng tỉnh lại nhưng mất trí nhớ, đặt tên Lam Nguyệt. Tuyên bố khoảng cách xa nhất là lãng quên — nếu sau khi quên mà hai người còn bắt đầu lại được thì sẽ không ngăn cản, dù Vương Lâm bị viễn cổ tiên vực lựa chọn cũng dám đánh một trận.","anchor":"dù là hắn bị viễn cổ tiên vực lựa chọn thì phụ thân cũng dám đánh một trận với viễn cổ tiên vực","mucCt":"ky","bridge":true,"khoang":"@c1241"},{"mucCt":"vua","text":"Hiện thân trong ánh sáng lam nhu hòa trên bầu trời, hình dạng nam tử trung niên, hỏi Vương Lâm có muốn học chín đại thần thông của mình không. Trước đó Vương Lâm suy đoán Lam Mộng đã dùng việc leo Lam Sơn để âm thầm nâng cao độ nhạy cảm nguyên thần linh hồn, qua đó ám chỉ cảnh báo về bạch y nữ tử bí ẩn.","anchor":"Ta có chín đại thần thông, ngươi có học hay không?","bridge":true,"khoang":"@c1242"},{"chuong":"@c1243","importance":"major","mucCt":"ky","tieuDe":"Chiêu mộ Vương Lâm thất bại, truyền ba thức thần thông","text":"Đưa ra hấp dẫn cực lớn chiêu mộ Vương Lâm kế thừa đạo thống: chín thức thần thông, sáu thức tiên pháp, ba thức đạo thuật, một thức sinh tử, hương hỏa hai ngàn triệu, năm đạo khí thiên thạch thiên ngoại, hứa giúp Cổ Thần thân và bảy đạo bổn nguyên đại thành, gánh nguy cơ nữ tử lai lịch lớn. Hai điều kiện: ăn vong tâm quả thoát ly giới nội, kết đạo lữ với nữ nhi duy nhất. Bị Vương Lâm cự tuyệt dứt khoát, bị phản vấn về người trọng yếu nhất mà không trả lời được. Thừa nhận giới nội có lực lượng khiến chưởng tôn hoảng sợ bỏ chạy. Tiết lộ tu vi bản thân: hai đạo bổn nguyên (một Không Huyền trung kỳ, một gần Không Kiếp sơ kỳ bị phong ấn, dung hợp đạt Không Huyền đỉnh phong). Giới ngoại không tính viễn cổ bát phi có ít nhất bảy người ngang hắn. Giảng giải tứ cảnh Không bước thứ ba: Không Niết, Không Linh, Không Huyền, Không Kiếp, chưa ai độ kiếp thành công. Chấp nhận cự tuyệt, xóa nhân quả, truyền ba thức: Phiên Thiên Ấn (lật thiên địa), thuật phòng ngự ánh sáng (cảm ngộ Không Linh), thức thứ ba (một trong tam đại đạo thuật, chưa thi triển). Tự nhận thân phận thái cổ tam tôn.","anchor":"Trong lòng ngươi đã quyết, ta cũng không cưỡng cầu nữa"},{"chuong":"@c1244","importance":"normal","mucCt":"ky","tieuDe":"Truyền Dung biến đạo thuật và dung hợp Hô Phong Hoán Vũ","text":"Truyền thức thứ ba Dung biến đạo thuật cho Vương Lâm, biểu diễn biến mây thành băng kiếm bảy thước. Nhận ra Vương Lâm thi triển lục đạo tam trọng thuật của tiên đế Bạch Phàm, nhận xét Bạch Phàm là Chí tôn Lôi giới, thần thông rất khó dung hợp. Biết Vương Lâm cố ý nhờ dung hợp giúp, dung hợp Hô Phong + Vũ đạo thành một giới phòng hộ tương đương Quang ảnh thuẫn. Trước khi rời đi tuyên bố sẵn sàng phản bội Lam Ti tộc và Thái Cổ Tinh Thần nếu giúp nàng khôi phục trí nhớ. Sau đó trên Lam Sơn kinh ngạc vì Vương Lâm bốn tháng đã học xong Phiên Thiên Ấn.","anchor":"chớ nói là Lam Ti tộc, dù là làm phản đồ của Thái Cổ Tinh Thần thì cũng có sao đâu"},{"chuong":"@c1248","importance":"normal","tieuDe":"Bị nghi tiết lộ","text":"Lam Mộng Đạo Tôn vẫn ở trên Lam Sơn vỗ cổ cầm sau khi Vương Lâm rời đi, rồi bị Lan Phi Lâu Lan suy đoán là người đã nói cho Vương Lâm biết chuyện phân thân.","anchor":"Lam Mộng Đạo Tôn ở trên Lam Sơn vẫn còn đang v**t v* cổ cầm"},{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Quang Ảnh Thuẫn được nhận ra","text":"Lam Mộng Đạo Tôn được nhắc qua Quang Ảnh Thuẫn, thần thông phòng hộ mà Vương Lâm dùng để phản chấn lực trùng kích trong trận chiến với đại trưởng lão Thiểm Lôi Tộc.","anchor":"Thần thông hùng mạnh nhất dùng để bảo vệ của Lam Mộng Đạo Tôn"},{"mucCt":"vua","text":"Lam Mộng Đạo Tôn ở cạnh Lý Thiến Mai trên Lam sơn và không tiếp tục đánh đàn. Khi dị động tinh không truyền tới, lão biến sắc, lao lên trời rồi nhìn chằm chằm vào tinh không vô tận.","anchor":"vẻ mặt hắn đột nhiên có biến đổi lớn, cơ thể chợt lóe","bridge":true,"khoang":"@c1275"},{"chuong":"@c1276","importance":"normal","mucCt":"vua","tieuDe":"Dấu hiệu Tiên Phi","text":"Khi dấu hiệu ở Viễn Cổ Tiên Phi lại xuất hiện, Lâm Mộng Đạo Tôn biến sắc âm trầm và nhìn lên bầu trời, cho thấy biến động này chạm tới tầng đại năng của Thái Cổ Tinh Thần.","anchor":"Vẻ mặt Lâm Mộng Đạo Tôn trở nên cực kỳ âm trầm"},{"mucCt":"vua","text":"Tại Lam Sơn của Lam Ti tộc, Lam Mộng Đạo Tôn cảm ứng dị động Không Môn của Vương Lâm và thi pháp hiện ra hình ảnh ba lần công kích. Lão hiếm khi lộ vẻ khiếp sợ, thừa nhận mình đã xem thường một người.","anchor":"Lam Mộng Đạo tôn nhìn chằm chằm vào hình ảnh trên trời, lão cẩn thận nhìn lại","bridge":true,"khoang":"@c1284"},{"mucCt":"gon","anchor":"Thần thông của Lam Mộng Đạo Tôn cực kỳ cường đại","text":"Lam Mộng Đạo Tôn được nhắc qua Đạo thuật Dung mà Vương Lâm dùng để dung hợp một vạn Băng long đan thành thủ đoạn sát thương mới.","bridge":true,"khoang":"@c1289"},{"chuong":"@c1291","importance":"normal","mucCt":"vua","tieuDe":"Phiên thiên được nhận ra","text":"Lam Mộng Đạo Tôn không trực tiếp xuất hiện, nhưng Tư Mặc Tử nhận ra thần thông nghịch chuyển thiên địa của Vương Lâm là Phiên thiên thần thông thuộc Lam Mộng Đạo Tôn. Chi tiết này xác nhận nguồn gốc thần thông mà Vương Lâm dùng để nén Tư Mặc Tử.","anchor":"Phiên thiên thần thông của Lam Mộng Đạo Tôn!"},{"chuong":"@c1293","importance":"bridge","mucCt":"gon","tieuDe":"Được so với đại đế","text":"Lam Mộng Đạo Tôn được Vương Lâm nhắc tới khi cân nhắc sức mạnh của Điên Lạc đại đế.","anchor":"không biết so với Lam Mộng Đạo Tôn thì ra sao"},{"mucCt":"gon","anchor":"Dưới uy áp của Lam Mộng Đạo Tôn Vương Lâm vẫn có thể thừa nhận","text":"Vương Lâm dùng uy áp của Lam Mộng Đạo Tôn làm mốc so sánh khi nhận định pho tượng và thân ảnh áo bảy màu vượt xa cường giả bước thứ ba mà hắn từng biết.","bridge":true,"khoang":"@c1303"},{"chuong":"@c1304","importance":"bridge","mucCt":"gon","tieuDe":"Đạo thuật được nhắc","text":"Được nhắc là nguồn gốc của Đạo thuật Dung mà Vương Lâm thi triển khi dung hợp ma hồn.","anchor":"Đạo thuật Dung của Lam Mộng Đạo Tôn được hắn thi triển ra"},{"chuong":"@c1312","importance":"bridge","mucCt":"gon","tieuDe":"Hiện thân lam quang","text":"Lam Mộng Đạo Tôn xuất hiện trong hình ảnh một đôi phụ tử toàn thân lam quang chiếm một khu vực riêng trên không trường đấu.","anchor":"một chỗ khác là ở gần bọn hắn, một đôi phụ tử toàn thân tràn ngập lam quang!"},{"mucCt":"vua","anchor":"Vãn bối xin ra mắt Lam Mộng đạo tôn tiền bối","text":"Lam Mộng đạo tôn xuất hiện cùng nữ tử trong lam quang và được Vương Lâm cung kính hành lễ. Ông mỉm cười đáp lại, nói trước kia đã xem thường Vương Lâm, khiến lão Chu Tước nhận ra hai người từng quen biết.","bridge":true,"khoang":"@c1313"},{"mucCt":"ky","text":"Lam Mộng đạo tôn quan sát Vương Lâm rồi nhìn con gái bên cạnh, trong lòng nảy sinh phức tạp. Ông cân nhắc trách nhiệm thủ hộ Thái Cổ Tinh Thần, thái độ với Trường Tôn hội và quan hệ giữa Vương Lâm với Nguyệt Nhi. Nghĩ tới Mộng Nhi và thê tử đã trở nên xa lạ sau khi rời đi, ông càng thêm đau đớn và khó xử.","anchor":"Lam Mộng đạo tôn nhìn thoáng qua nữ nhi bên cạnh, ánh mắt lộ ra chút phức tạp","bridge":true,"khoang":"@c1314"},{"mucCt":"vua","text":"Trên Đại Đế tinh, quan sát hai hàng lệ chảy từ thân thể Vương Lâm và giải thích hiện tượng hồn về quê cũ — hồn phách đau buồn khi trở về thân thể sẽ rơi lệ đau đớn.","anchor":"Hồn về quê cũ. hồn phách đau buồn, khi trở về thân thể sẽ có lệ đau đớn rơi xuống","bridge":true,"khoang":"@c1315"},{"chuong":"@c1317","importance":"bridge","mucCt":"gon","tieuDe":"Bị nêu làm ví dụ","text":"Lam Mộng Đạo Tôn được nêu như ví dụ rằng tưởng niệm với thê tử cũng có thể bị hư hỏa biến thành điểm yếu.","anchor":"Thậm chí là tưởng niệm của Lam Mộng đạo tôn với thê tử"},{"mucCt":"vua","text":"Trên Đại đế tinh, Lam Mộng đạo tôn nghe tiếng Chu Tước truyền ra từ cây hương thứ nhất và lập tức nhận ra đó không phải Chu Tước tầm thường. Khí tức dữ tợn, không cam lòng như đến từ địa ngục khiến ông chú ý đến biến hóa bất thường của Vương Lâm trong Nhân phương giới.","anchor":"Tiếng Chu Tước này. Không phải là Chu Tước tầm thường","bridge":true,"khoang":"@c1318"},{"mucCt":"vua","text":"Lam Mộng Đạo Tôn thở dài trước ánh mắt cầu xin của Lý Thiến Mai và hứa sẽ giúp Vương Lâm. Dù vậy, ông vẫn nhận định Vương Lâm có khả năng tự mình vượt qua kiếp này.","anchor":"Ta sẽ giúp hắn, con yên tâm","bridge":true,"khoang":"@c1319"},{"chuong":"@c1320","importance":"normal","mucCt":"vua","tieuDe":"Can thiệp cứu Vương Lâm bị Thiên Nghịch bức lui","text":"Đưa thần thức vào Địa Phương hương cứu Vương Lâm nhưng bị sức mạnh Thiên Nghịch bức khỏi Địa Phương giới. Nhận ra sức mạnh ấy là Thiên Nghịch nhưng không nói ra, sau đó trấn an Lý Thiến Mai rằng Vương Lâm không đáng ngại.","anchor":"Hắn lần này không có đáng ngại"},{"chuong":"@c1322","importance":"bridge","mucCt":"vua","text":"Khi sương mù từ lực thay thế bầu trời, vung tay tỏa lam quang bảo vệ nữ nhi và ngẩng đầu quan sát biến cố.","anchor":"tay phải vung lên, toàn thân tỏa ra lam quang, tràn ngập thân thể nữ nhi của mình"},{"chuong":"@c1323","importance":"bridge","mucCt":"gon","text":"Ánh mắt phức tạp khi chứng kiến biến cố Địa phương hương gãy, sau đó thu hồi ánh mắt và trầm mặc không nói.","anchor":"Ánh mắt Lam Mộng đạo tôn đầy phức tạp, thu hồi ánh mắt, trầm mặc không nói"}],"tuViMoc":[{"chuong":"@c1243","canhGioi":"Không Huyền đỉnh phong (hai đạo bổn nguyên dung hợp)","text":"Tiết lộ tu vi: hai đạo bổn nguyên, một đạo Không Huyền trung kỳ, một đạo gần Không Kiếp sơ kỳ bị phong ấn; dung hợp phát uy lực Không Huyền đỉnh phong. Thân phận thái cổ tam tôn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vương Lâm muốn đưa Lý Thiến Mai tới nhờ cậy","ghiChu":"@c1237"},{"ten":"Nữ tử áo hồng nhạt (Lam Ti tộc)","tag":"ho-hang","quanHe":"Em gái người yêu hắn","ghiChu":"Tới Lam Sơn hỏi thăm, bị hắn phản bác khi nói tỷ tỷ đã chết"},{"ten":"Bạch y nữ tử","tag":"doi-thu","quanHe":"Kẻ bị xua đuổi","ghiChu":"Bạch y nữ tử định vào Lam Ti tinh vực bị hắn chặn, quát đuổi bằng ý cảnh tuyệt sát"},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Đồng cấp ngũ tôn","ghiChu":"Chưởng Tôn kiêng kỵ hắn"},{"ten":"Lý Thiến Mai","tag":"cha-me","quanHe":"Con gái, gọi nàng là Nguyệt nhi / Lam Nguyệt","ghiChu":"Chữa trị hắc khí cho nàng, bảo vệ khỏi Vương Lâm","nguon":"@c1241"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người yêu con gái, từng gây tai ương cho hắn ở Thất Thải Giới","ghiChu":"Không thèm liếc nhưng đặt điều kiện: nếu sau lãng quên mà tìm lại được nhau thì sẽ không ngăn","nguon":"@c1241"},{"ten":"Nữ tử áo trắng","tag":"khac","quanHe":"Bị nghi tiết lộ thông tin","ghiChu":"Nữ tử áo trắng cho rằng Lam Mộng Đạo Tôn đã nói cho Vương Lâm biết chuyện phân thân của nàng."},{"ten":"Lan Phi","tag":"khac","quanHe":"người bị nghi tiết lộ","ghiChu":"Lan Phi Lâu Lan cho rằng Lam Mộng Đạo Tôn đã nói cho Vương Lâm biết chuyện phân thân của nàng."},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"người nhận ra thần thông","ghiChu":"Tư Mặc Tử gọi tên Lam Mộng Đạo Tôn khi thấy Phiên thiên thần thông."},{"ten":"Liêu Thiên Cửu","tag":"dong-minh","quanHe":"Người đi theo","ghiChu":"Liêu Thiên Cửu yên lặng theo sau Lam Mộng Đạo Tôn."},{"ten":"Lý Thiến Mai","tag":"ho-hang","quanHe":"phụ tử đồng hành","ghiChu":"Cùng xuất hiện trong lam quang trước mặt Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1237","@c1240","@c1241","@c1242","@c1243","@c1244","@c1248","@c1270","@c1275","@c1276","@c1284","@c1289","@c1291","@c1293","@c1303","@c1304","@c1305","@c1312","@c1313","@c1314","@c1315","@c1317","@c1318","@c1319","@c1320","@c1322","@c1323"]},{"id":"tien-quan","name":"Tiên Quân","cn":"仙君","aliases":["Chủ nhân Phong Giới","Tông Chủ"],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"khong-ro","nguon":["@c1238"],"tabs":{"kinhLich":[{"chuong":"@c1238","importance":"normal","mucCt":"vua","tieuDe":"Hồi tưởng sứ mệnh và dung nhập Phong Giới","text":"Được hồi tưởng chi tiết: sửa sang Tứ Đại Tiên Giới đối kháng Phong Giới Đại Trận, bị Thủy Đạo Tử đánh lén và Chưởng Tôn liên thủ trọng thương gần tử vong. Nhìn thấy năm đạo bổn nguyên trên người Vương Lâm mà nhận làm truyền nhân, giao sứ mệnh thống lĩnh nội giới chống ngoại giới. Chọn dung nhập vào Phong Giới Đại Trận biến thành vật nội giới.","anchor":"năm đạo bổn nguyên ở trên người Vương Lâm, chủ nhân Phong Giới hiển nhiên là đã nhìn thấy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Người đề tựa bức họa tầng chín Tàng Phẩm Các và an trí cơ duyên Hô phong cho người hữu duyên","chuong":"@c0736"},{"text":"Điều khiển thân thể Vương Lâm dùng tử quang đẩy lui tu sĩ, liên tục cứu người khỏi tầm thôn phệ","chuong":"@c0743"},{"text":"Đưa thân thể Vương Lâm lao đi với tốc độ gần như dung nhập thiên địa","chuong":"@c0744"},{"text":"Hóa điên khi đứng trong hàng ngũ Tu Chân Liên Minh trước thân hình cự nhân khổng lồ","chuong":"@c1012"},{"text":"Sau trận chiến, Phong Điên rồi mất tích không rõ tung tích","chuong":"@c1015"},{"text":"Được hồi tưởng: sửa sang Tứ Đại Tiên Giới đối kháng Phong Giới Đại Trận, bị Thủy Đạo Tử đánh lén","chuong":"@c1238"}]},"vaiTro":"Người đề tựa bức họa Tàng Phẩm Các và an trí cơ duyên Hô phong","tinhCach":"Trọng truyền thừa, chủ động sắp đặt cơ duyên cho người hữu duyên; xả thân cứu độ, điều khiển thân thể người khác để cứu viện; về sau tâm trí bất ổn, hóa điên","blurb":"Tiên Quân, còn được nhắc tới với bí danh Lão giả thần bí, là người đề tựa bức họa tầng chín Tàng Phẩm Các và để lại cơ duyên Hô phong cho người hữu duyên. Sau khi Vương Lâm bị Hô phong chấn vỡ nguyên thần, ông điều khiển thân thể Vương Lâm để cứu viện, đẩy lui tu sĩ và đưa thân thể lao đi với tốc độ gần như dung nhập thiên địa. Về sau, trong hàng ngũ Tu Chân Liên Minh trước cự nhân khổng lồ, ông hóa điên rồi mất tích không rõ tung tích."},{"id":"chuong-ton","name":"Chưởng Tôn","nguon":["@c1238","@c1247","@c1294","@c1303","@c1314"],"tabs":{"kinhLich":[{"chuong":"@c1238","importance":"normal","mucCt":"vua","tieuDe":"Nhắc lại liên thủ trọng thương Chủ nhân Phong Giới","text":"Được nhắc trong hồi tưởng: cùng người Viễn Cổ Tiên Vực liên thủ đánh trọng thương Chủ nhân Phong Giới gần tử vong. Con gái Chưởng Tôn làm tê liệt thần hồn Thanh Lâm.","anchor":"bị Chưởng Tôn cùng với một vài người đến từ viễn cổ tiên vực liên thủ đánh trọng thương, gần như tử vong"},{"importance":"bridge","mucCt":"gon","chuong":"@c1247","tieuDe":"","text":"Qua ký ức lão già tóc bạc, được biết là lão tổ tông Nguyệt Tộc bước thứ ba, từ giới nội trở về bị trọng thương, đang bế quan trị thương ở nơi thần bí.","anchor":"Chưởng Tôn dường như đã bị trọng thương từ trong giới nội trở về, ở một nơi thần bí nào đó bế quan trị thương"},{"chuong":"@c1294","importance":"bridge","mucCt":"vua","tieuDe":"Được nhắc qua pháp bảo","text":"Chưởng tôn được Tư Mặc Tử nhắc tới như người đã ban Thất Thải Thần Không Đinh chuyên giết tu sĩ bước thứ ba.","anchor":"Chưởng tôn ban cho ta Thất Thải Thần Không Đinh chuyên đế giết tu sĩ bước thứ ba"},{"mucCt":"gon","anchor":"Người này là chưởng tôn! Nhưng ý nghĩ này chỉ hiện lên một lát thì hắn liền loại bỏ","text":"Vương Lâm thoáng liên hệ thân ảnh áo bảy màu trong thức hải ngân y nữ tử với Chưởng Tôn, nhưng lập tức loại bỏ vì uy áp pho tượng vượt xa nhận thức của hắn về Chưởng Tôn.","bridge":true,"khoang":"@c1303"},{"chuong":"@c1314","importance":"bridge","mucCt":"vua","text":"Chưởng Tôn được Diệu Âm đạo tôn nhắc là người từng dùng lợi ích lớn để khiến ông ra tay, đồng thời vẫn là sức ép trong suy tính của Lam Mộng đạo tôn với Trường Tôn hội.","anchor":"Năm đó ta sở dĩ ra tay là bởi vì chưởng tôn cho ta lợi ích lớn"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Mặc Tử","tag":"cap-tren","quanHe":"Ban Thất Thải Thần Không Đinh cho Tư Mặc Tử.","ghiChu":"Quan hệ được nhắc qua lời Tư Mặc Tử @c1294"},{"ten":"Trung niên áo bảy màu trong thức hải ngân y nữ tử","tag":"khac","quanHe":"được Vương Lâm thoáng liên hệ rồi bác bỏ","ghiChu":"Chương này không xác nhận Chưởng Tôn và thân ảnh áo bảy màu là một."}],"tuiDo":{},"diem":[{"text":"Tự xưng bản tôn, dùng thần thông bảy màu Thiên Địa Thái Sơ phong ấn giết Chiến Tinh Dã để lấy chiến hồn trong Thiên Đạo Kế.","chuong":"@c1134"},{"text":"Luyện 108 cây Thất Thải Thần Không Đinh, pháp bảo chuyên uy hiếp và giết tu sĩ bước thứ ba.","chuong":"@c1206"},{"text":"Từng cùng người Viễn Cổ Tiên Vực liên thủ đánh trọng thương Chủ nhân Phong Giới gần tử vong.","chuong":"@c1238"},{"text":"Tại Thái Cổ Tinh Thần phát lệnh tuân ý chỉ Viễn Cổ Tiên Vực, triển khai tàn sát Phong Giới.","chuong":"@c1413"},{"text":"Lần đầu dùng bổn tôn bước vào giới nội, nhưng sau đó bị mũi tên xuyên thấu và phải dùng tam mệnh thuật bỏ trốn.","chuong":"@c1561"},{"text":"Bị Vương Lâm lấy nửa hồn, kết cục được khái quát là một đời kiêu hùng nhưng chỉ là nô bộc người điên.","chuong":"@c1680"}]},"gioiTinh":"nam","trangThai":"song","vaiTro":"Lão tổ Nguyệt Tộc, kẻ thù lớn của Vương Lâm","tinhCach":"Mưu tính thâm sâu, bày Thiên Đạo Kế và mai phục Thất Thải Giới; tàn nhẫn quyết đoán, giết Chiến Tinh Dã đoạt chiến hồn; giỏi dụ lợi mua chuộc, lôi kéo người khác ra tay; ngoài mạnh trong yếu, nhiều lần hoảng sợ trước tồn tại vượt tầm","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, từng bị đạo nhân bảy màu thu phục làm sai vặt chiếm cứ giới ngoại. Hắn nhiều đời bố trí Thiên Đạo Kế, luyện Thất Thải Thần Không Đinh, liên thủ trọng thương Chủ nhân Phong Giới và phát động giới ngoại tàn sát Phong Giới theo ý chỉ Viễn Cổ Tiên Vực. Trong các lần đối đầu Vương Lâm, hắn liên tiếp bị phá cục, trọng thương, cuối cùng bị lấy nửa hồn và rơi vào luân hồi nhân quả.","canhGioiCaoNhat":"Không đổi trong @c1314"},{"id":"bach-pham","name":"Bạch Phàm","nguon":["@c1238","@c1244","@c1290"],"tabs":{"kinhLich":[{"chuong":"@c1238","importance":"bridge","mucCt":"gon","text":"Được nhắc trong hồi tưởng kiếp nạn: nổi điên sau khi Chủ nhân Phong Giới bị trọng thương.","anchor":"Bạnh Phàm nổi điên"},{"chuong":"@c1244","importance":"major","mucCt":"gon","text":"Được Lam Mộng Đạo Tôn xác nhận là tiên đế, Chí tôn của Lôi giới, Hô Phong đạo và Vũ đạo thuộc lục đạo tam trọng thuật của hắn.","anchor":"Lục đạo tam trọng thuật của tiên đế Bạch Phàm, đây là Hô Phong đạo"},{"mucCt":"gon","text":"Bạch Phàm được Tư Mặc Tử nhắc đến khi nhận ra Sơn Băng thuật Vương Lâm thi triển là thần thông của hắn.","anchor":"Sơn Băng thuật? Đây là thần thông của Bạch Phàm","bridge":true,"khoang":"@c1290"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Nguồn gốc thần thông","ghiChu":"Vương Lâm thi triển Sơn Băng thuật, được Tư Mặc Tử nhận ra là thần thông của Bạch Phàm."},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Người nhận ra thần thông","ghiChu":"Tư Mặc Tử gọi thẳng Sơn Băng thuật là thần thông của Bạch Phàm."}],"tuiDo":{},"diem":[{"text":"Từng ra tay đánh bại Thanh Thủy khi đồ đệ nhập ma gây sát kiếp.","chuong":"@c0746"},{"text":"Bố trí trận pháp trị thương trên chín phong ấn cho Thanh Thủy.","chuong":"@c0747"},{"text":"Dùng Hô Phong trừng phạt Long Đạo Tử vì phạm tiên điều, đánh tan thân thể và xương cốt.","chuong":"@c0768"},{"text":"Được nhắc là người để lại ba thức thần thông Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh.","chuong":"@c0803"},{"text":"Khi sáng tạo mỗi tiên thuật, dùng thần thông cả đời cúng tế một pháp bảo dung nhập quy tắc thiên đạo.","chuong":"@c1047"},{"text":"Được Lam Mộng Đạo Tôn xác nhận là Tiên Đế, Chí tôn của Lôi giới, nắm Hô Phong đạo và Vũ đạo.","chuong":"@c1244"}]},"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","cn":"白凡","gioiTinh":"nam","tinhCach":"nghiêm minh với tiên điều; trọng tình thầy trò; có chí giáo hóa nhân gian","vaiTro":"Tiên Đế viễn cổ — sư tôn Thanh Thủy, Chí tôn Lôi giới","blurb":"Bạch Phàm là Tiên Đế thời viễn cổ, từng là phản đồ Âm Nguyệt Tông trước khi được xác nhận là Chí tôn của Lôi giới, nắm Hô Phong đạo và Vũ đạo trong lục đạo tam trọng. Ông là sư tôn của Thanh Thủy, để lại hệ tiên thuật gồm Hô Phong, Hoán Vũ và Vãi Đậu Thành Binh; mỗi thuật ẩn chứa pháp bảo được ông dùng thần thông cả đời cúng tế, dung nhập quy tắc thiên đạo. Khi Thanh Thủy nhập ma gây sát kiếp, Bạch Phàm đánh bại và phong ấn đồ đệ, nhưng vì thương hại nên vẫn lưu hồn phách cho hắn."},{"id":"thanh-lam","name":"Thanh Lâm","nguon":["@c1238","@c1243","@c1290","@c1300"],"tabs":{"kinhLich":[{"chuong":"@c1238","importance":"bridge","mucCt":"gon","text":"Được nhắc trong hồi tưởng: bị con gái Chưởng Tôn làm tê liệt thần hồn, rồi bị Cổ Yêu Cổ Ma truy sát.","anchor":"Thanh Lâm bị con gái của Chưởng Tôn làm tê liệt thâm thần, rồi sau đó lại bị Cổ Yêu Cổ Ma truy sát"},{"chuong":"@c1243","importance":"normal","mucCt":"gon","tieuDe":"Tiết lộ từng bị chưởng tôn dụ dỗ tại Vũ giới","text":"Được tiết lộ nhiều năm trước tại Vũ giới cũng từng phải chịu sự hấp dẫn tương tự Vương Lâm, nhưng người dụ dỗ là chưởng tôn.","anchor":"nhiều năm trước, Thanh Lâm tại Vũ giới cũng đã phải chịu sự hấp dẫn vô cùng như thể này"},{"mucCt":"gon","text":"Thanh Lâm được nhắc như người năm đó cũng cảm thấy không bằng trước các hành động tung hoành Thái Cổ Tinh Thần của Vương Lâm.","anchor":"Hết thảy mọi chuyện này cho dù Thanh Lâm năm đó cũng cảm thấy không bằng","bridge":true,"khoang":"@c1290"},{"chuong":"@c1300","importance":"bridge","mucCt":"gon","anchor":"trước pho tượng này thì Thanh Lâm cũng chỉ như một con kiến hôi","text":"Vương Lâm dùng pho tượng Thanh Lâm làm mốc so sánh và cảm nhận uy nghiêm của pho tượng mới vượt xa đến mức Thanh Lâm cũng như kiến hôi trước nó."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được đem ra so sánh","ghiChu":"Chương dùng Thanh Lâm để làm nổi bật khí thế và thành tựu của Vương Lâm."}],"tuiDo":{},"diem":[{"text":"Được xác nhận là Tiên Đế, cường giả đệ nhất Tiên giới và là phụ thân của Thanh Sương.","chuong":"@c0595"},{"text":"Lập Cửu Ấn Trận, thi triển Định Thân Thuật để áp chế thánh tổ Phù Tộc trong động phủ Tiên Đế.","chuong":"@c0968"},{"text":"Hiện thân truyền Quy tắc thân thể cho Vương Lâm trong lúc đối đầu Cổ Ma Tháp Già.","chuong":"@c1047"},{"text":"Thức tỉnh trong trận pháp hồi sinh và khai sinh Tân Vũ Giới.","chuong":"@c1050"},{"text":"Thi triển viễn cổ tiên thuật, dẫn đầu giới nội chống tu sĩ giới ngoại.","chuong":"@c1453"},{"text":"Được xác nhận là phách thứ ba của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri.","chuong":"@c1650"}]},"trangThai":"khong-ro","cn":"青鸾","gioiTinh":"nu","tinhCach":"Che chở đệ tử và giới nội; mưu tính sâu xa; lạnh lùng quyết đoán với kẻ địch; trọng ân nghĩa","vaiTro":"Tiên Đế — phách Thất Thải Tiên Tôn","blurb":"Thanh Lâm là Tiên Đế, từng được xác nhận là cường giả đệ nhất Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy và Hồ Quyên. Sau biến cố Tiên giới, thân thể ông bị Cổ Ma Tháp Già chiếm, rồi nhờ trận pháp hồi sinh mà thức tỉnh, truyền Quy tắc thân thể cho Vương Lâm và khai sinh Tân Vũ Giới. Về sau ông bế quan chữa thương tại Vũ Tiên Giới, nhiều lần ra tay bảo vệ giới nội, tham dự đại chiến giới ngoại, và được xác nhận là một phách của Thất Thải Tiên Tôn."},{"id":"ti-mac-tu","name":"Ti Mặc Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Viễn Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết (bước thứ ba)","trangThai":"song","blurb":"Tu sĩ Không Niết Sơ Kỳ thuộc Viễn Cổ Tinh Thần, một trong ba cao thủ bước thứ ba truy sát Thác Sâm mười năm. Dùng thần thông niệm chú hộ thân khiến Thác Sâm bỏ qua, sau nhận thưởng lục phẩm đạo linh từ nữ tử áo trắng bí ẩn.","vaiTro":"Cao thủ Viễn Cổ Tinh Thần, tham gia truy sát Thác Sâm","tinhCach":[{"text":"Mưu lược, giữ được bình tĩnh dưới áp lực; thực dụng — sẵn sàng nhận thuê để truy sát"}],"tabs":{"diem":[{"text":"Dùng thần thông niệm chú khiến Thác Sâm phải bỏ qua không tấn công, bảo toàn tính mạng trước Cổ Thần","chuong":"@c1239"},{"text":"Thi triển thần thông niệm chú khiến Thác Sâm phải bỏ qua không tấn công hắn khi toái tinh","chuong":"@c1239"},{"text":"Đọc chú đối kháng Thác Sâm nhưng thực chất không muốn bắt, lộ nụ cười quỷ dị cùng lão già Không Linh.","chuong":"@c1239"}],"kinhLich":[{"chuong":"@c1239","importance":"normal","mucCt":"vua","tieuDe":"Truy sát Thác Sâm, lộ mưu đồ riêng","text":"Đọc chú đối kháng Thác Sâm cùng hai cao thủ khác, bị toái tinh tách ra. Sau khi Thác Sâm rời, lộ nụ cười quỷ dị cùng lão già Không Linh. Nhận lục phẩm đạo linh từ nữ tử áo trắng Tiên Vực.","anchor":"Ti Mặc Tử kia là một trung niên, hai mắt lóe lên u quang"},{"mucCt":"vua","text":"Ti Mặc Tử thầm vui khi thấy Vương Lâm lâm vào hiểm cảnh trong Nhân phương giới, vừa cho rằng hắn khó thoát chết vừa tiếc những bí mật trên người hắn. Khi Nhân Phương Hương bất ngờ tắt ngấm, hắn thừ người vì biến cố vượt ngoài dự liệu.","anchor":"Ti Mặc Tử trong chốc lát thừ người ra","bridge":true,"khoang":"@c1319"},{"chuong":"@c1320","importance":"bridge","mucCt":"vua","text":"Chứng kiến lão Chu Tước và Lam Mộng đạo tôn ra tay cứu Vương Lâm nhưng đều bị đánh bật, rung động trước biến cố vượt ngoài dự liệu.","anchor":"hắn hiển nhiên nhìn ra hành động cứu người của người đám Lam Mộng đạo tôn"}],"tuViMoc":[{"chuong":"@c1239","canhGioi":"Không Niết Sơ Kỳ","text":"Không Niết Sơ Kỳ, tu sĩ bước thứ ba.","importance":"minor"}],"nhanMach":[{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát mười năm — cùng hai người khác vây Thác Sâm nhưng không cản nổi"},{"ten":"Lão già cảnh giới Không Linh (Viễn Cổ Tinh Thần)","tag":"dong-hanh","quanHe":"Đồng đội truy sát Thác Sâm"},{"ten":"Nữ tử áo trắng (khí tức Tiên Vực)","tag":"khac","quanHe":"Người thuê/phối hợp — trao lục phẩm đạo linh làm phần thưởng"},{"ten":"Lão già cảnh giới Không Linh (Viễn Cổ Tinh Thần)","tag":"dong-minh","quanHe":"Đồng liêu cùng truy sát Thác Sâm","ghiChu":"Cùng nhận thưởng lục phẩm đạo linh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Lục phẩm đạo linh","moTa":"Nhận từ nữ tử áo trắng Tiên Vực như phần thưởng truy sát Thác Sâm","trangThai":"dang-co","nguon":"@c1239"}]}},"nguon":["@c1239","@c1319","@c1320"]},{"id":"lao-gia-khong-linh-vien-co-tinh-than","name":"Lão già cảnh giới Không Linh (Viễn Cổ Tinh Thần)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Viễn Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Linh (bước thứ ba)","trangThai":"song","blurb":"Tu sĩ cảnh giới Không Linh thuộc Viễn Cổ Tinh Thần, mạnh nhất trong ba cao thủ truy sát Thác Sâm. Sau khi Thác Sâm rời đi, nhận thưởng lục phẩm đạo linh từ nữ tử áo trắng bí ẩn có khí tức Tiên Vực.","vaiTro":"Cao thủ Viễn Cổ Tinh Thần, lãnh đạo nhóm truy sát Thác Sâm","tinhCach":[{"text":"Thận trọng, chịu đựng tốt; có hiểu biết sâu về vương tộc Cổ Thần và thần tính thái cổ"}],"tabs":{"diem":[{"text":"Khi Thác Sâm toái tinh, chịu đựng tốt nhất trong ba người, không bị thương nặng — thể hiện thực lực cảnh giới Không Linh","chuong":"@c1239"},{"text":"Truy sát Thác Sâm mười năm nhưng thực chất không thật sự muốn bắt, lộ nụ cười quỷ dị sau khi Thác Sâm rời đi.","chuong":"@c1239"}],"kinhLich":[{"chuong":"@c1239","importance":"normal","mucCt":"vua","tieuDe":"Lộ mưu đồ trong cuộc truy sát Thác Sâm","text":"Cùng Ti Mặc Tử và nữ tu Không Niết chặn Thác Sâm, bị toái tinh tách ra nhưng không bị thương nặng. Sau khi Thác Sâm rời đi, lộ nụ cười quỷ dị — thực chất không muốn bắt. Nhận lục phẩm đạo linh từ nữ tử áo trắng Tiên Vực. Bàn bạc với Ti Mặc Tử về bí mật vương tộc Cổ Thần, nhắc tới thần tính thái cổ nhưng câu bị ngắt giữa chừng.","anchor":"Vương tộc Cổ Thần trong trời đất này có lẽ chỉ còn hai người này"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát mười năm"},{"ten":"Ti Mặc Tử","tag":"dong-hanh","quanHe":"Đồng đội truy sát Thác Sâm, cùng cấp bậc Viễn Cổ Tinh Thần"},{"ten":"Nữ tử áo trắng (khí tức Tiên Vực)","tag":"khac","quanHe":"Người thuê/phối hợp — trao lục phẩm đạo linh làm phần thưởng"},{"ten":"Ti Mặc Tử","tag":"dong-minh","quanHe":"Đồng đội","ghiChu":"Cùng truy sát Thác Sâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Lục phẩm đạo linh","moTa":"Nhận từ nữ tử áo trắng Tiên Vực như phần thưởng truy sát Thác Sâm","trangThai":"dang-co","nguon":"@c1239"}]}},"nguon":["@c1239"]},{"id":"nu-tu-khong-niet-vien-co-tinh-than","name":"Nữ tử Không Niết (Viễn Cổ Tinh Thần)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Viễn Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết Sơ Kỳ","trangThai":"mat-tich","blurb":"Nữ tu sĩ Không Niết Sơ Kỳ thuộc Viễn Cổ Tinh Thần, một trong ba cao thủ truy sát Thác Sâm. Bị Thác Sâm đánh bại và phong ấn vào tinh điểm.","vaiTro":"Cao thủ Viễn Cổ Tinh Thần, bị Thác Sâm phong ấn","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c1239","importance":"normal","mucCt":"gon","tieuDe":"Bị Thác Sâm phong ấn vào tinh điểm","text":"Một trong ba cao thủ truy sát Thác Sâm, bị đánh phun máu rồi phong ấn vào tinh điểm thứ hai của Thác Sâm.","anchor":"Vương tộc Cổ Thần trong trời đất này có lẽ chỉ còn hai người này"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Bị Thác Sâm đánh bại phong ấn vào tinh điểm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1239"]},{"id":"nu-tu-ao-trang-khi-tuc-tien-vuc","name":"Nữ tử áo trắng (khí tức Tiên Vực)","cn":"","aliases":["Nữ tử áo trắng (khí tức Tiên Vực)"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nữ tử tướng mạo mơ hồ, toàn thân áo trắng, khí tức giống người Tiên Vực. Trao lục phẩm đạo linh cho hai cao thủ Viễn Cổ Tinh Thần như phần thưởng, rồi một mình đi theo hướng Thác Sâm truy đuổi Vương Lâm.","vaiTro":"Nhân vật bí ẩn, nghi là người Tiên Vực, đứng sau vụ truy sát Thác Sâm","tinhCach":[{"text":"Bí ẩn, hành động thong dong vượt qua khoảng cách vô tận, mục đích chưa rõ"}],"tabs":{"diem":[{"text":"Khí tức mơ hồ giống người Tiên Vực — vốn không phải tồn tại trong trời đất này, trao lục phẩm đạo linh cho hai cao thủ như đã hứa trước","chuong":"@c1239"},{"text":"Không có sinh cơ, không phải người, lực lượng kỳ dị khiến ánh mắt xuyên thấu qua nàng","chuong":"@c1242"},{"text":"Bám theo Vương Lâm nhiều ngày từ sau khi gặp Thác Sâm, chỉ dừng ở ranh giới Lam Ti tộc","chuong":"@c1242"},{"text":"Vương Lâm suy đoán nàng là cố kỵ của Lam Mộng Đạo Tôn, lai lịch cực lớn","chuong":"@c1242"}],"kinhLich":[{"chuong":"@c1239","importance":"normal","mucCt":"vua","tieuDe":"Trao đạo linh cho hai cao thủ Viễn Cổ Tinh Thần","text":"Xuất hiện sau trận chiến Thác Sâm với ba cao thủ, tướng mạo mơ hồ, khí tức thuộc Tiên Vực. Trao lục phẩm đạo linh cho lão già Không Linh và Ti Mặc Tử theo giao dịch đã hứa. Sau đó chậm rãi đi theo hướng Thác Sâm truy đuổi.","anchor":"Khi tức mơ hồ lộ ra từ thân thể nữ tử này dường như vốn không phải tồn tại trong trời đất, mà là người của Tiên Vực"},{"mucCt":"ky","text":"Theo Vương Lâm suốt đoạn đường tới bờ tinh vực Lam Ti tộc, định đi vào nhưng bị Lam Mộng Đạo Tôn hiện thân chặn lại quát đuổi. Bình thản nói Vương Lâm đã bị lựa chọn rồi, Lam Mộng Đạo Tôn không bảo vệ được hắn. Bị Lam Mộng Đạo Tôn tấn công bằng ý cảnh tuyệt sát, lui đi, nói hắn sẽ phải đi ra rồi tiêu tan.","anchor":"Hắn đã bị lựa chọn rồi, ngươi không bảo vệ được hắn đâu","bridge":true,"khoang":"@c1240"},{"mucCt":"ky","text":"Tung bay trong tinh không ở biên giới Lam Ti tộc, không có sinh cơ, thần thức không thể phát hiện, mái tóc đen, ánh sáng bao phủ che kín tướng mạo. Đã bám theo Vương Lâm nhiều ngày từ sau khi hắn gặp Thác Sâm, chỉ dừng lại không vào phạm vi Lam Ti tộc. Bị Vương Lâm dùng ánh mắt ác mộng phát hiện, hai người đối mặt yên lặng rồi Vương Lâm rút lui. Sau đó thì thào tự nhủ rằng không ngờ hắn có thể cảm nhận được mình.","anchor":"không ngờ lại không có chút dấu hiệu của sinh cơ","bridge":true,"khoang":"@c1242"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"khac","quanHe":"Mục tiêu theo dõi — đi theo hướng Thác Sâm truy đuổi Vương Lâm"},{"ten":"Ti Mặc Tử","tag":"khac","quanHe":"Trao lục phẩm đạo linh làm phần thưởng"},{"ten":"Lão già cảnh giới Không Linh (Viễn Cổ Tinh Thần)","tag":"khac","quanHe":"Trao lục phẩm đạo linh làm phần thưởng"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị xua đuổi","ghiChu":"Bị Lam Mộng Đạo Tôn chặn ở bờ Lam Ti tinh vực, quát đuổi bằng ý cảnh tuyệt sát"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng theo dõi","ghiChu":"Bám theo Vương Lâm nhiều ngày, bị hắn phát hiện bằng ánh mắt ác mộng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1239","@c1240","@c1242"]},{"id":"lao-gia-toc-bac-nguyet-toc","name":"Lão già tóc bạc Nguyệt Tộc","cn":"","aliases":["Lão già bị Vương Lâm đọc ký ức"],"gioiTinh":"nam","theLuc":[{"ten":"Nguyệt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân đệ tứ suy","trangThai":"khong-ro","blurb":"Lão già tóc bạc là thủ lĩnh chỉ huy trận chiến của Nguyệt Tộc, người phát lệnh mở Phong Thần Đại Trận phong ấn Cổ Thần và liên tiếp triệu ra các chí bảo của tộc để chống địch. Sau khi thân thể sụp đổ và nguyên thần suy yếu, lão bị Vương Lâm dùng Côn Cực Tiên cuốn bắt, bị tra tấn khai thác ký ức và trở thành nguồn để Vương Lâm nắm được lịch sử Nguyệt Phệ Tộc.","vaiTro":"Chỉ huy tối cao Nguyệt Tộc trong trận chiến chống hai Cổ Thần","tinhCach":"Quyết đoán trong chỉ huy chiến trận; kiên cường chịu tra tấn nhưng không giữ nổi bí mật","tabs":{"diem":[{"text":"Phát lệnh mở Phong Thần Đại Trận phong ấn Cổ Thần, liên tiếp triệu ra các chí bảo Nguyệt Tộc rồi thân bại bị bắt","chuong":"@c1239"},{"text":"Nguyên thần bị Vương Lâm lấy ra từ Côn Cực Tiên, bị huyết kiếm xuyên thấu tra tấn suốt mấy canh giờ","chuong":"@c1247"},{"text":"Ký ức bị Vương Lâm tra xét, trở thành nguồn để hắn biết lịch sử Nguyệt Phệ Tộc và Thanh Vân Linh Tộc","chuong":"@c1248"}],"kinhLich":[{"chuong":"@c1239","importance":"major","mucCt":"ky","tieuDe":"Chỉ huy Phong Thần Đại Trận — thân bại bị bắt","text":"Phát lệnh mở Phong Thần Đại Trận phong ấn Cổ Thần, liên tiếp triệu ra các chí bảo Nguyệt Tộc: Vân Thần Diệt Phiến, Huyết Nguyệt Thú, Cổ Thần Cửu Cốt, Hội Thần Dịch, Mắt của Cổ Thần, Cự Linh Chung, Diệt Thế Đệ Cửu Linh. Tuyệt vọng triệu đệ nhất bảo vật — tàn cốt Cổ Thần ngón tay gần cửu tinh. Kêu gọi đồng tộc phá Nguyệt linh hiến tế, thu nhận ấn ký trăng rằm, thỉnh tàn cốt tấn công Thác Sâm. Bành trướng thân thể trăm trượng mô phỏng Cổ Thần cùng chín người khác tấn công nhưng không phải đối thủ. Dưới lực trùng kích từ đốt xương bị chém đôi, thân thể sụp đổ, nguyên thần suy yếu bỏ chạy, bị Vương Lâm dùng Côn Cực Tiên cuốn bắt mang đi.","anchor":"Phong Thần Đại Trận, mở!"},{"importance":"normal","mucCt":"vua","chuong":"@c1247","tieuDe":"Bị tra tấn khai thác ký ức và hủy diệt nguyên thần","text":"Nguyên thần bị Vương Lâm lấy ra từ Côn Cực Tiên, bị huyết kiếm xuyên thấu tra tấn suốt mấy canh giờ hút tinh khí sức sống. Bị dùng thần thức tìm kiếm thần thuật trong ký ức, sau đó bị hủy diệt hoàn toàn. Hồn phách hiện ra trong Hô Phong Hoán Vũ giới, tản ra hương hỏa kinh người.","anchor":"Chỉ là lục tinh Cổ Thần, trước đây Nguyệt Tộc ta đã giết không ít, cho dù ngươi nắm được nguyên thần lão phu, thì có thể làm được gì!"},{"chuong":"@c1248","importance":"normal","tieuDe":"Ký ức bị tra xét","text":"Ký ức của lão già được Vương Lâm tra xét, trở thành nguồn để hắn biết lịch sử Nguyệt Phệ Tộc, Thanh Vân Linh Thuật và điều kiện Linh Chủng.","anchor":"hắn tìm kiếm trong trí nhớ của lão già này"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cổ Thần — địch thủ, cuốn bắt nguyên thần hắn mang đi"},{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Cổ Thần — mục tiêu chính của Phong Thần Đại Trận"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị tra xét ký ức","ghiChu":"Ký ức của lão bị Vương Lâm dùng để truy ra bí mật Nguyệt Phệ Tộc và Thanh Vân Linh Thuật."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1239","@c1247","@c1248"]},{"id":"lao-nhan-tien-di-toc-toc-bac","name":"Lão nhân Tiên Di tộc tóc bạc","nguon":["@c1239"],"tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Cùng hơn trăm tộc nhân xuất hiện, cung kính gọi Vương Lâm là Thượng tiên và nhận ra Tử Mẫu Đạo Khô","chuong":"@c0755"},{"text":"Dẫn Vương Lâm tới nơi cư trú bộ tộc, giải thích trận pháp tiên vương và kể lại tai họa Vụ thú","chuong":"@c0756"},{"text":"Chỉ huy ứng chiến khi sương đen và Vụ thú ập đến, xin Vương Lâm tha cho Tháp Sơn","chuong":"@c0757"},{"text":"Bắt quyết dùng ký hiệu để đối phó hắc khí khi Tháp Sơn dẫn Vương Lâm xuống phía dưới","chuong":"@c0759"},{"text":"Đại diện Tiên Tuyển Tộc xin Vương Lâm cho một tu chân tinh để tộc nhân dung thân tại La Thiên","chuong":"@c0770"},{"text":"Đánh ấn quyết kích hoạt Sơn Hà Đồ từ lòng đất tu chân tinh, triển khai phòng tuyến bảo vệ Liên Minh","chuong":"@c1457"}]},"vaiTro":"Tổ tiên tộc Tiên Di-Tiên Tuyển — đại diện bộ tộc tiếp đón và quy phục Vương Lâm","tinhCach":"cung kính trước cường giả; thận trọng trước hiểm nguy; tận tụy bảo hộ tộc nhân; quyết đoán khi lâm trận","blurb":"Lão nhân tóc bạc là tiên tổ của tộc Tiên Di-Tiên Tuyển, người đại diện bộ tộc tiếp xúc với Vương Lâm — cung kính gọi hắn là Thượng tiên khi nhận ra Tử Mẫu Đạo Khô. Ông dẫn dắt tộc nhân qua tai họa Vụ thú, thuật lại trận pháp tiên vương, sau đó xin cho bộ tộc dung thân tại một tu chân tinh thuộc La Thiên. Về sau, khi Liên Minh lâm nguy, lão nhân đánh ấn quyết kích hoạt Sơn Hà Đồ từ lòng đất tu chân tinh để bảo vệ thế lực này."},{"id":"nu-tu-ao-hong-nhat-lam-ti-toc","name":"Nữ tử áo hồng nhạt (Lam Ti tộc)","gioiTinh":"nu","trangThai":"song","theLuc":[{"ten":"Lam Ti tộc","trangThai":"gan-bo"}],"blurb":"Em gái của người yêu Lam Mộng Đạo Tôn, tộc nhân Lam Ti tộc. Tới Lam Sơn hỏi Lam Mộng Đạo Tôn sao vẫn chưa quên, bị phản bác khi nói tỷ tỷ đã chết.","vaiTro":"Tộc nhân Lam Ti tộc, em gái người yêu Lam Mộng Đạo Tôn","tinhCach":"Quan tâm tỷ tỷ và Lam Mộng Đạo Tôn; đa cảm, dễ rơi lệ","tabs":{"diem":[{"text":"Em gái người yêu Lam Mộng Đạo Tôn, tới Lam Sơn khuyên hắn buông bỏ nhưng bị phản bác.","chuong":"@c1240"}],"kinhLich":[{"mucCt":"vua","text":"Tới gian phòng trên Lam Sơn hỏi Lam Mộng Đạo Tôn sao vẫn chưa quên tỷ tỷ, nói tỷ tỷ đã chết rồi. Bị Lam Mộng Đạo Tôn khẳng định tỷ tỷ chưa chết, nàng rơi lệ.","anchor":"Tỷ tỷ của muội chưa chết, nàng không chết","bridge":true,"khoang":"@c1240"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"ho-hang","quanHe":"Người yêu tỷ tỷ","ghiChu":"Tới Lam Sơn hỏi thăm hắn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1240"]},{"id":"lao-gia-toc-bac","name":"Lão giả tóc bạc","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1240","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm dùng Côn Cực Tiên hóa phong ấn phong bế toàn thân, thu vào không gian trữ vật.","anchor":"lão giả tóc bạc đang bị Côn Cực tiên trói chặt cũng bị Vương Lâm lấy Côn Cực tiên hóa thành phong ấn"}],"diem":[{"text":"Theo dõi Vương Lâm bị nhốt trong thông đạo tại Lôi Tiên Giới,ưu tiên thu hồn tiên sơn thay vì truy đuổi","chuong":"@c0696"},{"text":"Kích hoạt Trận pháp thứ chín Linh Khai Thiên Phủ trong sự kiện Phong Giới","chuong":"@c0884"},{"text":"Thôn phệ thất bại, nhận ra dấu hiệu Ngũ Tinh Vương Tộc Cổ Thần trên mi tâm Vương Lâm","chuong":"@c0885"},{"text":"Cầu xin Phong Giới Chi Tôn tha mạng, bị Nghịch Thiên Châu rút dấu ấn trăng lưỡi liềm","chuong":"@c0886"},{"text":"Phá ấn xuất thế tại tinh cầu phía bắc Liên Minh Tinh Vực, tiếp tục nhắm Vương Lâm","chuong":"@c1040"},{"text":"Bị Vương Lâm dùng Côn Cực Tiên hóa phong ấn phong bế toàn thân, thu vào không gian trữ vật","chuong":"@c1240"}]},"nguon":["@c1240"],"vaiTro":"Lão giả bí ẩn Nguyệt Phệ tộc, kẻ đối đầu Vương Lâm qua nhiều tiên giới","tinhCach":"thận trọng, quan sát kỹ trước khi ra tay; thực dụng, ưu tiên thu hồn tiên sơn; nghiêm khắc với đệ tử; biết cầu xin tha mạng khi thất thế","blurb":"Lão giả tóc bạc là nhân vật thần bí thuộc Nguyệt Phệ tộc, lần đầu xuất hiện tại Lôi Tiên Giới nơi lão theo dõi Vương Lâm bị nhốt trong thông đạo. Về sau lão hiện thân trong sự kiện Phong Giới, kích hoạt Trận pháp thứ chín Linh Khai Thiên Phủ nhưng thôn phệ thất bại và bị Nghịch Thiên Châu rút dấu ấn. Cuối cùng lão phá ấn xuất thế tại tinh cầu phía bắc Liên Minh Tinh Vực, tiếp tục nhắm vào Vương Lâm nhưng bị Lưu Nguyệt lật 5000 năm ký ức rồi bị Vương Lâm phong ấn toàn thân."},{"id":"nu-tu-ao-hong-lam-son","name":"Nữ tử áo hồng (Lam Sơn)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Lam Ti tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Nữ tử áo hồng ngồi trước phòng trên Lam Sơn thổi địch, vào phòng báo Lam Mộng Đạo Tôn rằng Vương Lâm sắp lên tới đỉnh. Danh tính chưa rõ.","vaiTro":"Người trên Lam Sơn, có thể là thân thuộc hoặc người hầu của Lam Mộng Đạo Tôn","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"text":"Ngồi trước phòng thổi địch trên Lam Sơn, vào phòng báo Lam Mộng Đạo Tôn rằng Vương Lâm sắp tới đỉnh.","anchor":"Phụ thân muốn ta tới nói với người, tên của ta là Lam Nguyệt, ngươi là ai?","mucCt":"gon","bridge":true,"khoang":"@c1241"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"cha-me","quanHe":"Có thể là con hoặc thân thuộc, ở cùng trên Lam Sơn","ghiChu":"Chương chưa nói rõ danh tính","nguon":"@c1241"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1241"]},{"id":"nguyet-nhi-lam-mong","name":"Nguyệt Nhi","cn":"","aliases":[],"gioiTinh":"nu","vaiTro":"Nữ nhi duy nhất của Lam Mộng Đạo Tôn, đối tượng điều kiện kết đạo lữ với Vương Lâm","tinhCach":"Chưa rõ","blurb":"Nữ nhi duy nhất của Lam Mộng Đạo Tôn. Được cha đưa ra làm điều kiện kết đạo lữ với Vương Lâm, bị Vương Lâm cự tuyệt.","theLuc":[{"ten":"Lam Ti tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1314","trangThai":"song","tabs":{"diem":[{"text":"Nữ nhi duy nhất của thái cổ tam tôn Lam Mộng Đạo Tôn, được cha dùng làm điều kiện kết đạo lữ chiêu mộ Vương Lâm","chuong":"@c1243"}],"kinhLich":[{"chuong":"@c1243","importance":"normal","mucCt":"gon","tieuDe":"Lam Mộng yêu cầu đưa Nguyệt Nhi tới xóa nhân quả","text":"Lam Mộng Đạo Tôn yêu cầu Vương Lâm đưa Nguyệt Nhi tới, đồng thời là đối tượng điều kiện kết đạo lữ bị Vương Lâm cự tuyệt.","anchor":"Ngươi đưa Nguyệt Nhi tới đây"},{"chuong":"@c1314","importance":"bridge","mucCt":"vua","text":"Quan hệ giữa Nguyệt Nhi và Vương Lâm được Lam Mộng đạo tôn nhớ tới, khiến lựa chọn của ông trước áp lực Trường Tôn hội thêm dao động.","anchor":"Nhưng người này với Nguyệt Nhi"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"cha-me","quanHe":"Phụ thân","ghiChu":"Lam Mộng là cha, đưa nàng làm điều kiện chiêu mộ Vương Lâm"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng kết đạo lữ (bị cự tuyệt)","ghiChu":"Lam Mộng muốn gả cho Vương Lâm, bị từ chối"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1243","@c1314"]},{"id":"bon-thai-to-truong-lao-vo-cuc-tong","name":"Bốn thái tổ trưởng lão Vô Cực Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Vô Cực Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi rất cao thâm)","trangThai":"song","blurb":"Bốn cường giả tu vi rất cao thâm của Vô Cực Tông, cuối chương 1217 mới xuất trận tấn công Vương Lâm khi hắn đoạt pháp khí Cổ Thần.","vaiTro":"Thái tổ trưởng lão Vô Cực Tông","tinhCach":[{"text":"Hành động dứt khoát, không nhiều lời, trực tiếp thi triển thần thông"}],"tabs":{"diem":[{"text":"Bốn cường giả tu vi rất cao thâm của Vô Cực Tông, xuất trận cuối cùng khi sáu cường giả ban đầu không ngăn nổi Vương Lâm.","chuong":"@c1217"}],"kinhLich":[{"chuong":"@c1217","importance":"normal","mucCt":"gon","tieuDe":"Xuất trận ngăn Vương Lâm đoạt pháp khí","text":"Từ xa tới gần, không nói nhiều lời mà trực tiếp thi triển thần thông tấn công Vương Lâm đang đoạt pháp khí Cổ Thần.","anchor":"bốn thái tổ trưởng lão của Vô Cực Tông, tu vi rất cao thâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ xâm nhập sơn môn đoạt pháp khí","ghiChu":"@c1217"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1217"]},{"id":"truong-lao-yeu-tong-toc-bac","name":"Trưởng lão Yêu Tông (lão già tóc bạc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Yêu Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhị Suy","trangThai":"song","blurb":"Trưởng lão Yêu Tông tu vi Thiên Nhân Đệ Nhị Suy, sư phụ của Lý Thiến Mai, giao đấu với Vương Lâm bại trận và bị âm thầm thi triển đạo thuật phá đạo niệm.","vaiTro":"Trưởng lão Yêu Tông, sư phụ Lý Thiến Mai","tinhCach":[{"text":"Can đảm dám chặn đường thử sức, nhưng biết tiến lùi, thua trận liền xin dừng tay và chủ động hòa giải."}],"tabs":{"diem":[{"text":"Tu vi Thiên Nhân Đệ Nhị Suy, thi triển Dịch Linh Ấn hoàn chỉnh năm ký hiệu nhưng vẫn bại trước Vương Lâm.","chuong":"@c1222"},{"text":"Năm xưa thu nhận Lý Thiến Mai làm môn hạ vì yêu mến tài năng, và đồng ý cho cô rời đi.","chuong":"@c1222"},{"text":"Bị Vương Lâm âm thầm thi triển đạo thuật xâm nhập đạo niệm mà không hay biết cho đến khi tự kiểm tra, kinh hãi nhận ra trên thân Vương Lâm còn phong ấn chưa mở.","chuong":"@c1222"}],"kinhLich":[{"chuong":"@c1222","importance":"normal","mucCt":"ky","tieuDe":"Giao đấu Vương Lâm, bại trận bị thi triển đạo thuật","text":"Từ tu chân tinh dịch chuyển ba bước qua tinh không đến chặn Vương Lâm trước khe nứt, đòi thử thực lực. Đối chưởng rồi dùng pháp bảo mai rùa phòng ngự nhưng bị huyết kiếm chém nát. Thi triển Dịch Linh Ấn hoàn chỉnh (năm ký hiệu: Thần, Hoàng, Đấu, Tiên, Oanh) nhưng bị Vương Lâm hóa toàn thân thành huyết kiếm phá hủy, song chỉ điểm trán đánh bay ra khỏi khe nứt phun máu. Hoảng sợ xin dừng khi thấy Vương Lâm dường như muốn mở phong ấn. Tự giới thiệu là sư phụ năm xưa thu nhận Lý Thiến Mai, tặng ngọc giản bản đồ khe nứt. Sau đó kiểm tra phát hiện đạo niệm bị ngoại lực xâm nhập — đạo thuật Vương Lâm âm thầm thi triển. Lập tức trở về sơn môn bế quan.","anchor":"tu vi Thiên Nhân Đệ Nhị Suy của ta đối kháng với hắn cũng không thể nắm chắc phần thắng"}],"tuViMoc":[{"chuong":"@c1222","canhGioi":"Thiên Nhân Đệ Nhị Suy","text":"Tự nhận tu vi ở cảnh giới Thiên Nhân Đệ Nhị Suy.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giao đấu","ghiChu":"Giao đấu bại trận, bị đạo thuật xâm nhập đạo niệm; được Vương Lâm cảnh báo cách chữa."},{"ten":"Lý Thiến Mai","tag":"su-mon","quanHe":"Sư phụ — đồ đệ","ghiChu":"Năm xưa yêu mến tài năng thu nhận Lý Thiến Mai, đồng ý cho cô rời đi."}],"tuiDo":{"phapBao":[{"ten":"Mai rùa","trangThai":"hong","moTa":"Pháp bảo phòng ngự, bị huyết kiếm Vương Lâm chém nứt rồi tan vỡ.","nguon":"@c1222"}]}},"nguon":["@c1222"]},{"id":"lao-gia-toc-bac-ao-den-nguyet-toc","name":"Lão già tóc bạc áo đen (Nguyệt Tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Nguyệt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (bước thứ ba hoặc tương đương)","trangThai":"khong-ro","blurb":"Lão già tóc bạc áo đen là trưởng bối có thân phận cao nhất trong Nguyệt Tộc, người đứng ra chỉ huy toàn bộ kế hoạch phong ấn Cổ Thần.Ông phát lệnh mở Phong Thần Đại Trận bằng mười vạn tộc nhân và triệu bảy chí bảo nhằm phong ấn cả Thác Sâm lẫn Vương Lâm. Kế hoạch cuối cùng thất bại, thân thể sụp đổ và nguyên thần bị Vương Lâm bắt mang đi.","vaiTro":"Trưởng bối thân phận cao nhất Nguyệt Tộc, chỉ huy kế hoạch phong ấn Cổ Thần","tinhCach":"quyết đoán, sẵn sàng hiến tế để đạt mục tiêu; đặt đại cục tộc lên trên sinh mệnh cá nhân","tabs":{"diem":[{"text":"Phát lệnh mở Phong Thần Đại Trận bằng mười vạn tộc nhân để phong ấn cả Thác Sâm lẫn Vương Lâm","chuong":"@c1239"},{"text":"Triệu bảy chí bảo phục vụ cho kế hoạch phong ấn Cổ Thần","chuong":"@c1239"},{"text":"Phong ấn Cổ Thần thất bại, thân thể sụp đổ và bị Vương Lâm bắt lấy nguyên thần","chuong":"@c1239"}],"kinhLich":[{"chuong":"@c1239","importance":"major","mucCt":"ky","tieuDe":"Phong ấn Cổ Thần thất bại, bị bắt nguyên thần","text":"Phát lệnh mở Phong Thần Đại Trận bằng mười vạn tộc nhân phong ấn cả Thác Sâm lẫn Vương Lâm. Lần lượt triệu bảy chí bảo: Vân Thần Diệt Phiến, Đại Nguyệt Diệt Thần thuật, Huyết Nguyệt Thú, Cổ Thần Cửu Cốt, Hội Thần Dịch, mắt Cổ Thần, Cự Linh Chung và Diệt Thế Đệ Cửu Linh. Triệu đệ nhất bảo vật Nguyệt Tộc — đốt xương Cổ Thần cửu tinh — đánh trọng thương cả hai Cổ Thần. Bị thần thông Hư xuyên phá, trận pháp sụp đổ. Bị Thác Sâm đánh trọng thương, kêu gọi đồng tộc hiến tế Nguyệt linh, thu ấn ký trăng rằm triệu hồi tàn cốt tấn công Thác Sâm. Lực trùng kích từ đốt xương vỡ khiến thân thể sụp đổ, nguyên thần suy yếu bỏ chạy nhưng bị Côn Cực Tiên Vương Lâm cuốn bắt mang đi.","anchor":"Một thanh âm già nua toán ra một vẻ điên cuồng cùng với sự hưng phấn, còn lộ ra một sự sợ hãi không thể che dấu"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cổ Thần mà Nguyệt Tộc muốn phong ấn, sau đó bắt nguyên thần lão"},{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Cổ Thần mà Nguyệt Tộc chờ mười năm để phong ấn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1239"]},{"id":"thu-dao","name":"Thu Dao","cn":"秋道","gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1244","importance":"bridge","mucCt":"gon","text":"Được Lam Mộng Đạo Tôn gián tiếp nhắc đến — việc khiến nàng khôi phục trí nhớ là động lực để hắn sẵn sàng làm phản đồ.","anchor":"Nếu có thể khiến cho nàng khôi phục trí nhớ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Hiện thân dưới Tiên Trì từ lốc xoáy với tổ phù đỏ máu và sát khí ngợp trời","chuong":"@c0964"},{"text":"Dù bị phong ấn vô số năm vẫn điều khiển biển máu và sát khí uy hiếp mọi người","chuong":"@c0965"},{"text":"Được xác định là thánh tổ của Phù Tộc, hiện trong động phủ Tiên Đế với dung nhan thê lương, hai hốc mắt trống","chuong":"@c0967"},{"text":"Chống lại phong áp của Thanh Lâm, dùng tiếng chất vấn tạo sóng âm phá hư không","chuong":"@c0968"},{"text":"Tự thuật vì lời hứa của Thanh Lâm mà phản bội Phù Tộc, dâng hai mắt chứa Thái Sơ Lực rồi bị phong ấn","chuong":"@c0969"},{"text":"Bị Thanh Lâm vạch trần là Phù Phi, phân thân của Thánh tổ Phù Tộc và con gái Chưởng Tôn","chuong":"@c0970"}]},"nguon":["@c1244"],"vaiTro":"Thánh tổ Phù Tộc — nữ tử bị Thanh Lâm phong ấn dưới Tiên Trì","tinhCach":"Oán hận sâu sắc kẻ đã lừa dối và phong ấn mình; kiên cường chống lại phong áp dù bị trấn áp vô số năm; từng trọng lời hứa đến mức phản bội tộc nhân","blurb":"Thu Dao là thánh tổ của Phù Tộc, hiện thân dưới Tiên Trì dưới hình dạng nữ tử mờ ảo với hai hốc mắt trống rỗng, bị Thanh Lâm phong ấn qua vô số năm. Nàng điều khiển biển máu, sát khí cùng tổ phù đỏ máu để uy hiếp quần hùng, tự thuật vì lời hứa của Thanh Lâm mà phản bội Phù Tộc, dâng hai mắt chứa Thái Sơ Lực rồi bị phong ấn. Về sau nàng bị Thanh Lâm vạch trần là Phù Phi, phân thân của Thánh tổ Phù Tộc và con gái Chưởng Tôn."},{"id":"lan-phi","name":"Lan Phi","cn":"蘭妃","aliases":["Nữ tử áo trắng","Bạch Y Nữ Tử","Lâu Lan","Viễn Cổ Bát Phi","Lan Phi Lâu Lan"],"gioiTinh":"nu","theLuc":[{"ten":"Viễn Cổ Tiên Vực","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Viễn Cổ Bát Phi — phân thân truy đuổi Vương Lâm để hấp thu thần tính Cổ Thần","tinhCach":"Kiên nhẫn, nhiều lần chặn lộ tuyến chờ thời cơ ra tay; Quyết đoán, hành động dứt khoát khi tiếp cận mục tiêu","blurb":"Nữ tử áo trắng tự xưng Lan Phi, Lâu Lan, Viễn Cổ Bát Phi. Phân thân của nàng nhiều lần chặn lộ tuyến Súc Địa Thành Thốn của Vương Lâm trong tinh không Thái Cổ Tinh Thần nhằm hấp thu thần tính Cổ Thần trên mi tâm hắn. Khi bị Vương Lâm phản kích, ngón tay triệu hồi bổn tôn bị huyết kiếm chém đứt, ngọc bội vỡ tan, phải phun máu bỏ chạy và bị truy sát; dung nhan hiện rõ trùng khớp Lý Mộ Uyển, mối liên hệ chưa rõ.","tabs":{"diem":[{"text":"Nhiều lần chặn lộ tuyến Súc Địa Thành Thốn của Vương Lâm, phá gợn sóng truyền tống và tạo lốc để hút thần tính","chuong":"@c1248"},{"text":"Ngón tay triệu hồi bổn tôn bị huyết kiếm Vương Lâm chém đứt, ngọc bội vỡ tan, phun máu bỏ chạy và bị truy sát","chuong":"@c1250"}],"kinhLich":[{"chuong":"@c1248","importance":"major","tieuDe":"Lộ danh hút thần tính","text":"Lan Phi Lâu Lan nhiều lần chặn lộ tuyến Súc Địa Thành Thốn của Vương Lâm, phá gợn sóng truyền tống và tạo lốc xoáy khiến Thuấn Di mất tác dụng. Nàng tự xưng là Lan Phi Lâu Lan thuộc Viễn Cổ Bát Phi, dùng dung mạo giống Lý Mộ Uyển làm Vương Lâm hoảng hốt để hút khói vàng thần tính từ tinh điểm Cổ Thần. Sau khi Vương Lâm phản kích, nàng bị hắn chỉ ra thân hiện tại chỉ là phân thân chứ không phải bản thể.","anchor":"Ta vốn không định hấp thu thần tính của ngươi bây giờ"},{"mucCt":"ky","text":"Ngón tay triệu hồi bổn tôn bị huyết kiếm Vương Lâm chém đứt, ngọc bội vỡ tan, phun máu bỏ chạy. Bị truy sát liên tục trong Thái Cổ Tinh Thần, dung nhập thiên địa di chuyển nhưng số lần có hạn. Bị Phiên Thiên Ấn đánh trúng rồi huyết kiếm xuyên hậu tâm, lúc bị thương nặng không gian quanh thân hiện hình ảnh cảnh quỳ trước cánh tay trắng nõn đặt lên mi tâm, hé lộ nguồn gốc sức mạnh phân thân. Từ thiên linh phóng ra lực hương hỏa môn đồ cực nồng đậm vượt ba thành Hô Phong Hoán Vũ giới, bên trong có tia sáng vàng. Chạy tới tinh vực Ma Hạt Tộc, bị huyết kiếm đâm vai phải mất khả năng cử động tay, cắn lưỡi phun máu tạo xung kích thoát thân. Tự xưng là một trong những phân thân của Lan Phi, sai Ma Hạt Tộc dùng mạng ngăn cản, nuốt đan dược biến mất. Cuối chương bị quyền Cổ Thần ngàn trượng bức hiện hình.","anchor":"Ma Hạt Tộc ở đâu, ta là một trong những phân thân của Lan phi. Các người mau dùng tính mạng ngăn cản người này.","bridge":true,"khoang":"@c1250"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu hấp thu thần tính Cổ Thần, truy đuổi trong tinh không","ghiChu":"Vương Lâm giả hoảng hốt dụ nàng lộ mục đích rồi phản kích"},{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Nghi ngờ Lam Mộng Đạo Tôn tiết lộ cho Vương Lâm biết nàng là phân thân","ghiChu":""},{"ten":"Lý Mộ Uyển","tag":"khac","quanHe":"Dung mạo trùng khớp, mối liên hệ chưa rõ","ghiChu":"Chưa xác nhận Lan Phi có phải Lý Mộ Uyển hay chỉ mượn dung mạo"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1248","@c1250"],"canhGioiCaoNhat":"khong-ro"},{"id":"nu-tu-ao-trang","name":"Nữ tử áo trắng","aliases":["Bạch Y Nữ Tử","Lan Phi","Lâu Lan","Viễn Cổ Bát Phi","Lan Phi Lâu Lan","Viễn cổ tiên phi"],"gioiTinh":"nu","canhGioiCaoNhat":"Thiên Nhân Tam Suy (phân thân)","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1248","importance":"normal","tieuDe":"Chặn đường hút thần tính","text":"Nữ tử áo trắng theo dấu các lần dịch chuyển của Vương Lâm, cắt gợn sóng Súc Địa Thành Thốn, tạo lốc xoáy phong tỏa Thuấn Di và dùng bàn tay ánh ngọc khống chế hắn. Nàng tự xưng Lan Phi, Lâu Lan, để lộ dung mạo giống Lý Mộ Uyển và ý định hấp thu thần tính Cổ Thần của Vương Lâm, nhưng bị hắn phản chế rồi nhìn ra đây chỉ là phân thân.","anchor":"Ta vốn không định hấp thu thần tính của ngươi bây giờ"},{"mucCt":"ky","text":"Bị Vương Lâm phân tích là chỉ là hình chiếu phân thân tu vi thiên nhân tam suy, không phải thực thể cũng không phải tu sĩ Đệ Tam Bộ. Phun ngọc bội phòng hộ chống Phiên Thiên Ấn, thi triển Thiên Linh Quang phản kích chiến hồn nhưng không gây thương tổn, ngưng hắc quang thành trường kiếm đen tấn công nhưng bị Quang Ảnh Thuẫn chiết xạ ngược. Ngọc bội bị huyết kiếm đánh nứt, phun máu tươi bỏ chạy (phân thân có máu khiến Vương Lâm ngạc nhiên). Tuyệt vọng kêu cứu bổn tôn, từ ngọc bội hiện ra cánh tay bổn tôn uy lực kinh thiên ấn ngón tay xuống, xuyên phá Quang Ảnh Thuẫn và đang đối kháng Hô Phong Hoán Vũ giới.","anchor":"Chỉ là một phân thân, tu vi mới tới thiên nhân tam suy, cũng dám theo sau ta có mưu đồ","bridge":true,"khoang":"@c1249"},{"chuong":"@c1251","importance":"normal","mucCt":"ky","tieuDe":"Tử vong — hồn phách và hương hỏa bị Vương Lâm đoạt","text":"Mi tâm xuất hiện ấn ký hình chữ ‘xuyên’ phát ba đạo ánh sáng đỏ, vàng, lam, kích hoạt ký ức bị phong ấn: từng được chọn làm thánh nữ bộ tộc, bị xóa tộc ấn biến thành phân thân nuôi dưỡng hình chiếu và cánh cửa hương hỏa. Dùng khí tức trắng sữa và lần na di cuối cùng thoát tới phía đông Thái Cổ Tinh Thần, thân thể dần trong suốt sắp biến mất. Bị Vương Lâm thi triển Định Thần Thuật đóng băng, kéo ra khỏi hư vô. Khí tức trong thân tự hủy nhưng bị huyết kiếm đâm thiên linh phá nguyên thần trước. Tử vong, hồn phách nhập Hô Phong Hoán Vũ giới, hương hỏa bị đoạt. Trong thi thể xuất hiện kim tuyến phân thân Lan Phi.","anchor":"Từ nay về sau, ngươi là một trong những phân thân của ta, dùng thân thể ngươi nuôi dưỡng hình chiếu phân thân của ta"},{"chuong":"@c1271","importance":"normal","mucCt":"gon","tieuDe":"Được nhắc qua hương hỏa","text":"Khi Vương Lâm rút hương hỏa từ các hồn phách trong Hô Phong Hoán Vũ, lực lượng của bạch y nữ tử viễn cổ tiên phi được nhắc như mức vượt xa linh hồn tu vi cao thâm thông thường.","anchor":"Đặc biệt la những linh hồn tu vi cao thâm, lực lượng hương hỏa lại càng cuồn cuộn như sóng dữ, nhưng nếu so sánh với bạch y nữ tử là viễn cổ tiên phi thì vẫn không thể nào bằng."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trực tiếp","ghiChu":"Nàng chặn đường, phong tỏa Thuấn Di, khống chế và định hấp thu thần tính Cổ Thần của hắn, nhưng bị hắn phản chế."},{"ten":"Lý Mộ Uyển","tag":"khac","quanHe":"Dung mạo giống hệt","ghiChu":"Dung mạo nàng hiện ra giống Lý Mộ Uyển, khiến Vương Lâm chấn động trong khoảnh khắc."},{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Người bị nàng nghi biết chuyện phân thân","ghiChu":"Nàng suy đoán Lam Mộng Đạo Tôn đã nói cho Vương Lâm biết việc nàng chỉ là phân thân."},{"ten":"Vương Lâm","tag":"khac","quanHe":"liên quan hương hỏa trong Hô Phong Hoán Vũ","ghiChu":"Lực lượng hương hỏa của nàng được nhắc khi so sánh với các hồn phách mà Vương Lâm rút lực lượng trong thuật Hô Phong Hoán Vũ."}],"tuiDo":{},"diem":[{"text":"Bước ra từ đại điện Tiên phủ, chỉ một ánh mắt đã khiến nhóm Vương Lâm kinh hãi; dùng kỳ hương, rừng hoa, Táng hoa và quang đoàn chứa bổn nguyên lực áp chế Vương Lâm","chuong":"@c0947"},{"text":"Tự xưng Hoa Phi Hàm Yên, một trong tiên đế bát phi, xác nhận Vương Lâm vượt khảo nghiệm; có liên hệ với Thanh Sương và bí mật của Tiên Đế Thanh Lâm về Thu Dao","chuong":"@c0949"},{"text":"Hiện thân trên vùng đất Yêu Linh, thu cung điện vào hoa hồng, đối kháng Cổ Ma Tháp Già cùng phe Chu Tước Thánh tông để bảo hộ Vương Lâm","chuong":"@c1001"},{"text":"Bị Vương Lâm phân tích là hình chiếu phân thân tu vi thiên nhân tam suy; mi tâm kích hoạt ký ức bị phong ấn, hồn phách và hương hỏa bị Vương Lâm đoạt","chuong":"@c1251"},{"text":"Trong cổ mộ sở hữu đài mộ và bí thuật hấp thu ký hiệu, bị trọng thương gần tuyệt vọng rồi được Vương Lâm dùng thần thức cứu thoát","chuong":"@c1383"},{"text":"Tiết lộ bí mật ba hồn bảy phách, đề nghị hợp tác với Vương Lâm; sau đó chỉ huy truy sát trong Đan Hải bằng la bàn giám sát","chuong":"@c1600"}]},"nguon":["@c1249","@c1251","@c1248","@c1271"],"cn":"白衣女子","tinhCach":"Uy áp tuyệt đối, chỉ bằng ánh mắt hoặc đứng yên đã khiến vạn vật tới gần tự diệt; hành sự lạnh lùng bình tĩnh, trầm mặc quan sát trước khi ra tay; kiên trì truy đuổi, theo dấu từng lần dịch chuyển của đối thủ để chặn đường; quyết đoán khi tiến lui, biết bỏ tranh đoạt lúc bất lợi và chuyển hướng mục ","theLuc":[{"ten":"Viễn Cổ Bát Phi","trangThai":"gan-bo"}],"vaiTro":"Hoa Phi Hàm Yên — một trong tiên đế bát phi, phân thân khảo nghiệm Tiên phủ và thế lực truy sát trong cổ mộ","blurb":"Nữ tử áo trắng dung mạo tuyệt trần bước ra từ đại điện Tiên phủ, dùng kỳ hương, rừng hoa và Táng hoa áp chế Vương Lâm rồi tự xưng Hoa Phi Hàm Yên — một trong tiên đế bát phi, có liên hệ mật thiết với Tiên Đế Thanh Lâm và bí mật về Thu Dao. Thân phận thực chất chỉ là hình chiếu phân thân tu vi thiên nhân tam suy; hồn phách và hương hỏa cuối cùng bị Vương Lâm đoạt. Về sau, một nữ tử dung nhan tuyệt trần hình dáng cực giống nàng xuất hiện trong cổ mộ, sở hữu đài mộ và bí thuật hấp thu ký hiệu, trải qua nhiều lần giao phong rồi được Vương Lâm cứu thoát khỏi cổ mộ; sau đó tiết lộ bí mật ba hồn bảy "},{"id":"ngan-y-luyen-thi","name":"Ngân Y Luyện Thi","cn":"银衣炼尸","nguon":["@c1251","@c1257","@c1303"],"tabs":{"kinhLich":[{"chuong":"@c1251","importance":"normal","mucCt":"ky","tieuDe":"Bắt nuốt kim tuyến Lan Phi, cảnh báo hương hỏa là âm mưu","text":"Tự mở khe không gian trữ vật bước ra không chịu khống chế của Vương Lâm. Tùy ý túm tay kéo kim tuyến phân thân Lan Phi đã biến mất trong hư vô quay lại, vuốt tan vỡ hóa sương vàng nuốt vào thất khiếu. Cảm thấy khí tức kim tuyến rất quen thuộc. Khi Vương Lâm hỏi có phải Viễn Cổ Bát Phi, nàng nói không nhớ, lộ vẻ thống khổ. Trước khi quay vào khe trữ vật, dừng lại cảnh báo: hương hỏa là một âm mưu rất lớn, nàng dường như vì nó mà mất đi hết thảy.","anchor":"ta mơ hồ nhớ được, hương hỏa là một loại.là một âm mưu.rất lớn.ta dường như vì nó mà mất đi hết thảy"},{"chuong":"@c1257","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc lại lời cảnh báo về hương khói có độc là một âm mưu, trở thành bằng chứng liên hệ cho suy đoán về bí mật Thái Cổ Tinh Thần.","anchor":"Hơn nữa còn có những lời nói của Ngân Y Nữ Tử, hương khói có độc, là một âm mưu."},{"mucCt":"ky","anchor":"Nàng ngẩng mạnh đầu, sự sợ hãi và mê mang trong nháy mắt đã biến mất","text":"Ngân y nữ tử nhìn thấy pho tượng liền sợ hãi cực độ, phủ nhận mình mở cánh cửa và nhắc Đào Vân, Tử Lạc đều đã chết. Khi Vương Lâm hỏi về người trong pho tượng, khuôn mặt nàng hiện thanh khí cùng ấn ký quỷ dị, ý thức chuyển lạnh lùng vô tình và đánh ra một chưởng khiến trời đất biến sắc, sau đó hôn mê nhưng vẫn lẩm bẩm phủ nhận việc mở cửa. Vương Lâm Sưu thần nàng, bị thanh quang trong thức hải phản chấn, rồi phát hiện sâu trong sương xanh có thân ảnh trung niên áo bảy màu do phong ấn biến thành.","bridge":true,"khoang":"@c1303"}],"tuViMoc":[],"nhanMach":[{"ten":"Đào Vân","tag":"khac","quanHe":"người đã chết trong ký ức đứt đoạn","ghiChu":"Nàng nhắc Đào Vân đã chết khi bị pho tượng kích phát nỗi sợ về biến cố cánh cửa."},{"ten":"Tử Lạc","tag":"khac","quanHe":"người đã chết trong ký ức đứt đoạn","ghiChu":"Nàng nhắc Tử Lạc đã chết cùng Đào Vân trong trạng thái hoảng loạn."},{"ten":"Trung niên áo bảy màu trong thức hải ngân y nữ tử","tag":"khac","quanHe":"thân ảnh phong ấn trong thức hải","ghiChu":"Thân ảnh áo bảy màu nằm sâu trong sương xanh ở thức hải nàng và giống hệt pho tượng khiến nàng sợ hãi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị gọi ra trong cung điện phong kín, tỉnh lại rồi phản kháng dữ dội bằng lốc xoáy","chuong":"@c0931"},{"text":"Lần đầu tiên mở miệng nói chuyện với giọng đứt quãng, nhắc lại lời Hoa Phù cứu nguy trận pháp","chuong":"@c1046"},{"text":"Mơ hồ nhớ lại ký ức, tự thi triển và giải trừ Sinh Tử Cấm thành thạo hơn cả lão bà","chuong":"@c1125"},{"text":"Tự mở khe không gian trữ vật bước ra ngoài sự khống chế của Vương Lâm, bắt nuốt kim tuyến Lan Phi và cảnh báo hương hỏa là âm mưu","chuong":"@c1251"},{"text":"Thủy Đạo Tử nhìn thấy liền lập tức nhận ra thân phận, tâm thần chấn động","chuong":"@c1206"},{"text":"Vương Lâm xác nhận thân phận nàng là nữ tử của một vị tiên tôn","chuong":"@c1545"}]},"trangThai":"song","gioiTinh":"nu","aliases":["Ngân Y Nữ Tử"],"tinhCach":"ban đầu phản kháng dữ dội, về sau trung thành bám sát hộ vệ Vương Lâm; trầm mặc ít nói, giọng đứt quãng như mới học nói; chiến đấu quyết đoán sắc bén; có ý chí tự chủ tiềm ẩn, nhiều lần hành động ngoài khống chế","vaiTro":"Luyện thi áo bạc của Vương Lâm — nữ tử của một vị tiên tôn","blurb":"Ngân Y Luyện Thi là nữ thi áo bạc tu vi Tịnh Niết sơ kỳ, bị Vương Lâm gọi ra trong cung điện phong kín và dần trở thành hộ vệ thủy chung theo sát hắn qua vô số biến cố. Nàng từng mơ hồ nhớ lại ký ức cũ, tự thi triển Sinh Tử Cấm, nhiều lần tự ý hành động ngoài sự khống chế của Vương Lâm, đồng thời được Thủy Đạo Tử nhận ra thân phận ngay khoảnh khắc nhìn thấy. Về sau Vương Lâm xác nhận nàng chính là nữ tử của một vị tiên tôn, mang lai lịch liên hệ tới những bí mật thượng cổ."},{"id":"thanh-nien-hac-y-thiem-loi-toc","name":"Thanh niên hắc y (Thiểm Lôi Tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (tu vi thấp)","trangThai":"tu-vong","vaiTro":"Tộc nhân Thiểm Lôi Tộc tu vi thấp, thân xác bị Vương Lâm đoạt xá","tinhCach":"Tuyệt vọng, oán hận thân phận tu sĩ; khao khát được làm phàm nhân bình thường","blurb":"Tộc nhân Thiểm Lôi Tộc tu vi thấp, bị thương nặng trước ngực. Trước khi chết tự kéo ký hiệu tộc trên mi tâm ra ngoài, thân xác bị Vương Lâm đoạt xá.","tabs":{"diem":[{"text":"Oán hận thân phận tu sĩ Thiểm Lôi Tộc, muốn làm phàm nhân bình thường.","chuong":"@c1252"},{"text":"Trước khi chết tự hủy ký hiệu tộc trên mi tâm, thân xác bị Vương Lâm đoạt xá.","chuong":"@c1252"}],"kinhLich":[{"mucCt":"vua","text":"Bị thương nặng trước ngực, tuyệt vọng oán hận thân phận tu sĩ Thiểm Lôi Tộc, muốn làm phàm nhân bình thường. Trước khi chết dùng sức cuối cùng kéo ký hiệu Thiểm Lôi Tộc trên mi tâm ra ngoài rồi nhắm mắt. Ngay khoảnh khắc đó, tia chớp của Vương Lâm phóng vào vết thương mi tâm, đoạt xá thân xác hắn.","anchor":"ta hận vì chính mình là tu sĩ, ta càng hận mình là tộc nhân Thiểm Lôi Tộc","bridge":true,"khoang":"@c1252"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Kẻ đoạt xá thân xác mình","ghiChu":"@c1252"}],"tuiDo":{}},"nguon":["@c1252"]},{"id":"vu-phi","name":"Vu Phi","cn":"巫飞","aliases":["Thanh niên hắc y"],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1274","trangThai":"khong-ro @c1274","blurb":"Vu Phi, bí danh Hồng y nhân, là sát sĩ thuộc Sát Thị của Sát Vực Giới Tu Chân Liên Minh, tới Liên Minh Tinh Vực để lấy đầu Hứa Mộc — danh tính giả của Vương Lâm. Hắn từng dùng Lôi Thụ Tàn Chi khắc chế sấm sét đối thủ, nhưng khi bị áp đảo bởi sức mạnh thân thể của Vương Lâm thì dùng Huyết Độn bỏ chạy và cuối cùng bị hình thần câu diệt. Về sau thân thể của hắn còn bị Vương Lâm đoạt xá và dùng làm vật chứa.","vaiTro":"Sát thủ Sát Thị của Sát Vực Giới, truy sát Vương Lâm","tinhCach":"Lạnh lùng ngạo mạn; tự tin vào bảo vật và thực lực; hoảng sợ, mất dũng khí khi gặp chênh lệch sức mạnh","tabs":{"diem":[{"text":"Sát sĩ Sát Thị của Sát Vực Giới, đến lấy đầu Hứa Mộc — danh tính giả của Vương Lâm","chuong":"@c0851"},{"text":"Dùng Lôi Thụ Tàn Chi (bảo vật Sát Vực Giới) hấp thu toàn bộ sấm sét của Vương Lâm","chuong":"@c0852"},{"text":"Hoảng sợ trước sức mạnh thân thể của Vương Lâm, mất dũng khí nên dùng Huyết Độn bỏ chạy","chuong":"@c0854"},{"text":"Bị Vương Lâm hình thần câu diệt khi vừa trở về Sát Vực Giới","chuong":"@c0855"},{"text":"Thân thể bị Vương Lâm đoạt xá, tu vi Kết Đan bị Tề Trì hút và ngừng trệ hai trăm năm","chuong":"@c1253"},{"text":"Thân thể đã đoạt xá được Vương Lâm dùng làm vật chứa để áp sát thánh địa Thiểm Lôi","chuong":"@c1274"}],"kinhLich":[{"chuong":"@c1253","importance":"normal","mucCt":"vua","tieuDe":"Bị đoạt xá bởi Vương Lâm","text":"Từng được thừa kế động phủ vùng linh mạch nhưng ngày thứ ba bị tu sĩ Nguyên Anh Tề Trì cướp mất, bị hút tu vi khi nuốt lôi quả, đánh trọng thương xua đuổi. Đang hấp hối thì bị Vương Lâm dùng phương pháp đoạt xá chiếm thân thể để trà trộn Thiểm Lôi Tộc.","anchor":"tên là Vu Phi, là một tộc nhân cực kỳ tầm thường của Thiểm Lôi Tộc"},{"chuong":"@c1257","importance":"bridge","mucCt":"gon","text":"Thân thể đang bị Vương Lâm chiếm dụng, được nhắc tối đa chỉ bùng ra tu vi Hóa Thần, tộc ấn trên mi tâm vẫn còn dù đã rút ra do dung nhập linh hồn.","anchor":"Thân thể của Vu Phi đã được ta cải tạo lại, tối đa cũng chỉ bùng ra tu vi Hóa Thần"},{"chuong":"@c1259","importance":"bridge","mucCt":"gon","text":"Tên Vu Phi xuất hiện trên Thiểm Lôi Bảng vị trí 799 với bốn mươi sáu vạn bốn ngàn Lôi tinh do Vương Lâm dùng ngọc giản mệnh hồn của hắn đổi vật phẩm.","anchor":"Vị trí thứ bảy trăm chín mươi chín là Vu Phi, số lượng Lôi tinh của người này chính là bốn mươi sáu vạn bốn ngàn"},{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Thân thể bị bỏ lại","text":"Thân thể Vu Phi đang bị Vương Lâm dùng làm vật chứa, đến khi nguyên thần Vương Lâm xuất khiếu thì thân thể này trôi về phía tinh không sau lưng.","anchor":"Nguyên thần Vương Lập trực tiếp từ trong cơ thể Vu Phi bay ra"},{"chuong":"@c1274","importance":"bridge","tieuDe":"Thân thể bị nhắc","mucCt":"gon","text":"Vu Phi được nhắc lại vì trước đó Vương Lâm từng dùng thân thể đã đoạt xá của hắn để áp sát thánh địa Thiểm Lôi tộc.","anchor":"dùng thân thể Vu Phi mà hắn đã đoạt xá"}],"tuViMoc":[{"chuong":"@c1253","canhGioi":"Kết Đan","text":"Tu vi Kết Đan bị ngừng trệ hai trăm năm, bị Tề Trì hút tu vi khi nuốt lôi quả","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị đoạt xá thân thể","ghiChu":"Vương Lâm tạm chiếm thân xác để trà trộn Thiểm Lôi Tộc, hứa sau sẽ trả lại kèm lợi ích","nguon":"@c1253"},{"ten":"Tề Trì","tag":"doi-thu","quanHe":"Kẻ cướp động phủ truyền thừa","ghiChu":"Cướp động phủ, hút tu vi khi Vu Phi nuốt lôi quả, đánh trọng thương xua đuổi","nguon":"@c1253"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1253","@c1257","@c1259","@c1270","@c1274"]},{"id":"te-tri","name":"Tề Trì","cn":"齐迟","aliases":["lão già áo xanh"],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh sơ kỳ","trangThai":"song","blurb":"Tu sĩ Nguyên Anh sơ kỳ Thiểm Lôi Tộc, kẻ cướp động phủ truyền thừa của Vu Phi. Bị Vương Lâm đánh bại hoàn toàn, lục ký ức và lấy hết pháp bảo.","vaiTro":"Tộc nhân Thiểm Lôi Tộc, chiếm động phủ Vu Phi","tinhCach":[{"text":"Tham lam, ỷ mạnh hiếp yếu, cướp bóc tộc nhân yếu hơn","chuong":"@c1253"}],"tabs":{"diem":[{"text":"Cướp động phủ truyền thừa của Vu Phi, hút tu vi khi Vu Phi nuốt lôi quả","chuong":"@c1253"},{"text":"Bị Vương Lâm (trong thân Vu Phi) chế phục hoàn toàn, lục ký ức bằng Sưu Thần Thuật, lấy hết bảo vật","chuong":"@c1253"}],"kinhLich":[{"mucCt":"gon","text":"Bị Vương Lâm xâm nhập động phủ, cấm chế tự mở, thi triển sấm sét lục quang kèm oan hồn rồi định thuấn di trốn nhưng bị chặn. Bị dùng Sưu Thần Thuật lục ký ức, lấy hết pháp bảo đan dược trong ký hiệu mi tâm, không bị giết vì luật tộc cấm chém giết sinh tử.","anchor":"trước mặt chính là động phủ của Tề Trì, hắn là lão quái Nguyên Anh sơ kỳ duy nhất trong phạm vi mười dặm quanh đây","bridge":true,"khoang":"@c1253"},{"chuong":"@c1254","importance":"bridge","mucCt":"gon","text":"Vẫn đang hôn mê, bị Vương Lâm ném ra ngoài động phủ khi Thiên Lôi Tông tới đòi cống nạp.","anchor":"đó chính là Tề Trì đang còn hôn mê"}],"tuViMoc":[{"chuong":"@c1253","canhGioi":"Nguyên Anh sơ kỳ","text":"Nguyên Anh sơ kỳ, chỉ có 7 vạn Lôi Tinh","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị chế phục","ghiChu":"Bị Vương Lâm (trong thân Vu Phi) đánh bại, lục ký ức, lấy hết bảo vật","nguon":"@c1253"},{"ten":"Vu Phi","tag":"doi-thu","quanHe":"Nạn nhân bị cướp động phủ","ghiChu":"Cướp động phủ truyền thừa Vu Phi, hút tu vi, đánh trọng thương xua đuổi","nguon":"@c1253"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1253","@c1254"]},{"id":"van-sam-tu","name":"Vân Sam Tử","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Người đứng đầu Thiểm Lôi Bảng với 19,7 tỷ Lôi Tinh, ứng viên số một cho suất vào thánh địa Thiểm Lôi Tộc.","vaiTro":"Tộc nhân Thiểm Lôi Tộc, đứng đầu Thiểm Lôi Bảng","tinhCach":[],"tabs":{"diem":[{"text":"Đứng đầu Thiểm Lôi Bảng với 19,7 tỷ Lôi Tinh, nắm ưu thế lớn nhất tranh suất vào thánh địa","chuong":"@c1253"}],"kinhLich":[{"mucCt":"gon","text":"Xếp vị trí thứ nhất trên Thiểm Lôi Bảng với 19,7 tỷ Lôi Tinh.","anchor":"người xếp ở vị trí thứ nhất có tên là Vân Sam Tử","bridge":true,"khoang":"@c1253"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1253"]},{"id":"phu-dung","name":"Phù Dung","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Xếp thứ hai trên Thiểm Lôi Bảng với 13,9 tỷ Lôi Tinh.","vaiTro":"Tộc nhân Thiểm Lôi Tộc, xếp thứ hai Thiểm Lôi Bảng","tinhCach":[],"tabs":{"diem":[{"text":"Xếp thứ hai Thiểm Lôi Bảng với 13,9 tỷ Lôi Tinh","chuong":"@c1253"}],"kinhLich":[{"mucCt":"gon","text":"Xếp vị trí thứ hai trên Thiểm Lôi Bảng với 13,9 tỷ Lôi Tinh.","anchor":"Người xếp vị trí thứ hai chính là Phù Dung","bridge":true,"khoang":"@c1253"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1253"]},{"id":"toc-quyen","name":"Tộc Quyền","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Lôi Tông","trangThai":"gan-bo"},{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh trung kỳ","trangThai":"song","blurb":"Lão già Nguyên Anh trung kỳ thuộc Thiên Lôi Tông (nhánh trong Thiểm Lôi Tộc), dẫn đội đến cướp bảo vật động phủ Tề Trì để đổi Lôi Tinh cho tông chủ.","vaiTro":"Thành viên Thiên Lôi Tông, chấp hành lệnh tông chủ","tinhCach":[{"text":"Hống hách ỷ thế tông phái, đi cướp bảo vật cho cấp trên","chuong":"@c1253"}],"tabs":{"diem":[{"text":"Dẫn ba tu sĩ Kết Đan đến cướp bảo vật động phủ Tề Trì để đổi Lôi Tinh cho tông chủ Thiên Lôi Tông","chuong":"@c1253"}],"kinhLich":[{"mucCt":"gon","text":"Dẫn ba tu sĩ Kết Đan phóng đến động phủ Tề Trì để cướp bảo vật đổi Lôi Tinh cho tông chủ Thiên Lôi Tông đang sắp lọt Thiểm Lôi Bảng.","anchor":"Những vật lão phu lấy được cũng không phải để cho chính mình đi đổi lấy lôi tinh mà phải giao cho tông chủ","bridge":true,"khoang":"@c1253"}],"tuViMoc":[{"chuong":"@c1253","canhGioi":"Nguyên Anh trung kỳ","text":"Nguyên Anh trung kỳ","importance":"minor"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1253"]},{"id":"khau-duc-hai","name":"Khâu Đức Hải","cn":"邱德海","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Lôi Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh trung kỳ","trangThai":"song","blurb":"Một trong tứ đại trưởng lão Thiên Lôi Tông, tu vi Nguyên Anh trung kỳ. Dẫn người đến động phủ Tề Trì đòi cống nạp cho tông chủ, bị Vương Lâm phế ký hiệu mi tâm và cướp sạch bảo vật.","vaiTro":"Trưởng lão Thiên Lôi Tông, bị Vương Lâm phế tu vi","tinhCach":"Tham lam bắt nạt kẻ yếu; khi gặp kẻ mạnh thì hèn nhát bỏ đồng đội làm vật cản; liều mạng cầu sinh","tabs":{"diem":[{"text":"Một trong tứ đại trưởng lão Thiên Lôi Tông, đẩy ba đệ tử Kết Đan làm vật cản để bỏ chạy khi gặp Vương Lâm","chuong":"@c1254"}],"kinhLich":[{"mucCt":"ky","text":"Dẫn ba tu sĩ Kết Đan đến động phủ Tề Trì đòi Tề Trì nộp pháp bảo và đan dược cho tông chủ Thiên Lôi Tông tiến vào Thiểm Lôi Bảng. Khi Vương Lâm bước ra, cảm nhận uy áp cực mạnh, Nguyên Anh chấn động, linh lực đông cứng, không dò thấy khí tức đối phương. Xin lỗi rồi đẩy ba Kết Đan ra làm vật cản, thuấn di liều mạng hơn mười lần gần mười vạn dặm, bóp nát ngọc giản cầu cứu đồng môn. Cuối cùng bị Vương Lâm ép dẫn đường về sơn môn, bị phá ký hiệu mi tâm và cướp sạch bảo vật.","anchor":"Tề đạo hữu, lão phu Khâu Đức Hải là một trong tứ đại trưởng lão của Thiên Lôi Tông","bridge":true,"khoang":"@c1254"}],"tuViMoc":[{"chuong":"@c1254","canhGioi":"Nguyên Anh trung kỳ","text":"Được giới thiệu ở tu vi Nguyên Anh trung kỳ, một trong tứ đại trưởng lão Thiên Lôi Tông.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cường giả phế tu vi và cướp bảo vật của hắn","ghiChu":"@c1254"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1254"]},{"id":"nguoi-dan-ong-trung-nien-ao-xanh","name":"Người đàn ông trung niên áo xanh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Lôi Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh","trangThai":"song","blurb":"Đồng môn Thiên Lôi Tông, tu sĩ Nguyên Anh. Thuấn di đến đáp lời cầu cứu của Khâu Đức Hải, bị giọng nói Vương Lâm chấn động Nguyên Anh phun máu, cuối cùng bị phế ký hiệu và cướp bảo vật.","vaiTro":"Trưởng lão Thiên Lôi Tông, đồng môn Khâu Đức Hải","tinhCach":"Oán hận khi bị kéo vào họa; bất lực trước cường giả","tabs":{"diem":[{"text":"Căm hận Khâu Đức Hải vì kéo mình vào họa sát thân khi đáp lời cầu cứu","chuong":"@c1254"}],"kinhLich":[{"mucCt":"vua","text":"Thuấn di đến đáp lời cầu cứu của Khâu Đức Hải, bị giọng nói Vương Lâm chấn động Nguyên Anh phun máu. Cực kỳ căm hận Khâu Đức Hải vì kéo mình vào. Bóp nát ngọc giản gọi thêm đồng môn, cuối cùng bị phế ký hiệu mi tâm và cướp pháp bảo.","anchor":"Khâu Đức Hải, ngươi chọc giận loại người như vậy thì tự mình chịu tội, sao lại kéo cả ta vào","bridge":true,"khoang":"@c1254"}],"tuViMoc":[{"chuong":"@c1254","canhGioi":"Nguyên Anh","text":"Được giới thiệu ở tu vi Nguyên Anh.","importance":"minor"}],"nhanMach":[{"ten":"Khâu Đức Hải","tag":"khac","quanHe":"Đồng môn Thiên Lôi Tông, bị kéo vào họa","ghiChu":"@c1254"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cường giả phế tu vi và cướp bảo vật","ghiChu":"@c1254"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1254"]},{"id":"chung-dai-hong","name":"Chung Đại Hồng","cn":"钟大洪","aliases":["Tu sĩ Hóa Thần gầy"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Lôi Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1301","trangThai":"song","blurb":"Chung Đại Hồng là tu sĩ Hóa Thần sơ kỳ thuộc Thiên Lôi Tông, tướng mạo gầy gò xấu xí. Sau khi chứng kiến Vương Lâm phế tứ đại trưởng lão, hắn lập tức quy phục, dâng hết pháp bảo xin làm tôi tớ và được ban đan dược cùng phi kiếm, chiến lực nhờ đó tăng ngang Hóa Thần trung kỳ. Từ đó hắn dẫn đường tại Lôi Tinh Điện, dò tin tức, tận lực hầu hạ chủ nhân, thậm chí được Vương Lâm ủy quyền chỉ huy hơn ngàn tu sĩ, đồng thời ỷ vào uy danh chủ mà cáo oai qua lại giữa Ám Hạt Tộc và Vân Độn tộc.","vaiTro":"Tu sĩ Hóa Thần Thiên Lôi Tông, tôi tớ cuồng tín của Vương Lâm","tinhCach":"Cuồng nhiệt sùng bái cường giả, chuyển hoảng sợ thành phục tùng cực nhanh; nịnh hót khéo léo, thức thời tự bảo toàn; ỷ thế chủ nhân mà kiêu ngạo cáo oai với kẻ yếu","tabs":{"diem":[{"text":"Chứng kiến Vương Lâm phế tứ đại trưởng lão Thiên Lôi Tông, lập tức chuyển từ hoảng sợ sang cuồng nhiệt sùng bái, dùng kỹ thuật nịnh hót để bảo toàn tính mạng và xin làm tôi tớ","chuong":"@c1255"},{"text":"Được Vương Lâm ban đan dược và một thanh phi kiếm, nhờ đó chiến lực ngang Hóa Thần trung kỳ","chuong":"@c1256"},{"text":"Dẫn đường tại Lôi Tinh Điện, giới thiệu quy củ và ba cửa đông/nam/tây cho Vương Lâm","chuong":"@c1259"},{"text":"Dò được tin đan dược có giá trị cao tại tu chân tinh và giao dịch con rối, nhưng bị thương dẫn họa về cho chủ","chuong":"@c1285"},{"text":"Được Vương Lâm chỉ định làm người đại diện, nắm quyền chỉ huy hơn ngàn tu sĩ trong lúc chủ rời đi","chuong":"@c1297"},{"text":"Ỷ thế Vương Lâm, kiêu ngạo cáo oai qua lại giữa Ám Hạt Tộc và Vân Độn tộc, ép tu sĩ hai tộc chữa thương và dâng lễ vật","chuong":"@c1301"}],"kinhLich":[{"mucCt":"ky","text":"Từ đại điện Thiên Lôi Tông phóng ra khi thấy Vương Lâm phế tứ đại trưởng lão, cực kỳ kích động sùng bái cuồng nhiệt. Tự nguyện dâng hết pháp bảo sưu tập, xin làm tôi tớ, phát biểu dài dòng ca tụng. Khiến Vương Lâm sửng sốt nhớ tới Hứa Lập Quốc.","anchor":"vì tiền bối mà cúc cung tận tụy chết không hối tiếc","bridge":true,"khoang":"@c1254"},{"mucCt":"ky","text":"Nhận ra không thể chống lại Vương Lâm, lập tức chuyển hoảng sợ thành kích động, dùng kỹ thuật nịnh hót để bảo toàn tu vi. Giao nộp đống vật phẩm chất như núi nhỏ, thêm cành cây Lôi quang và đan dược tử quang (tổng một vạn Lôi tinh), rồi thanh phi kiếm sắc bén (mười vạn Lôi tinh). Được Vương Lâm ban cho Hàm Hồn đan, nhận lệnh sưu tập vật đổi Lôi tinh cho Vương Lâm. Nhận ra Hứa Lập Quốc cũng tu luyện pháp thuật nịnh hót và hơn hẳn mình, coi đối phương là kẻ địch không đội trời chung. Chủ động gào lên bắt tộc nhân giao nộp thêm vật phẩm dâng Vương Lâm.","anchor":"hắn tu đạo cực kỳ cơ trí nên đổi lo sợ chuyển thành kích động không chút do dự","bridge":true,"khoang":"@c1255"},{"mucCt":"ky","text":"Được Vương Lâm ban đan dược và một thanh phi kiếm tầm thường (đối với Vương Lâm), nhờ đó chiến lực ngang Hóa Thần trung kỳ, chống đỡ được Hóa Thần hậu kỳ. Cẩn thận hơn Hứa Lập Quốc, quen thuộc tinh cầu nên biết nhiều động phủ, mang tu sĩ phá hủy động phủ vơ vét vật phẩm. Coi Hứa Lập Quốc là kình địch cả đời, tự nhủ cũng tu luyện được pháp thuật vô địch và chuẩn bị lời nịnh hót thi triển trước mặt Vương Lâm.","anchor":"Chung Đại Hồng ta rất có thiên phú tu luyện pháp thuật vô địch, ta không tin phải chịu thua Hứa Lập Quốc ngươi","bridge":true,"khoang":"@c1256"},{"mucCt":"vua","text":"Trở về trước Hứa Lập Quốc, mang theo đống vật phẩm đổi Lôi tinh chất cao như núi dâng cho Vương Lâm, được ban một viên thuốc. Đề nghị đi đổi Lôi tinh tại Lôi Tinh Điện sắp mở cửa, cố ý tranh giành vị trí cạnh Vương Lâm trước Hứa Lập Quốc, có dã tâm muốn nổi danh nhờ đi theo Vương Lâm.","anchor":"Chung Đại Hồng có dã tâm rất lớn, điều này chính là điểm khác biệt kh*ng b* giữa hắn và Hứa Lập Quốc.","bridge":true,"khoang":"@c1257"},{"chuong":"@c1258","importance":"normal","tieuDe":"Nhận Vương Lâm làm chủ","text":"Chung Đại Hồng dẫn đường và giải thích các quy củ của Lôi Tinh Điện, đồng thời tận lực hầu hạ Vương Lâm. Hắn đổi cách xưng hô từ tiền bối thành chủ nhân và dâng toàn bộ những vật cướp được để đổi Lôi tinh.","anchor":"trên đoạn đường này Chung Đại Hồng hầu hạ Vương Lâm cực kỳ chu đáo","mucCt":"vua"},{"chuong":"@c1259","importance":"bridge","mucCt":"vua","text":"Cùng Vương Lâm đi qua khe nứt sương mù đến Lôi Tinh Điện, giới thiệu ba cửa đông/nam/tây cho Vương Lâm. Biết Vương Lâm chưa từng đến nhưng giả vờ không biết vì lợi ích đã nhận.","anchor":"Chung Đại Hồng cũng biết Vương Lâm chưa từng đến Lôi Tinh Điện, dù có chút nghi ngờ nhưng so với những lợi ích mà Vương Lâm đã cho, hắn lập tức giả vờ không biết"},{"chuong":"@c1285","importance":"major","mucCt":"ky","tieuDe":"Bị thương dẫn họa","anchor":"Chung Đại Hồng ta nhất định phải trở nên cường đại","text":"Chung Đại Hồng dò được tin tại tu chân tinh này đan dược có giá trị rất cao, còn có giao dịch con rối và chưa nghe tin về Thái Cổ Tinh Thần Lệnh. Hắn dùng đan dược Vương Lâm ban để kết giao lão họ Chương, nhờ lão dẫn tới Ám Hạt Tộc mua một con rối Hóa Thần sơ kỳ. Sau giao dịch, hắn bị nam tử trung niên Ám Hạt Tộc dùng hắc quang đánh vào hậu tâm, trúng hắc khí, phun máu và bị lưu lạc ấn thần thức. Hắn chạy về giao con rối cho Vương Lâm, tự nhận có thể nhịn vì chủ nhân đang tránh truy sát, nhưng sau đó dẫn Vương Lâm quay lại thành trì Ám Hạt Tộc trả đũa."},{"chuong":"@c1286","importance":"normal","mucCt":"vua","tieuDe":"Nhắc lời thề tộc ấn","anchor":"phải để cho bọn hắn lấy tộc ấn phát lời thề của tộc thái cổ","text":"Chung Đại Hồng xác nhận nam tử trung niên là kẻ liên quan, chứng kiến Vương Lâm trấn áp Ám Hạt Tộc và sau đó chủ động nhắc phải buộc đối phương lấy tộc ấn phát lời thề thái cổ để ngăn phản bội."},{"chuong":"@c1296","importance":"normal","mucCt":"ky","tieuDe":"Mượn uy chủ nhân","text":"Chung Đại Hồng đang răn dạy Ám Hạt Tộc vì không dò được tin cho chủ nhân thì gặp Vân Độn tộc giáng xuống. Hắn nôn vì mùi thối của Tham Lang nên bị bắt tới trước mặt đối phương, vội lấy uy danh Vương Lâm ra dọa để giữ mạng. Sau khi thấy Tham Lang phô bày quá nhiều pháp bảo, hắn rơi vào tuyệt vọng rồi sững sờ khi Tham Lang vừa thấy Vương Lâm đã bỏ chạy.","anchor":"Chủ nhân của ta đang trên đường trở về, lúc này cũng có thể tới đây"},{"chuong":"@c1297","importance":"bridge","mucCt":"gon","tieuDe":"Được giao tạm quyền","text":"Chung Đại Hồng được Vương Lâm chỉ định làm người để hơn ngàn tu sĩ phải nghe lệnh trong lúc hắn rời đi.","anchor":"một ngón tay chỉ về phía Chung Đại Hồng đang hưng phấn đứng cách đó không xa"},{"chuong":"@c1300","importance":"normal","mucCt":"vua","tieuDe":"Cáo oai nhận lễ","anchor":"Chung Đại Hồng vừa hưng phấn, khí thế cao ngất trời","text":"Chung Đại Hồng dựa vào uy danh chủ nhân khiến tu sĩ Vân Độn tộc chữa thương, hầu hạ và dâng bình ngọc làm hậu lễ. Khi Vương Lâm trở về, hắn lập tức bỏ vẻ cao ngạo, đổi sang bộ dạng a dua cung nghênh chủ nhân."},{"chuong":"@c1301","importance":"bridge","mucCt":"gon","tieuDe":"Được thế hai tộc","text":"Chung Đại Hồng ỷ thế Vương Lâm, kiêu ngạo qua lại giữa Ám Hạt Tộc và Vân Độn tộc trong lúc hai tộc bị giữ lại quanh động phủ.","anchor":"Chung Đại Hồng cực kỳ kiêu ngạo, bước vào chỗ của hai tộc như chỗ không người"}],"tuViMoc":[{"chuong":"@c1254","canhGioi":"Hóa Thần sơ kỳ","text":"Được giới thiệu ở tu vi Hóa Thần sơ kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Cường giả mà hắn cuồng nhiệt sùng bái, tự nguyện làm tôi tớ","ghiChu":"@c1254"},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Quy phục, nhận lệnh sưu tập vật đổi Lôi tinh","ghiChu":"@c1255"},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Kình địch trong đường nịnh bợ trước Vương Lâm","ghiChu":"@c1255"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ nhân mà Chung Đại Hồng đi theo.","ghiChu":"Chung Đại Hồng thay Vương Lâm dò tin và mua con rối; khi hắn bị thương, Vương Lâm tuyên bố hắn là người của mình và ra mặt."},{"ten":"Lão già họ Chương","tag":"dong-minh","quanHe":"Người được Chung Đại Hồng dùng đan dược kết giao để nhờ dẫn đi mua con rối.","ghiChu":"Chung Đại Hồng tặng lão ba viên đan dược và cùng lão tới thành trì Ám Hạt Tộc."},{"ten":"Nam tử trung niên Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ giao dịch con rối rồi ra tay đả thương Chung Đại Hồng.","ghiChu":"Sau khi nhận hồn đan, người này theo lệnh thiếu chủ bắt lão họ Chương và đánh thương Chung Đại Hồng."},{"ten":"Thiếu chủ Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ đứng sau lệnh truy bắt và lưu lạc ấn.","ghiChu":"Thiếu chủ Ám Hạt Tộc ra lệnh đả thương một người, khiến Chung Đại Hồng bị truy tung."},{"ten":"Lão giả Ám Hạt Tộc hắc bào","tag":"doi-thu","quanHe":"Người bị đề nghị ràng buộc","ghiChu":"Chung Đại Hồng nhắc Vương Lâm bắt lão phát lời thề tộc ấn thái cổ."},{"ten":"Tộc trưởng Vân Độn tộc","tag":"khac","quanHe":"Người bị hắn mượn uy Vương Lâm ép cung kính hầu hạ và dâng hậu lễ.","ghiChu":"Quan hệ hình thành trong lúc Vân Độn tộc sợ đắc tội chủ nhân của Chung Đại Hồng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1254","@c1255","@c1256","@c1257","@c1258","@c1259","@c1285","@c1286","@c1296","@c1297","@c1300","@c1301","@c1305"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","cn":"许立国","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1254","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ tới khi nghe lời sùng bái cuồng nhiệt của tu sĩ Hóa Thần gầy tại Thiên Lôi Tông.","anchor":"hắn nhớ tới Hứa Lập Quốc"},{"mucCt":"ky","text":"Được Vương Lâm gọi ra khỏi túi trữ vật, xuất hiện tại Thiên Lôi Tông. Nịnh nọt Vương Lâm, khoe đã liên tục tra tấn Lưu Kim Bưu theo lệnh. Được truyền thần niệm về nhiệm vụ cướp vật đổi Lôi tinh, kích động tuyên bố nhận lấy việc vài chục tỷ Lôi tinh. Coi Chung Đại Hồng là kẻ tranh đoạt địa vị sủng vật bên cạnh Vương Lâm, tự nhủ hai ngàn năm bên sát tinh chỉ có mình có kết cục tốt. Nảy ý dùng Lưu Kim Bưu đi giết Chung Đại Hồng, lộ nụ cười âm hiểm.","anchor":"Con mẹ nó! dám cùng Hứa gia gia tranh đoạt địa vị được sủng ái trước mặt sát tinh","bridge":true,"khoang":"@c1255"},{"importance":"normal","mucCt":"ky","chuong":"@c1256","tieuDe":"Xuất hành kiểu đế vương, thu phục tu sĩ Nguyên Anh","text":"Được thả ra từ khe nứt trữ vật, thu phục gần trăm tu sĩ Thiểm Lôi Tộc gồm nhiều Kết Đan, bắt họ chế ngai vàng trăm trượng khiêng đi, bốn nữ tu và bốn thanh niên tuấn tú quỳ gối hầu hạ, sai hai tu sĩ Kết Đan gào khẩu hiệu. Thi triển kiếm khí phá tan trận pháp sương đen và tám lá cờ của lão quái Nguyên Anh hậu kỳ, xuyên nát cả ngọn núi, uy hiếp đối phương quy phục dâng hết vật phẩm. Nghe tin tông phái Lôi Tiên Đạo có tông chủ xinh đẹp tuyệt trần liền ra lệnh dẫn đoàn tiến quân cướp người đoạt bảo. Tự cảm thán hai ngàn năm bị Vương Lâm sai khiến, nay mới được hưởng thụ cuộc đời.","anchor":"Đây mới là cuộc sống! Đây mới là Hứa Lập Quốc ta hưởng thụ cuộc đời"},{"chuong":"@c1257","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhận xét không phải tu sĩ mà là kiếm linh nên mặc kệ cho tự do, bị Chung Đại Hồng cố ý về trước để tranh vị trí cạnh Vương Lâm.","anchor":"Còn Hứa Lập Quốc cũng không phải là tu sĩ mà chính là kiếm linh, vậy cứ mặc kệ cho hắn sung sướng."},{"chuong":"@c1264","importance":"normal","tieuDe":"Vơ vét Thiểm Lôi","text":"Bên ngoài bảy trăm vạn thiên địa, trên tu chân tinh Thiểm Lôi Tộc mà Vương Lâm đã rời đi, Hứa Lập Quốc dẫn vài ngàn người tiếp tục điên cuồng vơ vét. Hắn đổi ngai vàng lên năm trăm trượng, giam nhiều nữ tu xinh đẹp và bị một nữ tu căm hận cảnh cáo rằng hắn cùng chủ nhân sẽ gặp tai họa lớn.","anchor":"Đúng lúc này, ngoài bảy trăm vạn thiên địa, trong phạm vi Thiểm Lôi Tộc, trên tu chân tinh Vương Lâm đã bỏ đi, Hứa Lập Quốc đang cực kỳ sung sướng mang theo vài ngàn người, hắn tiếp tục điên cuồng vơ vét."},{"chuong":"@c1269","importance":"normal","mucCt":"ky","tieuDe":"Bắt con tin bị truy sát tại Thiểm Lôi Tộc","text":"Bắt giữ cô gái xinh đẹp (con nuôi cường giả Toái Niết viên mãn Thiểm Lôi Tộc) làm con tin và lá chắn, hóa thành sương đen bỏ chạy. Bị lão già áo xanh (Tịnh Niết) truy kích bằng lôi cầu màu đen từ tộc ấn, dùng kiếm khí chống trả nhưng liên tục bị trọng thương. Liên tục chửi bới khiêu khích để câu giờ, dọa đoạt xá thân thể cô gái. Khi cha nuôi cô gái (Toái Niết viên mãn) xuất hiện, thân thể bị đánh tan thành bốn năm phần, bị tra tấn liên tục tan rã rồi khôi phục, gần như diệt vong. Cuối cùng kêu gọi chủ nhân và được Vương Lâm xuất hiện cứu mạng.","anchor":"Chưa bao giờ Hứa Lập Quốc giống như lúc này, hắn cực kỳ vui sướng khi thấy"},{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Bị thu vào túi","text":"Hứa Lập Quốc chứng kiến Vương Lâm giết đối thủ, chưa kịp nịnh nọt đã bị Vương Lâm thu vào túi trữ vật trước khi xông tới thánh địa Thiểm Lôi Tộc.","anchor":"Hứa Lập Quốc nhìn thấy tất cả mọi chuyện"},{"mucCt":"gon","anchor":"Trong không gian trữ vật của chủ nhân có tên Hứa Lập Quốc quá mức ghê tởm","text":"Hứa Lập Quốc không trực tiếp xuất hiện, nhưng bị Chung Đại Hồng nhắc tới như kẻ có tu vi cao hơn và từng nhiều lần khi nhục hắn, khiến Chung Đại Hồng càng khao khát trở nên cường đại.","bridge":true,"khoang":"@c1285"},{"mucCt":"vua","text":"Hứa Lập Quốc tiếp tục uy hiếp và hành hạ Lưu Kim Bưu trong không gian trữ vật. Nghe tiếng ho của Vương Lâm, hắn lập tức lao ra, kéo Kim Bưu trình diện rồi cam đoan sẽ làm tốt việc được giao, sau đó chế nhạo luận thuyết lừa đảo của đối phương.","anchor":"Hứa gia gia nhà ngươi cô độc đã mấy ngàn năm nay rồi, tuyệt đối sẽ không giết ngươi đâu","bridge":true,"khoang":"@c1301"},{"mucCt":"vua","text":"Hứa Lập Quốc ban đầu bị khí độ của Lưu Kim Bưu làm đổi cách nhìn, sau đó lại chứng kiến hắn biến thành thân phận Chu Tước đời sáu. Hắn bị Vương Lâm giao nhiệm vụ hầu hạ và nghe lệnh Lưu Kim Bưu, rồi đi theo người này rời động phủ.","anchor":"Hứa Lập Quốc, hầu hạ Chu Tước đời sáu, nghe theo mệnh lệnh của hắn","bridge":true,"khoang":"@c1302"}],"tuViMoc":[],"nhanMach":[{"ten":"Chung Đại Hồng","tag":"doi-thu","quanHe":"Kình địch nịnh bợ bên cạnh Vương Lâm, nảy ý muốn giết","ghiChu":"@c1255"},{"ten":"Nữ tu tướng mạo tuyệt vời","tag":"doi-thu","quanHe":"Nữ tu bị giam cầm trên ngai vàng","ghiChu":"Mắng Hứa Lập Quốc chỉ là khí linh, đe dọa diệt sạch cả chủ nhân"},{"ten":"Cô gái xinh đẹp (Thiểm Lôi Tộc)","tag":"khac","quanHe":"Con tin bị bắt giữ","ghiChu":"Bắt cóc làm lá chắn, đe dọa đoạt xá @c1269"},{"ten":"Lão già áo xanh (Thiểm Lôi Tộc)","tag":"doi-thu","quanHe":"Bị truy kích","ghiChu":"Trưởng lão Tịnh Niết truy sát Hứa Lập Quốc @c1269"},{"ten":"Người đàn ông trung niên đạo bào xanh (Thiểm Lôi Tộc)","tag":"doi-thu","quanHe":"Bị tra tấn","ghiChu":"Cha nuôi cô gái, Toái Niết viên mãn, liên tục đánh tan rã thân thể @c1269"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ nhân của Hứa Lập Quốc.","ghiChu":"Nữ tu bị bắt đe dọa rằng ngay cả chủ nhân của Hứa Lập Quốc cũng sẽ bị diệt sạch."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Bị Vương Lâm bắt sống, hủy ý thức gốc và luyện nguyên thần thành ma đầu.","chuong":"@c0112"},{"text":"Là ma đầu duy nhất được Vương Lâm giữ lại, trà trộn bình an trong đám hơn vạn du hồn.","chuong":"@c0280"},{"text":"Nhập tiên kiếm làm kiếm hồn, từng cản đòn bảo vệ thân thể Vương Lâm đến kiệt sức.","chuong":"@c0338"},{"text":"Phản lại Cự Ma lão tổ, bẻ kiếm chém đứt tay trái đối phương rồi quay về theo Vương Lâm.","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm.","chuong":"@c0596"},{"text":"Sau khi tới Tiên Cương, khôi phục ký ức trước lúc rời động phủ giới và nhận lại Vương Lâm làm chủ.","chuong":"@c1881"}]},"nguon":["@c1254","@c1255","@c1256","@c1257","@c1264","@c1269","@c1270","@c1285","@c1301","@c1302","@c1305"],"trangThai":"song","tinhCach":"Kiêu ngạo, lải nhải và nhiều lần đòi đảo chủ tớ; thực dụng, giỏi nịnh nọt để tự bảo toàn; si mê nữ sắc, dễ mất tự chủ; nhát gan nhưng vẫn từng lập công hộ chủ","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1301","vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm linh Vũ tiên kiếm","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc rồi luyện nguyên thần thành ma đầu. Từ ma đầu duy nhất được giữ lại, hắn lần lượt ẩn trong đám du hồn, nhập tiên kiếm làm kiếm hồn, được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ và trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Về sau hắn được đưa tới Tiên Cương, từng mất rồi khôi phục ký ức, tiếp tục nhận Vương Lâm làm chủ."},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1255","tieuDe":"Bị nhắc đến trong kế hoạch của Hứa Lập Quốc","text":"Bị Hứa Lập Quốc nhắc là đã liên tục tra tấn theo lệnh Vương Lâm, và Hứa Lập Quốc nảy ý dùng hắn đi giết Chung Đại Hồng.","anchor":"hai ngàn năm nay ở bên cạnh sát tinh cũng chỉ có một mình sủng vật như Hứa gia gia là có kết cục tốt đẹp"},{"mucCt":"ky","text":"Lưu Kim Bưu bị Hứa Lập Quốc hành hạ đến tiều tụy, ban đầu quỳ xin tha và viện cớ mất ngọc bội nên không còn lừa được ai. Khi Vương Lâm lạnh lùng cho rằng giữ mạng hắn không còn cần thiết, hắn lập tức đổi lời, khẳng định thuật lừa gạt của mình không cần ngọc bội vẫn kinh thiên động địa. Hắn trình bày hệ thống ba cảnh giới gồm lừa người, lừa mình, rồi phản phác quy chân trở lại lừa người, đồng thời tuyên bố nếu ba nghìn đại đạo không có lừa đảo thì hắn sẽ tự sáng chế một đạo mới.","anchor":"Thuật lừa gạt tiểu nhân nghiên cứu chia làm ba cảnh giới","bridge":true,"khoang":"@c1301"},{"mucCt":"ky","text":"Lưu Kim Bưu giải thích đạo lừa đảo của mình đã tới mức tự lừa gạt bản thân, làm ký ức và nguyên thần cũng bị ảnh hưởng, nhờ mất ngọc bội và bị giam mà có cơ hội niết bàn tiến nửa bước vào bước thứ ba. Sau đó hắn được Vương Lâm dùng hỏa diễm màu lam cấy ký ức hơn một tháng, hoàn toàn tin mình là Chu Tước thứ sáu của Chu Tước Thánh Tông và rời động phủ làm mồi câu nhằm vào Hỏa Tước tộc.","anchor":"thuật lừa đảo đã ở đỉnh điểm của bước thứ hai, tiến vào bước thứ ba nửa bước","bridge":true,"khoang":"@c1302"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Dùng ngọc giản chứa khí tức Toái Niết phá hộ sơn đại trận, tống tiền Thiên Cương Tông dưới danh thế cường giả.","chuong":"@c1158"},{"text":"Lừa Quy Nguyên Tông bằng kim quang mang khí tức giả Toái Niết, nhưng bị Vương Lâm truy kích và bại lộ tu vi thực tế chỉ là Âm Hư.","chuong":"@c1198"},{"text":"Đạo lừa đảo đạt tới mức tự lừa bản thân, khiến ký ức và nguyên thần cũng bị ảnh hưởng.","chuong":"@c1302"},{"text":"Giả dạng Chu Tước đời thứ sáu để lừa lão tổ Hỏa Tước tộc trong lúc ẩn náu cùng Hứa Lập Quốc.","chuong":"@c1335"},{"text":"Bị Vương Lâm tước tự do, bắt làm nô bộc ngàn năm sau vụ tính toán máu tươi của Người điên.","chuong":"@c1474"},{"text":"Sau khi chuyển thế, khôi phục hai đời ký ức và tiếp tục đi theo Vương Lâm, mở ra nhận thức mới về đạo lừa gạt.","chuong":"@c1848"}]},"nguon":["@c1255","@c1301","@c1302"],"canhGioiCaoNhat":"Thuật lừa đảo nửa bước vào bước thứ ba @c1302","aliases":["Kim Bưu Tử","Chu Tước đời thứ sáu","Chu Tước thứ sáu của Chu Tước Thánh Tông"],"gioiTinh":"nam","vaiTro":"Kẻ lừa đảo kỳ cựu, nô bộc ngàn năm của Vương Lâm","tinhCach":"Xảo quyệt, giỏi giả mạo khí thế để tống tiền; Tham lợi nhưng biết sợ cường giả; Dai dẳng với đạo lừa gạt đến mức tự lừa bản thân; Linh hoạt nương theo Vương Lâm để sinh tồn","blurb":"Lưu Kim Bưu, bí danh Kim Bưu Tử, là tu sĩ chuyên dùng thủ đoạn giả mạo khí tức Toái Niết để lừa gạt các tông môn và người yếu thế. Sau khi bị Vương Lâm truy kích, mất bảo vật rồi nhiều lần bị cuốn vào kế hoạch của Vương Lâm và Hứa Lập Quốc, lão bị tước tự do, phải làm nô bộc ngàn năm. Về sau chuyển thế tại Tiên Cương, lão khôi phục ký ức hai đời, tiếp tục đi theo Vương Lâm và thức tỉnh nhận thức mới về đạo lừa gạt."},{"id":"tu-si-nguyen-anh-thiem-loi-toc","name":"Tu sĩ Nguyên Anh trung niên (Thiểm Lôi Tộc)","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh hậu kỳ","trangThai":"song","blurb":"Lão quái Nguyên Anh hậu kỳ thuộc Thiểm Lôi Tộc, có động phủ trên núi được trận pháp sương đen bảo vệ. Bị Hứa Lập Quốc phá tan trận pháp, hoảng sợ quy phục dâng hiến tất cả vật phẩm.","vaiTro":"Tu sĩ Thiểm Lôi Tộc bị Hứa Lập Quốc thu phục","tinhCach":"Biết thời thế, nhanh chóng quy phục trước cường giả","tabs":{"diem":[{"text":"Lão quái Nguyên Anh hậu kỳ bị Hứa Lập Quốc phá tan trận pháp, quy phục dâng hết vật phẩm và cung cấp tin tức về Lôi Tiên Đạo.","chuong":"@c1256"}],"kinhLich":[{"mucCt":"gon","text":"Bị Hứa Lập Quốc phá tan trận pháp sương đen và xuyên nát ngọn núi, hoảng sợ quy phục dâng hiến tất cả vật phẩm, cung cấp thông tin về tông phái Lôi Tiên Đạo cách mười vạn dặm.","anchor":"cách nơi này mười vạn dặm có một tông phái tên là Lôi Tiên Đạo","bridge":true,"khoang":"@c1256"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Bị Hứa Lập Quốc phá trận pháp, uy hiếp quy phục","ghiChu":"@c1256"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1256"]},{"id":"hac-ma-phap-vuong","name":"Hắc Ma Pháp Vương","cn":"黑魔法王","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Vũ Di Sơn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh sơ kỳ đỉnh phong","trangThai":"song","blurb":"Một trong Tứ vương của Vũ Di Sơn, tu vi Vấn Đỉnh sơ kỳ đỉnh phong, xếp hạng 766 trên Thiểm Lôi Bảng. Đàn ông trung niên hắc y đầu đội đạo quan.","vaiTro":"Tu sĩ mạnh của Thiểm Lôi Tộc, bị Vương Lâm chấn nhiếp chỉ bằng ánh mắt","tinhCach":"Kiêu căng với kẻ yếu nhưng nhạy bén với nguy hiểm, biết sợ cường giả","tabs":{"diem":[{"text":"Một trong Tứ vương Vũ Di Sơn, Vấn Đỉnh sơ kỳ đỉnh phong, hạng 766 Thiểm Lôi Bảng","chuong":"@c1258"},{"text":"Bị Vương Lâm chỉ quét mắt đã run rẩy toàn thân, vã mồ hôi lạnh, vội phóng đi","chuong":"@c1258"},{"text":"Chỉ bị Vương Lâm quét mắt một cái đã run rẩy toàn thân, vã mồ hôi lạnh, vội phóng đi không dám quay đầu dù là cường giả Vấn Đỉnh hạng 766 Thiểm Lôi Bảng","chuong":"@c1258"}],"kinhLich":[{"chuong":"@c1258","importance":"normal","tieuDe":"Kinh sợ trước Vương Lâm","text":"Hắc Ma Pháp Vương, một trong Tứ vương của Vũ Di Sơn và đứng hạng 766 trên Thiểm Lôi Bảng, đến Lôi Tinh Điện để đổi Lôi tinh. Khi bị Vương Lâm quét mắt nhìn, hắn run rẩy, vã mồ hôi lạnh và vội rời đi mà không dám quay đầu.","anchor":"Hắc Ma Pháp Vương Vũ Di Sơn, nghe nói tu vi người này đã đạt đến Vấn Đỉnh sơ kỳ đỉnh phong","mucCt":"vua"},{"chuong":"@c1260","importance":"bridge","mucCt":"gon","text":"Có mặt tại cửa tây Lôi Tinh Điện trong số hơn mười tu sĩ đang xem xét nhiệm vụ.","anchor":"Trong đám người này có cả Hắc Ma Pháp Vương"}],"tuViMoc":[{"chuong":"@c1258","canhGioi":"Vấn Đỉnh sơ kỳ đỉnh phong","text":"Tu vi Vấn Đỉnh sơ kỳ đỉnh phong, xếp hạng 766 trên Thiểm Lôi Bảng","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm chấn nhiếp chỉ bằng ánh mắt, không dám đối đầu","ghiChu":"@c1258"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị chấn nhiếp bởi ánh mắt","ghiChu":"Không biết danh tính thật của Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1258","@c1260"]},{"id":"chu-thien-tu","name":"Chu Thiên Tử","cn":"诸天子","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết","trangThai":"khong-ro","blurb":"Chu Thiên Tử là tu sĩ Khuy Niết Đệ Nhị Bộ đại thần thông thuộc Thiểm Lôi Tộc, hiện thân từ mây sấm sét tiến vào Lôi Tinh Điện để tranh thứ hạng trên Thiểm Lôi Bảng. Sau khinh thường và định giết Vương Lâm, ông bị Vương Lâm chặn lại rồi bị thần thông ánh mắt kích nổ, về sau còn bị nhắc làm đối chiếu để nhấn mạnh không đủ tư cách tự bạo trước mặt Vương Lâm.","vaiTro":"Tu sĩ Khuy Niết (Đệ Nhị Bộ) của Thiểm Lôi Tộc, tranh hạng Thiểm Lôi Bảng","tinhCach":"Tự tin, hào phóng khi thưởng đan dược cho hạ nhân; hung hăng, khinh thường đối thủ","tabs":{"diem":[{"text":"Hiện thân từ mây sấm sét, tiến vào Lôi Tinh Điện tranh thứ hạng Thiểm Lôi Bảng","chuong":"@c1258"},{"text":"Nhắm ngọc giản sáng nhất tại cửa tây, ra tay chộp nhiệm vụ Linh Niệm Lôi","chuong":"@c1260"},{"text":"Được xác nhận là tu sĩ Đệ Nhị Bộ (Khuy Niết); hung hăng khinh thường, định giết Vương Lâm","chuong":"@c1261"},{"text":"Bỏ chạy nhưng bị Vương Lâm chặn, bị thần thông ánh mắt kích nổ toàn thân","chuong":"@c1262"},{"text":"Bị nhắc làm đối chiếu để nhấn mạnh không đủ tư cách tự bạo trước mặt Vương Lâm","chuong":"@c1264"}],"kinhLich":[{"chuong":"@c1258","importance":"normal","tieuDe":"Tranh hạng Thiểm Lôi Bảng","text":"Chu Thiên Tử hiện thân từ mây sấm sét và tiến vào Lôi Tinh Điện để tranh thứ hạng trên Thiểm Lôi Bảng. Ông tự nhận có thể lọt vào nhóm ba mươi và ban hai khối đan dược cho hai tu sĩ áo đỏ gác khe nứt.","anchor":"Nhóm mười người đứng đầu thì không thể. nhưng có thể tiến vào nhóm ba mươi người","mucCt":"vua"},{"mucCt":"vua","text":"Có mặt tại cửa tây Lôi Tinh Điện xem nhiệm vụ, nhắm ngọc giản sáng nhất (nhiệm vụ Linh Niệm Lôi). Ra tay chộp ngọc giản trước Vương Lâm nhờ vị trí gần hơn, lạnh lùng quát Vương Lâm Cút với uy áp Khuy Niết, coi đối phương như kiến.","anchor":"Chu Thiên Tử cầm lấy ngọc giản thì lạnh lùng quét mắt về phía Vương Lâm, lão chỉ đơn giản nói ra một chữ","bridge":true,"khoang":"@c1260"},{"mucCt":"ky","text":"Hung hăng khinh thường Vương Lâm tại cửa Tây, định giết trong bảy trăm vạn thiên địa vì nơi đó có cấm chế chặn thần thức. Tiến vào con đường trước, suy tính giao dịch với Hạo Côn Tử. Khi sắp đến cửa ra thì bị Vương Lâm đuổi kịp từ phía sau, toàn lực vỗ mi tâm hóa Lôi Long tấn công nhưng bị phá tan chỉ bằng một vung tay. Nhận ra tu vi Vương Lâm đã vượt qua Toái Niết, hồn bay phách lạn bỏ chạy.","anchor":"Toái Niết! Đây là tu vi Toái Niết! Không, đã vượt qua Toái Niết, đây là…","bridge":true,"khoang":"@c1261"},{"mucCt":"ky","text":"Bỏ chạy về phía cửa ra vào bảy trăm vạn thiên địa nhưng bị Vương Lâm chặn. Bị thần thông ánh mắt kích nổ toàn bộ sấm sét tu luyện mấy ngàn năm trong cơ thể, thân thể nổ tung hóa máu thịt. Nguyên thần trọng thương được tộc ấn bao bọc xông ra bỏ chạy nhưng bị hút ngược lại. Cầu xin tha mạng, nhìn thấy hồn phách bị phong ấn trong cơ thể trong suốt của Vương Lâm, kịp nói không phải rồi bị bóp nát nguyên thần, hình thần câu diệt. Sấm sét và tộc ấn bị Vương Lâm thu đoạt.","anchor":"Chu Thiên Tử lập tức hình thần câu diệt","bridge":true,"khoang":"@c1262"},{"chuong":"@c1264","importance":"normal","tieuDe":"Đối chiếu tự bạo","text":"Chu Thiên Tử được nhắc làm đối chiếu để nhấn mạnh ngay cả hắn cũng không đủ tư cách tự bạo trước mặt Vương Lâm, huống chi các tu sĩ Vấn Đỉnh Thiểm Lôi Tộc.","anchor":"Nhưng ngay cả Chu Thiên Tử cũng không có tư cách tự bạo trước mặt Vương Lâm, vì vậy không cần phải nói đến những tu sĩ Vấn Đỉnh này."}],"tuViMoc":[{"chuong":"@c1261","canhGioi":"Khuy Niết (Đệ Nhị Bộ)","text":"Được xác nhận là tu sĩ Đệ Nhị Bộ (Khuy Niết)","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Khinh thường vì tưởng chỉ là Vấn Đỉnh, bị phá tan Lôi Long, nhận ra tu vi vượt Toái Niết"},{"ten":"Hạo Côn Tử","tag":"khac","quanHe":"Đối tượng giao dịch","ghiChu":"Đến bảy trăm vạn thiên địa để giao dịch, tu vi cao hơn Chu Thiên Tử, phải hẹn hảo hữu đến cùng kiềm chế"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Được nhắc làm đối chiếu","ghiChu":"Tên Chu Thiên Tử được dùng để so sánh với uy thế của Vương Lâm trước ý đồ tự bạo của tu sĩ Vấn Đỉnh Thiểm Lôi Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1258","@c1260","@c1261","@c1262","@c1264"]},{"id":"hai-tu-si-ao-do-loi-tinh-dien","name":"Hai tu sĩ áo đỏ (Lôi Tinh Điện)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Âm Hư","trangThai":"song","blurb":"Hai tu sĩ canh gác khe nứt sương mù dẫn vào Lôi Tinh Điện, bề ngoài khoảng bốn mươi tuổi nhưng thực tế sống vài ngàn năm, tu vi vượt Đệ Nhất Bộ đạt cảnh giới Âm Hư.","vaiTro":"Lính canh cửa Lôi Tinh Điện, tu vi Âm Hư","tinhCach":"Cung kính với bề trên, thản nhiên với tu sĩ bình thường","tabs":{"diem":[{"text":"Tu vi Âm Hư, canh gác khe nứt sương mù Lôi Tinh Điện, khiến cả Hắc Ma Pháp Vương cũng phải cung kính","chuong":"@c1258"},{"text":"Bề ngoài khoảng bốn mươi tuổi nhưng thực tế sống vài ngàn năm, tu vi Âm Hư, canh gác khe nứt sương mù Lôi Tinh Điện","chuong":"@c1258"},{"text":"Tu vi vượt Đệ Nhất Bộ đạt Âm Hư, canh gác khe nứt sương mù cấm địa Lôi Tinh Điện","chuong":"@c1258"}],"kinhLich":[{"chuong":"@c1258","importance":"normal","mucCt":"gon","tieuDe":"Canh gác khe nứt Lôi Tinh Điện","text":"Canh gác khe nứt sương mù, cung kính tiếp đón Chu Thiên Tử, không phát hiện bất thường ở Vương Lâm và Chung Đại Hồng.","anchor":"Tu vi của hai tên này đã vượt qua Đệ Nhất Bộ và đạt đến cảnh giới Âm Hư"}],"tuViMoc":[{"chuong":"@c1258","canhGioi":"Âm Hư","text":"Tu vi vượt Đệ Nhất Bộ đạt cảnh giới Âm Hư","importance":"minor"}],"nhanMach":[{"ten":"Chu Thiên Tử","tag":"cap-tren","quanHe":"Cung kính tham bái","ghiChu":"Được Chu Thiên Tử thưởng đan dược"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1258"]},{"id":"van-que-tu","name":"Vân Quế Tử","cn":"云桂子","aliases":[],"gioiTinh":"khong-ro","trangThai":"song","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"vaiTro":"Người đứng đầu Thiểm Lôi Bảng","tinhCach":"Chưa rõ","blurb":"Nhân vật đứng vị trí số một trên Thiểm Lôi Bảng của Thiểm Lôi Tộc, sở hữu lượng Lôi tinh khổng lồ hai mươi bốn tỷ chín ngàn.","tabs":{"diem":[{"text":"Đứng đầu Thiểm Lôi Bảng với Lôi tinh tăng từ mười bốn tỷ bảy ngàn lên hai mươi bốn tỷ chín ngàn.","chuong":"@c1259"}],"kinhLich":[{"mucCt":"gon","text":"Lôi tinh trên Thiểm Lôi Bảng tăng từ mười bốn tỷ bảy ngàn lên hai mươi bốn tỷ chín ngàn, giữ vững vị trí số một.","anchor":"Người xếp vị trí đầu tiên chính là Vân Quế Tử, nhưng số lượng mười bốn tỷ bảy ngàn trước đó đã biến thành hai mươi bốn tỷ chín ngàn","bridge":true,"khoang":"@c1259"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1259"]},{"id":"ba-lao-gia-canh-ao","name":"Ba lão già canh ao","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"vaiTro":"Phụ trách khu đổi Lôi tinh tại cửa đông Lôi Tinh Điện","tinhCach":"Chưa rõ","blurb":"Ba lão già tu vi một Dương Thực, hai Âm Hư, canh giữ ao đen tại cửa đông Lôi Tinh Điện, phụ trách việc đổi vật phẩm lấy Lôi tinh.","canhGioiCaoNhat":"Dương Thực (1 người), Âm Hư (2 người)","tabs":{"diem":[{"text":"Kinh ngạc trước lượng vật phẩm khổng lồ mà Vương Lâm lấy ra đổi Lôi tinh, rất ít khi thấy ai đổi nhiều đến vậy.","chuong":"@c1259"}],"kinhLich":[{"mucCt":"gon","text":"Phụ trách khu đổi Lôi tinh cửa đông, kinh ngạc khi Vương Lâm (giả danh Vu Phi) lấy ra lượng vật phẩm khổng lồ ném vào ao đen suốt nửa ngày.","anchor":"Ba người bọn họ phụ trách nơi đây, rất ít khi thất được người có thể lấy ra nhiều vật phẩm đổi Lôi tinh như vậy","bridge":true,"khoang":"@c1259"},{"mucCt":"vua","text":"Theo quy củ, ba lão già Dương Thực cửa đông Lôi Tinh Điện tặng tạo hóa cho người mới lên Thiểm Lôi Bảng. Lão thứ nhất tặng Tụ Lôi Hoàn nén 8900 lần, lão thứ hai tặng ngọc giản công pháp Thiểm Lôi Tộc mở rộng tộc ấn, lão thứ ba tặng lời khuyên đi cửa tây cùng ngọc giản lôi quang và tiết lộ bí mật Lôi Lục Đạo.","anchor":"hễ là người phụ trách cửa đông gặp được gương mặt mới tiến vào Thiểm Lôi Bảng đều phải đưa ra chút tạo hóa","bridge":true,"khoang":"@c1260"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1259","@c1260"]},{"id":"lao-tu-si-cua-tay","name":"Lão tu sĩ cửa Tây","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Tu sĩ Thiểm Lôi Tộc phụ trách cửa Tây Lôi Tinh Điện","tinhCach":"Có nghĩa khí; nể tình bạn cũ","blurb":"Một trong bảy tu sĩ Thiểm Lôi Tộc phụ trách cửa Tây. Nhận ra Vương Lâm là Vu Phi nhờ ngọc giản của Hạo Nhiên đạo hữu, xin Chu Thiên Tử nể mặt cho vào bảy trăm vạn thiên địa.","tabs":{"diem":[{"text":"Nể tình bạn cũ Hạo Nhiên, xin Chu Thiên Tử cho Vương Lâm vào bảy trăm vạn thiên địa","chuong":"@c1261"}],"kinhLich":[{"mucCt":"gon","text":"Nhận ra Vương Lâm là Vu Phi nhờ ngọc giản, ôm quyền xin Chu Thiên Tử nể mặt cho hắn tiến vào bảy trăm vạn thiên địa tu luyện.","anchor":"Người này được bạn cũ vãn bối cất nhắc, để hắn tiến vào bảy trăm vạn thiên địa tu luyện","bridge":true,"khoang":"@c1261"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được giới thiệu","ghiChu":"Nhận ngọc giản xác nhận thân phận Vu Phi, xin Chu Thiên Tử cho vào"},{"ten":"Hạo Nhiên đạo hữu","tag":"ban-be","quanHe":"Bạn cũ","ghiChu":"Người gửi lời truyền âm khen ngợi Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1261"]},{"id":"hao-con-tu","name":"Hạo Côn Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Cao hơn Khuy Niết (Chu Thiên Tử)","trangThai":"song","vaiTro":"Đối tượng giao dịch của Chu Thiên Tử tại bảy trăm vạn thiên địa","tinhCach":"Chưa rõ","blurb":"Nhân vật được Chu Thiên Tử nhắc tới trong suy nghĩ, là đối tượng giao dịch trong bảy trăm vạn thiên địa. Tu vi cao hơn Chu Thiên Tử, khiến lão phải hẹn hảo hữu đến cùng kiềm chế.","tabs":{"diem":[{"text":"Tu vi cao hơn Chu Thiên Tử, là đối tượng giao dịch tại bảy trăm vạn thiên địa","chuong":"@c1261"}],"kinhLich":[{"chuong":"@c1261","importance":"bridge","mucCt":"gon","text":"Được Chu Thiên Tử nhắc trong suy nghĩ là đối tượng giao dịch tại bảy trăm vạn thiên địa, tu vi cao hơn lão.","anchor":"tu vi người này cao hơn ta một chút, nếu hắn có ý niệm chiếm đoạt thì ta cũng không phải là đối thủ"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Thiên Tử","tag":"khac","quanHe":"Đối tác giao dịch","ghiChu":"Chu Thiên Tử đến bảy trăm vạn thiên địa để giao dịch, phải đề phòng vì tu vi thấp hơn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1261"]},{"id":"hao-nhien-dao-huu","name":"Hạo Nhiên đạo hữu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Bạn cũ của lão tu sĩ cửa Tây, người khen ngợi Vương Lâm trong lời truyền âm","tinhCach":"Chưa rõ","blurb":"Bạn cũ của lão tu sĩ cửa Tây, rất khen ngợi Vương Lâm trong lời truyền âm gửi kèm ngọc giản.","tabs":{"diem":[{"text":"Rất khen ngợi Vương Lâm trong lời truyền âm gửi kèm ngọc giản","chuong":"@c1261"}],"kinhLich":[{"chuong":"@c1261","importance":"bridge","mucCt":"gon","text":"Được nhắc là bạn cũ của lão tu sĩ cửa Tây, đã gửi lời truyền âm khen ngợi Vương Lâm.","anchor":"ta thấy trong lời truyền âm thì Hạo Nhiên đạo hữu rất khen ngợi tên này"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tu sĩ cửa Tây","tag":"ban-be","quanHe":"Bạn cũ","ghiChu":"Gửi lời truyền âm khen ngợi Vương Lâm"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được khen ngợi","ghiChu":"Rất khen ngợi trong lời truyền âm gửi kèm ngọc giản"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1261"]},{"id":"duong-thuc","name":"Dương Thực","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Tiểu bối Thiểm Lôi Tộc ở không gian cửa Đông, tặng ngọc giản cho Vương Lâm","tinhCach":"Chưa rõ","blurb":"Tiểu bối Thiểm Lôi Tộc ở không gian cửa Đông, đã tặng ngọc giản cho Vương Lâm giúp xác nhận thân phận Vu Phi.","tabs":{"diem":[{"text":"Tặng ngọc giản cho Vương Lâm, giúp hắn vào bảy trăm vạn thiên địa","chuong":"@c1261"}],"kinhLich":[{"chuong":"@c1261","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhớ lại là tiểu bối Thiểm Lôi Tộc ở cửa Đông đã tặng ngọc giản.","anchor":"Người này được bạn cũ vãn bối cất nhắc, để hắn tiến vào bảy trăm vạn thiên địa tu luyện"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được giúp đỡ","ghiChu":"Tặng ngọc giản giúp Vương Lâm xác nhận thân phận Vu Phi"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1261"]},{"id":"truong-canh-van","name":"Trương Cảnh Vân","cn":"张景云","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"tu-vong","blurb":"Tu sĩ trung niên Vấn Đỉnh trung kỳ của Thiểm Lôi Tộc, chuyên tiếp cận người mới đến bảy trăm vạn thiên địa để cướp Linh Niệm Lôi và có thể hại mạng, bị các tu sĩ khác kỵ.","vaiTro":"Kẻ chuyên cướp Linh Niệm Lôi trong bảy trăm vạn thiên địa","tinhCach":"Xảo quyệt; giả vờ thân thiện; tham lam; bất chấp mạng người","tabs":{"diem":[{"text":"Chuyên dụ dỗ người mới đến bảy trăm vạn thiên địa, cướp Linh Niệm Lôi, bị các tu sĩ kỵ và quen biết như kẻ nguy hiểm.","chuong":"@c1262"},{"text":"Từng hóa thân làm thiên đạo hoặc thiên kiếp để diệt tu sĩ và săn Linh Niệm Lôi.","chuong":"@c1264"},{"text":"Bị Vương Lâm giết ngay khi lao tới tấn công đòi niệm lôi.","chuong":"@c1264"}],"kinhLich":[{"mucCt":"vua","text":"Chủ động tiếp cận Vương Lâm (mạo danh Vu Phi), tự xưng đến bảy trăm vạn thiên địa lần thứ hai, mời kết bạn. Nhận ra tên Vu Phi mới thăng cấp trong Thiểm Lôi Bảng hôm nay. Dẫn Vương Lâm đến tổ hơn mười người trước trận pháp khổng lồ.","anchor":"tên Trương Cảnh Vân này rõ ràng được đám tu sĩ nơi đây cực kỳ quen thuộc và cố kỵ","bridge":true,"khoang":"@c1262"},{"mucCt":"vua","text":"Trương Cảnh Vân dẫn Vương Lâm đến giới thiệu với nhóm tu sĩ, chỉ huy cả đám tiến vào trận pháp bảy trăm vạn thiên địa. Tại thiên địa nơi Vi Lỗ Bị độ kiếp, hắn xin nhường phần đóng vai thiên đạo, bước ra khỏi kiếp vân tuyên bố rồi liên tiếp điều khiển sáu luồng sấm sét đánh chết Vi Lỗ Bị, gương mặt hưng phấn cực độ.","anchor":"Ta là thiên đạo, đánh xuống sấm sét!","bridge":true,"khoang":"@c1263"},{"chuong":"@c1264","importance":"normal","tieuDe":"Cướp lôi bị diệt","text":"Trương Cảnh Vân tiếc vì tu sĩ Hóa Thần đỉnh phong vừa chết không sinh ra Linh Niệm Lôi, rồi cùng đồng bọn vây giết nhóm tu sĩ mới tới trong bảy trăm vạn thiên địa. Hắn thi triển sấm sét giống thiên kiếp lao vào Vương Lâm để đòi niệm lôi, nhưng bị Vương Lâm chế trụ và bóp nát đến hình thần câu diệt.","anchor":"Một tiếng ầm vang lên, thân thể Trương Cảnh Vân lập tức tan vỡ thành máu thịt giống như lão già vừa rồi hủy diệt trong tay hắn, máu thịt tung tóe, hình thần câu diệt."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tiếp cận dụ dỗ Vương Lâm mạo danh Vu Phi, coi là con mồi để cướp Linh Niệm Lôi","ghiChu":"@c1262"},{"ten":"Tu sĩ họ Chu","tag":"dong-minh","quanHe":"Đồng bọn trong nhóm Thiểm Lôi Tộc giả thiên kiếp.","ghiChu":"Cùng tham gia bao vây người mới đến bảy trăm vạn thiên địa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1262","@c1263","@c1264"]},{"id":"tu-si-am-hu-canh-truyen-tong-tran","name":"Tu sĩ Âm Hư canh truyền tống trận","gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Âm Hư","trangThai":"tu-vong","blurb":"Tu sĩ Âm Hư canh giữ truyền tống trận tại quảng trường trung tâm bảy trăm vạn thiên địa, kiểm tra ngọc giản tộc và phát vật phẩm cho tộc nhân mới đến.","vaiTro":"Canh giữ truyền tống trận bảy trăm vạn thiên địa","tinhCach":"Nghiêm túc; làm việc theo quy tắc","tabs":{"diem":[{"text":"Canh giữ truyền tống trận tại trọng địa Thiểm Lôi Tộc, kiểm tra thân phận và phát vật phẩm cho người mới.","chuong":"@c1262"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1262","tieuDe":"Kiểm tra Vương Lâm mạo danh Vu Phi","text":"Kiểm tra ngọc giản tộc của Vu Phi rồi phát ba vật phẩm cho Vương Lâm.","anchor":"đưa ngọc giản đây cho ta, ta muốn kiểm tra một chút"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1262","@c1264"]},{"id":"vi-lo-bi","name":"Vi Lỗ Bị","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Hóa Thần đỉnh phong","trangThai":"tu-vong","blurb":"Tu sĩ tóc trắng tu đạo hơn 500 năm, đạt Hóa Thần đỉnh phong, chuẩn bị phá vỡ thiên địa nghênh đón thiên kiếp để thăng tiên. Có mấy ngàn đệ tử con cháu ủng hộ dưới chân núi. Bị sáu luồng sấm sét thiên kiếp đánh trúng, hình thần câu diệt.","vaiTro":"Tu sĩ hạ giới độ kiếp thăng tiên, bị thiên kiếp giết chết","tinhCach":"Kiên định; hào sảng trước cái chết; yêu thương đệ tử con cháu","tabs":{"diem":[{"text":"Tu đạo hơn 500 năm đạt tới cảnh giới Hóa Thần đỉnh phong","chuong":"@c1263"},{"text":"Đứng trên ngọn núi nghênh đón thiên kiếp để phá vỡ thiên địa thăng tiên","chuong":"@c1263"},{"text":"Được mấy ngàn đệ tử con cháu quỳ gối ủng hộ dưới chân núi","chuong":"@c1263"},{"text":"Bị sáu luồng sấm sét thiên kiếp đánh trúng, hình thần câu diệt","chuong":"@c1263"}],"kinhLich":[{"chuong":"@c1263","importance":"major","mucCt":"vua","tieuDe":"Hình thần câu diệt khi độ kiếp","text":"Vi Lỗ Bị đứng trên ngọn núi nghênh đón thiên kiếp, mấy ngàn đệ tử con cháu quỳ gối ủng hộ dưới chân núi. Sau sáu luồng sấm sét do Trương Cảnh Vân điều khiển, lão phun máu tươi, rống lên tiếng cuối rồi thân thể tan vỡ, hình thần câu diệt.","anchor":"khi luồng sấm sét thứ sáu rơi xuống, thân thể lão già tan vỡ, hình thần câu diệt"}],"tuViMoc":[{"chuong":"@c1263","canhGioi":"Hóa Thần đỉnh phong","text":"Tu đạo hơn 500 năm đạt Hóa Thần đỉnh phong, chuẩn bị phá vỡ thiên địa nghênh đón thiên kiếp thăng tiên","importance":"major"}],"nhanMach":[],"tuiDo":{}},"nguon":["@c1263"]},{"id":"tu-si-ho-chu","name":"Tu sĩ họ Chu","cn":"","aliases":["Tu sĩ họ Chu Thiểm Lôi Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh","trangThai":"tu-vong","blurb":"Một trong bốn tu sĩ cùng phe Trương Cảnh Vân trong bảy trăm vạn thiên địa, giải thích cơ chế thiên kiếp cho người mới.","vaiTro":"Tu sĩ nhóm Trương Cảnh Vân, giải thích cơ chế thiên kiếp","tinhCach":"Hay giải thích; từng trải","tabs":{"diem":[{"text":"Giải thích cho Vương Lâm lý do sấm sét thiên kiếp mạnh dần: buộc tu sĩ vùng vẫy bất khuất để sinh ra Linh Niệm Lôi","chuong":"@c1263"},{"text":"Dùng kiếp vân che khuất tầm nhìn của tu sĩ bên dưới khi nhóm Thiểm Lôi Tộc tập kích người mới đến.","chuong":"@c1264"},{"text":"Bị tia chớp hồng sắc Cực cảnh đánh chết trong nhóm tu sĩ Vấn Đỉnh bỏ chạy.","chuong":"@c1264"}],"kinhLich":[{"mucCt":"gon","text":"Giải thích cho người mới rằng sấm sét thiên kiếp mạnh dần là để buộc tu sĩ vùng vẫy bất khuất, sinh ra Linh Niệm Lôi trong cơ thể.","anchor":"điều khiển cho thiên kiếp ngày càng mạnh cũng chỉ vì bắt buộc tu sĩ phải vùng vẫy và có ý chí bất khuất","bridge":true,"khoang":"@c1263"},{"chuong":"@c1264","importance":"normal","tieuDe":"Bỏ chạy bị giết","text":"Tu sĩ họ Chu che kiếp vân để ngăn ánh mắt bên dưới, ra lệnh động thủ và giết hai tu sĩ Anh Biến mới tới. Sau khi Trương Cảnh Vân bị Vương Lâm giết, hắn hoảng sợ bỏ chạy nhưng cuối cùng bị tia chớp hồng sắc của Cực cảnh đánh chết.","anchor":"Chỉ là tu sĩ Vấn Đỉnh mà dám tự so mình với thiên đạo, Thiểm Lôi Tộc cuồng vọng, đây chính là nguyên nhân của sự diệt tộc."}],"tuViMoc":[{"chuong":"@c1264","canhGioi":"Vấn Đỉnh","text":"Tu sĩ họ Chu được xếp trong ba tu sĩ Vấn Đỉnh còn lại của nhóm Thiểm Lôi Tộc.","importance":"major"}],"nhanMach":[{"ten":"Trương Cảnh Vân","tag":"dong-minh","quanHe":"Đồng bọn trong nhóm giả thiên kiếp.","ghiChu":"Cùng bao vây người mới đến bảy trăm vạn thiên địa."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giết chết hắn bằng Cực cảnh.","ghiChu":"Tu sĩ họ Chu bỏ chạy nhưng bị Vương Lâm diệt sát."}],"tuiDo":{}},"nguon":["@c1263","@c1264"]},{"id":"trieu-tien-boi","name":"Triệu tiền bối","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Âm Hư","trangThai":"song","blurb":"Tu sĩ cảnh giới Âm Hư trong nhóm Trương Cảnh Vân, chỉ cần tiến thêm một bước là Dương Thực, là chỗ dựa sức mạnh của nhóm.","vaiTro":"Cao thủ nhóm Trương Cảnh Vân, chỗ dựa sức mạnh","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Tu vi Âm Hư, chỉ cần tiến thêm một bước là Dương Thực, là chỗ dựa cho nhóm Trương Cảnh Vân lừa người mới thu niệm lôi","chuong":"@c1263"}],"kinhLich":[{"chuong":"@c1263","importance":"bridge","mucCt":"gon","text":"Được nhóm Trương Cảnh Vân nhắc đến qua truyền âm như chỗ dựa sức mạnh khi bàn mưu lừa người mới.","anchor":"tu vi của Triệu tiền bối đã là Âm Hư, chỉ cần tiến thêm một bước nữa thì sẽ lên Dương Thực"}],"tuViMoc":[{"chuong":"@c1263","canhGioi":"Âm Hư","text":"Tu vi đạt Âm Hư, chỉ cần tiến thêm một bước nữa là Dương Thực","importance":"major"}],"nhanMach":[],"tuiDo":{}},"nguon":["@c1263"]},{"id":"tan-linh-thuong-nhan","name":"Tán Linh Thượng Nhân","cn":"散灵上人","aliases":["Tán Linh","thanh niên đầu láng","thanh niên đầu trọc láng bóng","Tán Linh đạo hữu"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1274","trangThai":"song","blurb":"Thanh niên đầu trọc láng bóng, vẻ mặt hiền lành, tồn tại hơn vạn năm trong bảy trăm vạn thiên địa, tu vi đạt tới Thiên Nhân Tứ Suy — điều gần như bất khả trong thế giới bị phong tỏa bởi sấm sét bất diệt. Sau khi phá phong hộ tu chân tinh lần đầu nhìn thấy tinh không và phát hiện chân tướng thế giới, y lập Tán Linh Tông chiêu mộ tộc nhân phản kháng, mở Tuyệt Thiên trận đối đầu sấm sét bất diệt, rồi dẫn tộc nhân thoát khỏi thiên địa đang sụp đổ vào Thái Cổ Tinh Thần, thề trung thành với Vương Lâm.","vaiTro":"Thủ lĩnh Tán Linh Tông — cường giả bí ẩn phản kháng sấm sét bất diệt trong bảy trăm vạn thiên địa","tinhCach":"Hiền lành bề ngoài nhưng tự tin cao độ; bình thản, quan sát sắc bén trước cường giả; kiên định phản kháng, sẵn sàng hy sinh vì tộc nhân","tabs":{"diem":[{"text":"Hiện thân sau khi Vương Lâm rời đi, xin mang thi thể tu sĩ Âm Hư, bộc lộ sự tồn tại dị thường","chuong":"@c1264"},{"text":"Bị Vương Lâm phát hiện khi ẩn trong hư không theo dõi, bị tia chớp đỏ kích bản thể hiện ra và xưng danh Tán Linh","chuong":"@c1267"},{"text":"Tiết lộ chân tướng thế giới cho Vương Lâm, kể lại việc phá phong hộ tu chân tinh và lập Tán Linh Tông phản kháng","chuong":"@c1268"},{"text":"Mở Tuyệt Thiên trận, dùng thân thể tộc nhân Thiểm Lôi Tộc bị phong ấn làm mảng lưới ánh sáng chịu sấm sét bất diệt","chuong":"@c1271"},{"text":"Dẫn tộc nhân thoát khỏi bảy trăm vạn thiên địa đang sụp đổ vào Thái Cổ Tinh Thần, tuyên thệ trung thành với Vương Lâm","chuong":"@c1273"},{"text":"Được liệt kê là phách thứ sáu của Vương Lâm, thuộc nhóm đã xảy ra biến số","chuong":"@c1653"}],"kinhLich":[{"chuong":"@c1264","importance":"major","tieuDe":"Dị thường hiện thân","text":"Tán Linh Thượng Nhân hiện thân sau khi Vương Lâm rời đi, xin mang thi thể tu sĩ Âm Hư và nói bất kỳ ai trong bảy trăm vạn thiên địa giống hắn thì chính là hắn. Hắn nhìn theo hướng Vương Lâm, nhận xét Vương Lâm khác những kẻ tự xưng thiên đạo và có lẽ không phải nô lệ của sấm sét, trong khi tu vi của hắn mơ hồ đạt Tịnh Niết, vượt khỏi giới hạn bình thường của nơi này.","anchor":"Đúng vậy, bất kỳ người nào trong bảy trăm vạn thiên địa này giống như ta, thì đó chính là ta."},{"mucCt":"vua","text":"Ẩn trong hư không theo dõi Vương Lâm giết tộc nhân Thiểm Lôi Tộc. Bị Vương Lâm phát hiện, chĩa tia chớp đỏ cực cảnh ép lộ diện, xuất hiện trong những con sóng gợn khi bầu trời vặn vẹo. Vương Lâm yêu cầu giải thích lý do theo dõi, đe dọa sẽ giết nếu không thỏa mãn.","anchor":"người thanh niên đầu láng trước đó đã lấy đi thi thể Thiểm Lôi Tộc, người được tu sĩ bảy trăm vạn thiên địa gọi là Tán Linh Thượng Nhân xuất hiện trong những con sóng gợn","bridge":true,"khoang":"@c1266"},{"chuong":"@c1267","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện trước Vương Lâm, tiết lộ chân tướng thế giới","text":"Bị Vương Lâm phóng tia chớp hồng sắc xuyên mi tâm kích bản thể thật hiện ra, xưng danh Tán Linh, tồn tại hơn vài vạn năm. Kể toàn bộ lai lịch: trăm năm Hóa Thần nghi ngờ Tiên nhân, bị đại trưởng lão Thiểm Lôi Tộc phế tu vi nhưng giữ mạng để tăng cơ hội sinh Linh Niệm Lôi. Tự sáng tạo thuật Tán Linh chia tu vi vào 971 phân thân tránh thiên kiếp, tu đến Toái Niết. Phát hiện bảy trăm vạn thiên địa là lao ngục do người khác tạo ra, sinh mạng chỉ là kiến hôi để sưu tập Linh Niệm Lôi. Nhìn thi thể Tiên nhân thối rữa mà tỉnh ngộ hoàn toàn, quyết tâm phá lao ngục. Đề nghị giao dịch với Vương Lâm, cùng phá hư không phóng về tận cùng thế giới.","anchor":"Lão phu tên là Tán Linh, đã tồn tại hơn vài vạn năm, tu vi đạt đến Thiên Nhân Tứ Suy"},{"importance":"normal","mucCt":"ky","chuong":"@c1268","tieuDe":"Tiết lộ chân tướng và lập Tán Linh Tông phản kháng","text":"Kể cho Vương Lâm toàn bộ chân tướng: từng phá phòng hộ tu chân tinh lần đầu thấy tinh không, phát hiện tu sĩ Hóa Thần Thiểm Lôi Tộc hóa thân thiên đạo hàng lâm thiên kiếp giết tộc nhân, giết tu sĩ Thiểm Lôi Tộc rồi biết bảy trăm vạn thiên địa là ngục tù nuôi tu sĩ lấy Linh Niệm Lôi. Ban đầu sợ hãi trốn chạy, bay đến tận cùng thế giới nơi có bức tường ngăn cách khổng lồ cao vô tận, mọi ý niệm trốn tránh tan vỡ, quyết tâm phản kháng. Quay về lập Tán Linh Tông, mỗi phân thân đều là Tán Linh Thượng Nhân để truyền bá ý niệm và truyền công pháp giúp tu sĩ nhanh đạt Hóa Thần. Sau vài ngàn năm đạt Thiên Nhân Tứ Suy nhưng vẫn không thắng được đại trưởng lão Thiên Nhân Ngũ Suy. Cầu xin Vương Lâm liên thủ, hứa tặng toàn bộ Linh Niệm Lôi, toàn tộc nghe lệnh, giúp đánh Nội giới, nói bảy phần nắm chắc. Tự hủy mấy vạn phân thân ngưng tụ thành linh phù huyết sắc trao cho Vương Lâm.","anchor":"Ta không trốn tránh, ta phải đối mặt, phải phản kháng!"},{"chuong":"@c1271","importance":"major","mucCt":"ky","tieuDe":"Mở Tuyệt Thiên trận","text":"Tán Linh dùng thân thể tộc nhân Thiểm Lôi Tộc bị phong ấn làm mảng lưới ánh sáng để chịu sấm sét bất diệt, rồi hiện thân cùng Vương Lâm phá luồng lôi truy kích ban đầu. Trước đại trưởng lão Thiểm Lôi Tộc, hắn tuyên bố sống tới nay là để phá thiên địa giả và báo thù cho đời đời sinh linh bảy trăm vạn thiên địa, sau đó thi triển bảy trăm vạn giết tiên ấn, Băng Diệt Thuật và mở đại trận hàng tỷ sinh linh. Khi thánh lôi bất diệt bị gió bão ý niệm ngăn lại, hắn dung hợp với bảy trăm vạn thiên địa như trận linh, ngưng Trảm Thiên kiếm giao cho Vương Lâm chém bảy kiếm.","anchor":"Đạo hữu, lão phu dùng tính mệnh sinh linh bảy trăm vạn thiên địa, dùng tất cả đại lục bố trí ra Tuyệt Thiên trận phong ấn bát hoang, đồng thời cũng ngưng tụ ra Trảm Thiên kiếm."},{"mucCt":"vua","text":"Phong ấn gió bão bị sấm sét bất diệt phá vỡ, bị ép khỏi trạng thái dung hợp, phun máu trọng thương. Tuyên bố tiên giới đã mở, hất tay áo cuốn tất cả tộc nhân còn sống theo lỗ hổng hư vô thoát đi.","anchor":"tất cả tộc nhân, tất cả sinh linh, chúng ta cùng nhau phá vỡ Tiên giới","bridge":true,"khoang":"@c1272"},{"chuong":"@c1273","importance":"normal","mucCt":"vua","tieuDe":"Lập tiên tộc tại Thái Cổ Tinh Thần, thề trung thành với Vương Lâm","text":"Dẫn tộc nhân thoát khỏi bảy trăm vạn thiên địa đang sụp đổ vào Thái Cổ Tinh Thần, kích động rơi nước mắt, tuyên bố tộc mình từ nay là tiên nhân. Ôm quyền thề cả đời và đời đời kiếp kiếp không quên ơn Vương Lâm, toàn tộc trăm vạn người hưởng ứng. Giao hơn một vạn Linh Niệm Lôi cho Vương Lâm theo đúng thỏa thuận. Đồng ý tấn công Thiểm Lôi tộc để trả hận chín phần dân số phải chết.","anchor":"Ơn của đạo hữu, cả đời Tán Linh không quên, tất cả tiên tộc của ta, đời đời kiếp kiếp sẽ không bao giờ quên"},{"mucCt":"vua","text":"Tán Linh thượng nhân đi sau Vương Lâm, chứng kiến lôi vực và thần thông phá trận của hắn. Khi lôi long xé mở phòng hộ, ông theo sát tiến vào Thiểm Lôi tộc và bị một đội tu sĩ Thiên Nhân Suy Kiếp do Thiên Nhân Đệ Tứ Suy dẫn đầu ngăn cản.","anchor":"Ánh mắt Tán Linh thượng nhân lóe lên, hắn theo sát lôi long tiến từng bước vào trong Thiểm Lôi tộc","bridge":true,"khoang":"@c1274"},{"chuong":"@c1275","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc hành động","text":"Tán Linh thượng nhân được Vương Lâm nhắc trực tiếp rằng thế cục Thiểm Lôi Tộc đã loạn và tu vị của ông đủ để hành động.","anchor":"Tâm thần đám người này đã loạn, Tán Linh đạo hữu, với tu vị của ngươi thì đã đủ"}],"tuViMoc":[{"chuong":"@c1264","canhGioi":"Tịnh Niết (mơ hồ)","text":"Tu vi vượt qua Hóa Thần đỉnh phong, vượt qua Vấn Đỉnh, mơ hồ đạt Tịnh Niết — điều không thể xảy ra trong bảy trăm vạn thiên địa","importance":"major"},{"chuong":"@c1264","canhGioi":"gần Tịnh Niết","text":"Tu vi của Tán Linh Thượng Nhân được mô tả vượt qua Hóa Thần đỉnh phong, vượt qua Vấn Đỉnh và mơ hồ đạt đến Tịnh Niết.","importance":"major"},{"chuong":"@c1267","canhGioi":"Toái Niết","text":"Tu vi hiện tại đạt Toái Niết, trải qua quá trình Hóa Thần → Vấn Đỉnh → Tịnh Niết → Toái Niết nhờ thuật Tán Linh chia phân thân. Từng bị phế tu vi khi còn Hóa Thần, tu luyện lại hàng vạn năm. Phân thân nhỏ nhất cũng đạt Tịnh Niết hoặc Khuy Niết.","importance":"major"},{"chuong":"@c1268","canhGioi":"Thiên Nhân Tứ Suy","text":"Sau vài ngàn năm điên cuồng tu luyện phân thân trong bảy trăm vạn thiên địa, đạt Thiên Nhân Tứ Suy, nhưng vẫn không đủ sức thắng đại trưởng lão Thiểm Lôi Tộc ở Thiên Nhân Ngũ Suy.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng quan sát","ghiChu":"Nhận xét Vương Lâm có lẽ không phải nô lệ của sấm sét"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đối tượng hợp tác","ghiChu":"Chủ động lộ diện trước Vương Lâm, đề nghị giao dịch có lợi cả hai bên, mời đến tận cùng thế giới"},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"doi-thu","quanHe":"Kẻ từng phế tu vi","ghiChu":"Năm xưa khi Tán Linh gặp thiên kiếp lần đầu, hắn (lúc đó Khuy Niết) phế tu vi Tán Linh nhưng giữ mạng để tăng cơ hội sinh Linh Niệm Lôi"},{"ten":"Tu sĩ Thiên Nhân Đệ Tứ Suy dẫn đội cản Tán Linh thượng nhân","tag":"doi-thu","quanHe":"bị đối phương dẫn đội ngăn cản","ghiChu":"Đối đầu sau khi tiến vào Thiểm Lôi tộc ở @c1274"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1264","@c1266","@c1267","@c1268","@c1271","@c1272","@c1273","@c1274","@c1275"]},{"id":"nu-tu-tuong-mao-tuyet-voi","name":"Nữ tu tướng mạo tuyệt vời","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tu có tướng mạo tuyệt vời bị Hứa Lập Quốc giam cầm trên ngai vàng. Lạnh lùng căm hận, mắng Hứa Lập Quốc chỉ là khí linh, tự tin đe dọa sẽ diệt sạch cả chủ nhân hắn bất kể thân phận hay tu vi, hàm ý lai lịch cực lớn.","vaiTro":"Nữ tu bí ẩn bị Hứa Lập Quốc giam cầm, hàm ý có lai lịch rất lớn","tinhCach":["Lạnh lùng, kiêu ngạo","Tự tin tuyệt đối vào thế lực đứng sau"],"tabs":{"diem":[{"text":"Bị giam cầm nhưng không sợ hãi, đe dọa sẽ diệt sạch cả chủ nhân Hứa Lập Quốc bất kể thân phận hay tu vi","chuong":"@c1264"},{"text":"Bị Hứa Lập Quốc giam cầm nhưng không hề sợ hãi, mắng hắn chỉ là khí linh, đe dọa cả chủ nhân hắn bất kể thân phận hay tu vi gì cũng phải chết.","chuong":"@c1264"}],"kinhLich":[{"chuong":"@c1264","importance":"normal","mucCt":"vua","tieuDe":"Bị Hứa Lập Quốc giam cầm, đe dọa sẽ diệt sạch","text":"Lạnh lùng ngồi trên ngai vàng Hứa Lập Quốc, dùng ánh mắt căm hận nhìn chằm chằm, mắng hắn chỉ là khí linh, đe dọa cả chủ nhân hắn bất kể thân phận hay tu vi gì cũng chắc chắn phải chết.","anchor":"Ngươi chỉ là một khí linh mà dám giam cầm ta, ngươi đã rước lấy tai họa ngập đầu rồi"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Kẻ giam cầm nàng","ghiChu":"Mắng hắn chỉ là khí linh, thề diệt cả chủ nhân"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1264"]},{"id":"nguoi-dan-ong-trung-nien-moi-nhu","name":"Người đàn ông trung niên (mồi nhử)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Hóa Thần đỉnh phong","trangThai":"song","blurb":"Phàm nhân tu sĩ hạ giới, tu vi Hóa Thần đỉnh phong, tướng mạo anh tuấn gương mặt chính trực. Bị Vương Lâm biến thành mồi nhử để dụ Tiên nhân Thiểm Lôi Tộc đến qua kiếp vân.","vaiTro":"Phàm nhân tu sĩ bị Vương Lâm dùng làm mồi nhử dụ Tiên nhân","tinhCach":"Chính trực; sợ hãi trước cảnh tàn sát; mỉa mai về bản chất thành tiên","tabs":{"diem":[{"text":"Tu sĩ Hóa Thần đỉnh phong, tướng mạo anh tuấn, bị Vương Lâm biến thành mồi nhử dụ Tiên nhân Thiểm Lôi Tộc đến qua kiếp vân","chuong":"@c1266"}],"kinhLich":[{"mucCt":"vua","text":"Đang ngồi khoanh chân trong đồng bằng tuyết trắng chờ thiên kiếp, bị Vương Lâm sai tản tu vi tiếp tục độ kiếp để dụ Tiên nhân Thiểm Lôi Tộc. Nhìn thấy Vương Lâm giết hàng loạt hơn một trăm tộc nhân, sợ hãi nhắm mắt không dám nhìn.","anchor":"lúc này hắn mới biết mình trở thành mồi nhử Tiên nhân cho người thanh niên áo trắng","bridge":true,"khoang":"@c1266"}],"tuViMoc":[{"chuong":"@c1266","canhGioi":"Hóa Thần đỉnh phong","text":"Tu vi Hóa Thần đỉnh phong, không thể áp chế, đang chờ thiên kiếp","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị Vương Lâm dùng làm mồi nhử","ghiChu":"@c1266"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1266"]},{"id":"tien-nhan-kiep-van","name":"Tiên nhân trên kiếp vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết hậu kỳ đại viên mãn","trangThai":"tu-vong","blurb":"Lão già Tiên nhân thuộc Thiểm Lôi Tộc, tu vi Khuy Niết hậu kỳ đại viên mãn sắp đột phá Tịnh Niết. Khi đứng trên kiếp vân bao phủ tiên khí để độ kiếp thành tiên, lão dùng hạt châu lôi quang tấn công Vương Lâm nhưng bị Vương Lâm giết chết, hình thần câu diệt.","vaiTro":"Tiên nhân Thiểm Lôi Tộc bị Vương Lâm giết khi đến độ kiếp","tinhCach":"Kiêu ngạo; tức giận khi bị cướp mục tiêu","tabs":{"diem":[{"text":"Tu vi Khuy Niết hậu kỳ đại viên mãn, sắp đột phá Tịnh Niết","chuong":"@c1266"},{"text":"Đứng trên kiếp vân bao phủ tiên khí, tuyên bố độ kiếp thành tiên","chuong":"@c1266"},{"text":"Dùng hạt châu lôi quang tấn công Vương Lâm nhưng bị giết, hình thần câu diệt","chuong":"@c1266"}],"kinhLich":[{"chuong":"@c1266","importance":"major","mucCt":"gon","tieuDe":"Bị Vương Lâm giết trên kiếp vân","text":"Đứng trên kiếp vân bao phủ tiên khí, tuyên bố độ kiếp thành tiên, dùng hạt châu lôi quang tấn công Vương Lâm nhưng bị điểm một ngón tay vào ót, hình thần câu diệt, tộc ấn bị thu.","anchor":"toàn thân bùng ra khí tức Khuy Niết hậu kỳ đại viên mãn, mơ hồ sắp đột phá lên Tịnh Niết"}],"tuViMoc":[{"chuong":"@c1266","canhGioi":"Khuy Niết hậu kỳ đại viên mãn","text":"Tu vi Khuy Niết hậu kỳ đại viên mãn, sắp đột phá Tịnh Niết","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm giết, tộc ấn bị thu","ghiChu":"@c1266"}],"tuiDo":{"phapBao":[{"ten":"Hạt châu lôi quang","loai":"phap-bao","trangThai":"mat","moTa":"Do năm luồng niệm lôi hóa thành, bị Vương Lâm bóp nát hấp thu niệm lôi","nguon":"@c1266"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1266"]},{"id":"lao-gia-ao-bao-den-toai-niet","name":"Lão già áo bào đen (Toái Niết)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết","trangThai":"tu-vong","blurb":"Tu sĩ Toái Niết Thiểm Lôi Tộc, dùng thuật phân thân bỏ chạy nhưng bị Vương Lâm dùng tia chớp đỏ cực cảnh hủy diệt nguyên thần.","vaiTro":"Tu sĩ Toái Niết Thiểm Lôi Tộc bị Vương Lâm giết","tinhCach":"Kinh hoàng trước cảnh tàn sát; phản ứng nhanh dùng phân thân bỏ chạy","tabs":{"diem":[{"text":"Tu sĩ Toái Niết Thiểm Lôi Tộc dùng thuật phân thân bỏ chạy nhưng bị Vương Lâm hủy diệt","chuong":"@c1266"}],"kinhLich":[{"mucCt":"gon","text":"Từ lỗ hổng kiếp vân phóng ra, thấy cảnh tàn sát liền tấn công đồng thời dùng thuật phân thân bỏ chạy, bị Vương Lâm dùng tia chớp đỏ xuyên qua cả phân thân và bản thể, nguyên thần bị hủy diệt, tộc ấn bị thu.","anchor":"Khoảnh khắc này thân thể lão già áo bào đen một phân thành hai, một hư ảnh phóng về phía Vương Lâm, một hư ảnh khác mang theo vẻ kinh hoàng mà điên cuồng lui về phía sau","bridge":true,"khoang":"@c1266"}],"tuViMoc":[{"chuong":"@c1266","canhGioi":"Toái Niết","text":"Tu vi Toái Niết","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm giết, nguyên thần hủy diệt","ghiChu":"@c1266"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1266"]},{"id":"co-gai-xinh-dep-thiem-loi-toc","name":"Cô gái xinh đẹp (Thiểm Lôi Tộc)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Con nuôi của cường giả Toái Niết viên mãn Thiểm Lôi Tộc, bị Hứa Lập Quốc bắt cóc làm con tin trong lúc hắn bỏ chạy khỏi lãnh địa Thiểm Lôi Tộc.","vaiTro":"Con tin bị Hứa Lập Quốc bắt giữ","tinhCach":["Nóng nảy, dám đe dọa kẻ bắt cóc nhưng bị khuất phục khi bị đe dọa đoạt xá"],"tabs":{"diem":[{"text":"Bị Hứa Lập Quốc bắt cóc làm lá chắn, bị sỉ nhục và đe dọa đoạt xá","chuong":"@c1269"},{"text":"Bị Hứa Lập Quốc bắt giữ làm con tin và lá chắn trong lúc bỏ chạy khỏi Thiểm Lôi Tộc, bị sỉ nhục và đe dọa đoạt xá","chuong":"@c1269"}],"kinhLich":[{"chuong":"@c1269","importance":"normal","mucCt":"vua","tieuDe":"Bị bắt cóc làm con tin","text":"Bị Hứa Lập Quốc hóa sương đen quấn quanh bắt giữ, bị dùng làm lá chắn chống trả trưởng lão truy kích. Bị đe dọa đoạt xá, sau được cha nuôi (Toái Niết viên mãn) giải cứu.","anchor":"đoạt xá rất dễ. sau khi đoạt xá ta sẽ cỡi quần áo"}],"tuViMoc":[],"nhanMach":[{"ten":"Người đàn ông trung niên đạo bào xanh (Thiểm Lôi Tộc)","tag":"cha-me","quanHe":"Cha nuôi","ghiChu":"Cường giả Toái Niết viên mãn @c1269"},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Bị bắt cóc","ghiChu":"Bị bắt giữ làm con tin, bị đe dọa đoạt xá @c1269"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1269"]},{"id":"lao-gia-ao-xanh-thiem-loi-toc","name":"Lão già áo xanh (Thiểm Lôi Tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết","trangThai":"tu-vong","blurb":"Trưởng lão Thiểm Lôi Tộc cảnh giới Tịnh Niết, truy kích Hứa Lập Quốc nhưng bị Vương Lâm giết chết chỉ bằng một chỉ điểm lên mi tâm.","vaiTro":"Trưởng lão Thiểm Lôi Tộc, bị Vương Lâm giết","tinhCach":["Nóng nảy, dễ bị khiêu khích; trung thành với Thiểm Lôi Tộc"],"tabs":{"diem":[{"text":"Bị Hứa Lập Quốc liên tục chửi bới khiêu khích đến tức giận sôi máu, cuối cùng bị Vương Lâm điểm mi tâm diệt vong","chuong":"@c1269"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c1269","canhGioi":"Tịnh Niết","text":"Được xác nhận cảnh giới Tịnh Niết khi truy kích Hứa Lập Quốc.","importance":"major"}],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Truy kích","ghiChu":"Truy sát Hứa Lập Quốc bắt cóc con nuôi cường giả @c1269"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị giết","ghiChu":"Bị Vương Lâm điểm mi tâm diệt vong @c1269"},{"ten":"Người đàn ông trung niên đạo bào xanh (Thiểm Lôi Tộc)","tag":"dong-minh","quanHe":"Đồng môn","ghiChu":"Cùng truy kích Hứa Lập Quốc @c1269"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1269"]},{"id":"nguoi-dan-ong-trung-nien-dao-bao-xanh-thiem-loi-toc","name":"Người đàn ông trung niên đạo bào xanh (Thiểm Lôi Tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết viên mãn","trangThai":"song","blurb":"Cường giả Toái Niết viên mãn của Thiểm Lôi Tộc, cha nuôi của cô gái bị Hứa Lập Quốc bắt cóc. Tra tấn Hứa Lập Quốc nhưng khiếp sợ trước sức mạnh của Vương Lâm.","vaiTro":"Cường giả Thiểm Lôi Tộc, cha nuôi cô gái","tinhCach":["Tàn nhẫn, tra tấn kẻ thù bằng cách liên tục đánh tan rã rồi khôi phục; bảo vệ con nuôi"],"tabs":{"diem":[{"text":"Cường giả Toái Niết viên mãn, tra tấn Hứa Lập Quốc bằng cách liên tục đánh tan rã thân thể rồi khôi phục","chuong":"@c1269"},{"text":"Thần thức không thể phát hiện Vương Lâm, khiếp sợ muốn bỏ trốn khi chứng kiến Vương Lâm giết trưởng lão Tịnh Niết bằng một chỉ","chuong":"@c1269"}],"kinhLich":[{"chuong":"@c1269","importance":"normal","mucCt":"ky","tieuDe":"Tra tấn Hứa Lập Quốc và đối diện Vương Lâm","text":"Xuất hiện đột ngột trước mặt Hứa Lập Quốc, vung tay đánh tan thân thể hắn thành bốn năm phần. Liên tục làm tan rã rồi khôi phục thân thể Hứa Lập Quốc để tra tấn. Khi Vương Lâm xuất hiện giết chết lão già áo xanh Tịnh Niết chỉ bằng một chỉ, thần thức đã tản ra nhưng không thể phát hiện Vương Lâm, khiếp sợ giữ chặt cô gái muốn bỏ trốn.","anchor":"Ta cũng không muốn giết ngươi ngay, mà muốn ngươi liên tục tan rã để gặm nhấm nổi sợ hãi của cái chết"}],"tuViMoc":[{"chuong":"@c1269","canhGioi":"Toái Niết viên mãn","text":"Được xác nhận cảnh giới Toái Niết viên mãn khi xuất hiện trước mặt Hứa Lập Quốc.","importance":"major"}],"nhanMach":[{"ten":"Cô gái xinh đẹp (Thiểm Lôi Tộc)","tag":"cha-me","quanHe":"Con nuôi","ghiChu":"Cha nuôi của cô gái @c1269"},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Tra tấn","ghiChu":"Liên tục đánh tan rã thân thể Hứa Lập Quốc @c1269"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu, khiếp sợ","ghiChu":"Thần thức không phát hiện được Vương Lâm, muốn bỏ trốn @c1269"},{"ten":"Lão già áo xanh (Thiểm Lôi Tộc)","tag":"dong-minh","quanHe":"Đồng môn","ghiChu":"Cùng truy kích Hứa Lập Quốc @c1269"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1269"]},{"id":"dai-truong-lao-thiem-loi-toc","name":"Đại trưởng lão Thiểm Lôi Tộc","cn":"","aliases":["Đại trưởng lão Luyện Hồn Phong","Đại trưởng lão Thiểm Lôi tộc","Đại trưởng lão"],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Ngũ Suy @c1278","trangThai":"khong-ro","blurb":"Đệ nhất cường giả Thiểm Lôi Tộc, tu luyện trong sấm sét bất diệt nơi miếu thờ thánh địa với phong ấn tu vi Thiên Nhân Đệ Tứ Suy viên mãn. Sau khi Vương Lâm công khai khiêu chiến, ông xé phong ấn bùng ra Đệ Ngũ Suy truy sát nhưng sa vào sát cục, tự bạo tộc ấn thi triển Tam Tức Thuật rồi bị kiếm đâm xuyên nguyên thần. Tàn thần của ông bị Vương Lâm thu lại, vơ vét làm nguồn minh ngộ lôi pháp, cuối cùng thất bại mất tích sau khi cả tộc bị tiêu diệt.","vaiTro":"Đại trưởng lão và đệ nhất cường giả Thiểm Lôi Tộc, đối thủ chính của Vương Lâm","tinhCach":"Cay nghiệt, quyết liệt trong truy sát; kiên cường không lùi bước khi thất thế; sẵn sàng tự bạo tộc ấn để liều mạng cùng địch","tabs":{"diem":[{"text":"Đệ nhất cường giả và đại trưởng lão Thiểm Lôi Tộc, tu luyện trong sấm sét bất diệt nơi thánh địa","chuong":"@c1270"},{"text":"Xé phong ấn cuối cùng trên tộc ấn mi tâm bùng rau vi Thiên Nhân Đệ Ngũ Suy","chuong":"@c1270"},{"text":"Nhận ra trận truy sát Vương Lâm trong bảy trăm vạn thiên địa là một sát cục","chuong":"@c1271"},{"text":"Tự bạo tộc ấn thi triển Tam Tức Thuật, bị kiếm thứ bảy đâm xuyên nguyên thần","chuong":"@c1272"},{"text":"Nguyên thần bị Vương Lâm tính làm nguồn chứa minh ngộ sấm sét để vơ vét","chuong":"@c1276"},{"text":"Thất bại mất tích sau biến cố cả tộc Thiểm Lôi bị tiêu diệt","chuong":"@c1278"}],"kinhLich":[{"chuong":"@c1270","importance":"major","mucCt":"ky","tieuDe":"Truy sát Vương Lâm","text":"Đại trưởng lão Thiểm Lôi Tộc hiện thân từ sấm sét bất diệt sau khi Vương Lâm công khai khiêu chiến, ra lệnh cao thủ trong tộc ở lại phòng thủ rồi truy vào lôi vực. Hắn dùng lôi long ý chí, Lôi Sát Kính và Tụ Lôi Ấn áp đảo nguyên thần Vương Lâm, nhưng bị bản thể Vương Lâm, huyết kiếm, Cực Cảnh, Quang Ảnh Thuẫn và lôi bản nguyên phản kích tới trọng thương. Sau đó hắn bùng tu vi Thiên Nhân Đệ Ngũ Suy, mở thái cổ lôi giới triệu tám hồn phách Thái Cổ Lôi Long, ép chúng tự bạo làm Côn Cực Tiên lộ bản chất Vạn Giới Phong Hồn Tiên. Khi Vương Lâm thôn phệ hồn phách Lôi Long và định rút đi, hắn hiến tế năm trăm năm thọ nguyên gọi Hồn Độn Bất Diệt Lôi, rồi đuổi theo vào hắc động đi tới bảy trăm vạn thiên địa.","anchor":"Tuyệt đối không thể để hắn tiếp tục"},{"chuong":"@c1271","importance":"major","mucCt":"ky","tieuDe":"Bị vây Trảm Thiên","text":"Đại trưởng lão Thiểm Lôi Tộc truy sát Vương Lâm vào bảy trăm vạn thiên địa và nhận ra đây là sát cục do Vương Lâm cùng Tán Linh chuẩn bị. Hắn liên tục tiêu hao thọ nguyên và truyền thừa để thi triển Thiên Nhân Đệ Ngũ Suy, Lôi Vân Chấn, Lục Đạo Thần Lôi, gọi thánh lôi bất diệt, mở Thiểm Lôi ấn, dùng sấm sét âm dương bất diệt và Nam Đẩu thuật hóa Cửu Kiếp Sa Tinh chống lại Trảm Thiên kiếm. Dù nhiều lần dựng phòng hộ và cầu sinh, hắn bị các kiếm Trảm Thiên phá giáp truyền thừa, chém trọng thương, nổ mất nửa thân dưới rồi phải bỏ chạy và khôi phục thân thể bằng pháp quyết.","anchor":"Đừng hòng có kẻ nào giết được lão phu, lão phu hiến tế ba ngàn năm thọ nguyên, mở ra Thiểm Lôi ấn hóa thành thuật thần thông của tổ tiên Đệ Tam Bộ Thiểm Lôi tộc."},{"chuong":"@c1272","importance":"major","mucCt":"ky","tieuDe":"Tự bạo tộc ấn, thi triển Tam Tức Thuật, bị kiếm thứ bảy đâm xuyên nguyên thần","text":"Bị kiếm thứ sáu dẫn oan hồn thôn phệ toàn bộ máu thịt xương cốt, chỉ còn nguyên thần. Cho nổ tộc ấn trên mi tâm nguyên thần, tu vi tăng vọt, thân thể sấm sét tái tạo, giết sạch oan hồn. Thi triển Tam Tức Thuật hút thọ nguyên Vương Lâm. Bị kiếm thứ bảy đâm xuyên nguyên thần, thân thể sấm sét tan vỡ. Gầm gọi sấm sét bất diệt cứu viện, sấm sét phá vỡ phong ấn gió bão nhưng không cứu được bản thân. Nguyên thần sắp tử vong, bị Côn Cực Tiên nhắm tới.","anchor":"Sấm sét bất diệt, cứu. cứu ta!"},{"chuong":"@c1273","importance":"bridge","mucCt":"gon","text":"Nguyên thần bị tàn phá hơn phân nửa, trí nhớ tiêu tán, bị Vương Lâm dùng Côn Cực Tiên thu lại.","anchor":"nguyên thần của đại trưởng lão Thiểm Lôi tộc có thể so sánh với những bảo vật cực kỳ quý giá"},{"chuong":"@c1274","importance":"normal","tieuDe":"Tàn thần bị phơi","mucCt":"vua","text":"Đại trưởng lão Thiểm Lôi tộc trở thành điểm tựa tinh thần cuối cùng khiến tộc nhân cố thủ trước Vương Lâm. Cuối chương, Côn Cực Tiên của Vương Lâm quấn tàn thần nguyên thần đã bị hủy hoại của ông, khiến lời tuyên bố ông đã bại trở thành bằng chứng trực diện.","anchor":"thân roi đang quấn quanh một tàn thần, chính là một nguyên thần đã bị hủy hoại và nó đúng là đại trưởng lão Thiểm Lôi tộc"},{"mucCt":"vua","text":"Đại trưởng lão Thiểm Lôi Tộc xuất hiện dưới dạng tàn thần bị Côn Cực Tiên quấn quanh trong tay Vương Lâm. Tình trạng thân thể tan vỡ và nguyên thần sắp tiêu tán của ông khiến tộc nhân Thiểm Lôi Tộc sụp đổ niềm tin.","anchor":"Đại trưởng lão đã tan vỡ thân thể, ngay cả nguyên thần cũng chuẩn bị tiêu tán chỉ còn một tàn thần","bridge":true,"khoang":"@c1275"},{"chuong":"@c1276","importance":"normal","mucCt":"gon","tieuDe":"Minh ngộ lôi pháp","text":"Nguyên thần của đại trưởng lão được Vương Lâm tính là nguồn chứa minh ngộ sấm sét để vơ vét, phối hợp với sấm sét bất diệt và hồn phách tám Thái Cổ Lôi Long nhằm khiến lôi bản nguyên đại thành.","anchor":"vơ vét những minh ngộ về sấm sét trong nguyên thần đại trưởng lão"},{"chuong":"@c1278","importance":"bridge","tieuDe":"Thất bại mất tích","mucCt":"vua","text":"Đại trưởng lão Thiểm Lôi Tộc bị nhắc là đã thất bại và mất tích sau biến cố cả tộc bị tiêu diệt.","anchor":"Nghe nói đại trưởng lão Thiểm Lôi Tộc đã đạt đến tu vi Thiên Nhân Đệ Ngũ Suy"},{"chuong":"@c1280","importance":"normal","mucCt":"vua","tieuDe":"Nguyên thần bị nuốt","text":"Nguyên thần của đại trưởng lão Thiểm Lôi Tộc bị Vương Lâm lấy ra và nuốt để hấp thu các loại sấm sét. Sau khi thôn phệ, nguyên thần sấm sét trong cơ thể Vương Lâm biến hóa thành hình dạng của hắn.","anchor":"Đây là nguyên thần của đại trưởng lão Thiểm Lôi tộc, lúc này hai mắt hắn đang nhắm chặt"},{"mucCt":"gon","text":"Đại trưởng lão Thiểm Lôi tộc được tộc trưởng Long Giáp Tộc nhắc lại như người đã bị Vương Lâm giết trong biến cố hủy diệt Thiểm Lôi tộc.","anchor":"người này chính là người đã hủy dệt Thiểm Lôi tộc, giết đại trưởng lão Thiểm Lôi tộc","bridge":true,"khoang":"@c1290"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Thiên Nhân Đệ Ngũ Suy","text":"Xé phong ấn cuối cùng trên tộc ấn mi tâm bùng ra tu vi Thiên Nhân Đệ Ngũ Suy để sống sót trước phản kích của Vương Lâm. Bình thường phong ấn ở Thiên Nhân Đệ Tứ Suy viên mãn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù sinh tử","ghiChu":"Đại chiến trong lôi vực, hai bên đều trọng thương, đuổi theo Vương Lâm vào hắc động."},{"ten":"Lão già hắc y (Thiên Nhân Đệ Nhất Suy)","tag":"dong-minh","quanHe":"Thuộc hạ cùng tộc","ghiChu":"Lão già hắc y bị Vương Lâm trọng thương, đại trưởng lão sai người cứu."},{"ten":"Người đàn ông trung niên cao lớn (Thiên Nhân Đệ Tam Suy)","tag":"dong-minh","quanHe":"Thuộc hạ cùng tộc","ghiChu":"Được đại trưởng lão sai ở lại bảo vệ thánh địa."},{"ten":"Tán Linh Thượng Nhân","tag":"doi-thu","quanHe":"đối thủ báo thù","ghiChu":"Tán Linh nhận hắn là đại diện Thiểm Lôi Tộc phải trả giá cho bảy trăm vạn thiên địa và mở Tuyệt Thiên trận để vây giết hắn."},{"ten":"Tổ tiên Đệ Tam Bộ Thiểm Lôi Tộc","tag":"ho-hang","quanHe":"tổ tiên truyền thừa","ghiChu":"Đại trưởng lão dùng bộ giáp sấm sét bất diệt và thần thông tổ tiên do vị đại năng Đệ Tam Bộ Thiểm Lôi Tộc để lại."},{"ten":"Thái Cổ Lôi Long","tag":"khac","quanHe":"hồn phách được triệu hoán","ghiChu":"Ông mở Thái cổ lôi giới gọi tám hồn Thái Cổ Lôi Long vây công Vương Lâm."},{"ten":"Thủ lĩnh đám tu sĩ thần bí năm xưa","tag":"khac","quanHe":"người từng chứng kiến","ghiChu":"Thời còn Hóa Thần, ông từng thấy người này cầm roi vạn giới phong hồn."},{"ten":"Lão tổ Thiểm Lôi Tộc","tag":"khac","quanHe":"lão tổ được nhắc tới","ghiChu":"Ông liên hệ Vạn Giới Phong Hồn Tiên với anh linh lão tổ và biến cố năm xưa."},{"ten":"Lão già hắc y Thiên Nhân Đệ Nhất Suy của Thiểm Lôi Tộc","tag":"dong-minh","quanHe":"cao thủ cùng tộc được cứu nguyên thần","ghiChu":"Sau khi lão già hắc y bị Vương Lâm đánh tan thân thể, phe đại trưởng lão cứu lại nguyên thần."},{"ten":"Người đàn ông trung niên cao lớn Thiểm Lôi Tộc","tag":"dong-minh","quanHe":"cao thủ cùng tộc dưới quyền","ghiChu":"Người này khom người nghe lệnh khi đại trưởng lão hiện thân chỉ huy phòng thủ."},{"ten":"Tộc nhân Thiểm Lôi tộc trong đại trận","tag":"khac","quanHe":"trụ tinh thần của tộc nhân","ghiChu":"Niềm tin vào ông khiến tộc nhân tiếp tục thủ trận ở @c1274"}],"tuiDo":{"phapBao":[{"ten":"Lôi Sát Kính","loai":"Gương cổ","trangThai":"hong","moTa":"Bảo vật Thiểm Lôi Tộc, nhị phẩm Thứ Không Niết. Chiếc gương một mặt màu xanh, mặt sau ký hiệu sấm sét bất diệt. Phục chế mọi thần thông dưới Đệ Tam Bộ với uy lực ngang bản gốc. Bị huyết kiếm Vương Lâm chém vỡ do lực lượng Cổ Thần không thể bị phục chế.","nguon":"@c1270"}],"danDuoc":[],"congPhap":[{"ten":"Tụ Lôi Ấn","moTa":"Thần thông cốt lõi Thiểm Lôi Tộc, nén sấm sét 500 vạn lần thành lôi cầu siêu cô đặc.","nguon":"@c1270"},{"ten":"Thái Cổ Lôi Giới","moTa":"Dùng máu tu vi Đệ Ngũ Suy làm vật dẫn triệu hoán hồn phách tám Thái Cổ Lôi Long trưởng thành đã chết, gần tiếp cận Đệ Tam Bộ đại năng.","nguon":"@c1270"},{"ten":"Sinh Mệnh Thần Thông","moTa":"Hy sinh thọ nguyên tản ra sinh cơ, cưỡng chế phát huy khí tức Đệ Tam Bộ đại năng. Hy sinh 500 năm thọ nguyên triệu la bàn khổng lồ hấp thu sinh cơ, rút sấm sét bất diệt tấn công.","nguon":"@c1270"},{"ten":"Ý chí sấm sét","moTa":"Ẩn giấu ý chí trong sấm sét do lôi long hóa thành, khống chế nguyên thần đối phương và tái chiếm quyền điều khiển lôi long.","nguon":"@c1270"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270","@c1271","@c1272","@c1273","@c1274","@c1275","@c1276","@c1278","@c1280","@c1290"]},{"id":"lao-gia-hac-y-thien-nhan-de-nhat-suy","name":"Lão già hắc y (Thiên Nhân Đệ Nhất Suy, Thiểm Lôi Tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhất Suy","trangThai":"song","blurb":"Tu sĩ hắc y tóc hoa râm từ miếu thờ thánh địa Thiểm Lôi Tộc, tu vị Thiên Nhân Đệ Nhất Suy. Bị cực cảnh Vương Lâm xuyên qua đầu, thân thể tan vỡ, nguyên thần trọng thương thoát ra.","vaiTro":"Cường giả Thiểm Lôi Tộc canh giữ miếu thờ thánh địa.","tinhCach":[{"text":"Chiến đấu quyết liệt, triệu lôi long và dùng trường kiếm lôi quang nghênh chiến."}],"tabs":{"diem":[{"text":"Bị cực cảnh Vương Lâm đâm vào mi tâm xuyên phá đầu và thân thể, nguyên thần trọng thương thoát ra.","chuong":"@c1270"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù","ghiChu":"Bị Vương Lâm cực cảnh xuyên đầu, thân thể tan vỡ, nguyên thần trọng thương."},{"ten":"Người đàn ông trung niên cao lớn (Thiên Nhân Đệ Tam Suy)","tag":"dong-minh","quanHe":"Đồng tộc","ghiChu":"Được cứu nguyên thần trọng thương."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nguoi-dan-ong-trung-nien-cao-lon-thien-nhan-de-tam-suy","name":"Người đàn ông trung niên cao lớn (Thiên Nhân Đệ Tam Suy, Thiểm Lôi Tộc)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tam Suy","trangThai":"song","blurb":"Tu sĩ Thiên Nhân Đệ Tam Suy Thiểm Lôi Tộc, từ miếu thờ phóng ra cứu nguyên thần lão già hắc y, chất vấn Vương Lâm phản tộc. Được đại trưởng lão sai ở lại bảo vệ thánh địa.","vaiTro":"Cường giả Thiểm Lôi Tộc canh giữ miếu thờ thánh địa.","tinhCach":[{"text":"Trung thành với tộc, phản ứng nhanh khi cứu đồng tộc."}],"tabs":{"diem":[{"text":"Phá vỡ tầng phòng hộ trong một bước để cứu nguyên thần lão già hắc y bị Vương Lâm trọng thương.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"minor","mucCt":"gon","tieuDe":"Cứu nguyên thần lão già hắc y","text":"Từ miếu thờ phóng ra cứu nguyên thần lão già hắc y Thiên Nhân Đệ Nhất Suy, chất vấn Vương Lâm phản tộc, được đại trưởng lão sai ở lại bảo vệ thánh địa.","anchor":"Ngươi dám phản tộc sao?"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù tộc","ghiChu":"Chất vấn Vương Lâm phản tộc."},{"ten":"Lão già hắc y (Thiên Nhân Đệ Nhất Suy)","tag":"dong-minh","quanHe":"Đồng tộc","ghiChu":"Cứu nguyên thần trọng thương."},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"cap-tren","quanHe":"Đại trưởng lão","ghiChu":"Nhận lệnh ở lại bảo vệ thánh địa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nu-thi-ao-trang","name":"Nữ thi áo trắng","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"trangThai":"tu-vong","nguon":["@c1271"]},{"id":"lao-gia-ao-xanh-thiem-loi-toc-tinh-niet","name":"Lão già áo xanh (Thiểm Lôi Tộc, trưởng lão Tịnh Niết)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết","trangThai":"tu-vong","blurb":"Trưởng lão Thiểm Lôi Tộc cảnh giới Tịnh Niết, truy kích Hứa Lập Quốc nhưng bị Vương Lâm giết chết chỉ bằng một chỉ điểm lên mi tâm.","vaiTro":"Trưởng lão Thiểm Lôi Tộc, truy kích Hứa Lập Quốc","tinhCach":[{"text":"Nóng nảy, dễ bị khiêu khích mất bình tĩnh"}],"tabs":{"diem":[{"text":"Bị Hứa Lập Quốc chửi bới khiêu khích đến tức giận sôi máu, cuối cùng bị Vương Lâm giết chết chỉ bằng một chỉ điểm lên mi tâm","chuong":"@c1269"}],"kinhLich":[{"chuong":"@c1269","importance":"normal","mucCt":"ky","tieuDe":"Truy kích Hứa Lập Quốc và bị Vương Lâm giết","text":"Truy kích Hứa Lập Quốc trong lãnh địa Thiểm Lôi Tộc, dùng tộc ấn trên mi tâm phóng lôi cầu màu đen tấn công. Bị Hứa Lập Quốc liên tục chửi bới khiêu khích đến tức giận. Khi Vương Lâm xuất hiện, lão vô tình vung tay ngăn Hứa Lập Quốc bay về phía chủ nhân. Vương Lâm lập tức xuất hiện bên cạnh, tùy ý điểm lên mi tâm lão khiến thân thể tan vỡ và nguyên thần diệt vong.","anchor":"Thân thể lão già áo xanh chợt run lên, trong mắt lộ ra vẻ hoảng sợ và không thể nào tin, thân thể ầm ầm tan vỡ, nguyên thần cũng diệt vong"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Mục tiêu truy kích","ghiChu":"Truy sát hắn vì bắt cóc cô gái Thiểm Lôi Tộc"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm giết bằng một chỉ điểm mi tâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1269"]},{"id":"vi-thu-linh-tu-si-than-bi","name":"Vị thủ lĩnh tu sĩ thần bí","cn":"","aliases":["Người cầm roi năm xưa"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Vị thủ lĩnh đám tu sĩ thần bí năm xưa, từng cầm Vạn Giới Phong Hồn Tiên vung ba roi: roi nhất tạo bảy trăm vạn thiên địa, roi nhì phá hư vô cuốn sinh linh đặt vào, roi ba đánh tan hình bóng khủng bố từ hư vô.","vaiTro":"Nhân vật trong hồi ức đại trưởng lão Thiểm Lôi Tộc, chủ nhân nguyên bản của Vạn Giới Phong Hồn Tiên.","tinhCach":[],"tabs":{"diem":[{"text":"Vung Vạn Giới Phong Hồn Tiên ba lần: tạo bảy trăm vạn thiên địa, phá hư vô đặt sinh linh, đánh tan hình bóng khủng bố.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Hồi ức — vung ba roi tạo bảy trăm vạn thiên địa","text":"Trong hồi ức đại trưởng lão Thiểm Lôi Tộc: vị thủ lĩnh đám tu sĩ thần bí cầm Vạn Giới Phong Hồn Tiên vung ba lần — roi nhất làm thiên địa tan vỡ tạo bảy trăm vạn thiên địa, roi nhì phá hư vô cuốn sinh linh đặt vào (nhóm người đầu tiên), roi ba đánh tan hình bóng khủng bố lao ra từ hư vô. Sau đó bọn họ mang roi đi.","anchor":"vị thủ lĩnh của đám tu sĩ thần bí cầm cây roi này vung lên làm thiên địa tan vỡ"}],"tuViMoc":[],"nhanMach":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"khac","quanHe":"Người chứng kiến","ghiChu":"Đại trưởng lão khi còn là tu sĩ Hóa Thần từng chứng kiến vị này vung roi tạo thiên địa."}],"tuiDo":{"phapBao":[{"ten":"Vạn Giới Phong Hồn Tiên (bản gốc)","trangThai":"mat","moTa":"Bản gốc cây roi, đã bị đám tu sĩ mang đi sau khi vung ba roi tạo bảy trăm vạn thiên địa. Côn Cực Tiên của Vương Lâm là bản mô phỏng.","nguon":"@c1270"}],"congPhap":[],"danDuoc":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"to-tien-de-tam-bo-thiem-loi-toc","name":"Tổ tiên Đệ Tam Bộ Thiểm Lôi Tộc","cn":"","aliases":["Tổ tiên Đệ Tam Bộ Thiểm Lôi tộc","Tổ tiên Đệ Tam bộ đại năng của Thiểm Lôi tộc"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đệ Tam Bộ","trangThai":"khong-ro","blurb":"Đại năng tổ tiên của Thiểm Lôi Tộc, được nhắc qua trọng bảo và thần thông truyền thừa mà đại trưởng lão vận dụng trong sát cục bảy trăm vạn thiên địa.","vaiTro":"Tổ tiên truyền thừa của Thiểm Lôi Tộc, người chế luyện bộ giáp sấm sét bất diệt và để lại thuật thần thông tổ tiên cho hậu nhân.","tinhCach":[],"mucCt":"gon","tabs":{"diem":[{"text":"Được hậu nhân nhắc như nguồn gốc của trọng bảo và thần thông truyền thừa Thiểm Lôi Tộc.","chuong":"@c1271"}],"kinhLich":[{"chuong":"@c1271","importance":"normal","mucCt":"gon","tieuDe":"Lưu truyền trọng bảo","text":"Vị tổ tiên Đệ Tam Bộ Thiểm Lôi Tộc được nhắc là người chế luyện bộ giáp sấm sét bất diệt và để lại thần thông tổ tiên mà đại trưởng lão tiêu hao thọ nguyên để thúc động trong lúc nguy cấp.","anchor":"Bộ giáp này vượt xa Lôi Sát kính, do chính tay vị tổ tiên Đệ Tam bộ đại năng của Thiểm Lôi tộc năm xưa chế luyện ra"}],"tuViMoc":[{"chuong":"@c1271","canhGioi":"Đệ Tam Bộ","text":"Được nhắc là đại năng Đệ Tam Bộ của Thiểm Lôi Tộc qua nguồn gốc bộ giáp sấm sét bất diệt.","importance":"major"}],"nhanMach":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"ho-hang","quanHe":"hậu nhân sử dụng truyền thừa","ghiChu":"Đại trưởng lão dùng bộ giáp sấm sét bất diệt và mở Thiểm Lôi ấn hóa thành thần thông tổ tiên do vị này để lại."}],"tuiDo":{"phapBao":[{"ten":"Bộ giáp sấm sét bất diệt","loai":"trọng bảo truyền thừa","trangThai":"truyen-lai","moTa":"Trọng bảo do vị tổ tiên Đệ Tam Bộ Thiểm Lôi Tộc chế luyện, về sau được đại trưởng lão dùng trong trận chiến và bị Trảm Thiên kiếm chém vỡ.","nguon":"@c1271"}],"danDuoc":[],"congPhap":[{"ten":"Thần thông tổ tiên Thiểm Lôi Tộc","loai":"thần thông truyền thừa","trangThai":"truyen-lai","moTa":"Thuật thần thông tổ tiên được đại trưởng lão mở bằng Thiểm Lôi ấn sau khi hiến tế ba ngàn năm thọ nguyên.","nguon":"@c1271"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1271"]},{"id":"thai-co-loi-long","name":"Thái Cổ Lôi Long","cn":"","aliases":["Tám Thái Cổ Lôi Long"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ @c1274","trangThai":"khong-ro","blurb":"","vaiTro":"","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c1270","importance":"major","mucCt":"vua","tieuDe":"Tám hồn bị nuốt","text":"Tám hồn phách Thái Cổ Lôi Long được đại trưởng lão Thiểm Lôi Tộc triệu ra từ Thái cổ lôi giới để vây công Vương Lâm. Sau khi bị Côn Cực Tiên khắc chế và tự bạo, hồn phách chúng bị kim quang cắt xé rồi bị Vương Lâm dùng Thôn Hồn nuốt lấy.","anchor":"Cũng không phải chỉ là một Thái Cổ Lôi Long tự bạo, mà chỉ trong khoảng thời gian cực ngắn cả tám con Thái Cổ Lôi Long đồng loạt tự bạo"},{"chuong":"@c1274","importance":"normal","tieuDe":"Chín hồn hợp long","mucCt":"vua","text":"Thái Cổ Lôi Long xuất hiện qua nguyên thần Thái Cổ Lôi Long của Vương Lâm và tám linh hồn đã bị thôn phệ. Các hồn phách hợp thành lôi long khổng lồ phá trận, trong đó linh hồn mạnh nhất áp chế tám linh hồn còn lại.","anchor":"Con rồng này được tạo thành từ tám linh hồn Thái Cổ Lôi Long bị nguyên thần Vương Lâm thôn phệ"},{"chuong":"@c1277","importance":"normal","mucCt":"vua","tieuDe":"Bảy long bị thôn phệ","text":"Tám Thái Cổ Lôi Long bị giam trong nguyên thần Vương Lâm, liên tục vùng vẫy trước biển lửa lam sắc và hư ảnh Chu Tước. Khi rượu gạo khiến hỏa lực tăng mạnh, bảy con lần lượt bị luyện hóa rồi bị nguyên thần Thái Cổ Lôi Long của Vương Lâm thôn phệ, chỉ còn một con cuối cùng.","anchor":"tám con Thái Cổ Lôi Long gầm lên tức giận, chúng vùng vẫy muốn phá tan nguyên thần"},{"chuong":"@c1295","importance":"bridge","mucCt":"vua","tieuDe":"Bị nhắc trong mối hận","text":"Thái Cổ Lôi Long được Tham Lang nhắc là tồn tại từng theo hắn từ nhỏ và đã bị Vương Lâm cắn nuốt, khiến hắn tiếc nuối khả năng dung hợp để trở thành lôi tu.","anchor":"Thái cổ lôi long đó từ nhỏ đã theo ta lớn lên"},{"chuong":"@c1299","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc trong cơ duyên","text":"Thái Cổ Lôi Long được nhắc như cơ duyên Tham Lang từng có và là nguồn giúp Vương Lâm mở đường lôi tu.","anchor":"nhờ vào thái cổ Lôi Long mới khiến Vương Lâm có cơ hội lôi tu"},{"chuong":"@c1311","importance":"bridge","mucCt":"gon","tieuDe":"Bị liên hệ với lôi nguyên","text":"Thái Cổ Lôi Long được Chu Tước đời thứ hai nhắc trong suy đoán về nguyên nhân lôi bổn nguyên của Vương Lâm đại thành.","anchor":"Chẳng lẽ là hắn nuốt thái cổ Lôi Long"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị thôn phệ hồn phách","ghiChu":"Tám hồn phách Lôi Long bị Vương Lâm nuốt vào nguyên thần trong trận chiến."},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"khac","quanHe":"được triệu hoán","ghiChu":"Đại trưởng lão mở Thái cổ lôi giới để triệu chúng ra vây công Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"nguyên thần và hồn phách bị Vương Lâm vận dụng trong thần thông lôi đạo","ghiChu":"Được hợp thành lôi long phá trận ở @c1274"},{"ten":"Tham Lang","tag":"khac","quanHe":"Từng gắn với Tham Lang","ghiChu":"Tham Lang xem Thái Cổ Lôi Long là bảo vật hoặc sinh linh quan trọng từng theo mình từ nhỏ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270","@c1274","@c1277","@c1295","@c1299","@c1311"]},{"id":"huyen-bao-thuong-nhan","name":"Huyền Bảo thượng nhân","cn":"","aliases":["Huyền Bảo Thượng Nhân"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Huyền Bảo thượng nhân là Đại Trưởng lão Địa Huyền Điện, thành viên Liên Minh Trưởng Lão Đoàn thuộc Tu Chân Liên Minh, được Thuỷ La triệu mời hiện thân tại chiến trường La Phù Sơn với dáng vẻ tiên phong đạo cốt, tay cầm phất trần. Ông triệu bốn Tiên vệ kim phẩm và dùng trọng bảo Thứ Không Niết Tiễn để trấn áp Vọng Nguyệt, nhưng bị Cổ Thần Tí huỷ tan pháp bảo, lộ thân phận Tiên nhân rồi bị ba phía vây đánh trọng thương. Nguyên thần ông cuối cùng bị Vương Lâm lấy ra làm vật uy hiếp, bị Thanh Thuỷ tra xét ký ức khiến mất linh trí, về sau còn bị dùng làm nguồn bổ sung tiên lực.","vaiTro":"Đại Trưởng lão Địa Huyền Điện, thành viên Liên Minh Trưởng Lão Đoàn","tinhCach":"Ung dung tiên phong đạo cốt khi hiện thân giữa chiến trường; quyết đoán triệu Tiên vệ và dùng trọng bảo trấn áp địch; kiên cường chống chịu khi bị nhiều phía vây đánh","tabs":{"diem":[{"text":"Được Thuỷ La triệu mời hiện thân tại chiến trường La Phù Sơn với dáng vẻ tiên phong đạo cốt, tay cầm phất trần","chuong":"@c0871"},{"text":"Mở khe hư không triệu bốn Tiên vệ kim phẩm và triển khai trọng bảo Thứ Không Niết Tiễn để trấn áp Vọng Nguyệt","chuong":"@c0872"},{"text":"Bị Cổ Thần Tí huỷ tan Thứ Không Niết Tiễn, lộ thân phận Tiên nhân rồi bị Thanh Thuỷ, Vọng Nguyệt và Viêm Lôi Tử ba phía vây đánh","chuong":"@c0874"},{"text":"Nguyên thần bị Vương Lâm lấy ra dùng làm vật uy hiếp kim long buộc ngừng tấn công","chuong":"@c0880"},{"text":"Nguyên thần bị Thanh Thuỷ tra xét ký ức khiến mất hết linh trí","chuong":"@c0887"},{"text":"Nguyên thần về sau bị Vương Lâm dùng làm nguồn bổ sung tiên lực","chuong":"@c1007"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Được so sánh pháp bảo","text":"Huyền Bảo Thượng Nhân được nhắc khi Lôi Sát Kính của Thiểm Lôi Tộc được so sánh với pháp bảo cửu phẩm Thứ Không Niết của ông là Thứ Không Niết.","anchor":"pháp bảo cửu phẩm Thứ Không Niết của Huyền Bảo Thượng Nhân"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"thien-quy","name":"Thiên Quỷ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"","vaiTro":"","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Được nhắc qua Côn Cực Tiên","text":"Thiên Quỷ được nhắc như ví dụ cho uy lực của Côn Cực Tiên, vì năm xưa cũng không thể ẩn giấu dưới cây roi chuyên đánh hồn phách và nguyên thần này.","anchor":"Ngay cả Thiên Quỷ năm xưa cũng không thể nào ẩn giấu dưới Côn Cực Tiên"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nguoi-dan-ong-trung-nien-ngoai-gioi","name":"Người đàn ông trung niên Ngoại giới","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ngoại giới","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết","trangThai":"tu-vong","blurb":"Tu sĩ Toái Niết Ngoại giới bị Vương Lâm truy sát đầu chương. Hắn dùng pháp bảo, thần thông và cả nữ tử song tu làm vật chắn nhưng vẫn bị Cực Cảnh giết chết.","vaiTro":"Tu sĩ Ngoại giới làm đối thủ bị Vương Lâm xử tử trước khi trận chiến với Thiểm Lôi Tộc bùng nổ.","tinhCach":[{"text":"Tàn nhẫn và ích kỷ trong lúc bỏ chạy, sẵn sàng ném nữ tử song tu ra làm vật cản.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Có tu vi Toái Niết và thuộc phe Ngoại giới.","chuong":"@c1270"},{"text":"Bị Vương Lâm coi là kẻ nhất định phải chết.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Bị Cực Cảnh giết","text":"Người đàn ông trung niên Ngoại giới bỏ chạy khỏi Vương Lâm, dùng nhiều thủ đoạn và ném nữ tử song tu ra câu giờ. Hắn vẫn bị tia chớp hồng sắc xuyên qua hậu tâm, thân thể nổ tung và nguyên thần diệt vong.","anchor":"thân thể hắn đã tiến vào một nửa thì tia chớp hồng sắc đã xuyên qua tất cả phóng đến"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Toái Niết","text":"Chương xác định hắn là tu sĩ Toái Niết ở Ngoại giới.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ truy sát và giết mình","ghiChu":"Bị Vương Lâm dùng Cực Cảnh tiêu diệt."},{"ten":"Cô gái xinh đẹp Ngoại giới","tag":"khac","quanHe":"nữ tử song tu bị lợi dụng","ghiChu":"Hắn ném nàng về phía Cực Cảnh để câu giờ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"co-gai-xinh-dep-ngoai-gioi","name":"Cô gái xinh đẹp Ngoại giới","cn":"","aliases":["Nữ tử song tu của người đàn ông trung niên Ngoại giới"],"gioiTinh":"nu","theLuc":[{"ten":"Ngoại giới","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Nữ tử song tu đi cùng người đàn ông trung niên Ngoại giới. Nàng bị chính hắn ném ra làm vật cản trước Cực Cảnh của Vương Lâm và thân thể tan vỡ.","vaiTro":"Nạn nhân bị đồng bạn lợi dụng trong cuộc truy sát đầu chương.","tinhCach":[{"text":"Kinh hoàng và không thể tin khi bị người đi cùng ném ra chắn đòn.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Là nữ tử song tu đi cùng tu sĩ Toái Niết Ngoại giới.","chuong":"@c1270"},{"text":"Vương Lâm vốn không chủ ý giết nàng, nhưng nàng bị ném vào đường Cực Cảnh.","chuong":"@c1270"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Người đàn ông trung niên Ngoại giới","tag":"khac","quanHe":"nữ tử song tu bị phản bội","ghiChu":"Bị hắn ném ra làm vật cản khi bỏ chạy."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị cuốn vào đòn truy sát","ghiChu":"Thân thể tan vỡ trên đường Cực Cảnh của Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"lao-gia-toai-niet-thiem-loi-toc","name":"Lão già Toái Niết Thiểm Lôi Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết","trangThai":"tu-vong","blurb":"Tu sĩ Toái Niết của Thiểm Lôi Tộc lao ra ngăn Vương Lâm khi thánh địa bị công kích. Ông bị Vương Lâm chụp lấy, nguyên lực phá thể và chết ngay trên tầng phòng hộ.","vaiTro":"Tu sĩ canh giữ thánh địa Thiểm Lôi Tộc bị giết khi Vương Lâm xông vào.","tinhCach":[{"text":"Phản ứng quyết liệt khi có kẻ xâm nhập thánh địa.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Có tu vi Toái Niết và trấn giữ thánh địa Thiểm Lôi Tộc.","chuong":"@c1270"},{"text":"Cái chết của ông kích động cảnh báo hồng quang trong ngọc giản toàn tộc.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Chết trên phòng hộ","text":"Lão già Toái Niết lao ra từ thánh địa khi Vương Lâm đánh tầng phòng hộ và thi triển thủ ấn ngăn cản. Ông bị Vương Lâm chụp lấy, nguyên lực phá thể rồi chết trên vầng sáng phòng hộ.","anchor":"lão già phát ra một tiếng thét thê lương, thân thể ầm ầm ngã trên vầng sáng"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Toái Niết","text":"Chương mô tả ông là lão già Toái Niết của Thiểm Lôi Tộc lao ra ngăn kẻ xâm nhập.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ xâm nhập giết mình","ghiChu":"Bị Vương Lâm giết khi ngăn hắn tiến vào thánh địa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"lao-gia-hac-y-thiem-loi-toc-thien-nhan-de-nhat-suy","name":"Lão già hắc y Thiểm Lôi Tộc Thiên Nhân Đệ Nhất Suy","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhất Suy","trangThai":"song","blurb":"Cao thủ Thiểm Lôi Tộc bước ra từ miếu thờ thánh địa với tu vi Thiên Nhân Đệ Nhất Suy. Ông dùng tộc ấn hóa lôi long và trường kiếm điện quang nhưng bị Vương Lâm phá tan thân thể, nguyên thần trọng thương.","vaiTro":"Cao thủ Thiểm Lôi Tộc bị Vương Lâm đánh bại trước khi đại trưởng lão hiện thân.","tinhCach":[{"text":"Kiêu hãnh trước kẻ xâm nhập nhưng nhanh chóng bị áp đảo.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Tu vi vượt Toái Niết, đạt Thiên Nhân Đệ Nhất Suy.","chuong":"@c1270"},{"text":"Sở hữu tộc ấn hóa lôi long và trường kiếm điện quang nhưng không chống nổi Cực Cảnh.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Nguyên thần trọng thương","text":"Lão già hắc y từ miếu thờ bước ra giao chiến với Vương Lâm, hóa tộc ấn thành lôi long và gọi trường kiếm điện quang. Cực Cảnh của Vương Lâm phá lôi long, đánh vỡ trường kiếm, xuyên mi tâm khiến thân thể ông tan vỡ, chỉ còn nguyên thần trọng thương được cứu.","anchor":"tu vị bùng ra trực tiếp vượt qua Toái Niết đạt đến mức độ Thiên Nhân Đệ Nhất Suy"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Thiên Nhân Đệ Nhất Suy","text":"Khi xuất hiện, tu vi của ông bùng ra vượt qua Toái Niết và đạt Thiên Nhân Đệ Nhất Suy.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ đánh tan thân thể","ghiChu":"Bị Vương Lâm dùng Cực Cảnh trọng thương."},{"ten":"Người đàn ông trung niên cao lớn Thiểm Lôi Tộc Thiên Nhân Đệ Tam Suy","tag":"dong-minh","quanHe":"người cứu nguyên thần","ghiChu":"Nguyên thần ông được người đàn ông trung niên cao lớn cứu lại."}],"tuiDo":{"phapBao":[{"ten":"Trường kiếm điện quang","loai":"pháp bảo công kích","trangThai":"hong","moTa":"Được dùng để ngăn Cực Cảnh nhưng lập tức bị đánh vỡ thành mảnh nhỏ.","nguon":"@c1270"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nguoi-dan-ong-trung-nien-cao-lon-thiem-loi-toc-thien-nhan-de-tam-suy","name":"Người đàn ông trung niên cao lớn Thiểm Lôi Tộc Thiên Nhân Đệ Tam Suy","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tam Suy","trangThai":"song","blurb":"Cao thủ Thiểm Lôi Tộc từ miếu thờ lao ra sau khi lão già hắc y bị đánh bại. Ông không cứu kịp thân thể đồng tộc nhưng bắt được nguyên thần và nhận ra Vương Lâm là kẻ phản tộc.","vaiTro":"Cao thủ Thiểm Lôi Tộc chứng kiến Vương Lâm bỏ thân thể Vu Phi và lộ thân phận thật.","tinhCach":[{"text":"Phản ứng nhanh khi đồng tộc gặp nguy nhưng vẫn bị biến cố vượt khỏi tầm tay.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Tu vi bùng ra ở mức Thiên Nhân Đệ Tam Suy.","chuong":"@c1270"},{"text":"Là người trực tiếp cứu nguyên thần lão già hắc y sau khi thân thể bị phá.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Cứu nguyên thần đồng tộc","text":"Người đàn ông trung niên cao lớn lao ra từ miếu thờ, hô dừng tay nhưng không kịp cứu thân thể lão già hắc y. Ông chỉ bắt được nguyên thần đồng tộc, rồi chứng kiến Vương Lâm bỏ thân thể Vu Phi và lộ thân phận không phải người Thiểm Lôi Tộc.","anchor":"khí tức Thiên Nhân Đệ Tam Suy từ trong thân thể bùng ra kinh thiên động địa"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Thiên Nhân Đệ Tam Suy","text":"Khí tức của ông được mô tả là Thiên Nhân Đệ Tam Suy, bùng ra kinh thiên động địa.","importance":"major"}],"nhanMach":[{"ten":"Lão già hắc y Thiểm Lôi Tộc Thiên Nhân Đệ Nhất Suy","tag":"dong-minh","quanHe":"đồng tộc được cứu nguyên thần","ghiChu":"Ông cứu được nguyên thần lão già hắc y sau khi thân thể đối phương tan vỡ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ xâm nhập phản tộc","ghiChu":"Nhận ra Vương Lâm không phải tộc nhân sau khi nguyên thần rời thân thể Vu Phi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"chin-tu-si-thien-nhan-suy-kiep-thiem-loi-toc","name":"Chín tu sĩ Thiên Nhân Suy Kiếp của Thiểm Lôi Tộc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Suy Kiếp","trangThai":"song","blurb":"Chín cao thủ Thiên Nhân Suy Kiếp của Thiểm Lôi Tộc xuất hiện từ miếu thờ thánh địa. Họ định khóa chặt Vương Lâm và khom người bái kiến khi đại trưởng lão hiện thân.","vaiTro":"Nhóm cao thủ hộ vệ thánh địa trong biến cố Vương Lâm xâm nhập Thiểm Lôi Tộc.","tinhCach":[{"text":"Tuân phục đại trưởng lão và giữ vai trò bảo vệ thánh địa.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Chín luồng khí tức đều thuộc tu sĩ Thiên Nhân Suy Kiếp.","chuong":"@c1270"},{"text":"Sau khi đại trưởng lão hiện thân, họ hóa thành chín người và bái kiến.","chuong":"@c1270"},{"text":"Cả chín luồng khí tức đều thuộc tầng Thiên Nhân Suy Kiếp.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Ở lại thủ hộ tộc","text":"Chín tu sĩ Thiên Nhân Suy Kiếp từ miếu thờ hiện thân, định tập trung vào Vương Lâm nhưng sau đó khom người nghe lệnh đại trưởng lão ở lại bảo vệ Thiểm Lôi Tộc.","anchor":"chín luồng khí tức này đều là tu sĩ Thiên Nhân Suy Kiếp"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Thiên Nhân Suy Kiếp","text":"Chương xác định chín luồng khí tức này đều là tu sĩ Thiên Nhân Suy Kiếp.","importance":"major"}],"nhanMach":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"cap-tren","quanHe":"cấp dưới bái kiến","ghiChu":"Họ khom người bái kiến đại trưởng lão khi ông hiện thân."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ xâm nhập bị khóa chặt","ghiChu":"Khí tức của họ định khóa chặt Vương Lâm trong thánh địa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"thu-linh-dam-tu-si-than-bi-nam-xua","name":"Thủ lĩnh đám tu sĩ thần bí năm xưa","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Đám tu sĩ thần bí năm xưa","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Thủ lĩnh bí ẩn từng cầm roi vạn giới phong hồn trong ký ức của đại trưởng lão Thiểm Lôi Tộc. Người này dùng roi phá tinh không, tạo bảy trăm vạn thiên địa, đưa sinh linh vào đó và đánh tan một hình bóng đáng sợ từ hư vô.","vaiTro":"Nhân vật cổ xưa hé lộ lai lịch thật của Côn Cực Tiên và bảy trăm vạn thiên địa.","tinhCach":[{"text":"Sở hữu uy năng vượt xa hiểu biết của đại trưởng lão thời còn Hóa Thần.","chuong":"@c1270"}],"tabs":{"diem":[{"text":"Từng cầm cây roi mà đại trưởng lão nhận là Vạn Giới Phong Hồn Tiên.","chuong":"@c1270"},{"text":"Liên quan trực tiếp tới việc tạo bảy trăm vạn thiên địa trong ký ức cổ xưa.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Chủ roi vạn giới","text":"Thủ lĩnh đám tu sĩ thần bí năm xưa được đại trưởng lão nhớ lại khi kim quang của Côn Cực Tiên hiện ra. Trong ký ức ấy, người này cầm roi vạn giới phong hồn phá vỡ tinh không, tạo bảy trăm vạn thiên địa và đánh tan một hình bóng khủng bố từ hư vô.","anchor":"hắn đã tận mắt nhìn thấy vị thủ lĩnh của đám tu sĩ thần bí cầm cây roi này vung lên làm thiên địa tan vỡ"}],"tuViMoc":[],"nhanMach":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"khac","quanHe":"người từng được chứng kiến","ghiChu":"Đại trưởng lão khi còn Hóa Thần từng tận mắt thấy thủ lĩnh này cầm roi."}],"tuiDo":{"phapBao":[{"ten":"Vạn Giới Phong Hồn Tiên","loai":"roi pháp bảo","trangThai":"mat","moTa":"Trong ký ức của đại trưởng lão, thủ lĩnh đám tu sĩ thần bí từng cầm cây roi này; về sau nó xuất hiện trong tay Vương Lâm dưới tên Côn Cực Tiên.","nguon":"@c1270"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"lao-to-thiem-loi-toc","name":"Lão tổ Thiểm Lôi Tộc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Lão tổ của Thiểm Lôi Tộc được đại trưởng lão nhắc tới khi liên hệ Côn Cực Tiên với biến cố năm xưa. Đại trưởng lão suy đoán việc Vạn Giới Phong Hồn Tiên xuất hiện có thể là ý trời do anh linh lão tổ đưa tới.","vaiTro":"Nhân vật tổ tiên được nhắc trong hồi ức về Vạn Giới Phong Hồn Tiên và đám tu sĩ thần bí.","tinhCach":[],"tabs":{"diem":[{"text":"Được đại trưởng lão gọi là lão tổ trong ký ức về đám tu sĩ thần bí năm xưa.","chuong":"@c1270"},{"text":"Tên ông gắn với suy đoán Vạn Giới Phong Hồn Tiên xuất hiện tại Thiểm Lôi Tộc là ý trời.","chuong":"@c1270"},{"text":"Gắn với hồi ức cổ xưa về chiếc roi Vạn Giới Phong Hồn và đám tu sĩ thần bí.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Được tu sĩ thần bí giúp","text":"Lão tổ Thiểm Lôi Tộc được nhắc trong hồi ức đại trưởng lão, nơi vị thủ lĩnh đám tu sĩ thần bí từng dùng chiếc roi đến giúp lão tổ.","anchor":"pháp bảo của vị thủ lĩnh đám tu sĩ năm xưa đến giúp đỡ lão tổ"}],"tuViMoc":[],"nhanMach":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"khac","quanHe":"lão tổ được hậu bối nhắc tới","ghiChu":"Đại trưởng lão liên hệ lão tổ với sự xuất hiện của Vạn Giới Phong Hồn Tiên."},{"ten":"Vị thủ lĩnh đám tu sĩ thần bí","tag":"khac","quanHe":"người từng đến giúp lão tổ","ghiChu":"Hồi ức đại trưởng lão gắn lão tổ với vị thủ lĩnh cầm chiếc roi Vạn Giới Phong Hồn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nguoi-dan-ong-trung-nien-toai-niet-thiem-loi-toc","name":"Người đàn ông trung niên Toái Niết của Thiểm Lôi Tộc","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết","trangThai":"tu-vong","blurb":"Tu sĩ Toái Niết của Thiểm Lôi Tộc bị Vương Lâm dùng Cực Cảnh truy sát sau khi bỏ chạy. Hắn từng dùng nữ tử song tu làm lá chắn nhưng vẫn thân diệt thần vong.","vaiTro":"Tu sĩ Thiểm Lôi Tộc bị Vương Lâm giết khi mở màn cuộc xâm nhập thánh địa.","tinhCach":[{"text":"Tàn nhẫn và hoảng loạn khi gặp nguy, sẵn sàng dùng nữ tử bên cạnh làm vật chắn để tự cứu.","chuong":"@c1270"}],"mucCt":"vua","tabs":{"diem":[{"text":"Có tu vi Toái Niết nhưng không thoát được Cực Cảnh của Vương Lâm.","chuong":"@c1270"},{"text":"Dùng nữ tử song tu làm lá chắn trong lúc trốn chạy.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Bị Cực Cảnh giết","text":"Người đàn ông trung niên Toái Niết bị Vương Lâm dùng Cực Cảnh hồng sắc truy sát, vội ném nữ tử song tu ra chắn rồi xé hư không bỏ chạy. Tia chớp hồng sắc vẫn xuyên qua hậu tâm khiến thân thể nổ tung, nguyên thần tiêu diệt.","anchor":"Thân thể người đàn ông trung niên khẽ rung lên"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Toái Niết","text":"Research xác nhận người này là tu sĩ Toái Niết của Thiểm Lôi Tộc.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ truy sát và giết chết hắn","ghiChu":"Vương Lâm dùng Cực Cảnh xuyên hậu tâm khiến hắn thân diệt thần vong."},{"ten":"Nữ tử song tu của người đàn ông trung niên","tag":"khac","quanHe":"nữ tử song tu bị hắn dùng làm vật chắn","ghiChu":"Hắn ném nàng ra trước người để chặn Cực Cảnh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nu-tu-song-tu-cua-nguoi-dan-ong-trung-nien","name":"Nữ tử song tu của người đàn ông trung niên","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"khong-ro","trangThai":"tu-vong","blurb":"Nữ tử đi cùng người đàn ông trung niên Toái Niết của Thiểm Lôi Tộc. Nàng bị chính người này ném ra làm lá chắn trước Cực Cảnh của Vương Lâm và chết ngay tại chỗ.","vaiTro":"Nạn nhân bị dùng làm vật chắn trong lúc tu sĩ Toái Niết Thiểm Lôi Tộc bỏ chạy.","tinhCach":[],"mucCt":"gon","tabs":{"diem":[{"text":"Bị người đàn ông trung niên dùng làm vật chắn khi chưa kịp phản ứng.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"gon","tieuDe":"Bị dùng làm chắn","text":"Nữ tử song tu bị người đàn ông trung niên giơ lên trước người để chặn Cực Cảnh của Vương Lâm và thân thể tan vỡ ngay trong biến cố đó.","anchor":"bị người đàn ông trung niên kia giơ lên trước người"}],"tuViMoc":[],"nhanMach":[{"ten":"Người đàn ông trung niên Toái Niết của Thiểm Lôi Tộc","tag":"khac","quanHe":"người song tu đã dùng nàng làm vật chắn","ghiChu":"Hắn ném nàng ra trước Cực Cảnh để tự cứu."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"người phóng Cực Cảnh giết mục tiêu phía sau nàng","ghiChu":"Nàng chết trong đường truy sát của Cực Cảnh nhằm vào người đàn ông trung niên."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"lao-gia-toai-niet-thu-thanh-dia-thiem-loi-toc","name":"Lão già Toái Niết thủ thánh địa Thiểm Lôi Tộc","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Toái Niết","trangThai":"tu-vong","blurb":"Lão già Toái Niết từ thánh địa Thiểm Lôi Tộc lao ra khi Vương Lâm công kích tầng phòng hộ. Ông bị Vương Lâm chụp lấy và dùng nguyên lực giết chết ngay tại chỗ.","vaiTro":"Cao thủ thủ vệ thánh địa Thiểm Lôi Tộc đầu tiên bị Vương Lâm hạ sát khi công khai xâm nhập.","tinhCach":[{"text":"Hành động như thủ vệ thánh địa, lập tức ra tay ngăn kẻ xâm nhập.","chuong":"@c1270"}],"mucCt":"vua","tabs":{"diem":[{"text":"Có tu vi Toái Niết và xuất hiện ngay sau khi tầng phòng hộ thánh địa bị công kích.","chuong":"@c1270"},{"text":"Cái chết của ông kích hoạt báo động đỏ trong ngọc giản tộc nhân Thiểm Lôi Tộc.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Chết tại thánh địa","text":"Lão già Toái Niết thủ thánh địa lao ra sau khi Vương Lâm gọi sấm sét đánh tầng phòng hộ và thi triển thủ ấn tấn công. Ông bị Vương Lâm chụp lấy, nguyên lực tràn vào cơ thể khiến tử vong, thân xác vỡ trên vầng sáng phòng hộ.","anchor":"Người này tu vị đạt đến Toái Niết"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Toái Niết","text":"Research xác nhận lão già thủ thánh địa có tu vi Toái Niết.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ xâm nhập đã giết ông","ghiChu":"Vương Lâm dùng nguyên lực giết ông trên tầng phòng hộ thánh địa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"lao-gia-hac-y-thien-nhan-de-nhat-suy-thiem-loi-toc","name":"Lão già hắc y Thiên Nhân Đệ Nhất Suy của Thiểm Lôi Tộc","aliases":["Lão già hắc y Thiên Nhân Đệ Nhất Suy"],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhất Suy","trangThai":"song","blurb":"Cao thủ Thiểm Lôi Tộc từ miếu thờ xuất hiện để ngăn Vương Lâm. Ông dùng tộc ấn hóa lôi long và trường kiếm điện quang nhưng bị Cực Cảnh phá tan thân thể, chỉ còn nguyên thần trọng thương được cứu.","vaiTro":"Cao thủ Thiên Nhân Đệ Nhất Suy của Thiểm Lôi Tộc tham chiến khi thánh địa bị Vương Lâm xâm nhập.","tinhCach":[{"text":"Kiêu hãnh và quyết liệt khi ra tay bảo vệ thánh địa, nhưng nhanh chóng bị Vương Lâm áp đảo.","chuong":"@c1270"}],"mucCt":"vua","tabs":{"diem":[{"text":"Tu vi vượt qua Toái Niết, đạt Thiên Nhân Đệ Nhất Suy.","chuong":"@c1270"},{"text":"Tộc ấn hóa lôi long và trường kiếm điện quang đều bị Cực Cảnh phá vỡ.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Bị Cực Cảnh phá","text":"Lão già hắc y từ miếu thờ xuất hiện, dùng tộc ấn hóa lôi long và trường kiếm điện quang chống Cực Cảnh của Vương Lâm. Cực Cảnh phá lôi long, phá kiếm rồi xuyên mi tâm khiến thân thể ông tan vỡ, nguyên thần trọng thương nhưng được phe Thiểm Lôi Tộc cứu lại.","anchor":"tu vị bùng ra trực tiếp vượt qua Toái Niết"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Thiên Nhân Đệ Nhất Suy","text":"Research xác nhận lão già hắc y có tu vi Thiên Nhân Đệ Nhất Suy.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"người đánh tan thân thể ông","ghiChu":"Vương Lâm dùng Cực Cảnh xuyên mi tâm khiến ông chỉ còn nguyên thần trọng thương."},{"ten":"Người đàn ông trung niên cao lớn Thiểm Lôi Tộc","tag":"dong-minh","quanHe":"cao thủ cùng tộc cứu nguyên thần","ghiChu":"Người đàn ông trung niên cao lớn xuất hiện từ miếu thờ để cứu nguyên thần ông."},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"dong-minh","quanHe":"cao tầng cùng tộc","ghiChu":"Ông là một trong các cao thủ Thiểm Lôi Tộc hiện diện trước khi đại trưởng lão trực tiếp nhận chiến."}],"tuiDo":{"phapBao":[{"ten":"Trường kiếm điện quang","loai":"pháp bảo","trangThai":"hong","moTa":"Lão già hắc y dùng trường kiếm điện quang chống Cực Cảnh, nhưng bị tia chớp hồng sắc phá vỡ thành nhiều mảnh.","nguon":"@c1270"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"nguoi-dan-ong-trung-nien-cao-lon-thiem-loi-toc","name":"Người đàn ông trung niên cao lớn Thiểm Lôi Tộc","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tam Suy","trangThai":"song","blurb":"Cao thủ Thiên Nhân Đệ Tam Suy của Thiểm Lôi Tộc xuất hiện từ miếu thờ khi lão già hắc y bị trọng thương. Ông cứu nguyên thần đồng tộc, chất vấn Vương Lâm phản tộc rồi dừng truy kích khi đại trưởng lão nhận chiến.","vaiTro":"Cao thủ Thiểm Lôi Tộc tham gia chỉ huy phòng thủ trước khi đại trưởng lão trực tiếp ra tay.","tinhCach":[{"text":"Đặt lập trường Thiểm Lôi Tộc lên trước, lập tức chất vấn Vương Lâm phản tộc khi thấy thân phận Vu Phi bị lộ.","chuong":"@c1270"}],"mucCt":"vua","tabs":{"diem":[{"text":"Có tu vi Thiên Nhân Đệ Tam Suy, cao hơn lão già hắc y Thiên Nhân Đệ Nhất Suy.","chuong":"@c1270"},{"text":"Ra tay cứu nguyên thần lão già hắc y và định truy kích Vương Lâm.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Cứu nguyên thần đồng tộc","text":"Người đàn ông trung niên cao lớn xuất hiện từ miếu thờ, mang tu vi Thiên Nhân Đệ Tam Suy và cứu nguyên thần lão già hắc y sau khi thân thể người này bị phá. Ông chất vấn Vương Lâm phản tộc, nhưng dừng truy kích khi đại trưởng lão Thiểm Lôi Tộc nhận lời quyết chiến.","anchor":"khí tức Thiên Nhân Đệ Tam Suy từ trong thân thể bùng ra"}],"tuViMoc":[{"chuong":"@c1270","canhGioi":"Thiên Nhân Đệ Tam Suy","text":"Research xác nhận người đàn ông trung niên cao lớn có khí tức Thiên Nhân Đệ Tam Suy.","importance":"major"}],"nhanMach":[{"ten":"Lão già hắc y Thiên Nhân Đệ Nhất Suy của Thiểm Lôi Tộc","tag":"dong-minh","quanHe":"đồng tộc được ông cứu nguyên thần","ghiChu":"Ông xuất hiện từ miếu thờ để cứu nguyên thần lão già hắc y."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"kẻ bị ông chất vấn phản tộc","ghiChu":"Ông định truy kích Vương Lâm trước khi đại trưởng lão nhận chiến."},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"cap-tren","quanHe":"cao tầng chỉ huy trực tiếp","ghiChu":"Ông dừng lại khi đại trưởng lão hiện thân và nhận lời giao chiến với Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"vi-thu-linh-dam-tu-si-than-bi","name":"Vị thủ lĩnh đám tu sĩ thần bí","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Đám tu sĩ thần bí năm xưa","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Thủ lĩnh một nhóm tu sĩ thần bí trong hồi ức cổ xưa của đại trưởng lão Thiểm Lôi Tộc. Người này từng cầm chiếc roi giống Vạn Giới Phong Hồn Tiên, tạo bảy trăm vạn thiên địa và đánh tan hình bóng khủng bố từ hư vô.","vaiTro":"Nhân vật cổ sử gắn với lai lịch Vạn Giới Phong Hồn Tiên và bảy trăm vạn thiên địa.","tinhCach":[{"text":"Thể hiện uy năng áp đảo trong hồi ức, dùng roi phá hư vô, thu sinh linh và đánh tan tồn tại khủng bố.","chuong":"@c1270"}],"mucCt":"vua","tabs":{"diem":[{"text":"Từng cầm chiếc roi được đại trưởng lão nhận ra là Vạn Giới Phong Hồn Tiên.","chuong":"@c1270"},{"text":"Liên quan trực tiếp tới việc hình thành bảy trăm vạn thiên địa trong hồi ức cổ xưa.","chuong":"@c1270"}],"kinhLich":[{"chuong":"@c1270","importance":"normal","mucCt":"vua","tieuDe":"Tạo bảy trăm vạn thiên địa","text":"Trong ký ức cổ xưa của đại trưởng lão, vị thủ lĩnh đám tu sĩ thần bí cầm chiếc roi giống Vạn Giới Phong Hồn Tiên, vung roi làm thiên địa tan vỡ và tạo bảy trăm vạn thiên địa. Người này còn đánh tan hình bóng khủng bố lao ra từ hư vô.","anchor":"vị thủ lĩnh của đám tu sĩ thần bí cầm cây roi này"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tổ Thiểm Lôi Tộc","tag":"khac","quanHe":"người từng được vị thủ lĩnh giúp đỡ","ghiChu":"Đại trưởng lão nhớ vị thủ lĩnh cầm roi năm xưa đến giúp lão tổ."},{"ten":"Hình bóng khủng bố trong hư vô","tag":"doi-thu","quanHe":"tồn tại bị roi của vị thủ lĩnh đánh tan","ghiChu":"Trong hồi ức, hình bóng từ hư vô bị roi thứ ba đánh tan."},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"khac","quanHe":"người hồi tưởng sự tích cổ xưa","ghiChu":"Đại trưởng lão nhận ra chiếc roi trong tay Vương Lâm nhờ ký ức về vị thủ lĩnh này."}],"tuiDo":{"phapBao":[{"ten":"Vạn Giới Phong Hồn Tiên","loai":"roi pháp bảo đánh hồn","trangThai":"khong-ro","moTa":"Trong hồi ức, vị thủ lĩnh từng cầm chiếc roi giống Vạn Giới Phong Hồn Tiên để tạo bảy trăm vạn thiên địa và đánh tan hình bóng khủng bố.","nguon":"@c1270"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"hinh-bong-khung-bo-trong-hu-vo","name":"Hình bóng khủng bố trong hư vô","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Tồn tại đáng sợ xuất hiện trong hồi ức cổ xưa của đại trưởng lão Thiểm Lôi Tộc. Hình bóng này lao ra khỏi hư vô nhưng bị vị thủ lĩnh đám tu sĩ thần bí dùng roi đánh tan.","vaiTro":"Tồn tại cổ sử chưa rõ lai lịch, làm nổi bật uy lực của chiếc roi Vạn Giới Phong Hồn Tiên.","tinhCach":[],"mucCt":"vua","tabs":{"diem":[{"text":"Chỉ xuất hiện qua hồi ức, chưa rõ thân phận thật hay phe phái.","chuong":"@c1270"},{"text":"Bị roi của vị thủ lĩnh đám tu sĩ thần bí đánh tan.","chuong":"@c1270"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vị thủ lĩnh đám tu sĩ thần bí","tag":"doi-thu","quanHe":"người dùng roi đánh tan hình bóng này","ghiChu":"Hình bóng bị roi thứ ba trong hồi ức cổ xưa đánh tan."},{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tag":"khac","quanHe":"người hồi tưởng sự xuất hiện của hình bóng","ghiChu":"Đại trưởng lão nhớ lại hình bóng này khi nhận ra lai lịch chiếc roi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1270"]},{"id":"tu-si-thien-nhan-de-tu-suy-dan-doi-can-tan-linh-thuong-nhan","name":"Tu sĩ Thiên Nhân Đệ Tứ Suy dẫn đội cản Tán Linh thượng nhân","cn":"","aliases":["Tu sĩ Thiên Nhân Đệ Tứ Suy dẫn đội cản Tán Linh thượng nhân Thiểm Lôi tộc"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tứ Suy @c1274","trangThai":"song @c1274","blurb":"Một tu sĩ Thiên Nhân Đệ Tứ Suy của Thiểm Lôi tộc, xuất hiện khi đại trận bị Vương Lâm phá mở. Người này dẫn bảy tu sĩ Thiên Nhân Suy Kiếp lao tới ngăn Tán Linh thượng nhân.","vaiTro":"tu sĩ Thiểm Lôi tộc cản Tán Linh","tinhCach":[{"text":"hành động theo thế phòng thủ của Thiểm Lôi tộc","chuong":"@c1274"},{"text":"quyết liệt ngăn kẻ xâm nhập khi phòng hộ bị phá","chuong":"@c1274"}],"tabs":{"diem":[{"text":"Là một trong hai tu sĩ Thiên Nhân Đệ Tứ Suy của Thiểm Lôi tộc xuất hiện ở tuyến phòng thủ.","chuong":"@c1274"},{"text":"Dẫn bảy tu sĩ Thiên Nhân Suy Kiếp lao về phía Tán Linh thượng nhân.","chuong":"@c1274"}],"kinhLich":[{"mucCt":"vua","text":"Khi đại trận phòng hộ bị phá, người này dẫn bảy tu sĩ Thiên Nhân Suy Kiếp của Thiểm Lôi tộc lao về phía Tán Linh thượng nhân. Đây là một trong hai mũi phòng thủ được Thiểm Lôi tộc chia ra để ngăn Vương Lâm và Tán Linh.","anchor":"người dẫn đầu đoàn người chính là một trong hai tu sĩ Thiên Nhân Đệ tứ Suy của Thiểm Lôi Tộc","bridge":true,"khoang":"@c1274"}],"tuViMoc":[{"chuong":"@c1274","canhGioi":"Thiên Nhân Đệ Tứ Suy","text":"Xuất hiện với thân phận một trong hai tu sĩ Thiên Nhân Đệ Tứ Suy của Thiểm Lôi tộc.","importance":"major"}],"nhanMach":[{"ten":"Tán Linh thượng nhân","tag":"doi-thu","quanHe":"dẫn đội ngăn cản","ghiChu":"Đối đầu khi Tán Linh tiến vào Thiểm Lôi tộc ở @c1274"},{"ten":"Các tu sĩ Thiên Nhân Suy Kiếp Thiểm Lôi tộc","tag":"dong-minh","quanHe":"dẫn bảy người trong nhóm cùng phòng thủ","ghiChu":"Chia đội ngăn mũi tiến công ở @c1274"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1274"]},{"id":"tu-si-thien-nhan-de-tu-suy-dan-doi-can-vuong-lam","name":"Tu sĩ Thiên Nhân Đệ Tứ Suy dẫn đội cản Vương Lâm","cn":"","aliases":["Tu sĩ Thiên Nhân Đệ Tứ Suy dẫn đội cản Vương Lâm Thiểm Lôi tộc"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tứ Suy @c1274","trangThai":"song @c1274","blurb":"Một tu sĩ Thiên Nhân Đệ Tứ Suy khác của Thiểm Lôi tộc, phụ trách mũi ngăn Vương Lâm khi phòng hộ bị phá. Người này dẫn các tu sĩ Thiên Nhân Suy Kiếp còn lại lao về phía Vương Lâm.","vaiTro":"tu sĩ Thiểm Lôi tộc cản Vương Lâm","tinhCach":[{"text":"trực tiếp tham gia phòng thủ trước kẻ xâm nhập","chuong":"@c1274"},{"text":"hành động theo niềm tin Thiểm Lôi tộc còn có thể chống đỡ","chuong":"@c1274"}],"tabs":{"diem":[{"text":"Là tu sĩ Thiên Nhân Đệ Tứ Suy còn lại trong phòng tuyến Thiểm Lôi tộc.","chuong":"@c1274"},{"text":"Dẫn nhóm tu sĩ còn lại lao về phía Vương Lâm sau khi lôi long mở trận.","chuong":"@c1274"}],"kinhLich":[{"mucCt":"vua","text":"Sau khi lôi long xé mở đại trận, người này dẫn số tu sĩ Thiên Nhân Suy Kiếp còn lại của Thiểm Lôi tộc lao về phía Vương Lâm. Mũi ngăn cản này nhằm chặn Vương Lâm trực tiếp tiến sâu vào địa bàn Thiểm Lôi tộc.","anchor":"Những tên Thiên Nhân Suy Kiếp còn lại lập tức được một tu sĩ Thiên Nhân Đệ Tứ Suy khác mang theo phóng về phía Vương Lâm","bridge":true,"khoang":"@c1274"}],"tuViMoc":[{"chuong":"@c1274","canhGioi":"Thiên Nhân Đệ Tứ Suy","text":"Xuất hiện với thân phận tu sĩ Thiên Nhân Đệ Tứ Suy còn lại của Thiểm Lôi tộc.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"dẫn đội ngăn cản","ghiChu":"Đối đầu khi Vương Lâm phá trận ở @c1274"},{"ten":"Các tu sĩ Thiên Nhân Suy Kiếp Thiểm Lôi tộc","tag":"dong-minh","quanHe":"dẫn số tu sĩ còn lại cùng phòng thủ","ghiChu":"Chia đội ngăn mũi tiến công ở @c1274"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1274"]},{"id":"cac-tu-si-thien-nhan-suy-kiep-thiem-loi-toc","name":"Các tu sĩ Thiên Nhân Suy Kiếp Thiểm Lôi tộc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Suy Kiếp @c1274","trangThai":"khong-ro @c1274","blurb":"Nhóm tu sĩ cấp cao của Thiểm Lôi tộc xuất hiện khi Vương Lâm kéo lôi vực tới trước đại trận. Họ vừa hoảng sợ trước bản thể Vương Lâm vừa chia đội liều chết ngăn Vương Lâm và Tán Linh thượng nhân.","vaiTro":"lực lượng phòng thủ Thiểm Lôi tộc","tinhCach":[{"text":"hoảng sợ khi nhận ra bản thể Vương Lâm","chuong":"@c1274"},{"text":"vẫn liều chết giữ niềm tin vào đại trưởng lão","chuong":"@c1274"}],"tabs":{"diem":[{"text":"Từ thánh địa Thiểm Lôi tộc đi ra khi có cường địch áp sát.","chuong":"@c1274"},{"text":"Chia đội ngăn Vương Lâm và Tán Linh thượng nhân sau khi phòng hộ bị phá.","chuong":"@c1274"},{"text":"Có người tự bạo tộc ấn để trì hoãn đối phương.","chuong":"@c1274"}],"kinhLich":[{"mucCt":"vua","text":"Các tu sĩ Thiên Nhân Suy Kiếp Thiểm Lôi tộc ra khỏi thánh địa, nhận ra bản thể Vương Lâm và rơi vào dao động. Khi đại trận bị phá, họ chia làm hai đội cản Vương Lâm và Tán Linh thượng nhân, thậm chí có người tự bạo tộc ấn để kéo dài thời gian.","anchor":"thậm chí còn có kẻ tự bạo tộc ấn để ngăn cản đối phương","bridge":true,"khoang":"@c1274"}],"tuViMoc":[{"chuong":"@c1274","canhGioi":"Thiên Nhân Suy Kiếp","text":"Xuất hiện với tư cách nhóm mười một người đạt Thiên Nhân Suy Kiếp trong Thiểm Lôi tộc.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"chia đội ngăn cản","ghiChu":"Đối đầu khi Vương Lâm phá trận ở @c1274"},{"ten":"Tán Linh thượng nhân","tag":"doi-thu","quanHe":"chia đội ngăn cản","ghiChu":"Đối đầu khi Tán Linh theo vào Thiểm Lôi tộc ở @c1274"},{"ten":"Đại trưởng lão Thiểm Lôi tộc","tag":"khac","quanHe":"tin tưởng là trụ tinh thần của toàn tộc","ghiChu":"Vẫn tin đại trưởng lão sẽ trở về ở @c1274"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Tộc ấn Thiểm Lôi tộc","trangThai":"da-dung","moTa":"Có người tự bạo tộc ấn để ngăn cản đối phương.","nguon":"@c1274"}]}},"nguon":["@c1274"]},{"id":"toc-nhan-thiem-loi-toc-trong-dai-tran","name":"Tộc nhân Thiểm Lôi tộc trong đại trận","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiểm Lôi tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1274","trangThai":"khong-ro @c1274","blurb":"Tộc nhân Thiểm Lôi tộc trong đại trận chứng kiến Vương Lâm công phá phòng hộ và tuyên bố đại trưởng lão đã bại. Họ không chịu tin sự thật này, tiếp tục dựa vào niềm tin đại trưởng lão sẽ trở về để chống đỡ tinh thần.","vaiTro":"tộc nhân cố thủ trong đại trận","tinhCach":[{"text":"dao động trước lời tuyên bố của Vương Lâm","chuong":"@c1274"},{"text":"cố chấp tin đại trưởng lão chưa thể bại","chuong":"@c1274"}],"tabs":{"diem":[{"text":"Chứng kiến lôi long phá đại trận phòng hộ của Thiểm Lôi tộc.","chuong":"@c1274"},{"text":"Không tin đại trưởng lão đã bị Vương Lâm bắt nguyên thần.","chuong":"@c1274"}],"kinhLich":[{"mucCt":"vua","text":"Tộc nhân trong đại trận nhìn phòng hộ bị lôi long công phá và nghe Vương Lâm tuyên bố đại trưởng lão đã bị bắt nguyên thần. Họ vẫn phản bác, tự trấn an rằng đại trưởng lão có tu vi thông thiên và không thể dễ dàng bại trận.","anchor":"Vẻ mặt đám người THiểm Lôi tộc trong tầng phòng hộ đều cực kỳ âm trầm","bridge":true,"khoang":"@c1274"}],"tuViMoc":[],"nhanMach":[{"ten":"Đại trưởng lão Thiểm Lôi tộc","tag":"khac","quanHe":"xem là trụ tinh thần của toàn tộc","ghiChu":"Cố giữ niềm tin vào đại trưởng lão ở @c1274"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị Vương Lâm dùng lời nói và bằng chứng đánh vào niềm tin","ghiChu":"Nghe Vương Lâm tuyên bố đại trưởng lão đã bại ở @c1274"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1274"]},{"id":"tu-si-thien-nhan-de-tu-suy-thiem-loi-toc","name":"Tu sĩ Thiên Nhân Đệ Tứ Suy Thiểm Lôi Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tứ Suy @c1275","trangThai":"tu-vong","blurb":"Một cường giả Thiểm Lôi Tộc bị Vương Lâm chọn làm mục tiêu khi toàn tộc đang rối loạn. Ông bị huyết kiếm xuyên mi tâm rồi xuyên tiếp nguyên thần.","vaiTro":"cường giả Thiểm Lôi Tộc bị giết","tinhCach":[{"text":"mất cảnh giác trong đại loạn","chuong":"@c1275"},{"text":"là một trong các tu sĩ cấp cao bảo vệ Thiểm Lôi Tộc","chuong":"@c1275"}],"tabs":{"diem":[{"text":"Bị Vương Lâm nhắm tới ngay khi tâm thần Thiểm Lôi Tộc hỗn loạn.","chuong":"@c1275"},{"text":"Thân thể và nguyên thần đều bị huyết kiếm xuyên phá.","chuong":"@c1275"}],"kinhLich":[{"mucCt":"vua","text":"Tu sĩ Thiên Nhân Đệ Tứ Suy Thiểm Lôi Tộc bị Vương Lâm chọn làm mục tiêu trong lúc cả tộc hỗn loạn. Huyết kiếm xuyên mi tâm làm thân thể tan vỡ rồi tiếp tục xuyên qua nguyên thần của ông.","anchor":"khoảnh khắc này thanh kiếm đã phóng về phía tên tu sĩ Thiên Nhân Đệ Tứ Suy ở phía trước","bridge":true,"khoang":"@c1275"}],"tuViMoc":[{"chuong":"@c1275","canhGioi":"Thiên Nhân Đệ Tứ Suy","text":"Xuất hiện với tu vi Thiên Nhân Đệ Tứ Suy trước khi bị Vương Lâm giết.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị Vương Lâm giết","ghiChu":"Bị huyết kiếm của Vương Lâm xuyên phá thân thể và nguyên thần."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1275"]},{"id":"am-thanh-trong-vong-xoay","name":"Âm thanh trong vòng xoáy","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ @c1275","trangThai":"khong-ro","blurb":"Chủ thể chưa lộ danh tính trong vòng xoáy hư vô. Thực thể này kéo sấm sét bất diệt vào vòng xoáy và uy hiếp Vương Lâm buông tay.","vaiTro":"chủ thể bí ẩn trong vòng xoáy","tinhCach":[{"text":"uy hiếp trực diện khi bị tranh đoạt sấm sét","chuong":"@c1275"},{"text":"ẩn giấu thân phận sau vòng xoáy hư vô","chuong":"@c1275"}],"tabs":{"diem":[{"text":"Phát ra lời cảnh cáo rằng sấm sét không thuộc về một người.","chuong":"@c1275"},{"text":"Âm thanh lan rộng khiến Thái Cổ Tinh Thần chấn động.","chuong":"@c1275"}],"kinhLich":[{"mucCt":"vua","text":"Âm thanh trong vòng xoáy kéo sấm sét bất diệt vào trung tâm vòng xoáy và ra lệnh cho Vương Lâm buông tay. Lời uy hiếp của chủ thể này vang rộng, làm toàn bộ Thái Cổ Tinh Thần chấn động.","anchor":"Ngươi hãy buông ra ngay, sấm sét này không phải thứ của một người","bridge":true,"khoang":"@c1275"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tranh đoạt sấm sét bất diệt","ghiChu":"Uy hiếp Vương Lâm buông tay trong lúc hai bên giằng co sấm sét."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Vòng xoáy hư vô kéo sấm sét","trangThai":"dang-co","moTa":"Dùng vòng xoáy kéo sấm sét bất diệt vào trung tâm hư vô.","nguon":"@c1275"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1275"]},{"id":"cac-tu-si-de-tam-bo-dai-nang-trong-thai-co-tinh-than","name":"Các tu sĩ Đệ Tam Bộ đại năng trong Thái Cổ Tinh Thần","cn":"","aliases":["Các tu sĩ Thái Cổ Tinh Thần truy tìm Vương Lâm"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Đệ Tam Bộ","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Đệ Tam Bộ @c1276","trangThai":"song","blurb":"Nhóm đại năng trong Thái Cổ Tinh Thần cùng cảm ứng dấu hiệu Viễn Cổ Tiên Phi tái hiện. Họ xuất hiện như phản ứng tập thể của tầng tu sĩ cấp cao trước biến động lớn.","vaiTro":"Đại năng cảm ứng biến động","tinhCach":[{"text":"Nhạy bén trước dấu hiệu dị thường","chuong":"@c1276"},{"text":"Giữ vẻ âm trầm khi biến cố tái hiện","chuong":"@c1276"}],"tabs":{"diem":[{"text":"Đồng loạt biến sắc và nhìn lên tinh không khi dấu hiệu Viễn Cổ Tiên Phi xuất hiện.","chuong":"@c1276"},{"text":"Đại diện cho tầng đại năng Đệ Tam Bộ tại Thái Cổ Tinh Thần.","chuong":"@c1276"},{"text":"Cùng cảm ứng dấu hiệu và ngẩng đầu nhìn tinh không.","chuong":"@c1276"}],"kinhLich":[{"mucCt":"vua","text":"Vài vạn tu sĩ Thái Cổ Tinh Thần bao phủ tu chân tinh để truy tìm Vương Lâm và dùng thần thức quét ngang thiên địa. Khi sấm sét của Vương Lâm tràn khắp trời đất rồi Không Đại Môn hiện ra, họ từ phấn chấn chuyển sang hoảng sợ và có người nhận ra cánh cửa Đệ Tam Bộ.","anchor":"Vài vạn tu sĩ đang truy tìm tung tích Vương Lâm đã không còn phấn chấn mà cảm thấy cực kỳ hoảng sợ","bridge":true,"khoang":"@c1282"}],"tuViMoc":[{"chuong":"@c1276","canhGioi":"Đệ Tam Bộ","text":"Được nêu là nhóm tu sĩ Đệ Tam Bộ đại năng trong Thái Cổ Tinh Thần.","importance":"major"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1276","@c1282"]},{"id":"vai-co-gai-trong-vien-co-tien-vuc","name":"Vài cô gái trong Viễn Cổ Tiên Vực","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Viễn Cổ Tiên Vực","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Những nữ tử tĩnh tọa trong khu vực ít người biết của Viễn Cổ Tiên Vực. Họ cùng mở mắt khi dấu hiệu Viễn Cổ Tiên Phi tái hiện.","vaiTro":"Nữ tu cảm ứng dấu hiệu","tinhCach":[{"text":"Ẩn cư trong nơi ít người biết","chuong":"@c1276"},{"text":"Cảm ứng được biến động Viễn Cổ Tiên Phi","chuong":"@c1276"}],"tabs":{"diem":[{"text":"Đang tĩnh tọa trong Viễn Cổ Tiên Vực thì đồng loạt mở mắt.","chuong":"@c1276"},{"text":"Phản ứng của họ cho thấy Viễn Cổ Tiên Vực có liên hệ với dấu hiệu Viễn Cổ Tiên Phi.","chuong":"@c1276"},{"text":"Cùng phản ứng khi dấu hiệu Viễn Cổ Tiên Phi tái hiện.","chuong":"@c1276"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1276"]},{"id":"do-ti","name":"Đồ Ti","aliases":["Cổ thần Đồ Ti","Đồ Ti"],"nguon":["@c1276","@c1303"],"tabs":{"kinhLich":[{"chuong":"@c1276","importance":"normal","mucCt":"gon","tieuDe":"Được nhận ra","text":"Đồ Ti được Thác Sâm nhắc tới trong ký ức khí tức đồng tộc, rồi lại bị tồn tại trong vòng xoáy kinh hãi gọi tên khi hư ảnh Cổ Thần sau lưng Vương Lâm hiện ra.","anchor":"Đây…Đây là Đồ Ti"},{"mucCt":"vua","anchor":"Thuật này trong trí nhớ của Đồ Ti không có","text":"Vương Lâm dùng trí nhớ Đồ Ti để đối chiếu Thiên Hoàng Lô và thần thông trong Hộ cốt Thạch Bi. Hắn xác nhận Tổ Hồn trợ giúp là thần thông Cổ Thần bát tinh không có trong trí nhớ Đồ Ti.","bridge":true,"khoang":"@c1303"}],"diem":[{"text":"Sau mười ba năm thử luyện, phân thân Đồ Ti xuất hiện và công nhận Vương Lâm là người lĩnh ngộ truyền thừa.","chuong":"@c0160"},{"text":"Truyền thừa của Đồ Ti khiến Tứ tinh Cổ Thần của Vương Lâm mang tính vương tộc và vượt xa đồng cấp thông thường.","chuong":"@c0881"},{"text":"La Trần xác nhận Đồ Ti đã chết và nhận ra truyền thừa của Vương Lâm đến từ hắn.","chuong":"@c0882"},{"text":"Đồ Ti được nhắc là người đơn độc mở ra không gian Cổ Thần Chi Địa, nơi tồn tại thân thể khổng lồ của hắn.","chuong":"@c0996"},{"text":"Thân thể Đồ Ti là vương tộc bát tinh Cổ Thần tồn tại từ vạn cổ, về sau bị Thác Sâm chiếm.","chuong":"@c1383"},{"text":"Đồ Ti thức tỉnh trong thân xác Thác Sâm, triệu trường mâu đâm Chưởng Tôn, rồi ở lại chặn Chiến lão quỷ cho Vương Lâm.","chuong":"@c1680"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"khac","quanHe":"Liên hệ ký ức Cổ Thần","ghiChu":"Tên Đồ Ti được Thác Sâm dùng để phân biệt ký ức nhận ra khí tức đồng tộc."},{"ten":"Sứ giả thiên đạo","tag":"doi-thu","quanHe":"Bị nhận ra trong hư ảnh Cổ Thần","ghiChu":"Tồn tại trong vòng xoáy kinh hãi gọi Đồ Ti khi thấy hư ảnh sau lưng Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"hư ảnh Cổ Thần được liên tưởng","ghiChu":"Hư ảnh Cổ Thần sau lưng Vương Lâm khiến tồn tại trong vòng xoáy kinh hãi gọi tên Đồ Ti."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"trangThai":"khong-ro","tinhCach":"Thận trọng chọn người kế thừa; kiêu hãnh mang khí phách Cổ Thần; trầm ổn tỉnh táo khi thức tỉnh; sẵn sàng chặn địch cho Vương Lâm","gioiTinh":"nam","canhGioiCaoNhat":"Cổ Thần","theLuc":[{"ten":"Bộ tộc Cổ Thần","trangThai":"gan-bo"}],"vaiTro":"Cổ thần vương tộc — nguồn truyền thừa Cổ Thần của Vương Lâm","blurb":"Đồ Ti là Cổ thần vương tộc bát tinh, chủ Cấm Sơn trong Cổ Thần Chi Địa và là nguồn truyền thừa Cổ Thần quan trọng của Vương Lâm. Truyền thừa ký ức của hắn giúp Vương Lâm nhận biết nhiều pháp bảo, sinh linh và quy luật Cổ Thần, nhưng phần ký ức ấy không trọn vẹn và còn bị phong ấn. Về sau, thân thể Đồ Ti được nhắc là đã bị Thác Sâm chiếm, song hắn từng thức tỉnh trong thân xác ấy và ở lại chặn Chiến lão quỷ cho Vương Lâm."},{"id":"su-gia-thien-dao","name":"Sứ giả thiên đạo","cn":"","aliases":["tồn tại thần bí trong vòng xoáy"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Sứ giả thiên đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Tồn tại thần bí trong vòng xoáy từng cướp hồn phách Uyển Nhi hơn một ngàn năm trước. Hắn hiện cánh tay khổng lồ tấn công Vương Lâm nhưng bị chém đứt bàn tay.","vaiTro":"Kẻ thù thiên đạo của Vương Lâm","tinhCach":[{"text":"Cao ngạo, xem Cổ Thần là dư nghiệt bị tinh không trừng phạt","chuong":"@c1276"},{"text":"Nhận biết Đồ Ti và kinh nghi trước thanh kiếm của Vương Lâm","chuong":"@c1276"},{"text":"Hung hãn nhưng vẫn rút lui khi bị thương","chuong":"@c1276"}],"tabs":{"diem":[{"text":"Từng liên quan trực tiếp tới việc cướp hồn phách Uyển Nhi.","chuong":"@c1276"},{"text":"Từ vòng xoáy xé ra cánh tay khổng lồ để trấn áp Vương Lâm.","chuong":"@c1276"},{"text":"Bị một kiếm của Vương Lâm chém đứt bàn tay và rút về trong kinh nghi.","chuong":"@c1276"},{"text":"Từng cướp hồn phách Uyển Nhi trong quá khứ.","chuong":"@c1276"},{"text":"Duỗi cánh tay khổng lồ từ vòng xoáy để tấn công Vương Lâm.","chuong":"@c1276"},{"text":"Bị Vương Lâm chém đứt bàn tay và rút về vòng xoáy.","chuong":"@c1276"},{"text":"Từng cướp hồn phách Uyển Nhi khỏi tay Vương Lâm hơn một ngàn năm trước.","chuong":"@c1276"},{"text":"Từ vòng xoáy duỗi cánh tay khổng lồ để trấn áp Vương Lâm nhưng bị huyết kiếm chém đứt bàn tay.","chuong":"@c1276"}],"kinhLich":[{"chuong":"@c1276","importance":"normal","mucCt":"ky","tieuDe":"Bị chém đứt tay","text":"Sứ giả thiên đạo từ vòng xoáy ép Vương Lâm buông sấm sét bất diệt, gọi hắn là dư nghiệt Cổ Thần bị tinh không trừng phạt. Sau khi duỗi cánh tay khổng lồ ra tấn công, hắn kinh hãi trước hư ảnh Đồ Ti và bị một kiếm hợp lực của Vương Lâm chém đứt bàn tay, phải rút về vòng xoáy trong tiếng kêu thảm.","anchor":"Sứ giả thiên đạo"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tử địch","ghiChu":"Bị Vương Lâm nhận ra là kẻ cướp hồn Uyển Nhi và bị chém đứt bàn tay."},{"ten":"Lý Mộ Uyển","tag":"doi-thu","quanHe":"Kẻ cướp hồn","ghiChu":"Vương Lâm nhắc lại việc sứ giả thiên đạo năm xưa cướp hồn phách Uyển Nhi."},{"ten":"Đồ Ti","tag":"khac","quanHe":"Nhận biết hư ảnh","ghiChu":"Kinh hãi gọi tên Đồ Ti khi thấy hư ảnh Cổ Thần sau lưng Vương Lâm."},{"ten":"Cổ thần Đồ Ti","tag":"khac","quanHe":"biết lai lịch","ghiChu":"Khi hư ảnh Cổ Thần hiện ra phía sau Vương Lâm, sứ giả thiên đạo kinh hãi gọi tên Đồ Ti."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1276"]},{"id":"lao-gia-chu-quan-than-truoc-cong-thon","name":"Lão già chủ quán than trước cổng thôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Lão chủ quán lưng còng ở con đường trước nhà Vương Lâm tại thành tây. Trong đêm lạnh, lão tặng Vương Lâm một bình rượu gạo và để lại một khoảnh khắc đời thường yên bình.","vaiTro":"chủ quán phàm tục","tinhCach":[{"text":"chất phác, hay quan tâm người khác","chuong":"@c1277"},{"text":"vui tính, nói chuyện thân tình","chuong":"@c1277"}],"tabs":{"diem":[{"text":"Lão thu dọn quán, trông nom hai tiểu nhị rồi để ý tới Vương Lâm ở căn nhà đối diện.","chuong":"@c1277"},{"text":"Lão tặng bình rượu gạo cho Vương Lâm, dặn uống vào cho ấm trong đêm lạnh.","chuong":"@c1277"}],"kinhLich":[{"mucCt":"gon","text":"Lão chủ quán sau khi thu dọn quán đã ném bình rượu gạo cho Vương Lâm, nói uống vào để giữ ấm thân thể khi đọc sách.","anchor":"bình rượu gạo này cho cậu, uống vào để thân thể ấm áp mà đọc sách","bridge":true,"khoang":"@c1277"}],"tuViMoc":[{"chuong":"@c1277","canhGioi":"Phàm nhân","text":"Xuất hiện như một lão chủ quán phàm tục ở thành tây.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người được lão tặng rượu","ghiChu":"Lão tưởng Vương Lâm là học trò nghèo đọc sách chờ thi nên đưa rượu gạo giữ ấm."},{"ten":"Hai tiểu nhị của quán than","tag":"khac","quanHe":"người làm trong quán","ghiChu":"Hai tiểu nhị thu dọn đồ đạc dưới sự trông nom của lão."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Bầu rượu gạo của lão chủ quán","loai":"đồ uống","trangThai":"da-tang","moTa":"Bình rượu gạo lão đưa cho Vương Lâm trong đêm lạnh.","nguon":"@c1277"}]}},"nguon":["@c1277"]},{"id":"hai-tieu-nhi-cua-quan-than","name":"Hai tiểu nhị của quán than","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Hai tiểu nhị làm việc tại quán than trước con đường nơi Vương Lâm mua nhà. Họ chỉ xuất hiện trong cảnh thu dọn quán lúc đêm xuống.","vaiTro":"tiểu nhị quán than","tinhCach":[{"text":"làm việc theo sự trông nom của chủ quán","chuong":"@c1277"},{"text":"ít được khắc họa riêng","chuong":"@c1277"}],"tabs":{"diem":[{"text":"Cùng thu dọn đồ đạc ở quán than khi lão chủ quán chuẩn bị nghỉ.","chuong":"@c1277"}],"kinhLich":[{"chuong":"@c1277","importance":"bridge","mucCt":"gon","tieuDe":"Thu dọn quán than","text":"Hai tiểu nhị thu dọn đồ đạc trong quán than dưới mắt lão chủ quán rồi cùng rời đi.","anchor":"đang đưa mắt nhìn hai tiểu nhị thu dọn đồ đạc"}],"tuViMoc":[{"chuong":"@c1277","canhGioi":"Phàm nhân","text":"Xuất hiện như tiểu nhị phàm tục trong quán than.","importance":"minor"}],"nhanMach":[{"ten":"Lão già chủ quán than trước cổng thôn","tag":"khac","quanHe":"chủ quán","ghiChu":"Hai người làm việc trong quán của lão chủ quán."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1277"]},{"id":"nguoi-go-mo-cam-canh","name":"Người gõ mõ cầm canh","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Người gõ mõ đi tuần trong đêm khuya ở thành tây. Tiếng mõ và lời nhắc của người này làm nổi bật sự yên bình phàm tục quanh nơi Vương Lâm tạm trú.","vaiTro":"người tuần canh ban đêm","tinhCach":[{"text":"làm việc theo nếp sinh hoạt ban đêm của thành tây","chuong":"@c1277"},{"text":"chỉ xuất hiện qua tiếng mõ và lời nhắc","chuong":"@c1277"}],"tabs":{"diem":[{"text":"Tiếng mõ cầm canh vang qua con đường yên tĩnh lúc Vương Lâm đang luyện hóa trong nhà.","chuong":"@c1277"}],"kinhLich":[{"chuong":"@c1277","importance":"bridge","mucCt":"gon","tieuDe":"Gõ mõ giữa đêm","text":"Người gõ mõ cầm canh đi qua trong đêm khuya, tiếng nói và tiếng mõ khẽ phá sự yên tĩnh của thành tây rồi xa dần.","anchor":"giọng nói của người gõ mõ cầm canh phá tan không gian yên tĩnh"}],"tuViMoc":[{"chuong":"@c1277","canhGioi":"Phàm nhân","text":"Xuất hiện như người cầm canh phàm tục trong đô thành.","importance":"minor"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1277"]},{"id":"nhung-hang-xom-thanh-tay","name":"Những hàng xóm thành tây","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","blurb":"Những cư dân sống quanh căn nhà Vương Lâm mua ở thành tây. Họ xem Vương Lâm là học trò nghèo tới thuê nhà đọc sách chờ kỳ thi năm sau.","vaiTro":"hàng xóm phàm tục","tinhCach":[{"text":"gần gũi, hay qua lại chuyện trò","chuong":"@c1277"},{"text":"tin vào thân phận học trò nghèo của Vương Lâm","chuong":"@c1277"}],"tabs":{"diem":[{"text":"Họ nhanh chóng biết Vương Lâm vừa tới thành tây và tưởng hắn là học trò chờ thi.","chuong":"@c1277"}],"kinhLich":[{"chuong":"@c1277","importance":"bridge","mucCt":"gon","tieuDe":"Nhận lầm học trò","text":"Những hàng xóm quanh nhà đến nói chuyện và tin rằng Vương Lâm là học trò nghèo thuê nhà đọc sách chờ kỳ thi năm sau.","anchor":"những người hàng xóm xung quanh biết được Vương Lâm là một học trò tới đây thi"}],"tuViMoc":[{"chuong":"@c1277","canhGioi":"Phàm nhân","text":"Xuất hiện như cư dân phàm tục ở khu thành tây.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"hàng xóm","ghiChu":"Họ sống quanh căn nhà Vương Lâm mua và trò chuyện với hắn theo thân phận học trò."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1277"]},{"id":"nguyet-huyen","name":"Nguyệt Huyên","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"khong-ro @c1278","trangThai":"song","blurb":"Nguyệt Huyên là nữ tu xuất hiện trên tầng mây của tu chân tinh trong lúc mưa sấm dữ dội. Nàng đi cùng thanh niên họ Dự, nghe tin Thiểm Lôi Tộc bị diệt và Thái Cổ Tinh Thần Lệnh đã ban ra.","vaiTro":"Nữ tu nhận tin truy sát","tinhCach":[{"text":"Dịu dàng khi gặp người quen","chuong":"@c1278"},{"text":"Dễ kinh hãi trước biến cố lớn","chuong":"@c1278"}],"nguon":["@c1278"],"tabs":{"diem":[{"text":"Đi cùng thanh niên họ Dự theo lệnh triệu tập khẩn cấp của bộ tộc.","chuong":"@c1278"},{"text":"Gọi thanh niên họ Chu là Chu đại ca và nghe tin Thiểm Lôi Tộc bị tiêu diệt.","chuong":"@c1278"}],"kinhLich":[{"mucCt":"vua","text":"Nguyệt Huyên cùng thanh niên họ Dự đi trên tầng mây theo lệnh triệu tập của bộ tộc. Khi thanh niên họ Chu xuất hiện, nàng chào hỏi rồi kinh hãi trước tin Thiểm Lôi Tộc bị diệt và Trường Tôn Hội phát lệnh truy sát.","anchor":"Cô gái y phục rực rỡ cũng lộ ra nụ cười dịu dàng, nàng khẽ nói","bridge":true,"khoang":"@c1278"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên họ Dự","tag":"dong-minh","quanHe":"đi cùng","ghiChu":"Cùng di chuyển trên tầng mây theo lệnh triệu tập của bộ tộc."},{"ten":"Thanh niên họ Chu","tag":"ban-be","quanHe":"quen biết","ghiChu":"Gọi là Chu đại ca khi gặp trên tầng mây."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"thanh-nien-ho-du","name":"Thanh niên họ Dự","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"mơ hồ đạt Khuy Niết @c1278","trangThai":"song","blurb":"Thanh niên họ Dự là nam tu áo xanh đi cùng Nguyệt Huyên trên tầng mây. Hắn tỏ ra thận trọng trước dị biến gió đen và chấn động khi nghe tin đại trưởng lão Thiểm Lôi Tộc cùng cả tộc thất bại.","vaiTro":"Nam tu nhận tin truy sát","tinhCach":[{"text":"Thận trọng trước dấu hiệu bất thường","chuong":"@c1278"},{"text":"Kính sợ cao thủ Thiểm Lôi Tộc","chuong":"@c1278"}],"nguon":["@c1278"],"tabs":{"diem":[{"text":"Đi cùng Nguyệt Huyên trong lúc nhận lệnh triệu tập khẩn cấp của bộ tộc.","chuong":"@c1278"},{"text":"Nhận ra biến động gió đen và dừng lại trước khi thanh niên họ Chu xuất hiện.","chuong":"@c1278"}],"kinhLich":[{"mucCt":"vua","text":"Thanh niên họ Dự đi cùng Nguyệt Huyên trên tầng mây, dừng lại khi phát hiện gió đen bất thường. Hắn chào thanh niên họ Chu và kinh hãi khi biết Thiểm Lôi Tộc bị diệt, đại trưởng lão thất bại mất tích.","anchor":"Đồng tử trong mắt người thanh niên đưa tay cản trước mặt cô gái đột nhiên co rút lại","bridge":true,"khoang":"@c1278"}],"tuViMoc":[{"chuong":"@c1278","canhGioi":"Khuy Niết","text":"Tu vi của thanh niên họ Dự được miêu tả mơ hồ đạt tới Khuy Niết.","importance":"minor"}],"nhanMach":[{"ten":"Nguyệt Huyên","tag":"dong-minh","quanHe":"đi cùng","ghiChu":"Cùng nhận lệnh triệu tập của bộ tộc."},{"ten":"Thanh niên họ Chu","tag":"ban-be","quanHe":"quen biết","ghiChu":"Chào hỏi khi gặp trên tầng mây."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"thanh-nien-ho-chu","name":"Thanh niên họ Chu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro @c1278","trangThai":"song","blurb":"Thanh niên họ Chu là tu sĩ áo đen xuất hiện từ gió đen trên tầng mây. Hắn mang tin Thiểm Lôi Tộc bị tiêu diệt, Trường Tôn Hội ban Thái Cổ Tinh Thần Lệnh và toàn Thái Cổ Tinh Thần sẽ truy sát hung thủ.","vaiTro":"Người truyền tin truy sát","tinhCach":[{"text":"Nắm tin tức từ Trường Tôn Hội","chuong":"@c1278"},{"text":"Nói thẳng biến cố lớn cho người quen","chuong":"@c1278"}],"nguon":["@c1278"],"tabs":{"diem":[{"text":"Xuất hiện từ gió đen và gặp Nguyệt Huyên cùng thanh niên họ Dự.","chuong":"@c1278"},{"text":"Thông báo việc Thiểm Lôi Tộc bị diệt và hung thủ bị toàn Thái Cổ Tinh Thần truy sát.","chuong":"@c1278"}],"kinhLich":[{"mucCt":"ky","text":"Thanh niên họ Chu xuất hiện từ gió đen và gặp hai người quen trên tầng mây. Hắn nói Thiểm Lôi Tộc đã bị tiêu diệt, đại trưởng lão thất bại mất tích, Trường Tôn Hội đã chứng thực và ban Thái Cổ Tinh Thần Lệnh cho các bộ tộc. Hắn còn cho biết Đại Tư Vân Lạc dùng Thuật Thiên Đại Tinh Thần thôi diễn hình ảnh cùng ký ức thần thức của hung thủ, rồi phân tán để sinh linh Thái Cổ Tinh Thần truy sát người đã thôn phệ sấm sét bất diệt.","anchor":"Cụ thể thì không rõ những nghe Trường Tôn Hội nói luồng sấm sét bất diệt của Thiểm Lôi Tộc đã bị người đó thôn phệ","bridge":true,"khoang":"@c1278"}],"tuViMoc":[],"nhanMach":[{"ten":"Nguyệt Huyên","tag":"ban-be","quanHe":"quen biết","ghiChu":"Được Nguyệt Huyên gọi là Chu đại ca."},{"ten":"Thanh niên họ Dự","tag":"ban-be","quanHe":"quen biết","ghiChu":"Gặp và truyền tin trên tầng mây."},{"ten":"Vân Lạc","tag":"khac","quanHe":"người được nhắc trong tin tức","ghiChu":"Nhắc Vân Lạc là người thôi diễn hung thủ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"van-lac","name":"Vân Lạc","cn":"云洛","aliases":["Đại Tư Vân Lạc Trường Tôn Hội","Vân Lạc Đại Tư Trường Tôn Hội","Vân Lạc đại ti","Vân Lạc địa ti","Vân Lạc đại tiểu thư"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Trường Tôn Hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1315","trangThai":"song","blurb":"Vân Lạc là Đại Tư của Trường Tôn Hội, sở hữu Thuật Thiên Đại Tinh Thần có thể thôi diễn hình ảnh, ký ức và tung tích mục tiêu. Nàng tính ra hình dáng cùng khí tức của Vương Lâm để hỗ trợ Tư Mặc Tử truy sát, đồng hành tới Đại Đế tinh bái kiến đại đế, và tại đó nhiều lần âm thầm thôi diễn bí ẩn liên quan tới hạo kiếp Thái Cổ Tinh Thần nhưng liên tục bị lực lượng bí ẩn cắt đứt phép tính và phản phệ trọng thương. Sau khi bế quan hồi phục, nàng tái xuất với vai trò chỉ huy đại quân giới ngoại tấn công Vương Lâm, bày bẫy liên hoàn nhưng phân thân bị Khai Thiên Phủ chém nát; về sau phân thân của nàng","vaiTro":"Đại Tư của Trường Tôn Hội — chuyên gia thôi diễn tinh thần, chỉ huy quân sự giới ngoại","tinhCach":"Tinh thông thuật toán thôi diễn, suy tính tung tích và bí ẩn với độ chính xác cao; hành sự âm trầm kín kẽ, thường giấu tay bắt ấn quyết ngay giữa đám đông; kiên trì truy xét và chỉ huy quyết đoán dù liên tục bị phản phệ trọng thương; dễ hoảng loạn khiếp sợ khi biến cố vượt ngoài dự liệu hoặc đối diệ","nguon":["@c1278","@c1280","@c1281","@c1287","@c1288","@c1305","@c1307","@c1309","@c1312","@c1313","@c1314","@c1315","@c1318","@c1319","@c1320","@c1322","@c1323"],"tabs":{"diem":[{"text":"Dùng Thuật Thiên Đại Tinh Thần thôi diễn quả cầu nước hiển hiện hình bóng Vương Lâm, suy tính ra khí tức và tung tích của hắn để hỗ trợ Tư Mặc Tử truy sát","chuong":"@c1281"},{"text":"Bị lực lượng bí ẩn phản phệ khi thôi diễn bí ẩn cây hương trên Đại Đế tinh, tay phải rách nát nôn máu, trong cảnh hư ảo thấy dự tượng hạo kiếp Thái Cổ Tinh Thần","chuong":"@c1322"},{"text":"Chỉ huy đại quân giới ngoại bày bẫy liên hoàn truy sát Vương Lâm, điều khiển toàn quân phân bốn hướng và tiên tri tiên cơ để phục kích Hồng Sam Tử","chuong":"@c1429"},{"text":"Phân thân trên chiến trường bị Khai Thiên Phủ chém nát huyết thuẫn bát giác rồi xuyên thấu, thân thể hóa tan, bổn tôn bị diệt nhưng hồn phách thoát đi","chuong":"@c1433"},{"text":"Nhận ra Vương Lâm chính là bóng hình đáng sợ từng thấy trong thôi diễn, thân thể run rẩy không thể khống chế","chuong":"@c1561"},{"text":"Bóp nát ngọc giản bảo mạng do sư tôn trước khi chết tế luyện để thoát khỏi bánh xe vận mệnh của Vương Lâm","chuong":"@c1566"}],"kinhLich":[{"mucCt":"gon","text":"Vân Lạc được nhắc là Đại Tư Trường Tôn Hội đã dùng Thuật Thiên Đại Tinh Thần để thôi diễn hình ảnh và ký ức thần thức của thủ phạm diệt Thiểm Lôi Tộc.","anchor":"Hơn nữa Đại Tư Vân Lạc Trường Tôn Hội đã thôi diễn thuật Thiên Đại Tinh Thần","bridge":true,"khoang":"@c1278"},{"mucCt":"gon","text":"Vân Lạc được nhắc là Đại Tư của Trường Tôn Hội đã tính ra mục tiêu nằm trong tinh vực này, khiến Vương Lâm biết thần thông của người này có thể suy ra địa phương của hắn.","anchor":"Vân Lạc Đại Tư Trường Tôn Hội đã tính ra người đó ở trong tinh vực này","bridge":true,"khoang":"@c1280"},{"mucCt":"vua","text":"Trên đảo nhỏ của tu chân tinh màu xanh, Vân Lạc dùng quả cầu nước hiển hiện hình bóng Vương Lâm và suy tính ra nơi hắn đang ẩn thân. Nàng báo tin cho Trường Tôn Hội cùng các trưởng lão, khiến cuộc truy tìm chuyển thành lệnh vây bắt quy mô lớn.","anchor":"VÂn Lạc đã tính ra được người hủy diệt THiểm Lôi tộc hiện đang ở chỗ nào rồi.","bridge":true,"khoang":"@c1281"},{"chuong":"@c1287","importance":"bridge","mucCt":"gon","tieuDe":"Tính ra tung tích","text":"Vân Lạc được Tư Mặc Tử nhắc là người đã tính ra Vương Lâm đang trốn tại Điên Lạc.","anchor":"Vân Lạc đại ti đã tính hắn trốn tại Điên Lạc này"},{"chuong":"@c1288","importance":"bridge","mucCt":"gon","text":"Vân Lạc được nhắc như người đã tính ra hình dáng và khí tức của Vương Lâm để Tư Mặc Tử nhận diện mục tiêu.","anchor":"Hình dáng vào khí tức của đối phương, sớm đã được Vân Lạc địa ti tính ra rồi"},{"mucCt":"ky","text":"Vân Lạc cưỡi đồ hình bát giác cùng Tư Mặc Tử đến Đại đế tinh, tự xưng thay mặt Trường Tôn hội bái kiến đại đế và nhận lời Lạc Sinh hội đến xem tuyển chọn trưởng lão. Nàng mềm mỏng hỏi tên Vương Lâm nhưng gọi hắn theo thế ngang hàng, nên bị Vương Lâm lạnh lùng mắng là tiểu bối không biết lễ.","anchor":"Tiểu nữ Vân Lạc, thay mặt Trường Tôn hội tới bái kiến đại đế","bridge":true,"khoang":"@c1307"},{"chuong":"@c1309","importance":"bridge","mucCt":"gon","tieuDe":"Được Vương Lâm cân nhắc","text":"Vân Lạc được Vương Lâm đặt trong mạch suy xét về Trường Tôn hội, khiến hắn vẫn giữ sự thận trọng dù từng tỏ ra ngạo mạn.","anchor":"Đối với Vân Lạc đại ti và Tư Mặc Tử của Trường Tôn hội"},{"mucCt":"vua","text":"Vân Lạc có mặt cạnh Tư Mặc Tử trong một vùng trên không của trường đấu mà không tu sĩ nào dám tới gần. Thân phận của nàng được nêu là đại ti của Trường Tôn hội.","anchor":"Một chỗ trong đó là vị trí của Tư Mặc Tử và VÂn Lạc đại ti của Trường Tôn hội!","bridge":true,"khoang":"@c1312"},{"mucCt":"vua","anchor":"VÂn Lạc đại ti vội vàng bước tới, ngọc thủ đặt lên lưng Tư Mặc Tử","text":"Vân Lạc đại ti né đòn đầu của lão Chu Tước rồi dùng bí thuật hỗ trợ Tư Mặc Tử giảm thương thế. Khi nàng định lấy danh nghĩa Trường Tôn hội ra can thiệp, lão Chu Tước quát dọa tát cả nàng khiến nàng phải im lặng.","bridge":true,"khoang":"@c1313"},{"mucCt":"vua","text":"Vân Lạc đứng cạnh Tư Mặc Tử với thần sắc âm trầm. Nàng giấu tay trong áo để bắt ấn quyết như đang thôi diễn, đồng thời âm thầm liếc về phía Diệu Âm đạo tôn.","anchor":"Tay phải nàng đặt trong áo khẽ động, bắt ấn quyết, dường như đang thôi diễn gì đó","bridge":true,"khoang":"@c1314"},{"mucCt":"vua","text":"Trên Đại Đế tinh, Vân Lạc đại ti nhíu mày khi thấy Vương Lâm chậm hoàn thành cửa Nhân. Nàng giấu tay phải trong ống tay áo bấm quyết càng lúc càng nhanh, như đang tính toán diễn biến then chốt của thí luyện.","anchor":"Đôi mày thanh tú của VÂn Lạc đại ti nhíu chặt, tay phải dấu trong ống tay áo tốc độ bắt quyết càng nhanh hơn","bridge":true,"khoang":"@c1315"},{"chuong":"@c1318","importance":"normal","mucCt":"vua","tieuDe":"Thôi diễn bị cắt","text":"Khi âm thầm thôi diễn biến hóa trong cây hương, Vân Lạc bị một lực lượng vô hình cắt đứt phép tính khiến đầu ngón tay rách toạc chảy máu. Trạng thái của Vương Lâm vượt khỏi khả năng tính toán của nàng, phá vỡ dự đoán về tử cục trước đó.","anchor":"Dường như trạng thái của Vương Lâm vượt quá khỏi khả năng tính toán của nàng!"},{"mucCt":"vua","text":"Vân Lạc ban đầu thở phào vì cho rằng Vương Lâm không phải người trong quẻ tổ tiên từng nói tới. Sau khi Nhân Phương Hương tắt ngấm ở nhịp thở thứ bảy, nàng sắc mặt đại biến, bỏ qua vết thương trên tay để tiếp tục bấm quyết tính toán.","anchor":"Vân Lạc đại ti ở bên cạnh hắn cũng sắc mặt đại biến","bridge":true,"khoang":"@c1319"},{"chuong":"@c1320","importance":"bridge","mucCt":"vua","text":"Sắc mặt âm trầm quan sát biến cố, tay phải bấm quyết càng nhanh, mơ hồ cảm thấy sắp biết được toàn bộ bí ẩn của các sự việc tại nơi này.","anchor":"tay phải bấm quyết càng nhanh, nàng mơ hồ có cảm giác"},{"chuong":"@c1322","importance":"normal","mucCt":"ky","tieuDe":"Bị phản phệ và thấy dự tượng hạo kiếp Thái Cổ Tinh Thần","text":"Đang bắt quyết suy tính thì bị lực lượng bí ẩn phản phệ, tay phải rách nát, nôn máu. Trong cảnh tượng hư ảo, nàng thấy bóng người có hạt châu và kim la bàn, Thái Cổ Tinh Thần ngập máu, nhiều tu sĩ bước thứ ba chết thảm, Diệu âm đạo tôn thân thể tan nát nguyên thần tử vong, Phong Giới Đại Trận sụp đổ, bản thân nàng cũng bị bóng người ấy giết. Sau đó kinh hoàng nghi bóng người chính là người trong Địa phương hương.","anchor":"Cô lại cũng thấy bản thân mình bị bàn tay của bóng người mơ hồ kia chụp tới"},{"chuong":"@c1323","importance":"normal","mucCt":"vua","tieuDe":"Hoảng sợ khi Địa phương hương gãy","text":"Chứng kiến Địa phương hương gãy đổ, tinh thần Vân Lạc như bị chặt đứt, sợ hãi hơn và liên tục phủ nhận người trong thí luyện là đối tượng nàng nghĩ tới.","anchor":"Trong nháy mắt khi Địa phương hương bị gãy, dường như tinh thần của nàng cũng bị chặt đứt"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên họ Chu","tag":"khac","quanHe":"được nhắc tới","ghiChu":"Được thanh niên họ Chu nhắc khi nói về lệnh truy sát."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"truy tìm qua thôi diễn","ghiChu":"Thôi diễn hình ảnh và ký ức thần thức của thủ phạm mà Vương Lâm chính là người bị nhắm tới."},{"ten":"Lão già đạo bào trong nhóm truy tìm","tag":"dong-minh","quanHe":"được nhắc trong truy tìm","ghiChu":"Suy tính của Vân Lạc được lão già đạo bào dùng làm căn cứ lục soát."},{"ten":"Trường Tôn Hội","tag":"dong-minh","quanHe":"Thế lực nhận tin","ghiChu":"Nàng truyền kết quả suy tính cho Trường Tôn Hội và các trưởng lão."},{"ten":"Tư Mặc Tử","tag":"dong-minh","quanHe":"Cung cấp tung tích Vương Lâm","ghiChu":"Tư Mặc Tử dựa vào tính toán của Vân Lạc để tới Điên Lạc."},{"ten":"Nam tử trung niên đi cùng Vân Lạc","tag":"dong-minh","quanHe":"Đồng hành ngoài vùng đất Điên Lạc","ghiChu":"Trao đổi về việc phân thân của nam tử trung niên bị Điên Lạc đại đế giết."},{"ten":"Điên Lạc đại đế","tag":"khac","quanHe":"Người liên quan đến nghi vấn của Vân Lạc","ghiChu":"Vân Lạc chú ý tới người được Điên Lạc đại đế che chở."},{"ten":"Lão Chu Tước","tag":"doi-thu","quanHe":"người uy hiếp mình","ghiChu":"Bị lão Chu Tước quát ngăn khi định nhắc tới Trường Tôn hội."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thuật Thiên Đại Tinh Thần","loai":"thuật thôi diễn","trangThai":"dang-co","moTa":"Dùng để tìm hình ảnh và ký ức thần thức của thủ phạm diệt Thiểm Lôi Tộc.","nguon":"@c1278"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"lao-gia-toai-niet-o-hoang-thanh-phia-dong","name":"Lão già Toái Niết ở hoàng thành phía đông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết @c1278","trangThai":"song","blurb":"Lão già Toái Niết ở hoàng thành phía đông là một trong các tu sĩ đạo bào đứng trên lầu cao quan sát cơn mưa sấm dị thường. Ông liên hệ bất an này với biến cố Thiểm Lôi Tộc nhưng chưa phát hiện được manh mối.","vaiTro":"Tu sĩ bản địa quan sát dị tượng","tinhCach":[{"text":"Thận trọng trước dị tượng sấm mưa","chuong":"@c1278"},{"text":"Biết liên hệ biến cố lớn với bất an hiện tại","chuong":"@c1278"}],"nguon":["@c1278"],"tabs":{"diem":[{"text":"Có tu vi Toái Niết trong nhóm tu sĩ đạo bào ở căn lầu cao nhất hoàng thành phía đông.","chuong":"@c1278"},{"text":"Cảm thấy bất an trước sấm mưa nhưng không tìm được manh mối.","chuong":"@c1278"}],"kinhLich":[{"mucCt":"vua","text":"Lão già Toái Niết ở hoàng thành phía đông cùng các tu sĩ đạo bào quan sát sấm mưa dữ dội trên tu chân tinh. Ông liên hệ dị tượng với việc Thiểm Lôi Tộc vừa bị diệt nhưng vẫn không phát hiện được tung tích hay manh mối của Vương Lâm.","anchor":"Lão già tu vi Toái Niết khẽ lắc đầu, sau đó cũng không có nói thêm điều gì","bridge":true,"khoang":"@c1278"}],"tuViMoc":[{"chuong":"@c1278","canhGioi":"Toái Niết","text":"Lão già này được xác định có tu vi Toái Niết.","importance":"minor"}],"nhanMach":[{"ten":"Các lão già Tịnh Niết ở hoàng thành phía đông","tag":"dong-minh","quanHe":"đứng cùng quan sát","ghiChu":"Cùng dùng thần thức dò xét cơn mưa sấm dị thường."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"cac-lao-gia-tinh-niet-o-hoang-thanh-phia-dong","name":"Các lão già Tịnh Niết ở hoàng thành phía đông","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Tịnh Niết @c1278","trangThai":"song","blurb":"Các lão già Tịnh Niết ở hoàng thành phía đông là nhóm tu sĩ đạo bào cùng quan sát cơn mưa sấm bất thường. Họ dùng thần thức quét qua nhưng không phát hiện manh mối.","vaiTro":"Nhóm tu sĩ quan sát dị tượng","tinhCach":[{"text":"Cẩn thận dò xét bằng thần thức","chuong":"@c1278"},{"text":"Nghi ngờ mình đa tâm trước dị tượng","chuong":"@c1278"}],"nguon":["@c1278"],"tabs":{"diem":[{"text":"Đứng tại căn lầu cao nhất hoàng thành phía đông cùng lão già Toái Niết.","chuong":"@c1278"},{"text":"Dùng thần thức kiểm tra nhưng không tìm thấy manh mối.","chuong":"@c1278"}],"kinhLich":[{"chuong":"@c1278","importance":"bridge","tieuDe":"Dò xét vô quả","mucCt":"gon","text":"Các lão già Tịnh Niết ở hoàng thành phía đông quét thần thức qua cơn mưa sấm dị thường nhưng không phát hiện được manh mối.","anchor":"Nhưng chúng ta đều đã quét thần thức qua, lại không phát hiện được bất cứ manh mối nào"}],"tuViMoc":[{"chuong":"@c1278","canhGioi":"Tịnh Niết","text":"Nhóm lão giả này được miêu tả có tu vi Tịnh Niết.","importance":"minor"}],"nhanMach":[{"ten":"Lão già Toái Niết ở hoàng thành phía đông","tag":"dong-minh","quanHe":"đứng cùng quan sát","ghiChu":"Cùng dò xét sấm mưa dị thường."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"lao-nhan-toc-trang-chan-ngon-toc","name":"Lão nhân tóc trắng Chân Ngôn Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Chân Ngôn Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro @c1278","trangThai":"song","blurb":"Lão nhân tóc trắng Chân Ngôn Tộc là lão nhân rất già đứng trên đỉnh núi cao trong sơn môn Chân Ngôn Tộc. Ông cảm nhận điềm đại nạn khi mưa sấm dị thường bao phủ tu chân tinh.","vaiTro":"Lão nhân Chân Ngôn Tộc","tinhCach":[{"text":"Nhạy cảm với điềm dữ","chuong":"@c1278"},{"text":"Lo lắng trước dị tượng bao phủ tu chân tinh","chuong":"@c1278"}],"nguon":["@c1278"],"tabs":{"diem":[{"text":"Đứng trên đỉnh núi cao trong sơn môn Chân Ngôn Tộc.","chuong":"@c1278"},{"text":"Cảm thấy như có đại nạn sắp giáng xuống đầu.","chuong":"@c1278"}],"kinhLich":[{"mucCt":"vua","text":"Lão nhân tóc trắng Chân Ngôn Tộc đứng trên đỉnh núi cao trong sơn môn, nhìn về phương xa giữa mưa sấm. Ông sinh ra cảm giác đại nạn sắp giáng xuống nhưng chưa biết nguyên nhân.","anchor":"Vì sao ta luôn sinh ra một loại cảm giác địa nạn ập xuống đầu","bridge":true,"khoang":"@c1278"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"lao-gia-mac-dao-bao-co-toc-an","name":"Lão già mặc đạo bào có tộc ấn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1279","trangThai":"song","blurb":"Lão già đạo bào dẫn đội tìm kiếm trong thành tây giữa đêm mưa. Y sử dụng tộc ấn ở mi tâm để dò xét dấu vết quá khứ, nhưng không phát hiện được Vương Lâm đang ẩn thân.","vaiTro":"Người dẫn đội dò xét thành tây","tinhCach":[{"text":"Cẩn trọng trong việc lùng sục tu sĩ che giấu","chuong":"@c1279"},{"text":"Lạnh lùng và tuân theo mệnh lệnh tìm kiếm","chuong":"@c1279"}],"tabs":{"diem":[{"text":"Mi tâm có tộc ấn quỷ dị, có thể phát hào quang dò xét hình ảnh quá khứ trong khu vực.","chuong":"@c1279"},{"text":"Dẫn bảy tu sĩ trung niên phối hợp thi triển thuật dò xét ở thành tây.","chuong":"@c1279"}],"kinhLich":[{"mucCt":"vua","text":"Lão già mặc đạo bào dẫn bảy tu sĩ trung niên tới thành tây, kích phát tộc ấn ở mi tâm để quét qua nhà cửa, phàm nhân và dấu vết người chết nhằm tìm tu sĩ ẩn náu. Thuật pháp bị Vương Lâm che giấu đánh lạc hướng, nên y kết luận nơi này không có tu sĩ che giấu rồi dẫn đội rời đi.","anchor":"Trên mi tâm của lão già đột nhiên xuất hiện một đồ án quỷ dị","bridge":true,"khoang":"@c1279"}],"tuViMoc":[],"nhanMach":[{"ten":"Bảy tu sĩ trung niên theo lão già đạo bào","tag":"dong-minh","quanHe":"thuộc hạ hoặc đồng đội thi pháp","ghiChu":"Bảy người vây quanh, nối u quang vào thân thể lão để tăng cường thuật dò xét."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối tượng truy tìm không phát hiện được","ghiChu":"Lão già dò xét đúng khu vực Vương Lâm ẩn thân nhưng bị che mắt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thuật tộc ấn nghịch chuyển hình ảnh năm tháng","loai":"thần thông dò xét","trangThai":"dang-co","moTa":"Dùng tộc ấn ở mi tâm phát hào quang, làm hiện lại hình ảnh quá khứ để tìm kẻ ẩn náu.","nguon":"@c1279"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1279"]},{"id":"bay-tu-si-trung-nien-theo-lao-gia-dao-bao","name":"Bảy tu sĩ trung niên theo lão già đạo bào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1279","trangThai":"song","blurb":"Bảy tu sĩ trung niên đi theo lão già đạo bào trong cuộc dò xét thành tây. Họ phối hợp bấm quyết, nối u quang vào lão để tăng cường thuật tộc ấn.","vaiTro":"Nhóm tu sĩ hỗ trợ dò xét","tinhCach":[{"text":"Lạnh lùng khi thi hành nhiệm vụ","chuong":"@c1279"},{"text":"Phối hợp kỷ luật trong trận thế dò xét","chuong":"@c1279"}],"tabs":{"diem":[{"text":"Cùng đứng sau lão già đạo bào với ánh mắt lạnh băng.","chuong":"@c1279"},{"text":"Vây quanh lão già, bấm pháp quyết và truyền u quang để thuật dò xét vận hành mạnh hơn.","chuong":"@c1279"}],"kinhLich":[{"mucCt":"vua","text":"Bảy tu sĩ trung niên đi theo lão già đạo bào, cùng vây quanh và bấm pháp quyết để nối u quang vào thân thể lão. Sau khi thuật dò xét thành tây kết thúc mà không phát hiện Vương Lâm, họ sắc mặt hơi tái rồi theo lão già rời đi.","anchor":"Sau lưng lão già có bảy tu sĩ trung niên ánh mắt lạnh băng","bridge":true,"khoang":"@c1279"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già mặc đạo bào có tộc ấn","tag":"dong-minh","quanHe":"đồng đội thi pháp","ghiChu":"Cùng lão già thi triển thuật dò xét thành tây."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối tượng truy tìm không phát hiện được","ghiChu":"Nhóm này hỗ trợ thuật pháp lùng sục nhưng không phát hiện được Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thuật tộc ấn nghịch chuyển hình ảnh năm tháng","loai":"thần thông dò xét","trangThai":"dang-co","moTa":"Phối hợp cùng lão già mặc đạo bào vận chuyển thuật dò xét bằng u quang và pháp quyết.","nguon":"@c1279"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1279"]},{"id":"nguoi-dan-ong-trung-nien-co-do-an-hoa-bay-canh","name":"Người đàn ông trung niên có đồ án hoa bảy cánh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1279","trangThai":"khong-ro","blurb":"Người đàn ông trung niên xuất hiện trong hình ảnh ký ức thứ hai của sấm sét bất diệt. Mi tâm y có đồ án hoa bảy cánh bảy màu và từng đưa sấm sét bất diệt vào hư vô.","vaiTro":"Nhân vật cổ xưa trong ký ức sấm sét","tinhCach":[{"text":"Lạnh lùng khi đánh giá sấm sét bất diệt","chuong":"@c1279"},{"text":"Thần bí, có liên hệ với nguồn gốc của sấm sét bất diệt","chuong":"@c1279"}],"tabs":{"diem":[{"text":"Mi tâm có đồ án hoa bảy cánh bảy màu nổi bật.","chuong":"@c1279"},{"text":"Từng nhận xét sấm sét bất diệt quá yếu và phất tay đưa nó vào hư vô.","chuong":"@c1279"}],"kinhLich":[{"mucCt":"vua","text":"Người đàn ông trung niên có đồ án hoa bảy cánh xuất hiện trong ký ức thứ hai mà Vương Lâm nhìn thấy sau khi luyện hóa sấm sét bất diệt. Y cho rằng luồng sấm sét này quá yếu, khó khôi phục như xưa, rồi phất tay đưa nó phóng vào hư vô và biến mất.","anchor":"Vẻ mặt người này cực kỳ lạnh lùng, trong mi tâm có một đồ án hoa bảy cánh","bridge":true,"khoang":"@c1279"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người được thấy trong ký ức","ghiChu":"Vương Lâm nhìn thấy hình ảnh của người này khi tiếp nhận ký ức từ sấm sét bất diệt."}],"tuiDo":{"phapBao":[{"ten":"Sấm sét bất diệt","loai":"dị vật lôi đình","trangThai":"mat","moTa":"Từng nằm trong tay người này rồi bị y phất tay đưa vào hư vô.","nguon":"@c1279"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1279"]},{"id":"lao-gia-thiem-loi-toc-trong-mieu-tho","name":"Lão già Thiểm Lôi Tộc trong miếu thờ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiểm Lôi Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1279","trangThai":"khong-ro","blurb":"Lão già Thiểm Lôi Tộc xuất hiện trong hình ảnh ký ức thứ ba của sấm sét bất diệt. Ông đứng cùng bảy người bên ngoài sấm sét tại miếu thờ và tỏ ra kính sợ thủ lĩnh có kim quang.","vaiTro":"Người Thiểm Lôi Tộc trong ký ức cổ","tinhCach":[{"text":"Kính sợ thủ lĩnh có kim quang","chuong":"@c1279"},{"text":"Gắn với nghi thức quanh sấm sét bất diệt của Thiểm Lôi Tộc","chuong":"@c1279"}],"tabs":{"diem":[{"text":"Mi tâm hiện ký hiệu tia chớp trong hình ảnh miếu thờ Thiểm Lôi Tộc.","chuong":"@c1279"},{"text":"Thái độ cung kính và sợ hãi trước thủ lĩnh có kim quang.","chuong":"@c1279"}],"kinhLich":[{"mucCt":"vua","text":"Lão già Thiểm Lôi Tộc xuất hiện trong ký ức thứ ba của sấm sét bất diệt, đứng cùng bảy người bên ngoài luồng sấm tại miếu thờ Thiểm Lôi Tộc. Khi thủ lĩnh có kim quang hiện diện, mi tâm ông lộ ký hiệu tia chớp và ông tỏ ra cung kính, sợ hãi.","anchor":"trên mi tâm một lão già trong số tám người này chợt xuất huện một ký hiệu tia chớp","bridge":true,"khoang":"@c1279"}],"tuViMoc":[],"nhanMach":[{"ten":"Thủ lĩnh có kim quang trong ký ức sấm sét","tag":"cap-tren","quanHe":"người được kính sợ","ghiChu":"Lão già Thiểm Lôi Tộc tỏ ra cung kính và sợ hãi với người đứng đầu có kim quang."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người nhìn thấy ký ức","ghiChu":"Vương Lâm nhìn thấy lão trong ký ức của sấm sét bất diệt."}],"tuiDo":{"phapBao":[{"ten":"Sấm sét bất diệt","loai":"dị vật lôi đình","trangThai":"khong-ro","moTa":"Luồng sấm xuất hiện tại miếu thờ Thiểm Lôi Tộc trong ký ức nơi lão già có mặt.","nguon":"@c1279"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1279"]},{"id":"thu-linh-co-kim-quang-trong-ky-uc-sam-set","name":"Thủ lĩnh có kim quang trong ký ức sấm sét","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1279","trangThai":"khong-ro","blurb":"Thủ lĩnh thần bí xuất hiện trong hình ảnh ký ức thứ ba tại miếu thờ Thiểm Lôi Tộc. Quanh thân có kim quang khiến Vương Lâm cảm thấy quen thuộc, và khoảnh khắc người này xoay lại khiến hắn chấn động.","vaiTro":"Thủ lĩnh thần bí trong ký ức sấm sét","tinhCach":[{"text":"Uy thế khiến người Thiểm Lôi Tộc kính sợ","chuong":"@c1279"},{"text":"Thân phận bí ẩn, gây chấn động mạnh cho Vương Lâm","chuong":"@c1279"}],"tabs":{"diem":[{"text":"Đứng đầu nhóm bảy người mặc y phục cổ quái trong ký ức miếu thờ.","chuong":"@c1279"},{"text":"Quanh thân có kim quang quen thuộc với Vương Lâm.","chuong":"@c1279"}],"kinhLich":[{"mucCt":"vua","text":"Thủ lĩnh có kim quang đứng ở vị trí đầu trong nhóm người mặc y phục cổ quái tại miếu thờ Thiểm Lôi Tộc, được lão già Thiểm Lôi Tộc kính sợ. Khi người này xoay lại trong ký ức của sấm sét bất diệt, Vương Lâm lập tức chấn động như nhận ra thân phận của y.","anchor":"Đặc biệt là một người đứng ở vị trí đầu tiên, rõ ràng người này là thủ lĩnh","bridge":true,"khoang":"@c1279"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già Thiểm Lôi Tộc trong miếu thờ","tag":"khac","quanHe":"người kính sợ mình","ghiChu":"Lão già Thiểm Lôi Tộc tỏ thái độ cung kính và sợ hãi trước thủ lĩnh."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người nhận ra trong ký ức","ghiChu":"Vương Lâm chấn động khi thấy người này xoay lại trong hình ảnh ký ức."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1279"]},{"id":"nap-da","name":"Nạp Đa","aliases":[],"gioiTinh":"nam","trangThai":"khong-ro","tabs":{"diem":[{"text":"Xuất hiện với danh nghĩa 'thanh niên tà dị', đuổi theo Vương Lâm đòi lại túi trữ vật bị mất","chuong":"@c0223"},{"text":"Tiết lộ bí quyết Cực Cảnh rồi rời tinh cầu bằng la bàn đen; nổi giận muốn trả đũa nhưng phải nhịn trước Cấm Phiên của Vương Lâm","chuong":"@c0224"},{"text":"Anh Biến sơ kỳ, tự nhận chỉ đạt khoảng 3/10 sức mạnh thật","chuong":"@c0224"},{"text":"Bế quan ngàn năm cùng tông chủ và trưởng lão Quy Nhất Tông trên Ngũ Hành tinh","chuong":"@c1634"},{"text":"Được Đệ Cửu lão tổ túm lên tầng chín, phủ phục xưng hậu bối, kể lại những gì mình biết","chuong":"@c1641"},{"text":"Bị Cửu Chuyển Tâm Luân nghịch chuyển đánh ngược, cuối cùng nằm lại trên mặt đất Ngũ Hành tinh","chuong":"@c1644"}],"kinhLich":[{"chuong":"@c1280","importance":"bridge","mucCt":"vua","tieuDe":"Đầu mối Cực Cảnh","text":"Nạp Đa được Vương Lâm nhớ lại từng có Cực Cảnh năm màu trên Ngũ Hành tinh và từng nằm trong nhóm truy sát Tư Đồ Nam, trở thành đầu mối cho nghi vấn về Côn Cực Tiên cùng bí mật Nội giới.","anchor":"Năm xưa Nạp Đa cũng là một người trong nhóm đuổi giết Tư Đồ Nam"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Đồ Nam","tag":"doi-thu","quanHe":"từng tham gia truy sát","ghiChu":"Nạp Đa từng thuộc nhóm đuổi giết Tư Đồ Nam."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280"],"vaiTro":"Nhân vật phụ — trưởng lão Quy Nhất Tông trên Ngũ Hành tinh","tinhCach":"Bộc trực, dễ nổi giận nhưng biết lùi khi gặp đối thủ vượt tầm; sùng kính bậc tiền bối tông môn; mang nỗi sợ hãi cũ khi đối diện Cửu Chuyển Tâm Luân","blurb":"Nạp Đa là tu sĩ Anh Biến sơ kỳ xuất thân Ngũ Hành tinh, ban đầu xuất hiện dưới danh nghĩa 'thanh niên tà dị' đuổi theo Vương Lâm đòi lại túi trữ vật và vô tình tiết lộ bí quyết đột phá Cực Cảnh. Ngàn năm sau hắn giữ vị trí trưởng lão Quy Nhất Tông, bế quan trên tháp Ngũ Hành tinh và chứng kiến Vương Lâm trở lại với thực lực đã vượt xa mình. Bị cuốn vào biến cố xoay quanh Cửu Chuyển Tâm Luân và lão tổ Đệ Cửu, cuối cùng hắn nằm lại trên mặt đất sau nghịch động."},{"id":"tu-do-nam","name":"Tư Đồ Nam","aliases":[],"gioiTinh":"nam","trangThai":"khong-ro","tabs":{"diem":[{"text":"Từng là cường giả Chu Tước Quốc lục cấp, thân hủy sau khi bị truy sát và ẩn tinh hoa Nguyên Anh vào Thạch Châu.","chuong":"@c0047"},{"text":"Thức tỉnh nhờ lửa Chu Tước thâm nhập Thiên Nghịch Châu, trong trạng thái rất suy yếu vẫn nhập thân Vương Lâm để hư trương thanh thế.","chuong":"@c0397"},{"text":"Đoạt xá đồng tử trong khối viêm băng, hoàn tất dung hợp và về sau hiện thân với bản lãnh đạt Vấn Đỉnh kỳ.","chuong":"@c0401"},{"text":"Tại Thủy Linh tinh, dùng thần thức Tịnh Niết sơ kỳ quét ngang khiến tinh cầu chấn động.","chuong":"@c0932"},{"text":"Được Thanh Lâm trợ giúp phá Không Môn, chính thức trở thành tu sĩ bước thứ ba và tử chiến tại Chu Tước Tinh.","chuong":"@c1520"},{"text":"Được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp.","chuong":"@c1650"}],"kinhLich":[{"chuong":"@c1280","importance":"bridge","mucCt":"gon","tieuDe":"Bị nhắc truy sát","text":"Tư Đồ Nam được nhắc lại là người từng bị nhóm tu sĩ có Nạp Đa tham gia đuổi giết trong quá khứ.","anchor":"Năm xưa Nạp Đa cũng là một người trong nhóm đuổi giết Tư Đồ Nam"}],"tuViMoc":[],"nhanMach":[{"ten":"Nạp Đa","tag":"doi-thu","quanHe":"từng bị truy sát","ghiChu":"Nạp Đa từng thuộc nhóm đuổi giết Tư Đồ Nam."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280"],"vaiTro":"Huynh trưởng Vương Lâm — cường giả Chu Tước, phách Thất Thải","tinhCach":"Kiêu ngạo ngang tàng; tàn nhẫn quyết đoán; trọng nghĩa với Vương Lâm; nóng nảy nhưng biết toan tính","blurb":"Tư Đồ Nam vốn là cường giả lục cấp của Chu Tước Quốc, bị truy sát đến thân hủy rồi dùng tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu, nhiều năm chỉ điểm và bảo vệ Vương Lâm. Sau khi thức tỉnh và đoạt xá thành công, ông phục hồi thực lực, nhiều lần cùng Vương Lâm vượt hiểm, về sau được Thanh Lâm trợ giúp bước vào bước thứ ba. Ở các mốc sau, ông được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp."},{"id":"nam-tu-si-la-co-cuc-canh-nam-mau","name":"Nam tu sĩ lạ có Cực Cảnh năm màu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1280","trangThai":"khong-ro","blurb":"Nam tu sĩ lạ xuất hiện trong hình ảnh mà Vương Lâm nhìn thấy. Mắt trái của người này có ánh sáng năm màu được nhận ra là Cực Cảnh, quanh người còn có kim quang bị Vương Lâm nghi là Côn Cực Tiên.","vaiTro":"đầu mối Cực Cảnh bí ẩn","tinhCach":[{"text":"bí ẩn, chưa rõ lai lịch","chuong":"@c1280"},{"text":"gắn với Cực Cảnh năm màu và Côn Cực Tiên","chuong":"@c1280"}],"tabs":{"diem":[{"text":"Mắt trái lóe ánh sáng năm màu, được Vương Lâm nhận ra là Cực Cảnh.","chuong":"@c1280"},{"text":"Quanh người có kim quang khiến Vương Lâm liên hệ tới Côn Cực Tiên.","chuong":"@c1280"}],"kinhLich":[{"mucCt":"vua","text":"Nam tu sĩ lạ xuất hiện trong hình ảnh đã tiêu tán, để lại dung mạo xa lạ nhưng mắt trái có ánh sáng năm màu. Dấu hiệu này khiến Vương Lâm nhận ra Cực Cảnh và suy đoán người này liên quan tới Côn Cực Tiên cùng bí mật Nội giới.","anchor":"trong mắt trái của người này lại lóe lên một luồng sáng năm màu","bridge":true,"khoang":"@c1280"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"đầu mối bị nhận ra","ghiChu":"Hình ảnh của người này khiến Vương Lâm suy luận về Cực Cảnh năm màu và Côn Cực Tiên."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Cực Cảnh năm màu","loai":"lực lượng đặc thù","trangThai":"khong-ro","moTa":"Biểu hiện qua ánh sáng năm màu trong mắt trái.","nguon":"@c1280"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280"]},{"id":"lao-gia-dao-bao-trong-nhom-truy-tim","name":"Lão già đạo bào trong nhóm truy tìm","cn":"","aliases":["Lão già đạo bào bị lấy mất một phần nguyên thần"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1280","trangThai":"song","blurb":"Lão già mặc đạo bào dẫn bảy người đàn ông trung niên kiểm tra các tu chân tinh để tìm hung thủ hủy diệt Thiểm Lôi tộc. Hắn bị Vương Lâm áp sát trong sấm chớp và cắt mất một phần nguyên thần mà gần như không phát giác.","vaiTro":"người truy tìm Vương Lâm","tinhCach":[{"text":"cẩn trọng khi kiểm tra tinh vực","chuong":"@c1280"},{"text":"bị động trước thủ đoạn ẩn kín của Vương Lâm","chuong":"@c1280"}],"tabs":{"diem":[{"text":"Dẫn nhóm truy tìm hung thủ hủy diệt Thiểm Lôi tộc.","chuong":"@c1280"},{"text":"Bị Vương Lâm cắt một phần nguyên thần để rút ký ức.","chuong":"@c1280"}],"kinhLich":[{"chuong":"@c1280","importance":"normal","mucCt":"vua","tieuDe":"Bị cắt nguyên thần","text":"Lão già đạo bào dẫn bảy trung niên kiểm tra tinh vực để truy tìm hung thủ hủy diệt Thiểm Lôi tộc. Trong khoảnh khắc sấm chớp, hắn bị Vương Lâm áp sát, cắt một phần nguyên thần và rút ký ức về bố trí truy tìm của Thái Cổ Tinh Thần.","anchor":"Lão già mặc đạo bào vẫn tiến về tinh không phía trước"},{"chuong":"@c1281","importance":"normal","mucCt":"vua","tieuDe":"Đổi hướng truy tìm","text":"Đang định rời khỏi tu chân tinh, lão già đạo bào cảm nhận dị biến sấm sét và lập tức quay lại. Lão dùng thần thức kiểm tra kỹ, tiếp tục dính vào cuộc truy tìm kẻ hủy diệt Thiểm Lôi tộc.","anchor":"lão già đạo bào bị lấy mất một phần nguyên thần đang định rời khỏi tu chân tinh cũng xoay người lại thật mạnh"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị cắt nguyên thần","ghiChu":"Bị Vương Lâm lấy một phần nguyên thần để đọc ký ức."},{"ten":"Bảy người đàn ông trung niên trong nhóm truy tìm","tag":"dong-minh","quanHe":"người đi theo","ghiChu":"Bảy trung niên theo sau hắn trong nhiệm vụ lục soát."},{"ten":"Vân Lạc","tag":"dong-minh","quanHe":"người cung cấp suy tính","ghiChu":"Hắn nhắc tới suy tính của Vân Lạc về vị trí mục tiêu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280","@c1281"]},{"id":"bay-nguoi-dan-ong-trung-nien-trong-nhom-truy-tim","name":"Bảy người đàn ông trung niên trong nhóm truy tìm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1280","trangThai":"song","blurb":"Bảy người đàn ông trung niên đi theo lão già đạo bào trong cuộc lục soát tinh vực. Họ mỏi mệt vì chưa tìm được hung thủ và không phát giác lúc Vương Lâm ra tay.","vaiTro":"nhóm truy tìm phụ trợ","tinhCach":[{"text":"mỏi mệt vì lục soát kéo dài","chuong":"@c1280"},{"text":"không nhận ra biến cố nguyên thần của lão già đạo bào","chuong":"@c1280"}],"tabs":{"diem":[{"text":"Đi theo lão già đạo bào kiểm tra các tu chân tinh.","chuong":"@c1280"},{"text":"Không phát hiện Vương Lâm cắt nguyên thần người dẫn đội.","chuong":"@c1280"}],"kinhLich":[{"chuong":"@c1280","importance":"bridge","mucCt":"gon","tieuDe":"Theo nhóm lục soát","text":"Bảy người đàn ông trung niên đi sau lão già đạo bào trong cuộc truy tìm và không nhận ra lúc Vương Lâm ra tay với người dẫn đội.","anchor":"Bảy người đàn ông trung niên đang đi theo phía sau"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già đạo bào trong nhóm truy tìm","tag":"dong-minh","quanHe":"đi theo","ghiChu":"Theo sau lão già đạo bào khi kiểm tra tinh vực."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280"]},{"id":"tieu-nhi-tuu-lau","name":"Tiểu nhị tửu lâu","aliases":[],"gioiTinh":"nam","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1280","importance":"bridge","mucCt":"gon","tieuDe":"Bán rượu đêm mưa","text":"Tiểu nhị tửu lâu tỉnh dậy vì gió lạnh khi Vương Lâm bước vào, lấy bầu rượu cho hắn và báo giá ba tiền Phàn Tinh.","anchor":"Một lúc sau hắn đi ra đặt bầu rượu trước mặt Vương Lâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người bán rượu","ghiChu":"Lấy bầu rượu cho Vương Lâm trong đêm mưa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280"]},{"id":"ba-nguoi-dan-ong-uong-ruou-trong-tuu-lau","name":"Ba người đàn ông uống rượu trong tửu lâu","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1280","trangThai":"song","blurb":"Ba người đàn ông ngồi uống rượu trong tửu lâu giữa đêm mưa gió. Họ chỉ xuất hiện thoáng qua khi Vương Lâm đến mua rượu.","vaiTro":"khách trong tửu lâu","tinhCach":[{"text":"lặng lẽ uống rượu trong đêm mưa","chuong":"@c1280"}],"tabs":{"diem":[{"text":"Có mặt trong tửu lâu khi Vương Lâm mua rượu.","chuong":"@c1280"}],"kinhLich":[{"chuong":"@c1280","importance":"bridge","mucCt":"gon","tieuDe":"Khách đêm mưa","text":"Ba người đàn ông ngồi uống rượu và nhìn đêm mưa gió trong tửu lâu nơi Vương Lâm ghé qua.","anchor":"có ba người đàn ông đang ngồi uống rượu nhìn bầu trời đêm mưa gió"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1280"]},{"id":"lao-gia-toai-niet-trong-lau-cac-hoang-thanh","name":"Lão già Toái Niết trong lầu các hoàng thành","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Toái Niết @c1281","trangThai":"song","blurb":"Lão già Toái Niết hiện diện trong lầu cao nhất hoàng thành khi dị biến sấm sét ở thành tây bùng lên. Lão nhanh chóng suy đoán có kẻ ẩn giấu và lao đi truy tìm.","vaiTro":"Tu sĩ truy tìm Vương Lâm","tinhCach":[{"text":"Cảnh giác trước dị biến sấm sét","chuong":"@c1281"},{"text":"Hành động nhanh khi nhận ra dấu vết","chuong":"@c1281"}],"tabs":{"diem":[{"text":"Là nhân vật nổi bật trong nhóm tu sĩ ở lầu cao nhất hoàng thành phát hiện lôi quang bất thường.","chuong":"@c1281"},{"text":"Lập tức phóng đi truy tìm sau khi suy đoán có kẻ ẩn giấu trên tinh cầu.","chuong":"@c1281"}],"kinhLich":[{"mucCt":"vua","text":"Sau khi cảm nhận sấm sét kinh người ở thành tây, lão già Toái Niết suy đoán có kẻ ẩn giấu và lập tức rời lầu các để truy tìm. Diễn biến này khiến tuyến điều tra trên tu chân tinh nhanh chóng chuyển thành truy lùng trực tiếp.","anchor":"Vẻ mặt lão già Toái Niết trở nên âm trầm, thân thể lão lóe lên rồi phóng thẳng về phương xa.","bridge":true,"khoang":"@c1281"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng truy tìm","ghiChu":"Lão truy dấu dị biến do Vương Lâm luyện hóa Lôi Lục đạo gây ra."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1281"]},{"id":"nguoi-dan-ong-trung-nien-ao-trang-dan-dau-nhom-tu-si-phia-tay","name":"Người đàn ông trung niên áo trắng dẫn đầu nhóm tu sĩ phía tây","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Người đàn ông trung niên áo trắng dẫn một nhóm tu sĩ quét thần thức ở phía tây tu chân tinh. Khi cảm thấy biến động lôi quang, hắn lập tức đổi hướng truy tìm.","vaiTro":"Người dẫn nhóm truy lùng phía tây","tinhCach":[{"text":"Quyết đoán khi phát hiện biến động","chuong":"@c1281"},{"text":"Cẩn trọng trong việc dò xét bằng thần thức","chuong":"@c1281"}],"tabs":{"diem":[{"text":"Dẫn nhóm tu sĩ áo trắng quét thần thức ở khu vực phía tây.","chuong":"@c1281"},{"text":"Không do dự đổi hướng khi cảm thấy dị biến sấm sét.","chuong":"@c1281"}],"kinhLich":[{"mucCt":"gon","text":"Khi nhóm tu sĩ phía tây không phát hiện gì nhưng cảm thấy biến động, người đàn ông trung niên áo trắng lập tức đổi hướng truy tìm.","anchor":"người đàn ông trung niên dẫn đầu đoàn người lại biến đổi lớn, người này không cần suy nghĩ nhiều mà trực tiếp thay đổi phương hướng","bridge":true,"khoang":"@c1281"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng truy tìm","ghiChu":"Hắn đổi hướng truy tìm sau dị biến do Vương Lâm gây ra."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1281"]},{"id":"ba-bong-nguoi-tren-bau-troi-dao-nho","name":"Ba bóng người trên bầu trời đảo nhỏ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Trường Tôn Hội","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Ba bóng người được huyễn hóa trên bầu trời đảo nhỏ sau lệnh của Vân Lạc. Họ nhận tin rồi tiêu tán, đóng vai trò truyền đạt thông báo tới Trường Tôn Hội và các trưởng lão.","vaiTro":"Người nhận lệnh truyền tin","tinhCach":[{"text":"Tuân lệnh Vân Lạc","chuong":"@c1281"},{"text":"Xuất hiện ngắn để truyền đạt tin tức","chuong":"@c1281"}],"tabs":{"diem":[{"text":"Được huyễn hóa ngay sau khi Vân Lạc xác định vị trí người hủy diệt Thiểm Lôi tộc.","chuong":"@c1281"},{"text":"Ôm quyền nhận tin rồi tiêu tán, cho thấy nhiệm vụ là truyền đạt mệnh lệnh.","chuong":"@c1281"}],"kinhLich":[{"chuong":"@c1281","importance":"bridge","mucCt":"gon","tieuDe":"Nhận tin truyền đạt","text":"Ba bóng người hiện ra trên bầu trời đảo nhỏ, nhận tin của Vân Lạc rồi tiêu tán để truyền đạt thông báo.","anchor":"bầu trời hòn đảo nhỏ lập tức có ba bóng người đựoc huyễn hóa ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vân Lạc","tag":"cap-tren","quanHe":"Người ra lệnh","ghiChu":"Ba bóng người nhận tin do Vân Lạc truyền đạt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1281"]},{"id":"tu-mac-tu","name":"Tư Mặc Tử","cn":"司默子","aliases":["Tư Mặc Tử phân thân","Tư Mã Mặc"],"gioiTinh":"nam","theLuc":[{"ten":"Đệ Tam Bộ","trangThai":"danh-nghia"},{"ten":"Trường Tôn Hội","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không đổi trong @c1315","trangThai":"song","blurb":"Tư Mặc Tử là một trong ba đại năng Đệ Tam Bộ từng tham gia đuổi giết Thác Sâm, sau khi hấp thu Lục Phẩm đạo linh trong khe nứt hư vô thì nhận huyết chỉ truy bắt Vương Lâm. Hắn dùng phân thân lần theo dấu Vương Lâm từ Thập Vạn Đại Sơn tới Đại Đế tinh, nhiều lần giao chiến bằng Phá Thiên Đạo, Phá Không Cửu Diệt và Hương hỏa thần thông nhưng đều thất lợi, cuối cùng bị Mộng Đạo gieo tâm ma và bị luyện hóa tại Thiên Hoàng Lô, toàn bộ quá khứ bi thương — từ thiếu niên hái thuốc đến vạn năm bầu bạn hư ảnh muội muội — bị phơi bày trước Vương Lâm. Ký ức của hắn sau đó trở thành tấm gương cảnh tỉnh cho ","vaiTro":"Đại năng Đệ Tam Bộ nhận huyết chỉ truy bắt Vương Lâm, mang quá khứ bi thương","tinhCach":"Kiêu ngạo, hay châm chọc khinh thường đối thủ yếu hơn; nhẫn nhịn e dè trước bậc mạnh hơn như lão Chu Tước; quyết liệt khi truy sát mục tiêu; nội tâm ẩn chứa nỗi đau sâu kín vì muội muội đã mất","tabs":{"diem":[{"text":"Nhận huyết chỉ truy bắt Vương Lâm sau khi hấp thu Lục Phẩm đạo linh trong khe nứt hư vô, với tư cách đại năng Đệ Tam Bộ từng đuổi giết Thác Sâm","chuong":"@c1281"},{"text":"Dùng phân thân thi triển Phá Thiên Đạo, lấy bức tranh thiên địa làm tù ngục để giết Vương Lâm nhưng thất lợi","chuong":"@c1291"},{"text":"Bị lão Chu Tước tát bay vạn trượng vì châm chọc thí luyện của thiếu đế thứ ba, để lại thương tích tím đen và hư hỏa cài sẵn trong người","chuong":"@c1316"},{"text":"Thi triển Phá Không Cửu Diệt và Hương hỏa thần thông đối đầu Vương Lâm, bị hư hỏa do lão Chu Tước cài bùng phát khi tâm tình dao động, lộ linh hồn gốc","chuong":"@c1330"},{"text":"Bị Mộng Đạo gieo tâm ma, đạo tâm dao động trước hư ảnh muội muội áo trắng vấy máu — người đã bầu bạn hắn mấy vạn năm","chuong":"@c1333"},{"text":"Toàn bộ quá khứ bi thương hé lộ khi bị luyện hóa tại Thiên Hoàng Lô: từ thiếu niên hái thuốc tới đạt Nguyên Anh rồi nhập Phá Thiên Tông, ký ức trở thành tấm gương cảnh tỉnh cho Vương Lâm","chuong":"@c1334"}],"kinhLich":[{"chuong":"@c1281","importance":"normal","mucCt":"ky","tieuDe":"Nhận huyết chỉ","text":"Tư Mặc Tử được giới thiệu là một trong ba đại năng Đệ Tam Bộ từng đuổi giết Thác Sâm. Trong khe nứt hư vô, hắn hấp thu Lục Phẩm đạo linh đến sáu phần và mơ hồ cảm thấy dấu hiệu đột phá Không Niết sơ kỳ. Sau khi nhận huyết chỉ treo thưởng đạo linh từ Trường Tôn Hội, hắn cho rằng nhiệm vụ đơn giản và phóng ra một hư ảnh tu vi Thiên Nhân Đệ Ngũ Suy đi xử lý việc truy bắt Vương Lâm.","anchor":"Người đàn ông trung niên này chính là một trong ba người Đệ Tam Bộ đại năng đuổi giết Thác SÂm"},{"mucCt":"ky","text":"Phân thân Tư Mặc Tử đến Thập Vạn Đại Sơn sau khi Vương Lâm rời đi, tái hiện cảnh Vương Lâm ba lần đánh Không Môn và trấn áp tu sĩ. Hắn ban đầu cho rằng Vương Lâm dùng sấm sét bất diệt của Thiểm Lôi tộc để dẫn Không Môn, nhưng sau đó kinh hãi vì đối phương không có khí tức hương hỏa. Hắn không giải cứu vài vạn tu sĩ bị phong ấn mà che giấu hoảng sợ, tăng tốc truy đuổi Vương Lâm.","anchor":"Vẻ hoảng sợ trong mắt Tư Mặc Tử dần được che dấu, trong mắt chỉ còn lại một mảnh âm u","bridge":true,"khoang":"@c1284"},{"mucCt":"vua","text":"Tư Mặc Tử xuất hiện ngoài Điên Lạc từ gợn sóng tinh không, xác nhận nhờ Vân Lạc đại ti tính ra Vương Lâm trốn ở đây. Hắn dự định mượn quan hệ với trưởng lão thứ chín, tộc trưởng Long Giáp Tộc, để vào Điên Lạc truy tìm Vương Lâm và sưu hồn lấy bí mật dẫn động hương hỏa.","anchor":"Người này chính là kẻ đuổi giết Vương Lâm, Tư Mặc Tử","bridge":true,"khoang":"@c1287"},{"mucCt":"ky","text":"Tư Mặc Tử xuất hiện trong tinh không gần chủ tinh Long Giáp Tộc và nhận ra Vương Lâm nhờ hình dáng, khí tức do Vân Lạc địa ti tính ra. Hắn muốn bắt mục tiêu nhưng tạm không động thủ vì kiêng kỵ Điên Lạc đại đế, sau đó được trưởng lão thứ chín Lạc Sinh hội họ Tôn ra nghênh đón.","anchor":"Hắn không ngờ mình vừa mới tới vùng đất Điên Lạc đa lại có thể gặp người muốn bắt.","bridge":true,"khoang":"@c1288"},{"mucCt":"vua","anchor":"Tư Mặc Tử sắc mặt lạnh như băng, cũng lộ ra sát khí vô cùng","text":"Tư Mặc Tử có mặt tại thánh địa Long Giáp Tộc khi tộc trưởng Long Giáp Tộc dựng cớ Vương Lâm cướp một vạn Băng long đan và mời hắn hỗ trợ bắt giết. Nghe tiếng Vương Lâm công khai khiêu chiến vang khắp tu chân tinh, hắn sắc mặt lạnh băng và lộ sát khí mạnh.","bridge":true,"khoang":"@c1289"},{"mucCt":"ky","text":"Tư Mặc Tử phát hiện Vương Lâm trên đỉnh núi tu chân tinh, rời đại điện Long Giáp Tộc và giao chiến với hắn. Ban đầu hắn tin tu vi tuyệt đối đủ áp chế mưu trí, nhưng khi Vương Lâm dùng bổn nguyên dẫn động lực lượng bước thứ ba, hắn trở nên ngưng trọng, dùng cơn lốc thần thông đối kháng Sơn Băng thuật, nhận ra đây là thần thông của Bạch Phàm, rồi thi triển thuật biến trời thành tranh, đất thành mực, bản thân thành bút khiến Vương Lâm liên hệ tới Phá Thiên Đạo và nghi vấn lai lịch thật của hắn.","anchor":"Thần sắc Tư Mặc Tử ngưng trọng. Hắn không dám xem thường người dựa vào lực lượng bổn nguyên","bridge":true,"khoang":"@c1290"},{"chuong":"@c1291","importance":"normal","mucCt":"ky","tieuDe":"Phá Thiên thất lợi","text":"Tư Mặc Tử dùng phân thân thi triển Phá Thiên Đạo, lấy bức tranh thiên địa làm tù ngục để giết Vương Lâm. Hắn bị tiếng hét Tư Mã Mặc làm dao động, trúng sát chiêu kiếm khí đến phun máu, phải dùng thủ đoạn tách thân tránh một kích tất sát. Khi Vương Lâm phá vây và thi triển Phiên thiên thần thông, hắn nhận ra nguồn gốc thần thông rồi lấy đại phiên mười trượng phóng Tuế Nguyệt Cấm chống lại.","anchor":"Tư Mặc Tử phun một ngụm máu tươi"},{"mucCt":"ky","text":"Tư Mặc Tử dùng Thiên hoang địa lão ngộ từ Tuế Nguyệt cấm và tung chưởng ấn chứa lực thiên nhân đệ ngũ suy để công kích Vương Lâm. Cấm chế của hắn bị lôi đồ vạn trượng phá tan, lôi đồ đánh thẳng vào ngực khiến hắn phun máu và bị lôi đình lan khắp cơ thể. Sau đó phân thân của hắn tiếp tục bị vụ nổ viên đan dược màu vàng xé rách huyết nhục, gãy xương, đồng thời chương hé lộ phân thân này do bổn tôn bước thứ ba luyện hóa khi tu vi đình trệ ở Không Niết sơ kỳ.","anchor":"Phân thân này là khi Tư Mặc Tử phát hiện ra tu vi bị đình trệ ở Không Niết sơ kỳ không thể tiến lên","bridge":true,"khoang":"@c1292"},{"mucCt":"ky","text":"Tư Mặc Tử đi cùng Vân Lạc tới Đại đế tinh, quanh thân có làn khói hương hỏa và uy áp khiến tu sĩ biến sắc. Khi thấy Vương Lâm trong thông đạo, hắn sát khí bùng lên, chửi mắng và đòi chiến, nhưng không bước vào vùng sương mù từ lực theo lời khiêu khích của Vương Lâm.","anchor":"Nam tử trung niên đứng bên cạnh nữ tử, thần sắc lạnh lùng, ánh mắt nhìn về Đại đế tinh","bridge":true,"khoang":"@c1307"},{"chuong":"@c1308","importance":"bridge","mucCt":"gon","tieuDe":"Bị bỏ lại trong thông đạo","text":"Tư Mặc Tử có mặt bên nữ tử Trường Tôn hội khi Vương Lâm không để ý tới họ nữa và đi sâu vào thông đạo.","anchor":"Vương Lâm xoay người không để ý tới nữ tử và Tư Mặc Tử nữa"},{"chuong":"@c1309","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc cùng Trường Tôn hội","text":"Tư Mặc Tử được Vương Lâm nhắc cùng Vân Lạc và Trường Tôn hội trong lúc cân nhắc tình thế trên Đại đế tinh.","anchor":"Đối với Vân Lạc đại ti và Tư Mặc Tử của Trường Tôn hội"},{"mucCt":"vua","text":"Tư Mặc Tử được Chu Tước đời thứ hai nhắc là người đã khiêu chiến Vương Lâm. Ông bị chọn làm đối tượng để Vương Lâm lập uy trước các tu sĩ được mời tới tuyển chọn trưởng lão Lạc Sinh hội.","anchor":"Tư Mặc Tử chính là đối tượng để ngươi lập uy","bridge":true,"khoang":"@c1311"},{"mucCt":"vua","text":"Tư Mặc Tử xuất hiện tại một khu vực trên không không ai dám tới gần ở trường đấu, đứng cùng Vân Lạc của Trường Tôn hội. Trước khi tới đây, Lão Chu Tước đã nói sau thí luyện sẽ lấy hắn lập uy.","anchor":"Thí luyện xong liền lấy Tư Mặc Tử lập uy!","bridge":true,"khoang":"@c1312"},{"mucCt":"vua","anchor":"Trong ánh mắt tư Mặc Tử cực kỳ băng hàn, lộ ra sát khí","text":"Tư Mặc Tử nhìn Vương Lâm đầy sát khí nhưng phải hạ giọng trước lão Chu Tước vì tự nhận không phải đối thủ. Hắn bị hư hỏa thiêu đốt, thổ huyết và bị tát liên tiếp trước mặt mọi người vì từng nhục mạ Vương Lâm.","bridge":true,"khoang":"@c1313"},{"mucCt":"vua","text":"Tư Mặc Tử mang thương tích tím đen do Lão Chu Tước lưu lại nên không dám công khai tỏ địch ý với Vương Lâm. Hắn dựa vào nghiên cứu của Trường Tôn hội về thí luyện Điên Lạc để tin rằng Vương Lâm không thể thành công.","anchor":"Lúc này Tư Mặc Tử cũng không dám tỏ địch ý rành rành như trước đối với Vương Lâm","bridge":true,"khoang":"@c1314"},{"chuong":"@c1315","importance":"normal","mucCt":"vua","tieuDe":"Khinh thường Vương Lâm tại thí luyện","text":"Trên Đại Đế tinh, cười nhạt khi thấy Vương Lâm bất động quá lâu tại cây hương thứ nhất. Gọi hắn là tiểu tạp chủng, cho rằng hắn kém cỏi và tin chắc hắn không thể thông qua thí luyện, sẽ bị thiếu đế thứ nhất trừng phạt.","anchor":"Tiểu tạp chủng này nhất định không thể thông qua thí luyện"},{"chuong":"@c1316","importance":"normal","mucCt":"vua","tieuDe":"Bị lão Chu Tước tát vạn trượng","text":"Tư Mặc Tử châm chọc thí luyện của thiếu đế thứ ba xảy ra ngoài ý muốn, lập tức bị lão Chu Tước tát một cái, phun máu tươi và bị cuốn đi vạn trượng.","anchor":"Tư Mặc Tử phun máu tươi, thân thể bị cuốn đi vạn trượng"},{"mucCt":"vua","text":"Tư Mặc Tử biến sắc khi tiếng Chu Tước vang lên và cây hương thứ nhất bốc cháy. Hắn không tin Vương Lâm còn có thể thoát khỏi tử cục mà Vân Lạc đại ti đã tính ra, rồi tiếp tục chăm chú nhìn biến hóa của cây hương.","anchor":"Không có khả năng! Vân Lạc đại ti cũng đã tính ra tiểu tạp chủng này khó thoát khỏi cái chết","bridge":true,"khoang":"@c1318"},{"chuong":"@c1322","importance":"bridge","mucCt":"vua","text":"Ở bên Vân Lạc đại ti trên Đại đế tinh, chứng kiến Đại đế tinh xoay tròn và sương mù từ lực tràn vào Địa phương hương, lộ vẻ hoảng sợ mờ mịt.","anchor":"Thần sắc Tư Mặc Tử lộ vẻ hoảng sợ, mờ mịt nhìn về Địa phương hương"},{"mucCt":"vua","text":"Chuỗi biến cố trong thí luyện của Vương Lâm vượt ngoài tưởng tượng, khiến Tư Mặc Tử dù là tu sĩ bước thứ ba cũng sinh kiêng kỵ với hồn phách Vương Lâm.","anchor":"tâm thần đối với hồn phách của Vương Lâm đã sinh ra một sự kiêng kỵ vô cùng","bridge":true,"khoang":"@c1323"}],"tuViMoc":[],"nhanMach":[{"ten":"Thác Sâm","tag":"doi-thu","quanHe":"Từng đuổi giết","ghiChu":"Tư Mặc Tử từng là một trong ba đại năng Đệ Tam Bộ đuổi giết Thác Sâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy bắt","ghiChu":"Hắn nhận huyết chỉ truy bắt người hủy diệt Thiểm Lôi tộc."},{"ten":"Trường Tôn Hội","tag":"cap-tren","quanHe":"Bên ban lệnh","ghiChu":"Huyết chỉ của Trường Tôn Hội giao nhiệm vụ và treo thưởng đạo linh cho hắn."},{"ten":"Vân Lạc","tag":"dong-minh","quanHe":"Nhờ tính toán tung tích","ghiChu":"Tư Mặc Tử biết Vương Lâm ở Điên Lạc nhờ Vân Lạc đại ti tính ra."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"dong-minh","quanHe":"Người quen cũ dự định mượn thế","ghiChu":"Tư Mặc Tử định mượn thân phận Long Giáp Tộc để hành động tại Điên Lạc."},{"ten":"Điên Lạc đại đế","tag":"doi-thu","quanHe":"người khiến hắn kiêng kỵ","ghiChu":"Không muốn động thủ tùy tiện vì sợ Điên Lạc đại đế xuất hiện."},{"ten":"Bạch Phàm","tag":"khac","quanHe":"Người có thần thông bị nhận diện","ghiChu":"Tư Mặc Tử nhận ra Sơn Băng thuật của Vương Lâm là thần thông của Bạch Phàm."},{"ten":"Tư Mã Mặc","tag":"khac","quanHe":"Manh mối cùng Phá Thiên tông","ghiChu":"Thần thông của Tư Mặc Tử khiến Vương Lâm nhớ tới Tư Mã Mặc và Phá Thiên tông."},{"ten":"Đại đế","tag":"khac","quanHe":"người can thiệp khiến biến sắc","ghiChu":"Tư Mặc Tử hoảng hốt khi tiếng nói từ hư vô đặt hạn năm nhịp thở cho Vương Lâm thắng phân thân bước thứ ba."},{"ten":"Nữ tử Trường Tôn hội","tag":"dong-minh","quanHe":"Người cùng hiện diện trong thông đạo","ghiChu":"Cùng bị Vương Lâm bỏ qua khi hắn đi tiếp."},{"ten":"Chu Tước đời thứ hai","tag":"doi-thu","quanHe":"Bị Chu Tước đời thứ hai xem là mục tiêu lập uy cho Vương Lâm.","ghiChu":"Dù là tu sĩ bước thứ ba vẫn bị xem là có thể đem ra lập uy."},{"ten":"Lão Chu Tước","tag":"doi-thu","quanHe":"đối tượng bị nhắm tới","ghiChu":"Lão Chu Tước định lấy Tư Mặc Tử lập uy sau thí luyện."}],"tuiDo":{"phapBao":[{"ten":"Huyết chỉ của Trường Tôn Hội","loai":"lệnh phù","trangThai":"da-dung","moTa":"Huyết chỉ mang nhiệm vụ truy bắt Vương Lâm và xác nhận khi bị bóp nát.","nguon":"@c1281"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Lục Phẩm đạo linh","loai":"đạo linh","trangThai":"dang-dung","moTa":"Được Tư Mặc Tử hấp thu để tăng tu vi và tìm dấu hiệu đột phá.","nguon":"@c1281"}],"linhThao":[],"khac":[]}},"nguon":["@c1281","@c1284","@c1287","@c1288","@c1289","@c1290","@c1291","@c1292","@c1307","@c1308","@c1309","@c1311","@c1312","@c1313","@c1314","@c1315","@c1316","@c1318","@c1322","@c1323"]},{"id":"loi-oa","name":"Lôi Oa","aliases":[],"gioiTinh":"khong-ro","trangThai":"khong-ro","tabs":{"diem":[{"text":"Dùng lôi cầu tự bạo trong trận Vương Lâm đấu Hồng Diệp để chặn ngân quang","chuong":"@c0274"},{"text":"Được Vương Lâm xuất ra khi rời thung lũng đi Chu Tước quốc, yêu khí đậm đặc khiến lão hổ Tiểu Bạch kinh sợ","chuong":"@c0334"},{"text":"Đối địch với Lôi Thú do Xạ Thần Xa hóa thành sau khi được thả khỏi túi trữ vật","chuong":"@c0689"},{"text":"Tái xuất khỏi Tiên Giới Toái Phiến với xích ở cổ, phù chỉ khắp thân và thiết hoàn","chuong":"@c0876"},{"text":"Chịu được nhiệt độ cao và hấp thu hỏa nguyên lực bên bờ núi lửa Chu Tước thánh tông","chuong":"@c1028"},{"text":"Được xác nhận là mãnh thú mang huyết mạch sấm sét, phong làm linh hồn lôi","chuong":"@c1282"}],"kinhLich":[{"chuong":"@c1282","importance":"normal","mucCt":"vua","tieuDe":"Hóa Huyết Mạch lôi","text":"Lôi Oa được Vương Lâm gọi ra và xác nhận là mãnh thú mang huyết mạch sấm sét. Nó được phong làm linh hồn lôi đồ thứ tám, hóa thành Huyết Mạch lôi rồi nhập vào mắt phải Vương Lâm.","anchor":"Lôi Oa đã đi theo Vương Lâm rất nhiều năm đột nhiên phóng ầm ầm từ trong không gian trữ vật ra ngoài"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1282"],"vaiTro":"Nhân vật phụ — yêu thú loại lôi điện đi theo Vương Lâm","tinhCach":"hiếu chiến khi lâm trận; trung thành đi theo Vương Lâm; hoài niệm nơi cũ; lười biếng nhàn nhã khi vô sự","blurb":"Lôi Oa là yêu thú thuộc loại lôi điện được Vương Lâm nuôi giữ, nhiều lần được thả ra giao chiến hoặc thu vào túi trữ vật. Nó từng dùng lôi cầu tự bạo trong trận đấu Hồng Diệp, về sau tái xuất khỏi Tiên Giới Toái Phiến trong tình trạng bị xích cổ, phù chỉ khắp thân và thiết hoàn, rồi hấp thu hỏa nguyên lực bên bờ núi lửa Chu Tước thánh tông. Tính tới mốc mới nhất, nó được xác nhận là mãnh thú mang huyết mạch sấm sét và được phong làm linh hồn lôi."},{"id":"co-gai-hac-y-phieu-mieu-toc","name":"Cô gái hắc y","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Phiêu Miễu tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Nữ tử của Phiêu Miễu tộc từng tính vị trí Vương Lâm. Nàng nắm truyền thừa quẻ tượng của tổ tiên và nhận ra dị tượng Không Môn đã ứng ba trong chín quẻ.","vaiTro":"người xem quẻ Phiêu Miễu tộc","tinhCach":[{"text":"nhạy cảm với dị tượng và quẻ tượng","chuong":"@c1284"},{"text":"kính sợ lời truyền của tổ tiên","chuong":"@c1284"}],"tabs":{"diem":[{"text":"Ở tinh vực Phiêu Miễu tộc, nàng chứng kiến hoa cỏ héo rũ, hồ nước cuộn xoáy và sấm sét giáng xuống khi Không Môn của Vương Lâm huyễn hóa.","chuong":"@c1284"},{"text":"Nàng nhận ra chín quẻ tổ tiên truyền xuống đã ứng ba quẻ trong lần dị tượng này.","chuong":"@c1284"}],"kinhLich":[{"mucCt":"vua","text":"Cô gái hắc y đang thổ nạp trên hòn đảo từng tính vị trí Vương Lâm thì chứng kiến hoa cỏ héo rũ, hồ nước cuộn xoáy và sấm sét giáng xuống. Nàng đọc các quẻ tổ tiên truyền lại và kinh hãi khi nhận ra đã ứng ba trong chín quẻ.","anchor":"Chín quẻ mà tổ tiên truyền xuống, lúc này lại xuất hiện ba quẻ","bridge":true,"khoang":"@c1284"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người từng bị nàng tính vị trí","ghiChu":"Dị tượng Không Môn của Vương Lâm khiến quẻ truyền thừa Phiêu Miễu tộc ứng nghiệm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Chín quẻ tổ tiên Phiêu Miễu tộc truyền xuống","loai":"bói/quẻ","trangThai":"dang-co","moTa":"Hệ quẻ truyền thừa dùng để nhận biết các dị tượng lớn, trong chương này đã ứng ba quẻ.","nguon":"@c1284"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1284"]},{"id":"cuu-thien-ma-ton","name":"Cửu Thiên Ma Tôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Cửu Thiên Ma Tôn là đại năng ma đạo từng nổi danh vì dám lẻn vào Điên Lạc Địa, song trọng thương rút lui và lập thề không quay lại. Trong cổ mộ nhiều tầng bản đồ, hắn ngồi trên đài mộ cấp bảy thi triển đạo thuật truy sát đối thủ nhưng liên tục bị Vương Lâm áp chế — phân thân toàn diệt, bổn tôn hoảng sợ, cuối cùng bị nhốt trong cổ mộ. Sau khi được Chưởng Tôn giải cứu, hắn bại trận trước Lam Mộng Đạo Tôn mất hương hỏa giới, rồi vây đánh Vương Lâm bị bắt gọn nguyên thần, và cuối cùng bị Vương Lâm phong ấn thu vào trữ vật.","vaiTro":"Đại năng ma đạo — đối thủ dai dẳng của Vương Lâm trong cổ mộ và ngoại giới","tinhCach":"tự phụ thực lực, dám đơn độc xâm nhập hiểm địa; biết tiến biết lui, thề không tái phạm khi trọng thương; mưu mô toan tính, sẵn sàng kết thỏa thuận vì lợi ích; thù dai, thương thế chưa hồi phục vẫn quyết trả thù","tabs":{"diem":[{"text":"Từng lẻn vào Điên Lạc Địa, trọng thương rút lui và thề không bao giờ quay lại","chuong":"@c1284"},{"text":"Ngồi trên đài mộ cấp bảy trong bản đồ thứ tám của cổ mộ, thi triển đạo thuật truy sát nhưng bị Vương Lâm áp chế, toàn bộ phân thân tử vong","chuong":"@c1377"},{"text":"Bị nhốt trong cổ mộ sau khi Vương Lâm thu Địa Phù","chuong":"@c1386"},{"text":"Được Chưởng Tôn giải cứu khỏi cổ mộ, bại trận trước Lam Mộng Đạo Tôn, hương hỏa giới bị hủy diệt và tâm thần tổn thương","chuong":"@c1583"},{"text":"Cùng Diệu Âm Đạo Tôn và Thất Phi vây Vương Lâm, bị mũi tên cung Lý Quảng đánh nổ thân thể, nguyên thần bị bắt gọn","chuong":"@c1596"},{"text":"Bị Vương Lâm phong ấn thu vào trữ vật khi đang trị thương trên tu chân tinh","chuong":"@c1697"}],"kinhLich":[{"chuong":"@c1284","importance":"bridge","mucCt":"gon","tieuDe":"Kiêng kỵ Điên Lạc","text":"Cửu Thiên Ma Tôn được nhắc là từng âm thầm lẻn vào Điên Lạc Địa, sau đó trọng thương rút lui và thề không vào nữa.","anchor":"Cửu Thiên ma Tôn đã từng âm thầm lẻn vào nơi này"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1284"]},{"id":"nguoi-buoc-vao-dong-phu","name":"Người bước vào động phủ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Nhân vật chưa lộ danh tính xuất hiện ở cuối chương trong động phủ Vương Lâm thuê tại Điên Lạc Địa. Mục đích và thân phận của người này chưa được nêu rõ.","vaiTro":"người bí ẩn vào động phủ","tinhCach":[{"text":"hành động nhanh và bất ngờ","chuong":"@c1284"}],"tabs":{"diem":[{"text":"Xuất hiện ngay khi cửa chính động phủ của Vương Lâm mở ra, tạo biến cố nối sang diễn biến kế tiếp.","chuong":"@c1284"}],"kinhLich":[{"mucCt":"gon","text":"Cuối chương, người này nhanh chóng bước vào động phủ của Vương Lâm tại Điên Lạc Địa khi Vương Lâm đang dưỡng thương.","anchor":"có một người bước vào rất nhanh","bridge":true,"khoang":"@c1284"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người xâm nhập nơi Vương Lâm dưỡng thương","ghiChu":"Chưa rõ mục đích khi bước vào động phủ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1284"]},{"id":"lao-gia-ho-chuong","name":"Lão già họ Chương","cn":"","aliases":["Chương đạo hữu"],"gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hóa Thần hậu kỳ","trangThai":"song","blurb":"Tu sĩ Hóa Thần hậu kỳ ở một sơn cốc âm khí, quen Chung Đại Hồng nhờ được biếu đan dược. Lão dẫn Chung đi mua con rối của Ám Hạt Tộc rồi bị bắt sau giao dịch.","vaiTro":"Người trung gian đưa Chung Đại Hồng tới giao dịch con rối với Ám Hạt Tộc.","tinhCach":[{"text":"Thận trọng trước Ám Hạt Tộc nhưng vẫn nhận lời giúp Chung Đại Hồng sau khi được tặng đan dược.","chuong":"@c1285"},{"text":"Biết nhìn thế cục, từ đan dược của Chung Đại Hồng mà nhận ra sau lưng hắn có chủ nhân khó lường.","chuong":"@c1285"}],"tabs":{"diem":[{"text":"Tu vi Hóa Thần hậu kỳ đã dừng lại rất lâu, nên đan dược thượng phẩm có sức hấp dẫn lớn với lão.","chuong":"@c1285"},{"text":"Sống trong sơn cốc hoang vu tràn âm khí, động phủ phủ sương đen và xung quanh có xương thú như bố trí theo trận pháp.","chuong":"@c1285"},{"text":"Nắm đường tới giao dịch con rối do Ám Hạt Tộc khống chế.","chuong":"@c1285"}],"kinhLich":[{"mucCt":"vua","anchor":"Tiểu đệ thấy tu vi của Chương đại ca đã dừng lại ở Hóa Thần hậu kỳ rất lâu","text":"Lão già họ Chương nhận ba viên thượng phẩm đan dược từ Chung Đại Hồng và càng kiêng dè chủ nhân sau lưng Chung. Sau khi cảnh báo Ám Hạt Tộc bá đạo và con rối khó mua, lão vẫn dẫn Chung tới thành trì hoang phế để giao dịch. Trên đường rời đi, lão bị nam tử trung niên Ám Hạt Tộc bắt lại và sau đó chứng kiến Vương Lâm phá thành.","bridge":true,"khoang":"@c1285"},{"mucCt":"gon","anchor":"quyết định một chuyện, nói là gì cũng phải theo Chung Đại Hồng","text":"Lão già họ Chương được Chung Đại Hồng đỡ khi bảo tháp sụp, chứng kiến thực lực của Vương Lâm rồi quyết định phải theo Chung Đại Hồng để kết giao.","bridge":true,"khoang":"@c1286"},{"mucCt":"vua","text":"Lão già họ Chương đứng sau Chung Đại Hồng với thái độ cung kính và tự đắc khi thấy Ám Hạt Tộc bị răn dạy. Khi Tham Lang dùng quạt lớn, lão phun máu, hôn mê và bị cuốn bay mất tung tích.","anchor":"Lão già họ Chương phun một ngụm máu tươi liền trực tiếp hôn mê","bridge":true,"khoang":"@c1296"},{"chuong":"@c1300","importance":"bridge","mucCt":"gon","anchor":"ngay cả lão giả họ Chương đi theo Chung Đại Hồng cũng được mời về","text":"Lão giả họ Chương đi theo Chung Đại Hồng cũng được Vân Độn tộc mời trở về cùng Ám Hạt Tộc sau khi đối phương đổi thái độ."}],"tuViMoc":[{"chuong":"@c1285","canhGioi":"Hóa Thần hậu kỳ","text":"Lão già họ Chương được nói rõ có tu vi Hóa Thần hậu kỳ và đã dừng ở cảnh giới này rất lâu.","importance":"minor"}],"nhanMach":[{"ten":"Chung Đại Hồng","tag":"dong-minh","quanHe":"Người đem đan dược tới kết giao và nhờ lão dẫn đi mua con rối.","ghiChu":"Lão nhận đan dược của Chung Đại Hồng rồi cùng hắn tới thành trì Ám Hạt Tộc."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân của Chung Đại Hồng mà lão suy đoán là tu sĩ mạnh khó lường.","ghiChu":"Lão biết Chung Đại Hồng có chủ nhân phía sau, về sau kinh hãi khi thấy Vương Lâm phá thành."},{"ten":"Nam tử trung niên Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ bắt lão sau giao dịch con rối.","ghiChu":"Người này dùng hắc quang bắt lão về đại điện theo lệnh thiếu chủ."},{"ten":"Thiếu chủ Ám Hạt Tộc","tag":"doi-thu","quanHe":"Kẻ ra lệnh bắt một người sau giao dịch.","ghiChu":"Lão là người bị bắt trong mệnh lệnh của thiếu chủ Ám Hạt Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Hồn đan của Vương Lâm","loai":"đan dược","trangThai":"dang-co","moTa":"Lão nhận ba viên đan dược từ Chung Đại Hồng và xem đó là thượng phẩm đan dược rất thích hợp với tu vi Hóa Thần hậu kỳ của mình.","nguon":"@c1285"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1285","@c1286","@c1296","@c1300"]},{"id":"nam-tu-trung-nien-am-hat-toc","name":"Nam tử trung niên Ám Hạt Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Âm Hư","trangThai":"tu-vong","blurb":"Tu sĩ Ám Hạt Tộc mặc hắc y, mi tâm có tộc ấn bọ cạp. Hắn giao dịch con rối với Chung Đại Hồng, sau đó theo lệnh thiếu chủ bắt lão họ Chương và đánh thương Chung.","vaiTro":"Người trực tiếp giao dịch con rối và ra tay truy kích Chung Đại Hồng sau giao dịch.","tinhCach":[{"text":"Lạnh lùng và bá đạo, sau khi nhận hồn đan liền báo lên thiếu chủ rồi quay lại bắt người, đả thương người.","chuong":"@c1285"},{"text":"Biết nhận ra giá trị hồn đan và lập tức truy hỏi số đan dược còn lại.","chuong":"@c1285"}],"tabs":{"diem":[{"text":"Mặc hắc y, mi tâm có tộc ấn hình bọ cạp, đại diện cho Ám Hạt Tộc trong giao dịch con rối.","chuong":"@c1285"},{"text":"Nhận hai viên hồn đan để đổi một con rối Hóa Thần sơ kỳ cho Chung Đại Hồng.","chuong":"@c1285"},{"text":"Dùng hắc quang bắt lão họ Chương và đánh vào hậu tâm Chung Đại Hồng, để lại thương thế cùng lạc ấn truy tung.","chuong":"@c1285"},{"text":"Có tộc ấn hình bọ cạp của Ám Hạt Tộc trên mi tâm.","chuong":"@c1286"},{"text":"Bị Vương Lâm một chỉ lôi đình đánh cho hình thần đều diệt.","chuong":"@c1286"}],"kinhLich":[{"mucCt":"ky","anchor":"ở trên mi tâm không ngờ có tộc ấn hình bọ cạp","text":"Nam tử trung niên Ám Hạt Tộc xuất hiện trong đại điện, nhận ra đan dược của Chung Đại Hồng là hồn đan và dùng hai viên đổi một con rối Hóa Thần sơ kỳ. Sau đó hắn đem việc này báo cho thiếu chủ ở bảo tháp dưới đất. Theo lệnh thiếu chủ, hắn hóa hiện trên đường rời thành, dùng hắc quang bắt lão họ Chương và đánh trọng thương Chung Đại Hồng. Cuối chương, hắn kinh hãi trước cảnh Vương Lâm dùng lôi đình phá tan thành trì Ám Hạt Tộc.","bridge":true,"khoang":"@c1285"},{"mucCt":"vua","anchor":"nguyên thần trực tiếp bị diệt vong","text":"Nam tử trung niên Ám Hạt Tộc bị Chung Đại Hồng nhận ra, lập tức lùi lại và vận tộc ấn hình bọ cạp. Vương Lâm điểm một chỉ dẫn lôi đình giáng xuống, khiến thân xác hắn tan nát và nguyên thần bị diệt.","bridge":true,"khoang":"@c1286"}],"tuViMoc":[{"chuong":"@c1286","canhGioi":"Âm Hư","text":"Bị mô tả là tu sĩ Âm Hư khi bị Vương Lâm trấn sát.","importance":"minor"}],"nhanMach":[{"ten":"Chung Đại Hồng","tag":"doi-thu","quanHe":"Người giao dịch con rối rồi bị hắn đánh thương.","ghiChu":"Hắn nhận hồn đan của Chung Đại Hồng, sau đó đánh vào hậu tâm Chung khiến Chung trọng thương và bị lưu lạc ấn."},{"ten":"Lão già họ Chương","tag":"doi-thu","quanHe":"Người bị hắn bắt sau giao dịch.","ghiChu":"Hắn dùng hắc quang bắt lão họ Chương đưa về đại điện."},{"ten":"Thiếu chủ Ám Hạt Tộc","tag":"cap-tren","quanHe":"Thiếu chủ ra lệnh cho hắn truy bắt hai tu sĩ sau giao dịch.","ghiChu":"Hắn báo việc hồn đan lên thiếu chủ rồi thi hành lệnh bắt một người, đả thương một người."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Chủ nhân của Chung Đại Hồng, người phá thành Ám Hạt Tộc để hỏi tội hắn.","ghiChu":"Hành động đả thương Chung Đại Hồng khiến Vương Lâm tìm tới thành trì Ám Hạt Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Hồn đan của Vương Lâm","loai":"đan dược","trangThai":"dang-co","moTa":"Hắn nhận hai viên hồn đan từ Chung Đại Hồng trong giao dịch đổi con rối, sau đó đem báo lên thiếu chủ.","nguon":"@c1285"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Con rối Hóa Thần sơ kỳ","loai":"con rối","trangThai":"da-dung","moTa":"Hắn triệu ra con rối Hóa Thần sơ kỳ để đổi lấy hai viên hồn đan của Chung Đại Hồng.","nguon":"@c1285"}]}},"nguon":["@c1285","@c1286"]},{"id":"thieu-chu-am-hat-toc","name":"Thiếu chủ Ám Hạt Tộc","cn":"","aliases":["Thanh niên thiếu chủ Ám Hạt Tộc","Tộc trưởng Ám Hạt Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thanh niên cao ngạo của Ám Hạt Tộc, thổ nạp tại tầng hai bảo tháp dưới đại điện. Sau khi thấy hồn đan, hắn ra lệnh bắt một người, đả thương một người và lưu lạc ấn thần thức để truy tung.","vaiTro":"Người ra lệnh truy bắt sau giao dịch hồn đan, khiến xung đột với Vương Lâm bùng phát.","tinhCach":[{"text":"Cao ngạo, xem hồn đan là cấp tầm thường nhưng vẫn muốn tra nguồn gốc người mang đan tới.","chuong":"@c1285"},{"text":"Ra lệnh tàn nhẫn và có chủ ý truy tung, bắt một người, đả thương một người để lần ra nơi đến.","chuong":"@c1285"}],"tabs":{"diem":[{"text":"Ngồi thổ nạp ở tầng hai bảo tháp dưới nền đại điện Ám Hạt Tộc.","chuong":"@c1285"},{"text":"Có quyền sai khiến nam tử trung niên Ám Hạt Tộc truy bắt người sau giao dịch.","chuong":"@c1285"},{"text":"Chính mệnh lệnh lưu lạc ấn thần thức của hắn khiến Vương Lâm phát hiện ý đồ truy tung.","chuong":"@c1285"},{"text":"Sở hữu và sử dụng Ám hạt châu để đánh lén.","chuong":"@c1286"},{"text":"Bị lưới điện của Vương Lâm phong ấn, mất khả năng chống cự.","chuong":"@c1286"}],"kinhLich":[{"mucCt":"vua","anchor":"Hai tiểu tu kia bắt lấy một người, đả thương một người","text":"Thiếu chủ Ám Hạt Tộc đang thổ nạp trong tầng hai bảo tháp dưới đại điện thì nhận hồn đan do nam tử trung niên dâng lên. Hắn xem hồn đan chỉ là cấp tầm thường nhưng vẫn ra lệnh bắt một trong hai tu sĩ Hóa Thần, đánh thương người còn lại và lưu lạc ấn thần thức để xem kẻ đó đi đâu. Mệnh lệnh này khiến Chung Đại Hồng bị thương và kéo Vương Lâm tới phá thành Ám Hạt Tộc.","bridge":true,"khoang":"@c1285"},{"mucCt":"vua","anchor":"Người này kêu lên thảm thiết mất đi khả năng chống cự","text":"Thanh niên thiếu chủ Ám Hạt Tộc ẩn trong bảo tháp, dùng Ám hạt châu đánh lén Vương Lâm nhưng không làm hắn bị thương. Sau đó hắn bị lưới điện phong ấn, lơ lửng giữa không trung và cùng tộc nhân chứng kiến lời thề quy phục.","bridge":true,"khoang":"@c1286"},{"mucCt":"vua","anchor":"Tộc trưởng Ám Hạt Tộc phía sau Vương Lâm tất nhiên là hắn nhận ra","text":"Tộc trưởng Ám Hạt Tộc đứng sau Vương Lâm trong lầu hai như người hầu, khiến lão giả Hỏa Tước tộc càng kiêng dè thân phận Vương Lâm. Sau khi rời lầu, hắn được Vương Lâm bảo về Ám Hạt Tộc trước và cung kính vâng lệnh bay đi.","bridge":true,"khoang":"@c1289"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam tử trung niên Ám Hạt Tộc","tag":"cap-duoi","quanHe":"Thuộc hạ thi hành lệnh truy bắt.","ghiChu":"Nam tử trung niên đem hồn đan báo lên thiếu chủ rồi theo lệnh đi bắt lão họ Chương và đánh thương Chung Đại Hồng."},{"ten":"Chung Đại Hồng","tag":"doi-thu","quanHe":"Mục tiêu bị hắn ra lệnh đả thương và lưu lạc ấn.","ghiChu":"Chung Đại Hồng là người bị đánh thương để Ám Hạt Tộc truy tung nơi đến."},{"ten":"Lão già họ Chương","tag":"doi-thu","quanHe":"Mục tiêu bị bắt theo lệnh của hắn.","ghiChu":"Lão họ Chương bị nam tử trung niên Ám Hạt Tộc bắt về sau giao dịch."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Chủ nhân của Chung Đại Hồng, người bị hành động truy tung của hắn chọc giận.","ghiChu":"Lệnh của thiếu chủ dẫn tới việc Vương Lâm phá thành Ám Hạt Tộc."},{"ten":"Lão giả Ám Hạt Tộc hắc bào","tag":"ho-hang","quanHe":"Trưởng bối trong tộc","ghiChu":"Cùng thuộc Ám Hạt Tộc và chịu kết cục toàn tộc quy phục Vương Lâm."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"đi theo và nghe lệnh","ghiChu":"Hắn theo sau Vương Lâm trong lầu giao dịch rồi nhận lệnh quay về Ám Hạt Tộc trước."},{"ten":"Lão giả Hỏa Tước tộc","tag":"khac","quanHe":"người nhận ra thân phận hắn","ghiChu":"Lão giả Hỏa Tước tộc nhận ra hắn đứng sau Vương Lâm nên càng cảnh giác."}],"tuiDo":{"phapBao":[{"ten":"Pho tượng bọ cạp trong bảo tháp","loai":"tượng","trangThai":"dang-co","moTa":"Tượng bọ cạp đặt tại tầng hai bảo tháp dưới đại điện, nơi thiếu chủ ngồi thổ nạp bên ngoài như hấp thu lực lượng từ pho tượng.","nguon":"@c1285"}],"danDuoc":[{"ten":"Hồn đan của Vương Lâm","loai":"đan dược","trangThai":"dang-co","moTa":"Thiếu chủ nhận hồn đan do nam tử trung niên dâng lên sau giao dịch và xem đó là cấp tầm thường.","nguon":"@c1285"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1285","@c1286","@c1289"]},{"id":"lao-gia-am-hat-toc-hac-bao","name":"Lão giả Ám Hạt Tộc hắc bào","cn":"","aliases":["Lão giả Ám Hạt Tộc","Tộc trưởng Ám Hạt Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"},{"ten":"Điên Lạc","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Tịnh Niết trung kỳ @c1287","trangThai":"song","blurb":"Trưởng bối Ám Hạt Tộc có tộc ấn bọ cạp bốn đuôi, bị Vương Lâm trấn áp tại đáy bảo tháp. Sau khi phát lời thề quy phục, lão báo cáo cục diện Điên Lạc, con rối, Hỏa Tước tộc và Viêm hỏa dị tinh.","vaiTro":"Đại diện Ám Hạt Tộc phát thệ quy phục Vương Lâm và cung cấp tin tức về Điên Lạc.","tinhCach":[{"text":"Ban đầu cứng rắn, viện danh Điên Lạc đại đế để uy hiếp đối phương.","chuong":"@c1286"},{"text":"Sau khi bị áp đảo thì biết thời thế, lập lời thề tộc ấn và cung cấp tin tức chi tiết.","chuong":"@c1286"}],"tabs":{"diem":[{"text":"Mang tộc ấn bọ cạp bốn đuôi của Ám Hạt Tộc.","chuong":"@c1286"},{"text":"Tu vi bị Vương Lâm nhận ra là Thiên Nhân Đệ Nhị Suy.","chuong":"@c1286"},{"text":"Nắm nhiều tin tức về Điên Lạc, Lạc Sinh hội, hệ thống con rối, Hỏa Tước tộc và Viêm hỏa dị tinh.","chuong":"@c1286"}],"kinhLich":[{"chuong":"@c1286","importance":"normal","mucCt":"ky","tieuDe":"Phát thệ quy phục","anchor":"lão phu xin lấy tộc ấn phát lời thề của tộc thái cổ","text":"Lão giả Ám Hạt Tộc hắc bào xuất thủ từ tầng sâu nhất của bảo tháp, dùng thần thông bọ cạp, bốn con rối và danh nghĩa Điên Lạc đại đế để uy hiếp Vương Lâm. Khi bị quyền Cổ Thần và một chỉ của Vương Lâm áp đảo tới mức nguyên thần xuất khiếu, lão phải lấy tộc ấn phát lời thề thái cổ, đại diện toàn tộc tôn Vương Lâm làm chủ. Sau khi quy phục, lão báo cáo Điên Lạc có ba trăm bảy mươi hai tiểu tộc, Lạc Sinh hội có mười ba trưởng lão, con rối cao cấp chỉ bán ở tinh cầu thuộc bộ tộc trưởng lão, đồng thời dâng Viêm hỏa dị tinh và nói về hoạt động của Hải hồn tông do Hỏa Tước tộc phái tới."},{"chuong":"@c1287","importance":"normal","mucCt":"vua","tieuDe":"Dâng dị tinh dẫn đường","text":"Kiệt trưởng lão đã lấy Viêm hỏa dị tinh ra trước đó, khiến Vương Lâm nhận ra manh mối liên quan Chu Tước Thánh Tông. Khi con rối Ám Hạt Tộc bị hủy, lão cảm nhận khí tức quen thuộc và sau đó vâng lệnh dẫn Vương Lâm tới tu chân tinh của trưởng lão Lạc Sinh hội gần nhất.","anchor":"lão giả của Ám Hạt Tộc xuất ra Viêm hỏa dị tinh này"},{"chuong":"@c1288","importance":"normal","mucCt":"vua","tieuDe":"Dẫn đường tới Long Giáp","text":"Kiệt trưởng lão dẫn Vương Lâm rời tu chân tinh Ám Hạt Tộc, giới thiệu Long Giáp Tộc, phường thị và việc Hỏa Tước tộc thường tranh mua Viêm hỏa dị tinh. Khi vào lầu các Long Giáp Tộc, hắn đứng phía sau Vương Lâm không dám ngồi, khiến nữ tử quản sự chú ý.","anchor":"Lão giả Ám Hạt Tộc vừa dẫn đường vừa thấp giọng nói."},{"mucCt":"vua","text":"Tộc trưởng Ám Hạt Tộc đang thổ nạp thì phát hiện Vân Độn tộc kéo tới, bèn viện dẫn thân phận Ám Hạt Tộc thuộc Lạc Sinh hội để kháng nghị. Trước khí thế và cuồng phong của Tham Lang, hắn không chống nổi và bị cuốn lùi.","anchor":"Tộc trưởng Ám Hạt Tộc đau khổ giãy dụa nhưng thân thể không tự chủ được bị cuốn lui lại phía sau","bridge":true,"khoang":"@c1296"}],"tuViMoc":[{"chuong":"@c1286","canhGioi":"Thiên Nhân Đệ Nhị Suy","text":"Vương Lâm nhận ra lão giả Ám Hạt Tộc hắc bào chỉ là tu sĩ Thiên Nhân Đệ Nhị Suy trong lúc giao phong.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ nhân sau lời thề","ghiChu":"Bị Vương Lâm đánh bại và buộc phát lời thề tộc ấn quy phục."},{"ten":"Chung Đại Hồng","tag":"doi-thu","quanHe":"Người đề nghị ràng buộc mình","ghiChu":"Chung Đại Hồng nhắc phải buộc lão phát lời thề tộc ấn thái cổ."},{"ten":"Thiếu chủ Ám Hạt Tộc","tag":"ho-hang","quanHe":"Tộc nhân hậu bối","ghiChu":"Cùng thuộc Ám Hạt Tộc và cùng chịu sự quy phục của toàn tộc."},{"ten":"Điên Lạc đại đế","tag":"cap-tren","quanHe":"Người bảo hộ Điên Lạc được viện danh","ghiChu":"Lão dùng danh nghĩa Điên Lạc đại đế để uy hiếp trước khi bị trấn áp."},{"ten":"Chu Tước lão Thánh Hoàng","tag":"khac","quanHe":"Liên hệ gián tiếp qua Viêm hỏa dị tinh","ghiChu":"Viêm hỏa dị tinh do lão dâng khiến Vương Lâm nhớ đến lời Chu Tước lão Thánh Hoàng."},{"ten":"Nữ tử quản sự lầu các Long Giáp Tộc","tag":"khac","quanHe":"người giao tiếp tại cửa hàng","ghiChu":"Thái độ đứng sau Vương Lâm của hắn khiến nữ tử quản sự kinh ngạc."}],"tuiDo":{"phapBao":[{"ten":"Bốn con rối trăm trượng","loai":"con rối chiến đấu","trangThai":"da-dung","moTa":"Bốn con rối cỡ trăm trượng được lão triệu ra để vây công Vương Lâm, mỗi con có khí tức tương đương âm dương hư thực và định tự nổ.","nguon":"@c1286"},{"ten":"Con rối Tịnh Niết trung kỳ của Ám Hạt Tộc","loai":"con rối chiến đấu","trangThai":"dang-co","moTa":"Con rối mạnh nhất của Ám Hạt Tộc, hình dạng trung niên nam tử, không có sinh cơ và toàn thân phủ phong ấn.","nguon":"@c1286"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Viêm hỏa dị tinh","loai":"dị vật","trangThai":"da-dung","moTa":"Mảnh nhỏ được lão lấy ra dâng cho Vương Lâm khi nói về Hải hồn tông và Hỏa Tước tộc.","nguon":"@c1286"}],"linhThao":[],"khac":[]}},"nguon":["@c1286","@c1287","@c1288","@c1296"]},{"id":"dien-lac-dai-de","name":"Điên Lạc đại đế","cn":"","aliases":["Đại đế vùng Điên Lạc","Đại đế","Đại đế thần bí","Điên Lạc đại đế"],"gioiTinh":"nam","theLuc":[{"ten":"Điên Lạc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1311","trangThai":"khong-ro","blurb":"Điên Lạc đại đế là lão tổ đầu tiên của Chu Tước thánh tộc, một trong tứ đại chiến tướng của viễn cổ tiên tôn, tự mình trấn giữ Thiên phương hương và che chở vùng Điên Lạc khiến nơi này nằm ngoài tầm quản lý của Trường Tôn hội. Tu vi đạt Không Kiếp sơ kỳ ở bước thứ ba, ông hành sự chủ yếu từ hư vô — giọng nói truyền tới tai sinh linh cả tu chân tinh mà không hiện thân, phong Vương Lâm làm thiếu đế và giảng đạo về bản chất Niết Không bước thứ ba cho hắn. Thân phận cùng mối liên hệ với Viêm hỏa dị tinh và Chu Tước thánh tộc từng bị Vương Lâm nghi vấn, cho đến khi Chu Tước đời thứ hai xác nhận Chu","vaiTro":"Đại đế thần bí bảo hộ vùng Điên Lạc — lão tổ đầu tiên Chu Tước thánh tộc, viễn cổ chiến tướng","tinhCach":"Ẩn mình hành sự từ hư vô, không trực tiếp lộ thân; quyết đoán trong thưởng phạt, xử tử kẻ phản trắc không do dự; ban phát đan dược và pháp bảo cho thuộc hạ xứng đáng; thâm trầm trước đại sự, trầm mặc cân nhắc trước khi thừa nhận lý lẽ người khác","tabs":{"diem":[{"text":"Được xác nhận là tồn tại bước thứ ba bảo hộ vùng Điên Lạc, khiến Trường Tôn hội không thể quản lý nơi này","chuong":"@c1286"},{"text":"Không lộ thân, chỉ dùng tiếng cười và giọng nói từ hư vô truyền tới tai mọi sinh linh trên tu chân tinh, can thiệp khiến Tư Mặc Tử phải kiêng kỵ","chuong":"@c1291"},{"text":"Truyền lệnh phong Vương Lâm làm thiếu đế, đồng thời xử tử tộc trưởng Long Giáp Tộc để lập uy","chuong":"@c1294"},{"text":"Được xác nhận là lão tổ đầu tiên Chu Tước thánh tộc, một trong tứ đại chiến tướng của viễn cổ tiên tôn, tự mình trấn giữ Thiên phương hương","chuong":"@c1324"},{"text":"Giảng đạo bản chất Phá Không Ngũ Chỉ và Niết Không bước thứ ba cho Vương Lâm, truyền bảo vật sau khi xác nhận hắn vượt qua thí luyện","chuong":"@c1327"},{"text":"Tu vi được xác định là Không Kiếp sơ kỳ, chỉ mở được năm lần Phần Giới Cổ Tán","chuong":"@c1336"}],"kinhLich":[{"mucCt":"gon","anchor":"Điên Lạc đại đế đạt tới bước thứ ba","text":"Điên Lạc đại đế được lão giả Ám Hạt Tộc nhắc là tồn tại bước thứ ba bảo hộ Điên Lạc khỏi Trường Tôn hội, đồng thời bị gắn với lời đồn mang Viêm hỏa dị tinh tới nơi này.","bridge":true,"khoang":"@c1286"},{"chuong":"@c1287","importance":"bridge","mucCt":"vua","tieuDe":"Bị nghi vấn thân phận","text":"Điên Lạc đại đế bị Vương Lâm nghi vấn sâu hơn vì Viêm hỏa dị tinh ở Điên Lạc giống vật liên quan Chu Tước Thánh Tông, còn phương pháp tế luyện con rối và tinh thể lạ lại gợi tới bí mật Cổ Thần.","anchor":"Điên Lạc đại đế…người này rốt cục là ai"},{"chuong":"@c1288","importance":"bridge","mucCt":"gon","text":"Điên Lạc đại đế được nhắc là tồn tại khiến Tư Mặc Tử kiêng kỵ, không dám tùy tiện động thủ với Vương Lâm trong vùng đất Điên Lạc.","anchor":"nếu là để cho Điên Lạc đại đế xuất hiện thì không ổn"},{"mucCt":"gon","anchor":"hai loại còn lại không phải do tộc ta sáng tạo mà là Điên Lạc đại đế ban tặng","text":"Điên Lạc đại đế được thiếu tộc trưởng Long Giáp Tộc nhắc là người ban tặng bạch cốt long và Băng long đan cho Long Giáp Tộc.","bridge":true,"khoang":"@c1289"},{"chuong":"@c1291","importance":"major","mucCt":"ky","tieuDe":"Năm nhịp thở","text":"Đại đế chưa lộ thân, chỉ có tiếng cười và tiếng nói từ hư vô truyền tới tai mọi sinh linh trên tu chân tinh. Ông đặt điều kiện nếu Vương Lâm trong năm nhịp thở thắng phân thân bước thứ ba thì sẽ bảo đảm hắn bình an ở vùng đất Điên Lạc, rồi bắt đầu đếm.","anchor":"Có ý tứ, trong vòng năm nhịp thở có thể chiến thắng phân thân"},{"chuong":"@c1293","importance":"normal","mucCt":"vua","tieuDe":"Can thiệp từ hư vô","text":"Điên Lạc đại đế không trực tiếp hiện thân nhưng giọng nói từ hư vô vang lên khi Tư Mặc Tử định rời vùng Điên Lạc. Một chỉ khổng lồ từ dòng xoáy trên trời giáng xuống chặn Tư Mặc Tử, và sứ giả của đại đế sau đó mang khẩu dụ xử phạt tộc trưởng Long Giáp Tộc đồng thời xưng Vương Lâm là thiếu đế.","anchor":"Vùng đất Điên Lạc, có phải là chỗ ngươi muốn đến thì đến, muốn đi thì đi đâu"},{"chuong":"@c1294","importance":"normal","mucCt":"gon","tieuDe":"Phong thiếu đế","text":"Điên Lạc đại đế không trực tiếp ra mặt nhưng truyền lệnh phong Vương Lâm làm thiếu đế, xử tử tộc trưởng Long Giáp Tộc bằng độc đan, trao ngọc bội thân phận và mời Vương Lâm dự tuyển chọn trưởng lão Lạc Sinh hội.","anchor":"Oai nghiêm của đại đế ở vùng đất Điên Lạc này tựa như thần linh, không ai dám chống lại"},{"chuong":"@c1295","importance":"bridge","mucCt":"gon","tieuDe":"Ban đan cho Tham Lang","text":"Điên Lạc đại đế được nhắc là từng nhận pháp bảo Tham Lang dâng lên rồi ban đan dược giúp hắn đề cao tu vi.","anchor":"Điên Lạc đại đế sau khi nhận lấy liền ban cho hắn đan dược"},{"chuong":"@c1296","importance":"bridge","mucCt":"vua","tieuDe":"Mục đích bị nghi vấn","text":"Điên Lạc đại đế được Vương Lâm suy xét qua việc ban danh hiệu thiếu đế, đưa ngọc bội, trừng phạt tộc trưởng Long Giáp Tộc, giết phân thân Tư Mặc Tử và hẹn Vương Lâm ba tháng sau tới Lạc Sinh hội.","anchor":"Ba tháng sau là lúc Lạc Sinh hội tuyển trưởng lão, muốn ta tới đó"},{"chuong":"@c1307","importance":"bridge","mucCt":"gon","tieuDe":"Công bố thiếu đế","text":"Điên Lạc đại đế từng phát ngọc giản báo cho các bộ tộc về sự tồn tại của thiếu đế và lần này thông đạo Đại đế tinh được mở sớm vì Vương Lâm.","anchor":"Sự tồn tại của thiếu đế trong mấy tháng trước đã được Điên Lạc đại đế phát ngọc giản"},{"chuong":"@c1308","importance":"bridge","mucCt":"gon","tieuDe":"Xem nhẹ Lạc Sinh hội","text":"Qua phản ứng đối với phép thử của Vương Lâm, Điên Lạc đại đế lộ ra thái độ không xem Lạc Sinh hội là trọng yếu.","anchor":"Đại đế thần bí kia căn bản không cần Lạc Sinh hội"},{"chuong":"@c1309","importance":"bridge","mucCt":"vua","tieuDe":"Bị Vương Lâm nghi kỵ","text":"Đại đế bị Vương Lâm nghi ngờ đã dự liệu trước sức hấp dẫn của Cổ Hồn cấm và vẫn là thế lực mà hắn cân nhắc lợi dụng.","anchor":"Đại đế này rốt cục là nhân vật thể nào"},{"mucCt":"vua","text":"Chu Tước lão tổ được Chu Tước đời thứ hai giải thích là cách gọi trong Chu Tước thánh tộc dành cho Điên Lạc đại đế. Ông được nhắc là một trong tứ đại chiến tướng cực mạnh dưới trướng viễn cổ tiên tôn.","anchor":"Điên Lạc đại đế là cách gọi của người ngoài","bridge":true,"khoang":"@c1311"}],"tuViMoc":[{"chuong":"@c1286","canhGioi":"Bước thứ ba","text":"Lão giả Ám Hạt Tộc nói Điên Lạc đại đế đạt tới bước thứ ba.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng khiến Vương Lâm sinh nghi","ghiChu":"Vương Lâm nghi vấn vì sao Điên Lạc đại đế có Viêm hỏa dị tinh."},{"ten":"Lão giả Ám Hạt Tộc hắc bào","tag":"cap-tren","quanHe":"Người được viện danh","ghiChu":"Lão giả Ám Hạt Tộc lấy danh Điên Lạc đại đế để uy hiếp Vương Lâm."},{"ten":"Tư Mặc Tử","tag":"doi-thu","quanHe":"người kiêng kỵ uy danh","ghiChu":"Tư Mặc Tử e ngại nếu động thủ tùy tiện sẽ khiến Điên Lạc đại đế xuất hiện."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"người được danh nghĩa Điên Lạc che chở","ghiChu":"Sự kiêng kỵ Điên Lạc đại đế khiến Tư Mặc Tử chưa ra tay ngay với Vương Lâm."},{"ten":"Thiếu tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"người nhắc tới bảo vật do hắn ban","ghiChu":"Thiếu tộc trưởng Long Giáp Tộc giới thiệu hai bảo vật của tộc có nguồn gốc từ Điên Lạc đại đế."},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Người bị đặt vào hạn đấu năm nhịp thở với Vương Lâm.","ghiChu":"Tư Mặc Tử biến sắc khi nghe tiếng Đại đế."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"Người nhận ra uy danh Đại đế và kinh hô.","ghiChu":"Phản ứng của trưởng lão thứ chín Lạc Sinh hội xác nhận danh xưng Đại đế."},{"ten":"Nam tử trung niên hồng sam","tag":"cap-tren","quanHe":"Sứ giả phụng khẩu dụ của đại đế.","ghiChu":"Lộ qua khẩu dụ tại @c1293."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"cap-tren","quanHe":"Tước tư cách trưởng lão thứ chín và ban đan trừng phạt.","ghiChu":"Thông qua sứ giả tại @c1293."},{"ten":"Tham Lang","tag":"khac","quanHe":"Từng ban thưởng","ghiChu":"Nhận pháp bảo từ Tham Lang và ban đan dược cho hắn."},{"ten":"Trưởng lão thứ chín của Lạc Sinh hội","tag":"khac","quanHe":"người nhận ra danh xưng","ghiChu":"Trưởng lão thứ chín biến sắc và kinh hô Đại đế khi tiếng nói vang lên."},{"ten":"Nam tử trung niên đi cùng Vân Lạc","tag":"doi-thu","quanHe":"Từng giết phân thân của đối phương","ghiChu":"Sự việc này được nam tử trung niên nhắc lại khi gặp Vân Lạc."},{"ten":"Vân Lạc","tag":"khac","quanHe":"Đối tượng quan sát gián tiếp","ghiChu":"Vân Lạc muốn gặp người được ông che chở."},{"ten":"Sứ giả đại đế","tag":"cap-tren","quanHe":"Người sai phái","ghiChu":"Sứ giả phụng mệnh đại đế đưa Vương Lâm vào Đại đế tinh."},{"ten":"Chu Tước đời thứ hai","tag":"su-mon","quanHe":"Lão tổ trong truyền thừa Chu Tước thánh tộc được Chu Tước đời thứ hai nhắc tới.","ghiChu":"Được nêu khi giải thích cách gọi Điên Lạc đại đế."},{"ten":"Viễn cổ tiên tôn","tag":"cap-tren","quanHe":"Một trong tứ đại chiến tướng dưới trướng viễn cổ tiên tôn.","ghiChu":"Quan hệ được nhắc qua lời Chu Tước đời thứ hai."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1286","@c1287","@c1288","@c1289","@c1291","@c1293","@c1294","@c1295","@c1296","@c1305","@c1307","@c1308","@c1309","@c1311"]},{"id":"chu-tuoc-lao-thanh-hoang","name":"Chu Tước lão Thánh Hoàng","cn":"","aliases":["Lỗ Vân"],"gioiTinh":"nam","theLuc":[{"ten":"Tứ Thánh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Người từng nói với Vương Lâm rằng Tứ Thánh Tông vốn từ Thái Cổ Tinh Thần rồi mới vào giới nội. Lời này được Vương Lâm nhớ lại khi thấy Viêm hỏa dị tinh.","vaiTro":"Người để lại manh mối về nguồn gốc Tứ Thánh Tông.","tinhCach":[],"tabs":{"diem":[{"text":"Từng tiết lộ nguồn gốc Tứ Thánh Tông liên quan Thái Cổ Tinh Thần.","chuong":"@c1286"}],"kinhLich":[{"mucCt":"gon","anchor":"Năm đó Chu Tước lão Thánh Hoàng từng nói","text":"Chu Tước lão Thánh Hoàng được Vương Lâm nhớ lại qua lời từng nói rằng Tứ Thánh Tông vốn từ Thái Cổ Tinh Thần tới rồi mới tiến vào giới nội.","bridge":true,"khoang":"@c1286"},{"chuong":"@c1287","importance":"bridge","mucCt":"vua","tieuDe":"Được Vương Lâm nhớ lại","text":"Chu Tước lão Thánh Hoàng được Vương Lâm nhớ lại như người có ân tái sinh, lời kể trước khi chết về xuất thân luyện khí và biến cố Hành Văn tộc cũng được gợi lại.","anchor":"Lão phu Lỗ Vân, sinh ra từ thời luyện khí thượng cổ"},{"chuong":"@c1310","importance":"bridge","mucCt":"gon","tieuDe":"Bị đem ra so sánh","text":"Chu Tước lão Thánh Hoàng năm xưa được Vương Lâm nhớ tới khi thấy hư ảnh Chu Tước của lão giả có hỏa lực vượt xa mình.","anchor":"Ngọn lửa ẩn chứa trong Chu Tước này mạnh mẽ vượt xa Chu Tước lão Thánh Hoàng năm xưa"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người từng nghe lời nhắc","ghiChu":"Vương Lâm nhớ lại lời của ông khi thấy Viêm hỏa dị tinh."},{"ten":"Lão giả Ám Hạt Tộc hắc bào","tag":"khac","quanHe":"Liên hệ gián tiếp qua Viêm hỏa dị tinh","ghiChu":"Vật do lão giả Ám Hạt Tộc dâng lên khiến lời cũ của Chu Tước lão Thánh Hoàng được nhắc lại."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1286","@c1287","@c1310"]},{"id":"chu-tuoc-thanh-hoang-doi-thu-ba","name":"Chu Tước Thánh Hoàng đời thứ ba","gioiTinh":"nam","theLuc":[{"ten":"Chu Tước Thánh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Chu Tước Thánh Hoàng đời thứ ba là một đời Thánh Hoàng được nhắc trong lời hồi ức của Lỗ Vân. Sau biến cố Hành Văn tộc, người này cùng đời thứ tư đi tới giới ngoại rồi không còn tin tức.","vaiTro":"Đời Thánh Hoàng được nhắc lại","tinhCach":[{"text":"Gắn với lịch sử Chu Tước Thánh Tông","chuong":"@c1287"},{"text":"Hành tung về sau không rõ","chuong":"@c1287"}],"nguon":["@c1287"],"tabs":{"diem":[{"text":"Được nhắc là cùng Chu Tước Thánh Hoàng đời thứ tư đi tới giới ngoại sau trận chiến Hành Văn tộc.","chuong":"@c1287"}],"kinhLich":[{"chuong":"@c1287","importance":"bridge","mucCt":"gon","tieuDe":"Đi tới giới ngoại","text":"Chu Tước Thánh Hoàng đời thứ ba được nhắc là đã cùng đời thứ tư đi tới giới ngoại sau trận chiến Hành Văn tộc.","anchor":"Thánh Hoàng đời thứ ba và thứ tư đều đi tới giới ngoại"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước Thánh Hoàng đời thứ tư","tag":"dong-minh","quanHe":"Cùng đời Thánh Hoàng đi tới giới ngoại","ghiChu":"Hai người được nhắc chung trong hồi ức về lịch sử Chu Tước Thánh Tông."},{"ten":"Chu Tước lão Thánh Hoàng","tag":"khac","quanHe":"Được Lỗ Vân nhắc lại","ghiChu":"Lỗ Vân kể lại sự kiện các đời Thánh Hoàng đi tới giới ngoại."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"chu-tuoc-thanh-hoang-doi-thu-tu","name":"Chu Tước Thánh Hoàng đời thứ tư","gioiTinh":"nam","theLuc":[{"ten":"Chu Tước Thánh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Chu Tước Thánh Hoàng đời thứ tư là một đời Thánh Hoàng được Vương Lâm đặc biệt suy đoán có thể từng tới Điên Lạc. Dấu vết liên quan tới Viêm hỏa dị tinh khiến người này trở thành manh mối cho lần thức tỉnh thứ tư của Chu Tước.","vaiTro":"Manh mối Thánh Hoàng ở Điên Lạc","tinhCach":[{"text":"Gắn với bí mật Điên Lạc","chuong":"@c1287"},{"text":"Hành tung sau khi tới giới ngoại chưa rõ","chuong":"@c1287"}],"nguon":["@c1287","@c1302"],"tabs":{"diem":[{"text":"Được Vương Lâm suy đoán có thể từng đến Điên Lạc do Viêm hỏa dị tinh giống hòn đá trắng của Chu Tước Thánh Tông.","chuong":"@c1287"}],"kinhLich":[{"chuong":"@c1287","importance":"bridge","mucCt":"gon","tieuDe":"Manh mối tại Điên Lạc","text":"Chu Tước Thánh Hoàng đời thứ tư được Vương Lâm suy đoán có thể từng tới Điên Lạc, trở thành manh mối liên hệ giữa Viêm hỏa dị tinh và Chu Tước Thánh Tông.","anchor":"chẳng lẽ Thánh Hoàng đời thứ tư năm đó đã đi tới Điên Lạc này"},{"chuong":"@c1302","importance":"bridge","mucCt":"gon","tieuDe":"Được thân phận giả tìm","text":"Chu Tước đời thứ tư được nhắc là mục tiêu mà thân phận giả Chu Tước đời sáu tin rằng mình phải tới Thái Cổ Tinh Thần để tìm.","anchor":"tới Thái Cổ Tinh Thần để tìm Chu Tước đời thứ tư"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước Thánh Hoàng đời thứ ba","tag":"dong-minh","quanHe":"Cùng đời Thánh Hoàng đi tới giới ngoại","ghiChu":"Hai người được nhắc chung trong hồi ức về lịch sử Chu Tước Thánh Tông."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Được Vương Lâm suy đoán hành tung","ghiChu":"Vương Lâm dựa vào Viêm hỏa dị tinh để suy đoán về dấu vết của người này ở Điên Lạc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"con-roi-nam-tu-trung-nien-cua-am-hat-toc","name":"Con rối nam tử trung niên của Ám Hạt Tộc","gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tịnh Niết trung kỳ","trangThai":"tu-vong","blurb":"Con rối nam tử trung niên của Ám Hạt Tộc ban đầu trông như con rối bất động, nhưng bên trong còn dấu vết kinh mạch và nguyên thần. Vương Lâm xác nhận nó vốn là tu sĩ bị tế luyện, rồi con rối nổ tung khi tầng phòng hộ bị phá.","vaiTro":"Tu sĩ bị tế luyện thành con rối","tinhCach":[{"text":"Bị biến thành con rối, gần như không còn biểu hiện ý chí riêng","chuong":"@c1287"},{"text":"Thân thể ẩn nhiều bí mật tinh thể và nguyên thần","chuong":"@c1287"}],"nguon":["@c1287"],"tabs":{"diem":[{"text":"Thân thể không có huyết nhục mà do tinh thể kỳ dị cấu thành.","chuong":"@c1287"},{"text":"Bên trong còn kinh mạch khô héo và nguyên thần giống hệt bản thể.","chuong":"@c1287"}],"kinhLich":[{"mucCt":"vua","text":"Con rối nam tử trung niên của Ám Hạt Tộc bị Vương Lâm kiểm tra và phát hiện cơ thể không phải huyết nhục mà là tinh thể kỳ dị, lại còn có kinh mạch khô héo. Khi tầng phòng hộ bị lôi đồ và Định thân thuật phá vỡ, nguyên thần bên trong lộ ra trong khoảnh khắc rồi con rối nổ tung.","anchor":"Con rối này là một nam tử trung niên","bridge":true,"khoang":"@c1287"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm phá giải và hủy diệt","ghiChu":"Vương Lâm nghiên cứu thân thể, phá tầng phòng hộ và khiến con rối nổ tung."},{"ten":"Kiệt trưởng lão","tag":"khac","quanHe":"Con rối thuộc Ám Hạt Tộc","ghiChu":"Kiệt trưởng lão cảm nhận được khí tức quen thuộc khi con rối bị hủy."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Tinh thể trong thân con rối","trangThai":"hong","moTa":"Tinh thể thay thế huyết nhục trong thân con rối, được Vương Lâm liên hệ với tinh thể ở vết thương đầu lâu Cổ Thần.","nguon":"@c1287"}]}}},{"id":"toc-truong-long-giap-toc","name":"Tộc trưởng Long Giáp Tộc","aliases":["Trưởng lão thứ chín Lạc Sinh hội","Trưởng lão thứ chín của Lạc Sinh hội","Trưởng lão thứ chín – Tộc trưởng Long Giáp tộc","Tôn đạo hữu"],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"},{"ten":"Lạc Sinh hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Tứ Suy @c1294","trangThai":"song","blurb":"Tộc trưởng Long Giáp Tộc, đồng thời là trưởng lão thứ chín họ Tôn của Lạc Sinh hội, là người quen cũ được Tư Mặc Tử nhắm tới để mượn thân phận hành sự tại Điên Lạc. Ông nghênh đón và trợ giúp Tư Mặc Tử, xuất một vạn Băng long đan cùng bàn tính với con trai về lai lịch Vương Lâm. Khi Vương Lâm tìm tới trả thù vì việc từng giúp Tư Mặc Tử, ông bị tước bỏ vị trí trưởng lão, và khi biết Vương Lâm đã là thiếu đế thì kinh hãi cầu xin tha cho nhi tử độc nhất.","vaiTro":"Tộc trưởng Long Giáp Tộc — trưởng lão thứ chín Lạc Sinh hội, họ Tôn","tinhCach":"thận trọng, hay dò xét tình thế qua thần thức; toan tính lợi hại, sẵn sàng liên minh khi có lợi; khi lâm nguy thì hoảng sợ, cầu xin để bảo toàn nhi tử","nguon":["@c1287","@c1288","@c1289","@c1290","@c1291","@c1292","@c1293","@c1294"],"tabs":{"diem":[{"text":"Tộc trưởng Long Giáp Tộc, kiêm trưởng lão thứ chín họ Tôn của Lạc Sinh hội, tu vi Thiên Nhân Đệ Tứ Suy","chuong":"@c1288"},{"text":"Là người quen cũ được Tư Mặc Tử nhắm tới để mượn thân phận hành sự tại Điên Lạc","chuong":"@c1287"},{"text":"Xuất ra một vạn Băng long đan theo phân phó, nghênh đón và trợ giúp Tư Mặc Tử","chuong":"@c1289"},{"text":"Dùng thần thức theo dõi trận chiến, ban đầu không tin Vương Lâm có thể kết thúc nhanh chóng","chuong":"@c1292"},{"text":"Bị Vương Lâm tìm tới trả thù vì từng giúp Tư Mặc Tử và bị tước bỏ vị trí trưởng lão","chuong":"@c1293"},{"text":"Kinh hãi khi biết Vương Lâm đã là thiếu đế, cầu xin tha cho nhi tử độc nhất","chuong":"@c1294"}],"kinhLich":[{"chuong":"@c1287","importance":"bridge","mucCt":"gon","tieuDe":"Được Tư Mặc Tử nhắm tới","text":"Tộc trưởng Long Giáp Tộc được Tư Mặc Tử nhắc là người quen cũ tại Điên Lạc, có thể giúp hắn mượn thân phận Long Giáp Tộc để hành động.","anchor":"cùng với trưởng lão thứ chín – Tộc trưởng Long Giáp tộc có quen biết"},{"mucCt":"vua","text":"Tộc trưởng Long Giáp Tộc, đồng thời là trưởng lão thứ chín Lạc Sinh hội họ Tôn, bay ra nghênh đón Tư Mặc Tử trên chủ tinh. Ông nhắc ân chỉ điểm năm xưa giúp mình vượt qua tam suy và mời Tư Mặc Tử tới động phủ.","anchor":"Hắn thân là trưởng lão thứ chính của Lạc Sinh hội, bình thường không hỏi thế sự","bridge":true,"khoang":"@c1288"},{"mucCt":"vua","anchor":"tộc trưởng Long Giáp Tộc và Tư Mặc Tử đang ngồi","text":"Tộc trưởng Long Giáp Tộc ở thánh địa nghe thiếu tộc trưởng báo đã xuất ra một vạn Băng long đan theo phân phó. Sau đó hắn đổi trắng thay đen nói Vương Lâm cướp đan của Long Giáp Tộc, dùng cớ này mời Tư Mặc Tử hỗ trợ bắt giết Vương Lâm.","bridge":true,"khoang":"@c1289"},{"mucCt":"vua","text":"Sau khi Tư Mặc Tử rời đại điện, tộc trưởng Long Giáp Tộc ở lại bàn với con trai, xác định Vương Lâm rất có thể là kẻ hủy Thiểm Lôi tộc và bị Trường Tôn hội truy đuổi. Ông ta quyết định hỗ trợ Tư Mặc Tử, cho rằng Vương Lâm không phải bước thứ ba, dù có biến cố cũng sẽ chết hoặc trọng thương, và tin thân phận trưởng lão thứ chín Lạc Sinh hội đủ khiến Vương Lâm không dám gây phiền toái cho Long Giáp Tộc.","anchor":"Tộc trưởng Long Giáp Tộc - Trưởng lão thứ chín của Lạc Sinh hội âm trầm mở miệng nói","bridge":true,"khoang":"@c1290"},{"chuong":"@c1291","importance":"normal","mucCt":"vua","tieuDe":"Lo họa trả thù","text":"Tộc trưởng Long Giáp Tộc quan sát trận chiến từ thánh địa, cho rằng Tư Mặc Tử là tu sĩ bước thứ ba nên Vương Lâm không còn sinh cơ. Ông cũng lo nếu Vương Lâm sống sót thì Long Giáp Tộc sẽ bị trả thù vì từng giúp Tư Mặc Tử.","anchor":"Tộc trưởng Long Giáp Tộc cũng biến sắc"},{"chuong":"@c1292","importance":"bridge","mucCt":"vua","tieuDe":"Quan sát biến sắc","text":"Tộc trưởng Long Giáp Tộc dùng thần thức theo dõi trận chiến, ban đầu không tin Vương Lâm có thể kết thúc trong năm nhịp thở và biến sắc khi thấy Viêm hỏa dị tinh bị kích nổ nối tiếp vụ nổ đan dược.","anchor":"Tộc trưởng Long Giáp Tộc đang dùng thần thức quan sát trận chiến không chớp mắt"},{"chuong":"@c1293","importance":"normal","mucCt":"ky","tieuDe":"Bị tước trưởng lão","text":"Tộc trưởng Long Giáp Tộc bị Vương Lâm tìm tới vì từng giúp Tư Mặc Tử, liền ra lệnh cho tộc nhân bước thứ hai ngăn cản. Khi hắn dùng thân phận trưởng lão thứ chín Lạc Sinh hội do đại đế chỉ định để uy hiếp, sứ giả của đại đế lại tuyên khẩu dụ tước tư cách ấy và ban Độc mệnh đan buộc hắn nuốt ngay.","anchor":"Ta chính là trưởng lão thứ chính của Lạc Sinh hội, do chính đại đế tự mình chỉ định"},{"mucCt":"ky","text":"Tộc trưởng Long Giáp Tộc kinh hãi khi biết Vương Lâm đã là thiếu đế, liền cầu xin tha cho nhi tử độc nhất. Hắn tự tay phế sạch kinh mạch, đánh nát nguyên thần và tu vi của con, khiến Thiếu tộc trưởng mất hết khả năng tu luyện nhưng được Vương Lâm gật đầu tha mạng. Sau đó hắn nuốt độc đan do sứ giả mang tới, bị hắc hỏa thiêu rụi nguyên thần, huyết nhục và xương cốt, chết không còn cặn bã.","anchor":"trực tiếp phế bỏ kinh mạch toàn thân hắn, đánh nát nguyên thần, khiến cho tu vi hắn trong nháy mắt mất sạch","bridge":true,"khoang":"@c1294"}],"tuViMoc":[{"chuong":"@c1288","canhGioi":"Thiên Nhân Đệ Tứ Suy","text":"Chương này nêu khí tức và vị thế của tộc trưởng Long Giáp Tộc ở mức Thiên Nhân Đệ Tứ Suy.","importance":"major"}],"nhanMach":[{"ten":"Tư Mặc Tử","tag":"dong-minh","quanHe":"Người quen cũ","ghiChu":"Tư Mặc Tử định lợi dụng quan hệ này để mượn thân phận Long Giáp Tộc."},{"ten":"Tư Mặc Tử","tag":"an-nhan","quanHe":"tiền bối từng chỉ điểm","ghiChu":"Từng được Tư Mặc Tử chỉ điểm nên thoát chết trong tam suy."},{"ten":"Vương Lâm","tag":"khac","quanHe":"khách tới chủ tinh","ghiChu":"Chủ tinh của ông là nơi Vương Lâm tới tìm mua Viêm hỏa dị tinh và con rối."},{"ten":"Thiếu tộc trưởng Long Giáp Tộc","tag":"cha-me","quanHe":"con trai và người chấp hành phân phó","ghiChu":"Thiếu tộc trưởng báo với hắn rằng một vạn Băng long đan đã được giao ra theo lệnh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"mục tiêu bị vu cướp đan","ghiChu":"Hắn gọi giao dịch một vạn Băng long đan là bị Vương Lâm cướp để hợp thức hóa việc bắt giết."},{"ten":"Điên Lạc đại đế","tag":"khac","quanHe":"Uy danh khiến tộc trưởng biến sắc kinh hô.","ghiChu":"Khi tiếng nói từ hư vô vang lên, tộc trưởng nhận ra danh xưng Đại đế."},{"ten":"Điên Lạc đại đế","tag":"cap-tren","quanHe":"Từng giữ thân phận trưởng lão do đại đế chỉ định nhưng bị khẩu dụ tước bỏ.","ghiChu":"Bị xử phạt tại @c1293."},{"ten":"Nam tử trung niên hồng sam","tag":"doi-thu","quanHe":"Bị sứ giả đại đế tuyên khẩu dụ tước chức và ban Độc mệnh đan.","ghiChu":"Đối mặt tại @c1293."},{"ten":"Nam tử trung niên hồng sam","tag":"khac","quanHe":"Sứ giả đại đế mang độc đan và khẩu dụ tới xử trí hắn.","ghiChu":"Người trực tiếp đưa độc đan @c1294"},{"ten":"Thiếu tộc trưởng Long Giáp Tộc","tag":"ho-hang","quanHe":"thiếu tộc trưởng cùng tộc","ghiChu":"Cùng ở thánh địa quan sát trận chiến."},{"ten":"Trưởng lão thứ chín của Lạc Sinh hội","tag":"khac","quanHe":"người cùng có mặt tại thánh địa","ghiChu":"Cùng xuất hiện khi tiếng nói Đại đế vang lên."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"truong-lao-lac-sinh-hoi-gan-nhat","name":"Trưởng lão Lạc Sinh hội gần nhất","gioiTinh":"khong-ro","theLuc":[{"ten":"Lạc Sinh hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Trưởng lão Lạc Sinh hội gần nhất là mục tiêu tiếp theo mà Vương Lâm muốn tìm tại Điên Lạc. Người này chưa trực tiếp xuất hiện trong chương, nhưng nơi sinh sống đã trở thành điểm đến kế tiếp của Vương Lâm.","vaiTro":"Mục tiêu tiếp xúc của Vương Lâm","tinhCach":[{"text":"Chưa lộ diện trực tiếp","chuong":"@c1287"},{"text":"Có địa bàn riêng trên một tu chân tinh gần đó","chuong":"@c1287"}],"nguon":["@c1287"],"tabs":{"diem":[{"text":"Được Vương Lâm yêu cầu Kiệt trưởng lão dẫn tới nơi sinh sống.","chuong":"@c1287"}],"kinhLich":[{"chuong":"@c1287","importance":"bridge","mucCt":"gon","tieuDe":"Trở thành điểm đến","text":"Trưởng lão Lạc Sinh hội gần nhất trở thành mục tiêu tiếp theo khi Vương Lâm yêu cầu Kiệt trưởng lão dẫn đường tới tu chân tinh nơi người này sinh sống.","anchor":"đi tới tu chân tinh của trưởng lão Lạc Sinh hội sinh sống gần nhất"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Được Vương Lâm tìm tới","ghiChu":"Vương Lâm rời động phủ và chuyển mục tiêu sang nơi người này sinh sống."},{"ten":"Kiệt trưởng lão","tag":"khac","quanHe":"Được Kiệt trưởng lão dẫn đường tới","ghiChu":"Kiệt trưởng lão phụ trách dẫn Vương Lâm tới tu chân tinh của người này."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"lao-gia-thanh-sam-long-giap-toc","name":"Lão giả thanh sam Long Giáp Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1288","trangThai":"song","blurb":"Tu sĩ Long Giáp Tộc ra nghênh đón đoàn Ám Hạt Tộc trên chủ tinh Long Giáp. Ông là người dẫn đầu trong ba tu sĩ tiếp khách và sớm chú ý thân phận bất thường của Vương Lâm.","vaiTro":"tu sĩ tiếp đón Long Giáp Tộc","tinhCach":[{"text":"cẩn trọng quan sát người lạ","chuong":"@c1288"},{"text":"giữ lễ với khách Ám Hạt Tộc","chuong":"@c1288"}],"tabs":{"diem":[{"text":"Dẫn đầu ba tu sĩ Long Giáp Tộc ra đón tộc trưởng Ám Hạt Tộc theo lệnh trưởng lão.","chuong":"@c1288"},{"text":"Nhận ra thái độ kính cẩn của tộc trưởng Ám Hạt Tộc với Vương Lâm và không dám xem thường hắn.","chuong":"@c1288"}],"kinhLich":[{"mucCt":"vua","text":"Lão giả thanh sam cùng hai tu sĩ Long Giáp Tộc chờ sẵn để nghênh đón tộc trưởng Ám Hạt Tộc. Khi thấy tộc trưởng Ám Hạt Tộc nhường Vương Lâm đi trước, ông âm thầm đánh giá và nhận định người này không thể xem thường.","anchor":"Nhất là lão giả đi trước, ánh mắt liền lóe lên, cẩn thận đánh giá Vương Lâm vài lân","bridge":true,"khoang":"@c1288"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"khách được chú ý","ghiChu":"Chú ý Vương Lâm vì thấy tộc trưởng Ám Hạt Tộc kính cẩn với hắn."},{"ten":"Kiệt trưởng lão","tag":"khac","quanHe":"khách được nghênh đón","ghiChu":"Ra đón tộc trưởng Ám Hạt Tộc theo lệnh trưởng lão Long Giáp Tộc."},{"ten":"Hai tu sĩ Long Giáp Tộc đi cùng lão giả thanh sam","tag":"dong-minh","quanHe":"đồng tộc cùng tiếp đón","ghiChu":"Cùng ra đón đoàn Ám Hạt Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1288"]},{"id":"hai-tu-si-long-giap-toc-di-cung-lao-gia-thanh-sam","name":"Hai tu sĩ Long Giáp Tộc đi cùng lão giả thanh sam","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1288","trangThai":"song","blurb":"Hai tu sĩ Long Giáp Tộc đi cùng lão giả thanh sam ra nghênh đón đoàn Ám Hạt Tộc. Họ giữ thái độ khách khí và dẫn khách vào chủ tinh Long Giáp Tộc.","vaiTro":"tu sĩ tiếp khách Long Giáp Tộc","tinhCach":[{"text":"khách khí khi tiếp khách","chuong":"@c1288"},{"text":"tuân theo sắp đặt của trưởng lão","chuong":"@c1288"}],"tabs":{"diem":[{"text":"Cùng lão giả thanh sam tiếp đón tộc trưởng Ám Hạt Tộc ở ngoài chủ tinh Long Giáp Tộc.","chuong":"@c1288"}],"kinhLich":[{"mucCt":"gon","text":"Hai tu sĩ Long Giáp Tộc cùng lão giả thanh sam ôm quyền tiếp đón tộc trưởng Ám Hạt Tộc và dẫn đoàn vào chủ tinh.","anchor":"Hai người phía sau lão giả đều ôm quyền, nói năng cực kỳ khách khí.","bridge":true,"khoang":"@c1288"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão giả thanh sam Long Giáp Tộc","tag":"dong-minh","quanHe":"đồng tộc cùng tiếp đón","ghiChu":"Cùng lão giả thanh sam ra nghênh đón đoàn Ám Hạt Tộc."},{"ten":"Kiệt trưởng lão","tag":"khac","quanHe":"khách được nghênh đón","ghiChu":"Cùng ôm quyền tiếp đón tộc trưởng Ám Hạt Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1288"]},{"id":"nu-tu-quan-su-lau-cac-long-giap-toc","name":"Nữ tử quản sự lầu các Long Giáp Tộc","cn":"","aliases":["Nữ tử quyến rũ"],"gioiTinh":"nu","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1288","trangThai":"song","blurb":"Nữ quản sự của lầu các cửa hàng Long Giáp Tộc tại phường thị phía đông. Nàng tiếp đón Vương Lâm và nhận ra thái độ bất thường của tộc trưởng Ám Hạt Tộc đối với hắn.","vaiTro":"quản sự cửa hàng Long Giáp Tộc","tinhCach":[{"text":"nhạy bén quan sát thân phận khách","chuong":"@c1288"},{"text":"giữ lễ trong giao dịch","chuong":"@c1288"}],"tabs":{"diem":[{"text":"Tiếp Vương Lâm ở lầu hai cửa hàng Long Giáp Tộc và hỏi hắn cần mua vật gì.","chuong":"@c1288"},{"text":"Kinh ngạc khi thấy tộc trưởng Ám Hạt Tộc đứng sau Vương Lâm mà không dám ngồi.","chuong":"@c1288"}],"kinhLich":[{"mucCt":"vua","text":"Nữ tử quản sự tiếp đón Vương Lâm và tộc trưởng Ám Hạt Tộc tại lầu các phường thị phía đông. Nàng nhận ra tộc trưởng Ám Hạt Tộc đứng sau Vương Lâm không dám ngồi nên kinh ngạc, rồi hỏi Vương Lâm muốn mua gì.","anchor":"Nữ tử thấy cảnh này trong ánh mắt lại hiện lên vẻ kinh ngạc","bridge":true,"khoang":"@c1288"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"khách mua Viêm hỏa dị tinh","ghiChu":"Tiếp đón Vương Lâm khi hắn hỏi mua Viêm hỏa dị tinh."},{"ten":"Kiệt trưởng lão","tag":"khac","quanHe":"khách quen từ Ám Hạt Tộc","ghiChu":"Kinh ngạc vì thấy tộc trưởng Ám Hạt Tộc đứng sau Vương Lâm không dám ngồi."},{"ten":"Lão giả Hỏa Tước tộc","tag":"khac","quanHe":"khách tranh mua","ghiChu":"Có mặt khi lão giả Hỏa Tước tộc bước lên lầu hai đòi mua Viêm hỏa dị tinh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1288"]},{"id":"lao-gia-hoa-tuoc-toc","name":"Lão giả Hỏa Tước tộc","cn":"","aliases":["Lão giả áo đỏ Hỏa Tước tộc","Hà đạo hữu"],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1288","trangThai":"song","blurb":"Lão giả áo đỏ tóc bạc của Hỏa Tước tộc, thân mang khí tức biển lửa và mi tâm có ấn ký ngọn lửa. Ông xuất hiện tại lầu các Long Giáp Tộc đúng lúc Vương Lâm hỏi mua Viêm hỏa dị tinh.","vaiTro":"tu sĩ Hỏa Tước tộc tranh mua dị tinh","tinhCach":[{"text":"trực tiếp tranh mua vật cần thiết","chuong":"@c1288"},{"text":"khí thế hỏa hệ rõ rệt","chuong":"@c1288"}],"tabs":{"diem":[{"text":"Thân như chứa biển lửa, bước chân để lại vết lửa và mi tâm có ấn ký ngọn lửa.","chuong":"@c1288"},{"text":"Tuyên bố cũng muốn mua Viêm hỏa dị tinh và yêu cầu Vương Lâm nhường.","chuong":"@c1288"},{"text":"Có thân phận thủ lĩnh phân tộc Hỏa Tước tộc ở vùng đất Điên Lạc và tu vi thiên nhân đệ tam suy.","chuong":"@c1289"},{"text":"Bị Vương Lâm dùng một tiếng hừ, gió vô tình và ánh mắt trấn áp đến phun máu, phải đổi sang tự xưng vãn bối.","chuong":"@c1289"},{"text":"Phát hiện hồn đan của Vương Lâm chứa hỏa bổn nguyên và về sau luyện đan để tìm ra giọt máu bí ẩn.","chuong":"@c1289"}],"kinhLich":[{"mucCt":"vua","text":"Lão giả Hỏa Tước tộc bước lên lầu hai cửa hàng Long Giáp Tộc ngay sau khi Vương Lâm hỏi mua Viêm hỏa dị tinh. Ông mang khí tức biển lửa, có ấn ký ngọn lửa ở mi tâm, tuyên bố cũng muốn mua vật này và bảo Vương Lâm nhường lại.","anchor":"Ở mi tâm người này không ngờ có ấn ký ngọn lửa!","bridge":true,"khoang":"@c1288"},{"mucCt":"ky","anchor":"là tộc nhân của đại tộc Hỏa Tước tộc của Thái Cổ Tinh Thần","text":"Lão giả Hỏa Tước tộc lên lầu hai để xin Vương Lâm nhường Viêm hỏa dị tinh, nhưng vừa tự xưng lão phu đã bị tiếng hừ và ánh mắt của Vương Lâm trấn áp đến phun máu, nguyên thần chấn động và phải tự xưng vãn bối. Khi phát hiện hồn đan có một tia hỏa bổn nguyên, hắn âm thầm theo Vương Lâm, dùng một trăm Viêm Hỏa dị tinh đổi một trăm hồn đan. Cuối chương, hắn cùng tộc nhân luyện tan hồn đan và phát hiện khí tức bổn nguyên đến từ một giọt máu đỏ đậm bí ẩn.","bridge":true,"khoang":"@c1289"},{"chuong":"@c1291","importance":"normal","mucCt":"vua","tieuDe":"Quan sát Phá Thiên","text":"Lão giả Hỏa Tước tộc dùng thần thức quan sát trận chiến, ban đầu cho rằng Vương Lâm khó sống dưới Phá Thiên Đạo. Khi Vương Lâm phá vây lao ra, lão mở bừng mắt và không tin nổi.","anchor":"lão giả Hỏa Tước tộc thần thức cũng đã sớm tản ra quan sát"},{"chuong":"@c1292","importance":"bridge","mucCt":"gon","tieuDe":"Không tin năm nhịp","text":"Lão giả Hỏa Tước tộc được nêu trong nhóm người không tin trận chiến với Tư Mặc Tử có thể kết thúc trong năm nhịp thở.","anchor":"dù là tộc trưởng Long Giáp Tộc hay là lão giả Hỏa Tước tộc hoặc Tư Mặc Tử cũng không tin tưởng"}],"tuViMoc":[{"chuong":"@c1289","canhGioi":"Thiên nhân đệ tam suy","text":"Lão giả Hỏa Tước tộc được xác nhận có tu vi thiên nhân đệ tam suy khi xuất hiện tại lầu giao dịch của Long Giáp Tộc.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"người tranh mua Viêm hỏa dị tinh","ghiChu":"Yêu cầu Vương Lâm nhường Viêm hỏa dị tinh trong cửa hàng Long Giáp Tộc."},{"ten":"Nữ tử quản sự lầu các Long Giáp Tộc","tag":"khac","quanHe":"người tiếp quản cửa hàng","ghiChu":"Xuất hiện tại lầu các nơi nữ tử quản sự đang tiếp Vương Lâm."},{"ten":"Thiếu chủ Ám Hạt Tộc","tag":"khac","quanHe":"người khiến hắn kiêng dè Vương Lâm","ghiChu":"Hắn nhận ra tộc trưởng Ám Hạt Tộc đứng sau Vương Lâm như người hầu nên càng cảnh giác."},{"ten":"Nữ tử quyến rũ Long Giáp Tộc","tag":"khac","quanHe":"người cùng có mặt tại giao dịch","ghiChu":"Cả hai cùng chứng kiến Vương Lâm dùng hồn đan đổi Viêm hỏa dị tinh trong lầu giao dịch."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người bị quan sát","ghiChu":"Lão theo dõi trận chiến và kinh ngạc khi Vương Lâm phá được Phá Thiên Đạo."},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"người bị quan sát","ghiChu":"Lão nhận định thần thông của Tư Mặc Tử quá mạnh khiến Vương Lâm khó còn sinh cơ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Viêm hỏa dị tinh","loai":"dị vật hỏa hệ","trangThai":"dang-tranh-mua","moTa":"Lão giả Hỏa Tước tộc tuyên bố cũng muốn mua Viêm hỏa dị tinh.","nguon":"@c1288"}],"linhThao":[],"khac":[]}},"nguon":["@c1288","@c1289","@c1291","@c1292"]},{"id":"nu-tu-quyen-ru-long-giap-toc","name":"Nữ tử quyến rũ Long Giáp Tộc","cn":"","aliases":["Triệu đạo hữu"],"gioiTinh":"nu","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Nữ tu phụ trách giao dịch trong lầu các Long Giáp Tộc. Nàng tiếp xúc trực tiếp với Vương Lâm trong giao dịch Viêm hỏa dị tinh và hồn đan.","vaiTro":"Người quản giao dịch tại lầu các Long Giáp Tộc, phụ trách mở cơ chế trưng hàng và báo việc hồn đan lên cấp trên.","tinhCach":[{"text":"Giữ lễ và thận trọng khi đối diện khách mạnh, lập tức báo lên khi nhận ra giá trị hồn đan.","chuong":"@c1289"}],"tabs":{"diem":[{"text":"Dùng ngọc giản mở vách tường chiết xạ để hiển lộ ba khối Viêm hỏa dị tinh trong lầu giao dịch.","chuong":"@c1289"},{"text":"Nhận ra hồn đan chế từ hỏa thú đỉnh cấp và báo lên khiến thiếu tộc trưởng Long Giáp Tộc xuất hiện.","chuong":"@c1289"}],"kinhLich":[{"mucCt":"vua","anchor":"Nữ tử quyến rũ kia cúi đầu nhẹ giọng nói","text":"Nữ tử quyến rũ Long Giáp Tộc tiếp Vương Lâm trong lầu giao dịch, chịu uy áp từ tiếng hừ của hắn và mở vách tường trưng ra ba khối Viêm hỏa dị tinh. Nàng nhận ba viên hồn đan chế từ hỏa thú đỉnh cấp, báo lên cấp trên và dẫn đến việc thiếu tộc trưởng Long Giáp Tộc đích thân xuất hiện.","bridge":true,"khoang":"@c1289"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"khách giao dịch","ghiChu":"Nàng giao dịch ba khối Viêm hỏa dị tinh với Vương Lâm bằng hồn đan."},{"ten":"Lão giả Hỏa Tước tộc","tag":"khac","quanHe":"người cùng có mặt tại giao dịch","ghiChu":"Lão giả Hỏa Tước tộc có mặt khi nàng tiếp Vương Lâm và nhìn thấy hồn đan."},{"ten":"Thiếu tộc trưởng Long Giáp Tộc","tag":"cap-tren","quanHe":"cấp trên trong Long Giáp Tộc","ghiChu":"Việc nàng báo lên khiến thiếu tộc trưởng Long Giáp Tộc đến lầu giao dịch."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Hồn đan hỏa thú đỉnh cấp","loai":"đan dược giao dịch","trangThai":"da-dung","moTa":"Nàng nhận ba viên hồn đan từ Vương Lâm để đổi ba khối Viêm hỏa dị tinh cho Long Giáp Tộc.","nguon":"@c1289"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Ngọc giản giao dịch","loai":"vật phẩm điều khiển","trangThai":"dang-co","moTa":"Ngọc giản phát thanh quang được nàng dùng để mở cơ chế vách tường trong lầu các, hiển lộ Viêm hỏa dị tinh.","nguon":"@c1289"}]}},"nguon":["@c1289"]},{"id":"thieu-toc-truong-long-giap-toc","name":"Thiếu tộc trưởng Long Giáp Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đã mất tu vi @c1294","trangThai":"song","blurb":"Nam tử trung niên tóc tím, thiếu tộc trưởng Long Giáp Tộc. Hắn ra mặt tại lầu giao dịch để giới thiệu tam bảo và giao dịch Băng long đan cùng Viêm hỏa dị tinh với Vương Lâm theo phân phó của phụ thân. Về sau bị chính cha phế bỏ kinh mạch và nguyên thần trong biến cố đổi mạng, mất sạch tu vi.","vaiTro":"Thiếu tộc trưởng Long Giáp Tộc — người đại diện tộc ra mặt giao dịch với Vương Lâm","tinhCach":"Cẩn trọng, hành sự theo phân phó của phụ thân; dễ hoảng sợ trước cường giả","tabs":{"diem":[{"text":"Xuất hiện tại lầu giao dịch, giao ba khối Viêm hỏa dị tinh cho Vương Lâm","chuong":"@c1289"},{"text":"Thưa với phụ thân về tu sĩ ẩn ở vùng đất Điên Lạc sau khi Tư Mặc Tử rời đi","chuong":"@c1290"},{"text":"Dùng thần thức quan sát Vương Lâm từ thánh địa trong sự kiện chấn động phá vây","chuong":"@c1291"},{"text":"Hoảng sợ rồi mừng rỡ khi Vương Lâm kéo tới bên phụ thân","chuong":"@c1293"},{"text":"Bị chính cha dùng nguyên lực phế sạch kinh mạch và nguyên thần, mất toàn bộ tu vi","chuong":"@c1294"}],"kinhLich":[{"mucCt":"vua","anchor":"Là thiếu tộc trưởng Long Giáp Tộc","text":"Thiếu tộc trưởng Long Giáp Tộc xuất hiện tại lầu giao dịch, giao ba khối Viêm hỏa dị tinh cho Vương Lâm và giới thiệu tam bảo của tộc. Hắn đồng ý dùng một vạn Băng long đan đổi lấy một trăm hồn đan, rồi về thánh địa báo với phụ thân rằng đã làm theo phân phó.","bridge":true,"khoang":"@c1289"},{"mucCt":"gon","text":"Sau khi Tư Mặc Tử rời đi, thiếu tộc trưởng Long Giáp Tộc thưa với phụ thân rằng tu sĩ ẩn ở vùng đất Điên Lạc có tu vi cao thâm và tiếp tục lo Tư Mặc Tử có thể thất bại.","anchor":"Thiếu tộc trưởng Long Giáp Tộc hơi do dự thấp giọng nói","bridge":true,"khoang":"@c1290"},{"chuong":"@c1291","importance":"normal","mucCt":"vua","tieuDe":"Chấn động phá vây","text":"Thiếu tộc trưởng Long Giáp Tộc ở thánh địa dùng thần thức quan sát, ban đầu thở phào vì tưởng Vương Lâm không thoát được Phá Thiên Đạo. Khi Vương Lâm lao ra, hắn chấn động, lùi lại mấy bước và thất thanh.","anchor":"Thiếu tộc trưởng Long Giáp Tộc tâm thần cũng chấn động"},{"chuong":"@c1293","importance":"bridge","mucCt":"vua","tieuDe":"Hoảng trước Vương Lâm","text":"Thiếu tộc trưởng Long Giáp Tộc ở cạnh phụ thân khi Vương Lâm kéo tới, ban đầu hoảng sợ lui lại rồi mừng rỡ khi thấy kiếm quang sứ giả đại đế xuất hiện.","anchor":"Thiếu tộc trưởng Long Giáp Tộc sắc mặt trắng bệch, theo tiềm thức lui lại phía sau vài bước"},{"chuong":"@c1294","importance":"major","mucCt":"vua","tieuDe":"Bị phế đổi mạng","text":"Thiếu tộc trưởng Long Giáp Tộc bị chính cha dùng nguyên lực đánh vào thân thể, phế sạch kinh mạch và nguyên thần. Hắn mất hết tu vi, hôn mê trong đau đớn, nhưng nhờ vậy được Vương Lâm tha mạng.","anchor":"Sự đau đớn từ trong cơ thể Thiếu tộc trưởng Long Giáp Tộc điên cuồng truyền ra"}],"tuViMoc":[{"chuong":"@c1294","canhGioi":"Đã mất tu vi","text":"Bị tộc trưởng Long Giáp Tộc phế bỏ kinh mạch, đánh nát nguyên thần, tu vi trong nháy mắt mất sạch; đây là mốc mất tu vi, không phải đột phá.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"đối tượng giao dịch","ghiChu":"Hắn đổi một vạn Băng long đan của Long Giáp Tộc lấy một trăm hồn đan của Vương Lâm."},{"ten":"Nữ tử quyến rũ Long Giáp Tộc","tag":"cap-tren","quanHe":"cấp trên trong giao dịch","ghiChu":"Hắn đến lầu sau khi giao dịch hồn đan được báo lên."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"cha-me","quanHe":"phụ thân và tộc trưởng","ghiChu":"Hắn báo với phụ thân rằng đã xuất ra một vạn Băng long đan theo phân phó."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mối nguy được nhắc tới","ghiChu":"Hắn lo ngại tu sĩ ẩn ở vùng đất Điên Lạc không phải người tầm thường."},{"ten":"Tư Mặc Tử","tag":"dong-minh","quanHe":"Người được kỳ vọng đối phó Vương Lâm","ghiChu":"Hắn vẫn lo Tư Mặc Tử có thể thất bại trước Vương Lâm."},{"ten":"Nam tử trung niên hồng sam","tag":"khac","quanHe":"Tưởng sứ giả đại đế xuất hiện sẽ giải vây cho Long Giáp Tộc.","ghiChu":"Chứng kiến tại @c1293."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"ho-hang","quanHe":"tộc trưởng cùng tộc","ghiChu":"Cùng ở thánh địa Long Giáp Tộc quan sát trận chiến."},{"ten":"Trưởng lão thứ chín của Lạc Sinh hội","tag":"khac","quanHe":"người cùng có mặt tại thánh địa","ghiChu":"Cùng xuất hiện trong thánh địa khi tiếng nói Đại đế vang lên."}],"tuiDo":{"phapBao":[{"ten":"Băng long đan","loai":"đan dược nổ/pháp bảo tiêu hao","trangThai":"da-dung","moTa":"Hắn giao một vạn Băng long đan cho Vương Lâm để đổi lấy một trăm hồn đan theo kế hoạch của Long Giáp Tộc.","nguon":"@c1289"},{"ten":"Long Giáp Tộc lân","loai":"bảo vật phòng hộ","trangThai":"dang-co","moTa":"Bảo vật thứ nhất trong tam bảo Long Giáp Tộc mà hắn giới thiệu, có thể tăng phòng hộ gấp bội.","nguon":"@c1289"},{"ten":"Bạch cốt long","loai":"bảo vật hài cốt","trangThai":"dang-co","moTa":"Bảo vật thứ hai trong tam bảo Long Giáp Tộc, do hài cốt tộc nhân xưa luyện hóa thành.","nguon":"@c1289"}],"danDuoc":[{"ten":"Hồn đan hỏa thú đỉnh cấp","loai":"đan dược giao dịch","trangThai":"dang-co","moTa":"Hắn nhận một trăm hồn đan từ Vương Lâm khi giao dịch Băng long đan.","nguon":"@c1289"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1289","@c1290","@c1291","@c1293","@c1294"]},{"id":"tham-lang","name":"Tham Lang","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ @c1299","trangThai":"song","blurb":"Tham Lang là lão tu sĩ từng cư ngụ Chu Tước Tinh hơn vạn năm, về sau lưu lạc qua Đại La Kiếm Tông, La Thiên Tinh Vực, vùng đất Điên Lạc và Tiên Cương. Hắn nhiều lần vì tham bảo mà rơi vào hiểm địa, mất pháp bảo hoặc bị Vương Lâm truy đuổi, nhưng vẫn sống sót nhờ nhiều thủ đoạn bảo mệnh. Về sau Tham Lang được xác nhận là phách thứ tư màu vàng của Thất Thải Tiên Tôn, đại biểu khí vận và cơ duyên cả đời.","vaiTro":"Lão tu sĩ lưu lạc — phách thứ tư của Thất Thải Tiên Tôn","tinhCach":"Tham bảo liều thân; tàn bạo cưỡng ép Văn thú; giỏi bỏ chạy giữ mạng; sợ hãi Vương Lâm","mucCt":"vua","tabs":{"diem":[{"text":"Từng đạt Âm Hư chi cảnh, vượt trên Vấn Đỉnh và chỉ kém Dương Thật.","chuong":"@c0571"},{"text":"Khống chế Văn thú đầu đàn bằng Thất Ma Châm, dùng bầy Văn thú vây khốn Đại La Kiếm Tông.","chuong":"@c0602"},{"text":"Vì tham bảo vào Vân Hà Tinh đào Kim Viêm quáng mạch, chạm tới Nguyệt Hoa nên bị Vọng Nguyệt nuốt vào và mắc kẹt.","chuong":"@c0668"},{"text":"Thoát khỏi lạc ấn sau biến cố Vọng Nguyệt, rơi xuống một tinh cầu nguyên thủy trong tình trạng thân thể vỡ nát, nguyên thần bị thương.","chuong":"@c0674"},{"text":"Ở vùng đất Điên Lạc trở thành đại cung phụng nổi danh, nhờ lai lịch thần bí và số lượng pháp bảo lớn; sau đó đạt Toái Niết trung kỳ nhờ được Điên Lạc đại đế ban đan dược.","chuong":"@c1295"},{"text":"Được xác nhận là phách thứ tư màu vàng của Thất Thải Tiên Tôn, phách đại biểu khí vận và cơ duyên cả đời.","chuong":"@c1650"}],"kinhLich":[{"mucCt":"vua","text":"Tham Lang đang tự đắc về thuật bỏ chạy thì bất ngờ bị huyết quang kinh thiên xuyên qua thân thể, đánh trọng thương, làm lộ áo giáp ẩn giấu, chấn bay huyết kiếm và buộc hắn dùng hai ma ảnh hóa thành gió lốc đen bỏ chạy. Vì trọng thương, hắn không còn điều khiển được phiến lá phong ấn, tạo cơ hội để Vương Lâm thoát ra và nắm lấy phiến lá.","anchor":"Một tiếng hét thảm thiết vang lên. Huyết quang trôi qua, thân thể Tham Lang bị đánh tung","bridge":true,"khoang":"@c1290"},{"chuong":"@c1293","importance":"bridge","mucCt":"vua","tieuDe":"Pháp bảo bị nghiên cứu","text":"Tham Lang không trực tiếp xuất hiện, nhưng các pháp bảo hắn từng lấy được được Vương Lâm đem ra nghiên cứu, trong đó có chín mươi chín thanh phi kiếm lấy cạnh một cái đầu lâu trong cổ mộ.","anchor":"Chín mươi chín thanh phi kiếm là tham Lang lấy được ở bên cạnh một cái đầu lâu trong cổ mộ"},{"chuong":"@c1294","importance":"normal","mucCt":"vua","tieuDe":"Tìm thi thể bọ cạp","text":"Tham Lang trở thành đại cung phụng nổi danh trong Điên Lạc tinh vực, được gần một ngàn tu sĩ hộ tống tới tu chân tinh Ám Hạt Tộc để tìm thi thể bọ cạp vạn cổ. Danh tiếng chỉ đến nơi có bảo vật khiến các tu sĩ tin rằng lợi ích hắn hứa sẽ không tầm thường.","anchor":"Tham Lang không đi những nơi không có bảo vật"},{"mucCt":"ky","text":"Tham Lang ở vùng đất Điên Lạc trở thành nhân vật hầu hết tu sĩ đều biết nhờ lai lịch thần bí, số lượng pháp bảo và đan dược phong phú, cùng thần thông bỏ chạy cực nhanh. Khi bị truy sát, hắn nhiều lần xuất pháp bảo chưa từng lộ, làm ba tu sĩ Toái Niết bị thương, giết một người, rồi dùng pho tượng tàn phá diệt tu sĩ thiên nhân đệ nhất suy, khiến danh tiếng càng chấn động. Sau đó hắn được đồn là được Điên Lạc đại đế coi trọng, dâng pháp bảo để đổi đan dược, tu vi tăng tới Toái Niết trung kỳ, đến mức tu sĩ thiên nhân đệ tứ suy tham bảo cũng trọng thương rời đi. Hiện tại hắn dẫn hơn mười tu sĩ tới gần tu chân tinh Ám Hạt Tộc, muốn mượn bảo vật của Vân Độn Tộc để tiêu trừ mùi thối đã ăn sâu vào nguyên thần. Trong lòng hắn vẫn oán hận Thiên Vận Tử, Vọng Nguyệt và nhất là Vương Lâm, coi Vương Lâm là khắc tinh đoạt bảo và là khe hở đạo tâm chỉ có thể phá bằng việc tự tay giết đối phương.","anchor":"Tham Lang này ở vùng đất Điên Lạc hầu hết tu sĩ đều biết","bridge":true,"khoang":"@c1295"},{"mucCt":"ky","text":"Tham Lang dẫn hơn một ngàn tu sĩ Vân Độn tộc tới tu chân tinh Ám Hạt Tộc để tìm vật, cưỡng ép Ám Hạt Tộc rời đi ba tháng. Vì Chung Đại Hồng nôn trước mùi thối của mình, hắn nổi giận dùng quạt lớn phá núi, phá động phủ của Vương Lâm, đánh thương nhiều tộc nhân rồi bắt Chung Đại Hồng tới trước mặt. Hắn phô bày nhiều pháp bảo để chờ giết chủ nhân của Chung Đại Hồng, nhưng khi nhận ra người tới là Vương Lâm thì ký ức bị đoạt pháp bảo bùng phát, lập tức bỏ chạy ngay cả pháp bảo đã xuất ra cũng không thu.","anchor":"Khắc tinh, hắn là khắc tinh của ta, hắn biết được ta có một thân pháp bảo nên tới cướp đoạt","bridge":true,"khoang":"@c1296"},{"mucCt":"ky","text":"Tham Lang vừa thấy Vương Lâm đã hoảng sợ bỏ chạy khỏi tu chân tinh, không kịp thu các pháp bảo đang bày ra. Giữa đường hắn từng tự trấn an rằng tu vi và pháp bảo hiện nay đã mạnh hơn xưa, nhưng liên tiếp cảm ứng phi kiếm, Hộ Cốt Cửu Bi, Vụ Ma Thương và Thiên Hoàng Lô bị xóa lạc ấn nên nỗi sợ cũ bùng lên. Cuối cùng hắn coi Vương Lâm là sát tinh, khắc tinh của mình và tiếp tục chạy sâu vào vùng đất Điên Lạc.","anchor":"Trong nháy mắt khi nhìn thấy Vương Lâm, trong đầu Tham Lang không còn ý niệm nào khác","bridge":true,"khoang":"@c1297"},{"mucCt":"ky","text":"Tham Lang bị Vương Lâm truy đuổi trong tinh không vùng đất Điên Lạc, liên tiếp dùng phiến lá khô Nhất diệp phong thiên, hai ma ảnh màu tím, áo giáp ẩn thân và Ma Hồn Bình để cắt đường truy kích. Hắn bị Huyết kiếm đánh trọng thương, mất phiến lá vào tay Vương Lâm, rồi sững sờ khi ba trăm ma hồn Cổ Ma bị tiếng rống Cổ Thần phá tan.","anchor":"Hắn chẳng sao hiểu nổi một kiện chí bảo lại chỉ vì một tiếng rống mà hỏng mất","bridge":true,"khoang":"@c1298"},{"mucCt":"ky","text":"Tham Lang xem Vương Lâm là khắc tinh, ném bình ngọc màu tím để kéo hướng truy đuổi rồi dùng quạt vàng dị thú bỏ chạy. Khi Vương Lâm vẫn đuổi sát và nhắc lại nỗi đau mất hàng loạt pháp bảo, hắn phẫn uất quay lại thi triển Yêu Lang hàng thế, phạt diệt đạo thiên bằng yêu khí Cổ Yêu. Sau khi yêu lang bị chém đôi, hắn lấy pho tượng khắc gỗ tàn phá nhưng lập tức bị Vương Lâm dùng Định khống chế, không thể tiếp tục ra tay.","anchor":"Khắc tinh.hắn là khắc tinh của ta! Ngay cả pháp bảo cũng bị hắn khắc","bridge":true,"khoang":"@c1299"},{"chuong":"@c1300","importance":"normal","mucCt":"ky","tieuDe":"Mất tượng khai mộ","anchor":"Trong lòng Tham Lang nổi lên sóng lớn, sự sợ hãi trong mắt tràn lan","text":"Tham Lang bị Định thân thuật khóa cứng, mất pho tượng bị tàn phá vào tay Vương Lâm và phải khai chuyện từng thoát khỏi Vọng Nguyệt, ẩn trong La Thiên Tinh Vực rồi gặp dòng xoáy dẫn vào cổ mộ. Hắn kể trong cổ mộ có không gian loạn lưu, đầu lâu khổng lồ có tinh điểm, các pháp bảo như Thiên Hoàng Lô, Phù Kinh Kiếm, Cốt bi, Vụ Ma Thương, Ma hồn bình, cùng khu rừng khô héo nơi hắn lấy Vạn Cổ Mộc Linh, Cổ Tức Diệp và pho tượng. Sau khi thử chạy trốn, hắn bị Vương Lâm sưu ký ức rồi được thả, về động phủ mới phát hiện mùi thối trên người đã biến mất."},{"chuong":"@c1302","importance":"bridge","mucCt":"vua","tieuDe":"Ký ức bị tra xét","text":"Ký ức của Tham Lang bị Vương Lâm tra xét, để lộ tọa độ dòng xoáy gần hàng rào giới nội ở La Thiên Tinh Vực và vị trí hắn rời cổ mộ thần bí tại Thái Cổ Tinh Thần.","anchor":"Vương Lâm đã tra xét trí nhớ của Tham Lang, biết được những lời nói của Tham Lang hầu như là chân thật"},{"mucCt":"vua","anchor":"Chín mươi chín thanh phi kiếm là Tham Lang lấy được ở bên cạnh một cái đầu lâu","text":"Nhóm bảo vật Vương Lâm nghiên cứu trong động phủ đều là đồ Tham Lang từng đoạt được trong cổ mộ. Ký ức của Tham Lang giúp Vương Lâm nhận ra nguồn gốc chín mươi chín phi kiếm Cổ Yêu và Hộ cốt Thạch Bi.","bridge":true,"khoang":"@c1303"},{"chuong":"@c1306","importance":"bridge","mucCt":"vua","tieuDe":"Bị nhắc làm cung phụng","text":"Tham Lang không trực tiếp xuất hiện nhưng bị nhiều tộc nhắc như cung phụng của Vân Độn tộc, khiến họ lầm tưởng Vương Lâm là người thay mặt hắn.","anchor":"Nghe nói Vân Độn tộc mời Tham Lang làm cung phụng"}],"tuViMoc":[{"chuong":"@c1295","canhGioi":"Toái Niết trung kỳ","text":"Sau khi dâng pháp bảo cho Điên Lạc đại đế và được ban đan dược, vài năm sau Tham Lang xuất hiện với tu vi Toái Niết trung kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ bị thoát phong ấn","ghiChu":"Tham Lang trọng thương nên mất quyền điều khiển phiến lá phong ấn, khiến Vương Lâm thoát ra."},{"ten":"Điên Lạc đại đế","tag":"cap-tren","quanHe":"Người từng coi trọng và ban đan dược","ghiChu":"Tham Lang dâng pháp bảo cho Điên Lạc đại đế rồi nhận đan dược đề cao tu vi."},{"ten":"Hơn mười tu sĩ vây quanh Tham Lang","tag":"dong-minh","quanHe":"Tùy tùng trong chuyến đi","ghiChu":"Đi cùng Tham Lang tới gần tu chân tinh Ám Hạt Tộc và giữ vẻ cung kính dù chịu mùi thối."},{"ten":"Vân Độn Tộc","tag":"khac","quanHe":"Mục tiêu tiếp cận","ghiChu":"Tham Lang muốn trở thành cung phụ để nghiên cứu bảo vật khử mùi của tộc này."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Đối tượng oán hận","ghiChu":"Tham Lang cho rằng Thiên Vận Tử từng ép hắn vào La Thiên, mở đầu chuỗi tai họa."},{"ten":"Vọng Nguyệt","tag":"doi-thu","quanHe":"Đối tượng căm hận","ghiChu":"Tham Lang căm hận Vọng Nguyệt vì biến cố khiến mùi thối ám ảnh hắn tới hiện tại."},{"ten":"Tộc trưởng Vân Độn tộc","tag":"dong-minh","quanHe":"Từng được Vân Độn tộc mời làm cung phụng.","ghiChu":"Danh tiếng của Tham Lang khiến Vân Độn tộc được các tộc khác coi trọng."}],"tuiDo":{"phapBao":[{"ten":"Áo giáp ẩn giấu của Tham Lang","loai":"áo giáp","trangThai":"hong","moTa":"Bộ giáp ẩn dưới áo bị huyết quang đánh lộ ra và xuất hiện vô số khe nứt.","nguon":"@c1290"},{"ten":"Huyết kiếm của Tham Lang","loai":"huyết kiếm","trangThai":"dang-co","moTa":"Huyết kiếm ngoài thân Tham Lang bị chấn bay hơn mười trượng khi hắn bị huyết quang đánh xuyên.","nguon":"@c1290"},{"ten":"Hai ma ảnh dưới chân Tham Lang","loai":"ma ảnh phụ trợ","trangThai":"dang-co","moTa":"Hai ma ảnh hóa thành hắc khí, vờn quanh thân thể tạo gió lốc đen cuốn Tham Lang bỏ chạy.","nguon":"@c1290"},{"ten":"Phiến lá phong ấn","loai":"vật phong ấn","trangThai":"mat","moTa":"Tham Lang không thể tiếp tục điều khiển phiến lá sau khi trọng thương bỏ chạy, để Vương Lâm chụp lấy.","nguon":"@c1290"}],"danDuoc":[],"congPhap":[{"ten":"Thuật bỏ chạy của Tham Lang","loai":"khả năng đào thoát","trangThai":"dang-co","moTa":"Tham Lang tự nhận sở trường bỏ chạy của mình hiếm người sánh bằng, và sau khi bị thương vẫn dùng ma ảnh hóa gió lốc đen để đào thoát.","nguon":"@c1290"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1290","@c1293","@c1294","@c1295","@c1296","@c1297","@c1298","@c1299","@c1300","@c1302","@c1303","@c1306"]},{"id":"tu-ma-mac","name":"Tư Mã Mặc","cn":"","aliases":["Tư Mã Mặc"],"gioiTinh":"nam","theLuc":[{"ten":"Phá Thiên tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Thiên Nhân Đệ Ngũ Suy @c1293","trangThai":"khong-ro","blurb":"Tư Mã Mặc (bí danh Tư Mã Đặc) là đại đệ tử Phá Thiên Tông một vạn tám ngàn năm trước, xuất thân tinh vực Vân Hải và tinh thông luyện đan. Mười vạn tám ngàn năm trước hắn mang mảnh xương thú cùng một phần đệ tử rời tông môn rồi biến mất, để lại động phủ chứa ba khối ngọc giản ghi lại trải nghiệm nhiều năm trong thế giới bảy màu cùng các bình đan dược quý. Về sau Vương Lâm thu được ngọc giản luyện đan cùng di vật của hắn trong động phủ nơi Thất Thải Giới.","vaiTro":"Đại đệ tử Phá Thiên Tông, tinh thông luyện đan; chủ nhân động phủ và ngọc giản","tinhCach":"Trọng tình đồng môn — để lại di vật và đưa đồng môn về; am tường luyện đan; kiên trì tìm đường sinh tồn nơi hiểm địa","mucCt":"gon","tabs":{"diem":[{"text":"Đại đệ tử Phá Thiên Tông một vạn tám ngàn năm trước, am hiểu luyện đan","chuong":"@c114"},{"text":"Mười vạn tám ngàn năm trước mang mảnh xương thú và một phần đệ tử rời tông môn rồi biến mất","chuong":"@c1091"},{"text":"Xuất thân tinh vực Vân Hải, cùng sư thúc và đồng môn tiến vào khe nứt không gian bảy màu","chuong":"@c1126"},{"text":"Để lại ba khối ngọc giản ghi lại toàn bộ trải nghiệm nhiều năm trong thế giới bảy màu","chuong":"@c1127"},{"text":"Chủ nhân ba bình đan dược quý, để lại cho đồng môn bằng trận pháp trong động phủ","chuong":"@c1128"},{"text":"Ở cảnh giới Toái Niết tìm được phương pháp thoát khỏi cây đinh bảy màu","chuong":"@c1206"}],"kinhLich":[{"mucCt":"gon","text":"Tư Mã Mặc được Vương Lâm nhớ tới qua ngọc giản và động phủ trong Thất Thải Giới khi hắn liên hệ thần thông của Tư Mặc Tử với Phá Thiên tông.","anchor":"lại cũng đạt được ngọc giản của Tư Mã Mặc","bridge":true,"khoang":"@c1290"},{"chuong":"@c1291","importance":"normal","mucCt":"vua","tieuDe":"Danh xưng phá nhịp","text":"Tên Tư Mã Mặc được Vương Lâm hét lên cùng Phá Thiên tông đúng lúc Tư Mặc Tử sắp hạ thần thông. Chương chỉ cho thấy danh xưng này khiến Tư Mặc Tử dao động, chưa xác nhận quan hệ đồng nhất hay lai lịch rõ ràng.","anchor":"- Phá Thiên tông, Tư Mã Mặc!"},{"mucCt":"ky","text":"Phân thân Thiên Nhân Đệ Ngũ Suy của Tư Mặc Tử bị Băng long đan, Viêm hỏa dị tinh và huyết kiếm của Vương Lâm đánh trọng thương nhưng vẫn chưa chết. Khi hắn sắp thuấn di rời khỏi vùng đất Điên Lạc, một ngón tay khổng lồ từ dòng xoáy trên trời điểm xuống chặn đường thoát.","anchor":"Phân thân của Tư Mặc Tử dù sao cũng là thiên nhân đệ ngũ suy, không thể dễ dàng bị g**t ch*t như vậy","bridge":true,"khoang":"@c1293"},{"chuong":"@c1294","importance":"normal","mucCt":"ky","tieuDe":"Phân thân tử vong","text":"Bổn tôn Tư Mặc Tử ở ngoài tinh vực Điên Lạc mở mắt khi cảm ứng phân thân đã chết, nổi sát khí vì kế hoạch tế luyện thêm một thân thể bước thứ ba bị phá hỏng. Hắn nhận ra Vương Lâm có lôi bổn nguyên, một tia hỏa bổn nguyên và biết tên cũ của mình, từ đó nghi ngờ Vương Lâm đến từ giới nội. Sau đó hắn triệu ra hai mươi chín cây Thất Thải Thần Không Đinh, cân nhắc dựa vào Trường Tôn hội để đối phó Điên Lạc đại đế.","anchor":"Phân thân chết đối với tu vi của bổn tôn hắn cũng không có ảnh hưởng gì"},{"chuong":"@c1296","importance":"bridge","mucCt":"vua","tieuDe":"Phân thân bị nhắc lại","text":"Tư Mặc Tử được Vương Lâm nhắc lại qua trận chiến trước đó và việc phân thân bị Điên Lạc đại đế giết, sự kiện được xem như thái độ của đại đế đối với Trường Tôn hội.","anchor":"Nhưng đại đế này không ngờ lại g**t ch*t phân thân của Tư Mặc Tử"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Nguồn manh mối","ghiChu":"Vương Lâm từng đạt được ngọc giản của Tư Mã Mặc, nhờ đó biết chuyện về Phá Thiên tông."},{"ten":"Tư Mặc Tử","tag":"khac","quanHe":"Manh mối lai lịch","ghiChu":"Thần thông của Tư Mặc Tử khiến Vương Lâm liên hệ tới Tư Mã Mặc và Phá Thiên tông."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát bằng nhiều sát chiêu.","ghiChu":"Giao chiến tại @c1293."},{"ten":"Đại đế vùng Điên Lạc","tag":"doi-thu","quanHe":"Bị một chỉ từ hư vô của đại đế chặn khi bỏ chạy.","ghiChu":"Biến cố tại @c1293."},{"ten":"Điên Lạc đại đế","tag":"doi-thu","quanHe":"Xem Điên Lạc đại đế là kẻ phá hỏng kế hoạch của mình và muốn mượn Trường Tôn hội để đối phó.","ghiChu":"Mưu tính sau biến cố phân thân @c1294"},{"ten":"Chưởng tôn","tag":"cap-tren","quanHe":"Từng được Chưởng tôn ban Thất Thải Thần Không Đinh để giết tu sĩ bước thứ ba.","ghiChu":"Quan hệ qua pháp bảo sát phạt @c1294"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Ngọc giản Tư Mã Mặc","loai":"ngọc giản","trangThai":"khong-ro","moTa":"Ngọc giản được Vương Lâm nhớ tới như nguồn hiểu biết về Tư Mã Mặc và Phá Thiên tông.","nguon":"@c1290"}]}},"nguon":["@c1290","@c1291","@c1293","@c1294","@c1296"]},{"id":"tieng-noi-trong-hu-vo","name":"Tiếng nói trong hư vô","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Chủ thể vô danh vang lên từ hư vô trong trận chiến giữa Vương Lâm và Tư Mặc Tử. Tiếng đếm của thực thể này đặt áp lực năm nhịp thở lên toàn bộ cuộc giao phong.","vaiTro":"Chủ thể đếm nhịp trận chiến","tinhCach":[{"text":"Bí ẩn, không lộ thân phận","chuong":"@c1292"},{"text":"Tạo áp lực thời gian trong giao chiến","chuong":"@c1292"}],"tabs":{"diem":[{"text":"Vang lên từ hư vô và đếm nhịp trong lúc Vương Lâm giao chiến với Tư Mặc Tử.","chuong":"@c1292"},{"text":"Tiếng đếm một, hai, ba, bốn khiến trận chiến bị đặt trong giới hạn cực ngắn.","chuong":"@c1292"}],"kinhLich":[{"chuong":"@c1292","importance":"bridge","mucCt":"gon","tieuDe":"Đếm giữa hư vô","text":"Tiếng nói trong hư vô nhiều lần vang lên để đếm nhịp, trực tiếp thúc ép diễn biến trận chiến năm nhịp thở.","anchor":"Tiếng nói từ trong hư vô lại vang lên một lần nữa"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1292"]},{"id":"tu-si-chan-ngon-toc","name":"Tu sĩ Chân Ngôn tộc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Chân Ngôn Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Tu sĩ thuộc Chân Ngôn Tộc được nhắc lại qua ký ức của Tư Mặc Tử về trận đánh trước đó. Sự kiện trên tu chân tinh Chân Ngôn tộc khiến Tư Mặc Tử kiêng kỵ thuật lôi đình của Vương Lâm.","vaiTro":"Tu sĩ được nhắc qua chiến trường cũ","tinhCach":[{"text":"Gắn với ký ức giao chiến tại Chân Ngôn tộc","chuong":"@c1292"},{"text":"Làm nền cho sự kiêng kỵ của Tư Mặc Tử đối với lôi đình","chuong":"@c1292"}],"tabs":{"diem":[{"text":"Được nhắc khi Tư Mặc Tử nhớ lại màn Vương Lâm ra tay trên Chân Ngôn tộc.","chuong":"@c1292"}],"kinhLich":[{"chuong":"@c1292","importance":"bridge","mucCt":"gon","tieuDe":"Được nhớ lại","text":"Tu sĩ Chân Ngôn tộc được nhắc gián tiếp qua ký ức khiến Tư Mặc Tử kinh hãi trước thuật lôi đình của Vương Lâm.","anchor":"một màn trên Chân Ngôn tộc gần đó đã đủ khiến hắn kinh hãi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1292"]},{"id":"ngan-y-nu-tu","name":"Ngân y nữ tử","aliases":["Ngân Y Luyện Thi"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1293","importance":"bridge","mucCt":"gon","tieuDe":"Bị thu vào trữ vật","text":"Ngân y nữ tử được Vương Lâm thu lại vào không gian trữ vật sau khi hắn tạm gác chuyện pho tượng bí ẩn.","anchor":"vung tay áo thu ngân y nữ tử vào trong không gian trữ vật một lần nữa"},{"mucCt":"vua","text":"Ngân y nữ tử được Vương Lâm gọi ra từ khe không gian thứ hai để xem pho tượng. Khi nhìn thấy pho tượng, nàng lập tức mất bình tĩnh, đồng tử co rút rồi hét lên thê lương.","anchor":"Một nữ tử tuyệt đẹp từ trong khe bước ra, chính là ngân y nữ tử trước kia","bridge":true,"khoang":"@c1302"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bị Vương Lâm thu vào không gian trữ vật.","ghiChu":"Diễn biến tại @c1293."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"tuViMoc":[],"diem":[{"text":"Được Vương Lâm thu vào không gian trữ vật","chuong":"@c1293"},{"text":"Sở hữu huyết mạch Tiên Cương, có thể tồn tại trong hư vô không bị ảnh hưởng","chuong":"@c1705"},{"text":"Bị cuốn vào khe nứt hư vô khi không gian trữ vật sụp đổ, biến mất cùng Liên Đạo Phi","chuong":"@c1712"}]},"nguon":["@c1293","@c1302"],"gioiTinh":"nu","vaiTro":"Nhân vật phụ — nữ tử bí ẩn mang huyết mạch Tiên Cương, bị thu trongữ vật của Vương Lâm","blurb":"Ngân y nữ tử là một nữ tu sở hữu huyết mạch Tiên Cương, được Vương Lâm thu vào không gian trữ vật. Sau đó nàng cùng Liên Đạo Phi bị cuốn vào hư vô khi không gian trữ vật sụp đổ, hiện vẫn mất tích trong khe không gian."},{"id":"phan-than-thu-hai-cua-vuong-lam","name":"Phân thân thứ hai của Vương Lâm","aliases":["Phân thân Cổ Yêu"],"gioiTinh":"nam","trangThai":"khong-ro @c1293","tabs":{"kinhLich":[{"chuong":"@c1293","importance":"bridge","mucCt":"vua","tieuDe":"Được giữ kiếm Cổ Yêu","text":"Phân thân thứ hai của Vương Lâm được nhắc tới khi Vương Lâm đánh giá chín mươi chín thanh phi kiếm chứa yêu khí và dự định giữ lại để phân thân Cổ Yêu đại thành sử dụng hoặc hấp thu sau khi trở về giới nội.","anchor":"nếu để cho phân thân thứ hai của ta đại thành thì phân thân Cổ Yêu đó cầm kiếm này uy lực tất nhiên là bất phàm"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Phân thân thứ hai của Vương Lâm, được bản tôn dự định giao phi kiếm Cổ Yêu.","ghiChu":"Được nhắc tại @c1293."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1293"]},{"id":"nam-tu-trung-nien-hong-sam","name":"Nam tử trung niên hồng sam","aliases":["Sứ giả của đại đế","Sứ giả của đại đế Điên Lạc","Sứ giả của Điên Lạc đại đế"],"gioiTinh":"nam","theLuc":[{"ten":"Điên Lạc Địa","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1301","trangThai":"song","blurb":"Sứ giả của Điên Lạc đại đế, xuất hiện bằng kiếm quang để tuyên khẩu dụ xử phạt tộc trưởng Long Giáp Tộc. Hắn che giấu tu vi rất sâu và cung kính gọi Vương Lâm là thiếu đế.","vaiTro":"Sứ giả truyền khẩu dụ đại đế","tinhCach":[{"text":"Lạnh lùng khi tuyên phạt tộc trưởng Long Giáp Tộc.","chuong":"@c1293"},{"text":"Cung kính trước Vương Lâm sau khi tuyên khẩu dụ.","chuong":"@c1293"}],"tabs":{"diem":[{"text":"Từ kiếm quang bước ra và không để lộ khí tức tu vi.","chuong":"@c1293"},{"text":"Tuyên khẩu dụ tước tư cách trưởng lão thứ chín của tộc trưởng Long Giáp Tộc.","chuong":"@c1293"},{"text":"Quay sang Vương Lâm cung kính tham kiến thiếu đế.","chuong":"@c1293"},{"text":"Tuyên bố thân phận thiếu đế của Vương Lâm trước Long Giáp Tộc.","chuong":"@c1294"},{"text":"Mang độc đan của đại đế tới xử tử tộc trưởng cũ Long Giáp Tộc.","chuong":"@c1294"},{"text":"Trao ngọc bội chữ “đế” và truyền lời mời dự tuyển chọn trưởng lão Lạc Sinh hội.","chuong":"@c1294"}],"kinhLich":[{"mucCt":"vua","text":"Nam tử trung niên hồng sam từ kiếm quang bước ra, không lộ khí tức tu vi vì tu luyện công pháp che giấu. Hắn tuyên khẩu dụ tước tư cách trưởng lão thứ chín của tộc trưởng Long Giáp Tộc, ban Độc mệnh đan, rồi quay sang cung kính tham kiến Vương Lâm là thiếu đế.","anchor":"Từ trong kiếm quang như cầu vồng, một nam tử trung niên mặc hồng sam bước ra","bridge":true,"khoang":"@c1293"},{"mucCt":"vua","text":"Nam tử trung niên hồng sam tới Long Giáp Tộc để đưa đan dược và tuyên khẩu dụ của Điên Lạc đại đế. Hắn công bố Vương Lâm là thiếu đế, yêu cầu Vương Lâm định đoạt tộc trưởng mới, rồi giao ngọc bội chữ “đế” và truyền lời mời dự Lạc Sinh hội sau ba tháng.","anchor":"Ta chỉ tới đưa đan dược, tuyên khẩu dụ của đại đế","bridge":true,"khoang":"@c1294"},{"chuong":"@c1296","importance":"bridge","mucCt":"gon","tieuDe":"Truyền khẩu dụ trừng phạt","text":"Sứ giả của Điên Lạc đại đế được Vương Lâm nhắc qua việc truyền khẩu dụ trừng phạt tộc trưởng Long Giáp Tộc, như một lời cảnh cáo dành cho hắn.","anchor":"Mà hắn thông qua sứ giả nọ truyền khẩu dụ trừng phạt tộc trưởng Long Giáp Tộc"},{"chuong":"@c1301","importance":"bridge","mucCt":"gon","tieuDe":"Lời báo kỳ tuyển chọn","text":"Nam tử trung niên hồng sam được Vương Lâm nhớ lại là người từng báo ở Long Giáp Tộc về kỳ tuyển chọn lại trưởng lão Lạc Sinh hội sau ba tháng.","anchor":"Hắn lúc trước ở Long Giáp Tộc đã được sứ giả của đại đế nói qua"}],"tuViMoc":[],"nhanMach":[{"ten":"Điên Lạc đại đế","tag":"cap-tren","quanHe":"Sứ giả phụng khẩu dụ đại đế.","ghiChu":"Xuất hiện theo lệnh đại đế tại @c1293."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cung kính tham kiến Vương Lâm là thiếu đế.","ghiChu":"Gặp tại @c1293."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"doi-thu","quanHe":"Tuyên khẩu dụ tước chức và ban Độc mệnh đan cho tộc trưởng.","ghiChu":"Xử phạt tại @c1293."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"Mang độc đan của đại đế tới cho tộc trưởng cũ nuốt theo khẩu dụ.","ghiChu":"Tộc trưởng chết sau khi dùng độc đan @c1294"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Độc mệnh đan","loai":"đan dược","trangThai":"da-dung","moTa":"Mang tới theo khẩu dụ đại đế để ban cho tộc trưởng Long Giáp Tộc.","nguon":"@c1293"}],"congPhap":[{"ten":"Công pháp ẩn dấu tu vi của sứ giả đại đế","loai":"công pháp","trangThai":"dang-co","moTa":"Giúp hắn không lộ khí tức tu vi, Vương Lâm cũng khó phát hiện.","nguon":"@c1293"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1293","@c1294","@c1296","@c1301"]},{"id":"thanh-nien-khuy-niet-long-giap-toc","name":"Thanh niên Khuy Niết Long Giáp Tộc","aliases":["Tân tộc trưởng Long Giáp Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"},{"ten":"Điên Lạc Địa","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Khuy Niết @c1294","trangThai":"song","blurb":"Một tu sĩ Khuy Niết của Long Giáp Tộc, vốn không phải ứng viên nổi bật nhất nhưng được Vương Lâm chỉ định làm tân tộc trưởng. Sau khi lên vị, hắn lập tức tuyên bố Long Giáp Tộc tùy Vương Lâm sai khiến.","vaiTro":"Tân tộc trưởng Long Giáp Tộc","tinhCach":[{"text":"Biết nắm lấy cơ hội sống còn khi được Vương Lâm lựa chọn.","chuong":"@c1294"},{"text":"Nhanh chóng thần phục, dùng thái độ cung kính để bảo toàn tộc mình.","chuong":"@c1294"}],"tabs":{"diem":[{"text":"Được Vương Lâm chọn làm tân tộc trưởng Long Giáp Tộc sau khi tộc trưởng cũ bị xử tử.","chuong":"@c1294"},{"text":"Lập tức tuyên bố Long Giáp Tộc xin tùy Vương Lâm sai khiến.","chuong":"@c1294"},{"text":"Nhận lệnh gom Băng long đan, Viêm hỏa dị tinh và con rối giao cho Vương Lâm.","chuong":"@c1294"}],"kinhLich":[{"chuong":"@c1294","importance":"normal","mucCt":"vua","tieuDe":"Trở thành tân tộc trưởng","text":"Thanh niên Khuy Niết Long Giáp Tộc được Vương Lâm chỉ định làm tộc trưởng mới sau cái chết của tộc trưởng cũ. Hắn mừng như điên, lập tức quỳ lạy cảm tạ và tuyên bố Long Giáp Tộc từ nay nghe theo sự sai khiến của Vương Lâm.","anchor":"Đa.đa tạ thiếu đế coi trọng. Từ nay về sau, Long Giáp Tộc của vãn bối xin tùy theo sự sai khiến của thiếu đế"},{"chuong":"@c1296","importance":"bridge","mucCt":"gon","tieuDe":"Giao tích lũy toàn tộc","text":"Tân tộc trưởng Long Giáp Tộc được nhắc là người giao toàn bộ tích súc Long Giáp Tộc cho Vương Lâm sau biến cố trước đó.","anchor":"Đây là toàn bộ tích súc của Long Giáp Tộc, lúc này bị tân tộc trưởng giao ra cả"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Được Vương Lâm chỉ định làm tân tộc trưởng và lập tức quy phục dưới quyền sai khiến của Vương Lâm.","ghiChu":"Quan hệ lệ thuộc bắt đầu từ biến cố @c1294"},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"Kế nhiệm vị trí tộc trưởng sau khi tộc trưởng cũ bị độc đan xử tử.","ghiChu":"Đổi lãnh đạo Long Giáp Tộc @c1294"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1294","@c1296"]},{"id":"thien-van-tu","name":"Thiên Vận Tử","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[{"text":"Cưỡi tảng đá khổng lồ như sao băng đi qua Chu Tước tinh, lần đầu xuất hiện với sức mạnh ước lượng vượt Hóa Thần","chuong":"@c0241"},{"text":"Nhận Vương Lâm làm đệ tử chân chính, mở tâm thần chứa 3600 phân thân cho Vương Lâm tự chọn thần thông cấm pháp","chuong":"@c0474"},{"text":"Thi triển Dẫn Tiên thuật cuốn hơn vạn đệ tử Đại La Kiếm Tông, thể hiện thực lực áp đảo trong đại thọ vạn năm","chuong":"@c0468"},{"text":"Chủ động hiến hồn để đoạt cấm chế bổn nguyên của Vương Lâm, tiết lộ Luân Hồi Toàn Thể Thuật là âm mưu hai ngàn năm","chuong":"@c1624"},{"text":"Bị phơi bày chân tướng: không phải Thất Thải Tiên Tôn mà là thực thể nguyên thủy thuộc Thiên Đạo, bổn tôn là nửa nghịch la bàn","chuong":"@c1628"},{"text":"Hoàn thành thức tỉnh thứ chín mươi chín, chiếm cứ phân thân Vương Lâm nhưng bị đoạt bổn tôn và tiêu diệt hoàn toàn","chuong":"@c1629"}],"kinhLich":[{"chuong":"@c1295","importance":"bridge","mucCt":"vua","tieuDe":"Bị Tham Lang oán hận","text":"Thiên Vận Tử bị Tham Lang oán hận vì Tham Lang cho rằng năm đó ông cùng những người khác ép hắn vào La Thiên, gián tiếp dẫn tới thảm cảnh hiện tại.","anchor":"Thiên Vận Tử, nếu không phải các ngươi năm đó bức ta đi vào La Thiên"},{"chuong":"@c1303","importance":"normal","mucCt":"vua","tieuDe":"Chuỗi bảy màu","anchor":"Thiên Vận Tử có bảy màu, chưởng tôn cũng là bảy màu","text":"Khi suy xét thân ảnh áo bảy màu trong thức hải ngân y nữ tử, Vương Lâm nhớ tới Thiên Vận Tử như một mắt xích trong chuỗi hiện tượng bảy màu từng gặp. Điều này khiến nghi vấn của hắn về bí mật bảy màu càng sâu hơn."},{"chuong":"@c1308","importance":"bridge","mucCt":"gon","tieuDe":"Được Vương Lâm kiêng kỵ","text":"Thiên Vận Tử được Vương Lâm nhớ tới như người khó lường khiến hắn cực kỳ kiêng kỵ.","anchor":"Thiên Vận Tử có thể nói là người mà Vương Lâm không nhìn thấy được"},{"chuong":"@c1315","importance":"bridge","mucCt":"gon","tieuDe":"Vấn đạo được nhắc","text":"Thiên Vận Tử được Vương Lâm nhắc làm đối chiếu khi hắn nhận ra cửa Nhân không phải vấn đạo như năm xưa mà là tâm ma. Được Vương Lâm nhắc làm mốc so sánh — cửa Nhân ban đầu khiến hắn tưởng giống vấn đạo năm xưa của Thiên Vận Tử nhưng thực chất là tâm ma.","anchor":"vốn tưởng là khảo nghiệm giống như Thiên Vận Tử vấn đạo"}],"tuViMoc":[],"nhanMach":[{"ten":"Tham Lang","tag":"doi-thu","quanHe":"Bị oán hận","ghiChu":"Tham Lang quy nguyên nhân tai họa năm xưa cho Thiên Vận Tử và những người liên quan."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1295","@c1303","@c1308","@c1315"],"tinhCach":"Giỏi tính toán thiên cơ và bố cục dài hạn qua hàng ngàn năm; điềm tĩnh uy nghi khi chủ trì tông môn, giảng đạo; tự tin quyết liệt trước cường địch; che giấu dã tâm thôn phệ dưới thân phận sư tôn","canhGioiCaoNhat":"Không đổi trong @c1315","vaiTro":"Chưởng môn Thiên Vận Tông — bộ phận Thiên Đạo, bổn tôn là nửa nghịch la bàn","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông, thành viên Liên Minh Trưởng Lão Đoàn, từng nhận Vương Lâm làm đệ tử chân chính nhưng âm thầm bố cục qua lạc ấn, phân hồn và Luân Hồi Toàn Thể Thuật suốt hai ngàn năm. Chân tướng về sau phơi bày: hắn không phải tàn hồn Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải, bổn tôn là nửa nghịch la bàn — một bộ phận của Thiên Đạo. Sau lần thức tỉnh thứ chín mươi chín và ý đồ chiếm cứ phân thân Vương Lâm, hắn bị Vương Lâm đoạt bổn tôn rồi tiêu diệt hoàn toàn."},{"id":"vong-nguyet","name":"Vọng Nguyệt","gioiTinh":"khong-ro","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1295","importance":"bridge","mucCt":"vua","tieuDe":"Cừu hận của Tham Lang","text":"Vọng Nguyệt bị Tham Lang căm hận vì biến cố nuốt hắn vào nơi bài tiết khiến hắn chịu hành hạ và lưu lại mùi thối ám ảnh đến hiện tại.","anchor":"cuối cùng lại bị Vọng Nguyệt chết tiệt nuốt vào chỗ bài tiết"},{"chuong":"@c1300","importance":"bridge","mucCt":"gon","anchor":"năm đó sau khi Vọng Nguyệt nuốt ta thì toàn thân","text":"Tham Lang nhắc lại việc sau khi bị Vọng Nguyệt nuốt rồi thoát chết, toàn thân và nguyên thần hắn bị ám mùi thối khó xua tan."}],"tuViMoc":[],"nhanMach":[{"ten":"Tham Lang","tag":"doi-thu","quanHe":"Đối tượng bị căm hận","ghiChu":"Biến cố với Vọng Nguyệt để lại ám ảnh mùi thối trong ký ức Tham Lang."},{"ten":"Lão giả áo trắng trên lưng Vọng Nguyệt","tag":"khac","quanHe":"Người đứng trên lưng","ghiChu":"Lão giả áo trắng xuất hiện trên lưng Vọng Nguyệt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1295","@c1300","@c1305"],"tinhCach":[]},{"id":"hon-muoi-tu-si-vay-quanh-tham-lang","name":"Hơn mười tu sĩ vây quanh Tham Lang","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Đoàn tùy hành của Tham Lang","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1295","trangThai":"song","blurb":"Nhóm hơn mười tu sĩ đi cùng Tham Lang trong chuyến tới gần tu chân tinh Ám Hạt Tộc. Họ ngửi thấy mùi thối trên người Tham Lang nhưng không dám để lộ vẻ khác thường.","vaiTro":"Tùy hành của Tham Lang","tinhCach":[{"text":"Cẩn trọng trước uy thế của Tham Lang","chuong":"@c1295"},{"text":"Giữ thái độ cung kính dù khó chịu","chuong":"@c1295"}],"tabs":{"diem":[{"text":"Đi cùng Tham Lang tới gần tu chân tinh Ám Hạt Tộc.","chuong":"@c1295"},{"text":"Không dám biểu lộ phản ứng trước mùi thối của Tham Lang.","chuong":"@c1295"}],"kinhLich":[{"chuong":"@c1295","importance":"bridge","mucCt":"gon","tieuDe":"Theo Tham Lang tới Ám Hạt","text":"Hơn mười tu sĩ đi cùng Tham Lang tới gần tu chân tinh Ám Hạt Tộc, ngửi thấy mùi thối nhưng vẫn giữ thái độ cung kính.","anchor":"Hơn mười tu sĩ vây quanh Tham Lang cũng ngửi được mùi thối"}],"tuViMoc":[],"nhanMach":[{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Tùy hành","ghiChu":"Đi theo Tham Lang trong chuyến tới gần tu chân tinh Ám Hạt Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1295"]},{"id":"lao-gia-nhan-ra-de-lenh","name":"Lão giả nhận ra Đế lệnh","cn":"","aliases":["Lão giả nhận ra Đế lệnh trong nhóm hơn ngàn tu sĩ"],"gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Một lão giả trong nhóm hơn ngàn tu sĩ trên tu chân tinh Ám Hạt Tộc. Ông nhận ra ngọc bội trong tay Vương Lâm là Đế lệnh và khiến uy quyền của lệnh vật được xác nhận trước đám đông.","vaiTro":"người nhận ra Đế lệnh","tinhCach":[{"text":"cẩn trọng khi quan sát lệnh vật","chuong":"@c1297"},{"text":"kinh sợ trước uy quyền của Đế lệnh","chuong":"@c1297"}],"tabs":{"diem":[{"text":"Là người đầu tiên trong đám tu sĩ nhận ra ngọc bội của Vương Lâm là Đế lệnh.","chuong":"@c1297"},{"text":"Phản ứng thất sắc của ông khiến các tu sĩ khác hiểu mức độ nghiêm trọng của mệnh lệnh.","chuong":"@c1297"}],"kinhLich":[{"mucCt":"gon","text":"Lão giả nhìn thấy ngọc bội của Vương Lâm thì mặt xám lại, quan sát cẩn thận rồi thất thanh nhận ra đó là Đế lệnh.","anchor":"sau khi nhìn thoáng qua mặt liền xám như cho tàn, thất thanh nói","bridge":true,"khoang":"@c1297"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người cầm Đế lệnh","ghiChu":"Lão giả nhận ra lệnh vật trong tay Vương Lâm."},{"ten":"Chung Đại Hồng","tag":"khac","quanHe":"người được chỉ định nghe lệnh","ghiChu":"Sau khi Đế lệnh được đưa ra, nhóm tu sĩ phải nghe Chung Đại Hồng theo phân phó của Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1297"]},{"id":"tu-si-van-don-toc","name":"Tu sĩ Vân Độn tộc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Vân Độn Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Tu sĩ thuộc Vân Độn Tộc được Tham Lang nhắc tới khi hối hận vì đã phô bày quá nhiều pháp bảo. Nhân vật này chỉ xuất hiện qua lời nhắc trong chương 1297.","vaiTro":"người được Tham Lang nhắc tới","tinhCach":[{"text":"chưa rõ tính cách","chuong":"@c1297"}],"tabs":{"diem":[{"text":"Được Tham Lang xem là người chứng kiến việc hắn khoe pháp bảo trước khi gặp Vương Lâm.","chuong":"@c1297"}],"kinhLich":[{"chuong":"@c1297","importance":"bridge","mucCt":"gon","tieuDe":"Bị Tham Lang nhắc","text":"Tu sĩ Vân Độn tộc bị Tham Lang nhắc tới trong lúc hắn hối hận vì đã làm trò khoe pháp bảo trước mặt người này.","anchor":"không nên làm trò trước mặt tu sĩ Vân Độn tộc kia"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Tham Lang","tag":"khac","quanHe":"người từng chứng kiến pháp bảo","ghiChu":"Tham Lang nhắc tới tu sĩ này khi hối hận vì phô bày quá nhiều bảo vật."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1297"]},{"id":"co-ma-thap-gia","name":"Cổ Ma Tháp Già","gioiTinh":"nam","trangThai":"khong-ro","aliases":[],"tabs":{"diem":[{"text":"Được xác nhận là nguồn tách ra ma niệm của Tán Ma và là kẻ chuẩn bị nơi chôn Thanh Lâm từ vô số năm","chuong":"@c0964"},{"text":"Thức tỉnh trong thân Thanh Sương tại tầng chín Tiên phủ sau khi ánh nến tắt, ma khí nhập linh đài hóa thành giáp","chuong":"@c0996"},{"text":"Bị Thái Cổ thánh khí phong ấn: ma ảnh bị trường kiếm đỏ thẫm áp chế, chân linh bị khiếp sợ trước Thái Cổ thiên đạo bảo vật","chuong":"@c1014"},{"text":"Đại bại trước Vương Lâm cấp Không Niết trong thức hải, hiện thân thể khổng lồ từ ma khí, mi tâm mang vết sẹo, bị giam giữ","chuong":"@c1047"},{"text":"Tự hủy thi triển Thủy Ma Đạo trong Thức Hải Thanh Lâm, tử vong sau khi Tử Khí Ma Kiếp bị Sơn Băng đánh bại","chuong":"@c1049"},{"text":"Hư ảnh vạn trượng hiện ra trong sứ đoàn Đạo Cổ, phủ phục run rẩy trước Vương Lâm rồi xé trời rời Hắc Thạch Thành","chuong":"@c1903"}],"kinhLich":[{"chuong":"@c1298","importance":"bridge","tieuDe":"Được đem đối chiếu","mucCt":"gon","text":"Vương Lâm dùng Cổ Ma Tháp Già làm đối chiếu khi nhận ra các ma hồn Cổ Ma trong gió lốc giống Tháp Già năm xưa nhưng khác ở đồng tử trái.","anchor":"Cổ Ma này cực kỳ giống với Tháp Già năm đó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1298"],"vaiTro":"Phản diện — tồn tại Cổ Ma bát tinh chiếm thân Thanh Sương, chi phối tuyến tranh đoạt Đại Dật Cô Yên Đồ","tinhCach":"Tàn nhẫn quyết đoán, hạ sát lão nhân hồ lô chỉ bằng một đao không chút do dự; giảo hoạt mưu tính, cố ý bố trí khiến Vương Lâm nghi ngờ mọi hành động trước đó; ngạo mạn khinh mạn, khiêu khích Hoa Phi và tuyên bố giết sạch; lạnh lùng ít dao động nhưng run rẩy khi cảm nhận lực Tàn Dạ","blurb":"Cổ Ma Tháp Già là tồn tại cấp bát tinh, nguồn tách ra ma niệm của Tán Ma và là kẻ chuẩn bị nơi chôn Thanh Lâm từ vô số năm. Sau khi thức tỉnh trong thân Thanh Sương tại tầng chín Tiên phủ, hắn trở thành trung tâm uy hiếp, giao chiến liên tiếp với Chu Tước Thánh tông, Hoa Phi, Lữ Vân Đạo, bị Thái Cổ thánh khí phong ấn và cuối cùng đại bại trước Vương Lâm cấp Không Niết trong Thức Hải Thanh Lâm, tự hủy thi triển Thủy Ma Đạo mà tử vong. Về sau Cổ Ma Hồn của hắn được Vương Lâm thu dụng, và hư ảnh Tháp Già từng hiện ra trong sứ đoàn Đạo Cổ, phủ phục trước Vương Lâm rồi xé trời rời đi."},{"id":"toc-truong-van-don-toc","name":"Tộc trưởng Vân Độn tộc","cn":"","aliases":["Vân Độn tử"],"gioiTinh":"nam","theLuc":[{"ten":"Vân Độn tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1307","trangThai":"song","blurb":"Người đứng đầu Vân Độn tộc trong sự kiện trên tu chân tinh Ám Hạt Tộc. Vì sợ chủ nhân của Chung Đại Hồng, hắn phải hạ mình xin lỗi và dâng hậu lễ.","vaiTro":"Tộc trưởng Vân Độn tộc, đại diện thế lực cúi đầu trước uy danh Vương Lâm.","tinhCach":[{"text":"Biết nhún nhường khi nhận ra đã đắc tội người không thể chọc.","chuong":"@c1300"}],"tabs":{"diem":[{"text":"Tu vi cao hơn Chung Đại Hồng nhưng vẫn phải cung kính đứng hầu vì kiêng sợ Vương Lâm.","chuong":"@c1300"},{"text":"Chủ động dâng bình ngọc làm hậu lễ để cầu được nói giúp.","chuong":"@c1300"}],"kinhLich":[{"mucCt":"vua","anchor":"Tộc trưởng Vân Độn tộc trong lòng khô sở.","text":"Tộc trưởng Vân Độn tộc cùng các trưởng lão không dám rời tu chân tinh Ám Hạt Tộc, phải cung kính đứng hầu Chung Đại Hồng và xin tha lỗi vì sợ chủ nhân của hắn. Hắn lấy ra bình ngọc làm hậu lễ, mong Chung Đại Hồng nói giúp trước Vương Lâm.","bridge":true,"khoang":"@c1300"},{"mucCt":"vua","text":"Tộc trưởng Vân Độn tộc có mặt bên cạnh Vương Lâm ngoài Đại đế tinh và bị Hồn Xà tộc, Hà tộc nhắm vào vì từng mời Tham Lang làm cung phụng. Ông nói Tham Lang có việc quan trọng đã rời đi, rồi ngẩng đầu châm chọc khi Hà tộc quay sang ép Vương Lâm.","anchor":"Tiền bối Tham Lang có chuyện quan trọng rời đi, sẽ không trở lại nữa","bridge":true,"khoang":"@c1306"},{"mucCt":"vua","text":"Tộc trưởng Vân Độn tộc bị Vương Lâm phát hiện từng cố tình dẫn mũi dùi về phía hắn. Theo lệnh xử phạt, hắn dùng song chỉ điểm lên vai trái làm đứt kinh mạch tay trái rồi nhận lỗi.","anchor":"Tự chặt một tay, kẻ dưới trướng ta cũng không phải ngoại lệ","bridge":true,"khoang":"@c1307"}],"tuViMoc":[],"nhanMach":[{"ten":"Chung Đại Hồng","tag":"khac","quanHe":"Người hắn buộc phải hạ mình hầu hạ và dâng lễ vì sợ chủ nhân của đối phương.","ghiChu":"Dù tu vi cao hơn, hắn vẫn phải nhún nhường trước uy danh Vương Lâm."},{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Từng mời làm cung phụng của Vân Độn tộc.","ghiChu":"Việc này khiến Vân Độn tộc bị các tộc khác chú ý trong kỳ tuyển chọn."},{"ten":"Đại trưởng lão Hồn Xà tộc","tag":"doi-thu","quanHe":"Bị đối phương khơi chuyện để kéo vào tranh chấp.","ghiChu":"Hồn Xà tộc từng giao chiến với Vân Độn tộc trong một lần tuyển chọn trưởng lão."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị xử phạt","ghiChu":"Bị Vương Lâm buộc tự chặt một tay vì âm thầm dẫn họa về phía hắn."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Bình ngọc của tộc trưởng Vân Độn tộc","loai":"lễ vật / bình ngọc","trangThai":"mat","moTa":"Bình ngọc được hắn lấy ra dâng cho Chung Đại Hồng làm hậu lễ.","nguon":"@c1300"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1300","@c1306","@c1307"]},{"id":"nam-tu-hoa-tuoc-toc-mang-mau-trong-dan-duoc","name":"Nam tử Hỏa Tước tộc mang máu trong đan dược","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1301","trangThai":"song","blurb":"Tộc nhân Hỏa Tước tộc được giao mang máu trong đan dược về tộc nghiên cứu. Hắn coi nhiệm vụ này là cực kỳ trọng yếu và không được phép sai sót.","vaiTro":"Người mang mồi máu về Hỏa Tước tộc","tinhCach":[{"text":"Thận trọng với nhiệm vụ trọng yếu","chuong":"@c1301"},{"text":"Kiên định khi hộ tống vật quan trọng","chuong":"@c1301"}],"tabs":{"diem":[{"text":"Được trưởng lão giao đưa máu trong đan dược về Hỏa Tước tộc nghiên cứu.","chuong":"@c1301"},{"text":"Tin rằng nếu phân tích đúng, tộc trưởng và các đại trưởng lão sẽ ra lệnh tiếp theo.","chuong":"@c1301"}],"kinhLich":[{"mucCt":"vua","text":"Nam tử Hỏa Tước tộc cùng hai tộc nhân rời vùng đất Điên Lạc, bay qua tinh vực Lạo Hắc tinh để đưa máu trong đan dược về tộc nghiên cứu. Hắn nhấn mạnh nhiệm vụ này cực kỳ trọng yếu và tuyệt đối không thể sai lầm.","anchor":"Việc này đối với tộc ta cực kỳ trọng yếu, tuyệt đối không thể có sai lầm","bridge":true,"khoang":"@c1301"}],"tuViMoc":[],"nhanMach":[{"ten":"Hai tộc nhân Hỏa Tước tộc đi cùng nam tử mang máu","tag":"dong-minh","quanHe":"đồng hành hộ tống","ghiChu":"Cùng tăng tốc đưa máu trong đan dược về Hỏa Tước tộc."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị dùng làm mắt xích kế hoạch","ghiChu":"Mang theo giọt máu mà Vương Lâm dùng làm mồi nhắm vào Hỏa Tước tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Hồn đan chứa máu bổn nguyên của Vương Lâm","trangThai":"dang-co","moTa":"Mang máu trong đan dược về Hỏa Tước tộc theo lệnh trưởng lão.","nguon":"@c1301"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1301"]},{"id":"hai-toc-nhan-hoa-tuoc-toc-di-cung-nam-tu-mang-mau","name":"Hai tộc nhân Hỏa Tước tộc đi cùng nam tử mang máu","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1301","trangThai":"song","blurb":"Hai tộc nhân Hỏa Tước tộc hộ tống nam tử mang máu trong đan dược. Họ cùng tăng tốc rời đi qua tinh vực Lạo Hắc tinh.","vaiTro":"Người hộ tống máu trong đan dược","tinhCach":[{"text":"Làm theo nhiệm vụ hộ tống của tộc","chuong":"@c1301"},{"text":"Ít lời, phối hợp với người dẫn đầu","chuong":"@c1301"}],"tabs":{"diem":[{"text":"Cùng nam tử Hỏa Tước tộc bay qua tinh vực Lạo Hắc tinh để đưa máu về tộc.","chuong":"@c1301"}],"kinhLich":[{"chuong":"@c1301","importance":"bridge","mucCt":"gon","tieuDe":"Hộ tống máu về tộc","text":"Hai tộc nhân Hỏa Tước tộc đi cùng nam tử mang máu, tăng tốc rời đi để đưa máu trong đan dược về tộc.","anchor":"Ánh mắt nam tử lộ vẻ kiên định, cùng với hai người bên cạnh tăng tốc"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam tử Hỏa Tước tộc mang máu trong đan dược","tag":"dong-minh","quanHe":"đồng hành hộ tống","ghiChu":"Cùng thực hiện nhiệm vụ đưa máu trong đan dược về Hỏa Tước tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1301"]},{"id":"dao-van","name":"Đào Vân","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Người được ngân y nữ tử nhắc trong ký ức hoảng loạn về biến cố cánh cửa. Chương này chỉ cho biết Đào Vân đã chết.","vaiTro":"Nạn nhân trong ký ức đứt đoạn của ngân y nữ tử.","tinhCach":[],"tabs":{"diem":[{"text":"Được nêu tên cùng Tử Lạc trong lời lẩm bẩm của ngân y nữ tử về những người đã chết.","chuong":"@c1303"}],"kinhLich":[{"mucCt":"gon","anchor":"Đào Vân đã chết.Tử Lạc cũng đã chết.chết hết rồi","text":"Đào Vân được ngân y nữ tử nhắc là đã chết trong biến cố liên quan đến cánh cửa.","bridge":true,"khoang":"@c1303"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Ngân Y Luyện Thi","tag":"khac","quanHe":"người nhắc đến cái chết của Đào Vân","ghiChu":"Ngân y nữ tử nêu tên Đào Vân khi ký ức sợ hãi bị pho tượng kích phát."},{"ten":"Tử Lạc","tag":"khac","quanHe":"cùng được nhắc là đã chết","ghiChu":"Hai người được ngân y nữ tử nhắc liền nhau trong cùng lời lẩm bẩm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1303"]},{"id":"tu-lac","name":"Tử Lạc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Người được ngân y nữ tử nhắc cùng Đào Vân trong ký ức hoảng loạn. Chương này chỉ cho biết Tử Lạc đã chết.","vaiTro":"Nạn nhân trong ký ức đứt đoạn của ngân y nữ tử.","tinhCach":[],"tabs":{"diem":[{"text":"Được nêu tên cùng Đào Vân trong lời lẩm bẩm của ngân y nữ tử về những người đã chết.","chuong":"@c1303"}],"kinhLich":[{"mucCt":"gon","anchor":"Đào Vân đã chết.Tử Lạc cũng đã chết.chết hết rồi","text":"Tử Lạc được ngân y nữ tử nhắc là đã chết trong biến cố liên quan đến cánh cửa.","bridge":true,"khoang":"@c1303"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Ngân Y Luyện Thi","tag":"khac","quanHe":"người nhắc đến cái chết của Tử Lạc","ghiChu":"Ngân y nữ tử nêu tên Tử Lạc khi ký ức sợ hãi bị pho tượng kích phát."},{"ten":"Đào Vân","tag":"khac","quanHe":"cùng được nhắc là đã chết","ghiChu":"Hai người được ngân y nữ tử nhắc liền nhau trong cùng lời lẩm bẩm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1303"]},{"id":"thap-tam","name":"Thập Tam","cn":"","aliases":["Mười Ba"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Kính Thập Tam là thanh niên trời sinh ngộ tính với Luyện Hồn Yêu Thuật, chỉ ba tháng đã đạt giai đoạn ba và được Vương Lâm thu nhận làm đại đệ tử. Sau khi bị phế tu vi, gã không cam lòng mà mỗi đêm chịu đau thổ nạp luyện thể theo pháp Cự Ma Tộc, dần khôi phục sức mạnh, nhận truyền thừa Cự Linh Cửu Tu rồi quỳ đập đầu tôn Vương Lâm làm Lão tổ, về sau trở thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, được rèn thân thể bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ mà khổ","vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn tại Thiên Vận Tinh","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, quỳ bái Vương Lâm làm Lão tổ và ngồi canh tượng đá suốt nghìn ngày đêm; cảnh giác điềm tĩnh trong hiểm cảnh","tabs":{"diem":[{"text":"Trời sinh ngộ tính, tu luyện Luyện Hồn Yêu Thuật ba tháng đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi thành người tàn phế, không cam lòng, mỗi đêm chịu đau thổ nạp tự phát luyện thể theo pháp Cự Ma Tộc","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu từ Vương Lâm, kích động quỳ đập đầu thề cả đời tôn Vương Lâm làm Lão tổ","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm trên đỉnh núi suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu chờ sư tôn","chuong":"@c1018"},{"text":"Là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ khổ tìm sư tôn khắp tinh vực","chuong":"@c1440"},{"text":"Quỳ trên hư không bái biệt sư tôn, thề dù ký ức bị phong ấn vẫn không quên ân truyền thụ, tự nguyện bước vào luân hồi chuyển thế","chuong":"@c1697"}],"kinhLich":[{"mucCt":"vua","anchor":"Cổ Yêu thì là một tia tàn hồn do bộ tộc của Mười Ba cúng bái","text":"Vương Lâm nhớ lại phân thân Cổ Yêu của mình bắt nguồn từ một tia tàn hồn được bộ tộc của Thập Tam cúng bái. Hương hỏa của bộ tộc ấy khiến Cổ Yêu tin rằng hắn là Vương Lâm.","bridge":true,"khoang":"@c1303"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1303"]},{"id":"trung-nien-ao-bay-mau-trong-thuc-hai-ngan-y-nu-tu","name":"Trung niên áo bảy màu trong thức hải ngân y nữ tử","cn":"","aliases":["thân ảnh áo bảy màu"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Thân ảnh do phong ấn biến thành, ngồi sâu trong sương xanh ở thức hải ngân y nữ tử. Người này giống hệt pho tượng bí ẩn nhưng chưa được xác nhận là Chưởng Tôn hay bất cứ nhân vật đã biết nào.","vaiTro":"Đầu mối trung tâm của bí mật bảy màu và biến cố cánh cửa trong ký ức ngân y nữ tử.","tinhCach":[],"tabs":{"diem":[{"text":"Xuất hiện dưới dạng thân ảnh áo bảy màu ngồi đả tọa sâu trong thức hải ngân y nữ tử.","chuong":"@c1303"},{"text":"Không phải nguyên thần hay thực thể, mà do một đạo phong ấn biến thành.","chuong":"@c1303"},{"text":"Giống hệt pho tượng khiến ngân y nữ tử sợ hãi cực độ.","chuong":"@c1303"}],"kinhLich":[{"mucCt":"vua","anchor":"Người này mặc áo bảy màu, vẻ ngoài là một trung niên đang khoanh chân ngồi","text":"Khi Vương Lâm Sưu thần ngân y nữ tử, hắn nhìn thấy sâu trong sương mù xanh một trung niên áo bảy màu đang khoanh chân ngồi. Thân ảnh này giống hệt pho tượng, không phải nguyên thần hay thực thể mà là do một đạo phong ấn biến thành, khiến Vương Lâm thoáng nghi là Chưởng Tôn rồi lập tức bác bỏ.","bridge":true,"khoang":"@c1303"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Ngân Y Luyện Thi","tag":"khac","quanHe":"thân ảnh phong ấn trong thức hải","ghiChu":"Thân ảnh áo bảy màu nằm sâu trong thức hải ngân y nữ tử và liên quan trực tiếp đến nỗi sợ do pho tượng kích phát."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người phát hiện qua Sưu thần","ghiChu":"Vương Lâm phát hiện thân ảnh này khi mạo hiểm dò sâu vào thức hải ngân y nữ tử."},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"bị liên hệ rồi bác bỏ","ghiChu":"Vương Lâm thoáng nghĩ thân ảnh này là Chưởng Tôn nhưng lập tức loại bỏ, nên chưa thể gộp hai thực thể."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1303"]},{"id":"truong-lao-thu-chin-lac-sinh-hoi","name":"Trưởng lão thứ chín của Lạc Sinh hội","gioiTinh":"khong-ro","theLuc":[{"ten":"Lạc Sinh hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Trưởng lão thứ chín của Lạc Sinh hội có mặt tại thánh địa Long Giáp Tộc. Khi tiếng nói từ hư vô vang lên, người này nhận ra uy danh Đại đế và kinh hô.","vaiTro":"Trưởng lão Lạc Sinh hội, nhân vật xác nhận danh xưng Đại đế trong chương.","tinhCach":[{"text":"Nhạy với uy thế của Đại đế, lập tức biến sắc khi tiếng nói từ hư vô xuất hiện.","chuong":"@c1291"}],"tabs":{"diem":[{"text":"Có mặt ở thánh địa Long Giáp Tộc trong lúc trận chiến giữa Vương Lâm và Tư Mặc Tử diễn ra.","chuong":"@c1291"},{"text":"Là người kinh hô Đại đế khi tiếng nói từ hư vô truyền tới tu chân tinh.","chuong":"@c1291"},{"text":"Có mặt ở thánh địa Long Giáp Tộc khi Đại đế can thiệp trận chiến.","chuong":"@c1291"},{"text":"Là người kinh hô danh xưng Đại đế, cho thấy biết rõ uy danh của tồn tại này.","chuong":"@c1291"}],"kinhLich":[{"chuong":"@c1291","importance":"normal","mucCt":"vua","tieuDe":"Kinh hô Đại đế","text":"Trưởng lão thứ chín của Lạc Sinh hội đang ở thánh địa Long Giáp Tộc khi tiếng nói từ hư vô vang lên. Người này lập tức biến sắc và kinh hô Đại đế, xác nhận uy danh của kẻ vừa can thiệp.","anchor":"trưởng lão thứ chín của Lạc Sinh hội sắc mặt đại biến"}],"tuViMoc":[],"nhanMach":[{"ten":"Đại đế","tag":"khac","quanHe":"người được nhận ra danh xưng","ghiChu":"Kinh hô Đại đế khi tiếng nói từ hư vô can thiệp."},{"ten":"Tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"người cùng có mặt tại thánh địa","ghiChu":"Cùng hiện diện trong thánh địa Long Giáp Tộc khi biến cố xảy ra."},{"ten":"Thiếu tộc trưởng Long Giáp Tộc","tag":"khac","quanHe":"người cùng có mặt tại thánh địa","ghiChu":"Cùng hiện diện khi Đại đế lên tiếng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1291"]},{"id":"truong-lao-hoa-tuoc-toc-tung-giao-dich-voi-vuong-lam","name":"Trưởng lão Hỏa Tước tộc từng giao dịch với Vương Lâm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1304","trangThai":"song","blurb":"Trưởng lão Hỏa Tước tộc đóng tại vùng đất Điên Lạc, từng có giao dịch với Vương Lâm. Khi dị biến lam hỏa bộc phát, ông bị hỏa lực trong thân ảnh hưởng mạnh và sau đó dẫn người đi truy xét.","vaiTro":"Trưởng lão Hỏa Tước tộc tại Điên Lạc","tinhCach":[{"text":"Nhạy bén với khí tức bổn nguyên liên quan hỏa lực","chuong":"@c1304"},{"text":"Chủ động truy xét dị biến của tộc","chuong":"@c1304"}],"tabs":{"diem":[{"text":"Bị dị biến lam hỏa làm hỏa diễm toàn thân hóa thành hỏa điểu như muốn bay đi.","chuong":"@c1304"},{"text":"Tại tinh cầu hoang dã, ông cảm nhận được khí tức bổn nguyên giống trong hồn đan từng giao dịch.","chuong":"@c1304"}],"kinhLich":[{"mucCt":"vua","text":"Đang đả tọa ở vùng đất Điên Lạc, trưởng lão Hỏa Tước tộc từng giao dịch với Vương Lâm bị dị biến lam hỏa tác động khiến hỏa diễm toàn thân hóa thành hỏa điểu như muốn rời thân. Sau đó ông dẫn tộc nhân tới tinh cầu hoang dã truy xét, không tìm được vật gì nhưng cảm nhận được một tia bổn nguyên giống trong hồn đan.","anchor":"Trưởng lão Hỏa Tước tộc trước đây giao dịch với Vương Lâm vốn đang ngồi đả tọa","bridge":true,"khoang":"@c1304"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Từng giao dịch","ghiChu":"Ông từng giao dịch với Vương Lâm và qua đó biết khí tức bổn nguyên trong hồn đan."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Hồn đan","loai":"đan/vật chứa bổn nguyên","trangThai":"khong-ro","moTa":"Từng giúp ông nhận ra khí tức bổn nguyên tương tự tại tinh cầu hoang dã.","nguon":"@c1304"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1304"]},{"id":"ba-toc-nhan-hoa-tuoc-toc-tu-vung-dat-dien-lac","name":"Ba tộc nhân Hỏa Tước tộc từ vùng đất Điên Lạc","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1304","trangThai":"song","blurb":"Ba tộc nhân Hỏa Tước tộc từ vùng đất Điên Lạc hộ tống một vật lạ trở về tộc. Vật họ nộp lên khiến cao tầng Hỏa Tước tộc chấn động vì được xác nhận là máu Chu Tước có bổn nguyên.","vaiTro":"Người hộ tống vật lạ","tinhCach":[{"text":"Cẩn trọng khi nộp vật lạ lên tộc","chuong":"@c1304"},{"text":"Lo lắng trước phản ứng của cao tầng","chuong":"@c1304"}],"tabs":{"diem":[{"text":"Hộ tống một vật từ vùng đất Điên Lạc trở về Hỏa Tước tộc.","chuong":"@c1304"},{"text":"Vật họ mang về trở thành đầu mối khiến Hỏa Tước tộc phát tộc mệnh truy tìm nguồn gốc.","chuong":"@c1304"}],"kinhLich":[{"mucCt":"vua","text":"Ba tộc nhân từ vùng đất Điên Lạc hộ tống một vật trở về Hỏa Tước tộc ở Thái Cổ Tinh Thần. Sau khi nộp lên, họ được triệu kiến và lo lắng không biết vật ấy có được tộc mình coi trọng hay không.","anchor":"Ba người từ vùng đất Điên Lạc hộ tống trở về một vật","bridge":true,"khoang":"@c1304"}],"tuViMoc":[],"nhanMach":[{"ten":"Tộc trưởng Hỏa Tước tộc","tag":"cap-tren","quanHe":"Cấp trên tiếp nhận vật","ghiChu":"Họ nộp vật được hộ tống từ Điên Lạc lên cho tộc trưởng xem xét."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Giọt máu Chu Tước có bổn nguyên","loai":"huyết vật","trangThai":"da-nop","moTa":"Vật được họ hộ tống từ vùng đất Điên Lạc về Hỏa Tước tộc.","nguon":"@c1304"}],"linhThao":[],"khac":[]}},"nguon":["@c1304"]},{"id":"toc-truong-hoa-tuoc-toc","name":"Tộc trưởng Hỏa Tước tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1304","trangThai":"song","blurb":"Tộc trưởng Hỏa Tước tộc tọa trấn đại điện dưới pho tượng Hỏa Tước trên chủ tinh Hỏa Tước. Khi nhận ra giọt máu có bổn nguyên, ông lập tức vào thánh địa cầu kiến lão tổ và nhận lệnh truy tìm nguồn gốc giọt máu tại Điên Lạc.","vaiTro":"Tộc trưởng Hỏa Tước tộc","tinhCach":[{"text":"Quyết đoán khi phát hiện vật có bổn nguyên","chuong":"@c1304"},{"text":"Kính sợ quy củ thánh địa và lão tổ","chuong":"@c1304"},{"text":"Sẵn sàng chấp hành tộc mệnh truy tìm nguồn gốc giọt máu","chuong":"@c1304"}],"tabs":{"diem":[{"text":"Nhận ra giọt máu được đưa về có bổn nguyên nên vào thánh địa cầu kiến lão tổ.","chuong":"@c1304"},{"text":"Được lão tổ khen ngợi sau khi giọt máu được xác nhận là máu Chu Tước.","chuong":"@c1304"},{"text":"Được giao nhiệm vụ phát tộc mệnh tới vùng đất Điên Lạc truy tìm nguồn gốc.","chuong":"@c1304"}],"kinhLich":[{"mucCt":"ky","text":"Ở đại điện dưới pho tượng Hỏa Tước trên chủ tinh Hỏa Tước, tộc trưởng Hỏa Tước tộc tiếp nhận vật do ba tộc nhân từ Điên Lạc hộ tống về và nhận ra giọt máu đang thiêu đốt có bổn nguyên. Ông lập tức vào thánh địa sâu trong chủ tinh cầu kiến lão tổ, ban đầu bị trách phạt vì tự tiện xông vào. Sau khi lão tổ xác nhận đó là máu Chu Tước, ông được đổi thái độ khen ngợi và nhận lệnh phát tộc mệnh không tiếc giá nào truy tìm nguồn gốc giọt máu tại vùng đất Điên Lạc.","anchor":"Hắn chính là tộc trưởng Hỏa Tước tộc","bridge":true,"khoang":"@c1304"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tổ Hỏa Tước tộc","tag":"cap-tren","quanHe":"Lão tổ trong tộc","ghiChu":"Tộc trưởng vào thánh địa cầu kiến và nhận tộc mệnh từ lão tổ."},{"ten":"Ba tộc nhân Hỏa Tước tộc từ vùng đất Điên Lạc","tag":"khac","quanHe":"Tộc nhân nộp vật","ghiChu":"Ba tộc nhân mang vật từ Điên Lạc về để tộc trưởng xem xét."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Giọt máu Chu Tước có bổn nguyên","loai":"huyết vật","trangThai":"da-chuyen","moTa":"Được tộc trưởng dâng lên lão tổ trong thánh địa để xác minh.","nguon":"@c1304"}],"linhThao":[],"khac":[]}},"nguon":["@c1304"]},{"id":"lao-to-hoa-tuoc-toc","name":"Lão tổ Hỏa Tước tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1304","trangThai":"song","blurb":"Lão tổ Hỏa Tước tộc là cường giả bước thứ ba giới ngoại, tu luyện ẩn cư trong biển lửa tím nơi thánh địa chủ tinh Hỏa Tước. Ông từng rời thánh địa truy tìm nguồn gốc huyết mạch Chu Tước tại Điên Lạc, bắt Lưu Kim Bưu đưa về kiểm chứng nhưng bị lừa nhận giả Chu Tước, sau đó còn bị trọng thương khi cánh cửa thánh địa sụp đổ. Trong cuộc đại chiến phá Phong Giới Đại Trận, ông dẫn đầu giới ngoại xông trận, hợp chiến Hồng Sam Tử cùng bốn tu sĩ bước thứ ba khác, và là người đầu tiên thoát khỏi vòng cầm chân nhưng bị Khai Thiên Phủ chẻ đôi tử trận.","vaiTro":"Lão tổ Hỏa Tước tộc — cao thủ bước thứ ba giới ngoại, trưởng bối tối cao của Hỏa Tước tộc","tinhCach":"Uy nghiêm và nghiêm khắc với tộc nhân; cẩn trọng đa nghi khi kiểm chứng huyết mạch Chu Tước; sát phạt quyết đoán trên chiến trường; trung thành tuyệt đối với tộc ấn và sứ mệnh Hỏa Tước tộc","tabs":{"diem":[{"text":"Tu luyện trong biển lửa tím thánh địa chủ tinh Hỏa Tước, trách phạt tộc trưởng vì tự ti, thể hiện uy nghiêm trưởng bối","chuong":"@c1304"},{"text":"Truy tìm huyết mạch Chu Tước tại Điên Lạc, bắt Lưu Kim Bưu và kiểm tra nhiều lần nhưng bị lừa nhận giả Chu Tước","chuong":"@c1335"},{"text":"Thi triển Súc Địa Thành Thốn mang Lưu Kim Bưu về thánh địa, quỳ gối trước cánh cửa hư ảo gọi chủ","chuong":"@c1337"},{"text":"Bị mảnh vỡ cánh cửa thánh địa sụp đổ đâm trúng, phun máu trọng thương","chuong":"@c1340"},{"text":"Dẫn đầu giới ngoại xông vào khe Phong Giới Đại Trận, phóng tộc ấn Hỏa Tước Tộc hóa hỏa điểu đen","chuong":"@c1425"},{"text":"Tử trận khi bị Khai Thiên Phủ chẻ đôi — là người đầu tiên thoát vòng cầm chân Hồng Sam Tử, toàn thân bao phủ ngọn lửa đen","chuong":"@c1431"}],"kinhLich":[{"mucCt":"ky","text":"Trong thánh địa biển lửa tím của chủ tinh Hỏa Tước, lão tổ Hỏa Tước tộc ban đầu trách phạt tộc trưởng vì tự tiện xông vào. Sau khi xem xét giọt máu, ông chấn động, nhiều lần kiểm tra rồi xác nhận đó là máu Chu Tước có bổn nguyên. Ông lập tức gọi tộc trưởng quay lại, đổi thái độ khen ngợi và ra lệnh Hỏa Tước tộc không tiếc giá nào tới vùng đất Điên Lạc tìm nguồn gốc, đồng thời dặn phải xem xét khả năng có âm mưu.","anchor":"Vãn bối cầu kiến lão tổ","bridge":true,"khoang":"@c1304"}],"tuViMoc":[],"nhanMach":[{"ten":"Tộc trưởng Hỏa Tước tộc","tag":"cap-tren","quanHe":"Lão tổ và tộc trưởng","ghiChu":"Lão tổ trách phạt, sau đó khen ngợi và giao tộc mệnh cho tộc trưởng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Giọt máu Chu Tước có bổn nguyên","loai":"huyết vật","trangThai":"dang-xem-xet","moTa":"Được lão tổ xác nhận là máu Chu Tước có bổn nguyên.","nguon":"@c1304"}],"linhThao":[],"khac":[]}},"nguon":["@c1304"]},{"id":"ma-hon-nho-be-cua-vuong-lam","name":"Ma hồn nhỏ bé của Vương Lâm","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Vương Lâm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1305","trangThai":"song","blurb":"Ma hồn đỏ sậm giống hệt Vương Lâm, được tạo ra trong động phủ trên tu chân tinh Ám Hạt Tộc. Nó hút sạch ma khí, phản nghịch rồi bị Vương Lâm trấn áp và ép dung nhập Vụ Ma Thương.","vaiTro":"Nền móng phân thân ma hồn","tinhCach":[{"text":"Bạo ngược sau khi thôn phệ ma khí","chuong":"@c1305"},{"text":"Bị ấn ký của Vương Lâm áp chế","chuong":"@c1305"}],"tabs":{"diem":[{"text":"Có hình dáng giống Vương Lâm và hấp thu lượng lớn ma khí quanh động phủ.","chuong":"@c1305"},{"text":"Từng sinh ý định thôn phệ cả người sáng tạo ra mình.","chuong":"@c1305"},{"text":"Bị cưỡng ép dung nhập Vụ Ma Thương, trở thành cơ sở của phân thân ma hồn.","chuong":"@c1305"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người sáng tạo và khống chế","ghiChu":"Bị Vương Lâm trấn áp khi phản nghịch."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"]},{"id":"nam-tu-trung-nien-di-cung-van-lac","name":"Nam tử trung niên đi cùng Vân Lạc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Trường Tôn hội","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không rõ @c1305","trangThai":"song","blurb":"Nam tử trung niên xuất hiện cạnh Vân Lạc ngoài vùng đất Điên Lạc. Phân thân của hắn từng bị Điên Lạc đại đế giết, khiến hắn chất vấn cách Trường Tôn hội xử lý.","vaiTro":"Người đồng hành của Vân Lạc","tinhCach":[{"text":"Âm trầm khi nhắc tới phân thân bị giết","chuong":"@c1305"},{"text":"Trực tiếp chất vấn Trường Tôn hội","chuong":"@c1305"}],"tabs":{"diem":[{"text":"Có phân thân từng bị Điên Lạc đại đế giết.","chuong":"@c1305"},{"text":"Đi cùng Vân Lạc trên đồ án bát giác ngoài vùng đất Điên Lạc.","chuong":"@c1305"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vân Lạc","tag":"dong-minh","quanHe":"Đồng hành","ghiChu":"Cùng xuất hiện ngoài vùng đất Điên Lạc và trao đổi về Trường Tôn hội."},{"ten":"Điên Lạc đại đế","tag":"doi-thu","quanHe":"Người từng giết phân thân","ghiChu":"Phân thân của hắn bị Điên Lạc đại đế giết."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"]},{"id":"lieu-thien-cuu","name":"Liêu Thiên Cửu","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lam Mộng Đạo Tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1305","trangThai":"song","blurb":"Liêu Thiên Cửu xuất hiện phía sau Lam Mộng Đạo Tôn trong Thái Cổ Tinh Thần. Chương này chỉ ghi nhận y yên lặng đi theo trên đường tới vùng sự kiện.","vaiTro":"Người theo sau Lam Mộng Đạo Tôn","tinhCach":[{"text":"Trầm lặng khi đi theo Lam Mộng Đạo Tôn","chuong":"@c1305"},{"text":"Chưa bộc lộ hành động riêng","chuong":"@c1305"}],"tabs":{"diem":[{"text":"Đi sau Lam Mộng Đạo Tôn trong Thái Cổ Tinh Thần.","chuong":"@c1305"},{"text":"Giữ thái độ yên lặng trong lần xuất hiện này.","chuong":"@c1305"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"dong-minh","quanHe":"Đi theo","ghiChu":"Xuất hiện phía sau Lam Mộng Đạo Tôn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"]},{"id":"lao-gia-ao-trang-tren-lung-vong-nguyet","name":"Lão giả áo trắng trên lưng Vọng Nguyệt","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1305","trangThai":"song","blurb":"Lão giả mặc trường bào trắng, có gương mặt quỷ dị phân rõ hai nửa đen trắng như âm dương. Ông đứng trên lưng Vọng Nguyệt cùng ba người hầu chưa rõ thân phận thế lực.","vaiTro":"Cường giả bí ẩn trên lưng Vọng Nguyệt","tinhCach":[{"text":"Thân phận và mục đích chưa được nói rõ","chuong":"@c1305"},{"text":"Khí chất quỷ dị qua tướng mạo phân âm dương","chuong":"@c1305"}],"tabs":{"diem":[{"text":"Xuất hiện trên lưng Vọng Nguyệt trong tinh vực vắng người.","chuong":"@c1305"},{"text":"Có ba người hầu đứng phía sau, gồm những người Vương Lâm sẽ nhận ra.","chuong":"@c1305"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vọng Nguyệt","tag":"khac","quanHe":"Đứng trên lưng","ghiChu":"Xuất hiện trên lưng Vọng Nguyệt."},{"ten":"Nhất Mộc Tử","tag":"khac","quanHe":"Người hầu phía sau","ghiChu":"Đứng trong nhóm ba người hầu."},{"ten":"Vũ Đông Thiện","tag":"khac","quanHe":"Người hầu phía sau","ghiChu":"Đứng trong nhóm ba người hầu."},{"ten":"Cực Hiền Thiên","tag":"khac","quanHe":"Người hầu phía sau","ghiChu":"Đứng trong nhóm ba người hầu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"]},{"id":"nhat-moc-tu","name":"Nhất Mộc Tử","trangThai":"song","tabs":{"diem":[],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lão giả áo trắng trên lưng Vọng Nguyệt","tag":"khac","quanHe":"Người hầu","ghiChu":"Đứng phía sau lão giả áo trắng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"]},{"id":"vu-dong-thien","name":"Võ Đông Thiện","aliases":["Vũ Đông Thiện"],"trangThai":"song","tabs":{"diem":[{"text":"Được nữ nhân váy lam mời ra, cuồng ngạo thách đấu Viêm Lôi Tử giữa tinh không","chuong":"@c0865"},{"text":"Cắn răng lao vào miệng Vọng Nguyệt, truy đuổi và triền đấu Nhất Mộc Tử trong thông đạo bên trong thân thể Vọng Nguyệt","chuong":"@c0878"},{"text":"Bị Cực Hiền Thiên đánh lõm ngực, tu vi giảm thảm hại, nhưng vẫn góp phần tiêu diệt Cực Hiền Thiên","chuong":"@c0880"},{"text":"Nhớ sách cổ Liên Minh Tu Chân ghi về Vọng Nguyệt, nhắm đoạt Nguyệt Hoa bên trong","chuong":"@c0882"},{"text":"Được Âm Dương lão nhân đẩy vào cơ thể Vọng Nguyệt, cùng đồng bạn tiến vào cổ mộ trong sương mù","chuong":"@c1345"},{"text":"Đứng trên đầu Vọng Nguyệt cùng đồng bạn cảnh giác quan sát, chờ Vọng Nguyệt phá cấm chế","chuong":"@c1386"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lão giả áo trắng trên lưng Vọng Nguyệt","tag":"khac","quanHe":"Người hầu","ghiChu":"Đứng phía sau lão giả áo trắng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"],"vaiTro":"Cường giả bí ẩn phía Liên Minh Tu Chân, đối thủ Viêm Lôi Tử","tinhCach":"Cuồng ngạo, chủ động thách đấu cường giả; quyết liệt tranh đoạt cơ duyên; lâm nguy vẫn chống đỡ dai dẳng","blurb":"Võ Đông Thiện là cường giả bí ẩn được nữ nhân váy lam mời ra từ đám mây đen để thách đấu Viêm Lôi Tử, từng giao chiến kinh thiên động địa giữa tinh không. Sau trận chiến, hắn cắn răng lao vào cơ thể Vọng Nguyệt, nhiều lần triền đấu Nhất Mộc Tử và bị thương nặng nhưng vẫn góp sức diệt Cực Hiền Thiên. Về sau hắn được Âm Dương lão nhân phái vào cổ mộ cùng Cực Hiền Thiên và Vọng Nguyệt, đứng trên đầu Vọng Nguyệt cảnh giác quan sát chờ phá cấm chế."},{"id":"cuc-hien-thien","name":"Cực Hiền Thiên","trangThai":"khong-ro","tabs":{"diem":[{"text":"Ẩn trong khe nứt tinh không, bị Viêm Lôi Tử điểm chỉ ép lộ diện","chuong":"@c0863"},{"text":"Bại trận trước Viêm Lôi Tử, mất toàn bộ 13 tầng Lam ý","chuong":"@c0864"},{"text":"Tự bạo bốn tầng Lam ý, bị thuật định thân và Vọng Nguyệt nuốt chửng","chuong":"@c0865"},{"text":"Lộ bản chất Cổ Thần Khôi Lỗi — dung hợp nhất tinh Cổ Thần khi bị phun ra từ mắt Vọng Nguyệt","chuong":"@c0879"},{"text":"Bị tiêu diệt hoàn toàn, mất lực lượng truyền thừa","chuong":"@c0880"},{"text":"Bị Âm Dương lão nhân đẩy từ mi tâm vào cơ thể Vọng Nguyệt, cùng tiến vào sương mù cổ mộ","chuong":"@c1345"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lão giả áo trắng trên lưng Vọng Nguyệt","tag":"khac","quanHe":"Người hầu","ghiChu":"Đứng phía sau lão giả áo trắng dù từng được nêu là đã tử vong."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1305"],"vaiTro":"Tứ Tôn của Tu Chân Liên Minh — Cổ Thần Khôi Lỗi dung hợp nhất tinh Cổ Thần","tinhCach":"Ẩn nhẫn chờ thời; quyết liệt cầu sinh; hung hãn trong giao chiến","blurb":"Cực Hiền Thiên, tức Hiền Tôn, là một trong Tứ Tôn của Tu Chân Liên Minh, tu vi Toái Niết trung kỳ nhưng không đủ tư cách vào Trưởng Lão Đoàn. Bản chất thực là Cổ Thần Khôi Lỗi dung hợp nhất tinh Cổ Thần, hắn ẩn trong khe nứt tinh không cho đến khi bị Viêm Lôi Tử ép lộ diện, trải qua nhiều trận bại rồi bị Vọng Nguyệt nuốt chửng, cuối cùng bị tiêu diệt và mất toàn bộ lực lượng truyền thừa."},{"id":"toc-truong-am-hat-toc","name":"Tộc trưởng Ám Hạt Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ám Hạt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Tộc trưởng Ám Hạt Tộc là người dẫn tộc hộ tống Vương Lâm tới ngoài Đại đế tinh trong kỳ tuyển chọn trưởng lão Lạc Sinh hội. Ông hiểu rõ quy tắc tiến vào Đại đế tinh và chứng kiến tộc trưởng Hà tộc chọn nhầm đối tượng lập uy.","vaiTro":"Tộc trưởng Ám Hạt Tộc","tinhCach":[{"text":"thận trọng quan sát tình thế","chuong":"@c1306"},{"text":"kính sợ uy thế của Vương Lâm","chuong":"@c1306"}],"tabs":{"diem":[{"text":"Đứng cạnh Vương Lâm và thấp giọng giải thích tình hình Đại đế tinh.","chuong":"@c1306"},{"text":"Khi Hà tộc chỉ sang Vương Lâm, ông lộ nụ cười trào phúng vì biết đối phương đang tự chuốc họa.","chuong":"@c1306"}],"kinhLich":[{"mucCt":"vua","text":"Tộc trưởng Ám Hạt Tộc hộ tống Vương Lâm tới ngoài Đại đế tinh, giải thích quy tắc thông đạo và giới thiệu Hồn Xà tộc, Hà tộc. Khi bị trưởng lão thứ mười ba làm nhục, ông biến sắc nhưng lập tức châm chọc khi đối phương chuyển sang ép Vương Lâm quỳ.","anchor":"Tộc trưởng Ám Hạt Tộc đứng bên cạnh Vương Lâm thấp giọng nói","bridge":true,"khoang":"@c1306"},{"mucCt":"gon","text":"Tộc trưởng Ám Hạt Tộc được Vương Lâm đề nghị đưa thành trưởng lão Lạc Sinh hội, và đề nghị này được sứ giả đại đế chấp thuận.","anchor":"Tộc trưởng Ám Hạt Tộc không tồi. Ta muốn cho hắn thành trưởng lão Lạc Sinh hội","bridge":true,"khoang":"@c1308"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Hộ tống và kính cẩn đứng bên cạnh Vương Lâm.","ghiChu":"Biết uy thế của Vương Lâm nên trào phúng khi Hà tộc đụng tới hắn."},{"ten":"Tộc trưởng Hà tộc","tag":"doi-thu","quanHe":"Bị đối phương công khai ép quỳ để lập uy.","ghiChu":"Mâu thuẫn diễn ra trước khi thông đạo Đại đế tinh mở."},{"ten":"Tộc trưởng Vân Độn tộc","tag":"dong-minh","quanHe":"Cùng hộ tống Vương Lâm tới kỳ tuyển chọn.","ghiChu":"Hai tộc cùng bị Hồn Xà tộc và Hà tộc nhắm vào."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1306","@c1308"]},{"id":"dai-truong-lao-hon-xa-toc","name":"Đại trưởng lão Hồn Xà tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hồn Xà tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Đại trưởng lão Hồn Xà tộc là nam tử trung niên áo lam có ấn ký hình rắn trên mi tâm. Ông lợi dụng chuyện Vân Độn tộc mời Tham Lang làm cung phụng để khơi mào tranh chấp trước kỳ tuyển chọn trưởng lão Lạc Sinh hội.","vaiTro":"Đại trưởng lão Hồn Xà tộc","tinhCach":[{"text":"ưa khích tướng","chuong":"@c1306"},{"text":"biết mượn tay người khác để gây áp lực","chuong":"@c1306"}],"tabs":{"diem":[{"text":"Mang ấn ký hình rắn trên mi tâm, đại diện cho Hồn Xà tộc trong đám tu sĩ chờ ngoài Đại đế tinh.","chuong":"@c1306"},{"text":"Cố ý khơi chuyện Tham Lang để Vân Độn tộc và Ám Hạt Tộc thành mục tiêu lập uy.","chuong":"@c1306"}],"kinhLich":[{"mucCt":"vua","text":"Đại trưởng lão Hồn Xà tộc xuất hiện trong đám tu sĩ ngoài Đại đế tinh, trào phúng Vân Độn tộc và Ám Hạt Tộc bằng chuyện Tham Lang làm cung phụng. Hành động của ông kéo ánh mắt các tộc tới hai tộc này và tạo cơ hội cho trưởng lão thứ mười ba Hà tộc lập uy.","anchor":"Ánh mắt đại trưởng lão Hồn Xà tộc lóe lên. Cuộc tranh chấp này đúng là do hắn khơi mào","bridge":true,"khoang":"@c1306"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Tộc trưởng Vân Độn tộc","tag":"doi-thu","quanHe":"Khơi mào tranh chấp nhằm vào Vân Độn tộc.","ghiChu":"Hồn Xà tộc từng giao chiến với Vân Độn tộc trong tuyển chọn trưởng lão."},{"ten":"Tộc trưởng Hà tộc","tag":"dong-minh","quanHe":"Tạo thế để đối phương ra mặt lập uy.","ghiChu":"Ông đứng sau kích hoạt cuộc tranh chấp nhưng để Hà tộc trực tiếp gây áp lực."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1306"]},{"id":"toc-truong-ha-toc","name":"Tộc trưởng Hà tộc","cn":"","aliases":["Trưởng lão thứ mười ba Lạc Sinh hội"],"gioiTinh":"nam","theLuc":[{"ten":"Hà tộc","trangThai":"gan-bo"},{"ten":"Lạc Sinh hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1307","trangThai":"song","blurb":"Tộc trưởng Hà tộc là lão giả áo tím thuộc phân chi Ngũ Hành Thủy tộc và đang giữ vị trí trưởng lão thứ mười ba của Lạc Sinh hội. Trước kỳ tuyển chọn, ông muốn lập uy bằng cách làm nhục Ám Hạt Tộc và ép Vương Lâm quỳ, nhưng nhanh chóng kinh hãi khi thấy các dấu hiệu cho thấy Vương Lâm không phải người thường.","vaiTro":"Trưởng lão thứ mười ba Lạc Sinh hội","tinhCach":[{"text":"kiêu ngạo dựa vào thân phận trưởng lão","chuong":"@c1306"},{"text":"muốn lập uy trước đám đông","chuong":"@c1306"},{"text":"dễ bất an khi tình thế vượt dự liệu","chuong":"@c1306"}],"tabs":{"diem":[{"text":"Vừa là tộc trưởng Hà tộc vừa là trưởng lão thứ mười ba của Lạc Sinh hội.","chuong":"@c1306"},{"text":"Lầm tưởng Vương Lâm chỉ là người tạm thay trước khi Tham Lang tới nên định dùng hắn để lập uy.","chuong":"@c1306"},{"text":"Hoảng sợ khi Long Giáp Tộc bái kiến Vương Lâm và sứ giả đại đế đi thẳng về phía hắn.","chuong":"@c1306"}],"kinhLich":[{"mucCt":"ky","text":"Tộc trưởng Hà tộc xuất hiện với thân phận trưởng lão thứ mười ba Lạc Sinh hội và muốn giữ vị trí nên tìm cách lập uy trước các tiểu tộc Điên Lạc. Ông ép Ám Hạt Tộc quỳ, sau đó chỉ thẳng Vương Lâm bắt quỳ vì lầm tưởng Vương Lâm là người do Tham Lang phái tới. Khi Long Giáp Tộc dẫn hơn một ngàn tộc nhân bái kiến Vương Lâm và sứ giả đại đế đi thẳng về phía hắn, ông kinh hãi đến mức tim đập thình thịch.","anchor":"Hắn là trưởng lão thứ mười ba của Lạc Sinh hội, lần tuyển chọn này vì muốn có thể giữ vị trí nên muốn lập uy một phen","bridge":true,"khoang":"@c1306"},{"mucCt":"ky","text":"Tộc trưởng Hà tộc nhận ra suy đoán về thân phận Vương Lâm đã thành sự thật và ban đầu tưởng chuyện nhỏ sẽ được bỏ qua. Sau đó hắn bị Vương Lâm chỉ đích danh tước tư cách trưởng lão Lạc Sinh hội, đày đến tu chân tinh Ám Hạt Tộc quỳ phạt trăm năm, còn Hà tộc cũng bị hủy tư cách dự tuyển trưởng lão.","anchor":"Hủy bỏ tư cách trưởng lão Lạc Sinh hội của hắn, đày đi tu chân tinh của Ám Hạt Tộc phạt quỳ trăm năm","bridge":true,"khoang":"@c1307"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Công khai ép Vương Lâm quỳ để lập uy.","ghiChu":"Ông lầm tưởng Vương Lâm chỉ là người thay mặt Tham Lang."},{"ten":"Tộc trưởng Ám Hạt Tộc","tag":"doi-thu","quanHe":"Ép Ám Hạt Tộc quỳ trước các tộc.","ghiChu":"Dùng thân phận trưởng lão Lạc Sinh hội để gây áp lực."},{"ten":"Đại trưởng lão Hồn Xà tộc","tag":"dong-minh","quanHe":"Bị cuộc khơi mào của đối phương tạo thế ra mặt lập uy.","ghiChu":"Quan hệ trong chương là cùng hướng vào Vân Độn tộc và Ám Hạt Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1306","@c1307"]},{"id":"toc-truong-long-giap-toc-moi","name":"Tộc trưởng Long Giáp Tộc mới","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Tộc trưởng Long Giáp Tộc mới là thanh niên dẫn hơn một ngàn tộc nhân tới ngoài Đại đế tinh. Ông công khai bái kiến Vương Lâm trước các tộc, khiến toàn trường nhận ra uy thế của Vương Lâm vượt xa nhận định ban đầu.","vaiTro":"Tộc trưởng mới của Long Giáp Tộc","tinhCach":[{"text":"cung kính với Vương Lâm","chuong":"@c1306"},{"text":"hành xử quyết đoán trước đám đông","chuong":"@c1306"}],"tabs":{"diem":[{"text":"Dẫn hơn một ngàn tộc nhân Long Giáp Tộc tới nơi tuyển chọn trưởng lão.","chuong":"@c1306"},{"text":"Công khai xưng vãn bối và tham kiến Vương Lâm trước mắt nhiều tiểu tộc Điên Lạc.","chuong":"@c1306"}],"kinhLich":[{"mucCt":"vua","text":"Tộc trưởng Long Giáp Tộc mới dẫn hơn một ngàn tộc nhân tới ngoài Đại đế tinh và lập tức cung kính bái kiến Vương Lâm. Hành động công khai này khiến các tu sĩ xung quanh biến sắc và làm tộc trưởng Hà tộc sinh nghi về thân phận thật của Vương Lâm.","anchor":"Vãn bối là tộc trưởng Long Giáp Tộc, tham kiến tiền bối","bridge":true,"khoang":"@c1306"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cung kính bái kiến Vương Lâm trước các tộc.","ghiChu":"Sự kiện thể hiện Long Giáp Tộc thừa nhận uy thế của Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1306"]},{"id":"su-gia-dai-de","name":"Sứ giả đại đế","cn":"","aliases":["Sứ giả của đại đế","Các sứ giả của đại đế"],"gioiTinh":"nam","theLuc":[{"ten":"Đại đế tinh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1307","trangThai":"song","blurb":"Sứ giả đại đế là tu sĩ từng xuất hiện ở tu chân tinh Long Giáp Tộc và dẫn đầu nhóm mười tu sĩ khi thông đạo Đại đế tinh mở. Ông bỏ qua mọi người xung quanh và đi thẳng về phía Vương Lâm, tạo cú sốc cho trưởng lão thứ mười ba.","vaiTro":"Sứ giả của đại đế","tinhCach":[{"text":"lạnh lùng trước đám đông","chuong":"@c1306"},{"text":"hướng thẳng tới mục tiêu được đại đế chú ý","chuong":"@c1306"}],"tabs":{"diem":[{"text":"Dẫn đầu mười tu sĩ xuất hiện từ thông đạo Đại đế tinh.","chuong":"@c1306"},{"text":"Không nhìn các tu sĩ xung quanh mà đi thẳng về phía Vương Lâm.","chuong":"@c1306"}],"kinhLich":[{"mucCt":"vua","text":"Khi thông đạo Đại đế tinh mở, sứ giả đại đế dẫn đầu mười tu sĩ bước ra. Ông không để ý tới các tộc đang chờ bên ngoài mà đi thẳng về phía Vương Lâm, khiến trưởng lão thứ mười ba Hà tộc kinh hãi.","anchor":"Người dần đầu là sứ giả của đại đế đã xuất hiện ở tu chân tinh của Long Giáp Tộc","bridge":true,"khoang":"@c1306"},{"mucCt":"vua","text":"Sứ giả đại đế dẫn tu sĩ ra khỏi thông đạo, cung kính bái kiến Vương Lâm là thiếu đế và giải thích việc mở thông đạo cần thời gian. Khi Vương Lâm nhìn về phía nam tử Hồn Xà tộc, hắn lập tức định bắt người rồi nghe theo quyết định xử phạt của Vương Lâm.","anchor":"Sứ giả của đại đế cuống quít ôm quyền, cung kính giải thích","bridge":true,"khoang":"@c1307"},{"chuong":"@c1308","importance":"normal","mucCt":"vua","tieuDe":"Dẫn vào Đại đế tinh","text":"Sứ giả đại đế dẫn Vương Lâm qua thông đạo vào Đại đế tinh và truyền âm xin ý kiến khi Vương Lâm đề nghị đưa tộc trưởng Ám Hạt Tộc thành trưởng lão Lạc Sinh hội. Sau khi được chấp thuận, hắn giải thích việc tuyển chọn rồi cáo lui để tiếp tục đi đón tu sĩ khác.","anchor":"Hắn mơ hồ phát hiện ra sứ giả của đại đế đang dùng một phương pháp đặc thù để truyền âm với người khác"},{"chuong":"@c1309","importance":"bridge","mucCt":"gon","tieuDe":"Đưa tu sĩ tới","text":"Các sứ giả của đại đế đưa một số tu sĩ tới Đại đế tinh sau khi Vương Lâm rời vị trí ban đầu.","anchor":"Mấy sứ giả của đại đế của đại đế mang theo một số tu sĩ đã tới"}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đi thẳng về phía Vương Lâm sau khi thông đạo Đại đế tinh mở.","ghiChu":"Cử chỉ này khiến các tộc phải nhìn lại thân phận của Vương Lâm."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Bái kiến và phục lệnh","ghiChu":"Gọi Vương Lâm là thiếu đế đại nhân, mời hắn vào Đại đế tinh và chấp hành xử phạt theo lời hắn."},{"ten":"Nam tử trung niên Hồn Xà tộc","tag":"khac","quanHe":"Người bị định bắt","ghiChu":"Định sai người bắt nam tử Hồn Xà tộc khi thấy ánh mắt Vương Lâm hướng tới."},{"ten":"Điên Lạc đại đế","tag":"cap-tren","quanHe":"Người sai phái","ghiChu":"Sứ giả phụng mệnh đại đế đưa người vào Đại đế tinh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1306","@c1307","@c1308","@c1309"]},{"id":"nam-tu-trung-nien-hon-xa-toc","name":"Nam tử trung niên Hồn Xà tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hồn Xà tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1307","trangThai":"song","blurb":"Tu sĩ Hồn Xà tộc từng đắc tội Vương Lâm ngay trước khi thân phận thiếu đế của hắn được công khai. Sau quyết định xử phạt của Vương Lâm, hắn sống sót nhưng trở thành người làm liên lụy cả tộc.","vaiTro":"Tu sĩ Hồn Xà tộc bị xử phạt","tinhCach":[{"text":"Hoảng sợ khi nhận ra thân phận thật của Vương Lâm","chuong":"@c1307"},{"text":"Bị đặt vào tình thế tội nhân toàn tộc","chuong":"@c1307"}],"nguon":["@c1307"],"tabs":{"diem":[{"text":"Biến sắc khi biết Vương Lâm là thiếu đế vùng đất Điên Lạc.","chuong":"@c1307"},{"text":"Không bị giết nhưng khiến Hồn Xà tộc mất tư cách dự tuyển trưởng lão.","chuong":"@c1307"}],"kinhLich":[{"mucCt":"vua","text":"Nam tử trung niên Hồn Xà tộc hoảng sợ khi biết người mình đắc tội là thiếu đế Vương Lâm. Hắn không bị giết, nhưng quyết định hủy tư cách dự tuyển trưởng lão của Hồn Xà tộc khiến hắn thành tội nhân trong tộc.","anchor":"Sắc mặt nam tử trung niên Hồn Xà tộc lập tức trắng bệch, ánh mắt lộ vẻ hoảng sợ","bridge":true,"khoang":"@c1307"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đắc tội rồi bị xử phạt","ghiChu":"Bị Vương Lâm hủy tư cách dự tuyển trưởng lão của Hồn Xà tộc."},{"ten":"Sứ giả đại đế","tag":"khac","quanHe":"Bị định bắt","ghiChu":"Sứ giả đại đế định sai người bắt hắn theo ánh mắt của Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"truong-lao-long-giap-toc","name":"Trưởng lão Long Giáp Tộc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Long Giáp Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1307","trangThai":"khong-ro","blurb":"Trưởng lão Long Giáp Tộc từng bị nhắc như tiền lệ bị thu hồi chức vụ vì đắc tội Vương Lâm. Việc này khiến những người khác thêm sợ hãi khi biết thân phận thiếu đế của hắn.","vaiTro":"Tiền lệ bị thu chức","tinhCach":[{"text":"Không rõ tính cách trong chương này","chuong":"@c1307"}],"nguon":["@c1307"],"tabs":{"diem":[{"text":"Được nhắc như ví dụ từng mất chức vì đắc tội Vương Lâm.","chuong":"@c1307"}],"kinhLich":[{"chuong":"@c1307","importance":"bridge","mucCt":"gon","tieuDe":"Tiền lệ mất chức","text":"Trưởng lão Long Giáp Tộc được nhắc như tiền lệ từng bị thu hồi chức vụ vì đắc tội Vương Lâm.","anchor":"Trưởng lão Long Giáp Tộc bởi vì đác tội với người này nên mới bị thu hồi chức vụ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Từng đắc tội","ghiChu":"Từng bị thu hồi chức vụ vì đắc tội với Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"nu-tu-truong-ton-hoi","name":"Nữ tử Trường Tôn hội","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Trường Tôn hội","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Nữ tử thuộc Trường Tôn hội, am hiểu thuật pháp liên quan tên thật. Nàng thử dùng tên của Vương Lâm để thi triển Danh khôi ti thuật nhưng thất bại vì hắn chỉ dùng tên Hứa Mộc.","vaiTro":"Tu sĩ Trường Tôn hội dò tên Vương Lâm","tinhCach":[{"text":"Kín đáo, biết âm thầm thử thuật dựa vào tên"},{"text":"Cẩn trọng khi phát hiện điều kiện thi triển không thành"}],"tabs":{"diem":[{"text":"Nàng hỏi tên Vương Lâm và âm thầm đọc tên Hứa Mộc để thử thi triển thuật.","chuong":"@c1308"},{"text":"Nàng nhận ra đối phương không tự nói tên thật nên không đủ điều kiện dùng Danh khôi ti thuật.","chuong":"@c1308"}],"kinhLich":[{"mucCt":"vua","text":"Nữ tử Trường Tôn hội tiếp tục hỏi tên Vương Lâm và âm thầm đọc Hứa Mộc ba lần. Nàng nhận ra tên này không phải tên thật do chính đối phương thừa nhận nên không thể thi triển Danh khôi ti thuật.","anchor":"Ánh mắt nữ tử kia chợp lóe lên, trong lòng thầm đọc ba làn Hứa Mộc","bridge":true,"khoang":"@c1308"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối tượng nàng muốn dùng Danh khôi ti thuật","ghiChu":"Nàng thất bại vì Vương Lâm chỉ báo danh Hứa Mộc."},{"ten":"Tư Mặc Tử","tag":"dong-minh","quanHe":"Người cùng hiện diện khi Vương Lâm rời đi","ghiChu":"Hai người bị Vương Lâm bỏ qua trong thông đạo."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Danh khôi ti thuật","loai":"thuật pháp","trangThai":"dang-co","moTa":"Thuật cần điều kiện tên thật do đối phương tự nói ra.","nguon":"@c1308"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1308"]},{"id":"lao-gia-mac-bach-y-ben-ho","name":"Lão giả mặc bạch y bên hồ","cn":"","aliases":["lão giả áo trắng bên hồ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lão giả mặc bạch y xuất hiện bên một hồ nước trên Đại đế tinh. Lão ngồi câu cá cạnh bầu rượu, im lặng cùng Vương Lâm hồi lâu rồi hỏi hắn có uống rượu không.","vaiTro":"người bí ẩn bên hồ","tinhCach":[{"text":"trầm mặc, ung dung bên hồ","chuong":"@c1309"},{"text":"chủ động mở lời bằng rượu sau thời gian dài im lặng","chuong":"@c1309"}],"tabs":{"diem":[{"text":"Ngồi câu cá bên hồ trên Đại đế tinh, cạnh đó có bầu rượu.","chuong":"@c1309"},{"text":"Là người đầu tiên Vương Lâm gặp trực tiếp trên Đại đế tinh ngoài nhóm sứ giả.","chuong":"@c1309"}],"kinhLich":[{"mucCt":"vua","text":"Lão giả mặc bạch y ngồi câu cá bên hồ giữa thực vật Đại đế tinh, bên cạnh có bầu rượu. Khi Vương Lâm hạ xuống ngồi cạnh và cả hai im lặng hồi lâu, lão chủ động hỏi hắn có uống rượu không.","anchor":"Lão giả nọ ngồi bên hồ, tay cầm một cái cần câu","bridge":true,"khoang":"@c1309"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người gặp bên hồ","ghiChu":"Lão ngồi bên cạnh Vương Lâm một lúc lâu rồi mở lời hỏi rượu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Bầu rượu","loai":"vật phẩm","trangThai":"dang-co","moTa":"Đặt bên cạnh lão khi lão câu cá ven hồ.","nguon":"@c1309"},{"ten":"Cần câu","loai":"vật phẩm","trangThai":"dang-co","moTa":"Lão cầm cần câu ngồi bên hồ, dưới nước không thấy cá.","nguon":"@c1309"}]}},"nguon":["@c1309"]},{"id":"chu-tuoc-doi-thu-hai","name":"Chu Tước đời thứ hai","cn":"","aliases":["Lão giả câu rồng","Lão phu Chu Tước tộc","Lão già bên hồ","Lão Chu Tước","Chu Tước đời thứ hai"],"gioiTinh":"nam","theLuc":[{"ten":"Chu Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1315","trangThai":"song","blurb":"Chu Tước đời thứ hai là một lão giả thường ngồi câu bên hồ trên Đại Đế tinh, có thể câu lên và áp chế Viêm long, lấy máu rồng mời khách uống. Lão kiểm tra thiên linh Vương Lâm, xác nhận hắn là tiểu bối Chu Tước đời thứ sáu mang năm đạo bổn nguyên khác nhau, sau đó công khai bao che hắn trước các đại năng và đưa hắn vào thí luyện thiếu đế. Khi thí luyện sinh biến nghiêm trọng, lão nhiều lần vi phạm quy định để cứu viện, thậm chí liều mạng lấy toàn bộ viêm huyết tinh hoa của Viêm long truyền vào cây hương nhằm trợ Vương Lâm thức tỉnh Chu Tước lần bốn.","vaiTro":"Tiền bối Chu Tước đời thứ hai — chủ trì thí luyện thiếu đế, che chở và trợ lực Vương Lâm","tinhCach":"Tinh tường, nhìn thấu căn cơ và bổn nguyên người khác; che chở tiểu bối cùng tộc một cách công khai và quyết đoán; dám vi phạm quy định thí luyện để cứu viện khi biến cố xảy ra; tính tình hào sảng, cười sang sảng giữa nguy nan","nguon":["@c1310","@c1311","@c1312","@c1313","@c1314","@c1315","@c1316","@c1317","@c1318","@c1319","@c1320","@c1321","@c1322","@c1323"],"tabs":{"diem":[{"text":"Ngồi câu bên hồ trên Đại Đế tinh, câu được Viêm long và lấy máu rồng mời Vương Lâm uống","chuong":"@c1310"},{"text":"Kiểm tra thiên linh Vương Lâm, phát hiện hắn mang năm đạo bổn nguyên khác nhau, xác nhận là tiểu bối Chu Tước đời thứ sáu","chuong":"@c1311"},{"text":"Công khai bao che Vương Lâm trước các đại năng, gọi hắn là tiểu bối nhà mình và dùng hư hỏa bảo vệ","chuong":"@c1313"},{"text":"Chủ trì thí luyện thiếu đế, hô dâng hương khiến ba cây hương Thiên, Địa, Nhân hiện ra","chuong":"@c1314"},{"text":"Liều mạng lấy toàn bộ viêm huyết tinh hoa trên đỉnh đầu Viêm long truyền vào Địa Phương hương để trợ Vương Lâm thức tỉnh Chu Tước lần bốn","chuong":"@c1321"},{"text":"Được Vương Lâm nhớ lại với tiếng cười sang sảng, bắt rồng lấy máu, nhiều lần trợ giúp và truyền Phần Giới Cổ Tán","chuong":"@c1341"}],"kinhLich":[{"mucCt":"ky","text":"Chu Tước đời thứ hai ngồi câu bên hồ, để Vương Lâm uống máu Viêm long rồi tiết lộ đó không phải rượu. Lão câu lên con rồng đỏ dài ngàn trượng, dùng hỏa vụ và hư ảnh Chu Tước khổng lồ áp chế nó, xuyên tay vào chỗ nhô trên đầu rồng để lấy máu. Sau khi thấy Vương Lâm không lãng phí máu rồng, lão kiểm tra thân thể hắn, xác nhận hắn là tộc nhân Chu Tước đời thứ sáu kiêm Cổ Thần và nhắc tới thần thông mà Chu Tước đời thứ tư không tu được.","anchor":"Tốt, không hổ là tộc nhân Chu Tước của ta, biết lãng phí là không tốt","bridge":true,"khoang":"@c1310"},{"chuong":"@c1311","importance":"normal","mucCt":"ky","tieuDe":"Xác nhận đời thứ hai","text":"Chu Tước đời thứ hai kiểm tra thiên linh Vương Lâm, phát hiện năm đạo bổn nguyên khác nhau và từ tiếc nuối chuyển sang kinh hãi, mừng rỡ. Ông nói rõ mình là Chu Tước đời thứ hai, cùng Chu Tước đời thứ tư đều là thiếu đế, đồng thời giải thích Điên Lạc đại đế trong tộc được gọi là Chu Tước lão tổ. Ông muốn Vương Lâm sau thí luyện dùng Tư Mặc Tử để lập uy, rồi chọn bí thuật vận lực Huyền Vũ để truyền vì thân thể Cổ Thần của Vương Lâm hợp với phương pháp này.","anchor":"Lão phu cũng không phải là Chu Tước đời đầu tiên, mà là đời thứ hai"},{"mucCt":"ky","text":"Lão Chu Tước biểu diễn một chưởng làm một tầng nước hồ tan thành hơi nước để dẫn Vương Lâm quan sát thâm ý vận dụng lực. Khi thấy Vương Lâm tự tiến tới chỗ mình định giảng, lão kinh hãi trước ngộ tính của hắn nhưng vẫn cố giữ vẻ cao thâm. Sau đó lão tuyên bố bí thuật đã học xong, dùng lửa hư ảo cuốn Vương Lâm tới trường đấu phía tây bắc và dự định lấy Tư Mặc Tử lập uy sau thí luyện.","anchor":"Lão Chu Tước nuốt nước bọt, thần sắc cố gắng kiềm chế sự vui mừng vô cùng.","bridge":true,"khoang":"@c1312"},{"chuong":"@c1313","importance":"normal","mucCt":"ky","tieuDe":"Bao che Vương Lâm","anchor":"nếu thí luyện thành công thì từ nay về sau hắn sẽ chính thức là thiếu đế của chúng ta","text":"Lão Chu Tước đưa Vương Lâm hiện thân trước các đại năng, công khai gọi hắn là tiểu bối nhà mình và dùng hư hỏa cùng những cái tát trấn áp Tư Mặc Tử vì từng nhắm vào Vương Lâm. Ông quát khiến Vân Lạc đại ti không dám lấy Trường Tôn hội ra can thiệp, đồng thời thể hiện rõ bản tính bao che của Chu Tước nhất tộc. Sau đó ông tuyên bố Vương Lâm sẽ tham gia thí luyện thiếu đế thứ ba, nếu thành công thì kẻ địch của Vương Lâm cũng là kẻ địch của ông và vùng đất Điên Lạc."},{"chuong":"@c1314","importance":"normal","mucCt":"ky","tieuDe":"Mở thí luyện thiếu đế","text":"Lão Chu Tước nghiêm túc chủ trì thí luyện thiếu đế, hô dâng hương khiến ba cây hương Thiên, Địa, Nhân hiện ra trên lưng cự quy. Ông công bố quy tắc sinh tử của thí luyện, nói người tham gia phải đưa hồn vào ba huyễn giới và thoát ra trước khi hương cháy hết. Sau khi Vương Lâm đáp rằng không có gì không dám, ông dùng cuồng phong đưa hắn tới cây hương thứ nhất.","anchor":"Lão Chu Tước vung hai tay lên, không còn vẻ đùa cợt như vừa rồi mà thần sắc cực kỳ nghiêm túc"},{"mucCt":"vua","text":"Trên Đại Đế tinh, Lão Chu Tước lo lắng quan sát Vương Lâm đặt tay lên cây hương thứ nhất mà chậm trễ quá mức dự tính. Bất động hơn một canh giờ, ông nghi ngờ hắn gặp trở ngại vì hồn không về quê cũ, cho rằng với tu vi của Vương Lâm, việc đốt cây hương đầu tiên đáng lẽ phải kết thúc sớm hơn.","anchor":"Làm sao lại chậm như vậy. đốt cây hương thứ nhất lấy tu vi của hắn hẳn là phải sớm hoàn thành rồi mới phải","bridge":true,"khoang":"@c1315"},{"chuong":"@c1316","importance":"normal","mucCt":"vua","tieuDe":"Thúc Vương Lâm đốt hương rồi thừa nhận con đường nghiệp hỏa","text":"Từ Đại Đế tinh, lão Chu Tước vi phạm quy định thí luyện truyền âm thúc Vương Lâm đốt hương, nhưng hắn từ chối. Lão tát Tư Mặc Tử văng vạn trượng vì dám châm chọc, rồi thầm nhận định nghiệp hỏa nhập hồn cực kỳ gian nan nhưng nếu Vương Lâm thành công sẽ trở thành nhân vật đệ nhất của Chu Tước tộc.","anchor":"nghiệp hỏa nhập hồn cực kỳ gian nan"},{"chuong":"@c1317","importance":"normal","mucCt":"ky","tieuDe":"Định hủy Nhân giới","text":"Lão Chu Tước hiện thân qua dòng xoáy, cảnh báo Vương Lâm rằng hiện tại mới là thiêu hồn, còn khi nghiệp hỏa thật sự xuất hiện thì Cửu chuyển nghiệp kiếp mới bắt đầu và hồn phách có thể lập tức bị hủy diệt. Thấy Vương Lâm không chịu buông bỏ phàm trần, lão quyết định phóng biển lửa xuống Nhân giới để cứu hắn bằng cách hủy diệt nơi này. Khi Vương Lâm ôm Lý Mộ Uyển chắn lửa và chấp niệm hóa thành nghiệp hỏa, lão thở dài thu hồi biển lửa cùng dòng xoáy, thừa nhận ngoài lão tổ đời đầu ra không ai có cách ngăn cản.","anchor":"Chấp niệm hóa thành nghiệp hỏa, ngoài lão tổ đời thứ nhất ra thì chẳng còn người nào có cách ngăn cản"},{"mucCt":"vua","text":"Chu Tước đời thứ hai nghe tiếng kêu liền biết trong cây hương đã sinh biến, cười dài khi thấy Vương Lâm có thể hóa Chu Tước trong nghiệp hỏa. Ông cũng chỉ ra cửa ải kế tiếp là Cửu chuyển hỏa kiếp, thử thách khó nhất trên con đường thức tỉnh lần thứ tư.","anchor":"Không ngờ lại có thể biến ảo ra Chu Tước trong nghiệp hỏa!","bridge":true,"khoang":"@c1318"},{"mucCt":"vua","text":"Trên Đại đế tinh, Lão Chu Tước theo dõi cây hương thứ nhất với vẻ lo lắng và biến sắc khi thấy Chanh, Hoàng, Lục tam kiếp đồng thời giáng xuống lúc Vương Lâm chưa vượt qua đệ nhất kiếp. Đến khi Nhân Phương Hương tắt ở nhịp thở thứ bảy, ông càng không thể tin nổi.","anchor":"Sắc mặt Lão Chu Tước đại biến","bridge":true,"khoang":"@c1319"},{"chuong":"@c1320","importance":"normal","mucCt":"ky","tieuDe":"Cứu viện Vương Lâm thất bại và ép máu Viêm long trợ lực","text":"Kinh hãi khi Nhân Phương hương tắt, đưa thần thức vào Địa Phương hương cứu Vương Lâm nhưng bị sức mạnh Thiên Nghịch cuốn khỏi Địa Phương giới. Sau khi Vương Lâm vượt kiếp và Chu Tước tỉnh giấc lần thứ tư, quyết định gian lận trợ lực bằng cách giẫm bắt Viêm long vạn trượng, mở vết thương trên đầu nó ép máu tưới Địa Phương hương. Hứa sẽ thả Viêm long tự do nếu Vương Lâm thức tỉnh thành công.","anchor":"Ta thân là trưởng bối, cho dù là gian lận, cũng phải giúp hắn một phen"},{"chuong":"@c1321","importance":"normal","mucCt":"ky","tieuDe":"Liều mạng trợ Vương Lâm thức tỉnh Chu Tước lần bốn","text":"Trên Đại đế tinh, lão lấy toàn bộ viêm huyết tinh hoa trên đỉnh đầu viêm long rồi truyền vào Địa Phương hương. Khi viêm huyết cạn, lão khóa miệng viêm long và mở vết thương trăm trượng để ép lấy long huyết thường bổ sung hỏa lực. Cuối cùng lão cắn răng điểm mi tâm, tự xuất hư hỏa bản thân vào Địa Phương hương, liều mạng hết thảy giúp Vương Lâm hoàn tất thức tỉnh.","anchor":"Tiểu tử kia, lão phu vì trợ giúp ngươi có thể liều mạng hết thảy"},{"chuong":"@c1322","importance":"bridge","mucCt":"vua","text":"Chứng kiến sương mù từ lực cuộn vào Địa phương hương, thần sắc cực kỳ ngưng trọng rồi lộ vẻ khiếp sợ.","anchor":"Thần sắc lão Chu Tước cực kỳ ngưng trọng, ngẩng đầu không nói"},{"mucCt":"vua","text":"Cười khổ khi nhận định biến cố trên Đại đế tinh liên quan tới Vương Lâm, than rằng cây hương đầu tiên tắt, cây thứ hai gãy, thí luyện khó tiếp tục theo thường quy. Đồng thời được Chu Tước đời thứ tư tiết lộ cũng mang phong ấn của người thần bí, tuy áp chế được nên không phải vào Địa phương giới nhưng không thể rời vùng đất Điên Lạc.","anchor":"Cây hương đầu tiên thì tắt, cây thứ hai thì gãy","bridge":true,"khoang":"@c1323"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"tiểu bối Chu Tước đời thứ sáu","ghiChu":"Xác nhận Vương Lâm là tộc nhân Chu Tước của mình và có thân thể Cổ Thần."},{"ten":"Viêm long","tag":"khac","quanHe":"hung thú bị câu lấy máu","ghiChu":"Câu Viêm long lên khỏi hồ, áp chế rồi lấy máu từ đầu nó."},{"ten":"Chu Tước đời thứ tư","tag":"su-mon","quanHe":"hậu bối trong hệ Chu Tước","ghiChu":"Nhắc rằng Chu Tước đời thứ tư phong lưu thành tính nên không tu được thần thông của mình."},{"ten":"Chu Tước đời thứ tư","tag":"dong-minh","quanHe":"Cùng là thiếu đế của Chu Tước thánh tộc.","ghiChu":"Ông nói Chu Tước đời thứ tư cũng đang ở nơi này."},{"ten":"Chu Tước lão tổ","tag":"su-mon","quanHe":"Lão tổ được ông giải thích là Điên Lạc đại đế trong cách gọi của người ngoài.","ghiChu":"Thuộc tuyến truyền thừa Chu Tước thánh tộc."},{"ten":"Tư Mặc Tử","tag":"doi-thu","quanHe":"Tu sĩ bước thứ ba được ông chọn làm đối tượng để Vương Lâm lập uy.","ghiChu":"Ông không e ngại thân phận bước thứ ba của đối phương."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"người được bảo hộ và đề cử thí luyện thiếu đế","ghiChu":"Công khai đứng ra che chở, giữ thể diện và mở đường cho Vương Lâm tại vùng đất Điên Lạc."},{"ten":"Vân Lạc","tag":"doi-thu","quanHe":"người bị quát ngăn can thiệp","ghiChu":"Dọa tát cả nàng khi nàng định lấy Trường Tôn hội ra nói."},{"ten":"Diệu Âm đạo tôn","tag":"khac","quanHe":"đại năng được giới thiệu với Vương Lâm","ghiChu":"Giới thiệu thân phận Diệu Âm đạo tôn là một trong Thái Cổ Ngũ Tôn."},{"ten":"Thái Hoang Công","tag":"khac","quanHe":"đại năng quen biết","ghiChu":"Giới thiệu Thái Hoang Công với Vương Lâm và bảo Vương Lâm nhận vật phòng thân do người này tặng."},{"ten":"Chu Tước đời đầu","tag":"su-mon","quanHe":"Tiền nhân của Chu Tước tộc","ghiChu":"Lão nhắc lại cách nhìn của đời đầu về bất diệt hồn hỏa và nghiệp hỏa nhập hồn."}],"tuiDo":{"phapBao":[{"ten":"Cần câu và dây câu bạc của lão giả","loai":"pháp bảo câu rồng","trangThai":"dang-co","moTa":"Dùng để câu giữ Viêm long dưới hồ, dây bạc cực kỳ cứng cỏi.","nguon":"@c1310"},{"ten":"Bầu rượu chứa máu Viêm long","loai":"vật chứa","trangThai":"dang-co","moTa":"Bầu có thể chứa máu Viêm long mà bình thuốc thường không chứa nổi.","nguon":"@c1310"}],"danDuoc":[],"congPhap":[{"ten":"Hư hỏa Chu Tước của lão giả","loai":"thần thông","trangThai":"dang-co","moTa":"Hư ảnh Chu Tước và hỏa vụ vô hình được lão dùng để áp chế Viêm long.","nguon":"@c1310"}],"linhThu":[],"nguyenLieu":[{"ten":"Máu Viêm long","loai":"huyết dịch hỏa thuộc tính","trangThai":"dang-co","moTa":"Lão câu Viêm long để lấy máu cho Vương Lâm uống và luyện hóa.","nguon":"@c1310"}],"linhThao":[],"khac":[]}}},{"id":"viem-long","name":"Viêm long","cn":"","aliases":["Cự long đỏ dưới hồ"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Uy áp ngang tu sĩ bước thứ ba @c1310","trangThai":"song","blurb":"Hung thú dạng rồng đỏ ẩn dưới hồ nơi Chu Tước đời thứ hai câu cá. Nó có uy áp ngang tu sĩ bước thứ ba, bị câu lên, áp chế và lấy máu rồi trốn về đáy hồ.","vaiTro":"hung thú dưới hồ","tinhCach":[{"text":"hung hãn, vừa bị kéo lên đã muốn cắn nuốt lão giả","chuong":"@c1310"},{"text":"sợ hư hỏa Chu Tước và bỏ chạy sau khi bị lấy máu","chuong":"@c1310"}],"nguon":["@c1310"],"tabs":{"diem":[{"text":"Thân rồng đỏ dài khoảng ngàn trượng, gây uy áp khiến Vương Lâm tái mặt lui lại.","chuong":"@c1310"},{"text":"Máu của nó chứa lực lượng hỏa diễm, có thể tăng hỏa bổn nguyên cho Vương Lâm.","chuong":"@c1310"}],"kinhLich":[{"mucCt":"vua","text":"Viêm long bị Chu Tước đời thứ hai dùng dây câu bạc kéo khỏi đáy hồ, để lộ thân rồng đỏ dài ngàn trượng và uy áp ngang tu sĩ bước thứ ba. Nó định cắn nuốt lão giả nhưng bị hư hỏa Chu Tước đánh lui, bị lấy máu từ chỗ nhô trên đầu rồi trốn về đáy hồ.","anchor":"Hừ, trước mặt lão phu, một viêm long nho nhỏ mà cũng dám trốn","bridge":true,"khoang":"@c1310"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước đời thứ hai","tag":"doi-thu","quanHe":"người câu và lấy máu","ghiChu":"Bị lão giả câu lên, áp chế và lấy máu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người luyện hóa máu","ghiChu":"Máu của Viêm long được Vương Lâm uống và luyện hóa."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"chu-tuoc-doi-thu-tu","name":"Chu Tước đời thứ tư","cn":"","aliases":["Nam tử trung niên trên ngọn núi trọc","Chu Tước Thánh Hoàng đời thứ tư"],"gioiTinh":"nam","theLuc":[{"ten":"Chu Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1312","trangThai":"song","blurb":"Chu Tước đời thứ tư là một đời Thánh Hoàng trong mạch truyền thừa Chu Tước tộc, được các tiền bối cùng tộc nhắc tới như người thiên tư kinh người song vì phong lưu thành tính mà không tu thành thần thông của mình.Ông ẩn thân dưới hình dạng nam tử trung niên trên ngọn núi trọc, mang thân phận thiếu đế, và là sư phụ của Lỗ Vân. Khi Vương Lâm tìm tới,ông nhận ra khí tức Lỗ Vân trên thân người này và tiếp nhận lại thi hài đệ tử.","vaiTro":"Chu Tước Thánh Hoàng đời thứ tư — sư phụ của Lỗ Vân","tinhCach":"Phong lưu thành tính; thiên tư kinh người nhưng khó lĩnh ngộ thần thông","nguon":["@c1310","@c1311","@c1312","@c1319","@c1321","@c1323"],"tabs":{"diem":[{"text":"Được Chu Tước đời thứ hai nhắc là phong lưu thành tính nên không tu được thần thông của mình","chuong":"@c1310"},{"text":"Cùng ở nơi này và cùng mang thân phận thiếu đế","chuong":"@c1311"},{"text":"Được Lão Chu Tước nhắc lại như người thiên tư kinh người nhưng năm xưa cũng không tự lĩnh ngộ","chuong":"@c1312"},{"text":"Làm mốc so sánh vì năm xưa chỉ duy trì dưới cây hương được năm nhịp thở","chuong":"@c1319"},{"text":"Lộ thân phận là sư phụ Lỗ Vân khi nhận ra khí tức quen thuộc trên thân Vương Lâm","chuong":"@c1321"},{"text":"Xác nhận thân phận với Vương Lâm và tiếp nhận thi hài đệ tử Lỗ Vân","chuong":"@c1323"}],"kinhLich":[{"chuong":"@c1310","importance":"bridge","mucCt":"gon","tieuDe":"Không hợp thần thông","text":"Chu Tước đời thứ tư được Chu Tước đời thứ hai nhắc là phong lưu thành tính nên không tu được thần thông của lão.","anchor":"Chu Tước đời thứ tư phong lưu thành tính, tu không được thần thông của lão phu"},{"chuong":"@c1311","importance":"bridge","mucCt":"vua","tieuDe":"Được nhắc cùng thiếu đế","text":"Chu Tước đời thứ tư được Chu Tước đời thứ hai nhắc là cũng ở nơi này và cùng mang thân phận thiếu đế.","anchor":"Chu Tước đời thứ tư cũng ở nơi này"},{"chuong":"@c1312","importance":"bridge","mucCt":"gon","tieuDe":"Được đem so sánh","text":"Chu Tước đời thứ tư được Lão Chu Tước nhắc lại như người thiên tư kinh người nhưng năm xưa cũng không tự lĩnh ngộ trọn thâm ý thuật vận lực này.","anchor":"Mặc dù là Chu Tước đời thứ tư thiên tư kinh người ngày đó cũng không lĩnh ngộ được"},{"chuong":"@c1319","importance":"bridge","mucCt":"gon","tieuDe":"Mốc năm nhịp thở","text":"Chu Tước đời thứ tư được nhắc làm mốc so sánh vì năm xưa chỉ duy trì dưới cây hương này được năm nhịp thở.","anchor":"Chu Tước đời thứ tư năm đó ở dưới cây hương này"},{"mucCt":"vua","text":"Trong Địa Phương giới, nhận ra khí tức quen thuộc của Lỗ Vân trên thân Vương Lâm, lộ thân phận là sư phụ Chu Tước đời thứ năm Lỗ Vân và là Chu Tước đời thứ tư. Phóng hư hỏa của bản thân vào Chu Tước chín màu của Vương Lâm để tương trợ quá trình thức tỉnh.","anchor":"Nam tử trung niên này chính là sư phụ của Chu Tước đời thứ năm Lỗ Vân, Chu Tước đời thứ tư","bridge":true,"khoang":"@c1321"},{"chuong":"@c1323","importance":"normal","mucCt":"vua","tieuDe":"Tiết lộ phong ấn, nhận thi hài đệ tử","text":"Vương Lâm tìm tới ngọn núi trọc xác nhận thân phận ông, đưa thi hài Lỗ Vân về bên cạnh. Sau khi Vương Lâm rời đi, ông đau đớn nhận lỗi với Lỗ Vân, tiết lộ mình bị người thần bí hạ phong ấn ở Thái Cổ Tinh Thần, hễ rời Địa phương giới sẽ mất tâm thần, nên không thể trở về Tứ Thánh Tông dù biết mọi chuyện. Ông còn nói phong ấn cũng có trên Chu Tước đời thứ hai, và nếu vùng đất Điên Lạc sụp đổ thì Chu Tước tộc sẽ phát điên mà chết.","anchor":"một ngày đi ra ngoài thì phong ấn liền bạo phát, khiến ta đánh mất tâm thần"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước đời thứ hai","tag":"su-mon","quanHe":"tiền bối Chu Tước tộc","ghiChu":"Bị tiền bối đánh giá là không phù hợp thần thông của lão."},{"ten":"Chu Tước đời thứ hai","tag":"dong-minh","quanHe":"Cùng là thiếu đế trong Chu Tước thánh tộc.","ghiChu":"Được nhắc trong lời giải thích thân phận bên hồ."},{"ten":"Lão Chu Tước","tag":"su-mon","quanHe":"tiền nhân cùng mạch Chu Tước","ghiChu":"Lão Chu Tước dùng kinh nghiệm năm xưa của Chu Tước đời thứ tư để so sánh với ngộ tính của Vương Lâm."},{"ten":"Lỗ Vân","tag":"su-mon","quanHe":"Đồ đệ — Chu Tước đời thứ năm","ghiChu":"@c1321"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người được tương trợ hư hỏa để thức tỉnh Chu Tước lần bốn","ghiChu":"@c1321"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"vien-co-tien-ton","name":"Viễn cổ tiên tôn","gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ @c1311","trangThai":"khong-ro","blurb":"Viễn cổ tiên tôn là một trong Thái Cổ Ngũ Tôn, chủ thượng của tứ đại chiến tướng trong đó có Chu Tước lão tổ. Từng bảo vệ lão tổ Chu Tước đời đầu khi vượt qua nghiệp kiếp, và đã tiến vào cổ mộ chiếm một phần sức mạnh Thái Cổ Tinh Thần. Năm xưa từng học trộm Phần Giới Cổ Tán, tại quê hương dùng thuật này mở ô tám lần gây hủy diệt.","vaiTro":"Chủ thượng viễn cổ — một trong Thái Cổ Ngũ Tôn, thống lĩnh tứ đại chiến tướng","tinhCach":[{"text":"Chưa rõ tính cách qua chương này","chuong":"@c1311"}],"nguon":["@c1311","@c1317"],"tabs":{"diem":[{"text":"Chủ thượng của tứ đại chiến tướng, trong đó có Chu Tước lão tổ","chuong":"@c1311"},{"text":"Từng bảo vệ lão tổ Chu Tước đời đầu khi vượt qua nghiệp kiếp","chuong":"@c1317"},{"text":"Học trộm Phần Giới Cổ Tán, tại quê hương dùng thuật mở ô tám lần gây hủy diệt","chuong":"@c1336"},{"text":"Một trong Thái Cổ Ngũ Tôn, đã tiến vào cổ mộ chiếm một phần sức mạnh Thái Cổ Tinh Thần","chuong":"@c1378"}],"kinhLich":[{"chuong":"@c1311","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc qua chiến tướng","text":"Viễn cổ tiên tôn được nhắc như chủ thượng của tứ đại chiến tướng, trong đó có Chu Tước lão tổ.","anchor":"là một trong tứ đại chiến tướng cực mạnh dưới trướng viễn cổ tiên tôn"},{"chuong":"@c1317","importance":"bridge","mucCt":"gon","tieuDe":"Từng bảo vệ lão tổ","text":"Tiên Tôn được nhắc là người từng bảo vệ lão tổ Chu Tước đời đầu khi vượt qua nghiệp kiếp.","anchor":"Lão tổ ngày đó có tiên tôn bảo vệ nếu không quả quyết cũng không thể thành công"}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Tước lão tổ","tag":"khac","quanHe":"Chu Tước lão tổ được nhắc là một trong tứ đại chiến tướng dưới trướng nhân vật này.","ghiChu":"Thông tin đến từ lời Chu Tước đời thứ hai."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"aliases":["Tiên Tôn"]},{"id":"thanh-long","name":"Thanh Long","trangThai":"khong-ro","nguon":["@c1311"],"tabs":{"kinhLich":[{"chuong":"@c1311","importance":"bridge","mucCt":"gon","tieuDe":"Nguồn thuật bị đoạt","text":"Thanh Long được nhắc là một trong các mạch từng bị lão tổ Chu Tước trẻ tuổi đoạt thuật đại thần thông.","anchor":"đoạt được thuật đại thần thông từ Thanh Long, Bạch Hổ, Huyền Vũ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Xưng Thánh Hoàng, chỉnh hợp Tứ Thánh Tông thành một tông và thu thái cổ thánh khí","chuong":"@c1054"},{"text":"Một mình tiến vào tinh vực Thi Âm Tông uy hiếp, bị Thác Sâm trọng thương","chuong":"@c147"},{"text":"Dung hợp hư ảnh Thanh Long đánh lén Vương Lâm thất bại, bị Cổ Tộc Bất Diệt chỉ bức lùi","chuong":"@c1549"},{"text":"Liên thủ cùng ba chiến tướng vẫn bị Khai Thiên Phủ chém tan, kinh hãi nhận ra thiên đạo","chuong":"@c1633"},{"text":"Tử vong trong vụ nổ hủy diệt chín mặt trời va tiễn thứ ba","chuong":"@c1670"}]},"vaiTro":"Tứ đại chiến tướng Viễn cổ Tinh Vực — danh vị Thanh Long trong Tứ Thánh","tinhCach":"hành sự quỷ quyệt, thiên về đánh lén; phân tích chiến cục lạnh lùng, thấu đáo; thận trọng, kiêng kị trước hiểm nguy chưa lường được","blurb":"Thanh Long là một trong Tứ Thánh, thuộc hàng tứ đại chiến tướng từng bị phong ấn tại Viễn cổ Tinh Vực, sau khi thoát phong ấn đã xưng Thánh Hoàng và chỉnh hợp Tứ Thánh Tông thành một tông phái duy nhất. Nhiều lần giao chiến với Vương Lâm — từ đánh lén bằng hư ảnh Thanh Long bất thành đến liên thủ cùng ba chiến tướng khác vẫn thất bại trước Khai Thiên Phủ — và cuối cùng tử vong trong vụ nổ hủy diệt của chín mặt trời va tiễn thứ ba."},{"id":"bach-ho","name":"Bạch Hổ","trangThai":"khong-ro","nguon":["@c1311"],"tabs":{"kinhLich":[{"chuong":"@c1311","importance":"bridge","mucCt":"gon","tieuDe":"Nguồn thuật bị đoạt","text":"Bạch Hổ được nhắc cùng Thanh Long và Huyền Vũ trong nguồn gốc các bí thuật mà Chu Tước tộc sử dụng.","anchor":"đoạt được thuật đại thần thông từ Thanh Long, Bạch Hổ, Huyền Vũ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Tử chiến chặn đại quân Liên Minh, giết nhiều trưởng lão chủ chốt trong đại chiến năm xưa","chuong":"@c0976"},{"text":"Bị phong ấn trong mi tâm pho tượng Cổ Thần tại Viễn cổ Tinh Vực cùng ba chiến tướng khác","chuong":"@c1458"},{"text":"Là người đầu tiên bước vào tàn giới, thiết lập toàn bộ quy tắc tại đó","chuong":"@c1661"},{"text":"Bại trận trước Vương Lâm trong giới cờ, bị uy áp trấn phục vàràng buộc nhận lệnh","chuong":"@c1663"},{"text":"Trọng thương vẫn cõng Chu Tước và Huyền Vũ bỏ chạy, từ chối đầu hàng khi bị truy sát tại Đan Hải","chuong":"@c1749"},{"text":"Được Vương Lâm cứu khỏi hai tu sĩ Lục Ma Châu và cùng hộ pháp phá cấm chế Đan Hải","chuong":"@c1750"}]},"vaiTro":"Một trong Tứ Thánh Tông — chiến tướng bị phong ấn tại Viễn cổ Tinh Vực, sau theo Vương Lâm","tinhCach":"trực tính, hay trào phúng khi chất vấn; dễ chấn động trước sự kiện bất ngờ; tự tin vào lợi thế huyết mạch tiên nhân; kiên cường, không chịu đầu hàng dù trọng thương","blurb":"Bạch Hổ là một trong bốn chiến tướng thuộc Tứ Thánh Tông, từng tử chiến chặn đại quân Liên Minh trong đại chiến năm xưa. Hắn bị phong ấn trong mi tâm pho tượng Cổ Thần khổng lồ tại Viễn cổ Tinh Vực, sau khi thoát ra đã giao chiến rồi quy phục Vương Lâm, trở thành người thiết lập toàn bộ quy tắc tại tàn giới nhưng cuối cùng bại trận trong giới cờ và bị ràng buộc nhận lệnh. Về sau hắn cùng Chu Tước và Huyền Vũ nhiều lần đồng hành, từng bị truy sát tại Đan Hải và được Vương Lâm cứu giúp."},{"id":"huyen-vu","name":"Huyền Vũ","trangThai":"khong-ro","nguon":["@c1311"],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Huyền Vũ được Chu Tước đời thứ hai nhắc là bộ tộc có khí lực lớn nhất. Vì thân thể Vương Lâm là Cổ Thần, ông chọn phương pháp vận lực liên quan mạch Huyền Vũ để truyền thử.","anchor":"Khí lực bộ tộc Huyền Vũ lớn nhất","bridge":true,"khoang":"@c1311"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"dieu-am-dao-ton","name":"Diệu Âm đạo tôn","aliases":["thiếu niên ăn đào","thiếu niên thanh sam nằm trên mây","Diệu Âm tiên tôn"],"gioiTinh":"nam","canhGioiCaoNhat":"Không đổi trong @c1314","trangThai":"song","blurb":"Diệu Âm Đạo Tôn là một trong Thái Cổ Ngũ Tôn, bản thể là lão già tóc bạc ẩn tu dưới đáy hải dương ở tu chân tinh trung tâm, từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa. Y lấy âm bổn nguyên đại thành phá vỡ cửa ải Không Niết lên bước thứ ba, phái phân thân thiếu niên tham gia tranh đoạt tại cổ mộ và giao chiến khốc liệt với phân hồn Đại Hoang Lão Độc để cướp tứ phẩm đạo linh. Sau đại chiến dung hợp âm–thủy, y bị trọng thương rồi bị Đại Hoang Thượng Nhân đoạt xá; mấy vạn năm sau ẩn dưới đáy tử hải ôm mối oán hận, mở mắt trở lại khi khe cổ mộ tái xuất, nhưng bị Vươ","vaiTro":"Cường giả cổ tu — một trong Thái Cổ Ngũ Tôn, bản thể ẩn tu dưới đáy hải dương","tinhCach":"Nhàn nhã phóng túng, thường nằm mây ăn đào quan sát thế cục; tham lam dã tâm, lộ rõ tham niệm khi thấy bảo vật; âm trầm khó lường, bề ngoài thiếu niên xinh xắn nhưng bản thể là lão già tóc bạc tu luyện dưới đáy hải dương","tabs":{"diem":[{"text":"Từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa","chuong":"@c1193"},{"text":"Lấy âm bổn nguyên đại thành phá cửa ải Không Niết, đạt bước thứ ba; dung hợp âm–thủy đại chiến nhưng bị trọng thương gần chết, bị Đại Hoang Thượng Nhân đoạt xá","chuong":"@c1365"},{"text":"Mấy vạn năm ẩn dưới đáy tử hải ôm oán hận, mở mắt trở lại khi khe cổ mộ tái xuất","chuong":"@c1378"},{"text":"Cùng Cửu Thiên Ma Tôn và Đại Hoang Thượng Nhân hợp lực đánh Lam Mộng Đạo Tôn ba ngày, bại trận trọng thương","chuong":"@c1583"},{"text":"Bị Vương Lâm bắt gọn nguyên thần bằng mũi tên cung Lý Quảng","chuong":"@c1596"},{"text":"Tu vi giảm xuống Không Linh do bị Lam Mộng đánh trọng thương, đang trị thương dưới đáy biển thì bị Vương Lâm tuyên chiến, không còn đường thoát","chuong":"@c1697"}],"kinhLich":[{"chuong":"@c1312","importance":"normal","mucCt":"vua","tieuDe":"Nằm mây quan chiến","text":"Diệu Âm đạo tôn xuất hiện ở một khu vực riêng trên không trường đấu, nằm lười trên mây và ăn quả giống quả đào trong lúc xem hai tu sĩ giao chiến bên dưới. Khi Lão Chu Tước và Vương Lâm tới, nhóm cường giả ở các khu vực không ai dám tới gần đều biến sắc ngẩng đầu.","anchor":"Hắn nằm trên một đám mây, lười biếng nhìn những người giao chiến phía dưới"},{"mucCt":"vua","anchor":"là một trong ngũ tôn thái cổ - Diệu âm đ*o tôn","text":"Diệu Âm đạo tôn ban đầu xuất hiện như thiếu niên xinh xắn ăn đào và nhìn Vương Lâm như cười như không. Sau đó lão Chu Tước giới thiệu hắn là một trong Thái Cổ Ngũ Tôn, khiến Vương Lâm chấn động nhưng vẫn bình tĩnh hành lễ.","bridge":true,"khoang":"@c1313"},{"mucCt":"ky","text":"Diệu Âm đạo tôn nằm trên mây quan sát Vương Lâm và nhớ lại tin Thủy Đạo Tử từng truyền âm rằng Vương Lâm là chủ nhân phong giới chưa chết. Ông tự nhận năm xưa ra tay vì Chưởng Tôn đưa ra lợi ích lớn. Hiện tại, ông không vội chọn thái độ mà muốn xem Trường Tôn hội có thể trả cái giá nào để khiến mình ra tay.","anchor":"Tên nhóc nào chính là Vương Lâm theo lời Thủy Đạo Tử truyền âm","bridge":true,"khoang":"@c1314"},{"chuong":"@c1318","importance":"bridge","mucCt":"gon","tieuDe":"Chấn động nhìn hương","text":"Diệu Âm đạo tôn bị tiếng Chu Tước làm chấn động và ngẩng đầu nhìn chằm chằm cây hương thứ nhất.","anchor":"thân thể đột nhiên chấn động, ngẩng phắt đầu, nhìn chằm chằm vào cây hương đầu tiên"},{"chuong":"@c1319","importance":"bridge","mucCt":"gon","tieuDe":"Chú ý cây hương","text":"Diệu Âm đạo tôn chú ý khi cây hương thứ nhất kéo dài tới bảy nhịp thở và lộ vẻ kỳ dị.","anchor":"Diệu ÂM tiên tôn trông như thiếu niên kia hai mắt sững lại"},{"chuong":"@c1320","importance":"bridge","mucCt":"vua","text":"Bị biến cố làm đứng bật dậy từ trên đám mây, ánh mắt lóe lên và xác nhận lời Thủy Đạo Tử từng nói là không sai.","anchor":"cả người từ trên đám mây mạnh mẽ đứng dậy"},{"mucCt":"vua","text":"Đứng bật dậy, thu tầng mây thành quạt, dùng thần thức dò xét biến cố. Nhận định lực lượng đang bộc phát là Thiên Nghịch, thiên đạo.","anchor":"Diệu âm đ*o tôn cũng đứng vọt dậy, tầng mây dưới chân tiêu tan","bridge":true,"khoang":"@c1322"},{"mucCt":"vua","text":"Nhìn Địa phương hương gãy, Diệu Âm đạo tôn ăn đào và lộ rõ tham niệm, tuyên bố nhất định sẽ đoạt lấy Thiên Nghịch.","anchor":"THiên Nghịch. Thiên Nghịch. Diệu âm đ*o tôn ta nhất định lấy","bridge":true,"khoang":"@c1323"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người được quan sát","ghiChu":"Chú ý tới Vương Lâm khi hắn hiện thân cùng lão Chu Tước."},{"ten":"Lão Chu Tước","tag":"khac","quanHe":"người giới thiệu thân phận","ghiChu":"Được lão Chu Tước giới thiệu với Vương Lâm trước các đại năng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1312","@c1313","@c1314","@c1318","@c1319","@c1320","@c1322","@c1323"],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"cn":"妙音道尊"},{"id":"thai-hoang-cong","name":"Thái Hoang Công","aliases":["lão già áo da thú ngồi trên hung thú đen","lão già khoác da thú ngồi trên thằn lằn","lão giả mặc da thú","lão già ngồi trên con thằn lằn"],"gioiTinh":"nam","canhGioiCaoNhat":"Không đổi trong @c1314","trangThai":"song","blurb":"Thái Hoang Công xuất hiện tại trường đấu trong dáng vẻ lão già mặc áo da thú ngồi trên hung thú đen khổng lồ. Ngoại hình dị thường của ông khiến khu vực quanh đó trở thành nơi tu sĩ khác không dám tới gần.","vaiTro":"cường giả quan chiến","tinhCach":[{"text":"khí thế quái dị, tách biệt khỏi đám đông","chuong":"@c1312"},{"text":"bình thản ngồi trên hung thú giữa trường đấu","chuong":"@c1312"}],"tabs":{"diem":[{"text":"Cưỡi hung thú đen khổng lồ với thân thể đầy lỗ, tạo thành khu vực riêng trên không.","chuong":"@c1312"},{"text":"Cùng các cường giả khác biến sắc khi phát giác biến động trên cao.","chuong":"@c1312"},{"text":"Không thuộc Thái Cổ Ngũ Tôn nhưng được đánh giá tu vi không hề kém cạnh.","chuong":"@c1313"},{"text":"Một thân độc công hung danh, có thể chứa vào nửa đoạn móng tay làm lợi khí đả thương địch thủ.","chuong":"@c1313"}],"kinhLich":[{"mucCt":"vua","text":"Thái Hoang Công xuất hiện trên không trường đấu, khoanh chân ngồi trên một hung thú đen khổng lồ. Ông cùng những cường giả chiếm các khu vực không ai dám tới gần đều biến sắc khi Lão Chu Tước và Vương Lâm tới nơi.","anchor":"Một lão già mặc áo da thú đang ngồi khoanh chân trên người nó.","bridge":true,"khoang":"@c1312"},{"mucCt":"vua","anchor":"Người này không phải một trong thái cổ ngũ tôn, nhưng tu vi không kém chút nào","text":"Thái Hoang Công được lão Chu Tước giới thiệu là đại năng không thuộc Thái Cổ Ngũ Tôn nhưng tu vi không kém, nổi danh bởi độc công. Ông nói mình đến để đánh lại lão Chu Tước, đồng thời đánh giá Vương Lâm không tồi và tặng nửa đoạn móng tay chứa độc công làm vật phòng thân.","bridge":true,"khoang":"@c1313"},{"chuong":"@c1314","importance":"bridge","mucCt":"gon","text":"Thái Hoang Công nhắm mắt, không để tâm tới thí luyện của Vương Lâm vì việc trong ngày không hấp dẫn bằng trận chiến với Chu Tước lão điểu.","anchor":"Lão giả mặc da thú lúc này đơn giản nhắm mắt, căn bản không thèm để ý"},{"chuong":"@c1318","importance":"bridge","mucCt":"gon","tieuDe":"Không để ý biến cố","text":"Thái Hoang Công vẫn nhắm mắt giữa lúc mọi người chấn động trước biến hóa của cây hương thứ nhất.","anchor":"Chỉ có lão già ngồi trên con thằn lằn là vẫn nhắm mắt"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"người được tặng vật phòng thân","ghiChu":"Tặng Vương Lâm nửa đoạn móng tay chứa độc công."},{"ten":"Lão Chu Tước","tag":"khac","quanHe":"đối thủ quen biết","ghiChu":"Gọi lão Chu Tước là lão điểu và nói muốn đánh lại một trận."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[{"ten":"Hung thú đen khổng lồ","trangThai":"dang-co","moTa":"Vật cưỡi khổng lồ mà Thái Hoang Công ngồi lên khi quan chiến tại trường đấu.","nguon":"@c1312"}],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1312","@c1313","@c1314","@c1318"]},{"id":"hai-tu-si-tranh-vi-tri-truong-lao","name":"Hai tu sĩ tranh vị trí trưởng lão","gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ @c1312","trangThai":"khong-ro","blurb":"Hai tu sĩ vô danh đang giao chiến giữa trường đấu để tranh đoạt vị trí trưởng lão. Họ là trung tâm cuộc đấu trước khi các cường giả trên không phát giác biến động do Lão Chu Tước và Vương Lâm tới.","vaiTro":"tu sĩ giao chiến tại trường đấu","tinhCach":[{"text":"giao chiến quyết liệt để tranh vị trí","chuong":"@c1312"},{"text":"làm nền cho cảnh trường đấu quy tụ cường giả","chuong":"@c1312"}],"tabs":{"diem":[{"text":"Đang chiến đấu hăng say giữa sân đấu để tranh vị trí trưởng lão.","chuong":"@c1312"}],"kinhLich":[{"chuong":"@c1312","importance":"bridge","mucCt":"gon","tieuDe":"Tranh vị trí trưởng lão","text":"Hai tu sĩ vô danh đang giao chiến hăng say giữa trường đấu để tranh đoạt vị trí trưởng lão.","anchor":"Giờ phút này giữa sân đấu đang có hai tu sĩ chiến đấu hăng say, tranh đoạt vị trí trưởng lão."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1312"]},{"id":"mong-nhi","name":"Mộng Nhi","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Mộng Nhi là người được Lam Mộng đạo tôn nghĩ tới trong lúc ông cân nhắc thái độ với Vương Lâm và Trường Tôn hội. Sự tồn tại của nàng gắn với nỗi khó xử trong gia đình của Lam Mộng đạo tôn.","vaiTro":"Người liên hệ với Lam Mộng","tinhCach":[{"text":"Chưa trực tiếp xuất hiện trong chương này","chuong":"@c1314"},{"text":"Được nhắc như nhân tố khiến Lam Mộng đạo tôn khó xử","chuong":"@c1314"}],"nguon":["@c1314"],"tabs":{"diem":[{"text":"Được Lam Mộng đạo tôn nghĩ tới trong thế khó xử nếu nàng xuất hiện.","chuong":"@c1314"},{"text":"Liên quan tới nỗi đau của Lam Mộng đạo tôn về thê tử đã trở nên xa lạ.","chuong":"@c1314"}],"kinhLich":[{"chuong":"@c1314","importance":"bridge","mucCt":"vua","text":"Mộng Nhi được Lam Mộng đạo tôn nghĩ tới như một người có thể khiến ông khó xử trong cục diện quanh Vương Lâm và Trường Tôn hội.","anchor":"Nếu như Mộng Nhi tới thì ta phải làm thế nào"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"được Lam Mộng đạo tôn nghĩ tới","ghiChu":"Sự xuất hiện của nàng được xem là điều có thể khiến Lam Mộng đạo tôn khó xử."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"thanh-nien-tren-thuyen-trong-nhan-gioi-huyen-canh","name":"Thanh niên trên thuyền trong Nhân giới huyễn cảnh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Thanh niên bí ẩn xuất hiện trong Nhân giới huyễn cảnh của thí luyện thiếu đế. Hắn uống rượu trên thuyền giữa nữ tử múa và tùy tùng, có dung mạo khiến Vương Lâm thấy vô cùng quen thuộc.","vaiTro":"Bóng dáng bí ẩn trong huyễn cảnh","tinhCach":[{"text":"Phóng khoáng qua lời nói về vạn vật tạm bợ và đời người như mộng","chuong":"@c1314"},{"text":"Bí ẩn vì chương chưa nói rõ danh tính thật","chuong":"@c1314"}],"nguon":["@c1314"],"tabs":{"diem":[{"text":"Xuất hiện rõ ràng khác thường giữa cảnh vật phàm nhân mờ ảo của Nhân giới huyễn cảnh.","chuong":"@c1314"},{"text":"Dung mạo của hắn khiến Vương Lâm chỉ nhìn một lần đã chấn động vì quen thuộc.","chuong":"@c1314"}],"kinhLich":[{"mucCt":"gon","text":"Thanh niên bí ẩn xuất hiện trên thuyền lớn trong Nhân giới huyễn cảnh, uống rượu giữa nữ tử múa và tùy tùng rồi khiến Vương Lâm chấn động vì dung mạo quen thuộc.","anchor":"Người thanh niên kia cầm chén rượu uống cạn","bridge":true,"khoang":"@c1314"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"gây chấn động trong huyễn cảnh","ghiChu":"Dung mạo của hắn khiến Vương Lâm cảm thấy vô cùng quen thuộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"thanh-nien-pham-nhan-giong-vuong-lam","name":"Thanh niên phàm nhân giống Vương Lâm","cn":"","aliases":["Hư hồn nhân sinh của Vương Lâm"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân @c1315","trangThai":"khong-ro","blurb":"Một phàm nhân gần ba mươi tuổi trong cửa Nhân, có dung mạo và linh hồn giống hệt Vương Lâm. Sự tồn tại của hắn biểu hiện một nhân sinh phàm tục giả định nếu Vương Lâm không tu đạo.","vaiTro":"hư hồn nhân sinh trong cửa Nhân","tinhCach":[{"text":"phóng khoáng, thích thơ rượu","chuong":"@c1315"},{"text":"hiếu kỳ trước người có dung mạo giống mình","chuong":"@c1315"}],"nguon":["@c1315"],"tabs":{"diem":[{"text":"Có dung mạo và linh hồn tương tự Vương Lâm, nhưng mang sinh cơ phàm tục.","chuong":"@c1315"},{"text":"Mời Vương Lâm lên thuyền đối ẩm khi thấy hai người giống nhau lạ thường.","chuong":"@c1315"},{"text":"Đại diện cho một đời người nếu Vương Lâm không tu đạo.","chuong":"@c1315"},{"text":"Có dung mạo và linh hồn giống hệt Vương Lâm, chỉ khác ở sinh cơ phàm tục và không mang dấu vết năm tháng tu đạo","chuong":"@c1315"},{"text":"Đại diện cho cuộc đời phàm tục mà Vương Lâm có thể đã sống nếu không bước vào tu đạo","chuong":"@c1315"},{"text":"Hư hồn do tâm ma Vương Lâm sinh ra, đại diện nhân sinh phàm tục hắn đã bỏ qua","chuong":"@c1315"}],"kinhLich":[{"chuong":"@c1315","importance":"normal","mucCt":"ky","tieuDe":"Gặp Vương Lâm trên thuyền, đối ẩm và bị nói trúng thân thế","text":"Trong huyễn cảnh cửa Nhân, đang cùng tùy tùng ngâm thơ uống rượu trên thuyền ở Triệu quốc thì thấy Vương Lâm có dung mạo giống mình. Kinh ngạc khi Vương Lâm bay xuống thuyền như chiếc lá và biến ra bầu rượu, hỏi có phải tiên nhân. Mời Vương Lâm lên thuyền đối ẩm, hỏi lai lịch đối phương. Càng chấn động khi nghe Vương Lâm tự thuật lai lịch trùng khớp với bản thân — cha Vương Thiên Thủy, mẹ Chu Anh Tố — qua đó xác lập hắn là hình bóng một nhân sinh phàm tục giả định của Vương Lâm.","anchor":"Bề ngoài của huynh đài có hơi giống tại hạ. Tại hạ trên đường gặp qua không ít người nhưng chưa bao giờ gặp phải trường hợp thế này"}],"tuViMoc":[{"chuong":"@c1315","canhGioi":"Phàm nhân","text":"Xuất hiện trong cửa Nhân với thân phận phàm nhân, không biểu hiện tu vi.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"bản ngã đối chiếu","ghiChu":"Dung mạo và linh hồn tương tự Vương Lâm trong huyễn cảnh cửa Nhân."},{"ten":"Vương Thiên Thủy","tag":"cha-me","quanHe":"cha trong thân thế huyễn cảnh","ghiChu":"Được Vương Lâm nói là cha của hắn trong nhân sinh phàm tục."},{"ten":"Chu Anh Tố","tag":"cha-me","quanHe":"mẹ trong thân thế huyễn cảnh","ghiChu":"Được Vương Lâm nói là mẹ của hắn trong nhân sinh phàm tục."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"tuy-tung-cua-thanh-nien-pham-nhan","name":"Tùy tùng của thanh niên phàm nhân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Phàm nhân @c1315","trangThai":"song","blurb":"Người hầu đi theo thanh niên phàm nhân trên thuyền trong cửa Nhân. Hắn vừa nịnh thơ, vừa tiếc rượu, rồi hoảng sợ khi chứng kiến năng lực của Vương Lâm.","vaiTro":"tùy tùng trong huyễn cảnh","tinhCach":[{"text":"nịnh chủ và thực dụng","chuong":"@c1315"},{"text":"dễ hoảng sợ trước dị tượng tiên nhân","chuong":"@c1315"}],"nguon":["@c1315"],"tabs":{"diem":[{"text":"Theo hầu thanh niên phàm nhân trên thuyền và quan tâm tới tiền thuê thuyền, tiền rượu.","chuong":"@c1315"},{"text":"Khi thấy Vương Lâm thể hiện năng lực vượt phàm tục, hắn xác nhận đó là tiên nhân.","chuong":"@c1315"},{"text":"Khi thấy Vương Lâm lấy rượu và bước lên trời thì kinh hãi, xác nhận Vương Lâm là tiên nhân","chuong":"@c1315"}],"kinhLich":[{"mucCt":"vua","text":"Tùy tùng đi theo thanh niên phàm nhân trên thuyền, ban đầu còn nịnh thơ và tiếc Quế Hoa lão tửu bị uống nhiều. Khi Vương Lâm lấy rượu rồi bước lên không, hắn hoảng sợ và gọi Vương Lâm là tiên nhân.","anchor":"Thật. thật sự là tiên nhân. công tử, đúng là tiên nhân đó. Giấc mộng của người là thật","bridge":true,"khoang":"@c1315"}],"tuViMoc":[{"chuong":"@c1315","canhGioi":"Phàm nhân","text":"Xuất hiện trong cửa Nhân với thân phận tùy tùng phàm nhân.","importance":"major"}],"nhanMach":[{"ten":"Thanh niên phàm nhân giống Vương Lâm","tag":"khac","quanHe":"công tử","ghiChu":"Đi theo hầu thanh niên trên thuyền."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người bị nhận là tiên nhân","ghiChu":"Chứng kiến Vương Lâm thi triển năng lực vượt phàm tục."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"vuong-thien-thuy","name":"Vương Thiên Thủy","canhGioiCaoNhat":"Không đổi trong @c1315","trangThai":"song","nguon":["@c1315"],"tabs":{"diem":[{"text":"Cảm động đến quỳ tạ Tứ thúc khi Vương Lâm được nhường danh ngạch đề cử Hằng Nhạc Phái, mở mấy trăm bàn tiệc tạ","chuong":"@c0001"},{"text":"Vui mừng đón đoàn về tưởng con thành tiên nhân; khi biết con trượt cả ba hạng trắc thí thì như già đi hơn mười tuổi","chuong":"@c0005"},{"text":"Quát thẳng Vương Thiên Sơn, tố cáo đại ca cướp phần gia sản của mình","chuong":"@c0006"},{"text":"An ủi con trên xe ngựa về nhà: bản thân từng bị đuổi khỏi gia môn còn chán nản hơn nhưng vẫn kiên trì","chuong":"@c0007"},{"text":"Thương tâm rơi lệ, ôm con khóc khi tìm thấy Vương Lâm dưới chân vách núi vì hiểu lầm con muốn tự sát","chuong":"@c0009"},{"text":"Vui mừng tiễn con vào phái sau khi Vương Lâm được nhận làm ký danh đệ tử, để lại khoai lang cho con rồi xuống núi","chuong":"@c0010"}],"kinhLich":[{"chuong":"@c1315","importance":"bridge","mucCt":"gon","tieuDe":"Thân thế huyễn cảnh","text":"Trong cửa Nhân, Vương Thiên Thủy được nhắc là cha của thanh niên phàm nhân giống Vương Lâm trong thân thế giả định. Được Vương Lâm nhắc trong huyễn cảnh cửa Nhân là cha của thanh niên phàm nhân, con thứ hai trong nhà, làm nghề thợ mộc. Được Vương Lâm nhắc đến khi tự thuật lai lịch trong huyễn giới cửa Nhân: phụ thân, con thứ hai trong nhà, làm nghề thợ mộc.","anchor":"phụ thân tên là Vương Thiên thủy, là con thứ hai trong nhà, làm nghề thợ mộc"}],"tuViMoc":[],"nhanMach":[{"ten":"Thanh niên phàm nhân giống Vương Lâm","tag":"cha-me","quanHe":"cha trong thân thế huyễn cảnh","ghiChu":"Được nêu là cha của thanh niên phàm nhân giống Vương Lâm."},{"ten":"Chu Anh Tố","tag":"the-thiep","quanHe":"Thê tử","ghiChu":"Mẫu thân của Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"gioiTinh":"nam","vaiTro":"Phụ thân của Vương Lâm — thợ mộc gốc con thứ dòng thứ","tinhCach":"Yêu thương con sâu sắc, dồn trọn kỳ vọng nơi Vương Lâm; nhẫn nhịn bất công trong lặng lẽ nhưng bùng nộ khi bị dồn ép; kiên trì trước nghịch cảnh; biết ơn ân nghĩa","blurb":"Vương Thiên Thủy là cha của Vương Lâm, một thợ mộc vốn là con thứ của dòng thứ, từng bị gia tộc bức rời gia môn. Ông đặt trọn tình thương và kỳ vọng vào con trai, cảm động quỳ tạ khi con được nhường danh ngạch đề cử vào Hằng Nhạc Phái và đau đớn khi con trượt cả ba hạng trắc thí. Tính đến Ch.10, ông tiễn con vào phái làm ký danh đệ tử rồi trở về nhà."},{"id":"chu-anh-to","name":"Chu Anh Tố","cn":"朱英素","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Chu gia trang","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân @c1315","trangThai":"khong-ro","blurb":"Người mẹ trong thân thế phàm tục giả định của thanh niên giống Vương Lâm. Bà là người Chu gia trang, từng đọc thi thư và dạy con biết chữ.","vaiTro":"mẹ trong nhân sinh huyễn cảnh","tinhCach":[{"text":"có học thức phàm tục","chuong":"@c1315"},{"text":"gắn với gia phong Chu gia trang","chuong":"@c1315"}],"nguon":["@c1315"],"tabs":{"diem":[{"text":"Được nói là người Chu gia trang, từng đọc thi thư.","chuong":"@c1315"},{"text":"Trong thân thế giả định, bà dạy thanh niên phàm nhân biết chữ.","chuong":"@c1315"},{"text":"Người Chu gia trang, từng đọc mấy năm thi thư, dạy con biết chữ","chuong":"@c1315"},{"text":"Người Chu gia trang, từng đọc thi thư, dạy Vương Lâm đọc sách nhận chữ thuở nhỏ","chuong":"@c1315"}],"kinhLich":[{"chuong":"@c1315","importance":"bridge","mucCt":"gon","tieuDe":"Mẹ trong huyễn cảnh","text":"Được Vương Lâm nhắc đến khi tự thuật lai lịch trong huyễn cảnh cửa Nhân: mẫu thân tên Chu Anh Tố, người Chu gia trang, từng đọc mấy năm thi thư.","anchor":"mẫu thân là Chu Anh Tố, là người của Chu gia trang, từng đọc mấy năm thi thư"}],"tuViMoc":[{"chuong":"@c1315","canhGioi":"Phàm nhân","text":"Được nhắc trong thân thế huyễn cảnh như một người mẹ phàm tục.","importance":"major"}],"nhanMach":[{"ten":"Thanh niên phàm nhân giống Vương Lâm","tag":"cha-me","quanHe":"mẹ trong thân thế huyễn cảnh","ghiChu":"Được nêu là mẹ của thanh niên phàm nhân giống Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"mảnh ghép nhân sinh giả định","ghiChu":"Thân phận của bà thuộc nhân sinh phàm tục mà cửa Nhân đưa ra để dao động Vương Lâm."},{"ten":"Vương Thiên Thủy","tag":"the-thiep","quanHe":"Chồng, thợ mộc","ghiChu":"@c1315"},{"ten":"Vương Lâm","tag":"cha-me","quanHe":"Con trai","ghiChu":"Vương Lâm nhắc đến mẫu thân khi tự thuật lai lịch trong huyễn giới"},{"ten":"Vương Thiên Thủy","tag":"cha-me","quanHe":"Phu quân","ghiChu":"Phụ thân của Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"su-ton-cua-uyen-nhi","name":"Sư tôn của Uyển nhi","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Lạc Hà môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1315","trangThai":"khong-ro","blurb":"Nữ tử trung niên ở đan phòng Lạc Hà môn trong huyễn cảnh cửa Nhân. Bà trách yêu Uyển nhi sau lần luyện đan thất bại và sai nàng đi lấy Thủy Nguyệt thảo.","vaiTro":"sư tôn của Lý Mộ Uyển thời thiếu nữ","tinhCach":[{"text":"nghiêm mà có vẻ thương học trò","chuong":"@c1315"},{"text":"quen việc luyện đan và quản dược thảo","chuong":"@c1315"}],"nguon":["@c1315"],"tabs":{"diem":[{"text":"Xuất hiện trong đan phòng Lạc Hà môn cạnh lò đan tỏa khói đen.","chuong":"@c1315"},{"text":"Sai Uyển nhi đi lấy Thủy Nguyệt thảo để luyện lại sau khi thất bại.","chuong":"@c1315"}],"kinhLich":[{"mucCt":"gon","text":"Trong huyễn cảnh cửa Nhân, sau khi Uyển nhi luyện đan thất bại trong đan phòng Lạc Hà môn, sư tôn trách yêu rồi sai nàng đi tới phía sau dược phong lấy Thủy Nguyệt thảo.","anchor":"Người đi về phía sau dược phong của vi sư lấy ít Thủy Nguyệt thảo về đây","bridge":true,"khoang":"@c1315"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Mộ Uyển","tag":"su-mon","quanHe":"đồ nhi","ghiChu":"Gọi nàng là Uyển nhi và sai đi lấy dược thảo trong đan phòng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[{"ten":"Thủy Nguyệt thảo","loai":"dược thảo","trangThai":"dang-co","moTa":"Dược thảo bà sai Uyển nhi đi lấy về để luyện lại đan.","nguon":"@c1315"}],"khac":[]}}},{"id":"ca-ca-cua-ly-mo-uyen","name":"Ca ca của Lý Mộ Uyển","gioiTinh":"nam","theLuc":[{"ten":"Lạc Hà môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Ca ca của Lý Mộ Uyển trong Nhân giới thí luyện, được nàng nhắc là có thiên tư hơn mình. Nhân vật này mới xuất hiện qua lời kể của nàng.","vaiTro":"Người thân được nhắc tới","tinhCach":[{"text":"Có thiên tư tu luyện tốt hơn Lý Mộ Uyển","chuong":"@c1316"},{"text":"Được môn phái bồi dưỡng trọng điểm","chuong":"@c1316"}],"tabs":{"diem":[{"text":"Được Lý Mộ Uyển so sánh là thiên tư tốt hơn nàng.","chuong":"@c1316"},{"text":"Vừa nhập phái đã được môn phái chú trọng bồi dưỡng.","chuong":"@c1316"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lý Mộ Uyển","tag":"ho-hang","quanHe":"Muội muội","ghiChu":"Được nàng nhắc tới khi tự than việc luyện đan khó."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1316"]},{"id":"su-ton-cua-ly-mo-uyen","name":"Sư tôn của Lý Mộ Uyển","gioiTinh":"khong-ro","theLuc":[{"ten":"Lạc Hà môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Sư tôn của Lý Mộ Uyển trong Nhân giới thí luyện, người giao nàng đi hái thảo dược. Danh tính và tu vi chưa được nêu rõ trong chương này.","vaiTro":"Sư tôn của Lý Mộ Uyển","tinhCach":[{"text":"Gắn với việc dạy dỗ và sai khiến Lý Mộ Uyển trong Lạc Hà môn","chuong":"@c1316"},{"text":"Được Lý Mộ Uyển dùng làm lý do để rời khỏi Vương Lâm khi cảnh giác","chuong":"@c1316"}],"tabs":{"diem":[{"text":"Sai Lý Mộ Uyển đi hái thảo dược.","chuong":"@c1316"},{"text":"Được Lý Mộ Uyển viện dẫn như người đang chờ nàng.","chuong":"@c1316"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lý Mộ Uyển","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"Sai nàng đi hái thảo dược và được nàng nhắc tới trước Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1316"]},{"id":"su-ty-cua-ly-mo-uyen","name":"Sư tỷ của Lý Mộ Uyển","gioiTinh":"nu","theLuc":[{"ten":"Lạc Hà môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Sư tỷ của Lý Mộ Uyển trong Nhân giới thí luyện, người từng cảnh báo nàng về sự cổ quái của lão quái tu chân giới. Nhân vật này hiện chỉ xuất hiện qua lời nhớ của Lý Mộ Uyển.","vaiTro":"Sư tỷ cảnh báo Lý Mộ Uyển","tinhCach":[{"text":"Thận trọng trước các lão quái tu chân giới","chuong":"@c1316"},{"text":"Có ảnh hưởng tới sự cảnh giác của Lý Mộ Uyển","chuong":"@c1316"}],"tabs":{"diem":[{"text":"Từng nói lão quái tu chân giới đều cổ quái.","chuong":"@c1316"},{"text":"Lời cảnh báo của nàng khiến Lý Mộ Uyển đề phòng Vương Lâm.","chuong":"@c1316"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Lý Mộ Uyển","tag":"su-mon","quanHe":"Sư muội","ghiChu":"Từng cảnh báo nàng về lão quái tu chân giới."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1316"]},{"id":"chu-tuoc-doi-dau","name":"Chu Tước đời đầu","aliases":["Lão tổ đời đầu Chu Tước tộc","Lão tổ đời thứ nhất của Chu Tước"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Chu Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Lão tổ khai tộc của Chu Tước tộc, là một trong số hiếm hoi nắm được cách ngăn nghiệp hỏa thiêu đốt thân thể. Năm xưa từng lừa viêm long ra khỏi viêm vực lúc còn nhỏ để liên tục lấy máu, đồng thời chỉ học trộm được Phần Giới cổ Tán chứ không nắm trọn vẹn. Lời truyền lại của người này đặt nghiệp hỏa nhập hồn cao hơn con đường mượn bất diệt hồn hỏa, và hư hỏa biến dị của Vương Lâm là loại biến hóa mà ngay cả lão tổ đời đầu cũng chưa từng đạt tới.","vaiTro":"Lão tổ đời đầu của Chu Tước tộc — người sáng lập nền tảng nghiên cứu nghiệp hỏa","tinhCach":"mưu lược sâu xa, dám hành sự tàn nhẫn để đạt mục đích; am hiểu sâu về hỏa đạo và nghiệp hỏa","tabs":{"diem":[{"text":"Là người hiếm hoi có cách ngăn cản nghiệp hỏa thiêu đốt thân thể, được Lão Chu Tước nhắc lại","chuong":"@c1317"},{"text":"Năm xưa lừa viêm long ra khỏi viêm vực khi còn nhỏ để liên tục lấy máu","chuong":"@c1321"},{"text":"Hư hỏa biến dị của Vương Lâm là loại biến hóa mà ngay cả lão tổ đời đầu cũng chưa từng đạt tới","chuong":"@c1323"},{"text":"Chỉ học trộm được Phần Giới cổ Tán, không nắm trọn vẹn","chuong":"@c1449"},{"text":"Từng nói chỉ có thể đưa vài người rời khỏi động phủ về quê hương Tiên Cương đại lục","chuong":"@c1540"}],"kinhLich":[{"chuong":"@c1317","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc về nghiệp hỏa","text":"Chu Tước đời đầu được Lão Chu Tước nhắc là người hiếm hoi có cách ngăn cản nghiệp hỏa thiêu đốt thân thể Vương Lâm.","anchor":"ngoài lão tổ đời thứ nhất ra thì chẳng còn người nào có cách ngăn cản"},{"chuong":"@c1321","importance":"bridge","mucCt":"gon","text":"Được viêm long nhớ lại là kẻ năm xưa đã lừa nó ra khỏi viêm vực khi còn nhỏ để liên tục lấy máu, đồng thời được liệt kê trong số cực ít người từng hoàn thành thức tỉnh Chu Tước lần bốn.","anchor":"năm đó chính Chu Tước đời đầu đã lừa ta khi đó còn nhỏ ra khỏi viêm vực"},{"chuong":"@c1323","importance":"bridge","mucCt":"gon","text":"Được nhắc tên trong phần giải thích hư hỏa biến dị của Vương Lâm, là loại biến hóa mà ngay cả lão tổ đời thứ nhất cũng không thể lý giải.","anchor":"bên trong lại xảy ra một loại biến hóa quỷ dị mà ngay cả lão tổ đời thứ nhất cũng không thể lý giải"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão Chu Tước","tag":"su-mon","quanHe":"Tiền nhân","ghiChu":"Lão Chu Tước nhắc tới pháp bảo và lời truyền của đời đầu khi đánh giá lựa chọn của Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người đi lại con đường nghiệp hỏa","ghiChu":"Vương Lâm chọn con đường được nhắc là từ cổ chí kim chỉ đời đầu từng thành công."}],"tuiDo":{"phapBao":[{"ten":"Pháp bảo huyễn hóa Nhân giới của Chu Tước đời đầu","loai":"pháp bảo huyễn hóa","trangThai":"khong-ro","moTa":"Dùng để huyễn hóa nơi thí luyện Nhân giới trong hồn, có thần thông khiến người ngoài khó can thiệp.","nguon":"@c1316"}],"danDuoc":[],"congPhap":[{"ten":"Nghiệp hỏa nhập hồn","loai":"hồn hỏa tu luyện Chu Tước","trangThai":"khong-ro","moTa":"Được lão Chu Tước nhắc là con đường từng có đời đầu thành công.","nguon":"@c1316"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1316","@c1317","@c1321","@c1323"]},{"id":"nam-tu-trung-nien-dia-phuong-gioi","name":"Nam tử trung niên trong Địa Phương giới","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Chu Tước tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người mặc văn bào có Chu Tước hư ảo ở mi tâm, ngồi trên ngọn núi trọc tận cùng Địa Phương giới. Nhận ra khí tức tộc nhân khi Vương Lâm xuất hiện và phóng ấn ký cứu viện nhưng bị đẩy lui.","vaiTro":"Tộc nhân Chu Tước bị mắc kẹt trong Địa Phương giới","tinhCach":"Quan tâm tộc nhân; phản ứng nhanh khi cảm nhận khí tức đồng tộc","tabs":{"diem":[{"text":"Mặc văn bào, mi tâm có Chu Tước hư ảo, ngồi trên núi trọc tận cùng Địa Phương giới suốt thời gian dài.","chuong":"@c1320"}],"kinhLich":[{"mucCt":"vua","text":"Nhận ra khí tức tộc nhân khi Vương Lâm phá vào Địa Phương giới, phóng ấn ký Chu Tước từ mi tâm lao tới ngọn lửa bảy màu cứu viện. Bị sức mạnh kỳ dị của Thiên Nghịch đánh bật xa.","anchor":"Người này nhìn như là một trung niên, toàn thân mặc văn bào","bridge":true,"khoang":"@c1320"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Tộc nhân Chu Tước, cảm nhận khí tức và phóng ấn ký cứu viện"}],"tuiDo":{}},"nguon":["@c1320"]},{"id":"viem-long-van-truong","name":"Viêm long vạn trượng","cn":"","aliases":["Viêm long"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Con viêm long dài vạn trượng trên Đại đế tinh, bị lão Chu Tước giẫm bắt và ép lấy máu tưới Địa Phương hương để trợ lực Vương Lâm thức tỉnh. Được hứa thả tự do nếu Vương Lâm thành công.","vaiTro":"Linh thú bị ép hiến máu trợ lực thí luyện Chu Tước","tinhCach":"Do dự nhưng cuối cùng chủ động hợp tác khi được hứa tự do","tabs":{"diem":[{"text":"Viêm long dài vạn trượng, bị lão Chu Tước giẫm bắt và mở vết thương trên đầu ép máu tưới Địa Phương hương.","chuong":"@c1320"}],"kinhLich":[{"mucCt":"vua","text":"Bị lão Chu Tước giẫm bắt, mở lại vết thương trên đầu ép máu chảy xuống nhuộm đỏ Địa Phương hương. Nghe hứa sẽ được thả tự do nếu Vương Lâm thức tỉnh thành công, do dự rồi chủ động cắn răng ép máu chảy ra.","anchor":"một con viêm long dài vạn trượng bị Lão Chu Tước nâng chân giẫm lên","bridge":true,"khoang":"@c1320"},{"mucCt":"vua","text":"Bị lão Chu Tước lấy sạch viêm huyết tinh hoa trên đỉnh đầu, sau đó tiếp tục bị mở vết thương trăm trượng để lấy long huyết thường. Uất ức nhớ lại việc năm xưa bị Chu Tước đời đầu lừa ra khỏi viêm vực khi còn nhỏ, nhưng vì lời hứa của Chu Tước đời thứ hai nên nhắm mắt phun máu liều một phen.","anchor":"Bây giờ Chu Tước đời thứ hai đã hứa rồi, lão long ta cũng phải liều mạng một phen","bridge":true,"khoang":"@c1321"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão Chu Tước","tag":"doi-thu","quanHe":"Bị lão Chu Tước bắt giẫm và ép lấy máu, được hứa thả tự do"},{"ten":"Chu Tước đời đầu","tag":"doi-thu","quanHe":"Kẻ từng lừa viêm long ra khỏi viêm vực khi còn nhỏ để lấy máu","ghiChu":"@c1321"}],"tuiDo":{}},"nguon":["@c1320","@c1321"]},{"id":"lo-van","name":"Lỗ Vân","cn":"","aliases":["Chu Tước đời thứ năm","Lão Thánh Hoàng"],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1321","importance":"bridge","mucCt":"gon","text":"Được Chu Tước đời thứ tư nhắc tới khi nhận ra khí tức của Lỗ Vân trên thân Vương Lâm, xác nhận Lỗ Vân là đồ đệ của Chu Tước đời thứ tư.","anchor":"chính là khí tức của tên l* m*ng Lỗ Vân"},{"chuong":"@c1323","importance":"normal","mucCt":"vua","tieuDe":"Thi hài được đưa về bên sư phụ","text":"Vương Lâm đưa thi hài Lỗ Vân về bên cạnh Chu Tước đời thứ tư trên ngọn núi trọc trong Địa phương giới. Chu Tước đời thứ tư gọi tên Lỗ Vân và đau đớn xin lỗi, xác nhận ông từng là dược đồng của sư phụ.","anchor":"Lỗ Vân. vi sư. xin lỗi ngươi"}],"nhanMach":[{"ten":"Chu Tước đời thứ tư","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"@c1321"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"tuViMoc":[]},"nguon":["@c1321","@c1323"],"canhGioiCaoNhat":"Không rõ"}]};
